CREATE FUNCTION [dbo].[__fnGET_FILEZILLA_BUTTONS] (@mandant_id INT = 98, @startingAtColumn INT = 1,@startingAtRow INT = 1)  
RETURNS XML AS  
BEGIN
	DECLARE @FILEZILLAs NVARCHAR(MAX)=''
	DECLARE @FILEZILLA NVARCHAR(MAX)=''
	DECLARE @t TABLE (ID INT NOT NULL IDENTITY(1, 1), PK INT NULL, FILEZILLAEntry xml NULL, FILEZILLAEntryString NVARCHAR(MAX))
	INSERT INTO @t (pk, FILEZILLAEntry)
	SELECT  PK,
  		(SELECT 
 				@startingAtColumn[@labelColumn], @startingAtRow[@labelRow], (@startingAtColumn+1)[@elementColumn], @startingAtRow[@elementRow],
 				dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','FILEZILLA','button',ISNULL(ALIAS,''))[@options],
				'{"readVars":["MandantId"], "action":"openFILEZILLA_'+CAST(PK as varchar(32) )+'"}'[@onClickAction],
 				'button'[@type],'0'[@readonly], ISNULL(ALIAS,'') AS '*'  FOR XML PATH('FILEZILLA') , TYPE)
		FROM dbo.[__fnworkspace_fileaccess](@mandant_id) FILEZILLA --WHERE MANDANT_ID = @mandant_id
	UPDATE @t SET FILEZILLAEntryString= CAST(FILEZILLAEntry AS NVARCHAR(MAX))
	UPDATE @t SET FILEZILLAEntryString= REPLACE(FILEZILLAEntryString,'<FILEZILLA ','<FILEZILLA'+CAST(PK as varchar(32) )+' ')
	UPDATE @t SET FILEZILLAEntryString= REPLACE(FILEZILLAEntryString,'</FILEZILLA>','</FILEZILLA'+CAST(PK as varchar(32) )+'>')
	UPDATE @t SET FILEZILLAEntryString= REPLACE(FILEZILLAEntryString,'Row="'+ CAST((@startingAtRow) as varchar(32) )+'"','Row="'+ CAST((ID+@startingAtRow) as varchar(32) )+'"')
	DECLARE @cursor_workspace_FILEZILLA CURSOR
	SET @cursor_workspace_FILEZILLA = CURSOR FOR
	SELECT FILEZILLAEntryString FROM @t
	OPEN @cursor_workspace_FILEZILLA
	FETCH NEXT FROM @cursor_workspace_FILEZILLA INTO @FILEZILLA
	WHILE @@FETCH_STATUS = 0
		BEGIN 
		--PRINT @FILEZILLA
			SET @FILEZILLAs+=@FILEZILLA
			FETCH NEXT FROM @cursor_workspace_FILEZILLA INTO @FILEZILLA
		END
	CLOSE @cursor_workspace_FILEZILLA
	DEALLOCATE @cursor_workspace_FILEZILLA 
	--SELECT * FROM @t
	IF (@FILEZILLAs = '')
		RETURN NULL
	RETURN CAST(@FILEZILLAs AS XML) 
END
GO
/****** Object:  UserDefinedFunction [dbo].[__fnGET_FILEZILLA_STRING]    Script Date: 25.01.2022 03:14:45 ******/
