CREATE FUNCTION [dbo].[__fnGET_FILEZILLA_STRING] (@mandant_id INT = 98, @PK INT = 10) 
RETURNS VARCHAR(MAX)
BEGIN
	DECLARE 
	@FILEZILLAS_STRING VARCHAR(MAX) = '',
	@FILEZILLA_STRING VARCHAR(MAX) = '',
	@ALIAS VARCHAR(128) = NULL,
	@SERVER_STRING VARCHAR(128) = NULL,
	@DOCUMENT_ROOT VARCHAR(2048) = NULL,
	@SERVER_PORT INT = NULL,
	@BENUTZER NVARCHAR(128) = NULL,
	@PASSWORT NVARCHAR(128) = NULL, 
	@MAIN_TERMINAL BIT = NULL
		DECLARE @cursor_workspace_FILEZILLA CURSOR
		SET @cursor_workspace_FILEZILLA = CURSOR FOR
		  SELECT SERVER_STRING,ISNULL(SERVER_PORT,22),ISNULL(DOCUMENT_ROOT,''),ISNULL(BENUTZER,''),ISNULL(PASSWORT,'') FROM dbo.[__fnworkspace_fileaccess](@mandant_id) where PK = @PK
		IF (EXISTS (SELECT * FROM dbo.[__fnworkspace_fileaccess](@mandant_id) WHERE PK = @PK AND ALIAS = 'öffne ALLE'))
			BEGIN
				SET @cursor_workspace_FILEZILLA = CURSOR FOR
				  SELECT SERVER_STRING,ISNULL(SERVER_PORT,22),ISNULL(DOCUMENT_ROOT,''),ISNULL(BENUTZER,''),ISNULL(PASSWORT,'') FROM dbo.[__fnworkspace_fileaccess](@mandant_id)	WHERE PK <> @PK		
			END

		OPEN @cursor_workspace_FILEZILLA
		FETCH NEXT FROM @cursor_workspace_FILEZILLA INTO @SERVER_STRING,@SERVER_PORT,@DOCUMENT_ROOT,@BENUTZER,@PASSWORT
		WHILE @@FETCH_STATUS = 0
			BEGIN 
				IF (CHARINDEX('!',@PASSWORT)>=1)
					BEGIN
						SET @PASSWORT = REPLACE(@PASSWORT,'!','\\!') 
					END
				IF (CHARINDEX(')',@PASSWORT)>=1)
					BEGIN
						SET @PASSWORT = REPLACE(@PASSWORT,')','\\)')
					END 
				IF (CHARINDEX('&',@PASSWORT)>=1) 
					BEGIN
						SET @PASSWORT = REPLACE(@PASSWORT,'&','\\&\\') 
					END 
				IF (CHARINDEX('$',@PASSWORT)>=1) 
					BEGIN
						SET @PASSWORT = REPLACE(@PASSWORT,'$','\\$\\') 
					END 
				--SET @separated_process = 'filezilla sftp://cx9:supP##66@192.168.253.189:22/var/www/ -a ~/updates & /dev/null '
			 	SET @FILEZILLA_STRING = 'filezilla sftp://'+@BENUTZER+':'+@PASSWORT+'@'+@SERVER_STRING+':'+CAST(@SERVER_PORT AS VARCHAR(32))+''+@DOCUMENT_ROOT+' -a ~/updates & /dev/null '
            
				SET @FILEZILLAS_STRING+=@FILEZILLA_STRING
				FETCH NEXT FROM @cursor_workspace_FILEZILLA INTO @SERVER_STRING,@SERVER_PORT,@DOCUMENT_ROOT,@BENUTZER,@PASSWORT
			END
		CLOSE @cursor_workspace_FILEZILLA
		DEALLOCATE @cursor_workspace_FILEZILLA 
	IF (@FILEZILLAS_STRING<>'')	
		RETURN SUBSTRING(@FILEZILLAS_STRING,1,LEN(@FILEZILLAS_STRING))
	RETURN ''
END

GO
