CREATE FUNCTION [dbo].[__fnGET_RDP_BUTTONS] (@mandant_id INT = 98, @startingAtColumn INT = 1,@startingAtRow INT = 1)  
RETURNS XML AS  
BEGIN
	DECLARE @rdps NVARCHAR(MAX)=''
	DECLARE @rdp NVARCHAR(MAX)=''
	DECLARE @t TABLE (ID INT NOT NULL IDENTITY(1, 1), PK INT NULL, rdpEntry xml NULL, rdpEntryString NVARCHAR(MAX))
	INSERT INTO @t (pk, rdpEntry)
	SELECT  PK,
  		(SELECT 
 				@startingAtColumn[@labelColumn], @startingAtRow[@labelRow], (@startingAtColumn+1)[@elementColumn], @startingAtRow[@elementRow],
 				dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','RDP','button',ISNULL(ALIAS,''))[@options],
				'{"readVars":["MandantId"], "action":"openRDP_'+CAST(PK as varchar(32) )+'"}'[@onClickAction],
 				'button'[@type],'0'[@readonly], ISNULL(ALIAS,'') AS '*'  FOR XML PATH('RDP') , TYPE)
		FROM dbo.[__fnworkspace_rdp](@mandant_id) rdp --WHERE MANDANT_ID = @mandant_id
	UPDATE @t SET rdpEntryString= CAST(rdpEntry AS NVARCHAR(MAX))
	UPDATE @t SET rdpEntryString= REPLACE(rdpEntryString,'<RDP ','<RDP'+CAST(PK as varchar(32) )+' ')
	UPDATE @t SET rdpEntryString= REPLACE(rdpEntryString,'</RDP>','</RDP'+CAST(PK as varchar(32) )+'>')
	UPDATE @t SET rdpEntryString= REPLACE(rdpEntryString,'Row="'+ CAST((@startingAtRow) as varchar(32) )+'"','Row="'+ CAST((ID+@startingAtRow) as varchar(32) )+'"')
	DECLARE @cursor_workspace_rdp CURSOR
	SET @cursor_workspace_rdp = CURSOR FOR
	SELECT rdpEntryString FROM @t
	OPEN @cursor_workspace_rdp
	FETCH NEXT FROM @cursor_workspace_rdp INTO @rdp
	WHILE @@FETCH_STATUS = 0
		BEGIN 
		--PRINT @rdp
			SET @rdps+=@rdp
			FETCH NEXT FROM @cursor_workspace_rdp INTO @rdp
		END
	CLOSE @cursor_workspace_rdp
	DEALLOCATE @cursor_workspace_rdp 
	--SELECT * FROM @t
	IF (@rdps = '')
		RETURN NULL
	RETURN CAST(@rdps AS XML) 
END
GO
