CREATE FUNCTION [dbo].[__fnGET_RDP_STRING] (@mandant_id INT = 98, @PK INT = 10, @screen_size VARCHAR(128) = '1912x952') 
RETURNS NVARCHAR(MAX)
BEGIN
	DECLARE 
	@MANDANT_NAME_PARSED NVARCHAR(MAX) = REPLACE(dbo.GET_MANDANT_NAME_PARSED(@mandant_id),' ','_')+':RDP_SERVER:',
	@XRDPS_STRING NVARCHAR(MAX) = '',
	@XRDP_STRING NVARCHAR(MAX) = '',
	@KILLS_STRING VARCHAR(MAX) = '',
	@xclip_STRING VARCHAR(MAX) = '',
	@KILL_STRING VARCHAR(MAX) = '',
	@ALIAS VARCHAR(128) = NULL,
	@WINDOW_TITLE VARCHAR(512) = NULL,
	@SERVER_STRING VARCHAR(128) = NULL,
	@DOMAIN VARCHAR(128) = NULL,
	@SERVER_PORT INT = NULL,
	@BENUTZER NVARCHAR(128) = NULL,
	@PASSWORT NVARCHAR(128) = NULL, 
	@MAIN_TERMINAL BIT = NULL
		DECLARE @cursor_workspace_rdp CURSOR
		SET @cursor_workspace_rdp = CURSOR FOR
		  SELECT SERVER_STRING,ISNULL(SERVER_PORT,3389),ISNULL(DOMAIN,''),ISNULL(BENUTZER,''),ISNULL(PASSWORT,'') FROM dbo.[__fnworkspace_rdp](@mandant_id) where PK = @PK
		IF (EXISTS (SELECT * FROM dbo.[__fnworkspace_rdp](@mandant_id) WHERE PK = @PK AND ALIAS = 'öffne ALLE RDP'))
			BEGIN
				SET @cursor_workspace_rdp = CURSOR FOR
				  SELECT SERVER_STRING,ISNULL(SERVER_PORT,3389),ISNULL(DOMAIN,''),ISNULL(BENUTZER,''),ISNULL(PASSWORT,'') FROM dbo.[__fnworkspace_rdp](@mandant_id)	WHERE PK <> @PK		
			END
		IF (EXISTS (SELECT * FROM dbo.[__fnworkspace_rdp](@mandant_id) WHERE PK = @PK AND ALIAS = 'schließe ALLE RDP'))
			BEGIN
				SET @kill_STRING = 'sh ~/bin/pkill_by_pattern.sh \\\"xfreerdp\\\" & > /dev/null ; sleep 1 ; exit '
				RETURN @kill_STRING
				SET @PK = -1
				SET @cursor_workspace_rdp = CURSOR FOR
				  SELECT SERVER_STRING,ISNULL(SERVER_PORT,3389),ISNULL(DOMAIN,''),ISNULL(BENUTZER,''),ISNULL(PASSWORT,'') FROM dbo.[__fnworkspace_rdp](@mandant_id)	WHERE PK = @PK	
			END            
		 
		OPEN @cursor_workspace_rdp
		FETCH NEXT FROM @cursor_workspace_rdp INTO @SERVER_STRING,@SERVER_PORT,@DOMAIN,@BENUTZER,@PASSWORT
		WHILE @@FETCH_STATUS = 0
			BEGIN 
				 
			--PRINT @rdpSET @separated_process = 'xfreerdp /v:192.168.254.210 /d:CXNEUN /u:jmunoz /p:''cx9'' /size:1900x1000 /cert-ignore & xfreerdp /v:192.168.254.200 /d:CXNEUN /u:jmunoz /p:cx9 /size:1900x1000 /cert-ignore'
				--ps -ef | grep 'xfreerdp +clipboard /v:192.168.254.220:3389 /d:CXNEUN /u:jmunoz' | grep -v grep | awk '{print $2}' | xargs -r kill
				--~/bin/pkill_by_pattern.sh "
				SET @kill_STRING = 'sh ~/bin/pkill_by_pattern.sh \\\"xfreerdp +clipboard /v:'+@SERVER_STRING+':'+CAST(@SERVER_PORT AS VARCHAR(32))+CASE WHEN @DOMAIN<>'' THEN ' /d:'+@DOMAIN ELSE ' ' END+' /u:'+@BENUTZER+'\\\" ; '
				SET @WINDOW_TITLE = @MANDANT_NAME_PARSED+''+@SERVER_STRING+':'+CAST(@SERVER_PORT AS VARCHAR(32))+CASE WHEN @DOMAIN<>'' THEN '['+@DOMAIN+'/' ELSE '[' END+''+@BENUTZER+'] '
				--SET @WINDOW_TITLE = CAST(@SERVER_PORT AS VARCHAR(32))+CASE WHEN @DOMAIN<>'' THEN 'domain_'+@DOMAIN ELSE '_' END+'_user_'+@BENUTZER+' '
				SET @WINDOW_TITLE = REPLACE(@WINDOW_TITLE,'(','_')
				SET @WINDOW_TITLE = REPLACE(@WINDOW_TITLE,')','_')
				--IF (CHARINDEX('&',@PASSWORT)>=1)
				--	BEGIN
						SET @PASSWORT = REPLACE(@PASSWORT,'&','\\&\\')
						--SET @PASSWORT = dbo._outputStringSSH(@PASSWORT)
					--END 					
				SET @XRDP_STRING = 'xfreerdp +clipboard /v:'+@SERVER_STRING+':'+CAST(@SERVER_PORT AS VARCHAR(32))+CASE WHEN @DOMAIN<>'' THEN ' /d:'+@DOMAIN ELSE ' ' END+' /u:'+@BENUTZER+' /p:'''+@PASSWORT+''' /size:'+@screen_size+' /cert-ignore +clipboard /t:'+@WINDOW_TITLE+' /drive:Transfer,/home/jmunoz/transfer/Jose /drive:tmp,/home/jmunoz/tmp /sec-rdp +clipboard & '
				--PRINT @XRDP_STRING
	

				IF (CHARINDEX('!',@PASSWORT)>=1)
					BEGIN
						SET @PASSWORT = REPLACE(@PASSWORT,'!','\\!')
						SET @XRDP_STRING = 'xfreerdp +clipboard /v:'+@SERVER_STRING+':'+CAST(@SERVER_PORT AS VARCHAR(32))+CASE WHEN @DOMAIN<>'' THEN ' /d:'+@DOMAIN ELSE ' ' END+' /u:'+@BENUTZER+' /p:'+@PASSWORT+' /size:'+@screen_size+' /cert-ignore +clipboard /t:'+@WINDOW_TITLE+' /drive:Transfer,/home/jmunoz/transfer/Jose /drive:tmp,/home/jmunoz/tmp /sec-rdp +clipboard & '
						--SELECT CHARINDEX('a','jose')
					END
				IF (CHARINDEX(')',@PASSWORT)>=1)
					BEGIN
						SET @PASSWORT = REPLACE(@PASSWORT,')','\\)')
						SET @XRDP_STRING = 'xfreerdp +clipboard /v:'+@SERVER_STRING+':'+CAST(@SERVER_PORT AS VARCHAR(32))+CASE WHEN @DOMAIN<>'' THEN ' /d:'+@DOMAIN ELSE ' ' END+' /u:'+@BENUTZER+' /p:'+@PASSWORT+' /size:'+@screen_size+' /cert-ignore +clipboard /t:'+@WINDOW_TITLE+' /drive:Transfer,/home/jmunoz/transfer/Jose /drive:tmp,/home/jmunoz/tmp /sec-rdp +clipboard & '
					END 
				IF (CHARINDEX('&',@PASSWORT)>=1) 
					BEGIN
						SET @PASSWORT = REPLACE(@PASSWORT,'&','\\&\\') 
						SET @XRDP_STRING= 'xfreerdp +clipboard /v:'+@SERVER_STRING+':'+CAST(@SERVER_PORT AS VARCHAR(32))+CASE WHEN @DOMAIN<>'' THEN ' /d:'+@DOMAIN ELSE ' ' END+' /u:'+@BENUTZER+' /p:'+@PASSWORT+' /size:'+@screen_size+' /cert-ignore +clipboard /t:'+@WINDOW_TITLE+' /drive:Transfer,/home/jmunoz/transfer/Jose /drive:tmp,/home/jmunoz/tmp /sec-rdp +clipboard & '
					END 	
				IF (CHARINDEX('$',@PASSWORT)>=1) 
					BEGIN
						SET @PASSWORT = REPLACE(@PASSWORT,'$','\\$\\')
						SET @XRDP_STRING= 'xfreerdp +clipboard /v:'+@SERVER_STRING+':'+CAST(@SERVER_PORT AS VARCHAR(32))+CASE WHEN @DOMAIN<>'' THEN ' /d:'+@DOMAIN ELSE ' ' END+' /u:'+@BENUTZER+' /p:'+@PASSWORT+' /size:'+@screen_size+' /cert-ignore +clipboard /t:'+@WINDOW_TITLE+' /drive:Transfer,/home/jmunoz/transfer/Jose /drive:tmp,/home/jmunoz/tmp /sec-rdp +clipboard & '						 
					END 
				SET @xclip_STRING = ''	
					
				IF (@PASSWORT <> '')
					BEGIN 
						SET @xclip_STRING = 'echo '+@PASSWORT+' | xclip -sel clip; '	
					END															 
					
					/**/                  
				--SET @XRDPS_STRING+=@XRDP_STRING
				SET @XRDPS_STRING+=@kill_STRING+@xclip_STRING+@XRDP_STRING
				FETCH NEXT FROM @cursor_workspace_rdp INTO @SERVER_STRING,@SERVER_PORT,@DOMAIN,@BENUTZER,@PASSWORT
			END
		CLOSE @cursor_workspace_rdp
		DEALLOCATE @cursor_workspace_rdp 
	IF (@XRDPS_STRING<>'')	
		RETURN SUBSTRING(@XRDPS_STRING,1,LEN(@XRDPS_STRING))+' > /dev/null ; sleep 5; exit '
	RETURN ''
END

GO
