 CREATE FUNCTION [dbo].[__fnGET_SSH_BUTTONS] (@mandant_id INT = 98, @startingAtColumn INT = 1,@startingAtRow INT = 1)  
RETURNS XML AS  
BEGIN
	DECLARE @SSHs NVARCHAR(MAX)=''
	DECLARE @SSH NVARCHAR(MAX)=''
	DECLARE @t TABLE (ID INT NOT NULL IDENTITY(1, 1), PK INT NULL, SSHEntry xml NULL, SSHEntryString NVARCHAR(MAX))
	INSERT INTO @t (pk, SSHEntry)
	SELECT  PK,
  		(SELECT 
 				@startingAtColumn[@labelColumn], @startingAtRow[@labelRow], (@startingAtColumn+1)[@elementColumn], @startingAtRow[@elementRow],
 				dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','SSH','button',ISNULL(ALIAS,''))[@options],
				'{"readVars":["MandantId"], "action":"openSSH_'+CAST(PK as varchar(32) )+'"}'[@onClickAction],
 				'button'[@type],'0'[@readonly], ISNULL(ALIAS,'') AS '*'  FOR XML PATH('SSH') , TYPE)
		FROM dbo.[__fnworkspace_fileaccess](@mandant_id) SSH --WHERE MANDANT_ID = @mandant_id
	UPDATE @t SET SSHEntryString= CAST(SSHEntry AS NVARCHAR(MAX))
	UPDATE @t SET SSHEntryString= REPLACE(SSHEntryString,'<SSH ','<SSH'+CAST(PK as varchar(32) )+' ')
	UPDATE @t SET SSHEntryString= REPLACE(SSHEntryString,'</SSH>','</SSH'+CAST(PK as varchar(32) )+'>')
	UPDATE @t SET SSHEntryString= REPLACE(SSHEntryString,'Row="'+ CAST((@startingAtRow) as varchar(32) )+'"','Row="'+ CAST((ID+@startingAtRow) as varchar(32) )+'"')
	DECLARE @cursor_workspace_SSH CURSOR
	SET @cursor_workspace_SSH = CURSOR FOR
	SELECT SSHEntryString FROM @t
	OPEN @cursor_workspace_SSH
	FETCH NEXT FROM @cursor_workspace_SSH INTO @SSH
	WHILE @@FETCH_STATUS = 0
		BEGIN 
		--PRINT @SSH
			SET @SSHs+=@SSH
			FETCH NEXT FROM @cursor_workspace_SSH INTO @SSH
		END
	CLOSE @cursor_workspace_SSH
	DEALLOCATE @cursor_workspace_SSH 
	--SELECT * FROM @t
	IF (@SSHs = '')
		RETURN NULL
	RETURN CAST(@SSHs AS XML) 
END
GO
/****** Object:  UserDefinedFunction [dbo].[__fnGET_SSH_STRING]    Script Date: 25.01.2022 03:14:45 ******/
SET ANSI_NULLS ON
