CREATE FUNCTION [dbo].[__fnGET_SSH_STRING] (@mandant_id INT = 98, @PK INT = 10) 
RETURNS VARCHAR(MAX)
BEGIN
	DECLARE 
	@sshS_STRING VARCHAR(MAX) = '',
	@ssh_STRING VARCHAR(MAX) = '',
	@xclip_STRING VARCHAR(MAX) = '',
	@ALIAS VARCHAR(128) = NULL,
	@SERVER_STRING VARCHAR(128) = NULL,
	@DOCUMENT_ROOT VARCHAR(2048) = NULL,
	@SERVER_PORT INT = NULL,
	@BENUTZER NVARCHAR(128) = NULL,
	@PASSWORT NVARCHAR(128) = NULL, 
	@ROOTPASSWORT NVARCHAR(128) = NULL, 
	@MAIN_TERMINAL BIT = NULL,
	@PUBLIC_KEY BIT = NULL
    DECLARE @cursor_workspace_ssh CURSOR
		SET @cursor_workspace_ssh = CURSOR FOR
		  SELECT SERVER_STRING,ISNULL(SERVER_PORT,22),ISNULL(DOCUMENT_ROOT,''),ISNULL(BENUTZER,''),ISNULL(PASSWORT,''),ISNULL(PUBLIC_KEY,0), ISNULL(ROOTPASSWORT,0) FROM dbo.[__fnworkspace_fileaccess](@mandant_id) where PK = @PK
		IF (EXISTS (SELECT * FROM dbo.[__fnworkspace_fileaccess](@mandant_id) WHERE PK = @PK AND ALIAS = 'öffne ALLE'))
			BEGIN
				SET @cursor_workspace_ssh = CURSOR FOR
				  SELECT SERVER_STRING,ISNULL(SERVER_PORT,3389),ISNULL(DOCUMENT_ROOT,''),ISNULL(BENUTZER,''),ISNULL(PASSWORT,''),ISNULL(PUBLIC_KEY,0), ISNULL(ROOTPASSWORT,0) FROM dbo.[__fnworkspace_fileaccess](@mandant_id)	WHERE PK <> @PK		
			END

		OPEN @cursor_workspace_ssh
		FETCH NEXT FROM @cursor_workspace_ssh INTO @SERVER_STRING,@SERVER_PORT,@DOCUMENT_ROOT,@BENUTZER,@PASSWORT,@PUBLIC_KEY, @ROOTPASSWORT
		WHILE @@FETCH_STATUS = 0
			BEGIN 
			--SET @separated_process = 'sshpass -p cx9 ssh -t jmunoz@192.168.254.163 \\\"cd /home/jmunoz/bin ; bash --login\\\" '
			--SET @separated_process = 'sshpass -p cx9 ssh -t jmunoz@192.168.254.163 -p22 \\\"cd /home/jmunoz/bin ; bash --login\\\" '
				SET @PASSWORT = dbo._outputStringSSH(@PASSWORT)	
				SET @xclip_STRING = ''	
					
				IF (@ROOTPASSWORT <> '')
					BEGIN
						SET @ROOTPASSWORT = dbo._outputStringSSH(@ROOTPASSWORT)
						SET @xclip_STRING = 'echo '+@ROOTPASSWORT+' | xclip -sel clip; '	
					END					
										
				SET @ssh_STRING = @xclip_STRING+'sshpass -p '+@PASSWORT+' ssh -t '+ @BENUTZER+'@'+@SERVER_STRING+' -p'+CAST(@SERVER_PORT AS VARCHAR(32))+' -o \\\"UserKnownHostsFile=/dev/null\\\" -o \\\"StrictHostKeyChecking=no\\\" \\\"cd '+@DOCUMENT_ROOT+' ; ls ; bash --login\\\"  & '
				IF(@PUBLIC_KEY = 1)
					--SET @ssh_STRING = 'ssh -i /home/jmunoz/transfer/Jose/tmp/a '+ @BENUTZER+'@'+@SERVER_STRING+' -p'+CAST(@SERVER_PORT AS VARCHAR(32))+' & '
					--SET @ssh_STRING = @xclip_STRING+'ssh -i /home/jmunoz/.ssh/id_rsa '+ @BENUTZER+'@'+@SERVER_STRING+' -p'+CAST(@SERVER_PORT AS VARCHAR(32))+' -o \\\"UserKnownHostsFile=/dev/null\\\" -o \\\"StrictHostKeyChecking=no\\\" \\\"cd '+@DOCUMENT_ROOT+' ; ls ; bash --login\\\ & '
					SET @ssh_STRING = @xclip_STRING+'ssh -i /home/jmunoz/.ssh/id_rsa '+ @BENUTZER+'@'+@SERVER_STRING+' -p'+CAST(@SERVER_PORT AS VARCHAR(32))+' & '-- +' -o \\\"UserKnownHostsFile=/dev/null\\\" -o \\\"StrictHostKeyChecking=no\\\" \\\"cd '+@DOCUMENT_ROOT+' ; ls ; bash --login\\\ & '

					--SET @ssh_STRING = 'ssh -i /home/jmunoz/.ssh/id_rsa '+ @BENUTZER+'@'+@SERVER_STRING+' -p'+CAST(@SERVER_PORT AS VARCHAR(32))+' & '
                 
				SET @sshS_STRING+=@ssh_STRING
				FETCH NEXT FROM @cursor_workspace_ssh INTO @SERVER_STRING,@SERVER_PORT,@DOCUMENT_ROOT,@BENUTZER,@PASSWORT,@PUBLIC_KEY, @ROOTPASSWORT
			END
		CLOSE @cursor_workspace_ssh
		DEALLOCATE @cursor_workspace_ssh 
	IF (@sshS_STRING<>'')	
		RETURN SUBSTRING(@sshS_STRING,1,LEN(@sshS_STRING)-1)
	RETURN ''
END

GO
