CREATE FUNCTION [dbo].[__fnGET_USABLE_LINK_STRING] (@mandante_environtmen_pk INT = NULL, @type VARCHAR(255) = 'ORM',  @TEXT_PARAMS1 VARCHAR(MAX)='',  @TEXT_PARAMS2 VARCHAR(MAX)='', @BASE64_PARAMS VARCHAR(MAX)='') 
RETURNS VARCHAR(MAX)
BEGIN
	DECLARE @table TABLE (pk INT NOT NULL IDENTITY(1,1), link VARCHAR(MAX) NULL, TYPE VARCHAR(255) NULL)
----sh ~/bin/exec.sh ["gnome-system-monitor" "teamviewer" "icedove" "nautilus ~/updates/" "nautilus ~/bin/"] '0'
	INSERT INTO @table (link,TYPE)
		VALUES ('gnome-system-monitor','ALLE'),
			   ('teamviewer','ALLE'),
			   ('thunderbird','ALLE'),
			   ('nautilus ~/updates/','ALLE'),
			   ('nautilus ~/bin/','ALLE'),
			   ('/opt/google/chrome/google-chrome --allow-file-access-from-files http://gitlab.cx9.info:8000/cx9/jasper/-/blob/master/NL/mietvertrag_einseitig/mietvertrag.jrxml','ALLE'),
			   ('/opt/google/chrome/google-chrome --allow-file-access-from-files http://gitlab.cx9.info:8000/cx9/jasper/','ALLE')
	--DECLARE @mandant_id INT = dbo.byp
	DECLARE @mandant_id INT = ISNULL((SELECT TOP 1 id FROM dbo.Mandant WHERE id= (SELECT TOP 1 mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @mandante_environtmen_pk)),'123456')
	DECLARE @mandant_ENV VARCHAR(32) = ISNULL((SELECT TOP 1 type FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @mandante_environtmen_pk),'_')
	
	DECLARE  
	@LINK_APPLICATION_STRINGS VARCHAR(MAX) = 'sh ~/bin/exec.sh ',
	@LINK_APPLICATION_STRING VARCHAR(MAX) = ISNULL((SELECT ormUrl FROM dbo.Mandant WHERE id = @mandant_id),'https://reservierung.crent.de'),
	@LINK_APPLICATION_STRING_GIT VARCHAR(MAX) = '',
	@LINK_APPLICATION_STRING_X VARCHAR(MAX) = '',
	@GIT_PROJECT VARCHAR(255) = @TEXT_PARAMS1,
	@GIT_BRANCH VARCHAR(255) = @TEXT_PARAMS2,
	@GIT_USER VARCHAR(255) = 'web',
	@LINK_APPLICATION_STRING_AUX VARCHAR(MAX) = '' 
	IF (@GIT_PROJECT IN ('crent_schema','jasper'))
		SET @GIT_USER ='cx9'

	SET @LINK_APPLICATION_STRING_GIT='http://gitlab.cx9.info:8000/'+@GIT_USER+'/'+@GIT_PROJECT+'/-/tree/'+@GIT_BRANCH
	INSERT INTO @table(link,TYPE)
	    SELECT  '/opt/google/chrome/google-chrome --allow-file-access-from-files '+@LINK_APPLICATION_STRING_GIT, 'GIT_OPEN_PROJECT' 
			
	IF (@mandant_ENV <> 'DEFAULT')
		SET @LINK_APPLICATION_STRING = REPLACE(@LINK_APPLICATION_STRING,'/reservierung','/reservierung_test')
	INSERT INTO @table(link,TYPE)
	    SELECT  '/opt/google/chrome/google-chrome --allow-file-access-from-files '+@LINK_APPLICATION_STRING, 'ORM'  
	SET @LINK_APPLICATION_STRING = ISNULL((SELECT crwUrl FROM dbo.Mandant WHERE id = @mandant_id),'https://demo.crentweb.de')
	IF (@mandant_ENV <> 'DEFAULT')
		SET @LINK_APPLICATION_STRING = REPLACE(@LINK_APPLICATION_STRING,'/crentweb','/crentweb_test')	 
	INSERT INTO @table(link,TYPE)
	    SELECT  '/opt/google/chrome/google-chrome --allow-file-access-from-files '+@LINK_APPLICATION_STRING, 'CRW' 

	DECLARE @LINK_APPLICATION_JASPER_AUSDRUCK VARCHAR(MAX)  = @LINK_APPLICATION_STRING +'/classes/P'+@TEXT_PARAMS1+'.php?'+@TEXT_PARAMS2+'&params='+dbo.uFnStringToBase64(@BASE64_PARAMS)
	SET @LINK_APPLICATION_JASPER_AUSDRUCK = REPLACE(@LINK_APPLICATION_JASPER_AUSDRUCK,'&','\\&\\') 
	INSERT INTO @table(link,TYPE)
	    SELECT  '/opt/google/chrome/google-chrome --allow-file-access-from-files '+(@LINK_APPLICATION_JASPER_AUSDRUCK), 'JASPER_AUSDRUCK' 		
	SET @LINK_APPLICATION_STRING_X = 'sh ~/bin/pkill_by_pattern.sh \\\"terminal\\\" & sh ~/bin/pkill_by_pattern.sh \\\"konsole\\\" & > /dev/null ; sleep 1 ; exit '
	SET @LINK_APPLICATION_STRING_X = REPLACE(@LINK_APPLICATION_STRING_X,'&','\\&\\') 

	INSERT INTO @table(link,TYPE)
	    SELECT   (@LINK_APPLICATION_STRING_X), 'CLOSE_TERMINALS' 		

--kunden_open_CLOSE_TERMINALS
	DECLARE @cursor_workspace_APP CURSOR
	SET @cursor_workspace_APP = CURSOR FOR
		SELECT  link  FROM @table where TYPE = @type
	IF (@type = 'ALLE')
		BEGIN
			SET @cursor_workspace_APP = CURSOR FOR
				SELECT  link  FROM @table
		END
    SET @LINK_APPLICATION_STRING = ''
	OPEN @cursor_workspace_APP
	FETCH NEXT FROM @cursor_workspace_APP INTO @LINK_APPLICATION_STRING
	WHILE @@FETCH_STATUS = 0
		BEGIN 
			--SET @separated_process = 'APP sftp://cx9:supP##66@192.168.253.189:22/var/www/ -a ~/updates & /dev/null '
			SET @LINK_APPLICATION_STRING_AUX += '\\\"'+@LINK_APPLICATION_STRING+'\\\" '
            
			 
			FETCH NEXT FROM @cursor_workspace_APP INTO @LINK_APPLICATION_STRING
		END
	CLOSE @cursor_workspace_APP
	DEALLOCATE @cursor_workspace_APP 		
		 
		 
	IF (@LINK_APPLICATION_STRING_AUX<>'')	
		BEGIN
			SET @LINK_APPLICATION_STRING_AUX =  SUBSTRING(@LINK_APPLICATION_STRING_AUX,1,LEN(@LINK_APPLICATION_STRING_AUX))	
			SET @LINK_APPLICATION_STRINGS += @LINK_APPLICATION_STRING_AUX + ' ''0'''
			RETURN @LINK_APPLICATION_STRINGS
		END
		
	RETURN ''
END

GO
