BEGIN 
	DECLARE @XML_ABASANSPRECHPARTNERS NVARCHAR(MAX) =
		(ISNULL((
				STUFF(( 
						SELECT 
									(SELECT ISNULL(PK,-1)[@PK] 
										
														,(SELECT 
																1[@labelColumn], 1[@labelRow], 2[@elementColumn],  1[@elementRow], 
