 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'1'[@readonly],  (SELECT TOP 1 subtable.companyname FROM mandant subtable WHERE subtable.abasId = tf.abasId)  AS '*'  FOR XML PATH('companyname'), TYPE)			
							
														,(SELECT 
																3[@labelColumn], 1[@labelRow], 4[@elementColumn], 1[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','PK','inputText',  ISNULL(PK,'') )[@options],												
 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'1'[@readonly],  PK  AS '*'  FOR XML PATH('PK'), TYPE)			
							
														,(SELECT 
																1[@labelColumn], 2[@labelRow], 2[@elementColumn], 2[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','abasId','inputText',  ISNULL(abasId,'') )[@options],												
 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  abasId  AS '*'  FOR XML PATH('abasId'), TYPE)			
							
														,(SELECT 
																3[@labelColumn], 2[@labelRow], 4[@elementColumn], 2[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','firmenName','inputText',  ISNULL(firmenName,'') )[@options],												
 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  firmenName  AS '*'  FOR XML PATH('firmenName'), TYPE)			
							
														,(SELECT 
																1[@labelColumn], 3[@labelRow], 2[@elementColumn], 3[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','betreuer','inputText',  ISNULL(betreuer,'') )[@options],												
 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  betreuer  AS '*'  FOR XML PATH('betreuer'), TYPE)			
							
														,(SELECT 
																3[@labelColumn], 3[@labelRow], 4[@elementColumn], 3[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','anrede','inputText',  ISNULL(anrede,'') )[@options],												
 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  anrede  AS '*'  FOR XML PATH('anrede'), TYPE)			
							
														,(SELECT 
																1[@labelColumn], 4[@labelRow], 2[@elementColumn], 4[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','ansprechpartner','inputText',  ISNULL(ansprechpartner,'') )[@options],												
 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  ansprechpartner  AS '*'  FOR XML PATH('ansprechpartner'), TYPE)			
							
														,(SELECT 
																3[@labelColumn], 4[@labelRow], 4[@elementColumn], 4[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','eMail','inputText',  ISNULL(eMail,'') )[@options],												
 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  eMail  AS '*'  FOR XML PATH('eMail'), TYPE)			
							
														,(SELECT 
																1[@labelColumn], 5[@labelRow], 2[@elementColumn], 5[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','ABASANSPRECHPARTNER_UPDATE_ACID_Button','button', 'TRY_UPDATE')[@options],	
																'{"readVars":[], "readObj":"1", "action":"ABASANSPRECHPARTNER_UPDATE_ACID_Button"}' [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('ABASANSPRECHPARTNER_UPDATE_ACID_Button'), TYPE)												
							
														,(SELECT 
																3[@labelColumn], 5[@labelRow], 4[@elementColumn], 5[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','ABASANSPRECHPARTNER_INSERT_ACID_Button','button', 'TRY_INSERT_NEW')[@options],	
																'{"readVars":[], "readObj":"1", "action":"ABASANSPRECHPARTNER_INSERT_ACID_Button"}' [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('ABASANSPRECHPARTNER_INSERT_ACID_Button'), TYPE)												
							
														,(SELECT 
																1[@labelColumn], 6[@labelRow], 2[@elementColumn], 6[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ABASANSPRECHPARTNER','ABASANSPRECHPARTNER_DELETE_ACID_Button','button', 'TRY_DELETE')[@options],	
																'{"readVars":[], "readObj":"1", "action":"ABASANSPRECHPARTNER_DELETE_ACID_Button"}' [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('ABASANSPRECHPARTNER_DELETE_ACID_Button'), TYPE)												
							
 
								FOR XML PATH('abasansprechpartner'), TYPE)   
							FROM ABASANSPRECHPARTNER tf WHERE PK = @PK
						FOR XML PATH(''),ROOT('abasansprechpartners')),1,0,'')	
		),''))
	RETURN @XML_ABASANSPRECHPARTNERS
END
