 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'1'[@readonly],  (SELECT TOP 1 subtable.companyname FROM MANDANT subtable WHERE subtable.id = tf.mandant)  AS '*'  FOR XML PATH('companyname'), TYPE)			
							
														,(SELECT 
																3[@labelColumn], 1[@labelRow], 4[@elementColumn], 1[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'CSAPP_version_URL','PK','inputText',  ISNULL(PK,'') )[@options],												
 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'1'[@readonly],  PK  AS '*'  FOR XML PATH('PK'), TYPE)			
							
