 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  DATE_INSERTED  AS '*'  FOR XML PATH('DATE_INSERTED'), TYPE)			
							
														,(SELECT 
																3[@labelColumn], 6[@labelRow], 4[@elementColumn], 6[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'UPDATES','DATE_UPDATE','inputText',  ISNULL(DATE_UPDATE,'') )[@options],												
 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  DATE_UPDATE  AS '*'  FOR XML PATH('DATE_UPDATE'), TYPE)			
							
														,(SELECT 
																1[@labelColumn], 7[@labelRow], 2[@elementColumn], 7[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'UPDATES','UPDATES_UPDATE_ACID_Button','button', 'TRY_UPDATE')[@options],	
																'{"readVars":[], "readObj":"1", "action":"UPDATES_UPDATE_ACID_Button"}' [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('UPDATES_UPDATE_ACID_Button'), TYPE)												
							
														,(SELECT 
																3[@labelColumn], 7[@labelRow], 4[@elementColumn], 7[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'UPDATES','UPDATES_INSERT_ACID_Button','button', 'TRY_INSERT_NEW')[@options],	
																'{"readVars":[], "readObj":"1", "action":"UPDATES_INSERT_ACID_Button"}' [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('UPDATES_INSERT_ACID_Button'), TYPE)												
							
														,(SELECT 
																1[@labelColumn], 8[@labelRow], 2[@elementColumn], 8[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'UPDATES','UPDATES_DELETE_ACID_Button','button', 'TRY_DELETE')[@options],	
																'{"readVars":[], "readObj":"1", "action":"UPDATES_DELETE_ACID_Button"}' [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('UPDATES_DELETE_ACID_Button'), TYPE)												
							
 
								FOR XML PATH('updates'), TYPE)   
							FROM UPDATES tf WHERE PK = @PK
						FOR XML PATH(''),ROOT('updatess')),1,0,'')	
		),''))
	RETURN @XML_UPDATESS
END
