 																'30'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  command  AS '*'  FOR XML PATH('command'), TYPE)			
							
														,(SELECT 
																1[@labelColumn], 3[@labelRow], 2[@elementColumn], 3[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES(PK, 'ZZEXECJOBS','ZZEXECJOBS_UPDATE_ACID_Button','button', 'TRY_UPDATE')[@options],	
																'{"readVars":[], "readObj":"1", "action":"ZZEXECJOBS_UPDATE_ACID_Button"}' [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('ZZEXECJOBS_UPDATE_ACID_Button'), TYPE)												
							
														,(SELECT 
