																'{"readVars":[], "readObj":"1", "action":"ZZEXECJOBS_INSERT_ACID_Button"}' [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('ZZEXECJOBS_INSERT_ACID_Button'), TYPE)												
							
