--GO
CREATE FUNCTION [dbo].[__fnSEARCH_ON_ABASANSPRECHPARTNER_BY_TERMS](@searchTerms NVARCHAR(MAX) = '', @INSERT_INT_DEFAULT_VALUE INT = NULL, @INSERT_STR_DEFAULT_VALUE VARCHAR(128) = NULL)
RETURNS @ABASANSPRECHPARTNER_RESULTS TABLE (master_identity_id INT NOT NULL IDENTITY(1,1), PK INT NULL, abasId INT NULL, firmenName NVARCHAR(255) NULL, betreuer NVARCHAR(255) NULL, companyname NVARCHAR(255) NULL, ABASANSPRECHPARTNER_ACID_Button NVARCHAR(512) NULL) --Author José. Erstellt am 2021-04-06T23:23:43.967
BEGIN
    DECLARE @ABASANSPRECHPARTNER_searchBy_PK NVARCHAR(255) = ''    DECLARE @ABASANSPRECHPARTNER_searchBy_abasId NVARCHAR(255) = ''    DECLARE @ABASANSPRECHPARTNER_searchBy_firmenName NVARCHAR(255) = ''    DECLARE @ABASANSPRECHPARTNER_searchBy_betreuer NVARCHAR(255) = ''    DECLARE @ABASANSPRECHPARTNER_searchBy_companyname NVARCHAR(255) = NULL 
	DECLARE @ABASANSPRECHPARTNER TABLE (PK INT NULL, abasId INT NULL, firmenName NVARCHAR(255) NULL, betreuer NVARCHAR(255) NULL)
 
    SET @ABASANSPRECHPARTNER_searchBy_PK = ISNULL((SELECT TOP 1 REPLACE(Aval,'PK=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'PK=%'),'') 
    SET @ABASANSPRECHPARTNER_searchBy_abasId = ISNULL((SELECT TOP 1 REPLACE(Aval,'abasId=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'abasId=%'),'') 
    SET @ABASANSPRECHPARTNER_searchBy_firmenName = ISNULL((SELECT TOP 1 REPLACE(Aval,'firmenName=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'firmenName=%'),'') 
    SET @ABASANSPRECHPARTNER_searchBy_betreuer = ISNULL((SELECT TOP 1 REPLACE(Aval,'betreuer=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'betreuer=%'),'') 
    SET @ABASANSPRECHPARTNER_searchBy_companyname = ISNULL((SELECT TOP 1 REPLACE(Aval,'companyname=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'companyname=%'),'')    
	IF (ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1 AND ISNULL(@INSERT_STR_DEFAULT_VALUE,'')<>'')
		INSERT INTO @ABASANSPRECHPARTNER_RESULTS (ABASANSPRECHPARTNER_ACID_Button)
			SELECT @INSERT_STR_DEFAULT_VALUE
 
    IF (@ABASANSPRECHPARTNER_searchBy_PK<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('ABASANSPRECHPARTNER','PK',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@ABASANSPRECHPARTNER_searchBy_PK)=0)
				SET @ABASANSPRECHPARTNER_searchBy_PK=@INSERT_INT_DEFAULT_VALUE
			UPDATE @ABASANSPRECHPARTNER_RESULTS SET PK = @ABASANSPRECHPARTNER_searchBy_PK WHERE ABASANSPRECHPARTNER_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@ABASANSPRECHPARTNER_searchBy_abasId<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('ABASANSPRECHPARTNER','abasId',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@ABASANSPRECHPARTNER_searchBy_abasId)=0)
				SET @ABASANSPRECHPARTNER_searchBy_abasId=@INSERT_INT_DEFAULT_VALUE
			UPDATE @ABASANSPRECHPARTNER_RESULTS SET abasId = @ABASANSPRECHPARTNER_searchBy_abasId WHERE ABASANSPRECHPARTNER_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@ABASANSPRECHPARTNER_searchBy_firmenName<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('ABASANSPRECHPARTNER','firmenName',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@ABASANSPRECHPARTNER_searchBy_firmenName)=0)
				SET @ABASANSPRECHPARTNER_searchBy_firmenName=@INSERT_INT_DEFAULT_VALUE
			UPDATE @ABASANSPRECHPARTNER_RESULTS SET firmenName = @ABASANSPRECHPARTNER_searchBy_firmenName WHERE ABASANSPRECHPARTNER_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@ABASANSPRECHPARTNER_searchBy_betreuer<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('ABASANSPRECHPARTNER','betreuer',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@ABASANSPRECHPARTNER_searchBy_betreuer)=0)
				SET @ABASANSPRECHPARTNER_searchBy_betreuer=@INSERT_INT_DEFAULT_VALUE
			UPDATE @ABASANSPRECHPARTNER_RESULTS SET betreuer = @ABASANSPRECHPARTNER_searchBy_betreuer WHERE ABASANSPRECHPARTNER_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@ABASANSPRECHPARTNER_searchBy_companyname<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('ABASANSPRECHPARTNER','companyname',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@ABASANSPRECHPARTNER_searchBy_companyname)=0)
				SET @ABASANSPRECHPARTNER_searchBy_companyname=@INSERT_INT_DEFAULT_VALUE
			UPDATE @ABASANSPRECHPARTNER_RESULTS SET companyname = @ABASANSPRECHPARTNER_searchBy_companyname WHERE ABASANSPRECHPARTNER_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					     
    INSERT INTO @ABASANSPRECHPARTNER_RESULTS([PK],[abasId],[firmenName],[betreuer], ABASANSPRECHPARTNER_ACID_Button)
		SELECT [PK],[abasId],[firmenName],[betreuer],'bearbeiten' FROM ABASANSPRECHPARTNER WHERE  (ISNULL(PK,'') LIKE '%'+@ABASANSPRECHPARTNER_searchBy_PK+'%') 		 			
					  AND (ISNULL(abasId,'') LIKE '%'+@ABASANSPRECHPARTNER_searchBy_abasId+'%') 		 			
					  AND (ISNULL(firmenName,'') LIKE '%'+@ABASANSPRECHPARTNER_searchBy_firmenName+'%') 		 			
					  AND (ISNULL(betreuer,'') LIKE '%'+@ABASANSPRECHPARTNER_searchBy_betreuer+'%') 		 			
					  AND (abasId IN (SELECT abasId FROM mandant WHERE companyname LIKE '%'+@ABASANSPRECHPARTNER_searchBy_companyname+'%'))	
					 
			UPDATE destinationTable  
				SET destinationTable.companyname = originTable.companyname
			FROM @ABASANSPRECHPARTNER_RESULTS destinationTable, mandant originTable WHERE originTable.abasId = destinationTable.abasId  	

						 
	RETURN
END
GO
