					  AND (ISNULL(version,'') LIKE '%'+@CSAPP_version_URL_searchBy_version+'%') 		 			
					  AND (ISNULL(APP_TYPE,'') LIKE '%'+@CSAPP_version_URL_searchBy_APP_TYPE+'%') 		 			
					  AND (mandant IN (SELECT id FROM MANDANT WHERE companyname LIKE '%'+@CSAPP_version_URL_searchBy_companyname+'%'))	
					 
