    SET @MANDANT_DB_ENVIRONMENT_MANDANTSearchByCompanyname = ISNULL((SELECT TOP 1 REPLACE(Aval,'mandant_companyname=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'mandant_companyname=%'),'')    
	IF (ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1 AND ISNULL(@INSERT_STR_DEFAULT_VALUE,'')<>'')
		INSERT INTO @MANDANT_DB_ENVIRONMENT_RESULTS (MANDANT_DB_ENVIRONMENT_ACID_Button)
			SELECT @INSERT_STR_DEFAULT_VALUE
 
    IF (@MANDANT_DB_ENVIRONMENTSearchBymandant_id<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('MANDANT_DB_ENVIRONMENT','mandant_id',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@MANDANT_DB_ENVIRONMENTSearchBymandant_id)=0)
				SET @MANDANT_DB_ENVIRONMENTSearchBymandant_id=@INSERT_INT_DEFAULT_VALUE
			UPDATE @MANDANT_DB_ENVIRONMENT_RESULTS SET mandant_id = @MANDANT_DB_ENVIRONMENTSearchBymandant_id WHERE MANDANT_DB_ENVIRONMENT_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@MANDANT_DB_ENVIRONMENTSearchByPK<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('MANDANT_DB_ENVIRONMENT','PK',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@MANDANT_DB_ENVIRONMENTSearchByPK)=0)
				SET @MANDANT_DB_ENVIRONMENTSearchByPK=@INSERT_INT_DEFAULT_VALUE
			UPDATE @MANDANT_DB_ENVIRONMENT_RESULTS SET PK = @MANDANT_DB_ENVIRONMENTSearchByPK WHERE MANDANT_DB_ENVIRONMENT_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@MANDANT_DB_ENVIRONMENTSearchByversion<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('MANDANT_DB_ENVIRONMENT','version',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@MANDANT_DB_ENVIRONMENTSearchByversion)=0)
				SET @MANDANT_DB_ENVIRONMENTSearchByversion=@INSERT_INT_DEFAULT_VALUE
			UPDATE @MANDANT_DB_ENVIRONMENT_RESULTS SET version = @MANDANT_DB_ENVIRONMENTSearchByversion WHERE MANDANT_DB_ENVIRONMENT_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					     
    INSERT INTO @MANDANT_DB_ENVIRONMENT_RESULTS ([mandant_id],[PK],[version],  MANDANT_DB_ENVIRONMENT_ACID_Button)
		SELECT [mandant_id],[PK],[version], 'bearbeiten' FROM MANDANT_DB_ENVIRONMENT 
				   WHERE  (ISNULL(mandant_id,'') LIKE '%'+@MANDANT_DB_ENVIRONMENTSearchBymandant_id+'%') 		 			
					  AND (ISNULL(PK,'') LIKE '%'+@MANDANT_DB_ENVIRONMENTSearchByPK+'%') 		 			
					  AND (ISNULL(version,'') LIKE '%'+@MANDANT_DB_ENVIRONMENTSearchByversion+'%') 		 			
					  AND  (mandant_id IN (SELECT id FROM dbo.Mandant WHERE companyname LIKE '%'+@MANDANT_DB_ENVIRONMENT_MANDANTSearchByCompanyname+'%')  ) 	
			UPDATE  me  
				SET me.companyname = m.companyname
			FROM @MANDANT_DB_ENVIRONMENT_RESULTS me, dbo.Mandant m WHERE m.id = me.mandant_id  		
					 
	RETURN
END
