CREATE FUNCTION [dbo].[__fnSEARCH_ON_NLCUSTOMERDATABASES_BY_TERMS](@searchTerms NVARCHAR(MAX) = '', @INSERT_INT_DEFAULT_VALUE INT = NULL, @INSERT_STR_DEFAULT_VALUE VARCHAR(128) = NULL)
RETURNS @NLCUSTOMERDATABASES_RESULTS TABLE (master_identity_id INT NOT NULL IDENTITY(1,1), DBSVRINST NVARCHAR(255) NULL, databaseName NVARCHAR(255) NULL, AbasID NVARCHAR(255) NULL, PK INT NULL, NLCUSTOMERDATABASES_ACID_Button NVARCHAR(512) NULL) --Author José. Erstellt am 2021-04-08T11:53:33.793
BEGIN
    DECLARE @NLCUSTOMERDATABASES_searchBy_DBSVRINST NVARCHAR(255) = ''    DECLARE @NLCUSTOMERDATABASES_searchBy_databaseName NVARCHAR(255) = ''    DECLARE @NLCUSTOMERDATABASES_searchBy_AbasID NVARCHAR(255) = ''    DECLARE @NLCUSTOMERDATABASES_searchBy_PK NVARCHAR(255) = ''
	DECLARE @NLCUSTOMERDATABASES TABLE (DBSVRINST NVARCHAR(255) NULL, databaseName NVARCHAR(255) NULL, AbasID NVARCHAR(255) NULL, PK INT NULL)
 
    SET @NLCUSTOMERDATABASES_searchBy_DBSVRINST = ISNULL((SELECT TOP 1 REPLACE(Aval,'DBSVRINST=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'DBSVRINST=%'),'') 
    SET @NLCUSTOMERDATABASES_searchBy_databaseName = ISNULL((SELECT TOP 1 REPLACE(Aval,'databaseName=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'databaseName=%'),'') 
    SET @NLCUSTOMERDATABASES_searchBy_AbasID = ISNULL((SELECT TOP 1 REPLACE(Aval,'AbasID=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'AbasID=%'),'') 
    SET @NLCUSTOMERDATABASES_searchBy_PK = ISNULL((SELECT TOP 1 REPLACE(Aval,'PK=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'PK=%'),'')    
	IF (ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1 AND ISNULL(@INSERT_STR_DEFAULT_VALUE,'')<>'')
		INSERT INTO @NLCUSTOMERDATABASES_RESULTS (NLCUSTOMERDATABASES_ACID_Button)
			SELECT @INSERT_STR_DEFAULT_VALUE
 
    IF (@NLCUSTOMERDATABASES_searchBy_DBSVRINST<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('NLCUSTOMERDATABASES','DBSVRINST',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@NLCUSTOMERDATABASES_searchBy_DBSVRINST)=0)
				SET @NLCUSTOMERDATABASES_searchBy_DBSVRINST=@INSERT_INT_DEFAULT_VALUE
			UPDATE @NLCUSTOMERDATABASES_RESULTS SET DBSVRINST = @NLCUSTOMERDATABASES_searchBy_DBSVRINST WHERE NLCUSTOMERDATABASES_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@NLCUSTOMERDATABASES_searchBy_databaseName<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('NLCUSTOMERDATABASES','databaseName',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@NLCUSTOMERDATABASES_searchBy_databaseName)=0)
				SET @NLCUSTOMERDATABASES_searchBy_databaseName=@INSERT_INT_DEFAULT_VALUE
			UPDATE @NLCUSTOMERDATABASES_RESULTS SET databaseName = @NLCUSTOMERDATABASES_searchBy_databaseName WHERE NLCUSTOMERDATABASES_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@NLCUSTOMERDATABASES_searchBy_AbasID<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('NLCUSTOMERDATABASES','AbasID',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@NLCUSTOMERDATABASES_searchBy_AbasID)=0)
				SET @NLCUSTOMERDATABASES_searchBy_AbasID=@INSERT_INT_DEFAULT_VALUE
			UPDATE @NLCUSTOMERDATABASES_RESULTS SET AbasID = @NLCUSTOMERDATABASES_searchBy_AbasID WHERE NLCUSTOMERDATABASES_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@NLCUSTOMERDATABASES_searchBy_PK<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('NLCUSTOMERDATABASES','PK',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@NLCUSTOMERDATABASES_searchBy_PK)=0)
				SET @NLCUSTOMERDATABASES_searchBy_PK=@INSERT_INT_DEFAULT_VALUE
			UPDATE @NLCUSTOMERDATABASES_RESULTS SET PK = @NLCUSTOMERDATABASES_searchBy_PK WHERE NLCUSTOMERDATABASES_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					     
    INSERT INTO @NLCUSTOMERDATABASES_RESULTS([DBSVRINST],[databaseName],[AbasID],[PK], NLCUSTOMERDATABASES_ACID_Button)
		SELECT [DBSVRINST],[databaseName],[AbasID],[PK],'bearbeiten' FROM NLCUSTOMERDATABASES WHERE  (ISNULL(DBSVRINST,'') LIKE '%'+@NLCUSTOMERDATABASES_searchBy_DBSVRINST+'%') 		 			
					  AND (ISNULL(databaseName,'') LIKE '%'+@NLCUSTOMERDATABASES_searchBy_databaseName+'%') 		 			
					  AND (ISNULL(AbasID,'') LIKE '%'+@NLCUSTOMERDATABASES_searchBy_AbasID+'%') 		 			
					  AND (ISNULL(PK,'') LIKE '%'+@NLCUSTOMERDATABASES_searchBy_PK+'%') 		 			
					 
	RETURN
END
GO
