    DECLARE @TSUSERS_searchBy_customer_id NVARCHAR(255) = ''    DECLARE @TSUSERS_searchBy_PK NVARCHAR(255) = ''    DECLARE @TSUSERS_searchBy_InitialPass NVARCHAR(255) = ''    DECLARE @TSUSERS_searchBy_aktiv NVARCHAR(255) = ''    DECLARE @TSUSERS_searchBy_companyname NVARCHAR(255) = NULL 
	DECLARE @TSUSERS TABLE (customer_id INT NULL, PK INT NULL, InitialPass NVARCHAR(255) NULL, aktiv BIT NULL)
 
    SET @TSUSERS_searchBy_customer_id = ISNULL((SELECT TOP 1 REPLACE(Aval,'customer_id=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'customer_id=%'),'') 
    SET @TSUSERS_searchBy_PK = ISNULL((SELECT TOP 1 REPLACE(Aval,'PK=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'PK=%'),'') 
    SET @TSUSERS_searchBy_InitialPass = ISNULL((SELECT TOP 1 REPLACE(Aval,'InitialPass=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'InitialPass=%'),'') 
    SET @TSUSERS_searchBy_aktiv = ISNULL((SELECT TOP 1 REPLACE(Aval,'aktiv=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'aktiv=%'),'') 
    SET @TSUSERS_searchBy_companyname = ISNULL((SELECT TOP 1 REPLACE(Aval,'companyname=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,';') WHERE Aval LIKE 'companyname=%'),'')    
	IF (ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1 AND ISNULL(@INSERT_STR_DEFAULT_VALUE,'')<>'')
		INSERT INTO @TSUSERS_RESULTS (TSUSERS_ACID_Button)
			SELECT @INSERT_STR_DEFAULT_VALUE
 
    IF (@TSUSERS_searchBy_customer_id<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('TSUSERS','customer_id',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@TSUSERS_searchBy_customer_id)=0)
				SET @TSUSERS_searchBy_customer_id=@INSERT_INT_DEFAULT_VALUE
			UPDATE @TSUSERS_RESULTS SET customer_id = @TSUSERS_searchBy_customer_id WHERE TSUSERS_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@TSUSERS_searchBy_PK<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('TSUSERS','PK',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@TSUSERS_searchBy_PK)=0)
				SET @TSUSERS_searchBy_PK=@INSERT_INT_DEFAULT_VALUE
			UPDATE @TSUSERS_RESULTS SET PK = @TSUSERS_searchBy_PK WHERE TSUSERS_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@TSUSERS_searchBy_InitialPass<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('TSUSERS','InitialPass',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@TSUSERS_searchBy_InitialPass)=0)
				SET @TSUSERS_searchBy_InitialPass=@INSERT_INT_DEFAULT_VALUE
			UPDATE @TSUSERS_RESULTS SET InitialPass = @TSUSERS_searchBy_InitialPass WHERE TSUSERS_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@TSUSERS_searchBy_aktiv<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('TSUSERS','aktiv',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@TSUSERS_searchBy_aktiv)=0)
				SET @TSUSERS_searchBy_aktiv=@INSERT_INT_DEFAULT_VALUE
			UPDATE @TSUSERS_RESULTS SET aktiv = @TSUSERS_searchBy_aktiv WHERE TSUSERS_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					  
    IF (@TSUSERS_searchBy_companyname<>'' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('TSUSERS','companyname',DEFAULT) LIKE '%INT%' AND ISNUMERIC(@TSUSERS_searchBy_companyname)=0)
				SET @TSUSERS_searchBy_companyname=@INSERT_INT_DEFAULT_VALUE
			UPDATE @TSUSERS_RESULTS SET companyname = @TSUSERS_searchBy_companyname WHERE TSUSERS_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					     
    INSERT INTO @TSUSERS_RESULTS([customer_id],[PK],[InitialPass],[aktiv], TSUSERS_ACID_Button)
		SELECT [customer_id],[PK],[InitialPass],[aktiv],'bearbeiten' FROM TSUSERS WHERE  (ISNULL(customer_id,'') LIKE '%'+@TSUSERS_searchBy_customer_id+'%') 		 			
					  AND (ISNULL(PK,'') LIKE '%'+@TSUSERS_searchBy_PK+'%') 		 			
					  AND (ISNULL(InitialPass,'') LIKE '%'+@TSUSERS_searchBy_InitialPass+'%') 		 			
					  AND (ISNULL(aktiv,'') LIKE '%'+@TSUSERS_searchBy_aktiv+'%') 		 			
					  AND (customer_id IN (SELECT id FROM mandant WHERE companyname LIKE '%'+@TSUSERS_searchBy_companyname+'%'))	
					 
			UPDATE destinationTable  
				SET destinationTable.companyname = originTable.companyname
			FROM @TSUSERS_RESULTS destinationTable, mandant originTable WHERE originTable.id = destinationTable.customer_id  	

						 
	RETURN
END
GO
