--GO
CREATE FUNCTION [dbo].[__fnSEARCH_XML_ABASANSPRECHPARTNER_BY_TERMS](@searchTerms NVARCHAR(MAX) = '')
RETURNS NVARCHAR(MAX) --Author José. Erstellt am 2021-04-06T23:23:44.080
BEGIN 
    --UPDATE @ABASANSPRECHPARTNER_RESULTS SET PK = -4000 WHERE ABASANSPRECHPARTNER_ACID_Button = 'suchen'
	DECLARE @XML_ABASANSPRECHPARTNERS NVARCHAR(MAX) =
		(ISNULL((
				STUFF(( 
						SELECT 
									(SELECT ISNULL(PK,-4000)[@PK] 
										
														,(SELECT 
																1[@labelColumn], master_identity_id[@labelRow], 2[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'ABASANSPRECHPARTNER','companyname','inputText',  companyname,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  companyname  AS '*'  FOR XML PATH('companyname'), TYPE)			
							
														,(SELECT 
																3[@labelColumn], master_identity_id[@labelRow], 4[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'ABASANSPRECHPARTNER','PK','inputText',   PK,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'inputText'[@type],'1'[@readonly],  CASE WHEN PK IS NOT NULL THEN CAST(PK AS NVARCHAR(MAX)) ELSE '' END  AS '*'  FOR XML PATH('PK'), TYPE)			
							
														,(SELECT 
																5[@labelColumn], master_identity_id[@labelRow], 6[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'ABASANSPRECHPARTNER','abasId','inputText',   abasId,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  abasId  AS '*'  FOR XML PATH('abasId'), TYPE)			
							
														,(SELECT 
																7[@labelColumn], master_identity_id[@labelRow], 8[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'ABASANSPRECHPARTNER','firmenName','inputText',   firmenName,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  firmenName  AS '*'  FOR XML PATH('firmenName'), TYPE)			
							
														,(SELECT 
																9[@labelColumn], master_identity_id[@labelRow], 10[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'ABASANSPRECHPARTNER','betreuer','inputText',   betreuer,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  betreuer  AS '*'  FOR XML PATH('betreuer'), TYPE)			
							
														,(SELECT 
																11[@labelColumn], master_identity_id[@labelRow], 12[@elementColumn], master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'ABASANSPRECHPARTNER','ABASANSPRECHPARTNER_ACID_Button','button', ISNULL(ABASANSPRECHPARTNER_ACID_Button,''),NULL, NULL)[@options], 
																CASE WHEN ISNULL(ABASANSPRECHPARTNER_ACID_Button,'') = 'suchen' 
																	THEN '{"readVars":[], "readObj":"1", "action":"suchen"}' 
																	ELSE '{"readVars":[], "readObj":"1", "action":"open_object_details"}' END [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('ABASANSPRECHPARTNER_ACID_Button'), TYPE)												
							
 
								FOR XML PATH('abasansprechpartner'), TYPE)   
							FROM dbo.__fnSEARCH_ON_ABASANSPRECHPARTNER_BY_TERMS(@searchTerms,-4000,'suchen') --WHERE PK IN (SELECT PK FROM @ABASANSPRECHPARTNER)
						FOR XML PATH(''),ROOT('abasansprechpartners')),1,0,'')	
		),''))
	 
	RETURN @XML_ABASANSPRECHPARTNERS  
END
--GO
