    --UPDATE @TSUSERS_RESULTS SET PK = -4000 WHERE TSUSERS_ACID_Button = 'suchen'
	DECLARE @XML_TSUSERSS NVARCHAR(MAX) =
		(ISNULL((
				STUFF(( 
						SELECT 
									(SELECT ISNULL(PK,-4000)[@PK] 
										
														,(SELECT 
																1[@labelColumn], master_identity_id[@labelRow], 2[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'TSUSERS','companyname','inputText',  companyname,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  companyname  AS '*'  FOR XML PATH('companyname'), TYPE)			
							
														,(SELECT 
																3[@labelColumn], master_identity_id[@labelRow], 4[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'TSUSERS','customer_id','inputText',   customer_id,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  customer_id  AS '*'  FOR XML PATH('customer_id'), TYPE)			
							
														,(SELECT 
																5[@labelColumn], master_identity_id[@labelRow], 6[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'TSUSERS','PK','inputText',   PK,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'inputText'[@type],'1'[@readonly],  CASE WHEN PK IS NOT NULL THEN CAST(PK AS NVARCHAR(MAX)) ELSE '' END  AS '*'  FOR XML PATH('PK'), TYPE)			
							
														,(SELECT 
																7[@labelColumn], master_identity_id[@labelRow], 8[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'TSUSERS','InitialPass','inputText',   InitialPass,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'inputText'[@type],'0'[@readonly],  InitialPass  AS '*'  FOR XML PATH('InitialPass'), TYPE)			
							
														,(SELECT 
																9[@labelColumn], master_identity_id[@labelRow], 10[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'TSUSERS','aktiv','checkbox',   aktiv,NULL, NULL )[@options],																																												
 																'10'[@labelWith],'50'[@textWith],'checkbox'[@type],'0'[@readonly],  aktiv  AS '*'  FOR XML PATH('aktiv'), TYPE)			
							
														,(SELECT 
																11[@labelColumn], master_identity_id[@labelRow], 12[@elementColumn], master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE(PK, 'TSUSERS','TSUSERS_ACID_Button','button', ISNULL(TSUSERS_ACID_Button,''),NULL, NULL)[@options], 
																CASE WHEN ISNULL(TSUSERS_ACID_Button,'') = 'suchen' 
																	THEN '{"readVars":[], "readObj":"1", "action":"suchen"}' 
																	ELSE '{"readVars":[], "readObj":"1", "action":"open_object_details"}' END [@onClickAction],																											
 																'30'[@labelWith],'50'[@textWith],'button'[@type],'0'[@readonly], '' AS '*'  FOR XML PATH('TSUSERS_ACID_Button'), TYPE)												
							
 
								FOR XML PATH('tsusers'), TYPE)   
							FROM dbo.__fnSEARCH_ON_TSUSERS_BY_TERMS(@searchTerms,-4000,'suchen') --WHERE PK IN (SELECT PK FROM @TSUSERS)
						FOR XML PATH(''),ROOT('tsuserss')),1,0,'')	
		),''))
	 
	RETURN @XML_TSUSERSS  
END
