CREATE FUNCTION [dbo].[__generator_FUNCTION_SEARCH_ON_TABLE_BY_TERMS](@table NVARCHAR(255) = 'mandant', @tableColumnIdentity VARCHAR(255) = 'ID', @searchOnFields VARCHAR(MAX) = 'id;companyname;email;AbasId', @searchOnFieldSeparator VARCHAR(1) = ';')  
RETURNS @fnDefinition TABLE   (functionName VARCHAR(MAX) NULL, functionDefinition VARCHAR(MAX) NULL)
BEGIN --Author José 
		IF (EXISTS (SELECT * FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA = 'dbo' AND TABLE_NAME = @table))
			BEGIN 
				DECLARE @functionName NVARCHAR(MAX) = '' 
				DECLARE @searchPrefixField NVARCHAR(128) = '_searchBy_'
			 
				SET @table = UPPER(@table) 
				SET @functionName = '__fnSEARCH_ON_'+@table+'_BY_TERMS' 
				DECLARE @functionDefinitionReplacement VARCHAR(MAX) = '' 
				
				SET @tableColumnIdentity = ISNULL((SELECT TOP 1 UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS 		WHERE  COLUMNPROPERTY(object_id(TABLE_SCHEMA+'.'+TABLE_NAME), COLUMN_NAME, 'IsIdentity') = 1 AND TABLE_NAME = @table),@tableColumnIdentity)  
				DECLARE @validFields TABLE (fieldName NVARCHAR(255) NULL, ownField BIT NULL)
				INSERT INTO @validFields  ( fieldName, ownField )
					SELECT COLUMN_NAME, 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @table AND COLUMN_NAME IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchOnFields,@searchOnFieldSeparator)) 
				INSERT INTO @validFields  ( fieldName, ownField )
					SELECT fieldAlias,0 FROM dbo.TABLE_RELATION(@table) WHERE fieldAlias IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchOnFields,@searchOnFieldSeparator)) 
				DECLARE @functionDefinition VARCHAR(MAX) =
'
--IF EXISTS (SELECT * FROM sys.objects WHERE object_id = OBJECT_ID(N'''+@functionName+''') AND type IN ( N''TF''))
	--DROP FUNCTION dbo.'+@functionName+' 
--GO
CREATE FUNCTION dbo.'+@functionName+'(@searchTerms NVARCHAR(MAX) = '''', @INSERT_INT_DEFAULT_VALUE INT = NULL, @INSERT_STR_DEFAULT_VALUE VARCHAR(128) = NULL)
RETURNS TABLE_DEFINITION_REPLACEMENT --Author José. Erstellt am '+dbo.GET_ISO_DATETIME(DEFAULT,DEFAULT)+'
BEGIN
TSQL_ON_SEARCH_LOGIC_REPLACEMENT
	RETURN
END'		END

	    DECLARE @_RESULT_LOGIC_DEFINITION VARCHAR(MAX)=''
		--DECLARE @table NVARCHAR(255) = 'mandant'
		--DECLARE @tableFields NVARCHAR(2048) = 'id;companyname;email;AbasId'
		DECLARE @searchTermTableDef NVARCHAR(MAX) =  ''
		DECLARE @searchTableHeaderFunctionDefinition NVARCHAR(MAX) =  ''
		DECLARE @validFieldCounter INT = 0
		DECLARE @searchTermDefinitionsTMPTable NVARCHAR(MAX) =  dbo.getVariableDefinitionFromTableAsTMPTable(@table,@searchOnFields, @searchOnFieldSeparator, 1)
		DECLARE @searchTermDefinitionsTABLE_RELATIONS NVARCHAR(MAX) =  dbo.getVariableDefinitionFromTableRelations(@table,'DECLARE',@searchOnFields, @searchOnFieldSeparator)
		DECLARE @searchTermDefinitions NVARCHAR(MAX) =  dbo.getVariableDefinitionFromTableReplaceDataType(@table,'DECLARE',@searchOnFields,@searchOnFieldSeparator,DEFAULT)+@searchTermDefinitionsTABLE_RELATIONS
		
		SET @validFieldCounter = ISNULL((SELECT COUNT(*) FROM @validFields),0)
		--SET @searchTermTableDef = dbo.getVariableDefinitionFromTable(@table,'DECLARE',@searchOnFields,@searchOnFieldSeparator)
		SET @searchTermTableDef = dbo.getVariableDefinitionFromTableAsTMPTable(@table, @searchOnFields,@searchOnFieldSeparator, 0)
		SET @searchTermDefinitions = REPLACE(@searchTermDefinitions,'DECLARE @','DECLARE @'+@table+@searchPrefixField)
		SET @searchTermDefinitions = REPLACE(@searchTermDefinitions,'DECLARE @','    DECLARE @')
 
		
		SET @searchTableHeaderFunctionDefinition = '@'+@table+'_RESULTS TABLE (master_identity_id INT NOT NULL IDENTITY(1,1), '+@searchTermTableDef+', '+@table+'_ACID_Button NVARCHAR(512) NULL)'
		IF (@searchTermDefinitionsTMPTable <> '')
			SET @searchTableHeaderFunctionDefinition = '@'+@table+'_RESULTS TABLE (master_identity_id INT NOT NULL IDENTITY(1,1), '+@searchTermTableDef+', '+@searchTermDefinitionsTMPTable+', '+@table+'_ACID_Button NVARCHAR(512) NULL)'
			
		SET @searchTermTableDef = 
'
	DECLARE @'+@table+' TABLE ('+@searchTermTableDef+')
'
		SET @functionDefinition = REPLACE(@functionDefinition,'TABLE_DEFINITION_REPLACEMENT',@searchTableHeaderFunctionDefinition)
		SET @searchTermTableDef = @searchTermDefinitions + REPLACE(@searchTermTableDef,', )',')')
 
			DECLARE @tsqlBuildingValidSyntax XML    
			DECLARE @tsqlBuildingValidSyntaxRelFields XML    
			SET @tsqlBuildingValidSyntax = (
				SELECT N' 
    SET @'+@table+@searchPrefixField+fieldName+' = ISNULL((SELECT TOP 1 REPLACE(Aval,'''+fieldName+'='','''') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,'';'') WHERE Aval LIKE '''+fieldName+'=%''),'''')'
				FROM @validFields
				FOR XML PATH(''), ROOT('result')
			,TYPE) 
			IF (ISNULL(@tsqlBuildingValidSyntax.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'') <> '') 
				SELECT @searchTermTableDef +=  @tsqlBuildingValidSyntax.value('/result[1]/text()[1]', 'NVARCHAR(MAX)') 
		SET @searchTermTableDef +=
'    
	IF (ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1 AND ISNULL(@INSERT_STR_DEFAULT_VALUE,'''')<>'''')
		INSERT INTO @'+@table+'_RESULTS ('+@table+'_ACID_Button)
			SELECT @INSERT_STR_DEFAULT_VALUE
'
			SET @tsqlBuildingValidSyntax = (
				SELECT N' 
    IF (@'+@table+@searchPrefixField+fieldName+'<>'''' AND ISNUMERIC(@INSERT_INT_DEFAULT_VALUE)=1)
		BEGIN
			IF(dbo.fn_GetTFieldDDL('''+@table+''','''+fieldName+''',DEFAULT) LIKE ''%INT%'' AND ISNUMERIC(@'+@table+@searchPrefixField+fieldName+')=0)
				SET @'+@table+@searchPrefixField+fieldName+'=@INSERT_INT_DEFAULT_VALUE
			UPDATE @'+@table+'_RESULTS SET '+fieldName+' = @'+@table+@searchPrefixField+fieldName+' WHERE '+@table+'_ACID_Button = @INSERT_STR_DEFAULT_VALUE
		END					 			
					 '
				FROM @validFields
				FOR XML PATH(''), ROOT('result')
			,TYPE) 
			IF (ISNULL(@tsqlBuildingValidSyntax.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'') <> '') 
				SELECT @searchTermTableDef +=  @tsqlBuildingValidSyntax.value('/result[1]/text()[1]', 'NVARCHAR(MAX)')  
			DECLARE @searchWhereCondition NVARCHAR(MAX) = ''
			SET @tsqlBuildingValidSyntax = (
				SELECT N' AND (ISNULL('+fieldName+','''') LIKE ''%''+@'+@table+@searchPrefixField+fieldName+'+''%'') 		 			
					 '
				FROM @validFields WHERE ownField = 1
				FOR XML PATH(''), ROOT('result')
			,TYPE) 
			SET @searchWhereCondition = ISNULL(@tsqlBuildingValidSyntax.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'') 
			---SELECT * FROM dbo.TABLE_RELATION('MANDANT_DB_ENVIRONMENT')
			SET @tsqlBuildingValidSyntaxRelFields = (
				SELECT N' AND ('+toField+' IN (SELECT '+fromField+' FROM '+fromTable+' WHERE '+fieldAlias+' LIKE ''%''+@'+@table+@searchPrefixField+fieldAlias+'+''%''))	
					 '
				FROM dbo.TABLE_RELATION(@table) WHERE fieldAlias IN (SELECT fieldName FROM @validFields where ownField = 0) 
				FOR XML PATH(''), ROOT('result')
			,TYPE) 
			SET @searchWhereCondition += ISNULL(@tsqlBuildingValidSyntaxRelFields.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'')   
			IF (ISNULL(@searchWhereCondition,'') <> '') 
				BEGIN
					SET @searchTermTableDef +=
'    
    INSERT INTO @'+@table+'_RESULTS('+dbo.OBJECT_GET_TABLEFIELDS_ADVANCE_CUSTOM(@table, DEFAULT,1,@searchOnFields,@searchOnFieldSeparator,1,'','')+', '+@table+'_ACID_Button)
		SELECT '+dbo.OBJECT_GET_TABLEFIELDS_ADVANCE_CUSTOM(@table, DEFAULT,1,@searchOnFields,@searchOnFieldSeparator,1,'','')+',''bearbeiten'' FROM '+@table+''                
					SELECT @searchTermTableDef +=  @searchWhereCondition
					SET @searchTermTableDef = REPLACE(@searchTermTableDef,@table+' AND',@table+' WHERE ')				
				END
		IF (ISNULL(@tsqlBuildingValidSyntaxRelFields.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'')<>'')
			BEGIN
				SET @tsqlBuildingValidSyntaxRelFields = (
					SELECT N'
			UPDATE destinationTable  
				SET destinationTable.'+fieldAlias+' = originTable.'+fieldAlias+'
			FROM @'+@table+'_RESULTS destinationTable, '+fromTable+' originTable WHERE originTable.'+fromField+' = destinationTable.'+toField+'  	

						 '
					FROM dbo.TABLE_RELATION(@table) WHERE fieldAlias IN (SELECT fieldName FROM @validFields where ownField = 0) 
					FOR XML PATH(''), ROOT('result')
				,TYPE)
				IF (ISNULL(@tsqlBuildingValidSyntaxRelFields.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'')<>'')
					BEGIN
						SET @searchTermTableDef += ISNULL(@tsqlBuildingValidSyntaxRelFields.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'')
					END 				
			END          
		IF (@searchTermTableDef <> '')
			SET @_RESULT_LOGIC_DEFINITION = @searchTermTableDef
		SET @functionDefinition = REPLACE(@functionDefinition,'TSQL_ON_SEARCH_LOGIC_REPLACEMENT',@searchTermTableDef)
		INSERT INTO @fnDefinition (functionName, functionDefinition)
			SELECT @functionName, @functionDefinition
	RETURN
END
GO
