CREATE FUNCTION [dbo].[__generator_FUNCTION_SEARCH_ON_TABLE_DEFINITION] (@table NVARCHAR(255) = 'mandant', @tableColumnIdentity VARCHAR(255) = 'ID', @searchOnFields VARCHAR(MAX) = 'id;companyname;email;AbasId', @searchOnFieldSeparator VARCHAR(1) = ';')  
RETURNS @fnDefinition TABLE   (functionName VARCHAR(MAX) NULL, functionDefinition VARCHAR(MAX) NULL, rootName VARCHAR(255) NULL, childName VARCHAR(255) NULL)
BEGIN --Author José 
		IF (EXISTS (SELECT * FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA = 'dbo' AND TABLE_NAME = @table))
			BEGIN 
				DECLARE @functionName NVARCHAR(MAX) = '' 
				DECLARE @validColumns INT = 4
				--SET @columns = @columns 
				SET @table = UPPER(@table) 
				SET @functionName = '__fnSEARCH_XML_'+@table+'_BY_TERMS' 
				DECLARE @functionDefinitionReplacement VARCHAR(MAX) = '' 
				DECLARE @rootName NVARCHAR(255) = LOWER(@table)+'s' 
				DECLARE @childName NVARCHAR(255) = LOWER(@table)
				
				SET @tableColumnIdentity = ISNULL((SELECT TOP 1 UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS 		WHERE  COLUMNPROPERTY(object_id(TABLE_SCHEMA+'.'+TABLE_NAME), COLUMN_NAME, 'IsIdentity') = 1 AND TABLE_NAME = @table),@tableColumnIdentity)  
				DECLARE @validFields TABLE (fieldName NVARCHAR(255) NULL)
				INSERT INTO @validFields  ( fieldName )
					SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @table AND COLUMN_NAME IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchOnFields,@searchOnFieldSeparator)) 
				--SET @validColumns = ISNULL((SELECT COUNT(*) FROM @validFields),@columns)
				--SET @validColumns+= ISNULL(((SELECT COUNT(*) FROM dbo.TABLE_RELATION(@table) WHERE fieldAlias IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchOnFields,@searchOnFieldSeparator)) )),0) 
				--SET @columns = (@validColumns+1)* 2 --wegen suchen button
				DECLARE @functionDefinition VARCHAR(MAX) =
'
--IF EXISTS (SELECT * FROM sys.objects WHERE object_id = OBJECT_ID(N'''+@functionName+''') AND type IN ( N''FN''))
	--DROP FUNCTION dbo.'+@functionName+' 
--GO
CREATE FUNCTION dbo.'+@functionName+'(@searchTerms NVARCHAR(MAX) = '''')
RETURNS NVARCHAR(MAX) --Author José. Erstellt am '+dbo.GET_ISO_DATETIME(DEFAULT,DEFAULT)+'
BEGIN 
    --UPDATE @'+@table+'_RESULTS SET '+@tableColumnIdentity+' = -4000 WHERE '+@table+'_ACID_Button = ''suchen''
	DECLARE @XML_'+@table+'S NVARCHAR(MAX) =
		(ISNULL((
				STUFF(( 
						SELECT 
									(SELECT ISNULL('+@tableColumnIdentity+',-4000)[@PK] 
										MUSTER_SELECT_REPLACEMENT
 
								FOR XML PATH('''+@childName+'''), TYPE)   
							FROM dbo.__fnSEARCH_ON_'+@table+'_BY_TERMS(@searchTerms,-4000,''suchen'') tf --WHERE '+@tableColumnIdentity+' IN (SELECT '+@tableColumnIdentity+' FROM @'+@table+')
						FOR XML PATH(''''),ROOT('''+@rootName+''')),1,0,'''')	
		),''''))
	 
	RETURN @XML_'+@table+'S  
END
--GO
--SELECT dbo.'+@functionName+'(''id=;companyname=;email=;AbasId='')
				'




					DECLARE @tableDefinition TABLE (PK INT NOT NULL IDENTITY(1,1), field NVARCHAR(255) NULL, fieldDefinition NVARCHAR(255), isIdentity VARCHAR(1) NULL, tsqlDataType VARCHAR(128) NULL, inputType VARCHAR(128) NULL, [labelColumn] VARCHAR(3) NULL, [labelRow] VARCHAR(3) NULL, [elementColumn] VARCHAR(3) NULL, [elementRow] VARCHAR(3) NULL, [dynTSQL] NVARCHAR(MAX) NULL)
					INSERT INTO @tableDefinition (field, fieldDefinition, isIdentity, tsqlDataType, inputType, [labelColumn], [labelRow], [elementColumn], [elementRow] )
						SELECT field, fieldDefinition, isIdentity, tsqlDataType, inputType, [labelColumn], [labelRow], [elementColumn], [elementRow]  FROM dbo.customTableDDLAdvanceJustValidFields(@table,0,1,@searchOnFields,@searchOnFieldSeparator)-- WHERE field IN (SELECT fieldName FROM @validFields)
					
					--UPDATE @tableDefinition SET dynTSQL = '(SELECT companyname FROM dbo.Mandant WHERE id=mandant_id)'
					--WHERE field IN (SELECT fieldAlias FROM dbo.TABLE_RELATION(@table))
					DELETE FROM @tableDefinition WHERE field IN (SELECT fieldAlias FROM dbo.TABLE_RELATION(@table) WHERE fieldAlias NOT IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchOnFields,@searchOnFieldSeparator)) )

			UPDATE td  
				SET td.dynTSQL = '(SELECT TOP 1 '+fieldAlias+' FROM '+fromTable+' subtable WHERE subtable.'+fromField+' = tf.'+toField+')' 
				-- (SELECT companyname FROM dbo.Mandant WHERE id=mandant_id)
			FROM @tableDefinition td, dbo.TABLE_RELATION(@table) tr WHERE td.field = tr.fieldAlias  	

			--SELECT * FROM dbo.TABLE_RELATION('MANDANT_DB_ENVIRONMENT')

					UPDATE @tableDefinition SET dynTSQL = ''
					WHERE field IS NULL
					DECLARE @result XML    
					SET @result = (
						SELECT 
							CASE 
							WHEN field LIKE '%_ACID_Button' THEN 
						    N'
														,(SELECT 
																'+labelColumn+'[@labelColumn], master_identity_id[@labelRow], '+elementColumn+'[@elementColumn], master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE('+@tableColumnIdentity+', '''+@table+''','''+field+''','''+inputType+''', ISNULL('+@table+'_ACID_Button,''''),NULL, NULL)[@options], 
																CASE WHEN ISNULL('+@table+'_ACID_Button,'''') = ''suchen'' 
																	THEN ''{"readVars":[], "readObj":"1", "action":"suchen"}'' 
																	ELSE ''{"readVars":[], "readObj":"1", "action":"open_object_details"}'' END [@onClickAction],																											
 																''30''[@labelWith],''50''[@textWith],'''+inputType+'''[@type],'''+isIdentity+'''[@readonly], '''' AS ''*''  FOR XML PATH('''+field+'''), TYPE)												
							'  
							WHEN (ISNULL(dynTSQL,'')<>'') THEN 
							N'
														,(SELECT 
																'+labelColumn+'[@labelColumn], master_identity_id[@labelRow], '+elementColumn+'[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE('+@tableColumnIdentity+', '''+@table+''','''+field+''','''+inputType+''', '+CASE WHEN tsqlDataType like '%XML%'  THEN '''''' ELSE+' '+field+'' END+',NULL, NULL )[@options],																																												
 																''10''[@labelWith],''50''[@textWith],'''+inputType+'''[@type],''0''[@readonly], '+CASE WHEN tsqlDataType like '%XML%' OR (fieldDefinition LIKE '%INT%' AND isIdentity=1)  THEN ' CASE WHEN '+field+' IS NOT NULL THEN CAST('+field+' AS NVARCHAR(MAX)) ELSE '''' END' ELSE+' '+field+'' END+'  AS ''*''  FOR XML PATH('''+field+'''), TYPE)			
							'
							ELSE
							N'
														,(SELECT 
																'+labelColumn+'[@labelColumn], master_identity_id[@labelRow], '+elementColumn+'[@elementColumn],  master_identity_id[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES_ADVANCE('+@tableColumnIdentity+', '''+@table+''','''+field+''','''+inputType+''', '+CASE WHEN tsqlDataType like '%XML%'  THEN '''''' ELSE+'  '+field+'' END+',NULL, NULL )[@options],																																												
 																''10''[@labelWith],''50''[@textWith],'''+inputType+'''[@type],'''+isIdentity+'''[@readonly], '+CASE WHEN tsqlDataType like '%XML%' OR (fieldDefinition LIKE '%INT%' AND isIdentity=1)  THEN ' CASE WHEN '+field+' IS NOT NULL THEN CAST('+field+' AS NVARCHAR(MAX)) ELSE '''' END' ELSE+' '+field+'' END+'  AS ''*''  FOR XML PATH('''+field+'''), TYPE)			
							' END
							
							+CHAR(13)
						FROM @tableDefinition
						FOR XML PATH(''), ROOT('result')
					 ,TYPE) 
	 
					 IF (ISNULL(@result.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'') <> '') 
						   SELECT @functionDefinitionReplacement =  @result.value('/result[1]/text()[1]', 'NVARCHAR(MAX)') 
					 SET @functionDefinition = REPLACE(@functionDefinition,'MUSTER_SELECT_REPLACEMENT',@functionDefinitionReplacement)
					 INSERT INTO @fnDefinition (functionName, functionDefinition, childName,  rootName)
					   SELECT @functionName , @functionDefinition , @childName ,  @rootName
					          
			END 
	RETURN 
END
GO
