CREATE FUNCTION [dbo].[__GET__ACID_TRANSACTION_CODE] (@table NVARCHAR(255) = 'mandant', @tableColumnIdentity VARCHAR(255) = 'ID', @ACID VARCHAR(32) = 'UPDATE', @codeTabs INT = 2 )  
RETURNS VARCHAR(MAX)
BEGIN --Author José 
	DECLARE @result VARCHAR(MAX) = ''
	IF (@ACID NOT IN ('UPDATE','INSERT'))
		RETURN @result
	--DECLARE @table VARCHAR(128) = 'mandant', @tableColumnIdentity VARCHAR(255) = 'ID'
	SET @tableColumnIdentity = ISNULL((SELECT TOP 1 UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS 		WHERE  COLUMNPROPERTY(object_id(TABLE_SCHEMA+'.'+TABLE_NAME), COLUMN_NAME, 'IsIdentity') = 1 AND TABLE_NAME = @table),@tableColumnIdentity)  
	DECLARE @tableColumnIdentityDefinition VARCHAR(255) = REPLACE(dbo.fn_GetTFieldDDL(@table,@tableColumnIdentity,DEFAULT),'IDENTITY(1,1)','')
	SET @tableColumnIdentityDefinition = REPLACE(@tableColumnIdentityDefinition,'[','')
	SET @tableColumnIdentityDefinition = REPLACE(@tableColumnIdentityDefinition,']','')
	SET @tableColumnIdentityDefinition = REPLACE(@tableColumnIdentityDefinition,'NOT','')
	SET @tableColumnIdentityDefinition = REPLACE(@tableColumnIdentityDefinition,'NULL','')
	SET @tableColumnIdentityDefinition = REPLACE(@tableColumnIdentityDefinition,'  ',' ')
	DECLARE @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_EXECUTION NVARCHAR(MAX) = ''
	DECLARE @VARIABLE_SP_EXECUTESQL_SQL_PARAM NVARCHAR(MAX) = '' 
	DECLARE @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES NVARCHAR(MAX) = ''
	DECLARE @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_VARIABLES NVARCHAR(MAX) = ''
	DECLARE @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_ASSIGNATION NVARCHAR(MAX) = ''
	DECLARE @codeTabString NVARCHAR(MAX) = ''
	DECLARE @spaceCounter INT = 0
	WHILE (@spaceCounter < @codeTabs * 4)
		BEGIN
			SET @codeTabString+=' '
			SET @spaceCounter+=1	
		END
		
	IF (@ACID = 'UPDATE')
		BEGIN
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES  =  dbo.OBJECT_GET_TABLEFIELDS_ADVANCE(@table, DEFAULT,0,DEFAULT,DEFAULT,1, '','')
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES  = REPLACE(@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES,'[','@')
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES  = REPLACE(@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES,'],',', ')
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES  = REPLACE(@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES,']',' ')+', @'+@tableColumnIdentity	
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_VARIABLES  = dbo.OBJECT_GET_TABLEFIELDS_ADVANCE(@table, DEFAULT,0,DEFAULT,DEFAULT,1, 'UPDATE','escaped_')			
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM = 'SET @sp_executesql_sql_param = ''UPDATE '+@table+' SET '+@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_VARIABLES+' WHERE '+@tableColumnIdentity+'=@escaped_'+@tableColumnIdentity+''''
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_ASSIGNATION  = dbo.OBJECT_GET_TABLEFIELDS_ADVANCE(@table, DEFAULT,0,DEFAULT,DEFAULT,1, 'ASSIGNATION','escaped_')	+', '+REPLACE(@tableColumnIdentityDefinition,@tableColumnIdentity,'@escaped_'+@tableColumnIdentity)

		END
	IF (@ACID = 'INSERT')
		BEGIN
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES  =  dbo.OBJECT_GET_TABLEFIELDS_ADVANCE(@table, DEFAULT,0,DEFAULT,DEFAULT,1, '','')  			
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM = 'SET @sp_executesql_sql_param = ''INSERT INTO '+@table+' ('+@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES+')'
			
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_ASSIGNATION  = dbo.OBJECT_GET_TABLEFIELDS_ADVANCE(@table, DEFAULT,0,DEFAULT,DEFAULT,1, 'ASSIGNATION','escaped_')	
		    SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM += 'VALUES('+dbo.OBJECT_GET_TABLEFIELDS_ADVANCE(@table, DEFAULT,0,DEFAULT,DEFAULT,0, 'ASSIGNATION','escaped_')+')'''
 
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES  = REPLACE(@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES,'[','@')
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES  = REPLACE(@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES,'],',', ')
			SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES  = REPLACE(@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES,']',' ')
		END        
	SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_ASSIGNATION = 'SET @sp_executesql_sql_param_variable_assignation = N'''+@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_ASSIGNATION+''''
	SET @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_EXECUTION = 'EXEC sp_executesql @sp_executesql_sql_param, @sp_executesql_sql_param_variable_assignation, '+@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_SELECT_VARIABLES+''	
		
	--SET @sp_executesql_sql_param_variable_assignation = N'
	/*PRINT @VARIABLE_SP_EXECUTESQL_SQL_PARAM
	PRINT @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_ASSIGNATION
	PRINT @VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_EXECUTION*/
	SET  @result += @codeTabString+@VARIABLE_SP_EXECUTESQL_SQL_PARAM+CHAR(10)
	SET  @result += @codeTabString+@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_ASSIGNATION+CHAR(10)
	SET  @result += @codeTabString+@VARIABLE_SP_EXECUTESQL_SQL_PARAM_SET_ACID_EXECUTION+CHAR(10)
	RETURN @result
END
GO
