CREATE FUNCTION [dbo].[__GET_FUNCTION_LOGIC_SEARCH_ON_TABLE_DEFINITION] (@table NVARCHAR(255) = 'mandant', @tableFields VARCHAR(MAX) = '', @searchOnFieldSeparator VARCHAR(1) = ';')
RETURNS VARCHAR(MAX)
AS
BEGIN
	DECLARE @_RESULT VARCHAR(MAX)=''
		--DECLARE @table NVARCHAR(255) = 'mandant'
		--DECLARE @tableFields NVARCHAR(2048) = 'id;companyname;email;AbasId'
		DECLARE @searchTermTableDef NVARCHAR(MAX) =  ''
		DECLARE @validFieldCounter INT = 0
		DECLARE @searchTermDefinitions NVARCHAR(MAX) =  dbo.getVariableDefinitionFromTableReplaceDataType(@table,'DECLARE',@tableFields,@searchOnFieldSeparator,DEFAULT)
		DECLARE @validFields TABLE (fieldName NVARCHAR(255) NULL)
		INSERT INTO @validFields  ( fieldName )
			SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @table AND COLUMN_NAME IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@tableFields,@searchOnFieldSeparator))
		
		SET @validFieldCounter = ISNULL((SELECT COUNT(*) FROM @validFields),0)
		SET @searchTermTableDef = dbo.getVariableDefinitionFromTable(@table,'DECLARE',@tableFields,@searchOnFieldSeparator)
		SET @searchTermDefinitions = REPLACE(@searchTermDefinitions,'DECLARE @','DECLARE @'+@table+'Search')
		SET @searchTermDefinitions = REPLACE(@searchTermDefinitions,'DECLARE @','    DECLARE @')
		SET @searchTermTableDef = REPLACE(@searchTermTableDef,'DECLARE @','')
		SET @searchTermTableDef = REPLACE(@searchTermTableDef,CHAR(10),',')
		SET @searchTermTableDef = REPLACE(@searchTermTableDef,CHAR(13),',')
		SET @searchTermTableDef = REPLACE(@searchTermTableDef,' ,',', ')
		SET @searchTermTableDef = REPLACE(@searchTermTableDef,' = ',' ')
		SET @searchTermTableDef = REPLACE(@searchTermTableDef,' 0',' ')
		SET @searchTermTableDef = REPLACE(@searchTermTableDef,' 1',' ')
		SET @searchTermTableDef = 
'
	DECLARE @'+@table+' TABLE ('+@searchTermTableDef+')
	DECLARE @'+@table+'_RESULTS TABLE (master_identity_id INT NOT NULL IDENTITY(1,1), '+@searchTermTableDef+@table+'_ACID_Button NVARCHAR(512) NULL)
'
		SET @searchTermTableDef = @searchTermDefinitions + REPLACE(@searchTermTableDef,', )',')')
		SET @searchTermTableDef +=
'	INSERT INTO @'+@table+'('+dbo.OBJECT_GET_TABLEFIELDS_ADVANCE_CUSTOM(@table, DEFAULT,1,@tableFields,';',1,'','')+')
		SELECT '+dbo.OBJECT_GET_TABLEFIELDS_ADVANCE_CUSTOM(@table, DEFAULT,1,@tableFields,';',1,'','')+' FROM '+@table+'
'
		--SELECT * FROM dbo.Mandant
		--PRINT @searchTermDefinitions
		--PRINT @searchTermTableDef
 
			DECLARE @result XML    
			SET @result = (
				SELECT N' 
    SET @'+@table+'Search'+fieldName+' = ISNULL((SELECT TOP 1 REPLACE(Aval,'''+fieldName+'='','''') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerms,'';'') WHERE Aval LIKE '''+fieldName+'=%''),'''')'
				FROM @validFields
				FOR XML PATH(''), ROOT('result')
			,TYPE) 
			IF (ISNULL(@result.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'') <> '') 
				SELECT @searchTermTableDef +=  @result.value('/result[1]/text()[1]', 'NVARCHAR(MAX)') 
		SET @searchTermTableDef +=
'    
    INSERT INTO @'+@table+'_RESULTS ('+@table+'_ACID_Button)
		SELECT  ''suchen''
'
			SET @result = (
				SELECT N' 
    IF (@'+@table+'Search'+fieldName+'<>'''')
		BEGIN
			DELETE FROM @'+@table+' WHERE ISNULL('+fieldName+','''') NOT LIKE ''%''+@'+@table+'Search'+fieldName+'+''%''
			IF(dbo.fn_GetTFieldDDL('''+@table+''','''+fieldName+''',DEFAULT) LIKE ''%INT%'' AND ISNUMERIC(@'+@table+'Search'+fieldName+')=0)
				SET @'+@table+'Search'+fieldName+'=-4001
			UPDATE @'+@table+'_RESULTS SET '+fieldName+' = @'+@table+'Search'+fieldName+' WHERE '+@table+'_ACID_Button = ''suchen''
		END					 			
					 '
				FROM @validFields
				FOR XML PATH(''), ROOT('result')
			,TYPE) 
			IF (ISNULL(@result.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'') <> '') 
				SELECT @searchTermTableDef +=  @result.value('/result[1]/text()[1]', 'NVARCHAR(MAX)')  
		SET @searchTermTableDef +=
'    
    INSERT INTO @'+@table+'_RESULTS
		SELECT *,''bearbeiten'' FROM @'+@table+'
'
		IF (@searchTermTableDef <> '')
			SET @_RESULT = @searchTermTableDef 
	RETURN @_RESULT
END
GO
