CREATE FUNCTION [dbo].[__GET_FUNCTION_TABLE_DEFINITION] (@table NVARCHAR(255) = 'mandant', @tableColumnIdentity VARCHAR(255) = 'ID', @columns INT = 4)  
RETURNS @fnDefinition TABLE  (functionName VARCHAR(MAX) NULL, functionDefinition VARCHAR(MAX) NULL, rootName VARCHAR(255) NULL, childName VARCHAR(255) NULL)
BEGIN --Author José 
		IF (EXISTS (SELECT * FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA = 'dbo' AND TABLE_NAME = @table) AND ISNUMERIC(@columns)=1)
			BEGIN 
				DECLARE @functionName NVARCHAR(MAX) = ''
				DECLARE @childName NVARCHAR(255) = LOWER(@table)
				DECLARE @rootName NVARCHAR(255) = LOWER(@table)+'s'
				SET @columns = @columns/2  
				SET @table = UPPER(@table) 
				SET @tableColumnIdentity = ISNULL((SELECT TOP 1 UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS 		WHERE  COLUMNPROPERTY(object_id(TABLE_SCHEMA+'.'+TABLE_NAME), COLUMN_NAME, 'IsIdentity') = 1 AND TABLE_NAME = @table),@tableColumnIdentity)  
				SET @functionName = '__fnGET_XML_'+@table+'_BY_'+@tableColumnIdentity+'' 
				DECLARE @functionDefinitionReplacement VARCHAR(MAX) = ''
				DECLARE @functionDefinition VARCHAR(MAX) =
'
IF EXISTS (SELECT * FROM sys.objects WHERE object_id = OBJECT_ID(N'''+@functionName+''') AND type IN ( N''FN''))
	DROP FUNCTION dbo.'+@functionName+' 
GO
CREATE FUNCTION dbo.'+@functionName+'(@'+@tableColumnIdentity+' BIGINT = NULL)
RETURNS NVARCHAR(MAX) --Author José. Erstellt am '+dbo.GET_ISO_DATETIME(DEFAULT,DEFAULT)+'
BEGIN 
	DECLARE @XML_'+@table+'S NVARCHAR(MAX) =
		(ISNULL((
				STUFF(( 
						SELECT 
									(SELECT '+@tableColumnIdentity+'[@PK] 
										MUSTER_SELECT_REPLACEMENT
 
								FOR XML PATH('''+@childName+'''), TYPE)   
							FROM '+@table+' WHERE '+@tableColumnIdentity+' = @'+@tableColumnIdentity+'
						FOR XML PATH(''''),ROOT('''+@rootName+''')),1,0,'''')	
		),''''))
	RETURN @XML_'+@table+'S
END
GO
SELECT dbo.'+@functionName+'((SELECT TOP 1 '+@tableColumnIdentity+' FROM '+@table+'))
				'




					DECLARE @tableDefinition TABLE (PK INT NOT NULL IDENTITY(1,1), field NVARCHAR(255) NULL, fieldDefinition NVARCHAR(255), isIdentity VARCHAR(1) NULL, tsqlDataType VARCHAR(128) NULL, inputType VARCHAR(128) NULL, [labelColumn] VARCHAR(3) NULL, [labelRow] VARCHAR(3) NULL, [elementColumn] VARCHAR(3) NULL, [elementRow] VARCHAR(3) NULL)
					INSERT INTO @tableDefinition (field, fieldDefinition, isIdentity, tsqlDataType, inputType, [labelColumn], [labelRow], [elementColumn], [elementRow] )
						SELECT field, fieldDefinition, isIdentity, tsqlDataType, inputType, [labelColumn], [labelRow], [elementColumn], [elementRow]  FROM dbo.customTableDDL(@table,@columns*2,0,1)
 --SELECT * FROM customTableDDL('DB_SCHEMA_DATA_COMPARE_UPDATE',4)
 --SELECT * FROM customTableDDL('mandant',4)
					DECLARE @result XML    
					SET @result = (
						SELECT CASE WHEN field LIKE '%_ACID_Button' THEN 
						    N'
														,(SELECT 
																'+labelColumn+'[@labelColumn], '+labelRow+'[@labelRow], '+elementColumn+'[@elementColumn], '+elementRow+'[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES('+@tableColumnIdentity+', '''+@table+''','''+field+''','''+inputType+''', '''+field+''')[@options],												
 																''30''[@labelWith],''50''[@textWith],'''+inputType+'''[@type],'''+isIdentity+'''[@readonly], '''' AS ''*''  FOR XML PATH('''+field+'''), TYPE)												
							' 
							ELSE
							N'
														,(SELECT 
																'+labelColumn+'[@labelColumn], '+labelRow+'[@labelRow], '+elementColumn+'[@elementColumn], '+elementRow+'[@elementRow], 
																dbo.GET_GENERAL_ELEMENT_PROPERTIES('+@tableColumnIdentity+', '''+@table+''','''+field+''','''+inputType+''', '+CASE WHEN tsqlDataType like '%XML%' THEN '''''' ELSE+' ISNULL('+field+','''')' END+' )[@options],												
 																''30''[@labelWith],''50''[@textWith],'''+inputType+'''[@type],'''+isIdentity+'''[@readonly], '+CASE WHEN tsqlDataType like '%XML%' THEN ' CASE WHEN '+field+' IS NOT NULL THEN CAST('+field+' AS NVARCHAR(MAX)) ELSE '''''''' END' ELSE+' ISNULL('+field+','''')' END+'  AS ''*''  FOR XML PATH('''+field+'''), TYPE)			
							' END +CHAR(13)
						FROM @tableDefinition
						FOR XML PATH(''), ROOT('result')
					 ,TYPE) 
	 
					 IF (ISNULL(@result.value('/result[1]/text()[1]', 'NVARCHAR(MAX)'),'') <> '') 
						   SELECT @functionDefinitionReplacement =  @result.value('/result[1]/text()[1]', 'NVARCHAR(MAX)') 
					 SET @functionDefinition = REPLACE(@functionDefinition,'MUSTER_SELECT_REPLACEMENT',@functionDefinitionReplacement)
					 INSERT INTO @fnDefinition
					   SELECT @functionName , @functionDefinition , @childName ,  @rootName
					          
			END 
	RETURN 
END
GO
