CREATE FUNCTION [dbo].[__GET_PROCEDURE_ACID_TABLE_DEFINITION] (@table NVARCHAR(255) = 'mandant', @tableColumnIdentity VARCHAR(255) = 'ID' )  
RETURNS @procDefinition TABLE  (procedureName VARCHAR(MAX) NULL, procedureDefinition VARCHAR(MAX) NULL)
BEGIN --Author José 
		IF (EXISTS (SELECT * FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA = 'dbo' AND TABLE_NAME = @table) )
			BEGIN 
				DECLARE @procedureName NVARCHAR(MAX) = ''
				DECLARE @childName NVARCHAR(255) = LOWER(@table)
				DECLARE @rootName NVARCHAR(255) = LOWER(@table)+'s'
 
				SET @table = UPPER(@table) 
				SET @tableColumnIdentity = ISNULL((SELECT TOP 1 UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS 		WHERE  COLUMNPROPERTY(object_id(TABLE_SCHEMA+'.'+TABLE_NAME), COLUMN_NAME, 'IsIdentity') = 1 AND TABLE_NAME = @table),@tableColumnIdentity)  
				SET @procedureName = '__procProcess_XML_ACID_'+@table+'_DATA_BY_'+@tableColumnIdentity+'' 
				DECLARE @procedureDefinitionReplacement VARCHAR(MAX) = ''
				DECLARE @procedureDefinition VARCHAR(MAX) =
'
IF EXISTS (SELECT * FROM sys.objects WHERE object_id = OBJECT_ID(N'''+@procedureName+''') AND type IN ( N''P''))
	DROP PROCEDURE dbo.'+@procedureName+' 
GO
CREATE PROCEDURE dbo.'+@procedureName+'(@INPUT_CLIENT_DATA XML = NULL, @confirm_acid_transaction BIT = 0)
AS
BEGIN   --Author José. Erstellt am '+dbo.GET_ISO_DATETIME(DEFAULT,DEFAULT)+'
	SET CONCAT_NULL_YIELDS_NULL ON  
    SET NOCOUNT ON  
    SET ANSI_WARNINGS ON
    SET ANSI_PADDING ON
	SET CONCAT_NULL_YIELDS_NULL ON

	/*Definition of Table field variables*/
'+REPLACE(dbo.getVariableDefinitionFromTable(@table,'DECLARE',DEFAULT, DEFAULT),'DECLARE ','    DECLARE ')+'

	/*Definition of help variables*/
    DECLARE @alertSystemGeneralMessage NVARCHAR(MAX) = ''''
	DECLARE @alertSystemMessageTitle NVARCHAR(128) = ''''
	DECLARE @alertSystemMessageDetails NVARCHAR(MAX) = ''{}'' 
	DECLARE @alertSystemGeneralMessageType VARCHAR(32) = ''showinfo''

	DECLARE @jsonObjectResponse NVARCHAR(MAX) = ''{}''
	DECLARE @newTSQL VARCHAR(2048) = ''''
	DECLARE @sql_in_separated_process VARCHAR(1) = ''''
	DECLARE @other_cmd VARCHAR(2048) = ''''
	DECLARE @ACID_TRANSACTION VARCHAR(32) = ''INSERT''
	DECLARE @separated_process_type VARCHAR(32) = ''''
	DECLARE @separated_process VARCHAR(2048) = ''''
    DECLARE @sp_executesql_sql_param NVARCHAR(MAX)
    DECLARE @sp_executesql_sql_param_variable_assignation NVARCHAR(MAX)
	
 
	IF (@INPUT_CLIENT_DATA IS NULL)
		SET @alertSystemGeneralMessage = ''Die erforderlichen Parameter wurden nicht übergeben''
 	BEGIN TRY
		IF (@INPUT_CLIENT_DATA IS NOT NULL) 
			BEGIN
'+REPLACE(dbo.getVariableDefinitionFromTable(@table,'SET',DEFAULT, DEFAULT),'SET ','			    SET ')+'
				--check if db table entry already there 
				IF(EXISTS(SELECT '+@tableColumnIdentity+' FROM '+@table+' WHERE '+@tableColumnIdentity+' = @'+@tableColumnIdentity+'))
					BEGIN
						SET @ACID_TRANSACTION = ''UPDATE''
					END
				IF (@ACID_TRANSACTION = ''UPDATE'' AND @confirm_acid_transaction = 0)
					BEGIN
						SET @alertSystemMessageDetails = ''{"DB Info":"Bitte beachten Sie, dass diese Transaktion nicht mehr als 3 Sekunden dauert", "Grund":"DB Erreichbarkeit kann nicht vorhanden sein", "Reaktion":"Bitte den Fehler melden, wenn er auftritt"}''
						SET @alertSystemGeneralMessage = ''Der Eintrag in '+@table+' mit der '+@tableColumnIdentity+'=(CAST(@'+@tableColumnIdentity+' AS VARCHAR (32) )) wird aktualisiert. Bitte bestätigen Sie es!''										
					 	SET @alertSystemMessageTitle = ''Eintrag wird upgedatet''	
						SET @alertSystemGeneralMessageType = ''askquestion''
					END	 
				IF (@ACID_TRANSACTION = ''INSERT'' AND @confirm_acid_transaction = 0)
					BEGIN
						SET @alertSystemMessageDetails = ''{"DB Info":"Bitte beachten Sie, dass diese Transaktion nicht mehr als 3 Sekunden dauert", "Grund":"DB Erreichbarkeit kann nicht vorhanden sein", "Reaktion":"Bitte den Fehler melden, wenn er auftritt"}''
						SET @alertSystemGeneralMessage = ''Der Eintrag in '+@table+' wird angelegt. Bitte bestätigen Sie es!''										
					 	SET @alertSystemMessageTitle = ''Eintrag wird angelegt''	
						SET @alertSystemGeneralMessageType = ''askquestion''
					END	 					
				ELSE IF (@ACID_TRANSACTION = ''UPDATE'' AND @confirm_acid_transaction = 1)
					BEGIN
						SET @alertSystemMessageDetails = ''{"DB Info":"Prozess done", "Success":"OK"}''
						SET @alertSystemGeneralMessage = ''Der Eintrag in '+@table+' wurde aktualisiert''										
					 	SET @alertSystemMessageTitle = ''Eintrag aktualisiert''
'+dbo.__GET__ACID_TRANSACTION_CODE(@table,@tableColumnIdentity,'UPDATE',6)+'
					END	
				ELSE IF (@ACID_TRANSACTION = ''INSERT'' AND @confirm_acid_transaction = 1)
					BEGIN
						SET @alertSystemMessageDetails = ''{"DB Info":"Prozess done", "Success":"OK"}''
						SET @alertSystemGeneralMessage = ''Der Eintrag in '+@table+' wurde angelegt''										
					 	SET @alertSystemMessageTitle = ''Eintrag angelegt''
'+dbo.__GET__ACID_TRANSACTION_CODE(@table,@tableColumnIdentity,'INSERT',6)+'
					END						 					    
			END
		SET @jsonObjectResponse = ''{"title":"''+@alertSystemMessageTitle+''","message":"''+@alertSystemGeneralMessage+''", "type":"''+@alertSystemGeneralMessageType+''", "result":[''+@alertSystemMessageDetails+''], "newTSQL":"''+@newTSQL+''", "sql_in_separated_process":"''+@sql_in_separated_process+''","other_cmd":"''+@other_cmd+''", "separated_process_type":"''+@separated_process_type+''", "separated_process":"''+@separated_process+''"}''
		SELECT @jsonObjectResponse[PY_'+@table+']		
	END TRY 
	BEGIN CATCH  
		SET @alertSystemGeneralMessageType = ''showerror''
		SET @jsonObjectResponse = ''{"title":"''+@alertSystemMessageTitle+''", "message":"''+ERROR_MESSAGE()+''", "type":"''+@alertSystemGeneralMessageType+''", "result":[], "newTSQL":"''+@newTSQL+''", "sql_in_separated_process":"''+@sql_in_separated_process+''","other_cmd":"''+@other_cmd+''", "separated_process_type":"''+@separated_process_type+''", "separated_process":"''+@separated_process+''"}''
		SELECT @jsonObjectResponse[PY_'+@table+']			
	END CATCH   
	    IF @jsonObjectResponse IS NULL	
			SELECT ''unknown error''[PY_'+@table+']	
 
END
GO 
				' 
				INSERT INTO @procDefinition
				        SELECT @procedureName , @procedureDefinition
				        
					   
			END 
	 RETURN
END
GO
