		IF (@isExtern <> 1)
			INSERT INTO @estimation 
				VALUES ('* LIVE- und ACC UMGEBUNG: RDP Benutzer anlegen','Umsetzung','subtopic',15)

	INSERT INTO @estimation -- Zusammenfassung
        VALUES  
			('Konzeptionaufwand = [Beratung & Projektmanagement]+[Konzeption]+[Übergabe an & mit Kunde inkl. Feedbackschleife]+[Dokumentation]: ','Konzeptionaufwand','main',0),
			('Umsetzungsaufwand = [Umsetzung]+[Übertragung in Live und Akzeptanz Umgebung]: ','Umsetzungsaufwand','main',0),
			('QS/PL-Aufwand = [Qualitätssicherung]: ','QS/PL-Aufwand','main',0)

		UPDATE @estimation SET cost_in_minutes = ROUND(cost_in_minutes*@mutiplyFactor,0) WHERE cost_in_minutes > 0  AND foreignkey IN ('Umsetzung','Übertragung')
		--UPDATE @estimation SET cost_in_minutes = SUM(cost_in_minutes)  WHERE foreignkey='BP' AND typ = 'subtopic'
		DECLARE @foreignkey VARCHAR(128),@typ VARCHAR(128),@id INT,@costs FLOAT
		DECLARE crentupdate6_estimation_costs_cursor CURSOR  
		   FOR SELECT id,foreignkey,typ from @estimation WHERE typ = 'main'
		OPEN crentupdate6_estimation_costs_cursor  
		FETCH NEXT FROM crentupdate6_estimation_costs_cursor INTO @id,@foreignkey ,@typ
  
		WHILE @@FETCH_STATUS = 0  
		BEGIN 
			SET @costs = ISNULL((SELECT SUM(cost_in_minutes) FROM @estimation WHERE foreignkey=@foreignkey AND typ='subtopic') ,0)  
			UPDATE @estimation SET cost_in_minutes = @costs WHERE id=@id
			FETCH NEXT FROM crentupdate6_estimation_costs_cursor	INTO @id,@foreignkey ,@typ
		END   
		CLOSE crentupdate6_estimation_costs_cursor;  
		DEALLOCATE crentupdate6_estimation_costs_cursor;  
		
		SET @costs = ISNULL((SELECT SUM(cost_in_minutes) FROM @estimation WHERE typ='subtopic' AND foreignkey='Umsetzung'),0)*0.2  
		UPDATE @estimation SET cost_in_minutes =  @costs WHERE foreignkey = 'QS' AND typ = 'main'  
		SET @costs = ISNULL((SELECT SUM(cost_in_minutes) FROM @estimation WHERE typ='main'),0)
		
		UPDATE @estimation SET cost_in_minutes =  @costs WHERE foreignkey = 'GESAMTAUFWAND' AND typ = 'main'  
		UPDATE @estimation SET cost_in_minutes =  ISNULL((SELECT SUM(cost_in_minutes) FROM @estimation WHERE typ='main' AND foreignkey IN('DUKU','übergabe','Konzeption','BP') ),0) WHERE foreignkey = 'Konzeptionaufwand' AND typ = 'main'  
		UPDATE @estimation SET cost_in_minutes =  ISNULL((SELECT SUM(cost_in_minutes) FROM @estimation WHERE typ='main' AND foreignkey IN('Umsetzung','Übertragung') ),0) WHERE foreignkey = 'Umsetzungsaufwand' AND typ = 'main'  
		UPDATE @estimation SET cost_in_minutes =  ISNULL((SELECT SUM(cost_in_minutes) FROM @estimation WHERE typ='main' AND foreignkey IN('QS') ),0) WHERE foreignkey = 'QS/PL-Aufwand' AND typ = 'main'  
		--UPDATE @estimation SET cost_in_minutes =  @costs WHERE foreignkey = 'Konzeptionaufwand' AND typ = 'main'  
		--UPDATE @estimation SET cost_in_minutes =  @costs WHERE foreignkey = 'Konzeptionaufwand' AND typ = 'main'  
 
	RETURNEND
GO
/****** Object:  UserDefinedFunction [dbo].[CRENT_UPDATES6_BETWEENDATES]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[CRENT_UPDATES6_BETWEENDATES] (@MandantID INT = null)
RETURNS  @updates TABLE(number INT NULL , numberLive INT NULL ,numberACC INT NULL )
BEGIN 
	INSERT INTO @updates
	        ( number, numberLive, numberACC )
			SELECT 
				(SELECT COUNT(*) FROM dbo.MANDANT_WEB_PRODUKTE WHERE TIMEOFUPDATE BETWEEN DATEADD(day,-7,CURRENT_TIMESTAMP) AND CURRENT_TIMESTAMP ),
				(SELECT COUNT(*) FROM dbo.MANDANT_WEB_PRODUKTE WHERE TIMEOFUPDATE BETWEEN DATEADD(day,-7,CURRENT_TIMESTAMP) AND CURRENT_TIMESTAMP AND Environment='LIVE' ),
				(SELECT COUNT(*) FROM dbo.MANDANT_WEB_PRODUKTE WHERE TIMEOFUPDATE BETWEEN DATEADD(day,-7,CURRENT_TIMESTAMP) AND CURRENT_TIMESTAMP AND Environment='ACC' )

	RETURNEND
GO
