/****** Object:  UserDefinedFunction [dbo].[CRW_ISO_DATE]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[CRW_ISO_DATE] (@date DATETIME =NULL, @time varchar(4) = '')  
RETURNS VARCHAR(24) AS  
BEGIN
  --Author José. Created on February 8th 2015
  IF(@date IS NULL) SET @date = (SELECT CURRENT_TIMESTAMP)
  IF(@time = '') 
	BEGIN
		SET @time = dbo.dattoctime(@date)
		RETURN CONVERT(VARCHAR,@date,126)
	END 
  DECLARE @iso_date VARCHAR(16)
  SELECT @iso_date=null
  IF(LEN(@time)=4) 
    IF (CONVERT(INT,RIGHT(@time,2))<60)
      IF (CONVERT(INT,SUBSTRING(@time,1,2))<25)
        IF ((@date IS NOT NULL) AND ((@time IS NOT NULL) and (@time<>'    ')))
           SET @iso_date=(SUBSTRING(CONVERT(VARCHAR,@date,126),1,10)+'T'+(SUBSTRING(@time,1,2)+':'+RIGHT(@time,2)))--+':00.0'
           --SET @iso_date=CONVERT(VARCHAR,DATEADD(SECOND, DATEDIFF(SECOND, 0, (SUBSTRING(@time,1,2)+':'+RIGHT(@time,2))), @date),126)  
  RETURN @iso_date+':00.0'
END
GO
