CREATE FUNCTION [dbo].[CSAPP_GET_API_URLS]
(
	-- Add the parameters for the function here
	@appcode varchar(255), @url varchar(255)
)
RETURNS 
@database TABLE 
(
	dbHost varchar(255),
	dbInstance varchar(255),
	dbName varchar(255),	
	dbUser varchar(255),
	dbPort int,
	apiUrl varchar(255)
)
AS
BEGIN



insert into @database	
SELECT c0_.HOST, c0_.INSTANCE, c0_.DB, c0_.DB_USER, c0_.[PORT], c0_.URL FROM Mandant m1_ LEFT JOIN CSAPP_version_URL c0_ ON (c0_.mandant = m1_.id) 
WHERE m1_.companyAppCode = @appcode 
AND c0_.CSAPP_URL = SUBSTRING(@url, 0, (LEN(c0_.CSAPP_URL) + '1')) AND c0_.CSAPP_URL <> '';
	
	RETURN 
END
GO
/****** Object:  UserDefinedFunction [dbo].[CSAPP_GET_CURRENT_version]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE function [dbo].[CSAPP_GET_CURRENT_version] (@app varchar(255))
RETURNS varchar(30)
as
begin
DECLARE @maxLength INT = (SELECT MAX(LEN(REPLACE([version],'.',''))) FROM CSAPP_version_URL where APP_TYPE = @app)
declare @maxversion INT = ( select MAX(convert(INT, LEFT(REPLACE([version],'.','') + REPLICATE('0', @maxLength), @maxLength))) from CSAPP_version_URL where APP_TYPE = @app)

declare @result varchar(30) = (select TOP 1 [version] from CSAPP_version_URL where convert(INT, LEFT(REPLACE([version],'.','') + REPLICATE('0', @maxLength), @maxLength)) = @maxversion)


return @result
end
GO
/****** Object:  UserDefinedFunction [dbo].[customTableDDL]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[customTableDDL] (@table VARCHAR(128),  @viewDefinitionColumnNumber INT = 4, @addSearchButton BIT=0, @addACIDButtons BIT = 0 ) 
RETURNS @tableDefinition TABLE (PK INT NOT NULL IDENTITY(1,1), field NVARCHAR(255) NULL, fieldDefinition NVARCHAR(255), isIdentity VARCHAR(1) NULL, tsqlDataType VARCHAR(128) NULL,  inputType VARCHAR(128) NULL, [labelColumn] VARCHAR(3) NULL, [labelRow] VARCHAR(3) NULL, [elementColumn] VARCHAR(3) NULL, [elementRow] VARCHAR(3) NULL)
BEGIN  --Author Jose
		--SET @viewDefinitionColumnNumber *=2
		IF (@addSearchButton = 1 AND @addACIDButtons = 0)-- entweder search oder ACID
			INSERT INTO @tableDefinition (field , fieldDefinition , isIdentity, inputType)
				SELECT @table+'_ACID_Button','NVARCHAR(32)',0,'button'
		INSERT INTO @tableDefinition (field , fieldDefinition , isIdentity, inputType)
			SELECT fieldAlias, fieldDataType, 1[readOnly], 'inputText' FROM dbo.TABLE_RELATION (@table) 
		INSERT INTO @tableDefinition (field , fieldDefinition , isIdentity)
			SELECT COLUMN_NAME, dbo.fn_GetTFieldDDL(@table,COLUMN_NAME,DEFAULT), ISNULL(COLUMNPROPERTY(object_id(TABLE_SCHEMA+'.'+TABLE_NAME), COLUMN_NAME, 'IsIdentity'),0)  FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @table ORDER BY ORDINAL_POSITION ASC
		IF (@addSearchButton = 0 AND @addACIDButtons = 1)-- entweder search oder ACID
			BEGIN
				INSERT INTO @tableDefinition (field , fieldDefinition , isIdentity, inputType)
					SELECT @table+'_UPDATE_ACID_Button','NVARCHAR(32)',0,'button' 				
				INSERT INTO @tableDefinition (field , fieldDefinition , isIdentity, inputType)
					SELECT @table+'_INSERT_ACID_Button','NVARCHAR(32)',0,'button' 
				INSERT INTO @tableDefinition (field , fieldDefinition , isIdentity, inputType)
					SELECT @table+'_DELETE_ACID_Button','NVARCHAR(32)',0,'button' 
			END
             
		IF EXISTS (SELECT TOP 1 PK FROM @tableDefinition)
			BEGIN
				UPDATE @tableDefinition SET elementColumn = CASE WHEN ( (PK * 2) % @viewDefinitionColumnNumber) = 0 THEN @viewDefinitionColumnNumber ELSE (PK * 2) % @viewDefinitionColumnNumber END 
				UPDATE @tableDefinition SET labelColumn  =  elementColumn - 1
				UPDATE @tableDefinition SET labelRow =  CEILING(CAST (pk AS FLOAT)/ (@viewDefinitionColumnNumber/2) )
				UPDATE @tableDefinition SET elementRow  =  labelRow
				UPDATE @tableDefinition SET inputType = 'checkbox' WHERE fieldDefinition LIKE '%BIT%'
				UPDATE @tableDefinition SET inputType = 'inputText' WHERE fieldDefinition NOT LIKE '%BIT%' AND inputType IS NULL
				UPDATE @tableDefinition SET tsqlDataType = REPLACE(fieldDefinition,'['+field+']','')								
				UPDATE @tableDefinition SET tsqlDataType = REPLACE(tsqlDataType,'NOT','')				
				UPDATE @tableDefinition SET tsqlDataType = REPLACE(tsqlDataType,'NULL','')	 
				UPDATE @tableDefinition SET tsqlDataType = REPLACE(tsqlDataType,'IDENTITY(1,1)','')
				UPDATE @tableDefinition SET tsqlDataType = REPLACE(tsqlDataType,' ','')		
				--UPDATE @tableDefinition SET tsqlDataTypeDefaultValue = '0' WHERE tsqlDataType IN ('BIGINT', 'INT', 'DECIMAL', 'MONEY', 'FLOAT')
				--UPDATE @tableDefinition SET tsqlDataTypeDefaultValue = '' WHERE tsqlDataType LIKE '%VARCHAR%' OR tsqlDataType IN ('tsqlDataType')
			END 
    RETURN 
END
GO
