/****** Object:  UserDefinedFunction [dbo].[dattoctime]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[dattoctime] (@adate DATETIME)
RETURNS VARCHAR(4)
BEGIN
  DECLARE @result VARCHAR(4)
  SELECT @result=REPLACE(LEFT(SUBSTRING(CONVERT(varchar(24), @adate, 121), 12, 12),5),':','')  
  RETURN @result
END
GO
/****** Object:  UserDefinedFunction [dbo].[Dattodt]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[Dattodt] (@ADate DateTime,
			 @ATime varchar(4))  
RETURNS DateTIme AS  
BEGIN
  declare @res datetime
  select @res=null
  if (len(@ATime)=4) 
    if (convert(int,right(@ATime,2))<60)
      if (convert(int,substring(@ATime,1,2))<24)
        if (not(@Adate is null) and (not (@ATime is null) and (@ATime<>'    ')))
           select @res=convert(datetime,(convert(varchar,@ADate,104)+' '+(substring(@ATime,1,2)+':'+right(@ATime,2))))
  return @res
END

GO
/****** Object:  UserDefinedFunction [dbo].[DEPLOY_TRANSLATIONS]    Script Date: 25.01.2022 03:14:46 ******/
