CREATE FUNCTION [dbo].[DEPLOY_TRANSLATIONS](@MandantId INT = null, @Environment NVARCHAR(128) = 'ACC', @from NVARCHAR(128) = 'STATIC_DATA_TO_CLIENT')
RETURNS NVARCHAR(MAX)
BEGIN
	DECLARE @BATINSTRUCTIONS NVARCHAR(MAX)
	DECLARE @ip NVARCHAR(255), @dbname NVARCHAR(255), @dbuser NVARCHAR(512)='', @dbpassword NVARCHAR(512)='',
	@XMLCompareData XML

	SET @BATINSTRUCTIONS = 'INVALID_DIRECTION' 
	IF (@Environment = 'LIVE') SET @Environment='DEFAULT'
	IF(NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN 
		RETURN 'INVALID_ABAS_ID'
	END
	IF @from NOT IN ('STATIC_DATA_TO_CLIENT', 'CLIENT_TO_STATIC_DATA')
		RETURN @BATINSTRUCTIONS
	IF @Environment NOT IN ('DEFAULT', 'ACC')
		RETURN @BATINSTRUCTIONS

	IF (EXISTS (SELECT * FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@Environment and version = '6.0'))
		BEGIN 
			SELECT TOP 1 @dbname=ISNULL(databaseName,''), @dbuser=ISNULL(databaseUser,''), @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
			@ip=ISNULL(databaseIp,'')+
			   CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END + 
				CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(databasePort)=1 /*intern extern unterschied*/  THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@Environment and version = '6.0'	 
		END 
	ELSE RETURN '' 

	SET @dbpassword = dbo.SEC_GetPWCOde(@dbuser)

	DECLARE @FROMDBBATINSTRUCTIONS NVARCHAR(1024) = '
 				SET FROMServer=192.168.254.209\SQL2012DEV
				SET FROMServerUser=
				SET FROMServerPW= 
				SET FROMDB=crentdev_jmunoz

	'
	DECLARE @TODBBATINSTRUCTIONS NVARCHAR(1024) = '
				SET TOServer='+@ip+'
				SET TOServerUser='+dbo.GET_BATCH_ESCAPED_PWD(@dbuser)+' 
				SET TOServerPW='+dbo.GET_BATCH_ESCAPED_PWD(@dbpassword)+'
				SET TODB='+@dbname+'
	'
	
	DECLARE @TODB_TRANSLATION_INSTRUCTIONS NVARCHAR(MAX) = '
				    SET GLOBALLOGMESSAGE=Patches are going to be applied to %TOServer%.%TODB% 
					::but from install tool
					SET SQLCONTENTS4=EXEC dbo.GET_CLIENT_TRANSLATIONS_SQL_COMMAND 
					SET GLOBALLOGMESSAGE=getting Patches with TSQL commant %SQLCONTENTS4%
					echo %GLOBALLOGMESSAGE%
					echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
					SET GLOBALLOGMESSAGE=getting Patches with TSQL commant %SQLCONTENTS5%
					echo %GLOBALLOGMESSAGE%
					echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
					 
					SET FileInputTranslationCommand=\\ku-fs01.kunden.local\deployment\post_trans6\logs\SQLCLIENT_TRANS_SQLABASID%MandantID%_'+@Environment+'_SQLInstructionsInput.sql
					SET FileOutputTranslationCommand=\\ku-fs01.kunden.local\deployment\post_trans6\logs\SQLCLIENT_TRANS_SQLABASID%MandantID%_'+@Environment+'_SQLInstructionsOutput.sql					
					SET FileOutputTranslationCommandResult=\\ku-fs01.kunden.local\deployment\post_trans6\logs\SQLCLIENT_TRANS_SQLABASID%MandantID%_'+@Environment+'_SQLInstructionsOutputResult.sql
					SET FileInputTSQLCommandResult=\\ku-fs01.kunden.local\deployment\post_trans6\logs\SQLCLIENT_TRANS_SQLABASID%MandantID%_'+@Environment+'_FileInputTSQLCommandResult.sql
					echo. 2>%FileInputTSQLCommandResult%
					echo. 2>%FileInputTranslationCommand%
					echo>> %FileInputTranslationCommand% %SQLCONTENTS4%  
					echo>> %FileInputTranslationCommand% GO	
					::type %FileInputTranslationCommand%		
				 

					echo. 2>%FileOutputTranslationCommand%
					echo>> %FileOutputTranslationCommand% GO

					echo. 2>%FileOutputTranslationCommandResult%
					echo>> %FileOutputTranslationCommandResult% GO

				set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %FileInputTranslationCommand% -o %FileOutputTranslationCommandResult%"
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE% 					 

				sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %FileInputTranslationCommand% -o %FileOutputTranslationCommandResult%

					::hier prog


				set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %FROMServer% -d %FROMDB% -i %FileOutputTranslationCommandResult% -o %FileInputTSQLCommandResult%"
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE% 
				::type %FileOutputTranslationCommandResult% 
				 
				sqlcmd -S %FROMServer% -d %FROMDB% -i %FileOutputTranslationCommandResult% -o %FileInputTSQLCommandResult%
 




					SET GLOBALLOGMESSAGE=Berechnete Uebersetzungen wurden db: %TOServer%.%TODB% extraiert
					echo %GLOBALLOGMESSAGE%
					echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
					::type %FileOutputTranslationCommand%
				 	del %FileInputTranslationCommand%
				 	del %FileOutputTranslationCommand%
				 	del %FileOutputTranslationCommandResult%
					if exist "\\ku-fs01.kunden.local\deployment\post_trans6\logs\*.*" (
						echo TEMP_FILES are goint to be DELETED
						timeout 2              
						DEL /Q /F /S "\\ku-fs01.kunden.local\deployment\post_trans6\logs\PROCESS*.*"
					)
	'

	DECLARE @IMPORT_EXPORT_DIRECTION_BATINSTUCTIONS NVARCHAR(MAX) = '
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=Exporting translations from %FROMServer%.%FROMDB% ... Estimated time 12 Seconds ...
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%


				set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %FROMServer% -d %FROMDB% -i %SQLInfoProCallFileSCP% -o %ResultSQLTransFile1%"
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE% 

				sqlcmd -S %FROMServer% -d %FROMDB% -i %SQLInfoProCallFileSCP% -o %ResultSQLTransFile1%
 
				SET GLOBALLOGMESSAGE=Exporting translations from %FROMServer%.%FROMDB% done
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%

				echo.
				echo.
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=Importing translations to %TOServer%.%TODB% ..... Estimated time 9 Seconds ...
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%


				set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %ResultSQLTransFile1% -o %ResultSQLGetTranslationsFile%"
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE% 
				sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %ResultSQLTransFile1% -o %ResultSQLGetTranslationsFile%

				SET GLOBALLOGMESSAGE=Importing translations to %TOServer%.%TODB% done
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo.	
	'
	IF (@from = 'CLIENT_TO_STATIC_DATA')
		BEGIN
			SET @FROMDBBATINSTRUCTIONS = '
 				SET FROMServer='+@ip+'
				SET FROMServerUser='+@dbuser+'
				SET FROMServerPW='+dbo.GET_BATCH_ESCAPED_PWD(@dbpassword)+'
				SET FROMDB='+@dbname+'
			'
			SET @TODBBATINSTRUCTIONS = '
