	DECLARE @BATINSTRUCTIONS NVARCHAR(MAX)
	DECLARE @MandantId INT = null, @Environment NVARCHAR(128) = '_unknown_'
	DECLARE @ip NVARCHAR(255), @dbname NVARCHAR(255), @dbuser NVARCHAR(512)='', @dbpassword NVARCHAR(512)='',
	@XMLCompareData XML

