				echo>> %SQLInfoProCallFileSCP% %SQLCONTENTS_FINAL_TRANS%
				echo>> %SQLInfoProCallFileSCP% GO
				'+@TODB_TRANSLATION_INSTRUCTIONS+'

				SET GLOBALLOGMESSAGE=Executing ExportSQLTansJob: %MandantID% 
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=FROMServer connection %FROMServer%.%FROMDB% is going to be stablished and SQL JOB "%MandantID%" is going to be created
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo.

				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET ResultSQLTransFile1=\\ku-fs01.kunden.local\deployment\post_trans6\logs\FROM_%FROMDB%_DB%MandantID%_'+@Environment+'__translationsTOBeimported.sql
				SET GLOBALLOGMESSAGE=The file %ResultSQLTransFile1% is going to be created
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo. 2>%ResultSQLTransFile1%
				echo>> %ResultSQLTransFile1% GO

				SET ResultSQLGetTranslationsFile=\\ku-fs01.kunden.local\deployment\post_trans6\logs\FROM_%FROMDB%_DB%MandantID%_'+@Environment+'__translations_res.txt
				SET GLOBALLOGMESSAGE=The file %ResultSQLGetTranslationsFile% is going to be created
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo. 2>%ResultSQLGetTranslationsFile%
				echo>> %ResultSQLGetTranslationsFile% GO

				'+@IMPORT_EXPORT_DIRECTION_BATINSTUCTIONS+'
				echo.
				SET /p XMLSCPFilename=<%ResultSQLGetTranslationsFile%

				echo.
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=SQL Result from Query %SQLCONTENTS_FINAL_TRANS% into DB
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=%TOServer%.%TODB%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				::type %ResultSQLTransFile1%
				::type %ResultSQLGetTranslationsFile%
				echo.
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
		 
 
				echo.
				echo.
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=Deleting temp files...:
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=%SQLInfoProCallFileSCP%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=%ResultSQLTransFile1%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=%ResultSQLGetTranslationsFile%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%

				::del %SQLInfoProCallFileSCP% 
				::del %ResultSQLTransFile1%
				::del %ResultSQLGetTranslationsFile%
				::del %SQLInfoProCallFileSCP%
				::del %TRANS_GENERALGLOBALLOGFILE%
					if exist "\\ku-fs01.kunden.local\deployment\post_trans6\logs\*.*" (
						echo TEMP_FILES are goint to be DELETED
						timeout 2              
						DEL /Q /F /S "\\ku-fs01.kunden.local\deployment\post_trans6\logs\PROCESS*.*"
					)
				Goto :Eof
  
	'
	RETURN @BATINSTRUCTIONSEND
