/****** Object:  UserDefinedFunction [dbo].[EXTRACT_MR_FROM_LOGS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[EXTRACT_MR_FROM_LOGS] (@xmlInputLog XML = NULL,@startPatern VARCHAR(MAX)='http',@endPatern VARCHAR(MAX)=' remote: To gitlab.cx9.info')
RETURNS VARCHAR(MAX)
BEGIN
	IF (@xmlInputLog IS NULL)
		RETURN ''
	DECLARE @start INT = 0
	DECLARE @end INT = 0
 
	DECLARE @path VARCHAR(128)=ISNULL(@xmlInputLog.value('local-name(/*[1])','NVARCHAR(128)'),'')
	DECLARE @extractedString VARCHAR(MAX)=''
	DECLARE @logMessage VARCHAR(MAX)=''
	DECLARE @logType VARCHAR(128)=''
	DECLARE @compareType VARCHAR(128)=ISNULL(@xmlInputLog.value('(/*[local-name()=sql:variable("@path")]/@type)[1]','NVARCHAR(128)'),'')
	DECLARE @compareEnvironemnt VARCHAR(128)=ISNULL(@xmlInputLog.value('(/*[local-name()=sql:variable("@path")]/@environment)[1]','NVARCHAR(128)'),'')
	WHILE (SELECT @xmlInputLog.exist('(/*[local-name()=sql:variable("@path")]/logs/log)[1]')) = 1
		BEGIN 
			SET @logMessage = ISNULL(@xmlInputLog.value('(/*[local-name()=sql:variable("@path")]/logs/log/text())[1]','VARCHAR(MAX)'),'')
			SET @logType = ISNULL(@xmlInputLog.value('(/*[local-name()=sql:variable("@path")]/logs/log/@type)[1]','NVARCHAR(MAX)'),'')
			SET @start = CHARINDEX(@startPatern,@logMessage)
			SET @end = CHARINDEX(@endPatern,@logMessage)
 
			IF (@start > 0 AND @end > @start)
				SET @extractedString = SUBSTRING(@logMessage,@start,@end-@start)
			SET @xmlInputLog.modify('delete (/*[local-name()=sql:variable("@path")]/logs/log)[1]')
		END 
	RETURN @extractedString 
END
GO
