/****** Object:  UserDefinedFunction [dbo].[fn_GetTFieldDDL]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[fn_GetTFieldDDL] (@TBL VARCHAR(255), @TBL_FIELD VARCHAR(255), @TBL_REPLACE_NAME VARCHAR(255) = '')
RETURNS VARCHAR(MAX)
AS
BEGIN
	-- created anhand http://www.stormrage.com/SQLStuff/sp_GetDDL_Latest.txt
	-- Fragen an José
  DECLARE     @TBLNAME                VARCHAR(200),
              @SCHEMANAME             VARCHAR(255),
              @STRINGLEN              INT,
              @TABLE_ID               INT,
              @FINALSQL               VARCHAR(MAX) = '',
              @vbCrLf                 CHAR(2),
              @ObjectDataTypeLen      INT;

  
  --SET @TBL =  '[DBO].[WHATEVER1]'
  --does the tablename contain a schema? 
  SET @vbCrLf =  ''
  SELECT @SCHEMANAME = ISNULL(PARSENAME(@TBL,2),'dbo') ,
         @TBLNAME    = PARSENAME(@TBL,1);
  SELECT
    @TBLNAME    = [OBJS].[name],
    @TABLE_ID   = [OBJS].[object_id]
  FROM [sys].[objects] [OBJS]
  WHERE [OBJS].[type]          IN ('S','U')
    AND [OBJS].[name]          <>  'dtproperties'
    AND [OBJS].[name]           =  @TBLNAME
    AND [OBJS].[schema_id] =  SCHEMA_ID(@SCHEMANAME) ;

 SELECT @ObjectDataTypeLen = MAX(LEN([name])) from [sys].[types];
  
 IF NOT EXISTS (SELECT * FROM sys.columns WHERE  object_id = OBJECT_ID(QUOTENAME(@SCHEMANAME) + '.' + QUOTENAME(@TBLNAME)) AND name = @TBL_FIELD)
	SET @FINALSQL = ''
 ELSE
 BEGIN
  SELECT 
   @FINALSQL =  ''
  SELECT
    @STRINGLEN = MAX(LEN([COLS].[name])) + 1
  FROM [sys].[objects] [OBJS]
    INNER JOIN [sys].[columns] [COLS]
      ON  [OBJS].[object_id] = [COLS].[object_id]
      AND [OBJS].[object_id] = @TABLE_ID 
--Get the column definition
  SELECT
    @FINALSQL = @FINALSQL
    + CASE
        WHEN [COLS].[is_computed] = 1
        THEN @vbCrLf
             + QUOTENAME([COLS].[name])
             + ' '
             + SPACE(@STRINGLEN - LEN([COLS].[name]))
             + 'AS ' + ISNULL([CALC].[definition],'')
             + CASE 
                 WHEN [CALC].[is_persisted] = 1 
                 THEN ' PERSISTED'
                 ELSE ''
               END
        ELSE @vbCrLf
             + QUOTENAME([COLS].[name])
             + ' '
             + SPACE(@STRINGLEN - LEN([COLS].[name]))
             + UPPER(TYPE_NAME([COLS].[user_type_id]))
             + CASE
-- data types with precision and scale  IE DECIMAL(18,3), NUMERIC(10,2)
               WHEN TYPE_NAME([COLS].[user_type_id]) IN ('decimal','numeric')
               THEN '('
                    + CONVERT(VARCHAR,[COLS].[precision])
                    + ','
                    + CONVERT(VARCHAR,[COLS].[scale])
                    + ') '
                    + SPACE(6 - LEN(CONVERT(VARCHAR,[COLS].[precision])
                    + ','
                    + CONVERT(VARCHAR,[COLS].[scale])))
                    + SPACE(7)
                    + SPACE(@ObjectDataTypeLen - LEN(TYPE_NAME([COLS].[user_type_id])))
                    + CASE
                        WHEN COLUMNPROPERTY ( @TABLE_ID , [COLS].[name] , 'IsIdentity' ) = 0
                        THEN ''
                        ELSE ' IDENTITY('
                               + CONVERT(VARCHAR,ISNULL(IDENT_SEED(@TBLNAME),1) )
                               + ','
                               + CONVERT(VARCHAR,ISNULL(IDENT_INCR(@TBLNAME),1) )
                               + ')'
                        END
                    + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                    + CASE
                        WHEN [COLS].[is_nullable] = 0
                        THEN ' NOT NULL'
                        ELSE '     NULL'
                      END
-- data types with scale  IE datetime2(7),TIME(7)
               WHEN TYPE_NAME([COLS].[user_type_id]) IN ('datetime2','datetimeoffset','time')
               THEN CASE 
                      WHEN [COLS].[scale] < 7 THEN
                      '('
                      + CONVERT(VARCHAR,[COLS].[scale])
                      + ') '
                    ELSE 
                      '    '
                    END
                    + SPACE(4)
                    + SPACE(@ObjectDataTypeLen - LEN(TYPE_NAME([COLS].[user_type_id])))
                    --+ '        '
                    + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                    + CASE
                        WHEN [COLS].[is_nullable] = 0
                        THEN ' NOT NULL'
                        ELSE '     NULL'
                      END

--data types with no/precision/scale,IE  FLOAT
               WHEN  TYPE_NAME([COLS].[user_type_id]) IN ('float') --,'real')
               THEN
               --addition: if 53, no need to specifically say (53), otherwise display it
                    CASE
                      WHEN [COLS].[precision] = 53
                      THEN SPACE(11 - LEN(CONVERT(VARCHAR,[COLS].[precision])))
                           + SPACE(7)
                           + SPACE(@ObjectDataTypeLen - LEN(TYPE_NAME([COLS].[user_type_id])))
                           + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                           + CASE
                               WHEN [COLS].[is_nullable] = 0
                               THEN ' NOT NULL'
                               ELSE '     NULL'
                             END
                      ELSE '('
                           + CONVERT(VARCHAR,[COLS].[precision])
                           + ') '
                           + SPACE(6 - LEN(CONVERT(VARCHAR,[COLS].[precision])))
                           + SPACE(7) + SPACE(@ObjectDataTypeLen - LEN(TYPE_NAME([COLS].[user_type_id])))
                           + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                           + CASE
                               WHEN [COLS].[is_nullable] = 0
                               THEN ' NOT NULL'
                               ELSE '     NULL'
                             END
                      END
--data type with max_length		ie CHAR (44), VARCHAR(40), BINARY(5000),
--##############################################################################
-- COLLATE STATEMENTS
-- personally i do not like collation statements,
-- but included here to make it easy on those who do
--##############################################################################
               WHEN  TYPE_NAME([COLS].[user_type_id]) IN ('char','varchar','binary','varbinary')
               THEN CASE
                      WHEN  [COLS].[max_length] = -1
                      THEN  '(MAX)'
                            + SPACE(6 - LEN(CONVERT(VARCHAR,[COLS].[max_length])))
                            + SPACE(7) + SPACE(@ObjectDataTypeLen - LEN(TYPE_NAME([COLS].[user_type_id])))
                            ----collate to comment out when not desired
                            --+ CASE
                            --    WHEN COLS.collation_name IS NULL
                            --    THEN ''
                            --    ELSE ' COLLATE ' + COLS.collation_name
                            --  END
                            + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                            + CASE
                                WHEN [COLS].[is_nullable] = 0
                                THEN ' NOT NULL'
                                ELSE '     NULL'
                              END
                      ELSE '('
                           + CONVERT(VARCHAR,[COLS].[max_length])
                           + ') '
                           + SPACE(6 - LEN(CONVERT(VARCHAR,[COLS].[max_length])))
                           + SPACE(7) + SPACE(@ObjectDataTypeLen - LEN(TYPE_NAME([COLS].[user_type_id])))
                           ----collate to comment out when not desired
                           --+ CASE
                           --     WHEN COLS.collation_name IS NULL
                           --     THEN ''
                           --     ELSE ' COLLATE ' + COLS.collation_name
                           --   END
                           + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                           + CASE
                               WHEN [COLS].[is_nullable] = 0
                               THEN ' NOT NULL'
                               ELSE '     NULL'
                             END
                    END
--data type with max_length ( BUT DOUBLED) ie NCHAR(33), NVARCHAR(40)
               WHEN TYPE_NAME([COLS].[user_type_id]) IN ('nchar','nvarchar')
               THEN CASE
                      WHEN  [COLS].[max_length] = -1
                      THEN '(MAX)'
                           + SPACE(5 - LEN(CONVERT(VARCHAR,([COLS].[max_length] / 2))))
                           + SPACE(7)
                           + SPACE(@ObjectDataTypeLen - LEN(TYPE_NAME([COLS].[user_type_id])))
                           ----collate to comment out when not desired
                           --+ CASE
                           --     WHEN COLS.collation_name IS NULL
                           --     THEN ''
                           --     ELSE ' COLLATE ' + COLS.collation_name
                           --   END
                           + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                           + CASE
                               WHEN [COLS].[is_nullable] = 0
                               THEN  ' NOT NULL'
                               ELSE '     NULL'
                             END
                      ELSE '('
                           + CONVERT(VARCHAR,([COLS].[max_length] / 2))
                           + ') '
                           + SPACE(6 - LEN(CONVERT(VARCHAR,([COLS].[max_length] / 2))))
                           + SPACE(7)
                           + SPACE(@ObjectDataTypeLen - LEN(TYPE_NAME([COLS].[user_type_id])))
                           ----collate to comment out when not desired
                           --+ CASE
                           --     WHEN COLS.collation_name IS NULL
                           --     THEN ''
                           --     ELSE ' COLLATE ' + COLS.collation_name
                           --   END
                           + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                           + CASE
                               WHEN [COLS].[is_nullable] = 0
                               THEN ' NOT NULL'
                               ELSE '     NULL'
                             END
                    END

               WHEN TYPE_NAME([COLS].[user_type_id]) IN ('datetime','money','text','image','real')
               THEN SPACE(18 - LEN(TYPE_NAME([COLS].[user_type_id])))
                    + '              '
                    + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                    + CASE
                        WHEN [COLS].[is_nullable] = 0
                        THEN ' NOT NULL'
                        ELSE '     NULL'
                      END

--  other data type 	IE INT, DATETIME, MONEY, CUSTOM DATA TYPE,...
               ELSE SPACE(@ObjectDataTypeLen - LEN(TYPE_NAME([COLS].[user_type_id])))
                            + CASE
                                WHEN COLUMNPROPERTY ( @TABLE_ID , [COLS].[name] , 'IsIdentity' ) = 0
                                THEN '              '
                                ELSE ' IDENTITY('
                                     + CONVERT(VARCHAR,ISNULL(IDENT_SEED(@TBLNAME),1) )
                                     + ','
                                     + CONVERT(VARCHAR,ISNULL(IDENT_INCR(@TBLNAME),1) )
                                     + ')'
                              END
                            + SPACE(2)
                            + CASE  WHEN [COLS].[is_sparse] = 1 THEN ' sparse' ELSE '       ' END
                            + CASE
                                WHEN [COLS].[is_nullable] = 0
                                THEN ' NOT NULL'
                                ELSE '     NULL'
                              END
               END
             + CASE
                 WHEN [COLS].[default_object_id] = 0
                 THEN ''
                 --ELSE ' DEFAULT '  + ISNULL(def.[definition] ,'')
                 --optional section in case NAMED default constraints are needed:
                 --ELSE '  CONSTRAINT ' + quotename([DEF].[name]) + ' DEFAULT ' + ISNULL([DEF].[definition] ,'') -- no constraints are going to be defined
                 ELSE '' 
                        --i thought it needed to be handled differently! NOT!
               END  --CASE cdefault
      END --iscomputed    
    FROM [sys].[columns] [COLS]
      LEFT OUTER JOIN  [sys].[default_constraints]  [DEF]
        ON [COLS].[default_object_id] = [DEF].[object_id]
      LEFT OUTER JOIN [sys].[computed_columns] [CALC]
         ON  [COLS].[object_id] = [CALC].[object_id]
         AND [COLS].[column_id] = [CALC].[column_id]
    WHERE [COLS].[object_id]=@TABLE_ID
	AND [COLS].[name] = @TBL_FIELD
    ORDER BY [COLS].[column_id] 	
 END
  
	IF(@FINALSQL <> '')
		BEGIN 
			WHILE (CHARINDEX('  ',@FINALSQL)> 0)
				BEGIN
					SET @FINALSQL = REPLACE(@FINALSQL,'  ',' ')	 
				END
				
			IF (@TBL_REPLACE_NAME <> '')
				BEGIN
				  SELECT @TBL_REPLACE_NAME    = PARSENAME(@TBL_REPLACE_NAME,1)
					SET @FINALSQL = REPLACE(@FINALSQL, QUOTENAME(@SCHEMANAME) + '.' + QUOTENAME(@TBLNAME), QUOTENAME(@SCHEMANAME) + '.' + QUOTENAME(@TBL_REPLACE_NAME))	    
				END
			
		END
	

RETURN @FINALSQL--[FINALSQL]
 
END 
GO
/****** Object:  UserDefinedFunction [dbo].[fnSplitString]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[fnSplitString] (  @string NVARCHAR(MAX),  @delimiter CHAR(1) ) 
RETURNS @output TABLE(splitdata NVARCHAR(MAX) ) 
BEGIN 
    DECLARE @start INT, @end INT 
    SELECT @start = 1, @end = CHARINDEX(@delimiter, @string) 
    WHILE @start < LEN(@string) + 1 BEGIN 
        IF @end = 0  
            SET @end = LEN(@string) + 1
       
        INSERT INTO @output (splitdata)  
        VALUES(SUBSTRING(@string, @start, @end - @start)) 
        SET @start = @end + 1 
        SET @end = CHARINDEX(@delimiter, @string, @start)
        
    END 
    RETURN 
END
GO
/****** Object:  UserDefinedFunction [dbo].[GenPass]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- ============================================================
-- Author:      Eli Leiba
-- Create date: 01-2018
-- Description: a view and a scalar UDF to generate a random
-- 8 characters password
-- ============================================================
CREATE FUNCTION [dbo].[GenPass](@sonderzeichen BIT=0)
RETURNS VARCHAR(10)
AS
BEGIN
       -- Declare the variables here
       DECLARE @Result VARCHAR(10)
       DECLARE @BinaryData VARBINARY(8)
       DECLARE @CharacterData VARCHAR(10)

       SELECT @BinaryData = randval
       FROM vRandom

       Set @CharacterData=cast('' as xml).value('xs:base64Binary(sql:variable("@BinaryData"))', 'varchar (max)')
   
       IF @sonderzeichen=1
       BEGIN
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, 'I', '!')
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, 'l', '-')
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, '0', '&')
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, 'O', '$')
       END
       ELSE
       BEGIN
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, 'I', '1')
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, 'l', '7')
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, '0', 'o')
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, 'O', 'C')
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, '+', 'p')
             SET @CharacterData = REPLACE(@CharacterData COLLATE SQL_Latin1_General_CP1_CS_AS, '/', 'S')
       END

       SET @Result = @CharacterData
   
       -- Return the result of the function
   RETURN @Result
END
GO
