GO

 
 CREATE FUNCTION [dbo].[GET_ADVANCE_DEPLOY_TRANS_BATCH_FOLDER](@subfolder NVARCHAR(255)= '')
 RETURNS NVARCHAR(MAX)
 BEGIN  

	SET @subfolder = ISNULL(@subfolder,'')
	DECLARE @deploymentBasePath NVARCHAR(2048) = '\\ku-fs01.kunden.local\deployment\'+@subfolder+'\'
	IF (@subfolder = '')
		SET  @deploymentBasePath  = '\\ku-fs01.kunden.local\deployment\'
	DECLARE @deploymentBasePathFilename NVARCHAR(4000) = ''
	DECLARE @deploymentBasePathFileContents NVARCHAR(MAX) = ''

 	DECLARE @BATINSTRUCTIONS NVARCHAR(MAX) 
 	DECLARE @FROMDBBATINSTRUCTIONS NVARCHAR(1024) = '
  			SET FROMServer=192.168.254.209\SQL2012DEV
 			SET FROMServerUser=
 			SET FROMServerPW= 
 			SET FROMDB=crentdev_tseitz
 	'
  
 	
 	DECLARE @TODB_TRANSLATION_INSTRUCTIONS NVARCHAR(MAX) = ' 
 			@Echo Off
 			'+@FROMDBBATINSTRUCTIONS+'
 			echo Translations fuer Kunden
 			echo ==============================================================================
 			
 		
  
 			SET FileInputTranslations="'+@deploymentBasePath+'advance_trans_deployment\tsql.sql"
 			SET FileInputTranslationsResult="'+@deploymentBasePath+'advance_trans_deployment\logs.log"
 			
 			for %%f in ("'+@deploymentBasePath+'advance_trans_deployment\*.sql") do (
 				echo processing file "%%f"
 				set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %FROMServer% -d %FROMDB% -i "%%f" -o "%%f.log"
 				echo %GLOBALLOGMESSAGE%
 				sqlcmd -S %FROMServer% -d %FROMDB% -i "%%f" -o "%%f.log"
 				echo TSQL Results
 				type "%%f.log"
 				echo.
 				echo.
 			)
 			echo Translations were deployed
