CREATE FUNCTION [dbo].[GET_ADVANCE_DEPLOY_TRANS_BATCH_TABLE_REPORTS_FOLDER](@subfolder NVARCHAR(255)= '')
RETURNS NVARCHAR(MAX)
BEGIN
	SET @subfolder = ISNULL(@subfolder,'')
