	IF (@subfolder = '')
		SET  @deploymentBasePath  = '\\ku-fs01.kunden.local\deployment\'
	DECLARE @deploymentBasePathFilename NVARCHAR(4000) = ''
	DECLARE @deploymentBasePathFileContents NVARCHAR(MAX) = ''

 	DECLARE @BATINSTRUCTIONS NVARCHAR(MAX) 
 	DECLARE @FROMDBBATINSTRUCTIONS NVARCHAR(1024) = '
  			SET FROMServer=192.168.254.209\SQL2012DEV
 			SET FROMServerUser=
 			SET FROMServerPW= 
 			SET FROMDB=crentdev_jmunoz
 	'
  
 	
 	DECLARE @TODB_INSTRUCTIONS NVARCHAR(MAX) = ' 
 			@Echo Off
 			'+@FROMDBBATINSTRUCTIONS+'
 			echo report does client have more table field as crent_schema_deployment
 			echo ==============================================================================
 			
 		
  
 			SET FileInputReports="'+@deploymentBasePath+'tableReports\tsql.sql"
 			SET FileInputReportsResult="'+@deploymentBasePath+'tableReports\logs.log"
 			
 			for %%f in ("'+@deploymentBasePath+'tableReports\*.sql") do (
 				echo processing file "%%f"
 				set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %FROMServer% -d %FROMDB% -i "%%f" -o "%%f.log"
 				echo %GLOBALLOGMESSAGE%
 				sqlcmd -S %FROMServer% -d %FROMDB% -i "%%f" -o "%%f.log"
 				echo TSQL Results
 				type "%%f.log"
 				echo.
 				echo.
 			)
 			echo tableReports were analysed
 			TIMEOUT /T 10
 	' 
 	SET @BATINSTRUCTIONS = @TODB_INSTRUCTIONS
  
 	RETURN @BATINSTRUCTIONSEND
GO
