CREATE FUNCTION [dbo].[GET_ARCHIV_SQL_XMLSCHEMACOMPARE] (@XML_SCHEMA_COMPARE XML = NULL, @MANDANT_ID INT = NULL, @MANDANT_ENVIRONMENT NVARCHAR(128) = '')
RETURNS @result TABLE(SCHEMA_COMPARE XML NULL, ARCHIV_SCHEMA_COMPARE XML NULL)  
BEGIN  --Autor José  
	DECLARE @XML_SCHEMA_RESULT XML = @XML_SCHEMA_COMPARE
	DECLARE @ARCHIV_SCHEMA_COMPARE XML  
	DECLARE @ARCHIV_DB VARCHAR(255) = '' 
	DECLARE @ARCHIV_HOST VARCHAR(255) = '' 
	DECLARE @ARCHIV_INSTANCE VARCHAR(255) = '' 
	DECLARE @ARCHIV_DB_USER VARCHAR(255) = '' 
	DECLARE @ARCHIV_DB_USER_PW NVARCHAR(255) = '' 
	DECLARE @ARCHIV_PORT NVARCHAR(255) = '' 
	DECLARE @ARCHIV_IP NVARCHAR(1024) = ''     
    IF (NOT EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MANDANT_ID AND Environment=@MANDANT_ENVIRONMENT))
		INSERT INTO @result
		    SELECT @XML_SCHEMA_RESULT, NULL	
	IF (EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MANDANT_ID AND Environment=@MANDANT_ENVIRONMENT))
		BEGIN
			SELECT TOP 1  @ARCHIV_DB = ISNULL(ARCHIV_DB, @ARCHIV_DB), 
			@ARCHIV_HOST = ISNULL(ARCHIV_HOST, @ARCHIV_HOST), 
			@ARCHIV_INSTANCE = ISNULL(ARCHIV_INSTANCE, @ARCHIV_INSTANCE), 
			@ARCHIV_DB_USER = ISNULL(ARCHIV_DB_USER, @ARCHIV_DB_USER), 
			@ARCHIV_DB_USER_PW = dbo.SEC_GetPWCOde(ARCHIV_DB_USER),
			@ARCHIV_PORT = ISNULL(ARCHIV_PORT, @ARCHIV_PORT),
			@ARCHIV_IP=ISNULL(ARCHIV_HOST,'')+				
				CASE WHEN ISNULL(ARCHIV_INSTANCE,'')<>'' THEN '\'+ARCHIV_INSTANCE ELSE '' END+
				CASE WHEN dbo.isClientExtern(@MANDANT_ID)=1 AND ISNUMERIC(ARCHIV_PORT)=1    THEN ','+CAST(ARCHIV_PORT AS VARCHAR(32)) ELSE '' END   --tsql port sintax		
			FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MANDANT_ID AND Environment=@MANDANT_ENVIRONMENT ORDER BY version DESC	 
		END  	  
	IF (@ARCHIV_DB <> '' AND @XML_SCHEMA_RESULT IS NOT NULL)
		BEGIN
			DECLARE @archivDeployTables XML =
'
      <Table version="1">
        <Include>True</Include>
        <Expression>((@NAME LIKE ''DOCS[_]%'')) OR ((@NAME = ''bilder'')) OR ((@NAME = ''next_pks'')) OR ((@NAME = ''docs''))</Expression>
      </Table>
'
			DECLARE @schemaNotDeployTables XML =
'
      <Table version="1">
        <Include>False</Include>
        <Expression>((@NAME LIKE ''DOCS[_]%'')) OR ((@NAME = ''bilder'')) OR ((@NAME = ''next_pks'')) OR ((@NAME = ''docs''))</Expression>
      </Table>
'        
	IF (@MANDANT_ID = 409) --arndt
		BEGIN
			SET @archivDeployTables =
'
      <Table version="1">
        <Include>True</Include>
        <Expression>((@NAME = ''DOCS'')) OR ((@NAME = ''bilder'')) OR ((@NAME = ''docs_docs''))</Expression>
      </Table>
'		
		SET	@schemaNotDeployTables =
'
      <Table version="1">
        <Include>False</Include>
        <Expression>((@NAME = ''DOCS'')) OR ((@NAME = ''bilder'')) OR ((@NAME = ''docs_docs''))</Expression>
      </Table>
'
		END
			DECLARE @SelectedSyncObjectsArchiv XML = 
'
  <SelectedSyncObjects version="1" type="SelectedSyncObjects">
    <Schemas type="ListString" version="2">
      <value type="string">ZABiAG8A</value>
      <value type="string">UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA</value>
    </Schemas>
    <ZABiAG8A>_</ZABiAG8A>
    <UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>ceEOw2bE7MRHO2asdFCfCwoAABJ9sr4Y5irklyH2c2tMcegKAABd+yoBYoVUbjPyopCJsn1QCgAAWe1Q/wtP4lsn3xYlequs6AoBAA__</UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>
    <Grouping type="ListByte" version="2">
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
    </Grouping>
    <SelectAll>False</SelectAll>
  </SelectedSyncObjects>
'  
	IF (@MANDANT_ID = 409) --arndt
		begin
set @SelectedSyncObjectsArchiv  = 
'
  <SelectedSyncObjects version="1" type="SelectedSyncObjects">
    <Schemas type="ListString" version="2">
      <value type="string">ZABiAG8A</value>
      <value type="string">UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA</value>
    </Schemas>
    <ZABiAG8A>_</ZABiAG8A>
    <UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>ceEOw2bE7MRHO2asdFCfCwoAABJ9sr4Y5irklyH2c2tMcegKAABd+yoBYoVUbjPyopCJsn1QCgAAKCQE62qWtZXUqn06CCeoYgoBAA__</UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>
    <Grouping type="ListByte" version="2">
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
    </Grouping>
    <SelectAll>False</SelectAll>
  </SelectedSyncObjects>
'  
		end

	DECLARE @SelectedSyncObjectsCHEMA XML =    
'  <SelectedSyncObjects version="1" type="SelectedSyncObjects">
    <Schemas type="ListString" version="2">
      <value type="string">ZABiAG8A</value>
      <value type="string">UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA</value>
    </Schemas>
    <ZABiAG8A>__</ZABiAG8A>
    <UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>mTXTBhq1DfjYp7bnvRvyngoBAHHhDsNmxOzERztmrHRQnwsKAAASfbK+GOYq5Jch9nNrTHHoCgAAXfsqAWKFVG4z8qKQibJ9UAoAADvJgfdd5juNpkabzWJb+K8KAQAPPX2osGw+Oq5YB9LTb6tmCgEA+bBynOTJcSzdxMIx6PLr1woBAFntUP8LT+JbJ98WJXqrrOgKAQDuhY6/yW3YAD8n0pcRxPIJCgEA</UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>
    <Grouping type="ListByte" version="2">
      <value type="Byte">63</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
    </Grouping>
    <SelectAll>True</SelectAll>
  </SelectedSyncObjects>'

  declare @ta xml = 
  '    <value version="1" type="SelectTableEvent">
      <action>DeselectItem</action>
      <val>[dbo].[DOCS_STANDARD_BELEGARTEN]:[dbo].[DOCS_STANDARD_BELEGARTEN]</val>
    </value>
	
	'
			SET @ARCHIV_SCHEMA_COMPARE = @XML_SCHEMA_RESULT
			SET @ARCHIV_SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/ServerName/text())[1] with sql:variable("@ARCHIV_IP")')
			SET @ARCHIV_SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/DatabaseName/text())[1] with sql:variable("@ARCHIV_DB")')
			SET @ARCHIV_SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@ARCHIV_DB_USER")')
			SET @ARCHIV_SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@ARCHIV_DB_USER_PW")')
			SET @ARCHIV_SCHEMA_COMPARE.modify('delete (/Project/SelectedSyncObjects)[1]')
			
			/*IF (@MANDANT_ID = 409) --arndt
				begin 
					SET @ARCHIV_SCHEMA_COMPARE.modify('insert sql:variable("@SelectedSyncObjectsArchiv") after (/Project/UserNote)[1]')
					SET @ARCHIV_SCHEMA_COMPARE.modify('insert sql:variable("@archivDeployTables") after (/Project/ProjectFilter/Filters)[1]')
			
				end
			else */
			begin			
				SET @ARCHIV_SCHEMA_COMPARE.modify('insert sql:variable("@SelectedSyncObjectsArchiv") after (/Project/UserNote)[1]')
				SET @ARCHIV_SCHEMA_COMPARE.modify('insert sql:variable("@archivDeployTables") after (/Project/ProjectFilter/Filters)[1]')
			end
			
			SET @XML_SCHEMA_COMPARE.modify('delete (/Project/SelectedSyncObjects)[1]')
			SET @XML_SCHEMA_COMPARE.modify('insert sql:variable("@SelectedSyncObjectsCHEMA") after (/Project/UserNote)[1]')
			SET @XML_SCHEMA_COMPARE.modify('insert sql:variable("@schemaNotDeployTables") after (/Project/ProjectFilter/Filters)[1]')

			--SET @SCHEMA_COMPARE.modify('insert sql:variable("@ta") into (/Project/TableActions)[1]')
			INSERT INTO @result
				SELECT @XML_SCHEMA_RESULT, @ARCHIV_SCHEMA_COMPARE	
		END
	RETURN  
END

GO
/****** Object:  UserDefinedFunction [dbo].[GET_BAT_INSTRUCTIONSFILES]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
