CREATE FUNCTION [dbo].[GET_BAT_INSTRUCTIONSFILES](@MandantId INT = null)
RETURNS NVARCHAR(MAX)
BEGIN
	DECLARE @BATINSTRUCTIONS VARCHAR(MAX) = '
	echo ========================================createajob.bat===========================================================
@echo off
::cls
echo ========================================================================
echo ERSTELLUNG der JOBS für CX9 - Kunden DB UPDATE
echo ========================================================================
::echo cls Kommando wurde ausgeführt...
SET DBAbasID=%1
SET COMPARETYPE=%2


if not defined COMPARETYPE (
  echo COMPARE TYPE ist nicht gueltig LIVE_SCHEMA_COMPARE or LIVE_DATA_COMPARE
  exit /b
) 

::SET DIRName=C:\sqlcompare\
SET DIRName=%cd%\
SET Server=192.168.253.109
SET ServerUser=c*]
SET ServerPW=D).)f
SET SQLUpdatesFolder=C:\Deployment\Data Compare\Logs\
SET USEDB=BETHUNDER_JL
SET FILEOUTPUT=%DBAbasID%
::set str = %1
::call :strLen str strlen
::echo String is %strlen% characters long
::echo mydirpath is 
::echo    %DIRName%
echo .......................................................................................
::exit /b

:: set /p var=Eingabe: 
if not defined DBAbasID (
  echo Bitte geben Sie den DBAbasID ein!
  exit /b
)
::if strlen > 2 
:: (
::  echo DB Name Specifikation ist falsch
::  exit /b
::)
 

SET SQLCONTENTS1=USE %USEDB%
SET SQLCONTENTS2=EXEC dbo.GET_SQL_COMPARE_XML_JOSE @MandantId = %DBAbasID%, @Environment = ''%COMPARETYPE%''


set XMLProCallFileSCP=SQLJob%DBAbasID%.sql
echo Creating DB File Input on %XMLProCallFileSCP%
echo. 2>%XMLProCallFileSCP%
echo .......................................................................................
echo Sie haben den DB AbasID: "%DBAbasID%" eingegeben. Der Vorgang wird bearbeitet:
echo >> %XMLProCallFileSCP% %SQLCONTENTS2%
echo >> %XMLProCallFileSCP% GO

 

::echo %SQLCONTENTS% > %XMLProCallFileSCP%
::echo GO > %XMLProCallFileSCP%
echo Executing SQLJob: %DBAbasID% 
echo server connection %Server%.%USEDB% is going to be stablished and SQL JOB "%DBAbasID%" is going to be created
echo.


echo .......................................................................................
SET SQLGetNamefunctionFile=DB%DBAbasID%_info.sql
echo. 2>%SQLGetNamefunctionFile%
echo >> %SQLGetNamefunctionFile% PRINT dbo.getUpdateCompareSchemaName(%DBAbasID%, ''%COMPARETYPE%'')
echo >> %SQLGetNamefunctionFile% GO

echo .......................................................................................
SET ResultSQLGetNamefunctionFile=DB%DBAbasID%_info.txt
echo. 2>%ResultSQLGetNamefunctionFile%
echo >> %ResultSQLGetNamefunctionFile% GO


sqlcmd -S %Server% -U %ServerUser% -P %ServerPW% -d %USEDB% -i %SQLGetNamefunctionFile% -o %ResultSQLGetNamefunctionFile%


Set /p XMLSCPFilename=<%ResultSQLGetNamefunctionFile%
::echo %ResultSQLGetNamefunctionFile%
echo writing file:
echo %XMLSCPFilename% 

::cd %XMLSCPFilename% 
::exit /b

if %XMLSCPFilename% == INVALID_ABAS_ID (
  echo AbasID ist nicht gueltig!
  exit /b
)
if %XMLSCPFilename% == INVALID_ENVIRONMENT (
	echo deleting temp files
	del %XMLProCallFileSCP%
	del %SQLGetNamefunctionFile%
	del %ResultSQLGetNamefunctionFile%
  echo Die eingegebene Umgebung ist nicht gueltig!
  exit /b
)
if not defined DBAbasID (
	echo deleting temp files
	del %XMLProCallFileSCP%
	del %SQLGetNamefunctionFile%
	del %ResultSQLGetNamefunctionFile%
  echo AbasID ist nicht gueltig!
  exit /b
) 

set replaced=_%DATE%_%TIME%
call set replaced=%%replaced::=_%% 
call set replaced=%%replaced:,=_%%
call set replaced=%%replaced:.=_%%
call set replaced=%%replaced: =%%
::echo %replaced%
set replaced=%replaced%.scp

set XMLSCPFilenameBak=%XMLSCPFilename% 
call set XMLSCPFilenameBak=%%XMLSCPFilenameBak:.scp=%replaced%%% 
call set XMLSCPFilenameBak=%%XMLSCPFilenameBak:,=_%%
::echo %XMLSCPFilenameBak%  

if exist %XMLSCPFilename% (
	echo Moving file: %XMLSCPFilename% to %XMLSCPFilenameBak%
	MOVE %XMLSCPFilename% %XMLSCPFilenameBak%
)  

::cd %SQLUpdatesFolder%
echo. 2>%XMLSCPFilename%
echo >> %XMLSCPFilename% GO

sqlcmd -S %Server% -U %ServerUser% -P %ServerPW% -d %USEDB% -i %XMLProCallFileSCP% -o %XMLSCPFilename%

echo deleting temp files
del %XMLProCallFileSCP%
del %SQLGetNamefunctionFile%
del %ResultSQLGetNamefunctionFile%

echo.

echo ========================================================================================================
echo ====																							      
echo ====Programm mit der Dateiname/parameter "%0 %DBAbasID% %COMPARETYPE%" wurde erfolgreich durchgefuhrt
echo ====																							      
echo ========================================================================================================


 
 
 

	echo ========================================end of createajob.bat===========================================================
 

	echo ========================================update_translations.bat===========================================================
@echo off
::cls
echo ========================================================================
echo IMPORT/EXPORT TRANSLATIONS
echo ========================================================================
::echo cls Kommando wurde ausgeführt...
SET DBAbasID=%1
SET BATTYPE=%2

 

if not defined BATTYPE (
  echo BATTYPE ist nicht gueltig STATIC_DATA_TO_CLIENT or CLIENT_TO_STATIC_DATA
  exit /b
) 
SET "var="&for /f "delims=0123456789" %%i in ("%DBAbasID%") do set var=%%i
if defined var (
	echo Der eingegegene Parameter "%DBAbasID%" ist nicht numeric. Programm wurde gestoppt. 
	echo Es wird Integer erwartet.
	exit /b
)				 

  
SET DIRName=%cd%\
SET Server=192.168.253.109
SET ServerUser=c*]
SET ServerPW=D).)f
SET USEDB=BETHUNDER_JL
 
:: set /p var=Eingabe: 
if not defined DBAbasID (
  echo Bitte geben Sie den DBAbasID ein!
  exit /b
)  
SET SQLCONTENTS14=PRINT dbo.GET_BAT_TRANSLATIONTEXT(%DBAbasID%, ''%BATTYPE%'')
SET SQLCONTENTS15=GO
SET SQLCONTENTS14=DECLARE @batinstructions NVARCHAR (MAX^^) ^^= dbo.GET_BAT_TRANSLATIONTEXT(%DBAbasID%, ''%BATTYPE%''^^)
SET SQLCONTENTS15=EXEC dbo.LongPrint @printigString ^^= @batinstructions
echo %SQLCONTENTS4%
echo %SQLCONTENTS5%



set UPDATEXMLProCallFileSCP=ExportImportSQLTransJob%DBAbasID%.sql
echo Creating DB File Input on %UPDATEXMLProCallFileSCP%
echo. 2>%UPDATEXMLProCallFileSCP%
echo ===============
echo Sie haben den DB AbasID: "%DBAbasID%" eingegeben. Der Vorgang wird bearbeitet:
  
echo >> %UPDATEXMLProCallFileSCP% %SQLCONTENTS14%
echo >> %UPDATEXMLProCallFileSCP% %SQLCONTENTS15%
echo >> %UPDATEXMLProCallFileSCP% GO
 

echo Executing File %UPDATEXMLProCallFileSCP% 
echo server connection %Server%.%USEDB% is going to be stablished and SQL JOB "%DBAbasID%" is going to be created
echo.

type %UPDATEXMLProCallFileSCP%
::exit /b

echo ===============
SET UPDAResultSQLGetNamefunctionFile=ExportToAbasID%DBAbasID%_BATINFOInstructions.bat
echo. 2>%UPDAResultSQLGetNamefunctionFile%
echo >> %UPDAResultSQLGetNamefunctionFile% GO

sqlcmd -S %Server% -U %ServerUser% -P %ServerPW% -d %USEDB% -i %UPDATEXMLProCallFileSCP% -o %UPDAResultSQLGetNamefunctionFile%

SET UPDATEXMLSCPFilename=::
SET /p UPDATEXMLSCPFilename=<%UPDAResultSQLGetNamefunctionFile%
 

echo writing file1 %UPDAResultSQLGetNamefunctionFile%
::echo %UPDATEXMLSCPFilename%  

echo Testing BAT Intructions...

 
if "%UPDATEXMLSCPFilename%" == INVALID_ABAS_ID (
	echo AbasID ist nicht gueltig
	echo deleting temp files
	echo %UPDATEXMLProCallFileSCP%
	echo %UPDAResultSQLGetNamefunctionFile%
	del %UPDATEXMLProCallFileSCP%
	del %UPDAResultSQLGetNamefunctionFile%
	exit /b
)
if "%UPDATEXMLSCPFilename%" == INVALID_DIRECTION (
	echo Die eingegebene Import Export Richtung ist nicht gueltig
	echo deleting temp files
	echo %UPDATEXMLProCallFileSCP% 
	echo %UPDAResultSQLGetNamefunctionFile%  
	del %UPDATEXMLProCallFileSCP% 
	del %UPDAResultSQLGetNamefunctionFile%
	exit /b
) 	

 



echo Call Import File - Importing...:
call %UPDAResultSQLGetNamefunctionFile%
echo Call Import File - Importing DONE : %UPDAResultSQLGetNamefunctionFile%
echo deleting temp files
echo %UPDATEXMLProCallFileSCP% 
echo %UPDAResultSQLGetNamefunctionFile%   
del %UPDATEXMLProCallFileSCP% 
del %UPDAResultSQLGetNamefunctionFile%   
echo.

echo ========================================================================================================
echo ====																							      
echo ====   Programm mit der Dateiname/parameter "%0 %DBAbasID% %BATTYPE%" wurde erfolgreich durchgefuhrt 
echo ====																							      
echo ========================================================================================================


	echo ========================================end of update_translations.bat===========================================================
 
	' 
	RETURN @BATINSTRUCTIONSEND
GO
/****** Object:  UserDefinedFunction [dbo].[GET_BAT_TRANSLATIONTEXT]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
