CREATE FUNCTION [dbo].[GET_BAT_TRANSLATIONTEXT](@MandantId INT = null, @Environment NVARCHAR(128) = 'ACC', @compareType NVARCHAR(128) = 'SCHEMA', @from NVARCHAR(128) = 'STATIC_DATA_TO_CLIENT')
RETURNS NVARCHAR(MAX)
BEGIN
	DECLARE @BATINSTRUCTIONS NVARCHAR(MAX)
	DECLARE @ip NVARCHAR(255), @dbname NVARCHAR(255), @dbuser NVARCHAR(512)='', @dbpassword NVARCHAR(512)='',
	@XMLCompareData XML

	SET @BATINSTRUCTIONS = 'INVALID_DIRECTION' 
	IF(NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN 
		RETURN 'INVALID_ABAS_ID'
	END
	IF @from NOT IN ('STATIC_DATA_TO_CLIENT', 'CLIENT_TO_STATIC_DATA')
		RETURN @BATINSTRUCTIONS

	IF (@environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS))
		BEGIN
			RETURN 'Environment ist nicht erkannt!'
			
		END
	IF (@compareType NOT IN ('SCHEMA','DATA'))
		BEGIN
			RETURN 'Type ist nicht erkannt!' 
		END 
	  
	SELECT @ip=ISNULL(databaseIp,'')+CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END, 
			@dbname=ISNULL(databaseName,''),
			@dbuser=ISNULL(databaseUser,'') FROM dbo.Mandant WHERE id=@MandantId   				    
	SET @dbpassword = dbo.SEC_GetPWCOde(@dbuser)

	IF (EXISTS (SELECT * FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@Environment and version = '6.0'))
		BEGIN 
			SELECT TOP 1 @dbname=ISNULL(databaseName,''), @dbuser=ISNULL(databaseUser,''), @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
			@ip=ISNULL(databaseIp,'')+
			   CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END + 
				CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(databasePort)=1 /*intern extern unterschied*/  THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@Environment and version = '6.0'	 
		END  


	IF( @Environment NOT IN ('DEFAULT'))	
		BEGIN	
			SELECT TOP 1 @XMLCompareData = DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @Environment AND TYPE = @compareType AND MANDANT_ID = @MandantId
			IF (@XMLCompareData IS NULL)--first execute the xml PFLEGE_XML_MANDANT_ENVIRONMENT
				RETURN 'INVALID_ENVIRONMENT'				
			SET @ip = ISNULL(@XMLCompareData.value('(/Project/DataSource2/ServerName/text())[1]', 'NVARCHAR(128)'),'')
			SET @dbname = ISNULL(@XMLCompareData.value('(/Project/DataSource2/DatabaseName/text())[1]', 'NVARCHAR(128)'),'')
			SET @dbuser = ISNULL(@XMLCompareData.value('(/Project/DataSource2/Username/text())[1]', 'NVARCHAR(128)'),'')
			SET @dbpassword = ISNULL(@XMLCompareData.value('(/Project/DataSource2/Password/text())[1]', 'NVARCHAR(128)'),'')
			--SET @dbpassword = dbo.SEC_GetPWCOde(@dbuser)
		END


	DECLARE @FROMDBBATINSTRUCTIONS NVARCHAR(1024) = '
 				SET FROMServer=192.168.254.209\SQL2012DEV
				SET FROMServerUser=
				SET FROMServerPW= 
				SET FROMDB=crentdev_jmunoz

	'
	DECLARE @TODBBATINSTRUCTIONS NVARCHAR(1024) = '
				SET TOServer='+@ip+'
				SET TOServerUser='+dbo.GET_BATCH_ESCAPED_PWD(@dbuser)+' 
				SET TOServerPW='+dbo.GET_BATCH_ESCAPED_PWD(@dbpassword)+'
				SET TODB='+@dbname+'
	'
	
	DECLARE @TODBPATCHBATINSTRUCTIONS NVARCHAR(MAX) = '
				::SET SQLCONTENTS4=DECLARE @sqlinstructions NVARCHAR (MAX^^) ^^= dbo.GET_UPDATE6CRENT_PATCHES(%MandantID%^^)
				::SET SQLCONTENTS5=EXEC dbo.longPrintingString @printigString ^^= @sqlinstructions
				    SET GLOBALLOGMESSAGE=Patches are going to be applied to %TOServer%.%TODB% 
				    :: To get from schema - not a goot idea
					::echo>> %SQLInfoProCallFileSCP% %SQLCONTENTS4%
					::echo>> %SQLInfoProCallFileSCP% %SQLCONTENTS5% 
					::echo>> %SQLInfoProCallFileSCP% GO	
					::but from install tool
					SET SQLCONTENTS4=DECLARE @sqlinstructions NVARCHAR (MAX^^) ^^= dbo.GET_UPDATE6CRENT_PATCHES(%MandantID%^^)
					SET SQLCONTENTS5=EXEC dbo.LongPrint @printigString ^^= @sqlinstructions
					SET GLOBALLOGMESSAGE=getting Patches with TSQL commant %SQLCONTENTS4%
					echo %GLOBALLOGMESSAGE%
					echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
					SET GLOBALLOGMESSAGE=getting Patches with TSQL commant %SQLCONTENTS5%
					echo %GLOBALLOGMESSAGE%
					echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
					 
					SET FileInputPatches=C:\SQLJobs\deployStepByStep\PATCHESTOABASID%MandantID%_'+@Environment+'_'+@compareType+'_SQLInstructionsInput.sql
					SET FileOutputPatches=C:\SQLJobs\deployStepByStep\PATCHESTOABASID%MandantID%_'+@Environment+'_'+@compareType+'_SQLInstructionsOutput.sql
					
					SET FileOutputPatchesResult=C:\SQLJobs\deployStepByStep\PATCHESTOABASID%MandantID%_'+@Environment+'_'+@compareType+'_SQLInstructionsOutputResult.sql
					echo. 2>%FileInputPatches%
					echo>> %FileInputPatches% %SQLCONTENTS4%
					echo>> %FileInputPatches% %SQLCONTENTS5% 
					echo>> %FileInputPatches% GO	
					type %FileInputPatches%		


					echo. 2>%FileOutputPatches%
					echo>> %FileOutputPatches% GO

					echo. 2>%FileOutputPatchesResult%
					echo>> %FileOutputPatchesResult% GO

					set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S 192.168.253.109 -U c*] -P D).)f -d BETHUNDER_JL -i %FileInputPatches% -o %FileOutputPatches%"
					echo %GLOBALLOGMESSAGE%
					echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE% 
					
					set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %FileOutputPatches% -o %FileOutputPatchesResult%"
					echo %GLOBALLOGMESSAGE%
					echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE% 					 


					sqlcmd -S 192.168.253.109 -U c*] -P D).)f -d BETHUNDER_JL -i %FileInputPatches% -o %FileOutputPatches%
					sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %FileOutputPatches% -o %FileOutputPatchesResult%
					call :LogFile %DBMandantID% '+@Environment+' '+@compareType+' %LogType% sqlQueryOutput 0 %FileOutputPatchesResult% 		



					SET GLOBALLOGMESSAGE=following patches were applied to the target db: %TOServer%.%TODB% 
					echo %GLOBALLOGMESSAGE%
					echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
					type %FileOutputPatches%
				 	del %FileInputPatches%
				 	del %FileOutputPatches%
				 	del %FileOutputPatchesResult%
	'

	DECLARE @IMPORT_EXPORT_DIRECTION_BATINSTUCTIONS NVARCHAR(MAX) = '
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=Exporting translations from %FROMServer%.%FROMDB% ... Estimated time 30 Seconds ...
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%


				set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %FROMServer% -d %FROMDB% -i %SQLInfoProCallFileSCP% -o %ResultSQLTransFile1%"
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE% 

				sqlcmd -S %FROMServer% -d %FROMDB% -i %SQLInfoProCallFileSCP% -o %ResultSQLTransFile1%
				::call :LogFile %DBMandantID% '+@Environment+' '+@compareType+' %LogType% sqlQueryInput 0 %SQLInfoProCallFileSCP%
				::call :LogFile %DBMandantID% '+@Environment+' '+@compareType+' %LogType% sqlQueryOutput 0 %ResultSQLTransFile1% 


				SET GLOBALLOGMESSAGE=Exporting translations from %FROMServer%.%FROMDB% done
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%

				echo.
				echo.
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=Importing translations to %TOServer%.%TODB% ..... Estimated time 15 Seconds ...
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%


				set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %ResultSQLTransFile1% -o %ResultSQLGetTranslationsFile%"
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE% 
				sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %ResultSQLTransFile1% -o %ResultSQLGetTranslationsFile%
				call :LogFile %DBMandantID% '+@Environment+' '+@compareType+' %LogType% sqlQueryOutput 0 %ResultSQLGetTranslationsFile% 	


				SET GLOBALLOGMESSAGE=Importing translations to %TOServer%.%TODB% done
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo.	
	'
	IF (@from = 'CLIENT_TO_STATIC_DATA')
		BEGIN
			SET @FROMDBBATINSTRUCTIONS = '
 				SET FROMServer='+@ip+'
				SET FROMServerUser='+@dbuser+'
				SET FROMServerPW='+dbo.GET_BATCH_ESCAPED_PWD(@dbpassword)+'
				SET FROMDB='+@dbname+'
			'
			SET @TODBBATINSTRUCTIONS = '
				SET TOServer=192.168.254.209\SQL2012DEV
				SET TOServerUser=
				SET TOServerPW= 
				SET TODB=crentdev_jmunoz
			'	
			SET @IMPORT_EXPORT_DIRECTION_BATINSTUCTIONS = '
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=Exporting translations from %FROMServer%.%FROMDB% ...
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%	
											
				set GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %FROMServer% -U %FROMServerUser% -P %FROMServerPW% -d %FROMDB% -i %SQLInfoProCallFileSCP% -o %ResultSQLTransFile1%"
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE% 
				sqlcmd -S %FROMServer% -U %FROMServerUser% -P %FROMServerPW% -d %FROMDB% -i %SQLInfoProCallFileSCP% -o %ResultSQLTransFile1%

				call :LogFile %DBMandantID% '+@Environment+' '+@compareType+' %LogType% sqlQueryInput 0 %SQLInfoProCallFileSCP%
				::call :LogFile %DBMandantID% '+@Environment+' '+@compareType+' %LogType% sqlQueryOutput 0 %ResultSQLTransFile1% 

				SET GLOBALLOGMESSAGE=Exporting translations from %FROMServer%.%FROMDB% done
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%

				echo.
				echo.
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=Importing translations to %TOServer%.%TODB% ...
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				sqlcmd -S %TOServer% -d %TODB% -i %ResultSQLTransFile1% -o %ResultSQLGetTranslationsFile%
				call :LogFile %DBMandantID% '+@Environment+' '+@compareType+' %LogType% sqlQueryOutput 0 %ResultSQLGetTranslationsFile% 
				SET GLOBALLOGMESSAGE=Importing translations to %TOServer%.%TODB% done
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo.	
			'	
			SET @TODBPATCHBATINSTRUCTIONS = '		
			'
		END

	SET @BATINSTRUCTIONS = '
				@echo off
				::cls
				SET GLOBALLOGMESSAGE=cls Kommando wurde  nicht ausgefuehrt...
				SET LogType=impExpTrans
				echo %GLOBALLOGMESSAGE%
				'+CASE WHEN dbo.GET_ENVIRONMENT_COMPARE_RESULT_LOG_ERRORS(@MandantId,@Environment,@compareType)<>'' THEN 'echo UPDATE WURDE GESTOPPT SIEHE COMPARE LOGS'+CHAR(10)+' exit /b' ELSE '' END +'
				SET MandantID='+CAST(@MandantId AS NVARCHAR(32))+'
				SET ISODATETIMENOW=%date:~6,4%-%date:~3,2%-%date:~0,2%T%time:~0,2%:%time:~3,2%:%time:~6,2%
				SET ISODATETIMENOW=%ISODATETIMENOW: =0%
				set replacedSuffix=%ISODATETIMENOW%
				call set replacedSuffix=%%replacedSuffix::=_%% 
				call set replacedSuffix=%%replacedSuffix:,=_%%
				call set replacedSuffix=%%replacedSuffix:.=_%%
				call set replacedSuffix=%%replacedSuffix: =%%
 
				set replacedSuffix=%replacedSuffix%
				SET TRANS_GENERALGLOBALLOGFILE=C:\SQLJobs\deployStepByStep\PROCESS_%DBMandantID%_TRANS_'+@Environment+'_'+@compareType+'_LOGS_%replacedSuffix%.log
                call set TRANS_GENERALGLOBALLOGFILE=%%TRANS_GENERALGLOBALLOGFILE: =%%

				echo %TRANS_GENERALGLOBALLOGFILE%
				echo. 2>%TRANS_GENERALGLOBALLOGFILE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%

				SET GLOBALLOGMESSAGE=Logs of Execution: %0 %1 %2 %3 %4 %5 %6 %7 %8 at %ISODATETIMENOW%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				 
				SET DIRName=%cd%\
				'+@FROMDBBATINSTRUCTIONS+'

				'+@TODBBATINSTRUCTIONS+'
				SET GLOBALLOGMESSAGE================
				if not defined MandantID (
				    SET GLOBALLOGMESSAGE=Bitte geben Sie den MandantID ein!
					echo %GLOBALLOGMESSAGE%
					echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				    exit /b
				)

				SET SQLCONTENTS1=USE %FROMDB%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET SQLCONTENTS2=EXEC dbo.LANG_EXPORT_TRANSLATIONS @components = N''%%''
				::SET SQLCONTENTS2=EXEC dbo.LANG_EXPORT_TRANSLATIONS @components = N''Login''
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%


				SET GLOBALLOGMESSAGE=========================================================================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=EXPORT TRANSLATIONS FROM DB: [%FROMServer%.%FROMDB%] TO DB [%TOServer%.%TODB%]
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=with TSQL Command: %SQLCONTENTS2%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=========================================================================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%


				set SQLInfoProCallFileSCP=C:\SQLJobs\deployStepByStep\ExportRealSQLTansJob_FROM_%FROMDB%_%MandantID%_'+@Environment+'_'+@compareType+'.sql
				SET GLOBALLOGMESSAGE=Creating DB File Input on %SQLInfoProCallFileSCP%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo. 2>%SQLInfoProCallFileSCP%
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=Sie haben den DB MandantID: "%MandantID%" eingegeben. Der Vorgang wird bearbeitet:
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo>> %SQLInfoProCallFileSCP% %SQLCONTENTS2%
				echo>> %SQLInfoProCallFileSCP% GO
				'+@TODBPATCHBATINSTRUCTIONS+'


				SET GLOBALLOGMESSAGE=Executing ExportSQLTansJob: %MandantID% 
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=FROMServer connection %FROMServer%.%FROMDB% is going to be stablished and SQL JOB "%MandantID%" is going to be created
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo.

				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET ResultSQLTransFile1=C:\SQLJobs\deployStepByStep\FROM_%FROMDB%_DB%MandantID%_'+@Environment+'_'+@compareType+'_translationsTOBeimported.sql
				SET GLOBALLOGMESSAGE=The file %ResultSQLTransFile1% is going to be created
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo. 2>%ResultSQLTransFile1%
				echo>> %ResultSQLTransFile1% GO

				SET ResultSQLGetTranslationsFile=C:\SQLJobs\deployStepByStep\FROM_%FROMDB%_DB%MandantID%_'+@Environment+'_'+@compareType+'_translations_res.txt
				SET GLOBALLOGMESSAGE=The file %ResultSQLGetTranslationsFile% is going to be created
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				echo. 2>%ResultSQLGetTranslationsFile%
				echo>> %ResultSQLGetTranslationsFile% GO

				'+@IMPORT_EXPORT_DIRECTION_BATINSTUCTIONS+'
				echo.
				SET /p XMLSCPFilename=<%ResultSQLGetTranslationsFile%

				echo.
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=SQL Result from Query %SQLCONTENTS2% into DB
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=%TOServer%.%TODB%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				::type %ResultSQLTransFile1%
				type %ResultSQLGetTranslationsFile%
				echo.
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
		 
 
				echo.
				echo.
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=Deleting temp files...:
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=%SQLInfoProCallFileSCP%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=%ResultSQLTransFile1%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=%ResultSQLGetTranslationsFile%
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				del %SQLInfoProCallFileSCP% 
				del %ResultSQLTransFile1%
				del %ResultSQLGetTranslationsFile%
				del %SQLInfoProCallFileSCP%
				SET GLOBALLOGMESSAGE=========================================================================================================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=====																							      
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%

				SET GLOBALLOGMESSAGE=====     Programm mit der Dateiname/parameter %0 %1 %2 %3 %4 %5 %6 %7 %8 wurde erfolgreich durchgefuhrt         
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%
				SET GLOBALLOGMESSAGE=====	
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%																										      
				SET GLOBALLOGMESSAGE=========================================================================================================
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%

				SET GLOBALLOGMESSAGE=Uploading log file: %TRANS_GENERALGLOBALLOGFILE% with command call "uploadLogs.bat %MandantID% '+@Environment+'_'+@compareType+'_COMPARE translationImportExport"
				echo %GLOBALLOGMESSAGE%
				echo>>%TRANS_GENERALGLOBALLOGFILE% %GLOBALLOGMESSAGE%

				call :LogFile %DBMandantID% '+@Environment+' '+@compareType+' %LogType% console 1 %TRANS_GENERALGLOBALLOGFILE% 
				Goto :Eof
 
				:LogFile
				call uploadLogFile.bat %~1 %~2 %~3 %~4 %~5 %~6 "%~7"
	'
	RETURN @BATINSTRUCTIONSEND
GO
/****** Object:  UserDefinedFunction [dbo].[GET_BATCH_ESCAPED_PWD]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_BATCH_ESCAPED_PWD] (@input VARCHAR(MAX))
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @result NVARCHAR(MAX)
    SET @result =
	REPLACE(
		REPLACE(
			REPLACE( 
				REPLACE(
					REPLACE(
						REPLACE(
							REPLACE(
								REPLACE(@input,'^', '^^^^')
							,'&', '^^&')
						,'>', '^^^>')
					,'<', '^^^<')
				,'|', '^^|')
			,'\','^^\')
		,'!','^^!')
	,'%','%%')

	/*
	eventually make it powerfull --https://www.robvanderwoude.com/escapechars.php
	DECLARE @orig VARCHAR(MAX) = '%BGL]%n#)l'
	DECLARE @result VARCHAR(MAX) = ''
	DECLARE @toThePowerSigns VARCHAR(512)='^s&s<s>s|s''s`s,s;s=s(s)'
	DECLARE @slashedSigns VARCHAR(512)='",\,[,],'
	SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@toThePowerSigns,'s')
	*/
RETURN @result
END
GO
