CREATE	FUNCTION [dbo].[GET_CRW6_DEPLOYMENT_ENVIRONMENTNAMES]()
RETURNS VARCHAR(MAX)
AS
BEGIN
--SELECT * FROM dbo.Mandant
	DECLARE @result XML    
	SET @result = (
		SELECT
N'    - local: ''/.deployment/'+CRW_DEPLOYMENT_NAME+'.yml'''+CHAR(10) FROM dbo.GET_CRW6DEPLOYMENT_MANDANT_DB_ENVIRONMENT(DEFAULT)	   
 
