CREATE FUNCTION [dbo].[GET_CRW6_DEPLOYMENT_ENVIRONMENTS] (@MANDANT_ID INT = NULL)
RETURNS VARCHAR(MAX) --Author José
AS
BEGIN
    DECLARE @result VARCHAR (MAX) = ''
    --DECLARE @MANDANT_ID int = (SELECT TOP 1 mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @MANDANT_ID AND version = '6.0')
	IF (@MANDANT_ID IS NULL)-- OR @MANDANT_ID = 363)
		RETURN @result
    DECLARE @SERVER_DOCROOT_ALIAS VARCHAR (128) = ISNULL((SELECT CASE WHEN documentRoot = 'html' OR documentRoot = '' THEN ISNULL(globalName,CAST( id AS NVARCHAR(32)) ) ELSE REPLACE(documentRoot,'html/','') END FROM dbo.Mandant WHERE id = @MANDANT_ID),'NOGlobalName')

    IF (@SERVER_DOCROOT_ALIAS = '') SET @SERVER_DOCROOT_ALIAS = @MANDANT_ID
    DECLARE @SERVER_DOCROOT VARCHAR (128) = ISNULL((SELECT documentRoot  FROM dbo.Mandant WHERE id = @MANDANT_ID),'')
    DECLARE @mandName VARCHAR (512) = ISNULL((SELECT companyname FROM dbo.Mandant WHERE id = @MANDANT_ID),'')
	SET @mandName=dbo.stringReplaceMultiple_pattern(ISNULL(@mandName,'noCompanyName'),',= ;ä=ae;ü=ue;ö=oe;&=und;',';','=') 
    DECLARE @INTERN_SSH_USER VARCHAR (128) = 'cx9'
    DECLARE @INTERN_SSH_HOST VARCHAR (128) = '192.168.253.189'
    DECLARE @INTERN_SSH_PORT VARCHAR (128) = '22'
    DECLARE @SSH_USER VARCHAR (128) = 'cx9'
    DECLARE @SSH_HOST VARCHAR (128) = '192.168.253.189'
    DECLARE @SSH_PORT VARCHAR (128) = '22' 
    DECLARE @SERVER_PATH VARCHAR (128) = ''
    DECLARE @SERVER_PATH_SUFFIX VARCHAR (128) = ''
    DECLARE @SERVER_ENVIRONMENT_NAME VARCHAR (128) = ''
    DECLARE @defaultEnvSuffix VARCHAR (128) = '_test'
    DECLARE @envSuffix VARCHAR (128) = '_test'
	DECLARE @ACCDatabaseIp VARCHAR(255) = '', @ACCDatabaseName VARCHAR(255) = '', @ACCDatabaseUser VARCHAR(512)='', 
	@ACCDatabaseInstance NVARCHAR(512)='',
	@dbpassword NVARCHAR(512)=''
	DECLARE @EnvironmentDatabaseIp VARCHAR(255) = '', @EnvironmentDatabaseName VARCHAR(255) = '', @EnvironmentDatabaseUser VARCHAR(512)='', 
	@EnvironmentDatabaseInstance NVARCHAR(512)=''
 
	SELECT TOP 1 @ACCDatabaseName=ISNULL(databaseName,''), @ACCDatabaseUser=ISNULL(databaseUser,''), @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
	@ACCDatabaseIp =ISNULL(databaseIp,''),@ACCDatabaseInstance = ISNULL(databaseInstance,'')
	FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MANDANT_ID and version = '6.0' AND type='ACC'	 
    DECLARE @ymlACCTemplate VARCHAR (MAX)=''
    DECLARE @ymlLIVETemplate VARCHAR (MAX)=''
    DECLARE @ymlEnvTemplate VARCHAR (MAX)=''
    DECLARE @ymlEnvTemplateOnlyTag VARCHAR (MAX)=''
    DECLARE @version VARCHAR (128)=''
    DECLARE @versionORIG VARCHAR (128)=''
    DECLARE @MandantEnvPK INT = NULL
    DECLARE @type VARCHAR (128)=''
    DECLARE @path VARCHAR (128)=''
    DECLARE @pathAlias VARCHAR (128)=''
    DECLARE @installBase BIT = 0
	DECLARE @makeSHEnvironment VARCHAR(MAX)=
'    script:
        - ssh -p'+@SSH_PORT+' '+@SSH_USER+'@'+@SSH_HOST+' "mkdir -p /var/www/'+@SERVER_DOCROOT+'/crentweb'+@envSuffix+'"
        - ssh -p'+@SSH_PORT+' '+@SSH_USER+'@'+@SSH_HOST+' "sh /home/cx9/updates/makeCRentWebModul600.sh \"'+@SERVER_DOCROOT+'\" \"'+@ACCDatabaseIp+'\" \"'+@ACCDatabaseInstance+'\" \"'+@ACCDatabaseName+'\" \"'+@ACCDatabaseUser+'\" \"'+@envSuffix+'\""
'	

SET @makeSHEnvironment = ''
	DECLARE mandant_cursor CURSOR  
	   FOR SELECT PK, version, CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE type END, LOWER(REPLACE(ISNULL(path,''),'CRent','')), REPLACE(version,'.',''), ISNULL(installBase,0),
	    ISNULL(databaseIp,''),ISNULL(databaseInstance,''),ISNULL(databaseName,''), ISNULL(databaseUser,'')/* @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), */
		 
	  FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MANDANT_ID AND type IN ('DEFAULT','ACC') AND type IS NOT NULL AND version IN ('6.0','5.16') ORDER BY type ASC
	OPEN mandant_cursor  
	
	FETCH NEXT FROM mandant_cursor INTO @MandantEnvPK, @versionORIG, @type, @path, @version, @installBase, @EnvironmentDatabaseIp, @EnvironmentDatabaseInstance, @EnvironmentDatabaseName, @EnvironmentDatabaseUser
  
	WHILE @@FETCH_STATUS = 0  
	BEGIN  
		IF (@installBase = 1) SET @path=''--extern möglicherweise
	    SET @envSuffix = '_test'
		SET @pathAlias = ''
		--SET @envSuffix = '_'+@path+'_test'
		IF(@path <> '')
			BEGIN
				SET @envSuffix = '_'+@path+'_test'
				SET @pathAlias = ' '+UPPER(@path)
				SET @path = '-'+@path
			END
		 
		SET @SERVER_ENVIRONMENT_NAME = 'Acceptance'
		
		SET @ymlEnvTemplateOnlyTag = 
'        - /^release-.*$/
        - '+dbo.GET_MANDANT_UPDATE_FIELD(@MANDANT_ID,'MainCRWBranch')+'
    when: manual
'
		IF (@type = 'LIVE' AND @version = '60')
			BEGIN
				SET @SERVER_ENVIRONMENT_NAME = 'Productive'
				
				IF(@path <> '')
					BEGIN
						SET @envSuffix = REPLACE(@envSuffix,'_test','')
					END
				ELSE SET @envSuffix = ''                  
				SET @ymlEnvTemplateOnlyTag = 
'        - tags
        - '+dbo.GET_MANDANT_UPDATE_FIELD(@MANDANT_ID,'MainCRWBranch')+'
    when: manual

'
			END 
		IF (@type = 'LIVE' AND (@version = '516' OR @version = '515'))
			BEGIN      
  				IF(@path <> '')
					BEGIN
						SET @envSuffix = REPLACE(@envSuffix,'_test','')
					END  
				ELSE SET @envSuffix = ''          
				SET @SERVER_ENVIRONMENT_NAME = 'Productive'
				SET @ymlEnvTemplateOnlyTag = 
'        - master_'+@version+'        
    when: manual

'
			END 			 

		
  
		IF (EXISTS (SELECT * FROM dbo.MANDANT_WEB_PRODUKTE  WHERE MandantId = @MANDANT_ID))
			SELECT TOP 1 
			@SSH_HOST=ISNULL(WEBSERVERIP,@INTERN_SSH_HOST), 
			@SSH_USER=ISNULL(WEBSERVERSSHUSER,@INTERN_SSH_USER),  
			@SSH_PORT=ISNULL(WEBSERVERPORT,@INTERN_SSH_HOST)  
			FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID AND Environment=  @type
/*SET @makeSHEnvironment =
'    script:
        - ssh -p'+@SSH_PORT+' '+@SSH_USER+'@'+@SSH_HOST+' "mkdir -p /var/www/'+@SERVER_DOCROOT+'/crentweb'+@envSuffix+'"
        - ssh -p'+@SSH_PORT+' '+@SSH_USER+'@'+@SSH_HOST+' "sh /home/cx9/updates/makeCRentWebModul600.sh \"'+@SERVER_DOCROOT+'\" \"'+@ACCDatabaseIp+'\" \"'+@ACCDatabaseInstance+'\" \"'+@ACCDatabaseName+'\" \"'+@ACCDatabaseUser+'\" \"'+@envSuffix+'\""
        DB_HOST: "'+@EnvironmentDatabaseIp+'"
        DB_INSTANCE: "'+@EnvironmentDatabaseInstance+'"
        DB_NAME: "'+@EnvironmentDatabaseName+'"
        DB_USER: "'+@EnvironmentDatabaseUser+'"
        DB_PASSWORD: ""
		dbo.GET_CRWCONFIG_BY_PK
'	*/		
		SET @ymlEnvTemplate = 
'deploy-'+@SERVER_DOCROOT_ALIAS+@path+'-'+LOWER(@SERVER_ENVIRONMENT_NAME)+':
    stage: '+LOWER(@SERVER_ENVIRONMENT_NAME)+'
    variables:
        MANDANT_ID: "'+CAST (@MANDANT_ID AS VARCHAR(32))+'"
        ENVIRONMENT_NAME: "'+@type+'"
        SSH_USER: "'+@SSH_USER+'"
        SSH_HOST: "'+@SSH_HOST+'"
        SSH_PORT: "'+@SSH_PORT+'"
        SERVER_PATH: "/var/www/'+@SERVER_DOCROOT+'"
        SERVER_PATH_SUFFIX: "'+@envSuffix+'"
        CRENT_version: "'+@versionORIG+'"
        CRW_CONFIG: "'+dbo.GET_CRWCONFIG_BY_PK(@MandantEnvPK,'config',@versionORIG)+'"
        CRW_DB_CONFIG: "'+dbo.GET_CRWCONFIG_BY_PK(@MandantEnvPK,'db',@versionORIG)+'"

    extends: '+CASE WHEN dbo.isClientExtern(@MANDANT_ID)=1 THEN '.deploy-crentweb_remote' ELSE '.deploy-crentweb' END+'

    environment:
        name: '+LOWER(@SERVER_ENVIRONMENT_NAME)+'_'+@version+'/'+@mandName+@pathAlias+' - '+@SERVER_ENVIRONMENT_NAME+'
    only:
'+@ymlEnvTemplateOnlyTag
		SET @result+=@ymlEnvTemplate
		FETCH NEXT FROM mandant_cursor	INTO @MandantEnvPK, @versionORIG, @type, @path, @version, @installBase, @EnvironmentDatabaseIp, @EnvironmentDatabaseInstance, @EnvironmentDatabaseName, @EnvironmentDatabaseUser
	END   
	CLOSE mandant_cursor
	DEALLOCATE mandant_cursor 





IF (NOT EXISTS (SELECT TOP 1 databaseIp FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MANDANT_ID and version = '6.0' AND type = 'ACC'))
	BEGIN 
		SET @makeSHEnvironment = ''	 
	END 
    
	IF (@SERVER_DOCROOT_ALIAS<>'') RETURN @result
	RETURN ''
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_CRW6_DEPLOYMENT_GITLAB_CI]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_CRW6_DEPLOYMENT_GITLAB_CI](@branch VARCHAR(255) = '')
RETURNS VARCHAR(MAX)
AS
BEGIN
    DECLARE @filesTobeIncluded VARCHAR(MAX)= 
'
    - local: ''/.deployment/productive_516.yml''
    - local: ''/.deployment/acceptance_516.yml''
    - local: ''/.deployment/productive_600_1_100.yml''
    - local: ''/.deployment/productive_600_101_200.yml''
    - local: ''/.deployment/acceptance_600_1_100.yml''
    - local: ''/.deployment/acceptance_600_101_200.yml''
'
	IF (ISNULL(@branch,'') NOT IN ('master','develop')) --für single branches wie acl
		BEGIN
			SET @filesTobeIncluded = 
'
'			
			IF ((SELECT COUNT (MainCRWBranch) FROM dbo.MANDANT_WEB_PRODUKTE WHERE MainCRWBranch = @branch AND Environment='ACC')=1)	
				SET @filesTobeIncluded += 
'
    - local: ''/.deployment/acceptance_600.yml''
'
			IF ((SELECT COUNT (MainCRWBranch) FROM dbo.MANDANT_WEB_PRODUKTE WHERE MainCRWBranch = @branch AND Environment='LIVE')=1)	
				SET @filesTobeIncluded += 
'
    - local: ''/.deployment/productive_600.yml''
' 
		END
	DECLARE @result VARCHAR (MAX) = 
'.deploy-crentweb_old:
    cache:
        key: ${CI_COMMIT_REF_SLUG}
    script:
        - echo "deploy to $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX on $SSH_HOST:$SSH_PORT as user $SSH_USER"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "mkdir -p $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX && rm -r $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/css.orig && rm -r $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/js.orig"

        - shopt -s dotglob
        - rsync -O -rltDv -e ''ssh -p''$SSH_PORT'''' --include=''*/config/*'' --exclude=''.git/'' --exclude=''.gitlab-ci.yml'' --exclude=''.deployment'' --exclude=''config/*'' --exclude=''print'' ./* $SSH_USER@$SSH_HOST:$SERVER_PATH/crentweb$SERVER_PATH_SUFFIX

        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "cd $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/tools && sh ./yuicompressor.sh"
        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "cd $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX && mkdir -p sign/image_handler/signed && mkdir -p sign/image_handler/tempImages && mkdir -p sign/tempImages && mkdir -p sign/xmlFiles && mkdir -p COCI/images/downloads && mkdir -p COCI/classes/uploadedPhotos/damages && mv js js.orig && mv js.min js && mv css css.orig && mv css.min css && mv _.htaccess .htaccess"
    allow_failure: false

.deploy-crentweb:
    cache:
        key: ${CI_COMMIT_REF_SLUG}
    script:
        - echo "deploy to $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX on $SSH_HOST:$SSH_PORT as user $SSH_USER"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "echo ''Deploying C-Rent Web version $CRENT_version''"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "mkdir -p $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX && rm -rf $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/css.orig && rm -rf $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/js.orig"
        - shopt -s dotglob
        - rsync -O -rltDv -e ''ssh -p''$SSH_PORT'''' --include=''*/config/*'' --exclude=''.git/'' --exclude=''.gitlab-ci.yml'' --exclude=''.deployment'' --exclude=''print'' ./* $SSH_USER@$SSH_HOST:$SERVER_PATH/crentweb$SERVER_PATH_SUFFIX
        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "echo $CRW_CONFIG | xxd -r -p > $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/config/config.inc.php"
        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "echo $CRW_DB_CONFIG | xxd -r -p > $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/config/config_db.inc.php"
        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "cd $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/tools && sh ./yuicompressor.sh"
        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "cd $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX && mkdir -p sign/image_handler/signed && mkdir -p sign/image_handler/tempImages && mkdir -p sign/tempImages && mkdir -p sign/xmlFiles && mkdir -p COCI/images/downloads && mkdir -p COCI/classes/uploadedPhotos/damages && mv js js.orig && mv js.min js && mv css css.orig && mv css.min css && mv _.htaccess .htaccess"
    allow_failure: false

.deploy-crentweb_remote:
    cache:
        key: ${CI_COMMIT_REF_SLUG}
    script:
        - echo "deploy to $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX on $SSH_HOST:$SSH_PORT as user $SSH_USER"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "echo ''Deploying C-Rent Web version $CRENT_version''"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "mkdir -p $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX && rm -rf $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/css.orig && rm -rf $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/js.orig"
        - shopt -s dotglob
        - rsync -O -rltDv -e ''ssh -p''$SSH_PORT'''' --include=''*/config/*'' --exclude=''.git/'' --exclude=''.gitlab-ci.yml'' --exclude=''.deployment'' --exclude=''print'' ./* $SSH_USER@$SSH_HOST:$SERVER_PATH/crentweb$SERVER_PATH_SUFFIX
        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "echo $CRW_CONFIG | xxd -r -p > $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/config/config.inc.php"
        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "echo $CRW_DB_CONFIG | xxd -r -p > $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/config/config_db.inc.php"
        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "cd $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/tools && sh ./yuicompressor.sh"
        - ssh -p$SSH_PORT $SSH_USER@$SSH_HOST "cd $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX && mkdir -p sign/image_handler/signed && mkdir -p sign/image_handler/tempImages && mkdir -p sign/tempImages && mkdir -p sign/xmlFiles && mkdir -p COCI/images/downloads && mkdir -p COCI/classes/uploadedPhotos/damages && mv js js.orig && mv js.min js && mv css css.orig && mv css.min css && mv _.htaccess .htaccess"
    allow_failure: true

stages:
    - build
    - develop
    - test
    - review
    - acceptance
    - productive

variables:
    CONTAINER_IMAGE: ${CI_REGISTRY}/${CI_PROJECT_PATH}:${CI_BUILD_REF_NAME}_${CI_BUILD_REF}
    CONTAINER_IMAGE_COMMIT: ${CI_REGISTRY}/${CI_PROJECT_PATH}:${CI_COMMIT_SHORT_SHA}

services:
    -   name: docker:18.09.7-dind
        command: [ "--experimental", "--insecure-registry=gitlab.cx9.info:4567" ]

build:
    image: docker:latest
    stage: build
    script:
        - docker login -u gitlab-ci-token -p ${CI_BUILD_TOKEN} ${CI_REGISTRY}
        - docker build -t ${CONTAINER_IMAGE} .
        - docker tag ${CONTAINER_IMAGE} ${CONTAINER_IMAGE_COMMIT}
        - docker push ${CONTAINER_IMAGE_COMMIT}

deploy-review:
    stage: review
    image: ${CONTAINER_IMAGE_COMMIT}

    script:
        - ssh -o StrictHostKeyChecking=no -p22 cx9@192.168.254.237 "sudo rm -rf /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG"
        - ssh -p22 cx9@192.168.254.237 "mkdir -p /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG"

        - sed -ie s/''\["db"\]\["host"\] = ""''/''\["db"\]\["host"\] = "192.168.253.109"''/ ./config/config_db.inc.php
        - sed -ie s/''\["db"\]\["instance"\] = ""''/''\["db"\]\["instance"\] = "SQL2012"''/ ./config/config_db.inc.php
        - sed -ie s/''\["db"\]\["database"\] = ""''/''\["db"\]\["database"\] = "CRent_Demo"''/ ./config/config_db.inc.php
        - sed -ie s/''\["db"\]\["username"\] = ""''/''\["db"\]\["username"\] = "CRDemo"''/ ./config/config_db.inc.php

        - rsync -q -O -rav -e ssh --exclude=''.git/'' --exclude=''.gitlab-ci.yml'' --exclude=''.deployment'' --exclude=''cache/'' --exclude=''.sass-cache/'' --exclude=''node_modules/'' --exclude=''tests/'' --exclude=''gl-code-quality-report.json'' --delete-excluded ./ cx9@192.168.254.237:/var/www/review/crentweb_$CI_ENVIRONMENT_SLUG

        - ssh -p22 cx9@192.168.254.237 "cd /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG && git clone git@192.168.254.232:cx9/jasper print"

        - ssh -p22 cx9@192.168.254.237 "cd /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG/tools && sh ./jrxml2jasper.sh && sh ./yuicompressor.sh"
        - ssh -p22 cx9@192.168.254.237 "cd /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG && mkdir -p sign/image_handler/signed && mkdir -p sign/image_handler/tempImages && mkdir -p sign/tempImages && mkdir -p sign/xmlFiles && mkdir -p COCI/images/downloads && mkdir -p COCI/classes/uploadedPhotos/damages && mv js js.orig && mv js.min js && mv css css.orig && mv css.min css && mv _.htaccess .htaccess && mv config/_.htaccess config/.htaccess && sudo chmod -R 775 . && sudo chown -R cx9:www-data ."

    environment:
        name: review/$CI_COMMIT_REF_NAME
        url: http://192.168.254.237/review/crentweb_$CI_ENVIRONMENT_SLUG
        on_stop: stop-review
    only:
        - branches
    except:
        - /^master.*$/
        - develop
        - /^release-.*$/

stop-review:
    stage: review
    variables:
        GIT_STRATEGY: none
    script:
        - ssh -p22 cx9@192.168.254.237 "sudo rm -rf /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG"
    when: manual
    environment:
        name: review/$CI_COMMIT_REF_NAME
        action: stop
    only:
        - branches
    except:
        - /^master.*$/
        - develop
        - /^release-.*$/

include:
'+@filesTobeIncluded+'
'
--+dbo.GET_CRW6_DEPLOYMENT_ENVIRONMENTNAMES()
	RETURN @result
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT] (@MANDANT_ENVIRONMENT_NAME VARCHAR(MAX) = NULL, @versionS NVARCHAR(1024) = '5.16;6.0', @BRANCHES NVARCHAR(1024) = 'master;develop')
RETURNS VARCHAR(MAX) --Author José
AS
BEGIN
    DECLARE @result VARCHAR (MAX) = ''
	DECLARE @mandant_id INT = NULL 
	DECLARE @type NVARCHAR(30) = NULL 
	IF (ISNULL(@MANDANT_ENVIRONMENT_NAME,'')='LIVE')
		SET @MANDANT_ENVIRONMENT_NAME= 'DEFAULT'
	SELECT @mandant_id = ISNULL(mandant_id, @mandant_id), @type = ISNULL(type, @type) FROM MANDANT_DB_ENVIRONMENT WHERE  type = @MANDANT_ENVIRONMENT_NAME
 
	DECLARE MANDANT_DB_ENVIRONMENT_CURSOR CURSOR
		FOR SELECT  ISNULL(mandant_id,0), ISNULL(type,'') FROM MANDANT_DB_ENVIRONMENT 
			WHERE  type = @MANDANT_ENVIRONMENT_NAME 
			AND version IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@versionS,';')) 
			AND (dbo.GET_MANDANT_UPDATE_FIELD(mandant_id,'MainCRWBranch') IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@BRANCHES,';')))
			ORDER BY version, mandant_id DESC --AND version IN ('5.16','6.0')
		OPEN MANDANT_DB_ENVIRONMENT_CURSOR
		FETCH NEXT FROM MANDANT_DB_ENVIRONMENT_CURSOR INTO  @mandant_id, @type
		WHILE @@FETCH_STATUS = 0
		BEGIN
			--do your stuff
			
			SET @result+=dbo.GET_CRW6_DEPLOYMENT_SINGLE_ENVIRONMENT(@mandant_id,@type)
			FETCH NEXT FROM MANDANT_DB_ENVIRONMENT_CURSOR INTO  @mandant_id, @type
		END
	CLOSE MANDANT_DB_ENVIRONMENT_CURSOR

	DEALLOCATE MANDANT_DB_ENVIRONMENT_CURSOR
  
	RETURN @result 
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT_LIMIT]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT_LIMIT] (@MANDANT_ENVIRONMENT_NAME VARCHAR(MAX) = NULL, @versionS NVARCHAR(1024) = '5.16;6.0', @FROM_ENTRY INT = 1, @TO_ENTRY INT = 100)
RETURNS VARCHAR(MAX) --Author José
AS
BEGIN
    DECLARE @result VARCHAR (MAX) = ''
	DECLARE @mandant_id INT = NULL 
	DECLARE @type NVARCHAR(30) = NULL 
	DECLARE @table TABLE([mandant_id] [int] NOT NULL, [type] NVARCHAR(32) NULL)
	IF (ISNULL(@MANDANT_ENVIRONMENT_NAME,'')='LIVE')
		SET @MANDANT_ENVIRONMENT_NAME= 'DEFAULT'
	SELECT @mandant_id = ISNULL(mandant_id, @mandant_id), @type = ISNULL(type, @type) FROM MANDANT_DB_ENVIRONMENT WHERE  type = @MANDANT_ENVIRONMENT_NAME
	AND dbo.GET_MANDANT_UPDATE_FIELD(mandant_id,'MainCRWBranch') IN ('master','develop')
 
;WITH tmpTable AS 
(
   SELECT ISNULL(mandant_id,0)[mandant_id], ISNULL(type,'')[type], 
   ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS RN 
   FROM MANDANT_DB_ENVIRONMENT WHERE  type = @MANDANT_ENVIRONMENT_NAME AND version IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@versionS,';'))-- ORDER BY  mandant_id DESC --AND version IN ('5.16','6.0')
   AND dbo.GET_MANDANT_UPDATE_FIELD(mandant_id,'MainCRWBranch') IN ('master','develop')
)
INSERT INTO @table
        ( mandant_id, type )
SELECT  mandant_id,type
FROM    tmpTable
WHERE   RN >= @FROM_ENTRY AND RN <= @TO_ENTRY 


	DECLARE MANDANT_DB_ENVIRONMENT_CURSOR CURSOR
		FOR 
			--SELECT TOP (@MAX_ENTRIES) ISNULL(mandant_id,0), ISNULL(type,'') FROM MANDANT_DB_ENVIRONMENT WHERE  type = @MANDANT_ENVIRONMENT_NAME AND version IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@versionS,';')) AND (ROW_NUMBER() )<= @MAX_ENTRIES --ORDER BY version, mandant_id DESC --AND version IN ('5.16','6.0')
			--SELECT TOP 100 mandant_id,type FROM tmpTable WHERE   RN <= @MAX_ENTRIES ORDER BY RN DESC
			SELECT mandant_id,type FROM @table
		OPEN MANDANT_DB_ENVIRONMENT_CURSOR
		FETCH NEXT FROM MANDANT_DB_ENVIRONMENT_CURSOR INTO  @mandant_id, @type
		WHILE @@FETCH_STATUS = 0
		BEGIN
			--do your stuff
			
			SET @result+=dbo.GET_CRW6_DEPLOYMENT_SINGLE_ENVIRONMENT(@mandant_id,@type)
			FETCH NEXT FROM MANDANT_DB_ENVIRONMENT_CURSOR INTO  @mandant_id, @type
		END
	CLOSE MANDANT_DB_ENVIRONMENT_CURSOR

	DEALLOCATE MANDANT_DB_ENVIRONMENT_CURSOR
  
	RETURN @result 
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_CRW6_DEPLOYMENT_SINGLE_ENVIRONMENT]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
