CREATE FUNCTION [dbo].[GET_CRW6_DEPLOYMENT_SINGLE_ENVIRONMENT] (@MANDANT_ID INT = NULL, @MANDANT_ENVIRONMENT_NAME VARCHAR(MAX) = NULL)
RETURNS VARCHAR(MAX) --Author José
AS
BEGIN
    DECLARE @result VARCHAR (MAX) = ''
	IF (ISNULL(@MANDANT_ENVIRONMENT_NAME,'')='LIVE')
		SET @MANDANT_ENVIRONMENT_NAME= 'DEFAULT'
    --DECLARE @MANDANT_ID int = (SELECT TOP 1 mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @MANDANT_ID AND version = '6.0')
	IF (@MANDANT_ID IS NULL OR ISNULL(@MANDANT_ENVIRONMENT_NAME,'')='' OR NOT EXISTS (SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MANDANT_ID AND path = @MANDANT_ENVIRONMENT_NAME) )-- OR @MANDANT_ID = 363)
	--	RETURN @result
    DECLARE @SERVER_DOCROOT_ALIAS VARCHAR (128) = ISNULL((SELECT CASE WHEN documentRoot = 'html' OR documentRoot = '' THEN ISNULL(globalName,CAST( id AS NVARCHAR(32)) ) ELSE REPLACE(documentRoot,'html/','') END FROM dbo.Mandant WHERE id = @MANDANT_ID),'NOGlobalName')

    IF (@SERVER_DOCROOT_ALIAS = '') SET @SERVER_DOCROOT_ALIAS = @MANDANT_ID
    DECLARE @SERVER_DOCROOT VARCHAR (128) = ISNULL((SELECT documentRoot  FROM dbo.Mandant WHERE id = @MANDANT_ID),'')
    DECLARE @mandName NVARCHAR (255) = ISNULL((SELECT REPLACE(companyname,'ß','ss') FROM dbo.Mandant WHERE id = @MANDANT_ID),'')
	SET @mandName=dbo.stringReplaceMultiple_pattern(ISNULL(@mandName,'noCompanyName'),',= ;ä=ae;ü=ue;ö=oe;&=und;(= ;)= ;´= ',';','=') 
    DECLARE @INTERN_SSH_USER VARCHAR (128) = 'cx9'
    DECLARE @INTERN_SSH_HOST VARCHAR (128) = '192.168.253.189'
    DECLARE @INTERN_SSH_PORT VARCHAR (128) = '22'
    DECLARE @SSH_USER VARCHAR (128) = 'cx9'
    DECLARE @SSH_HOST VARCHAR (128) = '192.168.253.189'
    DECLARE @SSH_PORT VARCHAR (128) = '22' 
    DECLARE @SERVER_PATH VARCHAR (128) = ''
    DECLARE @SERVER_PATH_SUFFIX VARCHAR (128) = ''
    DECLARE @SERVER_ENVIRONMENT_NAME VARCHAR (128) = ''
    DECLARE @defaultEnvSuffix VARCHAR (128) = '_test'
    DECLARE @envSuffix VARCHAR (128) = '_test'
	DECLARE @dbpassword NVARCHAR(512)=''
	DECLARE @EnvironmentDatabaseIp VARCHAR(255) = '', @EnvironmentDatabaseName VARCHAR(255) = '', @EnvironmentDatabaseUser VARCHAR(512)='', 
	@EnvironmentDatabaseInstance NVARCHAR(512)=''
 	 
    DECLARE @ymlACCTemplate VARCHAR (MAX)=''
    DECLARE @ymlLIVETemplate VARCHAR (MAX)=''
    DECLARE @ymlEnvTemplate VARCHAR (MAX)=''
    DECLARE @ymlEnvTemplateOnlyTag VARCHAR (MAX)=''
    DECLARE @version VARCHAR (128)=''
    DECLARE @versionORIG VARCHAR (128)=''
    DECLARE @MandantEnvPK INT = NULL
    DECLARE @type VARCHAR (128)=''
    DECLARE @path VARCHAR (128)=''
    DECLARE @pathAlias VARCHAR (128)=''
    DECLARE @installBase BIT = 0
 	
	 
	DECLARE mandant_cursor CURSOR  
	   FOR SELECT PK, version, CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE type END, LOWER(REPLACE(ISNULL(path,''),'CRent','')), REPLACE(version,'.',''), ISNULL(installBase,0),
	    ISNULL(databaseIp,''),ISNULL(databaseInstance,''),ISNULL(databaseName,''), ISNULL(databaseUser,'')/* @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), */
		 
	  FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MANDANT_ID AND type = @MANDANT_ENVIRONMENT_NAME AND version IN ('6.0','5.16')-- ORDER BY type ASC
	OPEN mandant_cursor  
	
	FETCH NEXT FROM mandant_cursor INTO @MandantEnvPK, @versionORIG, @type, @path, @version, @installBase, @EnvironmentDatabaseIp, @EnvironmentDatabaseInstance, @EnvironmentDatabaseName, @EnvironmentDatabaseUser
 
	WHILE @@FETCH_STATUS = 0  
	BEGIN  
		IF (@installBase = 1) SET @path=''--extern möglicherweise
		--IF (@EnvironmentDatabaseName = 'VorlageCRW') SET @EnvironmentDatabaseName = 'CRent_Demo'
	    SET @envSuffix = '_test'
		SET @pathAlias = ''
		--SET @envSuffix = '_'+@path+'_test'
		IF(@path <> '')
			BEGIN
				SET @envSuffix = '_'+@path+'_test'
				SET @pathAlias = ' '+UPPER(@path)
				SET @path = '-'+@path
			END
		 
		SET @SERVER_ENVIRONMENT_NAME = 'Acceptance'
		
		SET @ymlEnvTemplateOnlyTag = 
'        - /^release-.*$/
        - '+dbo.GET_MANDANT_UPDATE_FIELD(@MANDANT_ID,'MainCRWBranch')+'   
    when: manual
'
		IF (@type = 'LIVE' AND @version = '60')
			BEGIN
				SET @SERVER_ENVIRONMENT_NAME = 'Productive'
				
				IF(@path <> '')
					BEGIN
						SET @envSuffix = REPLACE(@envSuffix,'_test','')
					END
				ELSE SET @envSuffix = ''                  
				SET @ymlEnvTemplateOnlyTag = 
'        - tags
        - '+dbo.GET_MANDANT_UPDATE_FIELD(@MANDANT_ID,'MainCRWBranch')+'        
    when: manual

'
			END 
		IF (@type = 'LIVE' AND (@version = '516' OR @version = '515'))
			BEGIN      
  				IF(@path <> '')
					BEGIN
						SET @envSuffix = REPLACE(@envSuffix,'_test','')
					END  
				ELSE SET @envSuffix = ''          
				SET @SERVER_ENVIRONMENT_NAME = 'Productive'
				SET @ymlEnvTemplateOnlyTag = 
'        - master_'+@version+'        
    when: manual

'
			END 			 

		
  
		IF (EXISTS (SELECT * FROM dbo.MANDANT_WEB_PRODUKTE  WHERE MandantId = @MANDANT_ID))
			SELECT TOP 1 
			@SSH_HOST=ISNULL(WEBSERVERIP,@INTERN_SSH_HOST), 
			@SSH_USER=ISNULL(WEBSERVERSSHUSER,@INTERN_SSH_USER),  
			@SSH_PORT=ISNULL(WEBSERVERPORT,@INTERN_SSH_HOST)  
			FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID AND Environment=  @type
 
		SET @ymlEnvTemplate = 
'deploy-'+@SERVER_DOCROOT_ALIAS+@path+'-'+LOWER(@SERVER_ENVIRONMENT_NAME)+':
    stage: '+LOWER(@SERVER_ENVIRONMENT_NAME)+'
    image: ${CONTAINER_IMAGE_COMMIT}
    variables:
        MANDANT_ID: "'+CAST (@MANDANT_ID AS VARCHAR(32))+'"
        ENVIRONMENT_NAME: "'+@type+'"
        SSH_USER: "'+@SSH_USER+'"
        SSH_HOST: "'+@SSH_HOST+'"
        SSH_PORT: "'+@SSH_PORT+'"
        SERVER_PATH: "/var/www/'+@SERVER_DOCROOT+'"
        SERVER_PATH_SUFFIX: "'+@envSuffix+'"
        CRENT_version: "'+@versionORIG+'"
        CRW_CONFIG: "'+dbo.GET_CRWCONFIG_BY_PK(@MandantEnvPK,'config',@versionORIG)+'"
        CRW_DB_CONFIG: "'+dbo.GET_CRWCONFIG_BY_PK(@MandantEnvPK,'db',@versionORIG)+'"
 
    extends: '+CASE WHEN dbo.isClientExtern(@MANDANT_ID)=1 THEN '.deploy-crentweb_remote' ELSE '.deploy-crentweb' END+'

    environment:
        name: '+LOWER(@SERVER_ENVIRONMENT_NAME)+'_'+@version+'/'+@mandName+@pathAlias+' - '+@SERVER_ENVIRONMENT_NAME+'
    only:
'+@ymlEnvTemplateOnlyTag
		SET @result+=@ymlEnvTemplate
		FETCH NEXT FROM mandant_cursor	INTO @MandantEnvPK, @versionORIG, @type, @path, @version, @installBase, @EnvironmentDatabaseIp, @EnvironmentDatabaseInstance, @EnvironmentDatabaseName, @EnvironmentDatabaseUser
	END   
	CLOSE mandant_cursor
	DEALLOCATE mandant_cursor  
  
	IF (@SERVER_DOCROOT_ALIAS<>'') RETURN @result
	RETURN ''
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_CRW6DEPLOYMENT_MANDANT_DB_ENVIRONMENT]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_CRW6DEPLOYMENT_MANDANT_DB_ENVIRONMENT] (@MANDANT_ID INT = NULL)
RETURNS @MANDANT_DB_ENVIRONMENT TABLE(MANDANT_ID INT NULL, MANDANT_NAME VARCHAR(2048), CRW_DEPLOYMENT_NAME VARCHAR(128) NULL)  
			 
BEGIN 
	DECLARE @MANDANT_DB_ENVIRONMENT_AUX TABLE(MANDANT_ID INT NULL, MANDANT_NAME VARCHAR(2048), CRW_DEPLOYMENT_NAME VARCHAR(128) NULL)  
	INSERT INTO @MANDANT_DB_ENVIRONMENT_AUX (MANDANT_ID, MANDANT_NAME, CRW_DEPLOYMENT_NAME)
		SELECT id, ISNULL(companyname,''), dbo.GET_MANDANT_DEPLOYMENT_NAME(id)
	    FROM dbo.Mandant WHERE documentRoot IS NOT NULL AND globalName <> '' 
		AND ID IN (SELECT MANDANT_ID FROM MANDANT_DB_ENVIRONMENT WHERE version IN ('6.0','5.16')) ORDER BY documentRoot ASC	
 
	IF (@MANDANT_ID IS NOT NULL) 
		DELETE FROM @MANDANT_DB_ENVIRONMENT WHERE MANDANT_ID <> @MANDANT_ID
	INSERT INTO @MANDANT_DB_ENVIRONMENT
		SELECT * FROM @MANDANT_DB_ENVIRONMENT_AUX ORDER BY CRW_DEPLOYMENT_NAME ASC
  
	RETURN  
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_CRWCONFIG_BY_PK]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_CRWCONFIG_BY_PK](@mandIDPK INT = NULL, @type VARCHAR(8)='config', @version VARCHAR(16)= '6.0' )
RETURNS VARCHAR(MAX) --Author José
AS
BEGIN   
		IF (@type NOT IN ('config','db') OR @version NOT IN ('6.0','5.16') OR NOT EXISTS(SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK=@mandIDPK))
			RETURN ''
	    DECLARE @configText VARCHAR(MAX) = ''
	    DECLARE @configHEX VARCHAR(MAX) = ''
	    DECLARE @LANG VARCHAR(2) = 'DE'--hier auf Mandant Tabelle zugreifen, für Kunden die auf anderen Ländern sind
	    DECLARE @DEFAULT_TIMEZONE VARCHAR(16) = 'Europe/Berlin'
	    DECLARE @HOST NVARCHAR(128) = ''
	    DECLARE @PORT NVARCHAR(128) = ''
	    DECLARE @HOST_CLIENT_INTERN NVARCHAR(128) = ''
	    DECLARE @INSTANCE VARCHAR(128) = ''
	    DECLARE @DATABASENAME VARCHAR(128) = ''
	    DECLARE @DB_USERNAME VARCHAR(128) = ''
	    DECLARE @DB_USERNAME_PWD NVARCHAR(255) = ''
	    DECLARE @MANDANT_ID INT = NULL
			SELECT TOP 1 @DATABASENAME=ISNULL(databaseName,''), 
					     @DB_USERNAME=ISNULL(databaseUser,''), 
						 @DB_USERNAME_PWD=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
						 @HOST=ISNULL(databaseIp,''), 
						 @PORT=ISNULL(databasePort,0), 
						 @INSTANCE=  CASE WHEN ISNULL(databaseInstance,'')<>'' THEN databaseInstance ELSE '' END,
						 @MANDANT_ID = MANDANT_ID
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE PK = @mandIDPK-- and version = @version 


			--RETURN @HOST
		IF (EXISTS(SELECT TOP 1 timeZone FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID))
			BEGIN
				SET @DEFAULT_TIMEZONE = ISNULL((SELECT TOP 1 timeZone FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID),@DEFAULT_TIMEZONE)		
				SET @HOST_CLIENT_INTERN = ISNULL((SELECT TOP 1 CLIENT_INTERN_HOST FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID),@HOST)				
				IF ISNULL(@HOST_CLIENT_INTERN,'')<>''
					SET @HOST = @HOST_CLIENT_INTERN
			END
		IF (dbo.isClientExtern(@MANDANT_ID) = 1 AND @PORT NOT IN ('0','1433', '15620'))
			SET @HOST = @HOST+':'+@PORT 
		--IF (@DATABASENAME = 'VorlageCRW') SET @DATABASENAME = 'CRent_Demo'
			           
		DECLARE @configAndDBConfigReplacements VARCHAR(MAX) = 
			'REPLACE_version='+@version+';'+
			'REPLACE_DEFAULT_LANG='+@LANG+';'+
			'REPLACE_DEFAULT_TIMEZONE='+@DEFAULT_TIMEZONE+';'+
			'REPLACE_HOST='+CAST(@HOST AS VARCHAR)+';'+
			'REPLACE_DB_INSTANCE='+@INSTANCE+';'+
			'REPLACE_DATABASENAME='+@DATABASENAME+';'+
			'REPLACE_DB_USERNAME='+@DB_USERNAME+';'+
			'REPLACE_DBUSERNAME_PWD='+@DB_USERNAME_PWD+';'
			--return @configAndDBConfigReplacements
		--PRINT dbo.stringReplaceMultiple_pattern('searchjöseLüis',@configAndDBConfigReplacements,';','='
		--192.168.253.209
		SET @configText = dbo.GET_CRWCONFIG_TEXT(@type, @version)

		--return dbo.stringReplaceMultiple_pattern(@configText,@configAndDBConfigReplacements,';','=')  --zum Debuging
		SET @configText = dbo.stringReplaceMultiple_pattern(@configText,@configAndDBConfigReplacements,';','=') 
		SET @configHEX = CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), @configText), 1)		 
		RETURN  SUBSTRING(@configHEX,3,LEN(@configHEX))
 END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_CRWCONFIG_TEXT]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
