CREATE FUNCTION [dbo].[GET_CRWCONFIG_TEXT](@type VARCHAR(8)='config', @version VARCHAR(16)= '6.0')
RETURNS VARCHAR(MAX) --Author José
AS
BEGIN    
		IF (@type NOT IN ('config','db') OR @version NOT IN ('6.0','5.16'))
			RETURN ''
		DECLARE @config516_600 VARCHAR(MAX)=
'<?php
require_once ''config_mod.inc.php'';// mods
require_once ''config_db.inc.php'';// Datenbank Konfiguration
require_once ''config_mail.inc.php'';// EMail Konfiguration
define(''OS_LINUX'', 0);/* Betriebssystem, auf dem der Webserver laeuft */
define(''OS_WINDOWS'', 1);
define(''SYSTEM_OS'', OS_LINUX);
define(''USE_UTF8'', false);
define(''ENCODE_UTF8_TRANSLATIONS'', USE_UTF8);
define(''version'', ''REPLACE_version'');/* C-Rent version */
define(''DEFAULT_LANG'', ''REPLACE_DEFAULT_LANG'');/* Standardsprache und Zeitzone */
define(''DEFAULT_TIMEZONE'', ''REPLACE_DEFAULT_TIMEZONE'');
define(''CONFIG_COOKIE_LIFETIME'', 43200);/* Standard Cookie Lebenszeit (12h * 60m * 60s) */
define(''CONFIG_START_GROUP'', ''%'');/* Startgruppe in der Dispo, wenn keine Gruppe vom Benutzer festgelegt wird *//* !!! DEPRECATED !!! Mittlerweile im Benutzerstamm konfigurierbar */
/* Raten, die nicht fuer Kunden als Standardraten in Frage kommen */
define(''CONFIG_BLOCKED_CUSTOMER_RATES'', '''');
define(''CONFIG_BLOCKED_CUSTOMER_PRICELISTS'', '''');
//define(''JAVA_HOSTS'', ''127.0.0.1:8082'');/* Achtung!!! Auch der Jasper-Druck-Dienst muss entsprechend angepasst werden (HTTP_LOCAL:8080) *//* Port fuer Jasper Ausdrucke definieren */'
		DECLARE @config600 VARCHAR(MAX)=
'<?php
require_once(''config_mod.inc.php'');// mods
require_once(''config_db.inc.php'');// Datenbank Konfiguration
require_once(''config_mail.inc.php'');// EMail Konfiguration
define(''OS_LINUX'', 0);/* Betriebssystem, auf dem der Webserver laeuft */
define(''OS_WINDOWS'', 1);
define(''SYSTEM_OS'', OS_LINUX);
define(''USE_UTF8'', false);
define(''ENCODE_UTF8_TRANSLATIONS'', USE_UTF8);
define(''version'', ''6.0'');/* C-Rent version */
define(''DEFAULT_LANG'', ''DE'');/* Standardsprache und Zeitzone */
define(''DEFAULT_TIMEZONE'', ''Europe/Berlin'');
define(''CONFIG_COOKIE_LIFETIME'', 43200);/* Standard Cookie Lebenszeit (12h * 60m * 60s) */
define(''CONFIG_START_GROUP'', ''%'');/* !!! DEPRECATED !!! Mittlerweile im Benutzerstamm konfigurierbar */
define(''CONFIG_BLOCKED_CUSTOMER_RATES'', '''');/* Raten, die nicht fuer Kunden als Standardraten in Frage kommen */
define(''CONFIG_BLOCKED_CUSTOMER_PRICELISTS'', '''');
//define(''JAVA_HOSTS'', ''127.0.0.1:8082''); /* Port fuer Jasper Ausdrucke definieren *//* Achtung!!! Auch der Jasper-Druck-Dienst muss entsprechend angepasst werden (HTTP_LOCAL:8080) */'
		DECLARE @dbConfig516_600 VARCHAR(MAX)=
'<?php
/* Datenbank */
define(''DB_MSSQL'', 0);
define(''DB_SQLSRV'', 1);
define(''DB_MYSQL'', 2);
define(''SYSTEM_DB'', DB_MSSQL);
define(''PDO'', 0);
define(''PERSISTENT'', 0);
/* Zugangsdaten zur Datenbank */
$globalcfg[''db''][''host''] = ''REPLACE_HOST'';
$globalcfg[''db''][''database''] = ''REPLACE_DATABASENAME'';
$globalcfg[''db''][''username''] = ''REPLACE_DB_USERNAME''; 
//$globalcfg[''db''][''password''] = ''REPLACE_DBUSERNAME_PWD''; //die bekannte Art generiert, falls auskommentiert
$globalcfg[''db''][''instance''] = ''REPLACE_DB_INSTANCE''; // Instanz
/* Zugangsdaten zur Archiv Datenbank */
$globalcfg[''archiv''][''use_archiv''] = false;
$globalcfg[''archiv''][''host''] = '''';
$globalcfg[''archiv''][''database''] = '''';
$globalcfg[''archiv''][''username''] = '''';
//$globalcfg[''archiv''][''password''] = ''''; 
//$globalcfg[''archiv''][''instance''] = '''';
$globalcfg[''upload''][''localpath''] = '''';/* Pfade fuer Upload */
//$globalcfg[''upload''][''serverpath''] = '''';
$globalcfg[''upload''][''max_file_size''] = 1024 * 1024 * 2;/* Maximale Dateigroesse fuer Upload */
/* FTP-Zugangsdaten fuer Upload (deprecated) */
$globalcfg[''upload''][''use_ftp''] = false;'
		IF (@version = '6.0' AND @type='config') RETURN @Config600
		IF (@version = '5.16' AND @type='config') RETURN @config516_600
		IF (@version = '6.0' AND @type='db') RETURN @dbConfig516_600
		IF (@version = '5.16' AND @type='db') RETURN @dbConfig516_600
		
