CREATE FUNCTION [dbo].[GET_CRWJASPER_DEPLOYMENT_ENVIRONMENTNAME](@MANDANT_ID INT = NULL)
RETURNS VARCHAR(MAX)
AS
BEGIN
--SELECT * FROM dbo.Mandant
	DECLARE @result XML    
	SET @result = (
		SELECT
N'    - local: ''/.deployment/'+CRW_DEPLOYMENT_NAME+'.yml'''+CHAR(10) FROM dbo.GET_CRWJASPERDEPLOYMENT_MANDANT_DB_ENVIRONMENT(@MANDANT_ID)	   
 
		FOR XML PATH(''), ROOT('result')
	 ,TYPE)
	RETURN ISNULL(@result.value('/result[1]/text()[1]', 'VARCHAR(MAX)'),'')
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_CRWJASPER_DEPLOYMENT_ENVIRONMENTS]    Script Date: 25.01.2022 03:14:46 ******/
