CREATE FUNCTION [dbo].[GET_CRWJASPERCONFIG_BY_MANDANT_ID](@mandID INT = NULL, @type VARCHAR(8)='config')
RETURNS VARCHAR(MAX) --Author José
AS
BEGIN    
		IF (@type NOT IN ('config','db') OR NOT EXISTS(SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@mandID))
			RETURN ''
		 
	    DECLARE @configText VARCHAR(MAX) = ''
	    DECLARE @configHEX VARCHAR(MAX) = ''
	    DECLARE @LANG VARCHAR(2) = 'DE'--hier auf Mandant Tabelle zugreifen, für Kunden die auf anderen Ländern sind
	    DECLARE @DEFAULT_TIMEZONE VARCHAR(16) = 'Europe/Berlin'
	    DECLARE @HOST VARCHAR(128) = ''
	    DECLARE @version VARCHAR(128) = '6.0'--default
	    DECLARE @INSTANCE VARCHAR(128) = ''
	    DECLARE @DATABASENAME VARCHAR(128) = ''
	    DECLARE @DB_USERNAME VARCHAR(128) = ''
	    DECLARE @DB_USERNAME_PWD NVARCHAR(255) = ''
	    DECLARE @MANDANT_ID INT = NULL
			SELECT TOP 1 @DATABASENAME=ISNULL(databaseName,''), 
					     @DB_USERNAME=ISNULL(databaseUser,''), 
						 @DB_USERNAME_PWD=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
						 @HOST=ISNULL(databaseIp,''),
						 @INSTANCE=  CASE WHEN ISNULL(databaseInstance,'')<>'' THEN databaseInstance ELSE '' END,
						 @MANDANT_ID = MANDANT_ID,
						 @version = ISNULL(version,@version)
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @mandID ORDER BY type ASC-- and version = @version 
		IF (EXISTS(SELECT TOP 1 timeZone FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID))
			BEGIN
				SET @DEFAULT_TIMEZONE = ISNULL((SELECT TOP 1 timeZone FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID),@DEFAULT_TIMEZONE)		
				SET @HOST = ISNULL((SELECT TOP 1 CLIENT_INTERN_HOST FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID),@HOST)				
			END
		DECLARE @configAndDBConfigReplacements VARCHAR(MAX) = 
			'REPLACE_version='+@version+';'+
			'REPLACE_DEFAULT_LANG='+@LANG+';'+
			'REPLACE_DEFAULT_TIMEZONE='+@DEFAULT_TIMEZONE+';'+
			'REPLACE_HOST='+@HOST+';'+
			'REPLACE_DB_INSTANCE='+@INSTANCE+';'+
			'REPLACE_DATABASENAME='+@DATABASENAME+';'+
			'REPLACE_DB_USERNAME='+@DB_USERNAME+';'+
			'REPLACE_DBUSERNAME_PWD='+@DB_USERNAME_PWD+';'
		--	return @configAndDBConfigReplacements
		--PRINT dbo.stringReplaceMultiple_pattern('searchjöseLüis',@configAndDBConfigReplacements,';','='

		SET @configText = dbo.GET_CRWCONFIG_TEXT(@type, '6.0')
		SET @configText = dbo.stringReplaceMultiple_pattern(@configText,@configAndDBConfigReplacements,';','=')
		SET @configHEX = CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), @configText), 1)		 
		RETURN  SUBSTRING(@configHEX,3,LEN(@configHEX))
 END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_CRWJASPERDEPLOYMENT_MANDANT_DB_ENVIRONMENT]    Script Date: 25.01.2022 03:14:46 ******/
