CREATE FUNCTION [dbo].[GET_CRWJASPERDEPLOYMENT_MANDANT_DB_ENVIRONMENT] (@MANDANT_ID INT = NULL)
RETURNS @MANDANT_DB_ENVIRONMENT TABLE(MANDANT_ID INT NULL, MANDANT_NAME VARCHAR(2048), CRW_DEPLOYMENT_NAME VARCHAR(128) NULL)  
			 
BEGIN 
	DECLARE @MANDANT_DB_ENVIRONMENT_AUX TABLE(MANDANT_ID INT NULL, MANDANT_NAME VARCHAR(2048), CRW_DEPLOYMENT_NAME VARCHAR(128) NULL)  
	INSERT INTO @MANDANT_DB_ENVIRONMENT_AUX (MANDANT_ID, MANDANT_NAME, CRW_DEPLOYMENT_NAME)
		SELECT id, ISNULL(companyname,''), dbo.GET_MANDANT_JASPER_DEPLOYMENT_NAME(id)
	    FROM dbo.Mandant WHERE documentRoot IS NOT NULL AND globalName <> '' 
		ORDER BY documentRoot ASC	
 
	IF (@MANDANT_ID IS NOT NULL) 
		DELETE FROM @MANDANT_DB_ENVIRONMENT_AUX WHERE MANDANT_ID <> @MANDANT_ID
	INSERT INTO @MANDANT_DB_ENVIRONMENT
		SELECT * FROM @MANDANT_DB_ENVIRONMENT_AUX ORDER BY CRW_DEPLOYMENT_NAME ASC
  
	RETURN  
END
GO
