CREATE FUNCTION [dbo].[GET_CSAPP_OPTIONS_FIELDS] (@PROTOCOL_ID BIGINT)
RETURNS @output TABLE(PK BIGINT NOT NULL IDENTITY(1,1), Bezeichnung VARCHAR(55)  NULL, CHECKED BIT NULL)  
BEGIN 
		INSERT INTO @output(Bezeichnung,CHECKED)
		SELECT SUBSTRING(ISNULL(cof.OPTIONS_NAME, ''),1,55),CAST(ISNULL(cof.OPTIONS_VALUE,0) AS bit) FROM CSAPP_OPTIONS_FIELDS cof WHERE cof.PROTOKOLL_PK = @PROTOCOL_ID		
	RETURN  
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_DBO_TABLEFIELDS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[GET_DBO_TABLEFIELDS] (@tablename VARCHAR(512))
RETURNS VARCHAR(MAX)  
BEGIN  --Autor José  
	DECLARE @table_fields_result VARCHAR(MAX)
	SET @table_fields_result = '' 
	SELECT @table_fields_result = ISNULL((STUFF((SELECT ( 	 
		SELECT DISTINCT ', ['+TableColumn.NAME+']' AS '*' FOR XML PATH(''), TYPE)
		FROM [syscolumns] TableColumn
		INNER JOIN [systypes] sTyps ON TableColumn.xtype = sTyps.xtype
		INNER JOIN [sysobjects] sObjs ON sObjs.id = TableColumn.[id]
		AND UPPER(sObjs.name) = UPPER(@tablename) 
		ORDER BY TableColumn.id 
	FOR XML PATH('') ),1,1,'')), '') -- Be sure with is null that query returns a empty string 
 
	RETURN @table_fields_result 
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_DEPLOYMENT_LINKED_SERVER_CONNECTION_BY_PK]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE FUNCTION [dbo].[GET_DEPLOYMENT_LINKED_SERVER_CONNECTION_BY_PK](@mandIDPK INT = NULL, @envversion VARCHAR(16)= '6.0' )
RETURNS VARCHAR(MAX)
AS
BEGIN  
	    DECLARE @environments TABLE (MANDANT_ENV_PK INT NULL, MANDANT_ID INT NOT NULL, ENVIRONMENT VARCHAR(128) NOT NULL)
		
		INSERT INTO @environments
			SELECT PK, mandant_id, CASE WHEN type ='DEFAULT' THEN 'LIVE'
				WHEN databaseName LIKE 'ACC_%' THEN 'ACC'
				WHEN databaseName LIKE 'KOPIE_%' THEN 'ACC' ELSE type END[env]
			FROM MANDANT_DB_ENVIRONMENT ME WHERE me.PK =@mandIDPK AND  me.version = @envversion AND ME.mandant_id IN (SELECT id FROM dbo.Mandant)
 
	RETURN (ISNULL((
		 STUFF(( 
				 SELECT 
								(SELECT dbo.GET_MANDANT_DEPLOYMENT_NAME(mandant_id)+'_'+UPPER(REPLACE(ISNULL(path,''),':',''))+ISNULL(type,'NO_ENV') AS '@name', 
								(SELECT 
									ISNULL(databaseIp,'')+
											CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END + 
											CASE WHEN dbo.isClientExtern(mandant_id)=1 AND ISNUMERIC(databasePort)=1 THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END 
							
									AS '*'  FOR XML PATH('ServerName'), TYPE),							 
									(SELECT ISNULL(databaseName,'') AS '*'  FOR XML PATH('DatabaseName'), TYPE), 
									(SELECT ISNULL(databaseUser,'') AS '*'  FOR XML PATH('Username'), TYPE), 
									(SELECT dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')) AS '*'  FOR XML PATH('Password'), TYPE) 
							

							FOR XML PATH('LINKED_SERVER'), TYPE)   
						FROM dbo.MANDANT_DB_ENVIRONMENT WHERE  PK IN (SELECT MANDANT_ENV_PK FROM @environments) AND  version = @envversion AND ISNULL(databaseIp,'') <> '' AND 
								ISNULL(databaseName,'') <> '' AND ISNULL(databaseUser,'')<>''
								AND dbo.GET_MANDANT_DEPLOYMENT_NAME(mandant_id)<>''
					FOR XML PATH(''),ROOT('server')),1,0,'')	
	),''))

 
 END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_DEPLOYMENT_LINKED_SERVER_CONNECTIONS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
