CREATE FUNCTION [dbo].[GET_DEPLOYMENT_LINKED_SERVER_CONNECTIONS](@mandID INT = NULL, @userEnv NVARCHAR(128)= NULL, @envversion VARCHAR(16)= '6.0' )
RETURNS VARCHAR(MAX)
AS
BEGIN  
	    DECLARE @environments TABLE (MANDANT_ENV_PK INT NULL, MANDANT_ID INT NOT NULL, ENVIRONMENT VARCHAR(128) NOT NULL)
		
		INSERT INTO @environments
			SELECT PK, mandant_id, CASE WHEN type ='DEFAULT' THEN 'LIVE'
				WHEN databaseName LIKE 'ACC_%' THEN 'ACC'
				WHEN databaseName LIKE 'KOPIE_%' THEN 'ACC' ELSE type END[env]
			FROM MANDANT_DB_ENVIRONMENT ME WHERE me.version = @envversion AND ME.mandant_id IN (SELECT id FROM dbo.Mandant)
		IF (@mandID IS NOT NULL AND @userEnv IS NULL)
			DELETE FROM @environments WHERE MANDANT_ID NOT IN (@mandID) 
		ELSE IF (@mandID IS NULL AND @userEnv IS NOT NULL)
			BEGIN 
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@userEnv)
			END 
		ELSE IF (@mandID IS NOT NULL AND @userEnv IS NOT NULL)
			BEGIN
				DELETE FROM @environments WHERE MANDANT_ID NOT IN (@mandID)  
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@userEnv)
			END 
	RETURN (ISNULL((
		 STUFF(( 
				 SELECT 
								(SELECT dbo.GET_MANDANT_DEPLOYMENT_NAME(mandant_id)+'_'+UPPER(REPLACE(ISNULL(path,''),':',''))+ISNULL(type,'NO_ENV') AS '@name', 
								(SELECT 
									ISNULL(databaseIp,'')+
											CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END + 
											CASE WHEN dbo.isClientExtern(mandant_id)=1 AND ISNUMERIC(databasePort)=1 THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END 
							
									AS '*'  FOR XML PATH('ServerName'), TYPE),							 
									(SELECT ISNULL(databaseName,'') AS '*'  FOR XML PATH('DatabaseName'), TYPE), 
									(SELECT ISNULL(databaseUser,'') AS '*'  FOR XML PATH('Username'), TYPE), 
									(SELECT dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')) AS '*'  FOR XML PATH('Password'), TYPE) 
							

							FOR XML PATH('LINKED_SERVER'), TYPE)   
						FROM dbo.MANDANT_DB_ENVIRONMENT WHERE  PK IN (SELECT MANDANT_ENV_PK FROM @environments) AND  version = @envversion AND ISNULL(databaseIp,'') <> '' AND 
								ISNULL(databaseName,'') <> '' AND ISNULL(databaseUser,'')<>''
								AND dbo.GET_MANDANT_DEPLOYMENT_NAME(mandant_id)<>''
					FOR XML PATH(''),ROOT('server')),1,0,'')	
	),''))

 
 END
GO
