CREATE FUNCTION [dbo].[GET_DEPLOYMENT_MANDANT_ENVIRONMENT_NAMES] (@MANDANT_ID INT = NULL)
RETURNS @MANDANT_DB_ENVIRONMENT TABLE(MANDANT_ID INT NULL, MANDANT_NAME VARCHAR(2048), CRW_DEPLOYMENT_NAME VARCHAR(128) NULL)  
			 
BEGIN 
	DECLARE @MANDANT_DB_ENVIRONMENT_AUX TABLE(MANDANT_ID INT NULL, MANDANT_NAME VARCHAR(2048), CRW_DEPLOYMENT_NAME VARCHAR(128) NULL)  
	INSERT INTO @MANDANT_DB_ENVIRONMENT_AUX (MANDANT_ID, MANDANT_NAME, CRW_DEPLOYMENT_NAME)
		SELECT id, ISNULL(companyname,''), dbo.GET_MANDANT_DEPLOYMENT_NAME(id)
	    FROM dbo.Mandant WHERE documentRoot IS NOT NULL AND globalName <> '' 
		AND ID IN (SELECT MANDANT_ID FROM MANDANT_DB_ENVIRONMENT ) ORDER BY documentRoot ASC	
 
	IF (@MANDANT_ID IS NOT NULL) 
		DELETE FROM @MANDANT_DB_ENVIRONMENT WHERE MANDANT_ID <> @MANDANT_ID
	INSERT INTO @MANDANT_DB_ENVIRONMENT
		SELECT * FROM @MANDANT_DB_ENVIRONMENT_AUX ORDER BY CRW_DEPLOYMENT_NAME ASC
  
	RETURN  
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_Deployment_version_TSQLCODE]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_Deployment_version_TSQLCODE](@MandantId INT = null)
RETURNS NVARCHAR(MAX)
BEGIN

DECLARE @Deploy_version VARCHAR(128) = ISNULL((SELECT TOP 1 Deploy_version FROM dbo.DEPLOYMENT_versionS ORDER BY PK DESC),'0')
DECLARE @tsql VARCHAR(MAX) = 
 '
IF EXISTS (SELECT * FROM version)
  UPDATE version SET version = ''6.0'', Deploymentversion = '''+@Deploy_version+'''
else
  INSERT INTO version (version, Deploymentversion) VALUES (''6.0'', '''+@Deploy_version+''')
go

	'
	RETURN @tsql
END
