/****** Object:  UserDefinedFunction [dbo].[GET_ENVIRONMENT_COMPARE_RESULT_LOG_ERRORS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_ENVIRONMENT_COMPARE_RESULT_LOG_ERRORS](@MandantID INT = NULL, @environmentName VARCHAR(128) = NULL, @environmentType VARCHAR(128) = NULL)
RETURNS VARCHAR(MAX)
BEGIN
	  DECLARE @errors VARCHAR(MAX)='MissingLogs;Update6NotDone',
	  @COMPARE_RESULT_LOGS XML = NULL 
	  IF  
			EXISTS(
			SELECT ENVIRONMENT FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE 
			WHERE MANDANT_ID = @MandantID 
			AND ENVIRONMENT = @environmentName
			AND COMPARE_RESULT_LOGS IS NOT NULL
			AND  TYPE = @environmentType		
			)
		BEGIN
			 SET @errors=''  
			 DECLARE environment_cursor CURSOR  
				FOR SELECT COMPARE_RESULT_LOGS FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID=@MandantID AND ENVIRONMENT = @environmentName AND TYPE = @environmentType
			 OPEN environment_cursor  
			 FETCH NEXT FROM environment_cursor INTO @COMPARE_RESULT_LOGS
   
			 WHILE @@FETCH_STATUS = 0  
			 BEGIN   
				 SET @errors+=dbo.GET_UPDATE_LOG_ERRORS(@COMPARE_RESULT_LOGS, DEFAULT, DEFAULT)							
				 FETCH NEXT FROM environment_cursor	INTO @COMPARE_RESULT_LOGS
			 END   
			 CLOSE environment_cursor  
			 DEALLOCATE environment_cursor	
		END
	RETURN @errors
END
GO
