BEGIN
	  DECLARE @results NVARCHAR(MAX)=''
	  DECLARE @dbNameString NVARCHAR(MAX)=dbo.getUpdateDBEnvInfo(@MandantID,@environmentName,'SCHEMA')
	  DECLARE @errorDBSchemaDataEnvLogs VARCHAR(MAX)=dbo.GET_ENVIRONMENT_LOG_ERRORS(@MandantID, @environmentName)
	  DECLARE @tempResult NVARCHAR(MAX) =
'<tr style="background:green" class="bg-success">
 <th scope="row">1</th>
 <td>C-Rent '+@environmentName+' Datenbank Update<br>'+@dbNameString+'</td>
 <td>Alle Prozesse wurden erfolgreich abgeschlossen</td>
 <td>Erfolgreich &#128578;</td>
</tr>'
	  IF (@errorDBSchemaDataEnvLogs<>'')
		SET @tempResult = 
'<tr style="background:orangered" class="bg-danger">
 <th scope="row">1</th>
