</tr>'

IF (NOT EXISTS (SELECT PK FROM dbo.WEB_PRODUKTE_LOG_UPDATE WHERE  MANDANT_ID=@MandantID AND ENVIRONMENT = @environmentName) OR @justDBReport = 1)
		RETURN @results
	  DECLARE  @CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG XML = NULL, 
	  @CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG XML = NULL, @CREATE_GITLAB_JASPERMR_LOG XML = NULL,
	  @CREATE_GITLAB_CRENTWEBMR_LOG XML = NULL,
	  @JASPER_MR_APPROVED_LOG XML = NULL, 
	  @CRWEB_MR_APPROVED_LOG XML = NULL 
	  SELECT TOP 1 @CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG = CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG,
	  @CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG  = CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG, 
	  @CREATE_GITLAB_JASPERMR_LOG = CREATE_GITLAB_JASPERMR_LOG,
	  @CREATE_GITLAB_CRENTWEBMR_LOG = CREATE_GITLAB_CRENTWEBMR_LOG,
	  @JASPER_MR_APPROVED_LOG=JASPER_MR_APPROVED_LOG,
	  @CRWEB_MR_APPROVED_LOG=CRWEB_MR_APPROVED_LOG FROM dbo.WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID=@MandantID AND ENVIRONMENT = @environmentName --AND LAST_STATUS <> 'success'
	  

		 SET @tempResult = 
'<tr style="background:green" class="bg-success">
 <th scope="row">2</th>
 <td>C-Rent Web Environment '+@environmentName+' Ordner</td>
 <td>Erstellung erfolgreich.</td>
 <td>Erfolgreich &#128578;</td>
</tr>'	
	  
	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG, 'update cancelled', DEFAULT) <> '')
		 SET @tempResult = 
'<tr style="background:orangered" class="bg-danger">
 <th scope="row">2</th>
 <td>C-Rent Web Environment '+@environmentName+' Ordner</td>
 <td>Erstellung nicht erfolgreich.</td>
 <td>Fehler &#128577;</td>
</tr>'
	 SET @results+=@tempResult

		 SET @tempResult = 
'<tr style="background:green" class="bg-success">
 <th scope="row">3</th>
 <td>Reservierung Environment '+@environmentName+' Ordner</td>
 <td>Erstellung erfolgreich.</td>
 <td>Erfolgreich &#128578;</td>
</tr>'	
	  
	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG, 'update cancelled', DEFAULT) <> '')
		 SET @tempResult = 
'<tr style="background:orangered" class="bg-danger">
 <th scope="row">3</th>
 <td>Reservierung Environment '+@environmentName+' Ordner</td>
 <td>Erstellung nicht erfolgreich.</td>
 <td>Fehler &#128577;</td>
</tr>'
	 SET @results+=@tempResult

