'<tr style="background:green" class="bg-success">
 <th scope="row">4</th>
 <td>Jasper MR</td>
 <td>Erstellung erfolgreich.</td>
 <td>Erfolgreich &#128578;</td>
</tr>'	
	  
	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CREATE_GITLAB_JASPERMR_LOG, 'update cancelled', DEFAULT) <> '')
		 SET @tempResult = 
'<tr style="background:orangered" class="bg-danger">
 <th scope="row">4</th>
 <td>Jasper MR</td>
 <td>Erstellung nicht erfolgreich.</td>
 <td>Fehler &#128577;</td>
</tr>'
	 SET @results+=@tempResult 
		 SET @tempResult = 
'<tr style="background:green" class="bg-success">
 <th scope="row">5</th>
 <td>C-Rent Web MR</td>
 <td>Erstellung erfolgreich.</td>
 <td>Erfolgreich &#128578;</td>
</tr>'	
	  
	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CREATE_GITLAB_CRENTWEBMR_LOG, 'update cancelled', DEFAULT) <> '')
		 SET @tempResult = 
'<tr style="background:orangered" class="bg-danger">
 <th scope="row">5</th>
 <td>C-Rent Web MR</td>
 <td>Erstellung nicht erfolgreich.</td>
 <td>Fehler &#128577;</td>
</tr>'
	SET @results+=@tempResult

