 <th scope="row">6</th>
 <td>CX9 Gitlab C-Rentweb MR</td>
 <td>MR wurde approved.</td>
 <td>Erfolgreich &#128578;</td>
</tr>'	

	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CRWEB_MR_APPROVED_LOG, 'merge_requests', DEFAULT) = '' OR @CRWEB_MR_APPROVED_LOG IS NULL)
		 SET @tempResult = 
'<tr style="background:orange" class="bg-warning">
 <th scope="row">6</th>
 <td>CX9 Gitlab C-Rentweb MR</td>
 <td>MR wurde noch nicht approved bzw. noch nicht erstellt.<br><a href="'+dbo.EXTRACT_MR_FROM_LOGS(@CREATE_GITLAB_CRENTWEBMR_LOG, DEFAULT, DEFAULT)+'"><b>C-Rent Web Merge Request bearbeiten</b></a></td>
 <td>Ausstehend &#128054;</td>
</tr>'

	SET @results+=@tempResult
		 SET @tempResult = 
'<tr style="background:green" class="bg-success">
 <th scope="row">7</th>
 <td>CX9 Gitlab Jasper MR</td>
 <td>MR wurde approved.</td>
 <td>Erfolgreich &#128578;</td>
</tr>'	

	  IF(dbo.GET_UPDATE_LOG_ERRORS(@JASPER_MR_APPROVED_LOG, 'merge_requests', DEFAULT) = '' OR @JASPER_MR_APPROVED_LOG IS NULL)
		 SET @tempResult = 
