 <td>MR wurde noch nicht approved bzw. noch nicht erstellt.<br><a href="'+dbo.EXTRACT_MR_FROM_LOGS(@CREATE_GITLAB_JASPERMR_LOG, DEFAULT, DEFAULT)+'"><b>Jasper Merge Request bearbeiten</b></a></td>
 <td>Ausstehend &#128054;</td>
</tr>'
 
	 SET @results+=@tempResult
 
	RETURN @results
END
