CREATE FUNCTION [dbo].[GET_ENVIRONMENT_LOG_ERRORS](@MandantID INT = NULL, @environmentName VARCHAR(128) = NULL)
RETURNS VARCHAR(MAX)
BEGIN
	  DECLARE @errors VARCHAR(MAX)='MissingLogs;Update6NotDone',
	  @CREATE_COMPARE_JOB_LOG XML = NULL,
	  @UPLOAD_JOB_LOG XML = NULL,
	  @IMPORT_EXPORT_TRANSLATIONS_JOB_LOG XML = NULL,
	  @TRANSLATIONS_JOB_LOG XML = NULL,
	  @COMPARE_RESULT_LOGS XML = NULL 
	  IF /*EXISTS(SELECT CREATE_COMPARE_JOB_LOG, UPLOAD_JOB_LOG, TRANSLATIONS_JOB_LOG, IMPORT_EXPORT_TRANSLATIONS_JOB_LOG 
			FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID=@MandantID AND ENVIRONMENT = @environmentName 
			AND (CREATE_COMPARE_JOB_LOG IS NOT NULL AND UPLOAD_JOB_LOG IS NOT NULL AND TRANSLATIONS_JOB_LOG IS NOT NULL AND IMPORT_EXPORT_TRANSLATIONS_JOB_LOG IS NOT NULL) 
			) AND */
			EXISTS(
			SELECT ENVIRONMENT FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE 
			WHERE MANDANT_ID = @MandantID 
			AND ENVIRONMENT = @environmentName           
			AND /*EXECUTED = 1 AND*/ CREATE_COMPARE_JOB_LOG IS NOT NULL
			AND UPLOAD_JOB_LOG IS NOT NULL 
			AND TRANSLATIONS_JOB_LOG IS NOT NULL
			AND IMPORT_EXPORT_TRANSLATIONS_JOB_LOG IS NOT NULL
			AND COMPARE_RESULT_LOGS IS NOT NULL
			AND (TYPE = 'DATA' OR TYPE = 'SCHEMA') GROUP BY ENVIRONMENT HAVING COUNT(PK) = 2			
			)
		BEGIN
			 SET @errors=''  
			 DECLARE environment_cursor CURSOR  
				FOR SELECT CREATE_COMPARE_JOB_LOG, UPLOAD_JOB_LOG, TRANSLATIONS_JOB_LOG, IMPORT_EXPORT_TRANSLATIONS_JOB_LOG, COMPARE_RESULT_LOGS FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID=@MandantID AND ENVIRONMENT = @environmentName
			 OPEN environment_cursor  
			 FETCH NEXT FROM environment_cursor INTO @CREATE_COMPARE_JOB_LOG, @UPLOAD_JOB_LOG, @TRANSLATIONS_JOB_LOG, @IMPORT_EXPORT_TRANSLATIONS_JOB_LOG, @COMPARE_RESULT_LOGS
   
			 WHILE @@FETCH_STATUS = 0  
			 BEGIN   
				 SET @errors+=
							dbo.GET_UPDATE_LOG_ERRORS(@CREATE_COMPARE_JOB_LOG, DEFAULT, DEFAULT)+
							dbo.GET_UPDATE_LOG_ERRORS(@UPLOAD_JOB_LOG, DEFAULT, DEFAULT)+
							dbo.GET_UPDATE_LOG_ERRORS(@TRANSLATIONS_JOB_LOG, DEFAULT, DEFAULT)+
							dbo.GET_UPDATE_LOG_ERRORS(@IMPORT_EXPORT_TRANSLATIONS_JOB_LOG, 'Meldung;Falsche Syntax;SQL Server', DEFAULT)+ --ignore not imported translations
							dbo.GET_UPDATE_LOG_ERRORS(@COMPARE_RESULT_LOGS, DEFAULT, DEFAULT)
							
				 FETCH NEXT FROM environment_cursor	INTO @CREATE_COMPARE_JOB_LOG, @UPLOAD_JOB_LOG, @TRANSLATIONS_JOB_LOG, @IMPORT_EXPORT_TRANSLATIONS_JOB_LOG, @COMPARE_RESULT_LOGS
			 END   
			 CLOSE environment_cursor  
			 DEALLOCATE environment_cursor	
		END
	RETURN @errors
END
GO
