/****** Object:  UserDefinedFunction [dbo].[GET_ENVIRONMENT_UPDATE_STATUS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_ENVIRONMENT_UPDATE_STATUS](@MandantID INT = NULL, @environmentName VARCHAR(128) = NULL)
RETURNS NVARCHAR(MAX)
BEGIN
 
	  DECLARE @result NVARCHAR(MAX)=''
	  DECLARE  @CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG XML = NULL, 
	  @CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG XML = NULL, 
	  @CREATE_GITLAB_JASPERMR_LOG XML = NULL,
	  @CREATE_GITLAB_CRENTWEBMR_LOG XML = NULL, 
	  @JASPER_MR_APPROVED_LOG XML = NULL, 
	  @CRWEB_MR_APPROVED_LOG XML = NULL
 
	  IF (dbo.GET_ENVIRONMENT_LOG_ERRORS(@MandantID, @environmentName)<>'')
		SET @result+='db_update_problem;' 

	  IF NOT EXISTS (SELECT PK FROM dbo.WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID=@MandantID AND ENVIRONMENT = @environmentName)
			RETURN @result

	  SELECT TOP 1 @CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG = CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG,
	  @CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG  = CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG, 
	  @CREATE_GITLAB_JASPERMR_LOG = CREATE_GITLAB_JASPERMR_LOG,
	  @CREATE_GITLAB_CRENTWEBMR_LOG = CREATE_GITLAB_CRENTWEBMR_LOG,
	  @JASPER_MR_APPROVED_LOG=JASPER_MR_APPROVED_LOG,
	  @CRWEB_MR_APPROVED_LOG=CRWEB_MR_APPROVED_LOG  FROM dbo.WEB_PRODUKTE_LOG_UPDATE 
	  WHERE MANDANT_ID=@MandantID AND ENVIRONMENT = @environmentName --AND LAST_STATUS <> 'success'

	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG, 'update cancelled', DEFAULT) <> '')
		 SET @result+='webserver_crentweb_folder_creation_problem;' 
	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG, 'update cancelled', DEFAULT) <> '')
		 SET @result+='webserver_reservierung_folder_creation_problem;' 
	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CREATE_GITLAB_JASPERMR_LOG, 'update cancelled', DEFAULT) <> '')
		 SET @result+='jasper_mr_problem;'
	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CREATE_GITLAB_CRENTWEBMR_LOG, 'update cancelled', DEFAULT) <> '')
		 SET @result+='crentweb_mr_problem;'
	  IF(dbo.GET_UPDATE_LOG_ERRORS(@CRWEB_MR_APPROVED_LOG, 'merge_requests', DEFAULT) = '' OR @CRWEB_MR_APPROVED_LOG IS NULL)
		 SET @result+='crentweb_mr_not_approved;'
	  IF(dbo.GET_UPDATE_LOG_ERRORS(@JASPER_MR_APPROVED_LOG, 'merge_requests', DEFAULT) = '' OR @JASPER_MR_APPROVED_LOG IS NULL)
		 SET @result+='jasper_mr_not_approved;'

	  IF (@result = '')
		SET @result = 'success'
 
	RETURN @result
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_GENERAL_ELEMENT_PROPERTIES]    Script Date: 25.01.2022 03:14:46 ******/
