CREATE FUNCTION [dbo].[GET_GENERAL_ELEMENT_PROPERTIES] (@ID VARCHAR(32) = NULL, @TABLE VARCHAR(255) = '', @tableFieldName varchar(128) = '', @elementType varchar(128) = '', @elementValue NVARCHAR(MAX) = '')  
RETURNS VARCHAR(MAX) AS  --Author José.
BEGIN
  DECLARE @elementJSONProperties NVARCHAR(MAX) = ''
  DECLARE @uniqueElementName VARCHAR(255) = ''
  IF (@elementValue IS NULL)
	SET @elementValue = ''
 
  SET @uniqueElementName = LOWER(ISNULL(@tableFieldName,'elementName')+'_'+ISNULL(@elementType,'elementType')+'_'+ISNULL(@ID,SUBSTRING(dbo.getSHA1PWD(dbo.GenPass(0),1,1,1),1,12)))
	  --general definitions 
	DECLARE @standardWidth VARCHAR(4) = CAST (LEN(ISNULL(@tableFieldName,'elementName'))+1 AS VARCHAR(4))
	 
	IF (ISNULL(@elementType,'')='label') --hier davon ausgegangen 2 Label einanander daher properties von 2 labels
		SET @elementJSONProperties = '{"label":{"text":"'+ISNULL(@tableFieldName,'elementName')+': ", "height":"2", "font":"Helvetica 15 italic bold"}, "element":{"name":"'+@uniqueElementName+'", "width":"16", "height":"2", "anchor":"w", "justify":"left", "text":"'+@elementValue+'", "font":"Helvetica 15 bold", "fg":"red", "bg":"sky blue"}}'
	IF (ISNULL(@elementType,'')IN ('entry','inputText') ) --label + entry}
		SET @elementJSONProperties = '{"label":{"text":"'+ISNULL(@tableFieldName,'elementName')+': ", "height":"2", "font":"Helvetica 15 italic bold","anchor":"w", "justify":"right", "fg":"blue2", "bg":"light slate grey"}, "element":{"name":"'+@uniqueElementName+'", "width":"29", "justify":"left", "text":"'+@elementValue+'", "font":"Helvetica 12 bold", "highlightbackground":"black"}}'   
	IF (ISNULL(@elementType,'')IN ('checkbox') ) --label + entry
		SET @elementJSONProperties = '{"label":{"width":"1","text":"", "height":"2", "font":"Helvetica 12 bold","anchor":"w", "justify":"right", "fg":"medium blue", "bg":"light slate grey"}, "element":{"name":"'+@uniqueElementName+'", "width":"16", "justify":"left", "text":"'+@elementValue+'", "font":"Helvetica 14 bold", "fg":"medium blue", "bg":"brown1", "highlightbackground":"white"}}'   
	IF (ISNULL(@elementType,'')='button')
		BEGIN
			IF (@tableFieldName LIKE '%ACID_button')
				SET @tableFieldName=''
			SET @elementJSONProperties = '{"label":{"width":"1", "text":"'+ISNULL(@tableFieldName,'elementName')+'", "height":"2", "font":"Dosis 14 bold"}, "element":{"name":"'+@uniqueElementName+'", "width":"18", "justify":"left", "text":"'+@elementValue+'", "font":"Helvetica 14 bold", "highlightbackground":"red", "bg":"gray99", "fg":"forest green", "height":"2",  "highlightbackground":"dodger blue", "relief":"raised"}}'		    
					
		END 

 
 
  RETURN @elementJSONProperties
END
GO
