	IF (@tableFieldName IN ('companyname','firmenName','street','DBSVRINST','modul'))
		SET @widthElement = 27
	IF (@tableFieldName IN ('MandantId','Mandant_Id','Environment','version','id','abasId'))
		SET @widthElement = 3
	IF (@tableFieldName IN ('city'))
		SET @widthElement = 10
	IF (ISDATE(@elementValue)=1 AND LEN(@elementValue)>=10)
		SET @widthElement = 20
	DECLARE @standardWidthLabel VARCHAR(32) = '"width":"'+CAST (LEN(ISNULL(@tableFieldName,'elementName'))+2 AS VARCHAR(4))+'",' 
	DECLARE @standardWidthElement VARCHAR(32) = '"width":"'+CAST (LEN(ISNULL(@tableFieldName,'elementName'))+1 AS VARCHAR(4))+'",' 
 
	IF (ISNUMERIC(@widthLabel)=1)
		SET @standardWidthLabel =  '"width":"'+CAST(@widthLabel+2 AS VARCHAR(16))+'",' 
	IF (ISNUMERIC(@widthElement)=1)
		SET @standardWidthElement = '"width":"'+CAST(@widthElement+2 AS VARCHAR(16))+'",'  
	/**/ 
	IF (ISNULL(@elementType,'')='label') --hier davon ausgegangen 2 Label einanander daher properties von 2 labels
		SET @elementJSONProperties = '{"label":{"text":"'+ISNULL(@tableFieldName,'elementName')+': ", "height":"2", "font":"Helvetica 15 italic bold"}, "element":{"name":"'+@uniqueElementName+'", "width":"16", "height":"2", "anchor":"w", "justify":"left", "text":"'+@elementValue+'", "font":"Helvetica 15 bold", "fg":"red", "bg":"sky blue"}}'
	IF (ISNULL(@elementType,'')IN ('entry','inputText') ) --label + entry}
		SET @elementJSONProperties = '{"label":{'+@standardWidthLabel+'"text":"'+ISNULL(@tableFieldName,'elementName')+': ", "height":"2", "font":"Helvetica 13 bold italic","anchor":"w", "justify":"right", "fg":"blue2", "bg":"light slate grey"}, "element":{'+@standardWidthElement+'"name":"'+@uniqueElementName+'", "justify":"left", "text":"'+@elementValue+'", "font":"Helvetica 12 bold", "highlightbackground":"black"}}'   
	IF (ISNULL(@elementType,'')IN ('checkbox') ) --label + entry
		SET @elementJSONProperties = '{"label":{"width":"1","text":"", "height":"2", "font":"Helvetica 12 bold","anchor":"w", "justify":"right", "fg":"medium blue", "bg":"light slate grey","highlightbackground":"red"}, "element":{"name":"'+@uniqueElementName+'", "width":"16", "justify":"left", "text":"'+@elementValue+'", "font":"Helvetica 14 bold", "fg":"medium blue", "bg":"brown1", "highlightbackground":"white"}}'   
	IF (ISNULL(@elementType,'')='button')
		BEGIN
			IF (@tableFieldName LIKE '%ACID_button')
				SET @tableFieldName=''
			SET @elementJSONProperties = '{"label":{"width":"1", "text":"'+ISNULL(@tableFieldName,'elementName')+'", "height":"2", "font":"Dosis 14 bold"}, "element":{"name":"'+@uniqueElementName+'", "width":"18", "justify":"left", "text":"'+@elementValue+'", "font":"Helvetica 14 bold italic", "highlightbackground":"red", "bg":"white", "fg":"dark green", "height":"1",  "highlightbackground":"light slate grey", "relief":"raised"}}'		    	
		END
  RETURN @elementJSONProperties
END
GO
