CREATE FUNCTION [dbo].[GET_GIT_DEPLOYMENT6_UPDATE6_INSTRUCTIONS] (@MANDANT_ID INT = NULL, @type VARCHAR(32)='deployment')
RETURNS VARCHAR(MAX)
AS
BEGIN  --Authors Jose/José
    DECLARE @result VARCHAR (MAX) = ''
	DECLARE @abasTask VARCHAR (128) = dbo.GET_MANDANT_UPDATE_TASK_NO(@MANDANT_ID,DEFAULT)
	IF (@type NOT IN ('deployment','update'))	
		RETURN ''
	IF (@type = 'deployment')
		SET @result=
'			echo Aktualisiere Daten aus dem Git ...
			echo ==============================================================================
			echo %TIME%

			cd C:\Deployment\crent_schema

			git fetch
			git pull
			git checkout '+dbo.GET_GIT_LAST_RELEASE_BRANCH()+'
			git reset --hard origin/'+dbo.GET_GIT_LAST_RELEASE_BRANCH()+'
			git pull origin '+dbo.GET_GIT_LAST_RELEASE_BRANCH()+'
'
	IF (@type = 'update')
		SET @result=
'			echo Aktualisiere Daten aus dem Git ...
			echo ==============================================================================
			echo %TIME%
			C:

			cd C:\Deployment\

			RD /S /Q "C:\Deployment\crent_schema_updates5x_to_60\"
			git clone --single-branch --branch task-'+@abasTask+'-'+dbo.GET_GIT_LAST_RELEASE_BRANCH()+' git@gitlab.cx9.info:jose/crent_schema.git crent_schema_updates5x_to_60

'
 

	RETURN @result
END
