/****** Object:  UserDefinedFunction [dbo].[GET_GIT_LAST_RELEASE_BRANCH]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_GIT_LAST_RELEASE_BRANCH]()
RETURNS NVARCHAR(128)
BEGIN --Authors Jose, José
	DECLARE @Deploy_version VARCHAR(128) = ISNULL((SELECT TOP 1 Deploy_version FROM dbo.DEPLOYMENT_versionS ORDER BY PK DESC),'0')
	DECLARE @Deploy_Branch VARCHAR(128) = ISNULL((SELECT TOP 1 Deploy_branch FROM dbo.DEPLOYMENT_versionS ORDER BY PK DESC),'0')
	DECLARE @release VARCHAR(128)-- = 'master'
	--PRINT @Deploy_version
	IF (@Deploy_Branch <> '0')
	  SET @release = @Deploy_Branch --tse wenn eine Deploy_branch eingetragen ist, dann muss dieser genommen werden
	ELSE
      begin
		DECLARE @replacingString NVARCHAR(max)=''
		DECLARE @startPos INT = dbo.LastIndexOf(@Deploy_version,'.')+1
		DECLARE @endPos INT = LEN(@Deploy_version)
	
		IF (@startPos>=1 AND @endPos >=1 AND @endPos > @startPos)
			BEGIN
				SET @replacingString = SUBSTRING(@Deploy_version,@startPos,(@endPos))  
				--PRINT @replacingString
				SET @Deploy_version = REPLACE(@Deploy_version,@replacingString,'')
				SET @release = 'release-'+@Deploy_version
				--PRINT @release
			END   		
		END
--RETURN 'release-6.21.2'
--RETURN 'release-6.21.4'
	RETURN @release
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_ISO_DATETIME]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_ISO_DATETIME] (@date DATETIME =NULL, @time varchar(4) = '')  
RETURNS VARCHAR(24) AS  
BEGIN
  --Author José. Created on February 8th 2015
  IF(@date IS NULL) SET @date = (SELECT CURRENT_TIMESTAMP)
  IF(@time = '') 
	BEGIN
		SET @time = dbo.dattoctime(@date)
		RETURN CONVERT(VARCHAR,@date,126)
	END 
  DECLARE @iso_date VARCHAR(16)
  SELECT @iso_date=null
  IF(LEN(@time)=4) 
    IF (CONVERT(INT,RIGHT(@time,2))<60)
      IF (CONVERT(INT,SUBSTRING(@time,1,2))<25)
        IF ((@date IS NOT NULL) AND ((@time IS NOT NULL) and (@time<>'    ')))
           SET @iso_date=(SUBSTRING(CONVERT(VARCHAR,@date,126),1,10)+'T'+(SUBSTRING(@time,1,2)+':'+RIGHT(@time,2)))--+':00.0'
           --SET @iso_date=CONVERT(VARCHAR,DATEADD(SECOND, DATEDIFF(SECOND, 0, (SUBSTRING(@time,1,2)+':'+RIGHT(@time,2))), @date),126)  
  RETURN @iso_date+':00.0'
END
GO
