CREATE FUNCTION [dbo].[GET_JASPER_DEPLOYMENT_GITLAB_CI](@MANDANT_ID INT = NULL)
RETURNS VARCHAR(MAX)
AS
BEGIN
	IF NOT EXISTS (SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MANDANT_ID)
		RETURN ''
	DECLARE @jasperBranchName VARCHAR(128)= ISNULL((SELECT TOP 1 CRW_DEPLOYMENT_NAME FROM dbo.GET_CRWJASPERDEPLOYMENT_MANDANT_DB_ENVIRONMENT(@MANDANT_ID)),'')
	DECLARE @mandant1version VARCHAR(128)= ISNULL((SELECT TOP 1 version FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@MANDANT_ID ORDER BY type ASC),'UNKNOWN')
	IF (@jasperBranchName = '')
		RETURN ''
	DECLARE @result VARCHAR (MAX) = 
'.deploy-jasper:
    cache:
        key: ${CI_COMMIT_REF_SLUG}
    script:
        - echo "deploy to $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX on $SSH_HOST:$SSH_PORT as user $SSH_USER"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "echo ''Deploying JASPER Ausdrucke in der C-Rent version $CRENT_version''"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "mkdir -p $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/print"
        - shopt -s dotglob
        - rsync -O -rltDv -e ''ssh -p''$SSH_PORT'''' --exclude=''.git/'' --exclude=''.gitlab-ci.yml'' ./* $SSH_USER@$SSH_HOST:$SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/print
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "cd $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/tools && sh ./jrxml2jasper.sh"
    allow_failure: true

.deploy-jasper_remote:
    cache:
        key: ${CI_COMMIT_REF_SLUG}
    script:
        - echo "deploy to $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX on $SSH_HOST:$SSH_PORT as user $SSH_USER"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "echo ''Deploying JASPER Ausdrucke in der C-Rent version $CRENT_version''"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "mkdir -p $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/print"
        - shopt -s dotglob
        - rsync -O -rltDv -e ''ssh -p''$SSH_PORT'''' --exclude=''.git/'' --exclude=''.gitlab-ci.yml'' ./* $SSH_USER@$SSH_HOST:$SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/print
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "cd $SERVER_PATH/crentweb$SERVER_PATH_SUFFIX/tools && sh ./jrxml2jasper.sh"
    allow_failure: true

build:
    image: docker:latest
    stage: Build
    script:
        - docker login -u gitlab-ci-token -p ${CI_BUILD_TOKEN} ${CI_REGISTRY}
        - docker build -t ${CONTAINER_IMAGE} .
        - docker tag ${CONTAINER_IMAGE} ${CONTAINER_IMAGE_COMMIT}
        - docker push ${CONTAINER_IMAGE_COMMIT}

stages:
    - Build
    - develop
    - test
    - review
    - acceptance
    - productive

variables:
    CONTAINER_IMAGE: ${CI_REGISTRY}/${CI_PROJECT_PATH}:${CI_BUILD_REF_NAME}_${CI_BUILD_REF}
    CONTAINER_IMAGE_COMMIT: ${CI_REGISTRY}/${CI_PROJECT_PATH}:${CI_COMMIT_SHORT_SHA}

services:
    -   name: docker:18.09.7-dind
        command: [ "--experimental", "--insecure-registry=gitlab.cx9.info:4567" ]

deploy-review:
    stage: review
    image: ${CONTAINER_IMAGE_COMMIT}
    variables: 
        SSH_USER: "cx9"
        SSH_HOST: "192.168.254.237"
        SSH_PORT: "22"
        CRENT_version: "'+@mandant1version+'"
        CRW_CONFIG: "'+dbo.GET_CRWJASPERCONFIG_BY_MANDANT_ID (@MANDANT_ID,'config')+'"
        CRW_DB_CONFIG: "'+dbo.GET_CRWJASPERCONFIG_BY_MANDANT_ID(@MANDANT_ID,'db')+'"

    script:
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "echo ''Deploying JASPER Ausdrucke in der C-Rent version $CRENT_version''"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "sudo rm -rf /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "git clone git@192.168.254.232:web/CRENTWEB_DEV /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "mkdir -p /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG/print"
        - rsync -q -O -rav -e ssh --exclude=''.git/'' --exclude=''.gitlab-ci.yml'' --exclude=''cache/'' --exclude=''.sass-cache/'' --exclude=''node_modules/'' --exclude=''tests/'' --exclude=''gl-code-quality-report.json'' --delete-excluded ./ $SSH_USER@$SSH_HOST:/var/www/review/crentweb_$CI_ENVIRONMENT_SLUG/print
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "echo $CRW_CONFIG | xxd -r -p > /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG/config/config.inc.php"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "echo $CRW_DB_CONFIG | xxd -r -p > /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG/config/config_db.inc.php"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "cd /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG/tools && sh ./jrxml2jasper.sh && sh ./yuicompressor.sh"
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "cd /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG && mkdir -p sign/image_handler/signed && mkdir -p sign/image_handler/tempImages && mkdir -p sign/tempImages && mkdir -p sign/xmlFiles && mkdir -p COCI/images/downloads && mkdir -p COCI/classes/uploadedPhotos/damages && mv js js.orig && mv js.min js && mv css css.orig && mv css.min css && mv _.htaccess .htaccess && mv config/_.htaccess config/.htaccess && sudo chmod -R 775 . && sudo chown -R cx9:www-data ."

    environment:
        name: review/$CI_COMMIT_REF_NAME
        url: http://192.168.254.237/review/crentweb_$CI_ENVIRONMENT_SLUG
        on_stop: stop-review
    only:
        - branches
    except:
        - /^master.*$/
        - develop
        - /^release-.*$/
        - '+@jasperBranchName+'

stop-review:
    stage: review
    image: ${CONTAINER_IMAGE_COMMIT}
    variables:
        GIT_STRATEGY: none
        SSH_USER: "cx9"
        SSH_HOST: "192.168.254.237"
        SSH_PORT: "22"
    script:
        - ssh -o StrictHostKeyChecking=no -p$SSH_PORT $SSH_USER@$SSH_HOST "sudo rm -rf /var/www/review/crentweb_$CI_ENVIRONMENT_SLUG"
    when: manual
    environment:
        name: review/$CI_COMMIT_REF_NAME
        action: stop
    only:
        - branches
    except:
        - /^master.*$/
        - develop
        - /^release-.*$/
        - '+@jasperBranchName+'

'+dbo.GET_CRWJASPER_DEPLOYMENT_ENVIRONMENTS(@MANDANT_ID,'.deploy-jasper')
	RETURN @result
END
GO
