/****** Object:  UserDefinedFunction [dbo].[GET_MANDANT_UPDATE_FIELD]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_MANDANT_UPDATE_FIELD](@MANDANT_ID INT = NULL, @field VARCHAR(128) = '')
RETURNS VARCHAR(255)
AS --Author José
BEGIN 
	DECLARE @result VARCHAR(2048) = ''
	IF (@field = 'Kundenbetreuer')
		SET @result = ISNULL((SELECT TOP 1 betreuer FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId=@MANDANT_ID),'')
	IF (@field = 'fromversion')
		SET @result = ISNULL((SELECT TOP 1 fromversion FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId=@MANDANT_ID),'')
	IF (@field = 'MRCRWNUMMER1')
		BEGIN
			SET @result = ISNULL((SELECT TOP 1 dbo.EXTRACT_MR_FROM_LOGS(CRWEB_MR_APPROVED_LOG, DEFAULT, ' wurde gemerged') FROM dbo.WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID=@MANDANT_ID AND ENVIRONMENT ='ACC'),'')
			SET @result = SUBSTRING(@result,dbo.LastIndexOf(@result,'/')+2,LEN(@result))			
		END
	IF (@field = 'MRCRWNUMMER2')
		BEGIN
			SET @result = ISNULL((SELECT TOP 1 dbo.EXTRACT_MR_FROM_LOGS(CRWEB_MR_APPROVED_LOG, DEFAULT, ' wurde gemerged') FROM dbo.WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID=@MANDANT_ID AND ENVIRONMENT = 'LIVE'),'')
			SET @result = SUBSTRING(@result,dbo.LastIndexOf(@result,'/')+2,LEN(@result))			
		END
	IF (@field = 'MRJASPERNUMMER')
		BEGIN
			SET @result = ISNULL((SELECT TOP 1 dbo.EXTRACT_MR_FROM_LOGS(JASPER_MR_APPROVED_LOG, DEFAULT, ' wurde gemerged') FROM dbo.WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID=@MANDANT_ID),'')		
			SET @result = SUBSTRING(@result,dbo.LastIndexOf(@result,'/')+2,LEN(@result))			
		END
	IF (@field = 'JASPERBRANCHNAME')
		SET @result = dbo.GET_MANDANT_JASPER_DEPLOYMENT_NAME(@MANDANT_ID)
	IF (@field = 'AbasId')
		BEGIN
			SET @result = ISNULL((SELECT abasId FROM dbo.Mandant WHERE id=@MANDANT_ID),0)	
			IF(@result = '0')
				SET @result = '' 
		END
	IF (@field = 'MainCRWBranch')
		BEGIN
			SET @result = ISNULL((SELECT TOP 1 MainCRWBranch FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId=@MANDANT_ID),'master')	
		END  
	RETURN @result 
END
GO
