/****** Object:  UserDefinedFunction [dbo].[GET_PRE_CRENT_UPDATE6_SQLSCRIPTS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_PRE_CRENT_UPDATE6_SQLSCRIPTS](@mandant_id INT = NULL)
RETURNS NVARCHAR(MAX) --Author José
BEGIN  --Diese Skripte werden vor einem Update 6.0 einmalig ausgeführt
	DECLARE @version VARCHAR(128) = '5.09', @SQL NVARCHAR(MAX) = 
'DECLARE @CRENTversion NVARCHAR(MAX) = CAST (ISNULL((SELECT TOP 1 version FROM dbo.version),'''')  AS NVARCHAR(MAX))
PRINT @CRENTversion
PRINT ''SELECT * FROM systypes WHERE name=''''STATION_LIST''''''
IF (NOT(EXISTS (SELECT 1 FROM systypes WHERE name=''STATION_LIST'')))
	CREATE TYPE STATION_LIST AS TABLE (Station VARCHAR(30))
------ Bugfixes ab version 6.21.4.10
IF (EXISTS (SELECT * FROM INFORMATION_SCHEMA.TABLES  WHERE TABLE_SCHEMA = ''dbo'' AND  TABLE_NAME = ''PAYMENT_CONCARDIS_LOG''))
	Drop Table dbo.PAYMENT_CONCARDIS_LOG
UPDATE dbo.fieldactions SET Component =''cxDBStationAb''  WHERE Component = ''Editcodevstatan'' AND InitialVal = ''$Table1.vermietstation''
UPDATE dbo.fieldactions SET Component =''cxDBStationan''  WHERE Component = ''DBEdit5'' AND InitialVal = ''$table1.codevstatan''
------
SELECT * FROM systypes WHERE name=''STATION_LIST''
IF (ISNULL(@CRENTversion,'''') <> ''''  AND ISNUMERIC(@CRENTversion) = 1)  
	BEGIN
		DECLARE @clientversionFloat FLOAT 
	    SET  @clientversionFloat  = CAST(REPLACE(@CRENTversion,'','',''.'') AS FLOAT)
		IF (@clientversionFloat IN (5.07,5.08,5.09))
			BEGIN  
				IF NOT EXISTS(SELECT * FROM sys.columns WHERE object_id = OBJECT_ID(N''[dbo].[RECH_RATEN_ZUS]'') AND name = ''Rate'')
					ALTER TABLE dbo.RECH_RATEN_ZUS ADD Rate VARCHAR(255) NULL
 
				IF NOT EXISTS(SELECT * FROM sys.columns WHERE object_id = OBJECT_ID(N''[dbo].[RECH_RATEN_ZUS]'') AND name = ''Gruppe'')
					ALTER TABLE dbo.RECH_RATEN_ZUS ADD Gruppe VARCHAR(30) NULL

				IF NOT EXISTS(SELECT * FROM sys.columns WHERE object_id = OBJECT_ID(N''[dbo].[RECH_RATEN_ZUS]'') AND name = ''PREIS_ABW'')
					ALTER TABLE dbo.RECH_RATEN_ZUS ADD PREIS_ABW BIT NULL 
  
				IF ((SELECT COUNT(*) FROM sys.columns WHERE object_id = OBJECT_ID(N''[dbo].[RECH_RATEN_ZUS]'') AND name IN ( ''Gruppe'',''Rate'')) = 2)
					BEGIN
						EXEC (''UPDATE RECH_RATEN_ZUS SET 
							Rate = ISNULL((SELECT TOP 1 ISNULL(rate,'''''''') FROM dbo.RECH_RATEN WHERE PK=PKRate AND ISNULL(Rate,'''''''')<>''''''''),ZusRate),
							Gruppe = ISNULL((SELECT TOP 1 ISNULL(Grp,'''''''') FROM dbo.RECH_RATEN WHERE PK=PKRate AND ISNULL(Rate,'''''''')<>'''''''' ),''''*'''') 
						  '')			    
					END 
			END 
    END 
'+CHAR(13) 
 
	RETURN @SQL
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_PRE_POST_CRENT_SQLSCRIPTS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_PRE_POST_CRENT_SQLSCRIPTS](@version VARCHAR(128) = '5.09')
RETURNS NVARCHAR(max)
BEGIN -- Diese Skripte werden im Deployment 6.0 ausgeführt
	DECLARE @SQL_1 NVARCHAR(max) = 
'UPDATE abfragen SET query = ''EXEC [dbo].[Mietvertraege_die_laenger_als_X_Tage_laufen] :dateVon,:dateBis,:inteTage,:''''boolmit Transferfahrten'''',:striVermietstation'' WHERE nummer = 84
EXEC dbo.LANG_ADD_COMPONENT @comp=''Kassenbuch.popup.title'',@text=N''Einzahlung buchen'',@lang=''DE'', @update = 1'
	DECLARE @SQL_CCHEQ NVARCHAR(MAX) = '
declare @minpk int
--''C-Cheq''
if (Exists(select * from module where modul = ''C-Cheq'' and enabled = ''J''))
begin
  select @minpk = MIN(PK) from module where Modul = ''C-Cheq'' and enabled =''J''
  delete from module where Modul = ''C-Cheq'' and PK <> @minpk
end
else
  begin
    select @minpk = MIN(PK) from module where Modul = ''C-Cheq''
    delete from module where Modul = ''C-Cheq'' and PK <> @minpk
  end
--''C-Cheq-Dealer''
if (Exists(select * from module where modul = ''C-Cheq-Dealer'' and enabled =''J''))
begin
  select @minpk = MIN(PK) from module where Modul = ''C-Cheq-Dealer'' and enabled =''J''
  delete from module where Modul = ''C-Cheq-Dealer'' and PK <> @minpk
end
else
  begin
    select @minpk = MIN(PK) from module where Modul = ''C-Cheq-Dealer''
    delete from module where Modul = ''C-Cheq-Dealer'' and PK <> @minpk
  end
--''C-Share''
if (Exists(select * from module where modul = ''C-Share'' and enabled =''J''))
begin
  select @minpk = MIN(PK) from module where Modul = ''C-Share'' and enabled =''J''
  delete from module where Modul = ''C-Share'' and PK <> @minpk
end
else
  begin
    select @minpk = MIN(PK) from module where Modul = ''C-Share''
    delete from module where Modul = ''C-Share'' and PK <> @minpk
  end
'
	DECLARE @SQL NVARCHAR(max) = 
'
DECLARE @pkprintdok INT
Declare @MaxPKPrintMenuDok int
DECLARE #PMCursor CURSOR FOR SELECT pk FROM dbo.PRINT_DOKUMENTE WHERE BESCHREIBUNG IN (''Anschr. Anwalt'',''Anschr. Mobi.'',''Anschr. Unf. Kd.'',''Anschr. Vers.'')
OPEN #PMCursor

FETCH NEXT FROM #PMCursor INTO @pkprintdok
WHILE ( @@FETCH_STATUS=0)
BEGIN
  IF NOT(EXISTS(SELECT * FROM dbo.PRINT_MENU_DOKUMENTE WHERE PK_PRINT_DOKUMENTE = @pkprintdok AND MENU=''UE_EINZ''))
    begin
      SELECT @MaxPKPrintMenuDok = MAX(ISNULL(pk,0))+1 FROM dbo.PRINT_MENU_DOKUMENTE
      INSERT INTO dbo.PRINT_MENU_DOKUMENTE SELECT @MaxPKPrintMenuDok,''UE_EINZ'',@pkprintdok
    END
FETCH NEXT FROM #PMCursor INTO @pkprintdok
END
DEALLOCATE #PMCursor

IF NOT(EXISTS(SELECT * FROM dbo.PRINT_MENU_DOKUMENTE WHERE MENU = ''RECHNUNGSLAUF_Mail''))
  begin
  INSERT INTO dbo.PRINT_MENU_DOKUMENTE
  (PK,MENU,PK_PRINT_DOKUMENTE)  VALUES
  (   (SELECT ISNULL(MAX(pk),0)+1 FROM dbo.PRINT_MENU_DOKUMENTE),  -- PK - int
      ''RECHNUNGSLAUF_Mail'', -- MENU - varchar(50)
      (SELECT TOP 1 pk FROM dbo.PRINT_DOKUMENTE WHERE BESCHREIBUNG = ''Standardrechnung (Rechlauf)'')  -- PK_PRINT_DOKUMENTE - int
      )
  END

DECLARE @clientversion VARCHAR(16)= ISNULL((SELECT TOP 1 version FROM dbo.version),'''')
DECLARE @clientversionFloat FLOAT --= CAST()
IF (@clientversion<>'''')
	BEGIN
	    SET  @clientversionFloat  = CAST(REPLACE(@clientversion,'','',''.'') AS FLOAT)
		IF (@clientversionFloat <= 5.12)
			BEGIN
			  EXEC dbo.copy_table_with_new_vals @PKAutoInc = 1, @field = ''Aktion'', @Table = ''fieldactions'', 
			  @oldval = ''STANDARD_MV'', @newVal = ''STANDARD_RES_MV'' -- varchar(255)  
			END
	END
DECLARE @mandantName VARCHAR(1024)= ISNULL((SELECT TOP 1 MandantName FROM dbo.MAND_GLOBAL),'''')
IF (@mandantName<>''BERESA GmbH'')
	BEGIN 
		DELETE FROM farben where code LIKE ''CCOCI_%'' OR code LIKE ''CCHEQ_%'' OR code LIKE ''CSAPP_%'' 
	END
IF (@mandantName=''BERESA GmbH'')
	BEGIN 
		DISABLE TRIGGER ALL ON dbo.AUTOS;
	END
DELETE FROM lang_texte WHERE TEXTBAUSTEIN IN (SELECT lc.textbaustein FROM dbo.LANG_COMPONETS lc WHERE lc.component LIKE ''CSHARE.TFRM%'')
DELETE FROM lang_texte WHERE TEXTBAUSTEIN IN (SELECT lc.textbaustein FROM dbo.LANG_COMPONETS lc WHERE lc.component LIKE ''CCOCI.TFRM%'')
DELETE FROM lang_texte WHERE TEXTBAUSTEIN IN (SELECT lc.textbaustein FROM dbo.LANG_COMPONETS lc WHERE lc.component LIKE ''CCD.TFRM%'')
Delete FROM dbo.LANG_COMPONETS WHERE component LIKE ''CSHARE.TFRM%''
DELETE FROM dbo.LANG_COMPONETS WHERE component LIKE ''CCOCI.TFRM%''
DELETE FROM dbo.LANG_COMPONETS WHERE component LIKE ''CCD.TFRM%''

EXEC dbo.LANG_ADD_COMPONENT @comp = ''crent.fahrzzwei.TSMobile.caption'',  @text = N''Fahrzeugbilder'',  @lang = ''DE'',  @update = 1 -- bit
EXEC dbo.LANG_ADD_COMPONENT @comp = ''crent.fahrzzwei.TSMobile.caption'',   @text = N''Images véhicule'', @lang = ''FR'', @update = 1 -- bit
EXEC dbo.LANG_ADD_COMPONENT @comp = ''crent.fahrzzwei.TSMobile.caption'', @text = N''Vehicle Images'', @lang = ''US'',  @update = 1 -- bit
EXEC dbo.LANG_REFRESH_SEARCH_INDEX

UPDATE params SET beschreibung = ''Länge der Sachkonten in Datev (4 bzw. 6)'' WHERE param = ''SDATEV_LAENGE_SACHKONTEN''
UPDATE params SET beschreibung = ''Länge der Personenkonten in Datev (5 bzw. 7)'' WHERE param = ''SDATEV_LAENGE_PERSONENKONTEN''

UPDATE PRINT_MENU_DOKUMENTE SET menu = ''DISPO_RESERVIERUNG'' WHERE menu = ''DISPO''

IF (NOT(EXISTS(SELECT pk_print_dokumente FROM dbo.PRINT_MENU_DOKUMENTE WHERE menu=''ABSCHLAGSRELAUF'')))
  INSERT INTO dbo.PRINT_MENU_DOKUMENTE (pk,menu,PK_PRINT_DOKUMENTE) 
    SELECT (SELECT ISNULL(MAX(pk)+1,1) FROM dbo.PRINT_MENU_DOKUMENTE), ''ABSCHLAGSRELAUF'',
	(SELECT TOP 1 PK FROM dbo.PRINT_DOKUMENTE WHERE Beschreibung = ''Standardrechnung'')

UPDATE module SET modul=''C-Share'' WHERE modul=''CARSHARING''
UPDATE module SET modul=''C-Cheq-Dealer'' WHERE modul=''CCheqDealer''
UPDATE module SET modul=''C-Cheq'' WHERE modul = ''CCheq''

UPDATE params SET wert = ''support@cx9.de'' WHERE param = ''SMAIL_CX9_SUPPORT''
'+
CHAR(13)+@SQL_1+char(13)+@SQL_CCHEQ
+CHAR(13)+ dbo.GET_Deployment_version_TSQLCODE(DEFAULT)

	 
	
	RETURN @SQL
END
GO
