CREATE FUNCTION [dbo].[GET_RESTORE_PATCHES](@MandantId INT = NULL, @dbName VARCHAR(128))
RETURNS NVARCHAR(MAX)
BEGIN

DECLARE @abasID VARCHAR(128) = CAST((SELECT TOP 1 abasId FROM dbo.Mandant WHERE id = @MandantId) AS VARCHAR(128))
DECLARE @documentRoot VARCHAR(128) = ISNULL(CAST((SELECT TOP 1 documentRoot FROM dbo.Mandant WHERE id = @MandantId) AS VARCHAR(128)),'no_crw_install')
DECLARE @AbasIDPlusOtherUpdateCommands VARCHAR(MAX)=''
DECLARE @mandant_db VARCHAR(255) = REPLACE(ISNULL((SELECT databaseName FROM dbo.Mandant WHERE id=@MandantId),'_NODB'),'ACC_','')
IF (ISNULL(@MandantId,0) = 0 OR ISNULL(@dbName,'')='')
	RETURN ''
IF (@abasID <> '' AND @abasID IS NOT NULL)
	SET @AbasIDPlusOtherUpdateCommands = '
USE ['+@dbName+'];
IF EXISTS (SELECT * FROM sys.columns WHERE object_id=OBJECT_ID(''[dbo].[MAND_GLOBAL]'') AND name=''AbasId'') 
	EXEC (''IF (SELECT TOP 1 abasID FROM dbo.MAND_GLOBAL) IS NULL
				UPDATE dbo.MAND_GLOBAL SET abasID = '+@abasID+''')
	'
	SET @AbasIDPlusOtherUpdateCommands+='
USE ['+@dbName+'];

UPDATE dbo.MAND_GLOBAL SET Logo = 
UPDATE dbo.module SET enabled=''J'' WHERE Modul IN (''CRENTWEB'')
UPDATE dbo.PRINT_DOKUMENTE SET PARAMPROC = REPLACE(CAST(PARAMPROC AS NVARCHAR(MAX)),''kunden2.cx9.de/'+@documentRoot+'/crentweb'',''kunden2.cx9.de/'+@documentRoot+'/crentweb_test'') WHERE PARAMPROC IS NOT NULL AND ISNULL(CHARINDEX(CAST(PARAMPROC AS NVARCHAR(MAX)),''crentweb_test''),-1) = 0
UPDATE dbo.PRINT_DOKUMENTE SET PARAMPROC = REPLACE(CAST(PARAMPROC AS NVARCHAR(MAX)),'''+@documentRoot+'.crentweb.de'',''kunden2.cx9.de/'+@documentRoot+'/crentweb_test'') WHERE PARAMPROC IS NOT NULL AND ISNULL(CHARINDEX(CAST(PARAMPROC AS NVARCHAR(MAX)),''crentweb_test''),-1)=0
UPDATE dbo.PARAMS SET Wert = ''https://kunden2.cx9.de/'+@documentRoot+'/crentweb_test/classes/PUniversell.php'' WHERE Param = ''SJASPER_URL''
 
	'
	DECLARE @BATSQLINSTRUCTIONS NVARCHAR(MAX) = @AbasIDPlusOtherUpdateCommands +
'
DECLARE @clientversion VARCHAR(16)= ISNULL((SELECT TOP 1 version FROM dbo.version),'''')
DECLARE @clientversionFloat FLOAT --= CAST()
IF (@clientversion<>'''')
	BEGIN
	    SET  @clientversionFloat  = CAST(REPLACE(@clientversion,'','',''.'') AS FLOAT)
		IF (@clientversionFloat <= 5.12)
			BEGIN
			  EXEC dbo.copy_table_with_new_vals @PKAutoInc = 1, @field = ''Aktion'', @Table = ''fieldactions'', 
			  @oldval = ''STANDARD_MV'', @newVal = ''STANDARD_RES_MV'' -- varchar(255)  
			END
	END
	'
	RETURN @BATSQLINSTRUCTIONS
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_SEARCH_XML_MANDANT_DB_ENVIRONMENT]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_SEARCH_XML_MANDANT_DB_ENVIRONMENT](@terms VARCHAR(MAX) = '', @type VARCHAR(128) = 'search')
RETURNS @TABLE TABLE(TABID NVARCHAR(128) NULL, TABLABEL NVARCHAR(1024) NULL, TABCONTENTS NVARCHAR(MAX) NULL , TABSELECTED BIT NULL )  --Author José.-
BEGIN
	DECLARE @MANDANT_ID INT 
	DECLARE @MANDANT_ENVIRONTMENT_PK INT 
	IF (@type = 'search')
		BEGIN
			DECLARE @kdnUmgebungen VARCHAR(128) = CAST ( ISNULL((SELECT COUNT(*) FROM dbo.SEARCH_MANDANT_DB_ENVIRONMENT(@terms)),0) AS VARCHAR(128))  
			INSERT INTO @TABLE ( TABID, TABLABEL, TABCONTENTS, TABSELECTED )
				SELECT 'workspace_client_environments','Kunden Umgebungen ('+@kdnUmgebungen+')', dbo.SEARCH_UPDATE_XML_ENVIRONMENTS(@terms) , 1
			INSERT INTO @TABLE ( TABID, TABLABEL, TABCONTENTS, TABSELECTED )
				SELECT 'workspace_cx9_day','CX9 TAG', dbo.GET_UPDATE_XML_SPECIAL_MANDANT_BY_EVIRONMENT_PK(1, 'Haupt - CX9 Systems GmbH') ,0
			INSERT INTO @TABLE ( TABID, TABLABEL, TABCONTENTS, TABSELECTED )
				SELECT 'workspace_starcar_day','Starcar Tag', dbo.GET_UPDATE_XML_SPECIAL_MANDANT_BY_EVIRONMENT_PK(593, 'Starcar'),0 	

			IF (EXISTS(SELECT MANDANT_Id,MANDANT_ENVIRONTMENT_PK FROM dbo.SEARCH_MANDANT_DB_ENVIRONMENT(@terms)))
				BEGIN
					DECLARE @tab TABLE (MANDANT_ID INT NULL, MANDANT_ENVIRONTMENT_PK INT NULL)  
						INSERT INTO @tab
							SELECT  MANDANT_Id, MANDANT_ENVIRONTMENT_PK FROM dbo.SEARCH_MANDANT_DB_ENVIRONMENT(@terms)            
					DECLARE environment_win_tab CURSOR  
						FOR SELECT TOP 4 MANDANT_Id,MANDANT_ENVIRONTMENT_PK FROM dbo.SEARCH_MANDANT_DB_ENVIRONMENT(@terms) WHERE MANDANT_ID IN (SELECT DISTINCT MANDANT_Id FROM dbo.SEARCH_MANDANT_DB_ENVIRONMENT(@terms))
					OPEN environment_win_tab  
					FETCH NEXT FROM environment_win_tab INTO @MANDANT_Id,@MANDANT_ENVIRONTMENT_PK
  
					WHILE @@FETCH_STATUS = 0  
					BEGIN  
						INSERT INTO @TABLE ( TABID, TABLABEL, TABCONTENTS, TABSELECTED )
							SELECT 'workspace_'+CAST(@MANDANT_ENVIRONTMENT_PK AS VARCHAR(32)),SUBSTRING(dbo.GET_MANDANT_NAME(@MANDANT_Id),1,10)+'.. det', dbo.GET_UPDATE_XML_ENVIRONMENT_BY_PK(@MANDANT_ENVIRONTMENT_PK),0 
						DELETE FROM @tab WHERE MANDANT_ENVIRONTMENT_PK = @MANDANT_ENVIRONTMENT_PK 
						IF NOT EXISTS(SELECT * FROM @tab WHERE MANDANT_ID = @MANDANT_Id) 
							BEGIN
								INSERT INTO @TABLE ( TABID, TABLABEL, TABCONTENTS, TABSELECTED )
									SELECT 'environment_shortcuts'+CAST(@MANDANT_ENVIRONTMENT_PK AS VARCHAR(32)),SUBSTRING(dbo.GET_MANDANT_NAME(@MANDANT_Id),1,10)+'.. shor', dbo.GET_UPDATE_XML_MANDANT_BY_ENVIRONMENT_PK(@MANDANT_ENVIRONTMENT_PK) ,0										
							END

						FETCH NEXT FROM environment_win_tab	INTO @MANDANT_Id,@MANDANT_ENVIRONTMENT_PK
					END   
					CLOSE environment_win_tab;  
					DEALLOCATE environment_win_tab;  					
				END
			
							
		END
	IF (@type = 'open_environment')
		BEGIN
			INSERT INTO @TABLE ( TABID, TABLABEL, TABCONTENTS, TABSELECTED )
				SELECT 'environment_details','Details', dbo.GET_UPDATE_XML_ENVIRONMENT_BY_PK(@terms) , 1
			INSERT INTO @TABLE ( TABID, TABLABEL, TABCONTENTS, TABSELECTED )
				SELECT 'environment_shortcuts','Shortcuts', dbo.GET_UPDATE_XML_MANDANT_BY_ENVIRONMENT_PK(@terms) ,0
 		
		END        
		
	/*DECLARE @i INT = 1
	WHILE (@i<15)
		BEGIN
			INSERT INTO @TABLE ( TABID, TABLABEL, TABCONTENTS, TABSELECTED )
				SELECT 'workspace_starcar_day_'+CAST(@i AS VARCHAR(3)),'Starcar Tag '+CAST(@i AS VARCHAR(3)), dbo.GET_UPDATE_XML_MANDANT_BY_ENVIRONMENT_PK(593),0 	
			SET @i+=1		
		END*/

	RETURN 
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_SERVER_PARAMS_FROM_STRING]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_SERVER_PARAMS_FROM_STRING] (@RAWDATA VARCHAR(MAX) = '')
RETURNS @DBCredentials TABLE(HOST VARCHAR(128) NULL, INSTANCE VARCHAR(255) NULL, PORT VARCHAR(16) NULL,
						RAWDATA VARCHAR(1024) NULL)  
						--@HOST,@INSTANCE,@PORT
BEGIN 
		 
		DECLARE @HOST VARCHAR(255) = ''
		DECLARE @INSTANCE VARCHAR(255) = '' 
		DECLARE @PORT VARCHAR(15) = NULL 
       IF ( (@RAWDATA <> '') )
			BEGIN        
 
					BEGIN    
						--192.168.253.209,1433\CRENT -- nicht klar
						--192.168.253.209\CRENT,1433
						--SET @HOST = ISNULL(@XMLCompareData.value('(/Project/DataSource2/ServerName/text())[1]', 'NVARCHAR(128)'),'')
						SET @HOST = REPLACE(@RAWDATA,'/','\') --Tippfehler in DB XML Compare
						/*SET @HOST = '192.168.253.209\CRENT,1433'
						SET @HOST = '192.168.253.209,1433'
						SET @HOST = '192.168.253.209\CRENT'*/
						SET @RAWDATA = @HOST 
						DECLARE @InstanceIndexLimitator INT = dbo.LastIndexOf(@HOST,'\')
						DECLARE @portIndexLimitatorPort INT = dbo.LastIndexOf(@HOST,',')
						DECLARE @HOSTlenght INT =  LEN(@host)
 
 
						IF (@InstanceIndexLimitator = @HOSTlenght AND @portIndexLimitatorPort <> @HOSTlenght) --there are port and db
							BEGIN						
								SELECT
								 @PORT = SUBSTRING(@HOST,@portIndexLimitatorPort+2,16),
								 @HOST = SUBSTRING(@HOST,1,@portIndexLimitatorPort)
								 IF (ISNUMERIC(@PORT) = 0)
									SET @PORT = NULL
							END	
						IF (@InstanceIndexLimitator <> @HOSTlenght AND @portIndexLimitatorPort = @HOSTlenght)
							BEGIN						
								SELECT @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitator+2,LEN(@HOST))
								, @HOST = SUBSTRING(@HOST,1,@InstanceIndexLimitator)--hier für den Port doof
							END	
						IF (@InstanceIndexLimitator <> @HOSTlenght AND @portIndexLimitatorPort <> @HOSTlenght)
							BEGIN						--@HOST = '192.168.253.209\CRENT,1433'
								SELECT  @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitator+2,LEN(@HOST)-CHARINDEX(',',@HOST)+1)
								, @PORT = SUBSTRING(@HOST,CHARINDEX(',',@HOST)+1,LEN(@HOST)-CHARINDEX(',',@HOST)+1)
								, @HOST =  SUBSTRING(@HOST,1,@InstanceIndexLimitator)--hier für den Port doof

								--SELECT SUBSTRING(@HOST,@pos+1,LEN(@HOST)-@pos+1)
							END-- SELECT CHARINDEX(',', '192.168.253.209\CRENT,1433')
						INSERT INTO @DBCredentials--(HOST,INSTANCE,PORT,DB,DB_USER,DB_USER_PW)
						     SELECT @HOST,@INSTANCE,@PORT,@RAWDATA
						 		
					END  				
			END 		


	RETURN  
END
GO
