CREATE FUNCTION [dbo].[GET_SH_ESCAPED_PWD] (@input VARCHAR(MAX))
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @result NVARCHAR(MAX)
    SET @result =
 
		/*REPLACE(
			REPLACE( 
				REPLACE(
					REPLACE(
						REPLACE(
							REPLACE(*/
								REPLACE(@input,'$', 'DOLLER_SIGN_CX9')
							/*,'&', '^^&')
						,'>', '^^>')
					,'<', '^^<')
				,'|', '^^|')
			,'\','^^\')
		,'!','^^!')*/
 
RETURN @result
