/****** Object:  UserDefinedFunction [dbo].[GET_TABLE_FROM_LIST_DELIM]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_TABLE_FROM_LIST_DELIM] (@list varchar(MAX),@delimiter VARCHAR(1)=';')
   RETURNS @tbl TABLE (Aval NVARCHAR(255) NOT NULL) AS
BEGIN
   DECLARE @pos        int,
           @nextpos    int,
           @valuelen   int

   IF( (@delimiter IS NULL) OR (@delimiter = '') )
		SET @delimiter=';'

   SELECT @pos = 0, @nextpos = 1

   WHILE @nextpos > 0
   BEGIN
      SELECT @nextpos = charindex(@delimiter, @list, @pos + 1)
      SELECT @valuelen = CASE WHEN @nextpos > 0
                              THEN @nextpos
                              ELSE len(@list) + 1
                         END - @pos - 1
      if (not substring(@list, @pos + 1, @valuelen) is null)
        INSERT @tbl (AVal)
           VALUES (substring(@list, @pos + 1, @valuelen))
        SELECT @pos = @nextpos
   END
  RETURN
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_TEST_NICOLAS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE function [dbo].[GET_TEST_NICOLAS](@MandantID int = 441,@NumberOfUsers int = 11)
returns VARCHAR(16) 
BEGIN
-- vielleicht eine Funktion oder so die man aufruft mit der Mandant ID und der Menge der Users? 
 
declare @result varchar(16)
-- Keine Änderungen nach hier, MandantID + Menge der User muss reichen, rest muss sich "selbst befüllen"
DECLARE @MandantGlobName AS VARCHAR(17)
DECLARE @tsUsersName AS VARCHAR(20)
DECLARE @tsUsersNextName AS VARCHAR(20)
DECLARE @NameSpacer AS VARCHAR(2) = '_0'
DECLARE @tsUsersNextNumber AS int

--SELECT * FROM [BETHUNDER_JL].[dbo].[Mandant] WHERE [Mandant].id = @MandantID

SELECT TOP 1 @MandantGlobName=globalName FROM [BETHUNDER_JL].[dbo].[Mandant] WHERE [Mandant].id = @MandantID

--SELECT * FROM [BETHUNDER_JL].[dbo].[TSUsers] WHERE [BETHUNDER_JL].[dbo].[TSUsers].[customer_id] = @MandantID AND [BETHUNDER_JL].[dbo].[TSUsers].[NAME] LIKE @MandantGlobName+'%' order by NAME desc

IF EXISTS (SELECT * from [BETHUNDER_JL].[dbo].[TSUsers] WHERE [BETHUNDER_JL].[dbo].[TSUsers].[customer_id] = @MandantID AND [BETHUNDER_JL].[dbo].[TSUsers].[NAME] LIKE @MandantGlobName+'%')
	BEGIN
		SELECT TOP 1 @tsUsersName=[NAME]  from [BETHUNDER_JL].[dbo].[TSUsers] WHERE [BETHUNDER_JL].[dbo].[TSUsers].[customer_id] = @MandantID AND [BETHUNDER_JL].[dbo].[TSUsers].[NAME] LIKE @MandantGlobName+'%' order by [NAME] desc
		--SELECT CAST(RIGHT(@tsUsersName,2) as int )
		SET @tsUsersNextNumber = CAST(RIGHT(@tsUsersName,2) as int )+1
	END
ELSE
	BEGIN 
		SET @tsUsersNextNumber = 1 
	END 

DECLARE @i INT = 0

WHILE (@i < @NumberOfUsers)
	BEGIN 
		IF (@tsUsersNextNumber > 9) SET @NameSpacer = '_' 
		SET @tsUsersNextName = @MandantGlobName+@NameSpacer+CAST(@tsUsersNextNumber as varchar)
		--PRINT @tsUsersNextName
		SET @tsUsersNextNumber = @tsUsersNextNumber + 1 
		SET @i = @i + 1 
	END
return @tsUsersNextName
END
GO
