CREATE FUNCTION [dbo].[GET_TS_USERS] (@mandantID INT = NULL)
RETURNS VARCHAR(MAX)  
BEGIN  --Autor José  
	DECLARE @table_users_result VARCHAR(MAX)
	DECLARE @table_users_th VARCHAR(MAX) = ISNULL((STUFF((SELECT  	 
		(SELECT 'Benutzername' AS '*' FOR XML PATH('th'), TYPE),
        (SELECT 'Passwort' AS '*' FOR XML PATH('th'), TYPE)
	FOR XML PATH('tr')),1,0,'')), '') 
	SET @table_users_result = '' 
	SELECT @table_users_result = ISNULL((STUFF((SELECT  	 
		(SELECT ISNULL(NAME,'') AS '*' FOR XML PATH('td'), TYPE),
        (SELECT ISNULL(InitialPass,'') AS '*' FOR XML PATH('td'), TYPE)
		FROM dbo.TSUsers WHERE customer_id = @mandantID
	FOR XML PATH('tr')),1,0,'')), '') -- Be sure with is null that query returns a empty string 
	IF (@table_users_result = '')
		SET @table_users_result = '<tr><td>keine_Benutzer_gefunden.</td><td>ist es nur in C-Rent Web Kunden?</td></tr>'
	SET @table_users_result = '<table style="border:1px solid;">'+@table_users_th + @table_users_result +'</table>'
	RETURN @table_users_result 
END

