/****** Object:  UserDefinedFunction [dbo].[GET_UPDATE_LOG_ERRORS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_UPDATE_LOG_ERRORS] (@xmlInputLog XML = NULL,@errorPatern VARCHAR(MAX)='Meldung ;Falsche Syntax;SQL Server',@errorPaternSep VARCHAR(1)=';')
RETURNS VARCHAR(MAX)
BEGIN
	IF (@xmlInputLog IS NULL)
		RETURN 'Invalid Log format'
	DECLARE @path VARCHAR(128)=ISNULL(@xmlInputLog.value('local-name(/*[1])','NVARCHAR(128)'),'')
	DECLARE @errorMessages VARCHAR(MAX)=''
	DECLARE @logMessage VARCHAR(MAX)=''
	DECLARE @logType VARCHAR(128)=''
	DECLARE @compareType VARCHAR(128)=ISNULL(@xmlInputLog.value('(/*[local-name()=sql:variable("@path")]/@type)[1]','NVARCHAR(128)'),'')
	DECLARE @compareEnvironemnt VARCHAR(128)=ISNULL(@xmlInputLog.value('(/*[local-name()=sql:variable("@path")]/@environment)[1]','NVARCHAR(128)'),'')
	WHILE (SELECT @xmlInputLog.exist('(/*[local-name()=sql:variable("@path")]/logs/log)[1]')) = 1
		BEGIN 
			SET @logMessage = ISNULL(@xmlInputLog.value('(/*[local-name()=sql:variable("@path")]/logs/log/text())[1]','VARCHAR(MAX)'),'')
			SET @logType = ISNULL(@xmlInputLog.value('(/*[local-name()=sql:variable("@path")]/logs/log/@type)[1]','NVARCHAR(MAX)'),'')
			IF (EXISTS(SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@errorPatern,@errorPaternSep) WHERE CHARINDEX(Aval,@logMessage)>0))
				SET @errorMessages+='Error found:'+@path+' Log type: ['+@logType+'] Errors: '+(
					SELECT ISNULL((STUFF((SELECT (  
					SELECT ','+aval AS '*' FOR XML PATH(''), TYPE) FROM dbo.GET_TABLE_FROM_LIST_DELIM(@errorPatern,@errorPaternSep) 
						WHERE CHARINDEX(Aval,@logMessage)>0
					FOR XML PATH('')),1,1,'')), '')
				) +CHAR(10)  -- +@logMessage+CHAR(10)
			SET @xmlInputLog.modify('delete (/*[local-name()=sql:variable("@path")]/logs/log)[1]')
		END 
	RETURN @errorMessages 
END
GO
