BEGIN

DECLARE @Deploy_version VARCHAR(128) = ISNULL((SELECT TOP 1 Deploy_version FROM dbo.DEPLOYMENT_versionS ORDER BY PK DESC),'0')
DECLARE @tsql VARCHAR(MAX) =-- dbo.GET_PRE_POST_CRENT_SQLSCRIPTS('5.09')+ --felerhanft
 '
IF EXISTS (SELECT * FROM version)
  UPDATE version SET version = ''6.0'', Release='''+@Deploy_version+''', Deploymentversion = '''+@Deploy_version+'''
else
  INSERT INTO version (version, Release, Deploymentversion) VALUES (''6.0'', '''+@Deploy_version+''', '''+@Deploy_version+''')
go

	'
	RETURN @tsql
