CREATE FUNCTION [dbo].[GET_UPDATE_XML_ENVIRONMENT_BY_PK](@PK BIGINT = NULL)
 RETURNS NVARCHAR(MAX)--Author José.
 BEGIN  --tab Environtment
 		DECLARE @MANDANT_DB_ENVIRONMENT_PY TABLE(rowNumber INT NOT NULL IDENTITY(1,1), mandant_id INT NULL, PK INT NULL, type NVARCHAR(30) NULL, path NVARCHAR(255) NULL, version NVARCHAR(30) NULL, databaseIp NVARCHAR(255) NULL, databaseInstance NVARCHAR(255) NULL, databaseName NVARCHAR(255) NULL, databaseUser NVARCHAR(255) NULL, tsCreateDate VARCHAR(32) NULL, installBase INT NULL, databasePort VARCHAR(16) NULL,
 											   mandantName NVARCHAR(255) NULL, updateDate DATETIME NULL, entryType NVARCHAR(30) NULL, actionButton NVARCHAR(128) NULL, ABAS_TASK_NO NVARCHAR(128) NULL, isExtern VARCHAR(1) NULL)
 
 		INSERT INTO @MANDANT_DB_ENVIRONMENT_PY (mandant_id, PK, mandantName, updateDate, type, path, version, databaseIp, databaseInstance, databaseName, databaseUser, tsCreateDate, installBase, databasePort,actionButton, ABAS_TASK_NO, isExtern)
 				SELECT  ISNULL(mandant_id,0), ISNULL(PK,0), dbo.GET_MANDANT_NAME_PARSED(mandant_id), dbo.GET_MANDANT_UPDATE_DATE(mandant_id,(CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END)), (CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END), ISNULL(path,''), ISNULL(version,''), ISNULL(databaseIp,''), ISNULL(databaseInstance,''), ISNULL(databaseName,''), ISNULL(databaseUser,''), CASE WHEN tsCreateDate IS NOT NULL THEN tsCreateDate ELSE '' END, ISNULL(installBase,0), CASE WHEN ISNUMERIC(databasePort) = 0 THEN '' ELSE CAST(databasePort AS VARCHAR(16)) END, 'im Detail ansehen', dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,''), CASE WHEN dbo.isClientExtern(mandant_id)=1 THEN '1' ELSE '0' END FROM MANDANT_DB_ENVIRONMENT WHERE  PK = @PK
   
 		DECLARE @XML_ENVIRONMENTS NVARCHAR(MAX) =
 			(ISNULL((
 					STUFF((-- SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT
 							SELECT 
 										(SELECT PK[@PK], mandant_id[@mandant_id],  
 										(SELECT 
 												1[@labelColumn], 1[@labelRow], 2[@elementColumn], 1[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','MandantName','label', mandantName)[@options],												
  												'30'[@labelWith],'50'[@textWith],'label'[@type],'1'[@readonly], mandantName  AS '*'  FOR XML PATH('MandantName'), TYPE), 
										(SELECT 
 												1[@labelColumn], 2[@labelRow], 2[@elementColumn], 2[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','MandantId','label', mandant_id)[@options],												
  												'30'[@labelWith],'50'[@textWith],'label'[@type],'1'[@readonly], mandant_id  AS '*'  FOR XML PATH('MandantId'), TYPE), 
 										(SELECT 
 												1[@labelColumn], 3[@labelRow], 2[@elementColumn], 3[@elementRow],
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','version','entry',ISNULL(version,''))[@options],
 												'entry'[@type],'1'[@readonly], ISNULL(version,'') AS '*'  FOR XML PATH('version'), TYPE), 
										(SELECT 
 												1[@labelColumn], 4[@labelRow], 2[@elementColumn], 4[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','DatabaseIP','entry',updateDate)[@options],
 												'entry'[@type], '1'[@readonly], databaseIp AS '*'  FOR XML PATH('DatabaseIP'), TYPE),
 										(SELECT 
 												1[@labelColumn], 5[@labelRow], 2[@elementColumn], 5[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','DatabaseName','entry',updateDate)[@options],
 												'entry'[@type], '1'[@readonly], databaseName AS '*'  FOR XML PATH('DatabaseName'), TYPE),
 										(SELECT 
 												1[@labelColumn], 6[@labelRow], 2[@elementColumn], 6[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','DatabaseInstance','entry',updateDate)[@options],
 												'entry'[@type], '1'[@readonly], databaseInstance AS '*'  FOR XML PATH('DatabaseInstance'), TYPE),
 										(SELECT 
