CREATE FUNCTION [dbo].[GET_UPDATE_XML_ENVIRONMENTS](@mandantSearchName NVARCHAR(255) = '')
RETURNS NVARCHAR(MAX)
BEGIN  
	    DECLARE @mandant TABLE (MANDANT_ID INT NOT NULL, MANDANT_NAME NVARCHAR(255) NULL)
 
		INSERT INTO @mandant
			SELECT id, dbo.GET_MANDANT_NAME(id) FROM dbo.Mandant WHERE ISNULL(companyname,'')<>''				
		
		IF (ISNULL(@mandantSearchName,'')<>'')
			BEGIN
				DELETE FROM @mandant WHERE MANDANT_NAME NOT LIKE '%'+@mandantSearchName+'%' 
			END
	DECLARE @XML_ENVIRONMENTS NVARCHAR(MAX) =
	 (ISNULL((
			 STUFF(( 
					 SELECT 
										(SELECT PK[@PK], mandant_id[@mandant_id],  
										(SELECT '30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], dbo.GET_MANDANT_NAME_PARSED(mandant_id)  AS '*'  FOR XML PATH('MandantName'), TYPE), 
										(SELECT '6'[@labelWith],'4'[@textWith],'entry'[@type],'1'[@readonly], (CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END) AS '*'  FOR XML PATH('Type'), TYPE), 
										(SELECT '8'[@labelWith],'10'[@textWith],'entry'[@type],'1'[@readonly], ISNULL(version,'UNBEKANNT') AS '*'  FOR XML PATH('version'), TYPE),
										(SELECT '12'[@labelWith],'18'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_DATE(mandant_id,(CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END)) AS '*'  FOR XML PATH('UpdateDate'), TYPE),
										--(SELECT '14'[@labelWith],'8'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,'') AS '*'  FOR XML PATH('ABAS_TASK_NO'), TYPE),
										--(SELECT '12'[@labelWith],'8'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,'') AS '*'  FOR XML PATH('MR_JASPER'), TYPE),
										--(SELECT '10'[@labelWith],'8'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,'') AS '*'  FOR XML PATH('MR1_CRW'), TYPE),
										--(SELECT '10'[@labelWith],'8'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,'') AS '*'  FOR XML PATH('MR2_CRW'), TYPE),
										(SELECT '16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'DETAILS' AS '*'  FOR XML PATH('DETAIL'), TYPE)
										
							

								FOR XML PATH('environment'), TYPE)   
							FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id IN (SELECT MANDANT_ID FROM @mandant) ORDER BY mandant_id ASC
						FOR XML PATH(''),ROOT('environments')),1,0,'')	
		),''))
	RETURN @XML_ENVIRONMENTS	        
END
GO
