CREATE FUNCTION [dbo].[GET_UPDATE_XML_ENVIRONMENTS_BY_PK](@PK BIGINT = NULL)
RETURNS NVARCHAR(MAX)
BEGIN  
	DECLARE @XML_ENVIRONMENTS NVARCHAR(MAX) =
	 (ISNULL((
			 STUFF(( 
					 SELECT  
										(SELECT PK[@PK], mandant_id[@mandant_id],  
										(SELECT '8'[@labelWith],'27'[@textWith],'label'[@type],'0'[@readonly], dbo.GET_MANDANT_NAME_PARSED(mandant_id)  AS '*'  FOR XML PATH('Mandant'), TYPE), 
										(SELECT '6'[@labelWith],'4'[@textWith],'entry'[@type],'1'[@readonly], (CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END) AS '*'  FOR XML PATH('Type'), TYPE), 
										(SELECT '8'[@labelWith],'10'[@textWith],'entry'[@type],'1'[@readonly], ISNULL(version,'UNBEKANNT') AS '*'  FOR XML PATH('version'), TYPE),
										(SELECT '22'[@labelWith],'14'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_DATE(mandant_id,(CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END)) AS '*'  FOR XML PATH('EnvironmentUpdateDate'), TYPE),
										(SELECT '14'[@labelWith],'8'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,'') AS '*'  FOR XML PATH('ABAS_TASK_NO'), TYPE),
										(SELECT '17'[@labelWith],'8'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,'') AS '*'  FOR XML PATH('MRJASPERNUMMER'), TYPE),
										(SELECT '16'[@labelWith],'8'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,'') AS '*'  FOR XML PATH('MRCRWNUMMER1'), TYPE),
										(SELECT '16'[@labelWith],'8'[@textWith],'entry'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END[@readonly],dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,'') AS '*'  FOR XML PATH('MRCRWNUMMER2'), TYPE),
										(SELECT '16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'JASPER_MR' AS '*'  FOR XML PATH('jasperMR'), TYPE),
										(SELECT '16'[@labelWith],'8'[@textWith],'button'[@type], CASE WHEN type = 'DEFAULT' THEN '0' ELSE '1' END [@readonly],'BACKUP_DB' AS '*'  FOR XML PATH('backup'), TYPE),
										(SELECT '16'[@labelWith],'12'[@textWith],'button'[@type], CASE WHEN type = 'DEFAULT' THEN '0' ELSE '1' END [@readonly],'RESTORE_AS_ACC' AS '*'  FOR XML PATH('restore'), TYPE),
										(SELECT '16'[@labelWith],'12'[@textWith],'button'[@type], CASE WHEN ISNULL(version,'UNBEKANNT') = '6.0' THEN '1' ELSE '0' END [@readonly],'UPDATE_AUF_6.0' AS '*'  FOR XML PATH('updaten'), TYPE)
										
							

								FOR XML PATH('environment'), TYPE)   
							FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @PK
						FOR XML PATH(''),ROOT('environments')),1,0,'')	
		),''))
	RETURN @XML_ENVIRONMENTS	        
END
GO
