 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(appCCheqUrlTest,'')  AS '*'  FOR XML PATH('appCCheqUrlTest'), TYPE)			
			

										,(SELECT 
