												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','appCServiceUrl','entry', ISNULL(appCServiceUrl,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(appCServiceUrl,'')  AS '*'  FOR XML PATH('appCServiceUrl'), TYPE)			
			

										,(SELECT 
