												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','appCServiceUrlTest','entry', ISNULL(appCServiceUrlTest,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(appCServiceUrlTest,'')  AS '*'  FOR XML PATH('appCServiceUrlTest'), TYPE)			
			

										,(SELECT 
