												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','accDatabaseUser','entry', ISNULL(accDatabaseUser,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(accDatabaseUser,'')  AS '*'  FOR XML PATH('accDatabaseUser'), TYPE)			
			

										,(SELECT 
												3[@labelColumn], 19[@labelRow], 4[@elementColumn], 19[@elementRow], 
												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','accDatabaseIp','entry', ISNULL(accDatabaseIp,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(accDatabaseIp,'')  AS '*'  FOR XML PATH('accDatabaseIp'), TYPE)			
			

										,(SELECT 
												1[@labelColumn], 20[@labelRow], 2[@elementColumn], 20[@elementRow], 
												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','accDatabaseName','entry', ISNULL(accDatabaseName,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(accDatabaseName,'')  AS '*'  FOR XML PATH('accDatabaseName'), TYPE)			
			

										,(SELECT 
												3[@labelColumn], 20[@labelRow], 4[@elementColumn], 20[@elementRow], 
												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','accDatabaseInstance','entry', ISNULL(accDatabaseInstance,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(accDatabaseInstance,'')  AS '*'  FOR XML PATH('accDatabaseInstance'), TYPE)			
			

										,(SELECT 
