												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','accDatabasePort','entry', ISNULL(accDatabasePort,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(accDatabasePort,'')  AS '*'  FOR XML PATH('accDatabasePort'), TYPE)			
			

										,(SELECT 
												3[@labelColumn], 21[@labelRow], 4[@elementColumn], 21[@elementRow], 
												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','emailPrintUrl','entry', ISNULL(emailPrintUrl,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(emailPrintUrl,'')  AS '*'  FOR XML PATH('emailPrintUrl'), TYPE)			
			

										,(SELECT 
