												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','printPath','entry', ISNULL(printPath,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(printPath,'')  AS '*'  FOR XML PATH('printPath'), TYPE)			
			

										,(SELECT 
												3[@labelColumn], 22[@labelRow], 4[@elementColumn], 22[@elementRow], 
												dbo.GET_GENERAL_ELEMENT_PROPERTIES(ID, 'MANDANT','externalHosting','entry', ISNULL(externalHosting,''))[@options],												
 												'30'[@labelWith],'50'[@textWith],'label'[@type],'0'[@readonly], ISNULL(externalHosting,'')  AS '*'  FOR XML PATH('externalHosting'), TYPE)			
			

 
									FOR XML PATH('MANDANT'), TYPE)   
								FROM MANDANT WHERE ID = @ID
							FOR XML PATH(''),ROOT('MANDANTs')),1,0,'')	
			),''))
		RETURN @XML_ENVIRONMENTS
END

