/****** Object:  UserDefinedFunction [dbo].[GET_UPDATE_XML_SPECIAL_MANDANT_BY_EVIRONMENT_PK]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_UPDATE_XML_SPECIAL_MANDANT_BY_EVIRONMENT_PK](@PK BIGINT = NULL, @mandant_name nvarchar(512) = NULL)
 RETURNS NVARCHAR(MAX)--Author José.
 BEGIN  
 		DECLARE @MANDANT_DB_ENVIRONMENT_PY TABLE(rowNumber INT NOT NULL IDENTITY(1,1), mandant_id INT NULL, PK INT NULL, type NVARCHAR(30) NULL, path NVARCHAR(255) NULL, version NVARCHAR(30) NULL, databaseIp NVARCHAR(255) NULL, databaseInstance NVARCHAR(255) NULL, databaseName NVARCHAR(255) NULL, databaseUser NVARCHAR(255) NULL, tsCreateDate VARCHAR(32) NULL, installBase INT NULL, databasePort VARCHAR(16) NULL,
 											   mandantName NVARCHAR(255) NULL, updateDate DATETIME NULL, entryType NVARCHAR(30) NULL, actionButton NVARCHAR(128) NULL, ABAS_TASK_NO NVARCHAR(128) NULL, isExtern VARCHAR(1) NULL)
		DECLARE @mandant_id INT = (SELECT mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK=@PK)
 		INSERT INTO @MANDANT_DB_ENVIRONMENT_PY (mandant_id, PK, mandantName, updateDate, type, path, version, databaseIp, databaseInstance, databaseName, databaseUser, tsCreateDate, installBase, databasePort,actionButton, ABAS_TASK_NO, isExtern)
 				SELECT  ISNULL(mandant_id,0), ISNULL(PK,0), ISNULL(@mandant_name,dbo.GET_MANDANT_NAME_PARSED(mandant_id)), dbo.GET_MANDANT_UPDATE_DATE(mandant_id,(CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END)), (CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END), ISNULL(path,''), ISNULL(version,''), ISNULL(databaseIp,''), ISNULL(databaseInstance,''), ISNULL(databaseName,''), ISNULL(databaseUser,''), CASE WHEN tsCreateDate IS NOT NULL THEN tsCreateDate ELSE '' END, ISNULL(installBase,0), CASE WHEN ISNUMERIC(databasePort) = 0 THEN '' ELSE CAST(databasePort AS VARCHAR(16)) END, 'im Detail ansehen', dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,''), CASE WHEN dbo.isClientExtern(mandant_id)=1 THEN '1' ELSE '0' END FROM MANDANT_DB_ENVIRONMENT WHERE  PK = @PK
		DECLARE @rdp_row_number INT = (SELECT COUNT(*) FROM dbo.[__fnworkspace_rdp](@mandant_id))
		DECLARE @ssh_row_number INT = (SELECT COUNT(*) FROM dbo.[__fnworkspace_fileaccess](@mandant_id))
 		DECLARE @XML_ENVIRONMENTS NVARCHAR(MAX) =
 			(ISNULL((
 					STUFF((
 							SELECT 
 										(SELECT PK[@PK], mandant_id[@mandant_id],  
 										(SELECT 
 												1[@labelColumn], 1[@labelRow], 2[@elementColumn], 1[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','MandantName','label', mandantName)[@options],												
  												'30'[@labelWith],'50'[@textWith],'label'[@type],'1'[@readonly], mandantName  AS '*'  FOR XML PATH('MandantName'), TYPE), 
										(SELECT 
 												1[@labelColumn], 2[@labelRow], 2[@elementColumn], 2[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','MandantId','label', mandant_id)[@options],												
  												'30'[@labelWith],'50'[@textWith],'label'[@type],'1'[@readonly], mandant_id  AS '*'  FOR XML PATH('MandantId'), TYPE), 
 										dbo.__fnGET_RDP_BUTTONS(mandant_id,1,2),
 										dbo.__fnGET_SSH_BUTTONS(mandant_id,1,@rdp_row_number+2),
 										dbo.__fnGET_FILEZILLA_BUTTONS(mandant_id,1,@rdp_row_number+@ssh_row_number+2),
										
					
 											
 																																																										
 										--
										

										--column 3 und 4
										(SELECT   
 												3[@labelColumn], 1[@labelRow], 4[@elementColumn], 1[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','GIT Projekt','custom_combobox','GIT_PROJEKT')[@options],
 												dbo.__getOfficialGITBranches()[@combobox_contents],
 												'16'[@labelWith],'16'[@textWith],'custom_combobox'[@type], '1'[@readonly], '' AS '*'  FOR XML PATH('GIT_PROJEKT'), TYPE),
 			 
										(SELECT   
 												3[@labelColumn], 2[@labelRow], 4[@elementColumn], 2[@elementRow], 
												'GIT_PROJEKT'[@combobox_contents_from_element],
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Branch','custom_subcombobox','BRANCH')[@options],
 												'16'[@labelWith],'16'[@textWith],'custom_subcombobox'[@type], '1'[@readonly], '' AS '*'  FOR XML PATH('BRANCH'), TYPE),
 			 
										(SELECT 
 												3[@labelColumn], 3[@labelRow], 4[@elementColumn], 3[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Merge Request','button','Git')[@options],
 												'{"readVars":["MandantId","GIT_PROJEKT","BRANCH"], "action":"kunden_open_GIT_OPEN_PROJECT"}'[@onClickAction],
 												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'im browser öffnen' AS '*'  FOR XML PATH('GIT_OPEN_PROJECT_MR'),TYPE),
										(SELECT   
 												3[@labelColumn], 4[@labelRow], 4[@elementColumn], 4[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Priv_Branch','entry','PRIVATE_BRANCH')[@options],
 												'{"readVars":["MandantId"], "action":"local_mr_crent_schema"}'[@onClickAction],
 												'16'[@labelWith],'16'[@textWith],'entry'[@type], '0'[@readonly],'' AS '*'  FOR XML PATH('PRIVATE_BRANCH'), TYPE),
 										(SELECT 
 												3[@labelColumn], 5[@labelRow], 4[@elementColumn], 5[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','AbasNo','entry','AbasNo2.')[@options],
 												'entry'[@type], '0'[@readonly], '00000' AS '*'  FOR XML PATH('ABAS_TASK_NO'), TYPE),
 										(SELECT 
 												3[@labelColumn], 6[@labelRow], 4[@elementColumn], 6[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Commit MSG','entry','Commit MSG')[@options],
 												'entry'[@type], '0'[@readonly], 'Bugfixing' AS '*'  FOR XML PATH('COMMIT_MSG'), TYPE),
 										(SELECT 
 												3[@labelColumn], 7[@labelRow], 4[@elementColumn], 7[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Merge Request','button','ausführen')[@options],
 												'{"readVars":["MandantId","GIT_PROJEKT","BRANCH","ABAS_TASK_NO","COMMIT_MSG","PRIVATE_BRANCH"], "action":"DO_PROJECT_MR"}'[@onClickAction],
 												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'ausführen' AS '*'  FOR XML PATH('DO_PROJECT_MR'), TYPE),
 									    /*(SELECT   
 												3[@labelColumn], 7[@labelRow], 4[@elementColumn], 7[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Commit Jasper','entry','Messages')[@options], 
 												'16'[@labelWith],'16'[@textWith],'entry'[@type], '0'[@readonly],'Anpassungen des Updates 6.0' AS '*'  FOR XML PATH('MRMessage'), TYPE),
 										*/ (SELECT 
 												3[@labelColumn], 8[@labelRow], 4[@elementColumn], 8[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Jasper Branch','entry','Kdn.Jasper')[@options],
 												'entry'[@type], '1'[@readonly], dbo.GET_MANDANT_UPDATE_FIELD(mandant_id,'JASPERBRANCHNAME') AS '*'  FOR XML PATH('JASPERBRANCHNAME'), TYPE),
 										(SELECT 
 												3[@labelColumn], 9[@labelRow], 4[@elementColumn], 9[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Merge mit Live','checkbox','Merge mit Live')[@options], 												
 												'16'[@labelWith],'3'[@textWith],'checkbox'[@type], '0'[@readonly],'0' AS '*'  FOR XML PATH('JMRMergeLIVE'), TYPE),
 										(SELECT 
 												3[@labelColumn], 10[@labelRow], 4[@elementColumn], 10[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Jasper mit Pipelines','button','MR ausführen')[@options],
 												'{"readVars":["MandantId","JMRMergeLIVE","ABAS_TASK_NO"], "action":"local_mr_jasper"}'[@onClickAction],
 												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'JASPERMR' AS '*'  FOR XML PATH('JASPERMR'), TYPE),
 										(SELECT 
 												3[@labelColumn], 11[@labelRow], 4[@elementColumn], 11[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','CRW Pipelines','button','ausführen')[@options],
 												'{"readVars":["MandantId","ABAS_TASK_NO"], "action":"local_mrs_crw"}'[@onClickAction],
 												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'MR CRW Master wie develop' AS '*'  FOR XML PATH('ProcessWEB1'), TYPE),
 										(SELECT   
 												3[@labelColumn], 12[@labelRow], 4[@elementColumn], 12[@elementRow],
												dbo.__getOfficialCX9Mails()[@combobox_contents], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Teamviewer Daten an','custom_combobox','an')[@options], 
 												'16'[@labelWith],'16'[@textWith],'custom_combobox'[@type], '0'[@readonly], '' AS '*'  FOR XML PATH('TEAMVIEWER_AN'), TYPE),
 										(SELECT   
 												3[@labelColumn], 13[@labelRow], 4[@elementColumn], 13[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Teamviewer PWD','entry','Teamviewer PWD')[@options], 
 												'16'[@labelWith],'16'[@textWith],'entry'[@type], '0'[@readonly], CASE WHEN dbo.GET_WEEKDAY(CURRENT_TIMESTAMP) IN ('Mo','Do','Fr') THEN 'sc_sicher' ELSE 'js_sicher' END AS '*'  FOR XML PATH('TEAMVIEWER_PWD'), TYPE),
 										
										
										
										(SELECT 
 												3[@labelColumn], 14[@labelRow], 4[@elementColumn], 14[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','Teamviewer Daten','button','senden')[@options],
 												'{"readVars":["MandantId","TEAMVIEWER_PWD","TEAMVIEWER_AN"], "action":"teamviewer_per_mail"}'[@onClickAction],
 												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'Teamviewer Daten' AS '*'  FOR XML PATH('TEAMVIEWER_PER_MAIL'), TYPE),
 										(SELECT 
 												3[@labelColumn], 15[@labelRow], 4[@elementColumn], 15[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','ORM des Kunden','button','öffnen')[@options],
 												'{"readVars":["MandantId"], "action":"kunden_open_ORM"}'[@onClickAction],
 												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'ORM des Kunden' AS '*'  FOR XML PATH('KUNDEN_ORM'), TYPE),
 										(SELECT 
 												3[@labelColumn], 16[@labelRow], 4[@elementColumn], 16[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','CRW des Kunden','button','öffnen')[@options],
 												'{"readVars":["MandantId"], "action":"kunden_open_CRW"}'[@onClickAction],
 												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'CRW des Kunden' AS '*'  FOR XML PATH('KUNDEN_CRW'), TYPE),
 										(SELECT 
 												3[@labelColumn], 17[@labelRow], 4[@elementColumn], 17[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','KUNDEN LINKS','button','öffnen')[@options],
 												'{"readVars":["MandantId"], "action":"kunden_open_LINKS"}'[@onClickAction],
 												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'LINKS' AS '*'  FOR XML PATH('KUNDEN_LINKS'), TYPE),
										(SELECT 
 												3[@labelColumn], 18[@labelRow], 4[@elementColumn], 18[@elementRow], 
 												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverviewDetail','KUNDEN ALLE LINKS','button','öffnen')[@options],
 												'{"readVars":["MandantId"], "action":"kunden_open_ALLE"}'[@onClickAction],
 												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'LINKS' AS '*'  FOR XML PATH('KUNDEN_LINKS_ALLE'), TYPE)
    
 									FOR XML PATH('environment'), TYPE)   
 								FROM @MANDANT_DB_ENVIRONMENT_PY
 							FOR XML PATH(''),ROOT('environments')),1,0,'')	
 			),''))
 	RETURN @XML_ENVIRONMENTS	        
 END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_UPDATE6CRENT_PATCH_APPS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_UPDATE6CRENT_PATCH_APPS](@MandantId INT = NULL)
RETURNS NVARCHAR(MAX)
BEGIN
	DECLARE @ConfigAPP NVARCHAR(MAX) = ''
	DECLARE @companyAppCode VARCHAR(128) = ISNULL(CAST((SELECT TOP 1 companyAppcode FROM dbo.Mandant WHERE id = @MandantId) AS VARCHAR(128)),'companyAppcode_NOT_GIVEN')
	DECLARE @documentRoot VARCHAR(128) = '/var/www/'+ISNULL((SELECT TOP 1 documentRoot  FROM dbo.Mandant WHERE id = @MandantId),'_no_document_root')+ '/crentweb/print/'
	 
    SET @ConfigAPP+='EXEC dbo.set_param @param = ''SAPP_AUTHCODE'', @wert = '''+@companyAppCode+''', @Beschreibung = ''App Authentifizierungscode'', @Bereich = ''CSAPP'', @Pflicht = NULL, @LabeltextOneklick = '''''+CHAR(13)
    SET @ConfigAPP+='EXEC dbo.set_param @param = ''SAPP_DOCUMENT_ROOT'', @wert = '''+@documentRoot+''', @Beschreibung = ''Verzeichnis für Jasper Ausdrucke, die in C-Cheq und C-Share verwendet werden können'', @Bereich = ''CSAPP'', @Pflicht = NULL, @LabeltextOneklick = '''''+CHAR(13)
	SET @ConfigAPP+='DECLARE @csappUrl VARCHAR(MAX) = dbo.getParamValue(''CSAPP_HOMEPAGE'')
IF @csappUrl = ''0''  
	EXEC dbo.set_param @param = ''CSAPP_HOMEPAGE'', @wert = ''https://kunden2.cx9.de/cx9/csapp/web/'', @Beschreibung = ''csapp homepage'', @Bereich = ''CSAPP'', @Pflicht = NULL, @LabeltextOneklick = NULL
DECLARE @mandEmail VARCHAR(MAX) = ISNULL((SELECT TOP 1 email FROM dbo.MAND_GLOBAL),''F.Wedemeier@cx9.de'') 
DECLARE @fromEmail VARCHAR(MAX) = dbo.getParamValue(''SINET_MAIL_FROM'') 
IF @fromEmail = ''0''
	EXEC dbo.set_param @param = ''SINET_MAIL_FROM'', @wert = @mandEmail, @Beschreibung = ''Absender E-Mail Adresse für E-Mails aus dem Reservierungsmodul und dem C-Cheq'', @Bereich = ''STANDARD'', @Pflicht = NULL, @LabeltextOneklick = NULL
  '

	RETURN @ConfigAPP
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_UPDATE6CRENT_PATCHES]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_UPDATE6CRENT_PATCHES](@MandantId INT = null)
RETURNS NVARCHAR(MAX)
BEGIN

DECLARE @abasID VARCHAR(128) = CAST((SELECT TOP 1 abasId FROM dbo.Mandant WHERE id = @MandantId) AS VARCHAR(128))
DECLARE @documentRoot VARCHAR(128) = ISNULL(CAST((SELECT TOP 1 documentRoot FROM dbo.Mandant WHERE id = @MandantId) AS VARCHAR(128)),'no_crw_install')
DECLARE @AbasIDPlusOtherUpdateCommands VARCHAR(MAX)=''
DECLARE @mandant_db VARCHAR(255) = REPLACE(ISNULL((SELECT databaseName FROM dbo.Mandant WHERE id=@MandantId),'_NODB'),'ACC_','')
DECLARE @mandant_dbuser VARCHAR(255) = ISNULL((SELECT TOP 1 databaseUser FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MandantId AND type = 'DEFAULT'),'_kein_live_user')
DECLARE @DBTexte NVARCHAR(MAX)  
SET @DBTexte='IF NOT EXISTS (SELECT nummer FROM dbo.texte WHERE Code=''INET_ZUS_TEXT_STEP2'' AND Gruppe=''Online-Reservierungen(Kunden)'' AND Sprache=''DE'')
  INSERT INTO dbo.texte(mem,Beschreibung,nummer,Code,Gruppe,Sprache,memPlainText)
	SELECT ''{\rtf1\ansi\ansicpg1252\deff0\deflang1031{\fonttbl{\f0\fnil\fcharset0 MS Sans Serif;}}  \viewkind4\uc1\pard\f0\fs16 Zusatztext bei Step 2 \par}'',''Zusatztext bei Step 2'',ISNULL((SELECT MAX(nummer) FROM dbo.texte),0)+1,''INET_ZUS_TEXT_STEP2'',''Online-Reservierungen(Kunden)'',''DE'',''Zusatztext bei Step 2''
