'UPDATE z SET Max_Miettage = (SELECT ISNULL(a.MaxMietTage,z.Max_Miettage) FROM autos a WHERE (a.MVANUMMER = z.mvanummer) AND (ISNULL(a.MaxMietTage,0) > ISNULL(z.Max_Miettage,0))) FROM autoszusdaten z
