/****** Object:  UserDefinedFunction [dbo].[GET_VIRTUAL_TABLE_COLUMN_NUMBER]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

 

CREATE FUNCTION [dbo].[GET_VIRTUAL_TABLE_COLUMN_NUMBER](@TABLE_NUMBER_OF_COLUMNS INT = NULL, @WISHED_COLUMNS INT = NULL, @ACTUAL_ROW INT = NULL)
RETURNS INT
BEGIN
	DECLARE @VIRTUAL_ROW_NUMBER INT = 1
	IF (ISNUMERIC(@TABLE_NUMBER_OF_COLUMNS)=1 AND ISNUMERIC(@WISHED_COLUMNS)=1 AND ISNUMERIC(@ACTUAL_ROW)=1
		AND @TABLE_NUMBER_OF_COLUMNS>=1 AND @WISHED_COLUMNS>=1 AND @ACTUAL_ROW>=1)
			BEGIN
				SET @VIRTUAL_ROW_NUMBER = (@TABLE_NUMBER_OF_COLUMNS * @ACTUAL_ROW) % @WISHED_COLUMNS         
				IF (@VIRTUAL_ROW_NUMBER = 0)
					SET @VIRTUAL_ROW_NUMBER = @WISHED_COLUMNS	 
			END  
	RETURN @VIRTUAL_ROW_NUMBER  
END
GO
