CREATE FUNCTION [dbo].[GET_VIRTUAL_TABLE_COLUMN_NUMBER2](@WISHED_COLUMNS INT = NULL, @ACTUAL_ROW INT = NULL)
RETURNS INT
BEGIN
	DECLARE @VIRTUAL_ROW_NUMBER INT = 1
	IF (ISNUMERIC(@WISHED_COLUMNS)=1 AND ISNUMERIC(@ACTUAL_ROW)=1
		AND @WISHED_COLUMNS>=1 AND @ACTUAL_ROW>=1)
			BEGIN
				SET @VIRTUAL_ROW_NUMBER = (@WISHED_COLUMNS) % @ACTUAL_ROW           
				IF (@VIRTUAL_ROW_NUMBER = 0)
					SET @VIRTUAL_ROW_NUMBER = @ACTUAL_ROW	 
			END  
	RETURN @VIRTUAL_ROW_NUMBER  
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_VIRTUAL_TABLE_ROW_NUMBER]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[GET_VIRTUAL_TABLE_ROW_NUMBER] (@TABLE_NUMBER_OF_COLUMNS INT = NULL, @WISHED_COLUMNS INT = NULL, @ACTUAL_COLUMN INT = NULL, @ACTUAL_ROW INT = NULL)
RETURNS INT
BEGIN
	DECLARE @VIRTUAL_ROW_NUMBER INT = 1
	IF (ISNUMERIC(@TABLE_NUMBER_OF_COLUMNS)=1 AND ISNUMERIC(@WISHED_COLUMNS)=1 AND ISNUMERIC(@ACTUAL_COLUMN)=1 AND ISNUMERIC(@ACTUAL_ROW)=1
		AND @TABLE_NUMBER_OF_COLUMNS>=1 AND @WISHED_COLUMNS>=1 AND @ACTUAL_COLUMN>=1 AND @ACTUAL_ROW>=1)
			BEGIN
				SET @VIRTUAL_ROW_NUMBER = ((@TABLE_NUMBER_OF_COLUMNS * @ACTUAL_ROW)-@ACTUAL_COLUMN) % @WISHED_COLUMNS    -- (@ACTUAL_COLUMN * @ACTUAL_ROW) % @TABLE_NUMBER_OF_COLUMNS         
				IF (@VIRTUAL_ROW_NUMBER = 0 OR @VIRTUAL_ROW_NUMBER = @WISHED_COLUMNS)
					SET @VIRTUAL_ROW_NUMBER = @ACTUAL_ROW	 
			END  
	RETURN @VIRTUAL_ROW_NUMBER  
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_WEEKDAY]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_WEEKDAY] (@ADate Datetime)
returns varchar(2)
begin
  declare @result varchar(2)
  declare @wd int
  Select @wd=datepart(dw,@ADate)
  if (@wd=1) Select @result='Mo'
  if (@wd=2) Select @result='Di'
  if (@wd=3) Select @result='Mi'
  if (@wd=4) Select @result='Do'
  if (@wd=5) Select @result='Fr'
  if (@wd=6) Select @result='Sa'
  if (@wd=7) Select @result='So'
  return @result
end
GO
