SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_XML_DATACOMPARE_CREDENTIALS] (@MANDANT_ID INT = NULL, @environment VARCHAR(128) = '')
RETURNS @DBCredentials TABLE(HOST VARCHAR(128) NULL, INSTANCE VARCHAR(255) NULL, PORT VARCHAR(16) NULL,
						DB VARCHAR(128) NULL, DB_USER VARCHAR(128) NULL, DB_USER_PW VARCHAR(128) NULL, RAWDATA VARCHAR(1024) NULL)  
						--@HOST,@INSTANCE,@PORT,@DB,@DB_USER
BEGIN 
		DECLARE @XMLCompareData XML
		DECLARE @RAWDATA VARCHAR(1024) = ''
		DECLARE @HOST VARCHAR(255) = ''
		DECLARE @INSTANCE VARCHAR(255) = ''		
		DECLARE @DB VARCHAR(255) = ''
		DECLARE @DB_USER VARCHAR(128) = ''
		DECLARE @DB_USER_PW NVARCHAR(128) = ''
		DECLARE @PORT VARCHAR(15) = NULL 
       IF ( EXISTS (SELECT TOP 1 DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @environment AND MANDANT_ID = @MANDANT_ID) )
			BEGIN        
			--SELECT * FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = 447
				SELECT TOP 1 @XMLCompareData = DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @environment AND MANDANT_ID = @MANDANT_ID
				IF (@XMLCompareData IS NOT NULL)
					BEGIN    
						--192.168.253.209,1433\CRENT -- nicht klar
						--192.168.253.209\CRENT,1433
						SET @HOST = ISNULL(@XMLCompareData.value('(/Project/DataSource2/ServerName/text())[1]', 'NVARCHAR(128)'),'')
						SET @HOST = REPLACE(@HOST,'/','\') --Tippfehler in DB XML Compare
						/*SET @HOST = '192.168.253.209\CRENT,1433'
						SET @HOST = '192.168.253.209,1433'
						SET @HOST = '192.168.253.209\CRENT'*/
						SET @RAWDATA = @HOST 
						DECLARE @InstanceIndexLimitator INT = dbo.LastIndexOf(@HOST,'\')
						DECLARE @portIndexLimitatorPort INT = dbo.LastIndexOf(@HOST,',')
						DECLARE @HOSTlenght INT =  LEN(@host)
						SET @DB = @XMLCompareData.value('(/Project/DataSource2/DatabaseName/text())[1]', 'NVARCHAR(128)')
						SET @DB_USER = @XMLCompareData.value('(/Project/DataSource2/Username/text())[1]', 'NVARCHAR(128)')
						SET @DB_USER_PW = @XMLCompareData.value('(/Project/DataSource2/Password/text())[1]', 'NVARCHAR(128)')

 
						IF (@InstanceIndexLimitator = @HOSTlenght AND @portIndexLimitatorPort <> @HOSTlenght) --there are port and db
							BEGIN						
								SELECT
								 @PORT = SUBSTRING(@HOST,@portIndexLimitatorPort+2,16),
								 @HOST = SUBSTRING(@HOST,1,@portIndexLimitatorPort)
								 IF (ISNUMERIC(@PORT) = 0)
									SET @PORT = NULL
							END	
						IF (@InstanceIndexLimitator <> @HOSTlenght AND @portIndexLimitatorPort = @HOSTlenght)
							BEGIN						
								SELECT @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitator+2,LEN(@HOST))
								, @HOST = SUBSTRING(@HOST,1,@InstanceIndexLimitator)--hier für den Port doof
							END	
						IF (@InstanceIndexLimitator <> @HOSTlenght AND @portIndexLimitatorPort <> @HOSTlenght)
							BEGIN						--@HOST = '192.168.253.209\CRENT,1433'
								SELECT  @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitator+2,LEN(@HOST)-CHARINDEX(',',@HOST)+1)
								, @PORT = SUBSTRING(@HOST,CHARINDEX(',',@HOST)+1,LEN(@HOST)-CHARINDEX(',',@HOST)+1)
								, @HOST =  SUBSTRING(@HOST,1,@InstanceIndexLimitator)--hier für den Port doof

								--SELECT SUBSTRING(@HOST,@pos+1,LEN(@HOST)-@pos+1)
							END-- SELECT CHARINDEX(',', '192.168.253.209\CRENT,1433')
						INSERT INTO @DBCredentials--(HOST,INSTANCE,PORT,DB,DB_USER,DB_USER_PW)
						     SELECT @HOST,@INSTANCE,@PORT,@DB,@DB_USER,@DB_USER_PW,@RAWDATA
						 		
					END  				
			END 		


	RETURN  
END
GO
/****** Object:  UserDefinedFunction [dbo].[GET_XML_ESCAPED]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GET_XML_ESCAPED] (@input VARCHAR(MAX))
RETURNS VARCHAR(MAX)
AS
BEGIN
    DECLARE @result VARCHAR (MAX)
    SET @result = 
    REPLACE(
        REPLACE(
            REPLACE(
                REPLACE(
                    REPLACE(@input,'&', '&amp;')
                ,'<', '&lt;')
            ,'>', '&gt;')
        ,'"', '&quot;')
    ,'''', '&#39;')

RETURN @result
END
GO
