CREATE FUNCTION [dbo].[getABASDocuProductsInformation](@mandant_id INT = 98, @formatMail BIT = 0)
RETURNS NVARCHAR(MAX)
BEGIN	
	DECLARE @ABAS_DOKU NVARCHAR(MAX) = 
'[ACC, LIVE] Update 6.0 Doku: Web Produkte: CRW, ORM, Slider, Jasper, etc
Doku wurde am '+dbo.GET_ISO_DATETIME(CURRENT_TIMESTAMP,DEFAULT)+' maschinell erzeugt.'+CHAR(13)+CHAR(13)+
dbo.getClientWebProductsInformation(@mandant_id,'LIVE')+CHAR(13)+
dbo.getClientWebProductsInformation(@mandant_id,'ACC')+CHAR(13)

	DECLARE @MANDANT_RDP_USERS NVARCHAR(MAX) = 'RDP Benutzer: '+CHAR(13)+  
	ISNULL((STUFF((SELECT ( 	 
			SELECT top 25 ',[    '+name+'    :    '+InitialPass+'    ]' AS '*' FOR XML PATH(''), TYPE)
			FROM TSUsers where customer_id = @mandant_id  
		FOR XML PATH('')),1,1,'')), '')+CHAR(13)+CHAR(13) 
	DECLARE @jasperBranchname NVARCHAR(128) = dbo.GET_MANDANT_JASPER_DEPLOYMENT_NAME(@mandant_id)+CHAR(13)
	SET @ABAS_DOKU+=@MANDANT_RDP_USERS
	SET @ABAS_DOKU+='CX9 GIT Jasper Branchname: '+@jasperBranchname+CHAR(13)+CHAR(13)

	IF (@formatMail = 1)
		SET @ABAS_DOKU = REPLACE (@ABAS_DOKU,CHAR(13),'<br>')

	RETURN @ABAS_DOKU
END
GO
