CREATE FUNCTION [dbo].[getAdminLinkedServerArchiv] (@MANDANT_ID INT = NULL, @ENVIRONTMENT VARCHAR(32) = 'LIVE', @SETDB BIT = 0)
RETURNS XML
BEGIN
  DECLARE @result XML = NULL
  DECLARE @linkedServerName VARCHAR(255) = '', @ServerName VARCHAR(128) = '', @DatabaseName VARCHAR(128) = '', 
  @Username NVARCHAR(128) = 'c*]', @Password NVARCHAR(128) 
  SET  @Password = dbo.SEC_GetPWCOde(@Username)
  DECLARE @UsernameDefault NVARCHAR(128) = 'c*]'
  DECLARE @PasswordDefault NVARCHAR(128) = dbo.SEC_GetPWCOde(@UsernameDefault)
 
	IF EXISTS(SELECT * FROM dbo.getLinkedServerArchivDB(@MANDANT_ID,@ENVIRONTMENT,0))
		BEGIN
		 SELECT @linkedServerName=LinkedServerName, @ServerName=ServerName, @Username=Username, @Password=Password, @DatabaseName =DatabaseName  FROM dbo.getLinkedServerArchivDB(@MANDANT_ID,@ENVIRONTMENT,0)
		 IF (CHARINDEX('192.168.253.209',@ServerName)>0)
			BEGIN
			  SET @Username = 'sa'
			  SET @Password = 'chevy#2020'   				
			END
		ELSE IF (dbo.isClientExtern(@MANDANT_ID)=0 AND @linkedServerName<>'LINKED_192_168_253_109_MSSQL2014')
			BEGIN
			  SET @Username = @UsernameDefault
			  SET @Password = @PasswordDefault 				
			END
		ELSE IF (dbo.isClientExtern(@MANDANT_ID)=0 AND @linkedServerName = 'LINKED_192_168_253_109_MSSQL2014')
			BEGIN
			  SET @Username = 'sa'
			  SET @Password = 'chEvy$)' 				
			END
		 SET @result = '<server>
			<LINKED_SERVER name="'+@linkedServerName+'">
			<ServerName>'+@ServerName+'</ServerName>
			<DatabaseName></DatabaseName>
			<Username>'+@Username+'</Username>
			<Password>'+@Password+'</Password>
			</LINKED_SERVER>
		</server>'
		IF (@SETDB = 1)
		 SET @result = '<server>
			<LINKED_SERVER name="'+@linkedServerName+'">
			<ServerName>'+@ServerName+'</ServerName>
			<DatabaseName>'+@DatabaseName+'</DatabaseName>
			<Username>'+@Username+'</Username>
			<Password>'+@Password+'</Password>
			</LINKED_SERVER>
		</server>'						
		END
  RETURN @result
END
GO
