/****** Object:  UserDefinedFunction [dbo].[getClientWebProductsInformation]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getClientWebProductsInformation](@mandant_id INT = 98, @environment VARCHAR(128) = 'ACC')
RETURNS NVARCHAR(MAX)
BEGIN
	
	DECLARE @result NVARCHAR(MAX) = '' 
	DECLARE @ormUrlSlider VARCHAR(255) =  ''
	DECLARE @ormUrl VARCHAR(255) =  ''
	DECLARE @crwUrl VARCHAR(255) =  ''
	DECLARE @envTestFolder VARCHAR(255) =  ''
	DECLARE @environment_auxiliar VARCHAR(128) = CASE WHEN @environment = 'LIVE' THEN 'DEFAULT' ELSE @environment END
	DECLARE @ORM_IN_USE BIT = CASE WHEN (EXISTS((SELECT PK FROM dbo.MANDANT_MODULE_ALTE_STRUKTUR WHERE MANDANT_ID = @mandant_id AND Modul = 'ORM' AND enabled='J' AND MENVPK IN (SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@mandant_id AND type = @environment_auxiliar) ))) THEN 1 ELSE 0 END
	DECLARE @CRW_IN_USE BIT = CASE WHEN (EXISTS((SELECT PK FROM dbo.MANDANT_MODULE_ALTE_STRUKTUR WHERE MANDANT_ID = @mandant_id AND Modul = 'CRENTWEB' AND enabled='J' AND MENVPK IN (SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@mandant_id AND type = @environment_auxiliar) ))) THEN 1 ELSE 0 END
	DECLARE @ORM_AVAILABILITY_PLAN_IN_USE BIT = CASE WHEN (EXISTS((SELECT * FROM dbo.MANDANT_MODULE_ALTE_STRUKTUR WHERE MANDANT_ID = @mandant_id AND Modul = 'ORM_AVAILABILITY_PLAN' AND enabled='J' AND MENVPK IN (SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@mandant_id AND type = @environment_auxiliar) ))) THEN 1 ELSE 0 END
    SELECT TOP 1 @ormUrl=ISNULL(ormUrl,''), @crwUrl=ISNULL(crwUrl,'') FROM dbo.Mandant WHERE id=@mandant_id
	SET @envTestFolder = ISNULL((SELECT KUNDEN02_ORDNER_PREFIX FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId=@mandant_id AND Environment = @environment),'_test')
    SET @ormUrlSlider=@ormUrl+'/offers'
	IF (@environment = 'ACC')
		BEGIN
			SET @ormUrlSlider=REPLACE(@ormUrl,'reservierung_rd','reservierung_rd'+@envTestFolder+'/offers')
			SET @ormUrl=REPLACE(@ormUrl,'reservierung_rd','reservierung_rd'+@envTestFolder) 
			SET @crwUrl=REPLACE(@crwUrl,'crentweb','crentweb'+@envTestFolder)
			
		END

	IF (@crwUrl<>'' AND @CRW_IN_USE = 1)
		BEGIN
			SET @result+=@environment+' C-Rent Web 6.0: '+@crwUrl+CHAR(13)	
		END  		
	IF (@ormUrl<>'' AND @ORM_IN_USE = 1)
		BEGIN
			SET @result+=@environment+' ORM 6.0: '+@ormUrl+CHAR(13)		
		END
	IF (@ormUrlSlider<>'' AND @ORM_AVAILABILITY_PLAN_IN_USE = 1)
		BEGIN
			SET @result+=@environment+' ORM Slider 6.0: '+@ormUrlSlider	+CHAR(13)	
		END  
	      
		
	RETURN @result
END
GO
/****** Object:  UserDefinedFunction [dbo].[getConnection]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getConnection](@authcode VARCHAR(255), @app VARCHAR(10), @version VARCHAR(10),@url VARCHAR(MAX), @debug BIT = 0)
RETURNS @result TABLE(dbHost VARCHAR(255), dbInstance VARCHAR(255),
dbPort INT, dbName VARCHAR(255), dbUser VARCHAR(255), appCode VARCHAR(255), 
appSecret VARCHAR(255), environment INT, [version] VARCHAR(10))
AS
BEGIN
	DECLARE @environment VARCHAR(10)
	IF (@debug = 1 OR EXISTS(SELECT * FROM dbo.Apis WHERE CHARINDEX(url, @url) = 1 AND Acc = 1) OR EXISTS(SELECT * FROM dbo.APP_TEST_version WHERE [version] =@version AND app = @app) ) 
	AND EXISTS (SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT e,dbo.Mandant m WHERE e.mandant_id = m.id AND m.companyAppCode = @authcode AND type = 'ACC' )
		SET @environment = 'ACC'
	ELSE
		SET @environment =  'DEFAULT'
  
INSERT INTO @result  
	SELECT TOP 1 e.databaseIp, e.databaseInstance, CASE WHEN e.databasePort IS NOT NULL THEN e.databasePort ELSE 1433 END, e.databaseName, e.databaseUser, m.companyAppCode, m.appSecret, NULL, e.version
	FROM mandant m, dbo.MANDANT_DB_ENVIRONMENT e 
	WHERE companyAppCode = @authcode AND e.mandant_id = m.id AND type = @environment
	
	IF EXISTS(SELECT TOP 1 m.* FROM dbo.Mandant m, dbo.CSAPP_version_URL u WHERE m.id = u.mandant AND u.version = @version AND u.APP_TYPE = @app)
		UPDATE @result SET environment = (SELECT TOP 1 u.PK FROM dbo.CSAPP_version_URL u, dbo.Mandant m WHERE m.id = u.mandant AND u.version = @version AND u.APP_TYPE = @app)

	RETURN 
END

GO
/****** Object:  UserDefinedFunction [dbo].[getCRent60UpdateInstructions]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getCRent60UpdateInstructions](@MandantId INT = NULL, @AbasId INT = NULL, @environment VARCHAR(128)='ACC', @abasTaskNumber VARCHAR(128)='00000')
RETURNS VARCHAR(MAX)
BEGIN
	DECLARE	@ip VARCHAR(255) = '', @dbname VARCHAR(255) = '', @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)='', 
	@dbinstance VARCHAR(512)='', @documentRoot VARCHAR(512)='', @mandantName VARCHAR(512)='', 
	@JasperBranch VARCHAR(512)='master', @MainCRWBranch VARCHAR(512)='master', 
	@gitSchemasUpdate VARCHAR(1)='J',
	@justCreateJobs VARCHAR(1)='N'
    IF @AbasId IS NULL AND NOT EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId)
		RETURN '
		echo Daten in Mandant sind nicht gepflegt.
		exit /b'
    IF @AbasId IS NULL AND (SELECT TOP 1 abasId FROM dbo.Mandant WHERE id=@MandantId) IS NULL
		RETURN '
		echo AbasId Erforderlich, bitte pflegen 
		exit /b'
    IF (SELECT TOP 1 abasId FROM dbo.Mandant WHERE id=@MandantId) IS NOT NULL --overwrite the value
		SET @AbasId = (SELECT TOP 1 abasId FROM dbo.Mandant WHERE id=@MandantId)

	IF NOT EXISTS(SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE mandantId = @mandantId AND version = '6.0' 
					AND Environment = 'ACC' 
					AND ISNULL(DB,'')<>''
					AND ISNULL(HOST,'')<>''
					AND ISNULL(DB_USER,'')<>''
					AND ISNULL(DB_USER_PW,'')<>''
					AND ISNULL(JasperBranch,'')<>''
					AND ISNULL(MainCRWBranch,'')<>''
					AND ISNULL(KUNDEN02_ORDNER_PREFIX,'')<>''
					AND ISNULL(searchDataIndex,'')<>'' 
					) AND @justCreateJobs <> 'J'
		BEGIN 
			RETURN '
			echo nicht update faehig, bitte ACC Daten pflegen 
			exit /b'
		END 

	DECLARE @datasearchindex VARCHAR(128)='', @globalName VARCHAR(128)=''
	DECLARE @instructions VARCHAR(MAX) = '
		:: auf dem Server 192.168.254.210 unter dem Ordner C:\SQLJobs	
		@echo off
		echo ========================================================================
		echo Create '+@environment+' JOBS für die '+@environment+'_DB des Kunden
		echo ========================================================================
		::update crent_schema_db
		SET schema_job="C:\Deployment\update_crent_schema_deployment.BAT"
	'
	IF( NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN
		SET @instructions+='
		:: MandantId existiert nicht bitte pflege Daten in der DB install tool
		echo MandantId existiert nicht bitte pflege Daten in der DB install tool
		exit /b
		'
		RETURN @instructions
	END
	IF( @environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS) )
	BEGIN
		SET @instructions+='
		:: Environment ist nicht gueltig
		echo Environment ist nicht gueltig
		exit /b
		'
		RETURN @instructions
	END    
	IF (@environment = 'ACC' AND EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@environment))
		BEGIN
			SELECT TOP 1 @dbname=DB, @dbuser=DB_USER, @dbpassword=DB_USER_PW, 
			@ip=ISNULL(HOST,''),
			@datasearchindex = ISNULL(searchDataIndex,'IND'),
			@dbinstance=ISNULL(INSTANCE,''), @JasperBranch=JasperBranch, @MainCRWBranch=MainCRWBranch
			FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@environment 	 
		END
	IF (@environment = 'LIVE' AND EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@environment))
		BEGIN
			SELECT @ip=ISNULL(databaseIp,''),
				   @dbname=ISNULL(databaseName,''), @dbinstance=ISNULL(databaseInstance,''),
				   @dbuser=ISNULL(databaseUser,'') FROM dbo.Mandant WHERE id=@MandantId 
		END     
	SELECT @globalName=ISNULL(globalName,'_NOGlobalName'),@documentRoot=ISNULL(documentRoot,'_documentRoot'),
	@mandantName=ISNULL(companyname,'noCompanyName') FROM dbo.Mandant WHERE id=@MandantId 		   
	IF (@environment <> 'ACC')
		SET @datasearchindex = 'noSearchIndex'
    SET @instructions+='

		SET CLIENT=%1
		SET STEP=%2
		SET HOMEFOLDER=C:\SQLJobs		
 


		if "%STEP%" == "1" (
			:: CALL %schema_job%
			cd %HOMEFOLDER%
			:: Create both for DATA and Schema
			CALL C:\SQLJobs\createCompareJob.bat '+CAST(@MandantId AS VARCHAR(16))+' '+CAST(@environment AS VARCHAR(16))+' DATA '+CAST(@abasId AS VARCHAR(16))+' '+CAST(@datasearchindex AS VARCHAR(16))+' 
			CALL C:\SQLJobs\createCompareJob.bat '+CAST(@MandantId AS VARCHAR(16))+' '+CAST(@environment AS VARCHAR(16))+' SCHEMA '+CAST(@abasId AS VARCHAR(16))+' '+CAST(@datasearchindex AS VARCHAR(16))+' 
			echo Please make manually changes for data compare and schema compare
			echo and then execute %0 %1 2
			'+CASE WHEN @justCreateJobs<>'N' THEN '
			MOVE '+dbo.getUpdateCompareSchemaName(@MandantId,@environment,'SCHEMA')+' '+REPLACE(dbo.getUpdateCompareSchemaName(@MandantId,@environment,'SCHEMA'), '\TODO','')+'
			MOVE '+dbo.getUpdateCompareSchemaName(@MandantId,@environment,'DATA')+' '+REPLACE(dbo.getUpdateCompareSchemaName(@MandantId,@environment,'DATA'), '\TODO','')+'
			exit /b
			' ELSE '' END + '
'+dbo.GET_GIT_DEPLOYMENT6_UPDATE6_INSTRUCTIONS(@MandantId,'update')+
'			
			echo Schema Compare: crentdev_static_data -> crent_schema_deployment
			echo ==============================================================================
			echo %TIME%

			cd "C:\Program Files (x86)\Red Gate\SQL Compare 14"

			'+CASE WHEN @gitSchemasUpdate='J' THEN '
			SQLCompare /project:"C:\Deployment\Schema Compare\crentdev_static_data v 192.168.254.209_SQL2012DEV.crent_schema_deployment.scp" /synchronize' ELSE '' END+
			'echo Schema Compare: crentdev_static_data  -> crent_schema_deployment erfolgreich
			echo ==============================================================================
			echo %TIME%

			echo Schema Compare: Git -> crent_schema_deployment
			echo ==============================================================================
			echo %TIME%

			cd "C:\Program Files (x86)\Red Gate\SQL Compare 14"
			'+CASE WHEN @gitSchemasUpdate='J' THEN '
			SQLCompare /project:"C:\Deployment\Schema Compare\crent_schema v 192.168.254.209_SQL2012DEV.crent_schema_deployment.scp" /synchronize /include:Identical' ELSE '' END+
			'
			

			echo Schema Compare: Git -> crent_schema_deployment erfolgreich
			echo ==============================================================================
			echo %TIME%


			echo Schema Compare: crent_schema_deployment -> Kunden
			echo ==============================================================================
			echo %TIME%
 
 
			echo %TIME%
			SQLCompare /project:'+dbo.getUpdateCompareSchemaName(@MandantId,@environment,'SCHEMA')+' /synchronize /Out:'+dbo.getUpdateCompareSchemaNameLog(@MandantId,@environment,'SCHEMA')+'
			call :LogFile '+CAST(@MandantId AS VARCHAR(16))+' '+CAST(@environment AS VARCHAR(16))+' SCHEMA compare console 1 '+dbo.getUpdateCompareSchemaNameLog(@MandantId,@environment,'SCHEMA')+'
			
			echo %TIME%
 

			echo Schema Compare: crent_schema_deployment -> Kunden erfolgreich
			echo ==============================================================================
			echo %TIME%


			echo Data Compare: crentdev_static_data -> Kunden
			echo ==============================================================================
			echo %TIME%

			cd "C:\Program Files (x86)\Red Gate\SQL Data Compare 14"
 
 
	
			echo %TIME%
			SQLDataCompare /project:'+dbo.getUpdateCompareSchemaName(@MandantId,@environment,'DATA')+' /exclude:additional /synchronize /Out:'+dbo.getUpdateCompareSchemaNameLog(@MandantId,@environment,'DATA')+'
			call :LogFile '+CAST(@MandantId AS VARCHAR(16))+' '+CAST(@environment AS VARCHAR(16))+' DATA compare console 1 '+dbo.getUpdateCompareSchemaNameLog(@MandantId,@environment,'DATA')+'
			echo %TIME%
 

			echo Data Compare: crentdev_static_data -> Kunden erfolgreich
			echo ==============================================================================
			echo %TIME%


			echo Ende
			echo ==============================================================================
			echo %TIME% 

			CD C:\SQLJobs'+CASE WHEN @justCreateJobs='N' THEN '
			CALL %0 %1 2' ELSE '' END+'			
		)


		if "%STEP%" == "2" (
			:: after success of jobs, then upload the acc_.scp to DB and make the live Jobs
			CALL C:\SQLJobs\uploadCompareJob.bat '+CAST(@MandantId AS VARCHAR(16))+' '+CAST(@environment AS VARCHAR(16))+' DATA '+CAST(@abasId AS VARCHAR(16))+' '+CAST(@datasearchindex AS VARCHAR(16))+' 
			CALL C:\SQLJobs\uploadCompareJob.bat '+CAST(@MandantId AS VARCHAR(16))+' '+CAST(@environment AS VARCHAR(16))+' SCHEMA '+CAST(@abasId AS VARCHAR(16))+' '+CAST(@datasearchindex AS VARCHAR(16))+' 


			::export / import the translations (from client to cx9 and from cx9 to client) and 
			::make patch updates from S:\C-Rent\Updates\6.0\patch Vorlage.txt 


			echo ========================================================================
			echo Executing "C:\SQLJobs\update_translations.bat '+CAST(@MandantId AS VARCHAR(16))+' CLIENT_TO_STATIC_DATA '+CAST(@environment AS VARCHAR(16))+' SCHEMA"
			call C:\SQLJobs\update_translations.bat '+CAST(@MandantId AS VARCHAR(16))+' CLIENT_TO_STATIC_DATA '+CAST(@environment AS VARCHAR(16))+' SCHEMA
			echo ========================================================================
			echo.
			echo.

			echo ========================================================================
			echo Executing "C:\SQLJobs\update_translations.bat '+CAST(@MandantId AS VARCHAR(16))+' STATIC_DATA_TO_CLIENT '+CAST(@environment AS VARCHAR(16))+' DATA"
			call C:\SQLJobs\update_translations.bat '+CAST(@MandantId AS VARCHAR(16))+' STATIC_DATA_TO_CLIENT '+CAST(@environment AS VARCHAR(16))+' DATA
			echo ========================================================================
			echo.
			echo.
			if exist "C:\SQLJobs\deployStepByStep\*'+CAST(@MandantId AS VARCHAR(16))+'*'+CAST(@environment AS VARCHAR(16))+'*.*" (
				echo TEMP_FILES are goint to be DELETED
				timeout 20              
				DEL /Q /F /S "C:\SQLJobs\deployStepByStep\*'+CAST(@MandantId AS VARCHAR(16))+'*'+CAST(@environment AS VARCHAR(16))+'*.*"
			)
			EXIT /b
		)
		EXIT /b
		:LogFile
		CALL C:\SQLJobs\uploadLogFile.bat %~1 %~2 %~3 %~4 %~5 %~6 "%~7"
		
	'
	--
	RETURN @instructionsEND
GO
/****** Object:  UserDefinedFunction [dbo].[getCRent60UpdateSHInstructions]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getCRent60UpdateSHInstructions](@MandantId INT = NULL, @environment VARCHAR(128)='ACC')
RETURNS VARCHAR(MAX)
BEGIN
	DECLARE	@ip VARCHAR(255) = '', @dbname VARCHAR(255) = '', @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)='', 
	@dbinstance VARCHAR(512)='', @documentRoot VARCHAR(512)='', @mandantName VARCHAR(512)='', @abasTaskNumber VARCHAR(128)='00000',
	@JasperBranch VARCHAR(512)='master', @MainCRWBranch VARCHAR(512)='master'
	DECLARE @WEBSERVERIP VARCHAR(128) = '',@WEBSERVERSSHUSER VARCHAR(128) = '',@WEBSERVERSSHUSERPW VARCHAR(128) = ''
	DECLARE @ISO_LANG VARCHAR(16) = (SELECT ISNULL((SELECT iso FROM dbo.Language WHERE id = (SELECT systemLanguage_id FROM dbo.Mandant WHERE id=453)),@MandantId))
	DECLARE @KUNDEN02_ORDNER_PREFIX VARCHAR(128) = '_'+@environment
	DECLARE @timeZone VARCHAR(128) = 'Europe/Berlin'
	DECLARE @rightsToUserGroup VARCHAR(128) = 'cx9:www-data'
	DECLARE @nextExcutionTime VARCHAR(128) = '45'--CAST(ABS(CAST(NEWID() as binary(6)) % (1 + 50 - 30)) + 30 as varchar(8)) --between 30-50 secondes
	DECLARE	@ipLive VARCHAR(255) = '', @dbnameLive VARCHAR(255) = '', @dbuserLive VARCHAR(512)='', @dbinstanceLive VARCHAR(512)=''


	IF NOT EXISTS(SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE mandantId = @mandantId AND version = '6.0' 
					AND Environment = @environment 
					AND ISNULL(DB,'')<>''
					AND ISNULL(HOST,'')<>''
					AND ISNULL(DB_USER,'')<>''
					AND ISNULL(DB_USER_PW,'')<>''
					AND ISNULL(JasperBranch,'')<>''
					AND ISNULL(MainCRWBranch,'')<>''
					AND ISNULL(KUNDEN02_ORDNER_PREFIX,'')<>''
					AND ISNULL(searchDataIndex,'')<>'' 
					)
		BEGIN 
			RETURN '
			echo "nicht update faehig, bitte ACC Daten pflegen"
			exit 1'
		END 

	DECLARE @datasearchindex VARCHAR(128)='', @globalName VARCHAR(128)=''
	DECLARE @instructions VARCHAR(MAX) = '
		#!/bin/bash
		# SH Updates
		# Jose M.  
		RED="\e[31m"
		ORANGE="\e[33m"
		BLUE="\e[94m"
		GREEN="\e[92m"
		STOP="\e[0m" 
		export LANG=C.UTF-8
		prog() {
			local w=60 p=$1;  shift
			simNumber=($p*$w)/100 
			sim="*"
			# create a string of spaces, then change them to dots
			printf -v dots "%*s" "$(( $simNumber ))"; dots=${dots// /$sim};
			printf "${GREEN}"
			# print those dots on a fixed-width space plus the percentage etc. 
			printf "\r\e[K[%-*s] %3d%% %s" "$w" "$dots" "$p" "$*"; 
			#clear
		}
		timeout () {
			tput sc
			time=$1; while [ $time -ge 0 ]; do
				tput rc; tput el
				printf "$2" $time
				((time--))
				sleep 1
			done
			tput rc; tput ed;
		}
		printf "${ORANGE}" 
		echo "W E L C O M E   T O   C X 9    W E B    P R O D U C T S   U P D A T E S"
		echo -e "\n\n\n "

		bar() {
			local message=$2 p=$1 status=$3 ;  shift
			x=$p
			statusMessage="$x update unknown status"
			if [ "$status" = "0" ]; then 
			  statusMessage="$x update cancelled."
			fi   
			if [ "$status" = "1" ]; then 
			  statusMessage="$x update running ... "
			fi    
			if [ "$status" = "2" ]; then 
			  statusMessage="$x update will continue ... "
			fi        
			if [ "$status" = "5" ]; then 
			  statusMessage="$x update completed"
			fi 
			prog $statusMessage
			echo ""
			echo -e "\e[38;5;198m $message \e[0m"
			echo -e "\n"   
			sleep .1 
		}
	'
			
	IF( NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN
		SET @instructions+='
		echo "MandantId existiert nicht bitte pflege Daten in der DB install tool"
		exit 1
		'
		RETURN @instructions
	END
   
	IF( @environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS) )
	BEGIN
		SET @instructions+='
		echo "Environment ist nicht gueltig"
		exit 1
		'
		RETURN @instructions
	END 
	   
	IF (@environment <> 'LIVE' AND EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@environment))
		BEGIN
			SELECT TOP 1 @dbname=DB, @dbuser=DB_USER, @dbpassword=DB_USER_PW, 
			@ip=ISNULL(HOST,''),
			@datasearchindex = ISNULL(searchDataIndex,'IND'),
			@dbinstance=ISNULL(INSTANCE,''), @JasperBranch=JasperBranch, @MainCRWBranch=MainCRWBranch,
			@abasTaskNumber=ISNULL(ABAS_TASK_NO,''),@KUNDEN02_ORDNER_PREFIX=ISNULL(KUNDEN02_ORDNER_PREFIX,@KUNDEN02_ORDNER_PREFIX),
			@timeZone=ISNULL(timeZone,@timeZone),@rightsToUserGroup=ISNULL(rightsToUserGroup,@rightsToUserGroup),
			@WEBSERVERIP=ISNULL(WEBSERVERIP,''),@WEBSERVERSSHUSER=ISNULL(WEBSERVERSSHUSER,''),@WEBSERVERSSHUSERPW=ISNULL(WEBSERVERSSHUSERPW,'')
			FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@environment 	 
			 
		END
  --@ipLive VARCHAR(255) = '', @dbnameLive VARCHAR(255) = '', @dbuserLive VARCHAR(512)='', @dbinstanceLive      
    SELECT TOP 1 @ipLive=ISNULL(databaseIp,''), @dbnameLive=ISNULL(databaseName,''), @dbinstanceLive=ISNULL(databaseInstance,''), 
	@dbuserLive=dbo.GET_SH_ESCAPED_PWD(ISNULL(databaseUser,'')) FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MandantId AND type = 'DEFAULT' ORDER BY version desc
	SELECT @globalName=ISNULL(globalName,'_NOGlobalName'),@documentRoot=ISNULL(documentRoot,'_documentRoot'),
	@mandantName=dbo.stringReplaceMultiple_pattern(ISNULL(companyname,'noCompanyName'),'ä=ae;ü=ue;ö=oe;&=und;',';','=') FROM dbo.Mandant WHERE id=@MandantId
	IF (@environment <> 'ACC')
		SET @datasearchindex = 'noSearchIndex'		
	IF (@environment <> 'LIVE')
		SET @instructions+='
			WATING_TIME_FOR_NEXT_DEPLOYMENT='+@nextExcutionTime+'
		    DATE_WITH_TIME=$(date +%s)
			LINUXDEB05Folder="/home/jmunoz/updates/"
			cd $LINUXDEB05Folder
			CRW_MODUL_COMMAND_INSTALL_LIVE="crw_install.sh -r \"'+@documentRoot+'\" -s \"'+@ipLive+'\" -i \"'+@dbinstanceLive+'\" -d \"'+@dbnameLive+'\" -u \"'+@dbuserLive+'\" -n \"'+@mandantName+'\""
			RES_MODUL_COMMAND_INSTALL_LIVE="orm_install.sh -r \"'+@documentRoot+'\" -s \"'+@ipLive+'\" -i \"'+@dbinstanceLive+'\" -d \"'+@dbnameLive+'\" -u \"'+@dbuserLive+'\" -n \"'+@mandantName+'\" -v \"600\""
			
			CRW_MODUL_COMMAND="makeCRentWebModul600.sh \"'+@documentRoot+'\" \"'+@ip+'\" \"'+@dbinstance+'\" \"'+@dbname+'\" \"'+@dbuser+'\" \"'+@KUNDEN02_ORDNER_PREFIX+'\" \"'+@timeZone+'\" \"'+@ISO_LANG+'\" \"'+@rightsToUserGroup+'\""
			RES_MODUL_COMMAND="makeReservierungModul600.sh \"'+@documentRoot+'\" \"'+@ip+'\" \"'+@dbinstance+'\" \"'+@dbname+'\" \"'+@dbuser+'\" \"'+@KUNDEN02_ORDNER_PREFIX+'\" \"'+@timeZone+'\" \"'+@ISO_LANG+'\" \"'+@rightsToUserGroup+'\""
			

			SH_CRW_MODUL_REMOTE_COMMAND_INSTALL_LIVE="ssh '+@WEBSERVERSSHUSER+'@'+@WEBSERVERIP+' sh /home/cx9/updates/$CRW_MODUL_COMMAND_INSTALL_LIVE"
			SH_RES_MODUL_REMOTE_COMMAND_INSTALL_LIVE="ssh '+@WEBSERVERSSHUSER+'@'+@WEBSERVERIP+' sh /home/cx9/updates/$RES_MODUL_COMMAND_INSTALL_LIVE"

			SH_CRW_MODUL_REMOTE_COMMAND="ssh '+@WEBSERVERSSHUSER+'@'+@WEBSERVERIP+' sudo sh /home/cx9/updates/$CRW_MODUL_COMMAND"
			SH_RES_MODUL_REMOTE_COMMAND="ssh '+@WEBSERVERSSHUSER+'@'+@WEBSERVERIP+' sudo sh /home/cx9/updates/$RES_MODUL_COMMAND"


			
			GENERAL_MESSAGE="Executing command: $SH_CRW_MODUL_REMOTE_COMMAND_INSTALL_LIVE"
			bar "10" "$GENERAL_MESSAGE" "1"
			GENERAL_MESSAGE="Executing command: $SH_RES_MODUL_REMOTE_COMMAND_INSTALL_LIVE"
			bar "15" "$GENERAL_MESSAGE" "1" 

			GENERAL_MESSAGE="Executing command: $SH_CRW_MODUL_REMOTE_COMMAND"
			bar "17" "$GENERAL_MESSAGE" "1"
			GENERAL_MESSAGE="Executing command: $SH_RES_MODUL_REMOTE_COMMAND"
			bar "20" "$GENERAL_MESSAGE" "1"
			XMLProCallFileUpload=$LINUXDEB05Folder"temp/result_"$DATE_WITH_TIME".log"

			#create temp file
			echo 2>$XMLProCallFileUpload && chmod 0777 $XMLProCallFileUpload 
			echo `sshpass -p '+@WEBSERVERSSHUSERPW+' $SH_CRW_MODUL_REMOTE_COMMAND_INSTALL_LIVE` |& tee $XMLProCallFileUpload
			#hier log
			echo `sh uploadLogFile.sh "'+CAST(@MandantID AS VARCHAR(32))+'" "'+@environment+'" "createCRentWebFolder" "console" "1" "$XMLProCallFileUpload"`

			#create file again
			echo 2>$XMLProCallFileUpload && chmod 0777 $XMLProCallFileUpload
			#make update für crentweb
			echo `sshpass -p '+@WEBSERVERSSHUSERPW+' $SH_RES_MODUL_REMOTE_COMMAND_INSTALL_LIVE` |& tee $XMLProCallFileUpload
			#log results
			echo `sh uploadLogFile.sh "'+CAST(@MandantID AS VARCHAR(32))+'" "'+@environment+'" "createReservierungFolder" "console" "1" "$XMLProCallFileUpload"`




			#create temp file
			echo 2>$XMLProCallFileUpload && chmod 0777 $XMLProCallFileUpload 
			echo `sshpass -p '+@WEBSERVERSSHUSERPW+' $SH_RES_MODUL_REMOTE_COMMAND` |& tee $XMLProCallFileUpload
			#hier log
			echo `sh uploadLogFile.sh "'+CAST(@MandantID AS VARCHAR(32))+'" "'+@environment+'" "createReservierungFolder" "console" "1" "$XMLProCallFileUpload"`

			#create file again
			#echo 2>$XMLProCallFileUpload && chmod 0777 $XMLProCallFileUpload
			#make update für crentweb
			#echo `sshpass -p '+@WEBSERVERSSHUSERPW+' $SH_CRW_MODUL_REMOTE_COMMAND` |& tee $XMLProCallFileUpload
			#log results
			#echo `sh uploadLogFile.sh "'+CAST(@MandantID AS VARCHAR(32))+'" "'+@environment+'" "createCRentWebFolder" "console" "1" "$XMLProCallFileUpload"`


			#echo 2>$XMLProCallFileUpload && chmod 0777 $XMLProCallFileUpload
			#sh makeJasperMR.sh "'+@JasperBranch+'" "'+@KUNDEN02_ORDNER_PREFIX+'" "'+@abasTaskNumber+'" "'+@documentRoot+'" "'+@mandantName+'" "'+@ip+'" "'+@dbinstance+'" "'+@dbname+'" "'+@dbuser+'" "JASPER_ORDNER_'+@abasTaskNumber+'" "1" "'+@WEBSERVERIP+'" |& tee $XMLProCallFileUpload
			#echo `sh uploadLogFile.sh "'+CAST(@MandantID AS VARCHAR(32))+'" "'+@environment+'" "JasperMR" "console" "1" "$XMLProCallFileUpload"`

			#echo 2>$XMLProCallFileUpload && chmod 0777 $XMLProCallFileUpload
			#sh makeCRentWebMR.sh "'+@documentRoot+'" "'+@KUNDEN02_ORDNER_PREFIX+'" "'+@abasTaskNumber+'" "'+@documentRoot+'" "'+@mandantName+'" |& tee $XMLProCallFileUpload
			
			#echo `sh uploadLogFile.sh "'+CAST(@MandantID AS VARCHAR(32))+'" "'+@environment+'" "CRentWebMR" "console" "1" "$XMLProCallFileUpload"`
			
			
			WATING_TIME='+@nextExcutionTime+'
			echo "======== D E P L O Y     W A S    D O N E ============="
			echo "=== WATING TIME IN SECONDS FOR NEXT DEPLOYMENT: '+@nextExcutionTime+'. ==="
			timeout '+@nextExcutionTime+' "=== Remining time in seconds %s from '+@nextExcutionTime+' ==============="
			echo "======================================================="
			#sleep '+@nextExcutionTime+'
			exit 1
		'
	IF (@environment = 'LIVE')
		SET @instructions+='
			echo "Trigger manually the GIT '+@environment+' jasper and '+@environment+' C-Rent Web JOBS	"
			EXIT 1
		'
	--
	RETURN @instructions
END
GO
