CREATE FUNCTION [dbo].[getCRent60UpdateSHReservation](@MandantId INT = NULL, @environment VARCHAR(128)='ACC')
RETURNS nVARCHAR(MAX)
BEGIN
	DECLARE	@ip VARCHAR(255) = '', @dbname VARCHAR(255) = '', @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)='', 
	@dbinstance VARCHAR(512)='', @documentRoot VARCHAR(512)='', @mandantName VARCHAR(512)='', @abasTaskNumber VARCHAR(128)='00000',
	@JasperBranch VARCHAR(512)='master', @MainCRWBranch VARCHAR(512)='master'
	DECLARE @WEBSERVERIP VARCHAR(128) = '',@WEBSERVERSSHUSER VARCHAR(128) = '',@WEBSERVERSSHUSERPW VARCHAR(128) = ''
	DECLARE @ISO_LANG VARCHAR(16) = (SELECT ISNULL((SELECT iso FROM dbo.Language WHERE id = (SELECT systemLanguage_id FROM dbo.Mandant WHERE id=453)),@MandantId))
	DECLARE @KUNDEN02_ORDNER_PREFIX VARCHAR(128) = '_'+@environment
	DECLARE @timeZone VARCHAR(128) = 'Europe/Berlin'
	DECLARE @rightsToUserGroup VARCHAR(128) = 'cx9:www-data'
	DECLARE @nextExcutionTime VARCHAR(128) = '45'--CAST(ABS(CAST(NEWID() as binary(6)) % (1 + 50 - 30)) + 30 as varchar(8)) --between 30-50 secondes
	DECLARE	@ipLive VARCHAR(255) = '', @dbnameLive VARCHAR(255) = '', @dbuserLive VARCHAR(512)='', @dbinstanceLive VARCHAR(512)=''


	IF NOT EXISTS(SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE mandantId = @mandantId AND version = '6.0' 
					AND Environment = @environment 
					AND ISNULL(DB,'')<>''
					AND ISNULL(HOST,'')<>''
					AND ISNULL(DB_USER,'')<>''
					AND ISNULL(DB_USER_PW,'')<>''
					AND ISNULL(JasperBranch,'')<>''
					AND ISNULL(MainCRWBranch,'')<>''
					)
		BEGIN 
			RETURN '
			echo "nicht update faehig, bitte ACC Daten pflegen"
			exit 1'
		END 

	DECLARE @datasearchindex VARCHAR(128)='', @globalName VARCHAR(128)=''
	DECLARE @instructions nVARCHAR(MAX) = 
'#!/bin/bash 
#SH Updates
'
			
	IF( NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN
		SET @instructions+='
		echo "MandantId existiert nicht bitte pflege Daten in der DB install tool"
		exit 1
		'
		RETURN @instructions
	END
   
	IF( @environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS) )
	BEGIN
		SET @instructions+='
		echo "Environment ist nicht gueltig"
		exit 1
		'
		RETURN @instructions
	END 
	   
	IF (@environment <> 'DEFAULT' AND EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@environment))
		BEGIN
			SELECT TOP 1 @dbname=DB, @dbuser=DB_USER, @dbpassword=DB_USER_PW, 
			@ip=ISNULL(HOST,''),
			@datasearchindex = ISNULL(searchDataIndex,'IND'),
			@dbinstance=ISNULL(INSTANCE,''), @JasperBranch=JasperBranch, @MainCRWBranch=MainCRWBranch,
			@abasTaskNumber=ISNULL(ABAS_TASK_NO,''),@KUNDEN02_ORDNER_PREFIX=ISNULL(KUNDEN02_ORDNER_PREFIX,@KUNDEN02_ORDNER_PREFIX),
			@timeZone=ISNULL(timeZone,@timeZone),@rightsToUserGroup=ISNULL(rightsToUserGroup,@rightsToUserGroup),
			@WEBSERVERIP=ISNULL(WEBSERVERIP,''),@WEBSERVERSSHUSER=ISNULL(WEBSERVERSSHUSER,''),@WEBSERVERSSHUSERPW=ISNULL(WEBSERVERSSHUSERPW,'')
			FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@environment 	 
			 
		END
  --@ipLive VARCHAR(255) = '', @dbnameLive VARCHAR(255) = '', @dbuserLive VARCHAR(512)='', @dbinstanceLive      
    SELECT TOP 1 @ipLive=ISNULL(databaseIp,''), @dbnameLive=ISNULL(databaseName,''), @dbinstanceLive=ISNULL(databaseInstance,''), 
	@dbuserLive=dbo.GET_SH_ESCAPED_PWD(ISNULL(databaseUser,'')) FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MandantId AND type = 'DEFAULT' ORDER BY version desc
	SELECT @globalName=ISNULL(globalName,'_NOGlobalName'),@documentRoot=ISNULL(documentRoot,'_documentRoot'),
	@mandantName=dbo.stringReplaceMultiple_pattern(ISNULL(companyname,'noCompanyName'),'ä=ae;ü=ue;ö=oe;&=und;',';','=') FROM dbo.Mandant WHERE id=@MandantId
	IF (@environment IN ('LIVE','DEFAULT'))
		SET @KUNDEN02_ORDNER_PREFIX = '_'+@environment+'_600'
	IF (@environment <> 'ACC')
		SET @datasearchindex = 'noSearchIndex'		
	IF (@environment <> 'DEFAULT')
		SET @instructions+=
'DATE_WITH_TIME=$(date +%s)
LINUXDEB05Folder="/home/jmunoz/updates/"
cd $LINUXDEB05Folder
RES_MODUL_COMMAND="makeReservierungModul600.sh \"'+@documentRoot+'\" \"'+@ip+'\" \"'+@dbinstance+'\" \"'+@dbname+'\" \"'+@dbuser+'\" \"'+@KUNDEN02_ORDNER_PREFIX+'\" \"'+@timeZone+'\" \"'+@ISO_LANG+'\" \"'+@rightsToUserGroup+'\""
SH_RES_MODUL_REMOTE_COMMAND_INSTALL_LIVE="ssh '+@WEBSERVERSSHUSER+'@'+@WEBSERVERIP+' sh /home/cx9/updates/$RES_MODUL_COMMAND_INSTALL_LIVE"
SH_RES_MODUL_REMOTE_COMMAND="ssh '+@WEBSERVERSSHUSER+'@'+@WEBSERVERIP+' sudo sh /home/cx9/updates/$RES_MODUL_COMMAND"
