echo `sshpass -p '+@WEBSERVERSSHUSERPW+' $SH_RES_MODUL_REMOTE_COMMAND` |& tee $XMLProCallFileUpload
		'
	IF (@environment = 'DEFAULT')
		SET @instructions+='
			echo "Trigger manually the GIT '+@environment+' jasper and '+@environment+' C-Rent Web JOBS	"
			EXIT 1
		'
	--
	RETURN @instructions
END
GO
/****** Object:  UserDefinedFunction [dbo].[getDayNumber]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getDayNumber] (@shortname VARCHAR(2))
RETURNS INT --Author José March  29th. 2016
BEGIN
	DECLARE @result INT
	SET @result = 0
	SET  @result = (CASE @shortname WHEN 'Mo' THEN 1  WHEN 'Di' THEN 2 WHEN 'Mi' THEN 3  WHEN 'Do' THEN 4 WHEN 'Fr' THEN 5 WHEN 'Sa' THEN 6 WHEN 'So' THEN 7 END)
	RETURN @result
END
GO
/****** Object:  UserDefinedFunction [dbo].[getFormatDateFromString]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getFormatDateFromString] (@Datetime DATETIME, @FormatMask VARCHAR(32))
RETURNS VARCHAR(32)
AS
BEGIN
    DECLARE @StringDate VARCHAR(32)
    SET @StringDate = @FormatMask
    IF (CHARINDEX ('YYYY',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'YYYY', DATENAME(YY, @Datetime))
    ELSE IF (CHARINDEX ('YY',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'YY', RIGHT(DATENAME(YY, @Datetime),2))
    ELSE IF (CHARINDEX ('Y',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'Y', DATENAME(YY, @Datetime))
    IF (CHARINDEX ('Month',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'Month', DATENAME(MM, @Datetime))
    ELSE IF (CHARINDEX ('MON',@StringDate COLLATE SQL_Latin1_General_CP1_CS_AS)>0)
       SET @StringDate = REPLACE(@StringDate, 'MON',  LEFT(UPPER(DATENAME(MM, @Datetime)),3))
    ELSE IF (CHARINDEX ('Mon',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'Mon', LEFT(DATENAME(MM, @Datetime),3))
    ELSE IF (CHARINDEX ('MM',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'MM', RIGHT('0'+CONVERT(VARCHAR,DATEPART(MM, @Datetime)),2))
    ELSE IF (CHARINDEX ('M',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'M', RIGHT('0'+CONVERT(VARCHAR,DATEPART(MM, @Datetime)),2))
    IF (CHARINDEX ('DD',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'DD', RIGHT('0'+DATENAME(DD, @Datetime),2))
    ELSE IF (CHARINDEX ('D',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'D', RIGHT('0'+DATENAME(DD, @Datetime),2))
    IF (CHARINDEX ('H',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'H', RIGHT('0'+DATEPART(HH, @Datetime),2))
    IF (CHARINDEX ('i',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'i', RIGHT('0'+DATEPART(mi, @Datetime),2))
    IF (CHARINDEX ('s',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 's', RIGHT('0'+DATEPART(ss, @Datetime),2))
RETURN @StringDate
END
GO
/****** Object:  UserDefinedFunction [dbo].[getFormatDateTimeFromString]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[getFormatDateTimeFromString] (@Datetime DATETIME, @FormatMask VARCHAR(32))
RETURNS VARCHAR(32)
AS
BEGIN
	IF (ISDATE(@Datetime)=0)
		RETURN NULL
    DECLARE @StringDate VARCHAR(32)
    SET @StringDate = @FormatMask
    IF (CHARINDEX ('YYYY',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'YYYY', DATENAME(YY, @Datetime))
    ELSE IF (CHARINDEX ('YY',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'YY', RIGHT(DATENAME(YY, @Datetime),2))
    ELSE IF (CHARINDEX ('Y',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'Y', DATENAME(YY, @Datetime))
    IF (CHARINDEX ('Month',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'Month', DATENAME(MM, @Datetime))
    ELSE IF (CHARINDEX ('MON',@StringDate COLLATE SQL_Latin1_General_CP1_CS_AS)>0)
       SET @StringDate = REPLACE(@StringDate, 'MON',  LEFT(UPPER(DATENAME(MM, @Datetime)),3))
    ELSE IF (CHARINDEX ('Mon',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'Mon', LEFT(DATENAME(MM, @Datetime),3))
    ELSE IF (CHARINDEX ('MM',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'MM', RIGHT('0'+CONVERT(VARCHAR,DATEPART(MM, @Datetime)),2))
    ELSE IF (CHARINDEX ('M',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'M', RIGHT('0'+CONVERT(VARCHAR,DATEPART(MM, @Datetime)),2))
    IF (CHARINDEX ('DD',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'DD', RIGHT('0'+DATENAME(DD, @Datetime),2))
    ELSE IF (CHARINDEX ('D',@StringDate) > 0)
       SET @StringDate = REPLACE(@StringDate, 'D', RIGHT('0'+DATENAME(DD, @Datetime),2))

	IF (CHARINDEX('H', @StringDate) > 0)
		SET @StringDate = REPLACE(@StringDate, 'H', RIGHT('0'+DATENAME(HH, @Datetime),2))
	IF (CHARINDEX('i', @StringDate) > 0)
		SET @StringDate = REPLACE(@StringDate, 'i', RIGHT('0'+DATENAME(mi, @Datetime),2))
	IF (CHARINDEX('s', @StringDate) > 0)
		SET @StringDate = REPLACE(@StringDate, 's', RIGHT('0'+DATENAME(s, @Datetime),2))
			
RETURN @StringDate
END
GO
/****** Object:  UserDefinedFunction [dbo].[getHelpDefinitionVariablesFromTable]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getHelpDefinitionVariablesFromTable] (@TABLE_NAME NVARCHAR(2048) = NULL, @justFields NVARCHAR(MAX)='', @justFieldsSep NVARCHAR(1)=';')
RETURNS NVARCHAR(MAX)--Author José
BEGIN
	DECLARE @result NVARCHAR(MAX) = ''
	DECLARE @table TABLE(COLUMN_NAME NVARCHAR(128) NULL, IS_NULLABLE NVARCHAR(128) NULL, DATA_TYPE NVARCHAR(128) NULL, CHARACTER_MAXIMUM_LENGTH NVARCHAR(128) NULL, COLUMN_DEFAULT NVARCHAR(2048) NULL)
	DECLARE @COLUMN_NAME NVARCHAR(128) = NULL, @IS_NULLABLE NVARCHAR(128) = NULL, @DATA_TYPE NVARCHAR(128) = NULL, @CHARACTER_MAXIMUM_LENGTH NVARCHAR(128) = NULL, @COLUMN_DEFAULT NVARCHAR(2048) = NULL 
	DECLARE @TSQLFIELD_DEFINITION NVARCHAR(MAX) = ''
	IF EXISTS (SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TABLE_NAME)
		BEGIN
			INSERT INTO @table
			SELECT COLUMN_NAME, IS_NULLABLE, DATA_TYPE, CHARACTER_MAXIMUM_LENGTH,COLUMN_DEFAULT
			FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TABLE_NAME
												DECLARE help_table_field_definition CURSOR  
			   FOR  SELECT COLUMN_NAME, IS_NULLABLE, UPPER(DATA_TYPE), CHARACTER_MAXIMUM_LENGTH,ISNULL(COLUMN_DEFAULT,'NULL')  FROM @table
			OPEN help_table_field_definition  
			FETCH NEXT FROM help_table_field_definition INTO @COLUMN_NAME, @IS_NULLABLE, @DATA_TYPE, @CHARACTER_MAXIMUM_LENGTH, @COLUMN_DEFAULT
			IF (ISNULL(@justFields,'')<>'')
				DELETE FROM @table WHERE COLUMN_NAME NOT IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@justFields,@justFieldsSep))  
			WHILE @@FETCH_STATUS = 0  
			BEGIN  --@COLUMN_NAME NVARCHAR(128) = NULL 
				--SET @TSQLFIELD_DEFINITION = ''
				IF (@CHARACTER_MAXIMUM_LENGTH <=0)SET @CHARACTER_MAXIMUM_LENGTH=255 
				SET @TSQLFIELD_DEFINITION += N'DECLARE @'+@COLUMN_NAME+' '+CASE 
																					WHEN @DATA_TYPE IN ('VARCHAR','NVARCHAR') AND ISNUMERIC(@CHARACTER_MAXIMUM_LENGTH)=1 AND @IS_NULLABLE='YES' THEN @DATA_TYPE+'('+@CHARACTER_MAXIMUM_LENGTH+') = NULL '+CHAR(13)
																					WHEN @DATA_TYPE IN ('VARCHAR','NVARCHAR') AND ISNUMERIC(@CHARACTER_MAXIMUM_LENGTH)=1 AND @IS_NULLABLE='NO' THEN @DATA_TYPE+'('+@CHARACTER_MAXIMUM_LENGTH+') = '+REPLACE(REPLACE(@COLUMN_DEFAULT,'(',''),')','')+' '+CHAR(13)
																					WHEN @DATA_TYPE IN ('TEXT','NTEXT')  THEN 'NVARCHAR(MAX) = '+REPLACE(REPLACE(@COLUMN_DEFAULT,'(',''),')','')+' '+CHAR(13)
																					WHEN @DATA_TYPE IN ('BIGINT','INT','BIT', 'DECIMAL', 'MONEY', 'FLOAT', 'DECIMAL') THEN @DATA_TYPE+' = '+REPLACE(REPLACE(@COLUMN_DEFAULT,'(',''),')','')+' '+CHAR(13)
																					--WHEN @DATA_TYPE IN ('BIGINT','INT','BIT', 'DECIMAL', 'MONEY', 'FLOAT', 'DECIMAL') AND ISNUMERIC(@CHARACTER_MAXIMUM_LENGTH)=1 AND @IS_NULLABLE='NO' THEN @DATA_TYPE+'('+@CHARACTER_MAXIMUM_LENGTH+') = '''' '+CHAR(13)
																					ELSE @DATA_TYPE+' = '+REPLACE(REPLACE(@COLUMN_DEFAULT,'(',''),')','')+' '+CHAR(13)
																			   END 
    

				FETCH NEXT FROM help_table_field_definition	INTO @COLUMN_NAME, @IS_NULLABLE, @DATA_TYPE, @CHARACTER_MAXIMUM_LENGTH, @COLUMN_DEFAULT
	
			END   
			CLOSE help_table_field_definition
			DEALLOCATE help_table_field_definition 	
			IF (@TSQLFIELD_DEFINITION <> '')
				SET @result = @TSQLFIELD_DEFINITION	
		END

  RETURN @result
END
GO
/****** Object:  UserDefinedFunction [dbo].[getInfoKundenBeforeUpdate]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getInfoKundenBeforeUpdate](@MandantId INT = null, @environment VARCHAR(128) = 'ACC', @EnvironmentToBeUpdated VARCHAR(32)= NULL)
RETURNS NVARCHAR(MAX)
BEGIN
	DECLARE @result NVARCHAR(MAX) = '' 
	DECLARE @ormUrl VARCHAR(255) =  ''
	DECLARE @crwUrl VARCHAR(255) =  ''
	DECLARE @envTestFolder VARCHAR(255) =  ''
	IF (@EnvironmentToBeUpdated IS NULL) SET @EnvironmentToBeUpdated = dbo.GET_ISO_DATETIME(CURRENT_TIMESTAMP,'1800')
	--<p>- Nach erfolgreicher Livestellung sind nur die neuen User verwendbar. Der Zugriff auf die alte version mit alten Usern wird dann gesperrt.</p>
	DECLARE @ORM_TEST_MODULE VARCHAR(4096) = '<p>Sehr geehrte Damen und Herren,</p><br><br>
<p>Ein C-Rent Akzeptanz('+@environment+') -Update 6.0 wird abgeschlossen.</p>
<p>- Bitte machen Sie alle C-Rent '+@environment+' Instanzen zu.</p>
<p>- Ihr Update am '+@EnvironmentToBeUpdated+' geplannt.</p>
<p>- Ihr '+@environment+' C-Rent System wird innerhalb der nächsten zwei Stunden nicht erreichbar sein und es darf nicht gearbeitet werden.</p>
<p>- Wir melden uns, sobald der Prozess komplett abgeschlossen wurde.</p>
<p>- Wenden Sie sich bitte an unseren Support, wenn es zu Problemen kommt.</p><br><br>
<p>- (Falls Sie dieses Update verzogen möchten, dann geben Sie uns bitte so schnell wie möglich Bescheid).</p><br><br>
<p>Vielen Dank im Voraus.<br></p>'
	DECLARE @ORM_LIVE_MODULE VARCHAR(4096) = '<p>Sehr geehrte Damen und Herren,</p><br><br>
<p>Ihr '+@environment+' C-Rent System wird auf version 6.0 upgedatet.</p>
<p>- Bitte machen Sie alle C-Rent '+@environment+' Instanzen zu.</p>
<p>- Ihr Update ist am '+@EnvironmentToBeUpdated+' geplannt.</p>
<p>- Ihr '+@environment+' C-Rent System wird innerhalb der nächsten zwei Stunden nicht erreichbar sein und es darf nicht gearbeitet werden.</p>
<p>- Wir melden uns, sobald der Prozess komplett abgeschlossen wurde.</p>
<p>- Wenden Sie sich bitte an unseren Support, wenn es zu Problemen kommt.</p><br><br>
<p>- (Falls Sie dieses Update verschieben möchten, dann geben Sie uns bitte so schnell wie möglich Bescheid).</p><br><br>
<p>Vielen Dank im Voraus.<br></p>'
	IF(NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN 
		RETURN @result
	END
	IF(@Environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS))
	BEGIN
		RETURN 'INVALID_ENVIRONMENT' 
	END

	SET @result+= CASE WHEN @environment <> 'LIVE'  THEN @ORM_TEST_MODULE ELSE @ORM_LIVE_MODULE END

	RETURN @resultEND
GO
/****** Object:  UserDefinedFunction [dbo].[getKU_FSUpdateCompareSchemaName]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getKU_FSUpdateCompareSchemaName](@MandantId INT = null, @environment VARCHAR(128) = 'ACC',@compareType NVARCHAR(128) = 'SCHEMA' )
RETURNS VARCHAR(MAX)
BEGIN
	DECLARE @name VARCHAR(MAX)
	DECLARE @abasId INT

	DECLARE @ip VARCHAR(255), @dbname VARCHAR(255), @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)=''
	DECLARE @XMLCompareData XML

	SET @name = 'INVALID_ABAS_ID'

	-- TODO @Environment berücksichtigen
	IF(NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN 
		RETURN @name
	END
	IF(@Environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS))
	BEGIN
		RETURN 'INVALID_ENVIRONMENT' 
	END
	IF(@compareType NOT IN ('DATA','SCHEMA'))
	BEGIN
		RETURN 'INVALID_COMPARE_TYPE'
	END     
    
  
	SELECT TOP 1 @ip=ISNULL(databaseIp,'')+CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '_'+databaseInstance ELSE '' END, 
			@dbname=ISNULL(databaseName,''),
			@dbuser=ISNULL(databaseUser,''), @abasId=ISNULL(abasId,0) FROM dbo.Mandant WHERE id=@MandantId	
	IF( EXISTS(SELECT TOP 1 DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @Environment AND TYPE = @compareType AND MANDANT_ID = @MandantId) )	
		BEGIN		
			SELECT TOP 1 @XMLCompareData = DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @Environment AND TYPE = @compareType AND MANDANT_ID = @MandantId
			IF (@XMLCompareData IS NULL)--first execute the xml PFLEGE_XML_MANDANT_ENVIRONMENT
				RETURN 'INVALID_ENVIRONMENT'				
			SET @ip = ISNULL(@XMLCompareData.value('(/Project/DataSource2/ServerName/text())[1]', 'NVARCHAR(128)'),'')
			SET @dbname = ISNULL(@XMLCompareData.value('(/Project/DataSource2/DatabaseName/text())[1]', 'NVARCHAR(128)'),'')
			--SET @dbuser = ISNULL(@XMLCompareData.value('(/Project/DataSource2/Username/text())[1]', 'NVARCHAR(128)'),'')
		END		
	IF EXISTS(SELECT * FROM MANDANT_DB_ENVIRONMENT WHERE mandant_id=@MandantId AND type=@environment and version = '6.0')
	BEGIN
			SELECT TOP 1 @dbname=ISNULL(databaseName,''), @dbuser=ISNULL(databaseUser,''), @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
			@ip=ISNULL(databaseIp,'')+
			   CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '_'+databaseInstance ELSE '' END + 
				CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(databasePort)=1 /*intern extern unterschied*/  THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
				,@dbname = ISNULL(databaseName,'_no_dbname')
				--,@dbuser = ISNULL(databaseUser,'_no_username')
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@environment and version = '6.0'	 		
	END		    
    IF (@compareType IN ('SCHEMA'))
		BEGIN  --crent_schema_deployment v KU-SQLACC.KUNDEN.LOCAL.ACC_wuddi (83409)
	    
		    SET @name = '\\ku-fs01.kunden.local\deployment\Schema Compare\crent_schema_deployment v '
			SET @name += REPLACE(REPLACE(@ip,'\','_'),',','_')+'.'+@dbname+' ('+CAST(@abasId AS VARCHAR(32))+')'+'.scp'
			SET @name = REPLACE(@name,'/','_')
		END  
    IF (@compareType IN ('DATA'))
		BEGIN  --crentdev_static_data v 192.168.254.209.KUDB53109ACC.ACC_mages (82838)	    
		    SET @name = '\\ku-fs01.kunden.local\deployment\Data Compare\crentdev_static_data v '
			SET @name += REPLACE(REPLACE(@ip,'\','_'),',','_')+'.'+@dbname+' ('+CAST(@abasId AS VARCHAR(32))+')'+'.sdc'			
			SET @name = REPLACE(@name,'/','_')
		END  
 
	--
	RETURN @nameEND
GO
