/****** Object:  UserDefinedFunction [dbo].[GetLastDayOfTheMonth]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
Create FUNCTION [dbo].[GetLastDayOfTheMonth](@GivenDate datetime)
returns datetime
as
Begin
Return dateadd(day,-1* day(dateadd(month,1,@GivenDate)),dateadd(month,1,@GivenDate))

End
GO
/****** Object:  UserDefinedFunction [dbo].[GetLastNextDay]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GetLastNextDay](@GivenDate DATETIME, @dayNumber INT)
returns datetime
as
BEGIN
	--DECLARE @todayDayNumber INT = dbo.getDayNumber(dbo.GET_WEEKDAY(CURRENT_TIMESTAMP))
	DECLARE @addDays INT = @dayNumber-1
	--IF @dayNumber = 1
	--	SET @addDays=0
	DECLARE @result DATETIME = dateadd(day,7+@addDays,@GivenDate)
RETURN @result

End
