CREATE FUNCTION [dbo].[getLinkedServerArchivDB](@MANDANT_ID INT = NULL, @ENVIRONTMENT VARCHAR(32) = 'LIVE', @LinkedSufix BIT = 0)
RETURNS @data TABLE (linkedServerName VARCHAR(255) NULL, ServerName VARCHAR(128) NULL, DatabaseName VARCHAR(128) NULL, Username NVARCHAR(128) NULL, Password NVARCHAR(128) NULL)
BEGIN
	DECLARE @name VARCHAR(MAX), @linkedServerName VARCHAR(255)=''
	DECLARE @abasId INT = ISNULL((SELECT TOP 1 abasId FROM dbo.Mandant WHERE id= (SELECT TOP 1 mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @MANDANT_ID)),'123456')

	DECLARE @ip VARCHAR(255)='', @dbname VARCHAR(255)='', @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)=''
	DECLARE @XMLCompareData XML

	SET @name = ''
	/*IF(( EXISTS(SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId=@MANDANT_ID AND Environment = @ENVIRONTMENT AND ISNULL(ARCHIV_DB,'')='' AND ISNULL(ARCHIV_HOST,'')=''  AND ISNULL(ARCHIV_DB_USER,'')='') ) )
	BEGIN 
			
		RETURN
	END */
 	
    IF (EXISTS(SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId=@MANDANT_ID AND Environment = @ENVIRONTMENT AND ISNULL(ARCHIV_DB,'')<>'' AND ISNULL(ARCHIV_HOST,'')<>''  AND ISNULL(ARCHIV_DB_USER,'')<>''))
	BEGIN
			SELECT TOP 1 @dbname=ISNULL(ARCHIV_DB,''), 
			@dbuser=ISNULL(ARCHIV_DB_USER,''), 
			@dbpassword=dbo.SEC_GetPWCOde(ISNULL(ARCHIV_DB_USER,'')), 
			@ip=ISNULL(ARCHIV_HOST,'')+
			CASE WHEN ISNULL(ARCHIV_INSTANCE,'')<>'' THEN '\'+ARCHIV_INSTANCE ELSE '' END + 
			CASE WHEN dbo.isClientExtern(MandantId)=1 AND ISNUMERIC(ARCHIV_PORT)=1 /*intern extern unterschied*/  THEN ','+CAST(ARCHIV_PORT AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
			,@dbname = ISNULL(ARCHIV_DB,'_no_dbname')
				--,@dbuser = ISNULL(databaseUser,'_no_username')
			FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId= @MANDANT_ID AND Environment = @ENVIRONTMENT
			SET @linkedServerName = REPLACE(REPLACE(@ip,'\','_'),',','_') 
			SET @linkedServerName = REPLACE(@linkedServerName,'.','_')
			SET @linkedServerName = REPLACE(@linkedServerName,'/','_')
			IF (@LinkedSufix = 1)
				SET @linkedServerName = 'LINKED_'+@linkedServerName+'_'+@dbname
			ELSE 
				SET @linkedServerName = 'LINKED_'+@linkedServerName
			
			INSERT INTO @data
				SELECT @linkedServerName, @ip,@dbname,@dbuser,@dbpassword
 	
	END
	RETURNEND
GO
