			SET @linkedServerName = REPLACE(@linkedServerName,'.','_')
			SET @linkedServerName = REPLACE(@linkedServerName,'/','_')
			SET @linkedServerName = 'LINKED_'+@linkedServerName
			
			INSERT INTO @data
				SELECT @linkedServerName, @ip,@dbname,@dbuser,@dbpassword
 	
	END
	RETURNEND
