CREATE FUNCTION [dbo].[getLocalNameDeploymentFileByMandandtEnvironmentPK](@MandantEnvPK INT = null ,@compareType NVARCHAR(128) = 'SCHEMA', @subFolder NVARCHAR(255) = '')
RETURNS VARCHAR(MAX)
BEGIN
	DECLARE @name VARCHAR(MAX)
	DECLARE @abasId INT = ISNULL((SELECT TOP 1 abasId FROM dbo.Mandant WHERE id= (SELECT TOP 1 mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @MandantEnvPK)),'123456')

	DECLARE @ip VARCHAR(255)='', @dbname VARCHAR(255)='', @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)=''
	DECLARE @XMLCompareData XML

	SET @name = 'INVALID_MAND_ENV6_PK'
	SET @subFolder = ISNULL(@subFolder,'')
 	/*SET @subFolder = REPLACE(@subFolder,'\','')
	SET @subFolder = REPLACE(@subFolder,'/','')*/
	DECLARE @deploymentBasePath NVARCHAR(2048) = '\\ku-fs01.kunden.local\deployment\'+@subFolder+'\'
	IF (@subFolder = '') 
		SET @deploymentBasePath = '\\ku-fs01.kunden.local\deployment\'
	DECLARE @deploymentBasePathFilename NVARCHAR(4000) = ''
	DECLARE @deploymentBasePathFileContents NVARCHAR(MAX) = ''
	-- TODO @Environment berücksichtigen
	IF(NOT( EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK=@MandantEnvPK and version in ('6.0','MASTER')) ) )
	BEGIN 
		RETURN @name
	END
 
	IF(@compareType NOT IN ('DATA','SCHEMA'))
	BEGIN
		RETURN 'INVALID_COMPARE_TYPE'
	END    
 	
    IF (EXISTS(SELECT * FROM MANDANT_DB_ENVIRONMENT WHERE pk= @MandantEnvPK and version in ('6.0','MASTER')))
	BEGIN
			SELECT TOP 1 @dbname=ISNULL(databaseName,''), 
			@dbuser=ISNULL(databaseUser,''), 
			@dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
			@ip=ISNULL(databaseIp,'')+
			CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '_'+databaseInstance ELSE '' END + 
			CASE WHEN dbo.isClientExtern(mandant_id)=1 AND ISNUMERIC(databasePort)=1 /*intern extern unterschied*/  THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
			,@dbname = ISNULL(databaseName,'_no_dbname')
				--,@dbuser = ISNULL(databaseUser,'_no_username')
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE pk= @MandantEnvPK  and version in ('6.0','MASTER')	 		
	END		    
	
    IF (@compareType IN ('SCHEMA'))
		BEGIN  --crent_schema_deployment v KU-SQLACC.KUNDEN.LOCAL.ACC_wuddi (83409)
	    
		    SET @name = @deploymentBasePath+'Schema Compare\crent_schema_deployment_v_'
			
			SET @name += REPLACE(REPLACE(@ip,'\','_'),',','_')+'.'+@dbname+'_('+CAST(@abasId AS NVARCHAR(32))+')'+'.scp'
			--SET @name = REPLACE(@name,' ','_')
			RETURN @name
			SET @name = REPLACE(@name,'/','_')
		END  
    IF (@compareType IN ('DATA'))
		BEGIN  --crentdev_static_data v 192.168.254.209.KUDB53109ACC.ACC_mages (82838)	    
		    SET @name = @deploymentBasePath+'Data Compare\crentdev_static_data_v_'
			SET @name += REPLACE(REPLACE(@ip,'\','_'),',','_')+'.'+@dbname+'_('+CAST(@abasId AS NVARCHAR(32))+')'+'.sdc'			
			SET @name = REPLACE(@name,'/','_')
			--SET @name = REPLACE(@name,' ','_')
		END  
 
	--
	RETURN @nameEND
GO
