/****** Object:  UserDefinedFunction [dbo].[getSHA1PWD]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getSHA1PWD] (@password VARCHAR(255), @timestamp BIGINT, @encodePWD BIT = 1, @rounds INT = 1) 
RETURNS VARCHAR(1024) --Autor José
	BEGIN 
		DECLARE @passwordEncrypted VARCHAR(255)
		DECLARE @superTimestamp BIGINT
		DECLARE @passwordSUMOrd BIGINT  
		DECLARE @passwordCode VARCHAR(MAX)  
		DECLARE @result VARCHAR(1024)
		
		SET @passwordCode = dbo.SEC_GetPWCOde(@password)
		IF(@encodePWD = 0)
			SET @passwordCode = (@password)
		SET @passwordSUMOrd = dbo.GetSumASCII(@passwordCode)
		SET @superTimestamp = @timestamp * @passwordSUMOrd 
		SET @passwordEncrypted =  master.dbo.fn_varbintohexstr(HASHBYTES('SHA1',@passwordCode+CONVERT(VARCHAR,@superTimestamp))) 
		--RETURN @passwordEncrypted
		IF(@rounds > 1)
		  BEGIN
			WHILE (1 < @rounds)
			BEGIN
			  SET @result =  SUBSTRING(@passwordEncrypted, 3, LEN(@passwordEncrypted))           
			  SET @passwordEncrypted =  master.dbo.fn_varbintohexstr(HASHBYTES('SHA1',@result)) 
			  SET @rounds = @rounds -1 
			END
			--RETURN @result 
           END          
		SET @result =  SUBSTRING(@passwordEncrypted, 3, LEN(@passwordEncrypted)) 
		--SELECT @result AS result, @superTimestamp AS suppertime, @passwordCode AS passcode, @passwordSUMOrd AS ord,
		--HASHBYTES('SHA1',@passwordCode+CONVERT(VARCHAR,@superTimestamp)) AS resultss
		RETURN @result
	END 
GO
/****** Object:  UserDefinedFunction [dbo].[GetSumASCII]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[GetSumASCII] (@string varchar(255))
RETURNS INT
BEGIN
DECLARE @str VARCHAR(255)
DECLARE @t INT
DECLARE @result INT
DECLARE @zeichen CHAR(1)
SET @str = @string
  SET @t=1
  SET @result = 0
  WHILE (@t<LEN(@str)+1)
    BEGIN
      SET @zeichen=SUBSTRING(@str,@t,1)    
      SET @result=@result+ASCII(@zeichen)     
      SET @t=@t+1
    END
RETURN @result  
END
GO
/****** Object:  UserDefinedFunction [dbo].[getTSQLCleanACCDB]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
