CREATE FUNCTION [dbo].[getTSQLCleanACCDB] ( @dbname VARCHAR(128))
RETURNS VARCHAR(MAX)
BEGIN
	IF ((@dbname IS NULL OR @dbname = '') )
		RETURN ''
	 
	DECLARE @getTSQLCleanACCDB VARCHAR(MAX) =
'
DECLARE @SERVER_IP VARCHAR(128) = ISNULL((SELECT TOP 1 dec.local_net_address FROM sys.dm_exec_connections AS dec WHERE dec.session_id = @@SPID),'''')
DECLARE @SERVER_NAME VARCHAR(128) = ISNULL((@@SERVERNAME),'''')
IF (@SERVER_IP = ''192.168.253.209'' AND @SERVER_NAME = ''KU-SQLACC'')
	BEGIN	    
	    USE ['+@dbname+']
		DECLARE @dbname VARCHAR(128) = DB_NAME()
		IF (CHARINDEX(''ACC_'',@dbname)> 0 AND @dbname LIKE ''ACC_%'') --just ACC Nomeklatur / doppelte Prüfung
			BEGIN		
				DECLARE @dbLogicFilename1 VARCHAR(128) = FILE_NAME(1)
				DECLARE @dbLogicFilename2 VARCHAR(128) = FILE_NAME(2)
				DECLARE @dbSize FLOAT = NULL
				DECLARE @dbSizeVorOptimierung VARCHAR(128) = NULL
				DECLARE @dbSizeNachOptimierung VARCHAR(128) = NULL

				PRINT ''processing:... ''+@dbname
				PRINT ''db logic name: ''+@dbLogicFilename1
				PRINT ''db logic name: ''+@dbLogicFilename2

				DECLARE @Query VARCHAR(1024) = ''''
				DECLARE @tableSynonym VARCHAR(1024) = ''''
				DECLARE @synonymCounter INT = 0 
				WHILE EXISTS(SELECT * FROM SYS.SYNONYMS WHERE name NOT LIKE ''LINKED_TRESOR_%'')
					BEGIN
						SET @tableSynonym = (SELECT TOP 1 name FROM SYS.SYNONYMS)
						SET @Query = ''DROP SYNONYM dbo.''+@tableSynonym
						PRINT ''Synonym dbo.''+@tableSynonym+'' wurde gelöscht.''
						EXEC (@Query)
						SET @synonymCounter+=1
					END
				PRINT ''Es wurden insgesamt '' + CAST(@synonymCounter AS VARCHAR(32)) + '' Synonyme gelöscht.''

				SELECT @dbSize =  SUM((size * 8) / 1024)  FROM ['+@dbname+'].sys.database_files WHERE file_id IN (1,2)
				SELECT @dbSizeVorOptimierung = CAST( (@dbSize/1024.0) AS VARCHAR(128))+'' (GB)'' 

				TRUNCATE TABLE dbo.MIETVERTRAEGEAENDERUNGEN
				TRUNCATE TABLE dbo.AUTOSAENDERUNGEN
				TRUNCATE TABLE dbo.KUNDENAENDERUNGEN
				--TRUNCATE TABLE dbo.DOCS_REL_OBJ
				--TRUNCATE TABLE dbo.DOCS_DOCS
				IF EXISTS(SELECT 1 FROM sys.columns  WHERE Name = N''PK_SIGNATURE'' AND Object_ID = Object_ID(N''dbo.DOCS_REL_OBJ''))
					DELETE FROM dbo.DOCS_DOCS WHERE PK NOT IN (SELECT PK_DOCS FROM dbo.DOCS_REL_OBJ WHERE PK_SIGNATURE IS NOT NULL)
				TRUNCATE TABLE dbo.bilder		 
 
				DBCC SHRINKDATABASE (@dbname)
				DBCC SHRINKFILE (@dbLogicFilename1)
				DBCC SHRINKFILE (@dbLogicFilename2)
				SELECT @dbSize =  SUM((size * 8) / 1024)  FROM ['+@dbname+'].sys.database_files WHERE file_id IN (1,2)
				SELECT @dbSizeNachOptimierung = CAST( (@dbSize/1024.0) AS VARCHAR(128))+'' (GB)''	
				--SELECT @dbSizeVorOptimierung[vor],@dbSizeNachOptimierung[nach],''['+@dbname+']''[dbname],''['+@dbname+']'',''['+@dbname+']'',''['+@dbname+']''		
			END
		--ELSE SELECT 0[vor],0[nach],''['+@dbname+']''[dbname],''['+@dbname+']'',''['+@dbname+']'',''['+@dbname+']''	
	END 
--ELSE SELECT 0[vor],0[nach],''['+@dbname+']''[dbname],''['+@dbname+']'',''['+@dbname+']'',''['+@dbname+']''		
'
	RETURN @getTSQLCleanACCDB
END
GO
/****** Object:  UserDefinedFunction [dbo].[getTSQLCreateDBFROMTO]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[getTSQLCreateDBFROMTO] ( @fromDB VARCHAR(128), @BACKUPTO VARCHAR(256) = '\\ku-fs01.kunden.local\dbtransfer\', @dbTarget VARCHAR(255) = '', @dbLogicFile1Target VARCHAR(255) = '', @dbLogicFile2Target VARCHAR(255) = '', @typ VARCHAR(32)='restore')
RETURNS VARCHAR(MAX)
BEGIN  --Author José
	IF ((@fromDB IS NULL OR @fromDB = '') OR (@BACKUPTO = '' OR @BACKUPTO IS NULL) OR (@dbLogicFile1Target = '' OR @dbLogicFile1Target IS NULL) OR (@dbLogicFile2Target = '' OR @dbLogicFile2Target IS NULL))
		RETURN ''
    IF (@dbTarget IS NULL OR @dbTarget = '') 
		SET @dbTarget = 'ACC_'+LOWER(@fromDB)
	DECLARE @BACKUPTOFINAL VARCHAR (2048) = @BACKUPTO + @fromDB+'.bak'
	DECLARE @targetDBUser VARCHAR (128) = SUBSTRING(@fromDB,1,4)+'acc'
	DECLARE @targetDBUserPW VARCHAR (128) = dbo.SEC_GetPWCOde(@targetDBUser)
	DECLARE @getTSQLCreateDBLogin VARCHAR(MAX) =

'   USE master;
	IF NOT EXISTS (SELECT * FROM sys.server_principals WHERE name = N'''+@targetDBUser+''')
		CREATE LOGIN ['+@targetDBUser+'] WITH PASSWORD = '''+@targetDBUserPW+'''

	USE ['+@dbTarget+'] 
	IF NOT EXISTS (SELECT * FROM sys.database_principals WHERE name = N'''+@targetDBUser+''')
	BEGIN
		CREATE USER ['+@targetDBUser+'] FOR LOGIN ['+@targetDBUser+']
		EXEC sp_addrolemember N''db_owner'', N'''+@targetDBUser+'''
		EXEC sp_addsrvrolemember '''+@targetDBUser+''', ''sysadmin'' 
	END		 
 
'
	IF (@typ = 'restore')
		RETURN '
	IF DB_ID('''+@dbTarget+''') IS NOT NULL  -- Vorhandene DB droppen, wenn vorhanden*, und zwar so dass auch offene Verbindungen getrennt werden.
		BEGIN
			USE [master]
			EXEC msdb.dbo.sp_delete_database_backuphistory @database_name = N'''+@dbTarget+'''
			ALTER DATABASE ['+@dbTarget+'] SET SINGLE_USER WITH ROLLBACK IMMEDIATE
			DROP DATABASE ['+@dbTarget+']		 
		END			
	-- ACC DB wiederherstellen, auf dem ACC DB Server (bis auf weiteres immer der 192.168.253.209)
	-- *Prüfung ob vorhanden müsste erst noch eingebaut werden 
	RESTORE DATABASE ['+@dbTarget+'] FROM  DISK = N'''+@BACKUPTOFINAL+''' WITH  FILE = 1, MOVE N'''+@dbLogicFile1Target+''' TO N''F:\ACCDBs\'+@fromDB+'.mdf'',  MOVE N'''+@dbLogicFile2Target+''' TO N''F:\ACCDBs\'+@dbTarget+'_1.LDF'',  NOUNLOAD,  REPLACE,  STATS = 5 		'
	IF (@typ = 'rename')
		RETURN '
USE ['+@dbTarget+'];
ALTER DATABASE ['+@dbTarget+'] MODIFY FILE (NAME=N'''+@dbLogicFile1Target+''', NEWNAME=N'''+@dbTarget+''');
USE ['+@dbTarget+'];
ALTER DATABASE ['+@dbTarget+'] MODIFY FILE (NAME=N'''+@dbLogicFile2Target+''', NEWNAME=N'''+@dbTarget+'_log'');'
	IF (@typ = 'login')
		RETURN @getTSQLCreateDBLogin

 
	RETURN ''
END
GO
