BEGIN
	DECLARE @result NVARCHAR(MAX) = '' 
	DECLARE @ormUrl VARCHAR(255) =  ''
	DECLARE @crwUrl VARCHAR(255) =  ''
	DECLARE @envTestFolder VARCHAR(255) =  ''
	DECLARE @environment_auxiliar VARCHAR(128) = CASE WHEN @environment = 'LIVE' THEN 'DEFAULT' ELSE @environment END
	DECLARE @ORM_IN_USE BIT = CASE WHEN (EXISTS((SELECT * FROM dbo.MANDANT_MODULE_ALTE_STRUKTUR WHERE MANDANT_ID = @MandantId AND Modul = 'ORM' AND enabled='J' AND MENVPK IN (SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@MandantId AND type = @environment_auxiliar) ))) THEN 1 ELSE 0 END
	DECLARE @CRW_IN_USE BIT = CASE WHEN (EXISTS((SELECT * FROM dbo.MANDANT_MODULE_ALTE_STRUKTUR WHERE MANDANT_ID = @MandantId AND Modul = 'CRENTWEB' AND enabled='J' AND MENVPK IN (SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@MandantId AND type = @environment_auxiliar) ))) THEN 1 ELSE 0 END
	DECLARE @ORM_AVAILABILITY_PLAN_IN_USE BIT = CASE WHEN (EXISTS((SELECT * FROM dbo.MANDANT_MODULE_ALTE_STRUKTUR WHERE MANDANT_ID = @MandantId AND Modul = 'ORM_AVAILABILITY_PLAN' AND enabled='J' AND MENVPK IN (SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@MandantId AND type = @environment_auxiliar) ))) THEN 1 ELSE 0 END

	--
	--<p>- Nach erfolgreicher Livestellung sind nur die neuen User verwendbar. Der Zugriff auf die alte version mit alten Usern wird dann gesperrt.</p>
	DECLARE @ORM_TEST_MODULE VARCHAR(4096) = '<p>Sehr geehrte Damen und Herren,</p><br><br>
 <p>Das Akzeptanz('+@environment+') -Update 6.0 wurde erfolgreich abgeschlossen.</p>
<p>- Ab jetzt kann '+@environment+' C-Rent Datenbank getestet werden.</p>
<p>- Ihre neuen C-Rent 6.0 Releases werden durch ein Continuous Delivery Deployment ausgeliefert,
 nur wenn C-Rent alle anvisierten Features enthält, problemlos läuft und in der Qualitätsüberprüfung keine gravierenden Mängel aufweist.
 C-Rent 6.0 enthält das Updater-Modul, dies soll von Ihrem Antivirensystem zugelassen werden, damit die neuen Releases ausgeliefert werden können.</p>
<p>- Sollte der Kunde Interesse an einem zusätzlichen Modul haben, dann kommt er gerne auf uns zu.</p>'+
'<p>- [die Anmeldung auf dem RDP erfolgt wie vorher und<br></p>
<p>Akzeptanz C-Rent EXE befindet sich unter M:\CRentACCLNKs (Falls bei CX9 gehostet wird, falls nicht, dann unter C:\ oder unter D:\ oder nach der Kunden EDV Infrastruktur)]<br></p>						 
						
						'
						--montags = day 1
	DECLARE @nextUpdateDate1 VARCHAR(32) = (select dbo.getFormatDateFromString(dbo.GetLastNextDay(CURRENT_TIMESTAMP,1),'d.m.Y'))
	DECLARE @nextUpdateDate2 VARCHAR(32) = (select dbo.getFormatDateFromString(dbo.GetLastNextDay(DATEADD(day,7,CURRENT_TIMESTAMP),1),'d.m.Y'))
	SET @ORM_TEST_MODULE += 
'
<p>
Dieses Update wurde von C-Rent version '+dbo.GET_MANDANT_UPDATE_FIELD(505,'fromversion')+' auf C-Rent version 6.0 mit Release '+dbo.GET_GIT_LAST_RELEASE_BRANCH()+' durchgeführt (Ihre Ausdrucke werden in Laufe der Woche für version 6.0 konvertiert und aktualisiert)
'
	IF @environment_auxiliar = 'ACC'
		BEGIN

IF dbo.isClientExtern(@MandantId) = 1
 SET @ORM_TEST_MODULE+='
@Tobias: Wir brauchen die konvertierten Ausdrucken bitte.

Anleitung ACC C-Rent Verknüpfungen
 
Um das C-Rent in der ACC Umgegebung zu starten, muss eine Verknüpfung erstellt werden, welche die C-Rent .ini Datei mit den Zugangsparametern als Parameter dem Aufruf der
exe hinzufügt.
In unserer Umgebung geschieht dies vollautomatisch, jedoch können wir das nur in der uns bekannten und bei uns gehosteten Struktur leisten.

Nehmen wir mal an, das C-Rent (die crent.exe) liegt unter C:\Crent\(crent.exe)  bzw. C:\Crent-ACC\(crent.exe) und der User Ludwig hat sein Home Verzeichnis in C:
\Users\Ludwig, sprich die crent.ini Datei und die crent-acc.ini Datei liegen in C:\Users\Ludwig\Documents\(crent.ini|crent-acc.ini).

In den Eigenschaften der Verknüpfung muss als "Ziel:" folgendes stehen:

Verknüpfung für die Echtumgebung:

Ziel: C:\Crent\crent.exe %USERPROFILE%\Documents\crent.ini    (Streng genommen unnötig, da diese Datei als default Einprogrammiert ist)
Ausführen in: C:\Crent\

Verknüpfung für die Akzeptanzumgebung:

Ziel: C:\Crent-ACC\crent.exe %USERPROFILE%\Documents\crent-acc.ini
Ausführen in: C:\Crent-ACC\

Die crent-acc.ini sollte aus der crent.ini kopiert, und darin dann der Datenbankname (Zeile 3, direkt nach Server IP/Name) und der Loginname (Zeile 5, direkt vor dem
Datenbank Konnektor) für den SQL Server angepasst werden. Die anderen Werte sollen nicht verändert werden.

Dieser Weg ist der von uns vorgeschlagene. Es gibt andere Methoden die technisch funktionieren, jedoch führen diese unserer Erfahrung nach zu erhöhtem
Supportaufkommen und werden daher nicht unterstützt.
'
SET @ORM_TEST_MODULE+=
'
Ich kann ein Live Update am Montag '+@nextUpdateDate1+' oder am Montag den '+@nextUpdateDate1+' nach 17 Uhr anbieten. 
Bitte bestätigen Sie einen Termin.
</p>'
		END
	DECLARE @ORM_LIVE_MODULE VARCHAR(4096) = '<p>Sehr geehrte Damen und Herren,</p><br><br>
<p>Das C-Rent '+@environment+' -Update 6.0 wurde erfolgreich abgeschlossen.</p>
<p></p>
<p>- Ihre neuen C-Rent 6.0 Releases werden durch ein Continuous Delivery Deployment ausgeliefert,
 nur wenn C-Rent alle anvisierten Features enthält, problemlos läuft und in der Qualitätsüberprüfung keine gravierenden Mängel aufweist.
 C-Rent 6.0 enthält das Updater-Modul, dies soll von Ihrem Antivirensystem zugelassen werden, damit die neuen Releases ausgeliefert werden können.</p>
<p>- Wenden Sie sich bitte an unseren Support, wenn es zu Problemen kommt. </p>
<p>- Im Liveupdate werden nur die Module übernommen, die Sie beauftragt haben.</p> 
<p>- Sollten Sie Interesse an einem zusätzlichen Modul haben, kommen Sie gerne auf uns zu.</p>'
	IF(NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN 
		RETURN @result
	END
	IF(@Environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS))
