    SELECT TOP 1 @ormUrl=ormUrl, @crwUrl=crwUrl FROM dbo.Mandant WHERE id=@MandantId
	SET @envTestFolder = ISNULL((SELECT KUNDEN02_ORDNER_PREFIX FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId=@MandantId AND Environment = @environment),'_test')
    SET @ormUrl=REPLACE(@ormUrl,'reservierung_rd','reservierung_rd'+@envTestFolder)
    SET @crwUrl=REPLACE(@crwUrl,'crentweb','crentweb'+@envTestFolder)
/*- Da die neue version 6.0 eine hochmoderne homogene Struktur voraussetzt, die sich mit den jetzigen Benutzern nicht abbilden lässt, erhalten Sie neue Benutzer für diese Exe. Die neuen User sind bereits angelegt und stehen unten. Die aktuellen/alten User haben weiterhin den gewohnten Zugriff auf die Liveumgebung.
- Für die Abnahme gibt es die ersten z.B. 3  User mit Zugriff auf diese Umgebung.*/
	SET @result+= CASE WHEN @environment <> 'LIVE'  THEN @ORM_TEST_MODULE ELSE @ORM_LIVE_MODULE END
	IF (@ORM_IN_USE = 1 AND @ORM_AVAILABILITY_PLAN_IN_USE = 1) 
		BEGIN
			SET @result+='<br><p><b>Online '+@environment+' Reservierungsmodul Link unter:</b><br>
				<a href="'+@ormUrl+'" title="CX9 Online Reservierungsmodul">'+@environment+' Reservierungsmodul</a>	
				<br>'+@ormUrl+'
				<p><b>Online '+@environment+' ORM Angebotsslider (Modul ORM_ANGEBOTE -> Falls vorhanden ) Link unter :</b><br>
				<a href="'+@ormUrl+'/offers" title="CX9 Online Reservierungsmodul Angebotsslider">'+@environment+' Reservierungsmodul Angebotsslider</a>	
				<br>'+@ormUrl+'/offers
				<p>(Wenn unter der Link nichts zu sehen ist, bitte stellen Sie die Raten für den Angebotsslider frei und konfigurieren Sie sie den entsprechenden Bilder, damit sie zu sehen sind)</b><br>

			</p>'+CHAR(10)			
		END
	ELSE IF (@ORM_IN_USE = 1 AND @ORM_AVAILABILITY_PLAN_IN_USE = 0) 
		BEGIN
			SET @result+='<br><p><b>Online '+@environment+' Reservierungsmodul Link unter:</b><br>
				<a href="'+@ormUrl+'" title="CX9 Online Reservierungsmodul">'+@environment+' Reservierungsmodul</a>	
				<br>'+@ormUrl+'
				<p>(Wenn unter der Link nichts zu sehen ist, bitte stellen Sie die Raten für den Angebotsslider frei und konfigurieren Sie sie den entsprechenden Bilder, damit sie zu sehen sind)</b><br>
			</p>'+CHAR(10)			
		END        

	SET @result+='<p><b>'+@environment+' C-Rent Web Link unter:</b><br>
		<a href="'+@crwUrl+'" title="CX9 C-Rent Web">'+@environment+' C-Rent Web</a>
		<br>'+@crwUrl+'
	</p>'+CHAR(10)
	--IF (@environment <> 'LIVE')
	SET @result+='<p><b>RDP Benutzern:</b>
		<br>'+dbo.GET_TS_USERS(@MandantId)+'<br><br>'

	RETURN @result
END
