CREATE FUNCTION [dbo].[getVariableDefinitionFromTableReplaceDataType] (@TABLE_NAME NVARCHAR(2048) = NULL, @type VARCHAR(8)='DECLARE', @justFields NVARCHAR(MAX)='', @justFieldsSep NVARCHAR(1)=';', @dataTypeReplacement VARCHAR(255) = ' NVARCHAR(255) =  ''''')
RETURNS NVARCHAR(MAX)--Author José
BEGIN
	DECLARE @result NVARCHAR(MAX) = ''
	DECLARE @table TABLE(COLUMN_NAME NVARCHAR(128) NULL, IS_NULLABLE NVARCHAR(128) NULL, DATA_TYPE NVARCHAR(128) NULL, CHARACTER_MAXIMUM_LENGTH NVARCHAR(128) NULL, COLUMN_DEFAULT NVARCHAR(2048) NULL)
	DECLARE @COLUMN_NAME NVARCHAR(128) = NULL, @IS_NULLABLE NVARCHAR(128) = NULL, @DATA_TYPE NVARCHAR(128) = NULL, @CHARACTER_MAXIMUM_LENGTH NVARCHAR(128) = NULL, @COLUMN_DEFAULT NVARCHAR(2048) = NULL 
	DECLARE @TSQLFIELD_DEFINITION NVARCHAR(MAX) = ''
	DECLARE @XML_SET_FIELD_DEFINITION NVARCHAR(MAX) = ''
	IF EXISTS (SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TABLE_NAME)
		BEGIN
			INSERT INTO @table
			SELECT COLUMN_NAME, IS_NULLABLE, DATA_TYPE, CHARACTER_MAXIMUM_LENGTH,COLUMN_DEFAULT
			FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TABLE_NAME
												DECLARE help_table_field_definition CURSOR  
			   FOR  SELECT COLUMN_NAME, IS_NULLABLE, UPPER(DATA_TYPE), CHARACTER_MAXIMUM_LENGTH,ISNULL(COLUMN_DEFAULT,'NULL')  FROM @table
			OPEN help_table_field_definition  
			FETCH NEXT FROM help_table_field_definition INTO @COLUMN_NAME, @IS_NULLABLE, @DATA_TYPE, @CHARACTER_MAXIMUM_LENGTH, @COLUMN_DEFAULT
			IF (ISNULL(@justFields,'')<>'')
				DELETE FROM @table WHERE COLUMN_NAME NOT IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@justFields,@justFieldsSep))  
			WHILE @@FETCH_STATUS = 0  
			BEGIN  --@COLUMN_NAME NVARCHAR(128) = NULL 
				--SET @TSQLFIELD_DEFINITION = '' 
				IF (@CHARACTER_MAXIMUM_LENGTH <=0)SET @CHARACTER_MAXIMUM_LENGTH=255 
				IF (CHARINDEX('getdate()',@COLUMN_DEFAULT) > 0) SET @COLUMN_DEFAULT='CURRENT_TIMESTAMP'
				SET @TSQLFIELD_DEFINITION += N'DECLARE @'+@COLUMN_NAME+' '+@dataTypeReplacement+CHAR(13)
				SET @TSQLFIELD_DEFINITION = REPLACE(@TSQLFIELD_DEFINITION,'CURRENT_TIMESTAMP','GETDATE()')
				IF (@DATA_TYPE = 'XML')
					SET @XML_SET_FIELD_DEFINITION += 'SET @'+@COLUMN_NAME+' = ISNULL((@INPUT_CLIENT_DATA.query(N''(/input[1]/param[@id="'+@COLUMN_NAME+'"])[1]'')),@'+@COLUMN_NAME+') '+' '+CHAR(13)
														-- ISNULL((@INPUT_CLIENT_DATA.query('(/input[1]/param[@id="DATA"])[1]')),@DATA)  
				ELSE 
					SET @XML_SET_FIELD_DEFINITION += 'SET @'+@COLUMN_NAME+' = ISNULL((@INPUT_CLIENT_DATA.value(N''(/input[1]/param[@id="'+@COLUMN_NAME+'"]/text())[1]'','''+ISNULL((SELECT TOP 1 tsqlDataType FROM dbo.customTableDDL(@TABLE_NAME,2,0,0) WHERE field = @COLUMN_NAME),'VARCHAR(MAX)')+''')),@'+@COLUMN_NAME+') '+' '+CHAR(13)
				--SET @MRCRWNUMMER2 = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="MRCRWNUMMER2"]/text())[1]','VARCHAR(4)')),'')

				FETCH NEXT FROM help_table_field_definition	INTO @COLUMN_NAME, @IS_NULLABLE, @DATA_TYPE, @CHARACTER_MAXIMUM_LENGTH, @COLUMN_DEFAULT
	
			END   
			CLOSE help_table_field_definition
			DEALLOCATE help_table_field_definition 	
			IF (@TSQLFIELD_DEFINITION <> '' AND @type = 'DECLARE')
				SET @result = @TSQLFIELD_DEFINITION	
			IF (@XML_SET_FIELD_DEFINITION <> '' AND @type = 'SET')
				SET @result = @XML_SET_FIELD_DEFINITION	
			SET @result = REPLACE(@result,'  ',' ')	
		END

  RETURN @result
END
GO
