CREATE FUNCTION [dbo].[isClientExtern] (@mandantId INT = NULL)
RETURNS BIT 
BEGIN
  DECLARE @result BIT = 0
  DECLARE @externalHosting BIT = 0
  DECLARE @DBIP VARCHAR(128) = ''
  IF EXISTS(SELECT TOP 1 companyname FROM dbo.Mandant WHERE id = @mandantId)
	BEGIN
		SELECT TOP 1 @DBIP = databaseIp, @externalHosting=ISNULL(externalHosting,0) FROM dbo.Mandant WHERE id = @mandantId
		IF (@externalHosting = 1) RETURN 1
		ELSE IF @DBIP LIKE '10.%' --smile
			SET @result = 1
		ELSE IF @DBIP LIKE '193.210.%'--acl
			SET @result = 1
		ELSE IF @DBIP LIKE '192.168.1.%'
			SET @result = 1
		ELSE IF @DBIP NOT LIKE '192.168.25%'
			SET @result = 1
	END
  RETURN @result
END
GO
