CREATE FUNCTION [dbo].[isOWIRechnung] (@ARechNO varchar(30))
RETURNS bit AS  
BEGIN
  declare @result BIT = 0
  DECLARE @ratencode VARCHAR(30) = NULL
  SELECT @ratencode = dbo.getParamValue('SANSCH_BEH_RATE_CODE_RE')
  IF exists(select rate FROM rech_pos WHERE PKRECHNUNG = @ARechNO AND Rate = @ratencode)
  SET @result = 1 
  return @result
END
GO
/****** Object:  UserDefinedFunction [dbo].[JASPER_DB_CONNECTION]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[JASPER_DB_CONNECTION] (@mandant_id INT = NULL, @MandantEnvironmentName NVARCHAR(128)= NULL, @type VARCHAR(16) = 'xml')
RETURNS NVARCHAR(MAX)
BEGIN  	
	DECLARE @id INT = NULL  
	DECLARE @COUNTER INT = 1 
	DECLARE @PK INT = NULL 
	DECLARE @databaseIp NVARCHAR(255) = NULL 
	DECLARE @databaseInstance NVARCHAR(255) = NULL 
	DECLARE @databaseName NVARCHAR(255) = NULL 
	DECLARE @databaseUser NVARCHAR(255) = NULL 
	DECLARE @databasePort INT = NULL
	DECLARE @iReportConnectionVarchar NVARCHAR(MAX)=''
	DECLARE @iReportConnectionVarcharResult NVARCHAR(MAX)=''
	DECLARE @iReportRawConnectionEmpty NVARCHAR(MAX)='connection.0=\t<iReportConnection name\="Empty datasource" connectionClass\="com.jaspersoft.ireport.designer.connection.JREmptyDatasourceConnection">\n\t\t<connectionParameter name\="records"><\![CDATA[1]]></connectionParameter>\n\t</iReportConnection>\n'+CHAR(13)
	DECLARE @iReportRawConnection NVARCHAR(MAX)=''
	DECLARE @iReportConnectionXML XML='<iReportConnectionSet></iReportConnectionSet>'
	DECLARE @sigleiReportConnectionXML XML=''
	DECLARE @companyname NVARCHAR(255) = NULL 
	DECLARE @connectionParameterURL NVARCHAR(255) = '' 
	DECLARE @connectionParameterDatabase NVARCHAR(255) = '' 
	DECLARE @connectionParameterPassword NVARCHAR(255) = '' 
	DECLARE @connectionDefaultName NVARCHAR(MAX) = '' 
 
	DECLARE @environments TABLE (MANDANT_ENV_PK INT NULL, MANDANT_ID INT NOT NULL, ENVIRONMENT VARCHAR(128) NOT NULL) 

	INSERT INTO @environments
		SELECT PK, mandant_id, CASE WHEN type ='DEFAULT' THEN 'LIVE'
			WHEN databaseName LIKE 'ACC_%' THEN 'ACC'
			WHEN databaseName LIKE 'KOPIE_%' THEN 'ACC' ELSE type END[env]
		FROM MANDANT_DB_ENVIRONMENT ME WHERE ME.mandant_id IN (SELECT id FROM dbo.Mandant) AND ME.type IS NOT NULL
	IF (@mandant_id IS NOT NULL AND @MandantEnvironmentName IS NULL)
		DELETE FROM @environments WHERE MANDANT_ID NOT IN (@mandant_id) 
	ELSE IF (@mandant_id IS NULL AND @MandantEnvironmentName IS NOT NULL)
		BEGIN 
			DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@MandantEnvironmentName)
		END 
	ELSE IF (@mandant_id IS NOT NULL AND @MandantEnvironmentName IS NOT NULL)
		BEGIN
			DELETE FROM @environments WHERE MANDANT_ID NOT IN (@mandant_id)  
			DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@MandantEnvironmentName)
		END 
	--SELECT * FROM @environments
	--return 
	--SELECT TOP 1  @id = ISNULL(id, @id), @companyname = ISNULL(companyname, @companyname) FROM MANDANT WHERE id = 407 

	DECLARE MANDANT_DB_ENVIRONMENT_CURSOR CURSOR
		FOR SELECT  ISNULL(mandant_id,0), ISNULL(PK,0), ISNULL(databaseIp,''), ISNULL(databaseInstance,''), ISNULL(databaseName,''), ISNULL(databaseUser,''), ISNULL(databasePort,0) FROM MANDANT_DB_ENVIRONMENT WHERE PK IN (SELECT MANDANT_ENV_PK FROM @environments)
	OPEN MANDANT_DB_ENVIRONMENT_CURSOR
	FETCH NEXT FROM MANDANT_DB_ENVIRONMENT_CURSOR INTO @mandant_id, @PK, @databaseIp, @databaseInstance, @databaseName, @databaseUser, @databasePort
	WHILE @@FETCH_STATUS = 0
	BEGIN
		--do your stuff
		SET @iReportConnectionVarchar = ''
		--SELECT  407[mandant_id], @databaseIp[databaseIp], @databaseInstance[databaseInstance], @databaseName[databaseName], @databaseUser[databaseUser], @databasePort[databasePort]
		SET @connectionParameterURL = @databaseIp+'/'+@databaseName
		SET @connectionParameterPassword = dbo.SEC_GetPWCOde(@databaseUser)
		SET @connectionParameterDatabase = @databaseName
		IF (ISNULL(@databasePort,0)>0 AND ISNULL(@databaseInstance,'')='')
			BEGIN
				SET @connectionParameterURL = @databaseIp+':'+CAST(@databasePort AS NVARCHAR(16)) +'/'+@databaseName
			END
		
		IF (ISNULL(@databasePort,0)=0 AND ISNULL(@databaseInstance,'')<>'')
			BEGIN
				SET @connectionParameterURL = @databaseIp+'/'+@databaseName+';instance='+@databaseInstance	
				SET @connectionParameterDatabase = @databaseName+';instance='+@databaseInstance
			END
		
		IF (ISNULL(@databasePort,0)>0 AND ISNULL(@databaseInstance,'')<>'')
			BEGIN
				SET @connectionParameterURL = @databaseIp+':'+CAST(@databasePort AS NVARCHAR(16))+'/'+@databaseName+';instance='+@databaseInstance
				SET @connectionParameterDatabase = @databaseName+';instance='+@databaseInstance			
			END 
		SET @connectionDefaultName = 'DEFAULT_CONNECTION_NAME='+@databaseName+CHAR(13)
		IF (CHARINDEX(@databaseName,'ACC_')>0)
			SET @connectionDefaultName = 'DEFAULT_CONNECTION_NAME='+@databaseName+CHAR(13)	
		SET @iReportConnectionVarchar += '	<iReportConnection name="'+@databaseName+'" connectionClass="com.jaspersoft.ireport.designer.connection.JDBCConnection">'+CHAR(13)
		SET @iReportConnectionVarchar += '		<connectionParameter name="ServerAddress"><![CDATA['+@databaseIp+']]></connectionParameter>'+CHAR(13)
		SET @iReportConnectionVarchar += '		<connectionParameter name="SavePassword"><![CDATA[true]]></connectionParameter>'+CHAR(13)
		SET @iReportConnectionVarchar += '		<connectionParameter name="Url"><![CDATA[jdbc\:jtds\:sqlserver\://'+@connectionParameterURL+']]></connectionParameter>'+CHAR(13)
		SET @iReportConnectionVarchar += '		<connectionParameter name="JDBCDriver"><![CDATA[net.sourceforge.jtds.jdbc.Driver]]></connectionParameter>'+CHAR(13)
		SET @iReportConnectionVarchar += '		<connectionParameter name="Database"><![CDATA['+@connectionParameterDatabase+']]></connectionParameter>'+CHAR(13)
		SET @iReportConnectionVarchar += '		<connectionParameter name="Password"><![CDATA['+@connectionParameterPassword+']]></connectionParameter>'+CHAR(13)
		SET @iReportConnectionVarchar += '		<connectionParameter name="Username"><![CDATA['+@databaseUser+']]></connectionParameter>'+CHAR(13)
		SET @iReportConnectionVarchar += '	</iReportConnection>'+CHAR(13)
		SET @sigleiReportConnectionXML = REPLACE(@iReportConnectionVarchar,'jdbc\:jtds\:sqlserver\','jdbc:jtds:sqlserver')
		--SET @iReportConnectionXML.modify('insert sql:variable() /iReportConnectionSet[1]')
		SET @iReportConnectionXML.modify('insert sql:variable("@sigleiReportConnectionXML")  into (/iReportConnectionSet)[1]') 
		SET @iReportConnectionVarchar = REPLACE(@iReportConnectionVarchar,CHAR(13),'\n')
		SET @iReportConnectionVarchar = REPLACE(@iReportConnectionVarchar,CHAR(9),'\t')
		SET @iReportConnectionVarchar = REPLACE(@iReportConnectionVarchar,'="','\="')/**/
		SET @iReportConnectionVarchar = REPLACE(@iReportConnectionVarchar,'![CDATA','\![CDATA')/**/ 
		
		SET @iReportRawConnection += 'connection.'+CAST(@COUNTER AS VARCHAR(16))+'='+@iReportConnectionVarchar+CHAR(13)
		--DEFAULT_CONNECTION_NAME=ACC_Mkminden
		SET @COUNTER+=1
		FETCH NEXT FROM MANDANT_DB_ENVIRONMENT_CURSOR INTO @mandant_id, @PK, @databaseIp, @databaseInstance, @databaseName, @databaseUser, @databasePort
	END
	CLOSE MANDANT_DB_ENVIRONMENT_CURSOR
	DEALLOCATE MANDANT_DB_ENVIRONMENT_CURSOR

	IF (@type = 'ireport')
		BEGIN
			SET @iReportConnectionVarcharResult = @connectionDefaultName+@iReportRawConnectionEmpty+@iReportRawConnection
			RETURN @iReportConnectionVarcharResult		
		END 
		--RETURN @connectionDefaultName+@iReportRawConnectionEmpty+@iReportRawConnection
	ELSE IF (@type = 'xml')
		RETURN dbo.RenderXMLToString(@iReportConnectionXML)
	RETURN ''
END
GO
/****** Object:  UserDefinedFunction [dbo].[LastIndexOf]    Script Date: 25.01.2022 03:14:46 ******/
