CREATE FUNCTION [dbo].[SEARCH_MANDANT_DB_ENVIRONMENT] (@searchTerm VARCHAR(MAX) = '')
RETURNS @MANDANT_DB_ENVIRONMENT TABLE (MANDANT_ID INT NOT NULL, MANDANT_ENVIRONTMENT_PK INT NOT NULL)
BEGIN 
		DECLARE @mandantSearchName NVARCHAR(255) = ''
		DECLARE @mandantSearchtype NVARCHAR(255) = ''
		DECLARE @mandantSearchversion NVARCHAR(255) = ''
		--mandant=demo;type=ACC;version=6.0
		SET @mandantSearchName = ISNULL((SELECT REPLACE(Aval,'mandant=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerm,';') WHERE Aval LIKE 'mandant=%'),'')
		SET @mandantSearchtype = ISNULL((SELECT REPLACE(Aval,'type=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerm,';') WHERE Aval LIKE 'type=%'),'')
		SET @mandantSearchversion = ISNULL((SELECT REPLACE(Aval,'version=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerm,';') WHERE Aval LIKE 'version=%'),'')
		IF(@mandantSearchtype='LIVE') SET @mandantSearchtype = 'DEFAULT'
		IF(@mandantSearchtype='L') SET @mandantSearchtype = 'D'
		IF(@mandantSearchtype='LI') SET @mandantSearchtype = 'DE'
		IF(@mandantSearchtype='LIV') SET @mandantSearchtype = 'DEF' 

		IF (@mandantSearchName<>'' AND @mandantSearchtype = '' AND @mandantSearchversion = '')
			BEGIN
				INSERT INTO @MANDANT_DB_ENVIRONMENT --print '100'
					SELECT mandant_id, PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE dbo.GET_MANDANT_NAME(mandant_id) LIKE '%'+@mandantSearchName+'%'						 			
			END
		IF (@mandantSearchName<>'' AND @mandantSearchtype <> '' AND @mandantSearchversion = '')
			BEGIN
				INSERT INTO @MANDANT_DB_ENVIRONMENT --print '110'
					SELECT  mandant_id, PK  FROM dbo.MANDANT_DB_ENVIRONMENT WHERE dbo.GET_MANDANT_NAME(mandant_id) LIKE '%'+@mandantSearchName+'%' AND type LIKE '%'+@mandantSearchtype+'%'						 			
			END  
		IF (@mandantSearchName<>'' AND @mandantSearchtype <> '' AND @mandantSearchversion <> '')
			BEGIN
				INSERT INTO @MANDANT_DB_ENVIRONMENT --print '111'
					SELECT mandant_id, PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE dbo.GET_MANDANT_NAME(mandant_id) LIKE '%'+@mandantSearchName+'%' AND type LIKE '%'+@mandantSearchtype+'%' AND version LIKE '%'+@mandantSearchversion+'%'				 			
			END  
				
		IF (@mandantSearchName = '' AND @mandantSearchtype <> '' AND @mandantSearchversion = '')
			BEGIN
				INSERT INTO @MANDANT_DB_ENVIRONMENT --print '010'
					SELECT mandant_id, PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE ISNULL(type,'') LIKE '%'+@mandantSearchtype+'%'							 			
			END  

		IF (@mandantSearchName = '' AND @mandantSearchtype <> '' AND @mandantSearchversion <> '')
			BEGIN
				INSERT INTO @MANDANT_DB_ENVIRONMENT --print '011'
					SELECT mandant_id, PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE ISNULL(type,'') = @mandantSearchtype AND version LIKE '%'+@mandantSearchversion+'%'						 			
			END 
		IF (@mandantSearchName  <> '' AND @mandantSearchtype = '' AND @mandantSearchversion <> '')
			BEGIN
				INSERT INTO @MANDANT_DB_ENVIRONMENT --print '101'
					SELECT mandant_id, PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE  dbo.GET_MANDANT_NAME(mandant_id) LIKE '%'+@mandantSearchName+'%' AND version LIKE '%'+@mandantSearchversion+'%'					 			
			END 			    							          
   
		IF (@mandantSearchName = '' AND @mandantSearchtype = '' AND @mandantSearchversion <> '')
			BEGIN
				INSERT INTO @MANDANT_DB_ENVIRONMENT --print '001'
					SELECT mandant_id, PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE ISNULL(version,'') LIKE '%'+@mandantSearchversion+'%'						 			
			END 
	RETURNEND
GO
/****** Object:  UserDefinedFunction [dbo].[SEARCH_MANDANT_DB_ENVIRONMENT_TEST]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
