CREATE FUNCTION [dbo].[SEARCH_MANDANT_DB_ENVIRONMENT_TEST] (@searchTerm VARCHAR(MAX) = '')
RETURNS @MANDANT_DB_ENVIRONMENT TABLE (MANDANT_ID INT NOT NULL, MANDANT_ENVIRONTMENT_PK INT NOT NULL)
BEGIN 
		DECLARE @mandantSearchName NVARCHAR(255) = ''
		DECLARE @mandantSearchtype NVARCHAR(255) = ''
		DECLARE @mandantSearchversion NVARCHAR(255) = ''
	    INSERT INTO @MANDANT_DB_ENVIRONMENT ( MANDANT_ID , MANDANT_ENVIRONTMENT_PK )
			SELECT mandant_id, pk FROM dbo.MANDANT_DB_ENVIRONMENT   
		--mandant=demo;type=ACC;version=6.0
		SET @mandantSearchName = ISNULL((SELECT REPLACE(Aval,'mandant=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerm,';') WHERE Aval LIKE 'mandant=%'),'')
		SET @mandantSearchtype = ISNULL((SELECT REPLACE(Aval,'type=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerm,';') WHERE Aval LIKE 'type=%'),'')
		SET @mandantSearchversion = ISNULL((SELECT REPLACE(Aval,'version=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerm,';') WHERE Aval LIKE 'version=%'),'')
		IF(@mandantSearchtype='LIVE') SET @mandantSearchtype = 'DEFAULT'
		IF(@mandantSearchtype='L') SET @mandantSearchtype = 'D'
		IF(@mandantSearchtype='LI') SET @mandantSearchtype = 'DE'
		IF(@mandantSearchtype='LIV') SET @mandantSearchtype = 'DEF' 

		IF (@mandantSearchName<>'')
			BEGIN
				DELETE FROM @MANDANT_DB_ENVIRONMENT  WHERE  dbo.GET_MANDANT_NAME(mandant_id) NOT LIKE '%'+@mandantSearchName+'%'						 			
			END
		IF ( @mandantSearchtype <> '' )
			BEGIN
				DELETE FROM @MANDANT_DB_ENVIRONMENT  WHERE MANDANT_ENVIRONTMENT_PK NOT IN (SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE ISNULL(type,'') LIKE '%'+@mandantSearchtype+'%'	)
			
			END  
		IF ( @mandantSearchversion <> '')
			BEGIN
				DELETE FROM @MANDANT_DB_ENVIRONMENT  WHERE MANDANT_ENVIRONTMENT_PK NOT IN (SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE ISNULL(version,'') LIKE '%'+@mandantSearchversion+'%'	)
			END  
				
 

   
	RETURNEND
GO
/****** Object:  UserDefinedFunction [dbo].[SEARCH_UPDATE_XML_ENVIRONMENTS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[SEARCH_UPDATE_XML_ENVIRONMENTS](@searchTerm VARCHAR(MAX) = '')
RETURNS NVARCHAR(MAX)--Author José.
BEGIN  
		DECLARE @mandantSearchName NVARCHAR(255) = ''
		DECLARE @mandantSearchtype NVARCHAR(255) = ''
		DECLARE @mandantSearchversion NVARCHAR(255) = ''
		--mandant=demo;type=ACC;version=6.0
		SET @mandantSearchName = ISNULL((SELECT REPLACE(Aval,'mandant=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerm,';') WHERE Aval LIKE 'mandant=%'),'')
		SET @mandantSearchtype = ISNULL((SELECT REPLACE(Aval,'type=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerm,';') WHERE Aval LIKE 'type=%'),'')
		SET @mandantSearchversion = ISNULL((SELECT REPLACE(Aval,'version=','') FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchTerm,';') WHERE Aval LIKE 'version=%'),'')
		IF(@mandantSearchtype='LIVE') SET @mandantSearchtype = 'DEFAULT'
	    DECLARE @mandant TABLE (MANDANT_ID INT NOT NULL, MANDANT_EVENVIRONTMENT_PK INT NOT NULL)
		INSERT INTO @mandant
		        SELECT  MANDANT_ID , MANDANT_ENVIRONTMENT_PK FROM dbo.SEARCH_MANDANT_DB_ENVIRONMENT(@searchTerm)


		DECLARE @MANDANT_DB_ENVIRONMENT_PY TABLE(rowNumber INT NOT NULL IDENTITY(1,1), mandant_id INT NULL, PK INT NULL, type NVARCHAR(30) NULL, path NVARCHAR(255) NULL, version NVARCHAR(30) NULL, databaseIp NVARCHAR(255) NULL, databaseInstance NVARCHAR(255) NULL, databaseName NVARCHAR(255) NULL, databaseUser NVARCHAR(255) NULL, tsCreateDate DATETIME2 NULL, installBase INT NULL, databasePort INT NULL,
											   mandantName NVARCHAR(255) NULL, updateDate VARCHAR(32) NULL, entryType NVARCHAR(30) NULL, actionButton NVARCHAR(128) NULL, ABAS_TASK_NO NVARCHAR(128) NULL, AbasId NVARCHAR(128) NULL)

		--IF (ISNULL(@mandantSearchName,'')<>'')
			BEGIN
				IF(@mandantSearchtype='DEFAULT') SET @mandantSearchtype = 'LIVE'          
				INSERT INTO @MANDANT_DB_ENVIRONMENT_PY (mandant_id, PK, mandantName, updateDate, type, path, version, databaseIp, databaseInstance, databaseName, databaseUser, tsCreateDate, installBase, databasePort,actionButton, ABAS_TASK_NO, AbasId)
						SELECT  2000, 4000, @mandantSearchName, '', @mandantSearchtype, '', @mandantSearchversion, '', '', '', '', NULL, '', 0, 'suchen', '','' -- FROM MANDANT_DB_ENVIRONMENT WHERE mandant_id IN (SELECT MANDANT_ID FROM @mandant) ORDER BY mandant_id ASC  				
			END
		INSERT INTO @MANDANT_DB_ENVIRONMENT_PY (mandant_id, PK, mandantName, updateDate, type, path, version, databaseIp, databaseInstance, databaseName, databaseUser, tsCreateDate, installBase, databasePort,actionButton, ABAS_TASK_NO, AbasId)
				SELECT  ISNULL(mandant_id,0), ISNULL(PK,0), dbo.GET_MANDANT_NAME_PARSED(mandant_id)/*+'        [id='+CAST(mandant_id AS VARCHAR(8))+';PK='+CAST(PK AS VARCHAR(8))+']'*/, dbo.GET_MANDANT_UPDATE_DATE(mandant_id,(CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END)), (CASE WHEN type = 'DEFAULT' THEN 'LIVE' ELSE ISNULL(type,'') END), ISNULL(path,''), ISNULL(version,''), ISNULL(databaseIp,''), ISNULL(databaseInstance,''), ISNULL(databaseName,''), ISNULL(databaseUser,''), tsCreateDate, ISNULL(installBase,0), ISNULL(databasePort,0), 'im Detail ansehen', dbo.GET_MANDANT_UPDATE_TASK_NO(mandant_id,''),dbo.GET_MANDANT_UPDATE_FIELD(mandant_id,'AbasId')  FROM MANDANT_DB_ENVIRONMENT WHERE PK IN (SELECT MANDANT_EVENVIRONTMENT_PK FROM @mandant) ORDER BY mandant_id ASC
        DECLARE @zeilenversetzung INT = 0 --wegen der suche
 
		DECLARE @XML_ENVIRONMENTS NVARCHAR(MAX) =
			(ISNULL((
					STUFF(( 
							SELECT 
										(SELECT PK[@PK], mandant_id[@mandant_id],  
										(SELECT 
												1[@labelColumn], (rowNumber+@zeilenversetzung)[@labelRow], 2[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow], 												
												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','MandantName',(CASE WHEN ISNULL(actionButton,'') = 'suchen' THEN 'entry' ELSE 'label' END), (CASE WHEN ISNULL(actionButton,'') = 'suchen' THEN 'suchen' ELSE mandantName END))[@options],												
 												'30'[@labelWith],'50'[@textWith],(CASE WHEN ISNULL(actionButton,'') = 'suchen' THEN 'entry' ELSE 'label' END)[@type],'0'[@readonly], mandantName  AS '*'  FOR XML PATH('MandantName'), TYPE), 
										(SELECT 
												3[@labelColumn], (rowNumber+@zeilenversetzung)[@labelRow], 4[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow],
												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','Type','entry',type)[@options],
											'6'[@labelWith],'4'[@textWith],'entry'[@type],(CASE WHEN ISNULL(actionButton,'') = 'suchen' THEN '0' ELSE '1' END)[@readonly], type AS '*'  FOR XML PATH('Type'), TYPE), 
										(SELECT 
												5[@labelColumn], (rowNumber+@zeilenversetzung)[@labelRow], 6[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow],
												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','version','entry',ISNULL(version,''))[@options],
												'entry'[@type],(CASE WHEN ISNULL(actionButton,'') = 'suchen' THEN '0' ELSE '1' END)[@readonly], ISNULL(version,'') AS '*'  FOR XML PATH('version'), TYPE),
										(SELECT 
												7[@labelColumn], (rowNumber+@zeilenversetzung)[@labelRow], 8[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow], --(CASE WHEN ISNULL(actionButton,'') = 'suchen' THEN '1' ELSE '0' END)
												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','UpdateDate','entry',updateDate)[@options],
												'entry'[@type], CASE WHEN ISNULL(version,'') = '6.0' OR ISNULL(actionButton,'') = 'suchen' THEN '1' ELSE '0' END[@readonly], (CASE WHEN ISDATE(updateDate)=0 THEN '' ELSE dbo.getFormatDateTimeFromString (updateDate, 'dd.mm.YYYY H:i') END) AS '*'  FOR XML PATH('UpdateDate'), TYPE),
										(SELECT 
												9[@labelColumn], (rowNumber+@zeilenversetzung)[@labelRow],  10[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow], 
												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','ABAS_TASK_NO','entry',ABAS_TASK_NO)[@options],
												'entry'[@type], '1'[@readonly], ABAS_TASK_NO AS '*'  FOR XML PATH('ABAS_TASK_NO'), TYPE),
										(SELECT 
												11[@labelColumn], (rowNumber+@zeilenversetzung)[@labelRow],  12[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow], 
												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','AbasId','entry',AbasId)[@options],
												'entry'[@type], '1'[@readonly], AbasId AS '*'  FOR XML PATH('AbasId'), TYPE),
										(SELECT 
												13[@labelColumn], (rowNumber+@zeilenversetzung)[@labelRow],  14[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow], 
												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','PK','entry',AbasId)[@options],
												'entry'[@type], '1'[@readonly], PK AS '*'  FOR XML PATH('PK'), TYPE),
										(SELECT 
												15[@labelColumn], (rowNumber+@zeilenversetzung)[@labelRow],  16[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow], 
												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','id','entry',mandant_id)[@options],
												'entry'[@type], '1'[@readonly], mandant_id AS '*'  FOR XML PATH('mandant_id'), TYPE),
										(SELECT 
												17[@labelColumn],(rowNumber+@zeilenversetzung)[@labelRow], 18[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow], 
												dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','detail','button',actionButton)[@options],
												CASE WHEN ISNULL(actionButton,'') = 'suchen' 
													THEN '{"readVars":["MandantName","Type","version"], "action":"suchen"}' 
													ELSE '{"readVars":[], "action":"open_mandant_details"}' END [@onClickAction],
												'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'DETAILS' AS '*'  FOR XML PATH('DETAIL'), TYPE),
										CASE WHEN PK <> 4000 THEN 
											(SELECT 
													19[@labelColumn],(rowNumber+@zeilenversetzung)[@labelRow], 20[@elementColumn], (rowNumber+@zeilenversetzung)[@elementRow], 
													dbo.GET_ELEMENT_PROPERTIES_BY_MASK(PK, 'pyUpdateOverview','shortcut','button','Shortcuts')[@options],
													'{"readVars":[], "action":"open_mandant_shortcuts"}'  [@onClickAction],
													'16'[@labelWith],'8'[@textWith],'button'[@type], '0'[@readonly],'shortcuts' AS '*'  FOR XML PATH('DETAIL'), TYPE)
										ELSE '' END
									FOR XML PATH('environment'), TYPE)   
								FROM @MANDANT_DB_ENVIRONMENT_PY
							FOR XML PATH(''),ROOT('environments')),1,0,'')	
			),''))
	RETURN @XML_ENVIRONMENTS	        
END
GO
