		ELSE IF ASCII(@zeichen)+square(@t) IN ('311', '489') SET @result=@result+'k'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('313', '315', '317', '321') SET @result=@result+'L'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('314', '316', '318', '322', '410') SET @result=@result+'l'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('323', '325', '327') SET @result=@result+'N'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('324', '326', '328') SET @result=@result+'n'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('332', '334', '336', '415', '416', '465', '490', '492', '937') SET @result=@result+'O'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('333', '335', '337', '417', '466', '491', '493') SET @result=@result+'o'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('340', '342', '344') SET @result=@result+'R'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('341', '343', '345') SET @result=@result+'r'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('346', '348', '350', '931') SET @result=@result+'S'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('347', '349', '351', '963') SET @result=@result+'s'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('354', '356', '358', '430', '920') SET @result=@result+'T'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('355', '357', '359', '427', '964') SET @result=@result+'t'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('360', '362', '364', '366', '368', '370', '431', '467', '469', '471', '473', '475') SET @result=@result+'U'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('361', '363', '365', '367', '369', '371', '432', '468', '470', '472', '474', '476') SET @result=@result+'u'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('372') SET @result=@result+'W'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('373') SET @result=@result+'w'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('374') SET @result=@result+'Y'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('375') SET @result=@result+'y'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('377', '379') SET @result=@result+'Z'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('378', '380', '438') SET @result=@result+'z'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('384') SET @result=@result+'b'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('401') SET @result=@result+'ƒ'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('448') SET @result=@result+'|'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('451') SET @result=@result+'!'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('697', '700', '712') SET @result=@result+''''
		ELSE IF ASCII(@zeichen)+square(@t) IN ('698', '782') SET @result=@result+'"'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('708', '770') SET @result=@result+'^'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('713', '772', '773') SET @result=@result+'¯'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('714', '769') SET @result=@result+'´'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('715', '768') SET @result=@result+'`'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('717', '817', '818') SET @result=@result+'_'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('730', '778') SET @result=@result+'°'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('771') SET @result=@result+'~'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('776') SET @result=@result+'¨'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('807') SET @result=@result+'¸'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('894') SET @result=@result+';'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('934') SET @result=@result+'F'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('946') SET @result=@result+'ß'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('956') SET @result=@result+'µ'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('960') SET @result=@result+'p'
		ELSE IF ASCII(@zeichen)+square(@t) IN ('966') SET @result=@result+'f'
	    ELSE      
         SET @result=@result+CHAR(ASCII(@zeichen)+square(@t))              
      SET @t=@t+1
    END
--  SELECT @result
  RETURN @result
end
GO
/****** Object:  UserDefinedFunction [dbo].[setCRent60CompareInstructions]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[setCRent60CompareInstructions](@MandantId INT = NULL, @AbasId INT = NULL, @environment VARCHAR(128)='ACC', @abasTaskNumber VARCHAR(128)='00000')
RETURNS VARCHAR(MAX)
BEGIN
	DECLARE	@ip VARCHAR(255) = '', @dbname VARCHAR(255) = '', @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)='', 
	@dbinstance VARCHAR(512)='', @documentRoot VARCHAR(512)='', @mandantName VARCHAR(512)='', 
	@JasperBranch VARCHAR(512)='master', @MainCRWBranch VARCHAR(512)='master', 
	@gitSchemasUpdate VARCHAR(1)='J'
    IF @AbasId IS NULL AND NOT EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId)
		RETURN '
	echo Daten in Mandant sind nicht gepflegt.
	exit /b'
    IF @AbasId IS NULL AND (SELECT TOP 1 abasId FROM dbo.Mandant WHERE id=@MandantId) IS NULL
		RETURN '
	echo AbasId Erforderlich, bitte pflegen 
	exit /b'
    IF (SELECT TOP 1 abasId FROM dbo.Mandant WHERE id=@MandantId) IS NOT NULL --overwrite the value
		SET @AbasId = (SELECT TOP 1 abasId FROM dbo.Mandant WHERE id=@MandantId)


	DECLARE @datasearchindex VARCHAR(128)='', @globalName VARCHAR(128)=''
	DECLARE @instructions VARCHAR(MAX) = ''
	IF( NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN
		SET @instructions+=':: MandantId existiert nicht bitte pflege Daten in der DB install tool
		echo MandantId existiert nicht bitte pflege Daten in der DB install tool
		exit /b
		'
		RETURN @instructions
	END
	IF( @environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS) )
	BEGIN
		SET @instructions+=
		'echo Environment ist nicht gueltig
		exit /b
		'
		RETURN @instructions
	END    
	IF (@environment = 'ACC' AND EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@environment))
		BEGIN
			SELECT TOP 1 @dbname=DB, @dbuser=DB_USER, @dbpassword=DB_USER_PW, 
			@ip=ISNULL(HOST,''),
			@datasearchindex = ISNULL(searchDataIndex,'IND'),
			@dbinstance=ISNULL(INSTANCE,''), @JasperBranch=JasperBranch, @MainCRWBranch=MainCRWBranch
			FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@environment 	 
		END
	IF (@environment = 'LIVE')
		BEGIN  
			SELECT @ip=ISNULL(databaseIp,''),@datasearchindex = ISNULL(globalName,'IND'),
				   @dbname=ISNULL(databaseName,''), @dbinstance=ISNULL(databaseInstance,''),
				   @dbuser=ISNULL(databaseUser,'') FROM dbo.Mandant WHERE id=@MandantId			
		END     
	SELECT @globalName=ISNULL(globalName,'_NOGlobalName'),@documentRoot=ISNULL(documentRoot,'_documentRoot'),
	@mandantName=ISNULL(companyname,'noCompanyName') FROM dbo.Mandant WHERE id=@MandantId 		   

    SET @instructions+=
'CALL C:\SQLJobs\createCompareJob.bat '+CAST(@MandantId AS VARCHAR(16))+' '+CAST(@environment AS VARCHAR(16))+' DATA '+CAST(@abasId AS VARCHAR(16))+' '+CAST(@datasearchindex AS VARCHAR(16))+'
CALL C:\SQLJobs\createCompareJob.bat '+CAST(@MandantId AS VARCHAR(16))+' '+CAST(@environment AS VARCHAR(16))+' SCHEMA '+CAST(@abasId AS VARCHAR(16))+' '+CAST(@datasearchindex AS VARCHAR(16))+'
'
	RETURN @instructions+CHAR(10)END
GO
/****** Object:  UserDefinedFunction [dbo].[stringReplaceMultiple_pattern]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[stringReplaceMultiple_pattern] (@originalText NVARCHAR(MAX),@paramReplacements NVARCHAR(MAX),@paramReplacementDivider VARCHAR(1),@termDivider VARCHAR(1))
RETURNS NVARCHAR(MAX)   --created by José on November 12th, 2018
BEGIN   --usage SELECT dbo.stringReplaceMultiple_pattern('usage test my mind and can be done','test=of this script&my mind=is important to know&done=&can be=do not think too much','&','=')
DECLARE @wordSearchedDividerReplacement NVARCHAR(MAX)
DECLARE @replace_search NVARCHAR(MAX) 
DECLARE @replacement NVARCHAR(MAX)  
DECLARE @terminology CURSOR
SET @terminology = CURSOR FOR
SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@paramReplacements,@paramReplacementDivider)
OPEN @terminology
FETCH NEXT FROM @terminology INTO @wordSearchedDividerReplacement
WHILE @@FETCH_STATUS = 0
	BEGIN 
		  IF ((SELECT count(Aval) FROM dbo.GET_TABLE_FROM_LIST_DELIM(@wordSearchedDividerReplacement,@termDivider))=2)
			BEGIN
			  SET @replace_search =  (SELECT TOP 1 Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@wordSearchedDividerReplacement,@termDivider))
			  SET @replacement =  (SELECT TOP 1 Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@wordSearchedDividerReplacement,@termDivider) WHERE Aval <>@replace_search) 
			  SET @originalText = REPLACE(@originalText,@replace_search,@replacement) 
			END 
		FETCH NEXT FROM @terminology INTO @wordSearchedDividerReplacement
	END
CLOSE @terminology
DEALLOCATE @terminology
RETURN @originalText
END
GO
/****** Object:  UserDefinedFunction [dbo].[TABLE_HAS_FIELD]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[TABLE_HAS_FIELD](@table_name VARCHAR(128) = '', @column_name VARCHAR(255) = '')
RETURNS BIT --Author José
BEGIN
	DECLARE @result BIT
	SET @result = 0
	SET @column_name = REPLACE(@column_name,'[','')
	SET @column_name = REPLACE(@column_name,']','')
	IF EXISTS(SELECT TOP 1 column_id FROM sys.columns WHERE Name = @column_name and Object_ID = Object_ID(@table_name))
		SET @result = 1
	RETURN @result
END
GO
