/****** Object:  UserDefinedFunction [dbo].[UrlEncode]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[UrlEncode](@string NVARCHAR(MAX))
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @count INT, @c NCHAR(1), @i INT, @stringReturn NVARCHAR(MAX)
    SET @count = LEN(@string)
    SET @i = 1
    SET @stringReturn = ''    
    WHILE (@i < = @count)
     BEGIN
        SET @c = SUBSTRING(@string, @i, 1)
        IF @c LIKE N'[A-Za-z0-9()''*\-._!~]' COLLATE Latin1_General_BIN ESCAPE N'\' COLLATE Latin1_General_BIN
         BEGIN
            SET @stringReturn = @stringReturn + @c
         END
        ELSE
         BEGIN
            SET @stringReturn = 
                   @stringReturn + '%'
                   + SUBSTRING(sys.fn_varbintohexstr(CAST(@c AS VARBINARY(MAX))),3,2)
                   + ISNULL(NULLIF(SUBSTRING(sys.fn_varbintohexstr(CAST(@c AS VARBINARY(MAX))),5,2), '00'), '')
         END
        SET @i = @i +1
     END
    RETURN @stringReturn
END


GO
/****** Object:  UserDefinedFunction [dbo].[VALIDATE_EMAIL_ADDRESS]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[VALIDATE_EMAIL_ADDRESS] (@EMAIL VARCHAR(1024))
RETURNS BIT

BEGIN
	DECLARE @valid bit  
    SET @valid = 0
    SET @email = LOWER(@email)
    IF @email IS NOT NULL    
        IF @email like '[a-z,0-9,_,-]%@[a-z,0-9,_,-]%.[a-z][a-z]%'  
           AND @email NOT like '%@%@%'  
           AND CHARINDEX('.@',@email) = 0  
           AND CHARINDEX('..',@email) = 0  
           AND CHARINDEX(',',@email) = 0  
           AND RIGHT(@email,1) between 'a' AND 'z'  
             SET @valid=1
    
    RETURN @valid

END
GO
/****** Object:  UserDefinedFunction [dbo].[VALIDATE_MANDANT_UPDATE]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[VALIDATE_MANDANT_UPDATE] (@MANDANT_ID INT = NULL)
RETURNS @result TABLE  (VALID BIT NULL, TSQL_UPDATE NVARCHAR(MAX) NULL )

BEGIN
	DECLARE @valid BIT  =  1
	
	DECLARE @id INT = NULL 
	DECLARE @companyname NVARCHAR(255) = '' 
	DECLARE @email NVARCHAR(255) = '' 

	DECLARE @documentRoot NVARCHAR(255) = '' 
	DECLARE @ormUrl NVARCHAR(255) = '' 
	DECLARE @crwUrl NVARCHAR(255) = '' 
	DECLARE @abasId INT = NULL  
	DECLARE @externalHosting BIT = dbo.isClientExtern(@MANDANT_ID)
	DECLARE @companyAppcode VARCHAR(255) = '' 
	DECLARE @TSQL_UPDATE NVARCHAR(MAX) = 'UPDATE dbo.mandant SET '

	DECLARE @mandantMissingInfo VARCHAR(MAX) = '' 
	
	SELECT TOP 1 
	@companyname = ISNULL(companyname, @companyname), 
	@email = ISNULL(email, @email), 
	@documentRoot = ISNULL(documentRoot,@documentRoot), 
	@ormUrl = 	ISNULL(ormUrl, @ormUrl), 
	@crwUrl = ISNULL(crwUrl, @crwUrl),
	@abasId = ISNULL(abasId, 0),
	@companyAppcode = ISNULL(companyAppcode, '')  FROM Mandant WHERE id=@MANDANT_ID
	DECLARE @inValidEmail NVARCHAR(255) = (SELECT TOP 1 Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@email,';') WHERE dbo.VALIDATE_EMAIL_ADDRESS(Aval)=0)  
	DECLARE @validClientMail BIT = CASE WHEN EXISTS(
			SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@email,';') WHERE dbo.VALIDATE_EMAIL_ADDRESS(Aval)=0)
			 THEN 0 ELSE 1 END
	IF (@companyname='')
		SET @mandantMissingInfo+='companyname = '''' /*empty*/ ,'+CHAR(13)
	IF (@email='' OR @email = 'fill@me' OR @validClientMail=0)
		SET @mandantMissingInfo+='email = '''+@email+'''/*invalid email entry = '+@inValidEmail+' */,'+CHAR(13)
	IF (@externalHosting = 0)
		BEGIN
			IF (@documentRoot='' OR (LOWER(@documentRoot) <> @documentRoot COLLATE Latin1_General_CS_AI))
				BEGIN
					SET @mandantMissingInfo+='documentRoot = '''+@documentRoot+''' /*invalid documentRoot entry*/ ,'+CHAR(13)		
				--	SET @valid = 0					    
				END
			IF (@documentRoot<>'' and (LOWER(@documentRoot) = @documentRoot COLLATE Latin1_General_CS_AI) AND (SELECT COUNT(documentRoot) FROM dbo.Mandant WHERE id <> @MANDANT_ID AND documentRoot=@documentRoot )>=1 )
				BEGIN
					SET @mandantMissingInfo+='documentRoot = '''+@documentRoot+''' /*invalid documentRoot double entry*/ ,'+CHAR(13)	
					--SET @valid = 0					    
				END
				    
		END
	IF (@externalHosting = 1)
		BEGIN
			IF (@documentRoot='' OR (LOWER(@documentRoot) <> @documentRoot COLLATE Latin1_General_CS_AI))
				SET @mandantMissingInfo+='documentRoot = '''+@documentRoot+''' /*invalid documentRoot entry */ ,'+CHAR(13)					    
		END

	IF (@ormUrl='')
		SET @mandantMissingInfo+='ormUrl = '''' /*empty*/ ,'+CHAR(13)
	IF (@ormUrl='')
		SET @mandantMissingInfo+='ormUrl = '''' /*empty*/ ,'+CHAR(13)

	IF (@companyAppcode='')
		SET @mandantMissingInfo+='companyAppcode = '''' /*empty */,'+CHAR(13)

	IF (@abasId IS NULL OR @abasId<=0)  
		SET @mandantMissingInfo+='abasId = '+CAST(@abasId AS VARCHAR(32))+' /*invalid AbasId*/ ,'+CHAR(13)
	--ELSE IF NOT EXISTS (SELECT * FROM dbo.nlCustomerImport2 WHERE AbasID = CAST( @abasId AS NVARCHAR(32))  )
	--	SET @mandantMissingInfo+=' abasId = '+CAST(@abasId AS VARCHAR(32))+'/* posible invalid AbasId (SELECT * FROM dbo.nlCustomerImport2 WHERE AbasID = '+CAST( @abasId AS NVARCHAR(32)) +') */ ,'+CHAR(13)
 
	IF (@mandantMissingInfo<>'')
		SET @mandantMissingInfo = SUBSTRING(@mandantMissingInfo,1,LEN(@mandantMissingInfo)-2)
	IF (@mandantMissingInfo<>'')
		BEGIN
		  SET @TSQL_UPDATE+=@mandantMissingInfo+' WHERE id = '+CAST(@MANDANT_ID AS VARCHAR(32))  
		  INSERT INTO @result
		  SELECT 0, @TSQL_UPDATE
		END
	IF (@mandantMissingInfo='')
		BEGIN 
		  INSERT INTO @result
		  SELECT 1, ''
		END 
    RETURN 

END
GO
/****** Object:  UserDefinedFunction [dbo].[WRITE_STRING_TO_FILE_LINE_BY_LINE]    Script Date: 25.01.2022 03:14:46 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[WRITE_STRING_TO_FILE_LINE_BY_LINE] (@string VARCHAR(MAX), @toFile VARCHAR(max))
RETURNS INT
BEGIN  
    /*Writes on a incoming file the incoming string, if questions then jose*/
	DECLARE @Cmd AS VARCHAR(4000)  
	DECLARE @FileOK  INT, @result INT
	IF(@string = '' OR @string IS NULL)
		SET @result = 0
	ELSE 
	BEGIN  
		DECLARE ONE_CURSOR Cursor
		FOR select splitdata from dbo.fnSplitString(@string, CHAR(13))
		OPEN ONE_CURSOR
			DECLARE @split VARCHAR(MAX) 
			FETCH NEXT FROM ONE_CURSOR INTO @split 
			WHILE (@@FETCH_STATUS <> -1)
			BEGIN
				IF (@@FETCH_STATUS <> -2)
				BEGIN 
				  SET @Cmd = 'DEL '+@toFile   
				  EXECUTE Master.dbo.xp_CmdShell @Cmd   
				  SET @Cmd = 'echo '+ REPLACE(@split, CHAR(10), '') +' >> '+@toFile   
				  EXECUTE Master.dbo.xp_CmdShell @Cmd   
				END
				FETCH NEXT FROM ONE_CURSOR INTO @split
		END  
		CLOSE ONE_CURSOR
		DEALLOCATE ONE_CURSOR 
		--test that file was created
		EXEC xp_fileExist @toFile ,@FileOK OUTPUT 
		IF (@FileOK = 0 )
			SET @result = 0
	ELSE 
		SET @result = 1
	END
  RETURN @result  
END
GO
