			    SET @PK = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="PK"]/text())[1]','INT')),@PK)  			    SET @inserted = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="inserted"]/text())[1]','DATETIME')),@inserted)  			    SET @executed = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="executed"]/text())[1]','DATETIME')),@executed)  			    SET @command = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="command"]/text())[1]','NVARCHAR(MAX)')),@command)  

				--check if db table entry already there 
				/*IF(EXISTS(SELECT PK FROM ZZEXECJOBS WHERE PK = @PK))
					BEGIN
						SET @ACID_TRANSACTION = 'UPDATE'
					END*/
				IF ((@ACID_TRANSACTION = 'DELETE' OR @making_action_by_user LIKE '%DELETE%') AND @confirm_acid_transaction = 0)
					BEGIN
						SET @alertSystemMessageDetails = '{"DB Info":"Bitte beachten Sie, dass diese Transaktion nicht mehr als 3 Sekunden dauert", "Grund":"DB Erreichbarkeit kann nicht vorhanden sein", "Reaktion":"Bitte den Fehler melden, wenn er auftritt"}'
						SET @alertSystemGeneralMessage = 'Der Eintrag in ZZEXECJOBS mit der PK=('+CAST(@PK AS VARCHAR (32))+') wird GELÖSCHT. Bitte bestätigen Sie es!'										
					 	SET @alertSystemMessageTitle = 'Eintrag wird GELÖSCHT'	
						SET @alertSystemGeneralMessageType = 'askquestion'
					    IF(NOT EXISTS(SELECT PK FROM ZZEXECJOBS WHERE PK = @PK))
							BEGIN
								SET @alertSystemMessageDetails = '{"DB Info":"Datensatz exitiert nicht", "Grund":"In der DB nicht gefunden", "Reaktion":"Bitte den Fehler melden"}'
								SET @alertSystemGeneralMessage = 'Der Eintrag in ZZEXECJOBS mit der PK= '+CAST(@PK AS VARCHAR (32))+' kann nicht aktualisiert werden.'										
					 			SET @alertSystemMessageTitle = 'Eintrag Info'	
								SET @alertSystemGeneralMessageType = 'showerror'
							END
					END
				ELSE IF ((@ACID_TRANSACTION = 'DELETE' OR @making_action_by_user LIKE '%DELETE%') AND @confirm_acid_transaction = 1)
					BEGIN
					    IF(NOT EXISTS(SELECT PK FROM ZZEXECJOBS WHERE PK = @PK))
							BEGIN
								SET @alertSystemMessageDetails = '{"DB Info":"Datensatz exitiert nicht", "Grund":"In der DB nicht gefunden", "Reaktion":"Bitte den Fehler melden"}'
								SET @alertSystemGeneralMessage = 'Der Eintrag in ZZEXECJOBS mit der PK= '+CAST(@PK AS VARCHAR (32))+' kann nicht aktualisiert werden.'										
					 			SET @alertSystemMessageTitle = 'Eintrag Info'	
								SET @alertSystemGeneralMessageType = 'showerror'
							END			
						ELSE
							BEGIN			
								SET @alertSystemMessageDetails = '{"DB Info":"Bitte beachten Sie, dass diese Transaktion nicht mehr als 3 Sekunden dauert", "Grund":"alles gelöscht", "Reaktion":"Daten können nicht wiederherstellen"}'
								SET @alertSystemGeneralMessage = 'Der Eintrag von der Tabelle ZZEXECJOBS wurde GELÖSCHT!'										
					 			SET @alertSystemMessageTitle = 'Eintrag wurde GELÖSCHT'	
								SET @alertSystemGeneralMessageType = 'showinfo'
								DELETE FROM ZZEXECJOBS WHERE PK = @PK
							END
					END	 
				IF ((@ACID_TRANSACTION = 'UPDATE' OR @making_action_by_user LIKE '%UPDATE%') AND @confirm_acid_transaction = 0)
					BEGIN
						SET @alertSystemMessageDetails = '{"DB Info":"Bitte beachten Sie, dass diese Transaktion nicht mehr als 3 Sekunden dauert", "Grund":"DB Erreichbarkeit kann nicht vorhanden sein", "Reaktion":"Bitte den Fehler melden, wenn er auftritt"}'
						SET @alertSystemGeneralMessage = 'Der Eintrag in ZZEXECJOBS mit der PK=('+CAST(@PK AS VARCHAR (32))+') wird aktualisiert. Bitte bestätigen Sie es!'										
					 	SET @alertSystemMessageTitle = 'Eintrag wird upgedatet'	
						SET @alertSystemGeneralMessageType = 'askquestion'
					    IF(NOT EXISTS(SELECT PK FROM ZZEXECJOBS WHERE PK = @PK))
							BEGIN
								SET @alertSystemMessageDetails = '{"DB Info":"Datensatz exitiert nicht", "Grund":"In der DB nicht gefunden", "Reaktion":"Bitte den Fehler melden"}'
								SET @alertSystemGeneralMessage = 'Der Eintrag in ZZEXECJOBS mit der PK= '+CAST(@PK AS VARCHAR (32))+' kann nicht aktualisiert werden.'										
					 			SET @alertSystemMessageTitle = 'Eintrag Info'	
								SET @alertSystemGeneralMessageType = 'showerror'
							END
					END	 	 										
				ELSE IF ((@ACID_TRANSACTION = 'UPDATE' OR @making_action_by_user LIKE '%UPDATE%') AND @confirm_acid_transaction = 1)
					BEGIN
						SET @alertSystemMessageDetails = '{"DB Info":"Prozess done", "Success":"OK"}'
						SET @alertSystemGeneralMessage = 'Der Eintrag in ZZEXECJOBS wurde aktualisiert'										
					 	SET @alertSystemMessageTitle = 'Eintrag aktualisiert'
                        SET @sp_executesql_sql_param = 'UPDATE ZZEXECJOBS SET  [inserted] = @escaped_inserted, [executed] = @escaped_executed, [command] = @escaped_command WHERE PK=@escaped_PK'
                        SET @sp_executesql_sql_param_variable_assignation = N' @escaped_inserted DATETIME, @escaped_executed DATETIME, @escaped_command NVARCHAR(MAX),  @escaped_PK INT  '
                        EXEC sp_executesql @sp_executesql_sql_param, @sp_executesql_sql_param_variable_assignation, @inserted, @executed, @command , @PK

					    IF(NOT EXISTS(SELECT PK FROM ZZEXECJOBS WHERE PK = @PK))
							BEGIN
								SET @alertSystemMessageDetails = '{"DB Info":"Datensatz exitiert nicht", "Grund":"In der DB nicht gefunden", "Reaktion":"Bitte den Fehler melden"}'
								SET @alertSystemGeneralMessage = 'Der Eintrag in ZZEXECJOBS mit der PK= '+CAST(@PK AS VARCHAR (32))+' kann nicht aktualisiert werden.'										
					 			SET @alertSystemMessageTitle = 'Eintrag Info'	
								SET @alertSystemGeneralMessageType = 'showerror'
							END
					END	
				IF ((@ACID_TRANSACTION = 'INSERT' OR @making_action_by_user LIKE '%INSERT%') AND @confirm_acid_transaction = 0)
					BEGIN
						SET @alertSystemMessageDetails = '{"DB Info":"Bitte beachten Sie, dass diese Transaktion nicht mehr als 3 Sekunden dauert", "Grund":"DB Erreichbarkeit kann nicht vorhanden sein", "Reaktion":"Bitte den Fehler melden, wenn er auftritt"}'
						SET @alertSystemGeneralMessage = 'Der Eintrag in ZZEXECJOBS wird angelegt. Bitte bestätigen Sie es!'										
					 	SET @alertSystemMessageTitle = 'Eintrag wird angelegt'	
						SET @alertSystemGeneralMessageType = 'askquestion'
					END
				ELSE IF ((@ACID_TRANSACTION = 'INSERT' OR @making_action_by_user LIKE '%INSERT%') AND @confirm_acid_transaction = 1)
					BEGIN
						SET @alertSystemMessageDetails = '{"DB Info":"Prozess done", "Success":"OK"}'
						SET @alertSystemGeneralMessage = 'Der Eintrag in ZZEXECJOBS wurde angelegt'										
					 	SET @alertSystemMessageTitle = 'Eintrag angelegt'
                        SET @sp_executesql_sql_param = 'INSERT INTO ZZEXECJOBS ([inserted],[executed],[command])VALUES( @escaped_inserted , @escaped_executed , @escaped_command )'
                        SET @sp_executesql_sql_param_variable_assignation = N' @escaped_inserted DATETIME, @escaped_executed DATETIME, @escaped_command NVARCHAR(MAX)'
                        EXEC sp_executesql @sp_executesql_sql_param, @sp_executesql_sql_param_variable_assignation, @inserted, @executed, @command 

					END						 					    
			END
		SET @jsonObjectResponse = '{"title":"'+@alertSystemMessageTitle+'","message":"'+@alertSystemGeneralMessage+'", "type":"'+@alertSystemGeneralMessageType+'", "result":['+@alertSystemMessageDetails+'], "newTSQL":"'+@newTSQL+'", "sql_in_separated_process":"'+@sql_in_separated_process+'","other_cmd":"'+@other_cmd+'", "separated_process_type":"'+@separated_process_type+'", "separated_process":"'+@separated_process+'"}'
		SELECT @jsonObjectResponse[PY_ZZEXECJOBS]		
	END TRY 
	BEGIN CATCH  
		SET @alertSystemGeneralMessageType = 'showerror'
		SET @jsonObjectResponse = '{"title":"'+@alertSystemMessageTitle+'", "message":"'+ERROR_MESSAGE()+'", "type":"'+@alertSystemGeneralMessageType+'", "result":[], "newTSQL":"'+@newTSQL+'", "sql_in_separated_process":"'+@sql_in_separated_process+'","other_cmd":"'+@other_cmd+'", "separated_process_type":"'+@separated_process_type+'", "separated_process":"'+@separated_process+'"}'
		SELECT @jsonObjectResponse[PY_ZZEXECJOBS]			
	END CATCH   
	    IF @jsonObjectResponse IS NULL	
			SELECT 'unknown error'[PY_ZZEXECJOBS]	
 
END
--GO 
				
GO
/****** Object:  StoredProcedure [dbo].[ADD_MANDANT_TO_GROUP]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[ADD_MANDANT_TO_GROUP]
	@MandantId INT,
	@Groupname VARCHAR(255) = 'ALL'
AS
BEGIN
	SET NOCOUNT ON

	IF( NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN
		RAISERROR (N'Mandant with Id ''%d'' does not exist.', 10, 1, @MandantId)
		RETURN
	END
	IF( @Groupname NOT IN ('ALL', 'DB') )
	BEGIN
		RAISERROR (N'Groupname ''%s'' is not allowed.', 10, 1, @Groupname)
		RETURN
	END

	IF( NOT( EXISTS(SELECT * FROM dbo.DEPLOYMENT_GROUPS WHERE Mandant_ID=@MandantId AND @Groupname=@Groupname) ) )
		INSERT INTO dbo.DEPLOYMENT_GROUPS ( Groupname, Mandant_ID )
			VALUES ( @Groupname, @MandantId )
	IF( @Groupname='ALL' )
		IF( NOT( EXISTS(SELECT * FROM dbo.DEPLOYMENT_GROUPS WHERE Mandant_ID=@MandantId AND @Groupname='DB') ) )
			INSERT INTO dbo.DEPLOYMENT_GROUPS ( Groupname, Mandant_ID )
				VALUES ( 'DB', @MandantId )
END
GO
