CREATE PROCEDURE [dbo].[ADD_UPDATES_FOR_GROUP]
	@environment VARCHAR(128) = 'ALL'
AS
BEGIN
	SET NOCOUNT ON

	/*IF( NOT( EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE type=@environment) ) )
	BEGIN
		RAISERROR (N'Groupname ''%s'' does not exist or is empty.', 10, 1, @environment)
		RETURN
	END 
	INSERT INTO dbo.Updates	( MANDAND_ID, DATE_INSERTED )
		SELECT Mandant_ID, GETDATE() FROM dbo.DEPLOYMENT_GROUPS WHERE Groupname=@environment*/

if @environment = 'ALL'
	INSERT INTO dbo.Updates	( ENVIRONMENT_ID  )	
		SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT ME where 
		[version]='6.0' AND 
		type in ('DEFAULT','ACC') AND PK NOT IN (SELECT MANDANT_ENVIRONMENT_PK FROM [dbo].[BLACKLIST_MANDANT_DB_ENVIRONMENT])
ELSE
	INSERT INTO dbo.Updates	( ENVIRONMENT_ID  )	
		SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT ME where
		[version]='6.0' AND 
		type in (@environment) AND PK NOT IN (SELECT MANDANT_ENVIRONMENT_PK FROM [dbo].[BLACKLIST_MANDANT_DB_ENVIRONMENT])
END
