CREATE PROCEDURE [dbo].[AUTOMATISCHE_PFLEGE_MANDANT_API_ENVIRONMENTS](
@mandantId INT = NULL, 
@environment VARCHAR(30) = 'ACC',
@version VARCHAR(30) = NULL,
@URL VARCHAR(255) = NULL,
@APP_TYPE VARCHAR(30) = 'C-CHEQ',
@DB VARCHAR(255) = NULL,
@HOST VARCHAR(255) = NULL,
@INSTANCE VARCHAR(255) = NULL,
@DB_USER VARCHAR(255) = NULL,
@PORT INT = NULL,
@CSAPP_URL VARCHAR(255) = NULL,
@PRINT_PATH VARCHAR(255) = NULL)
AS 
	SET NOCOUNT ON  --Nach Anweisungen von Florian wurde alles erstellt
	RETURN

	DECLARE @AbasIdAux INT, @ip VARCHAR(255), @dbname VARCHAR(255), @dbuser VARCHAR(512)= NULL, @dbpassword VARCHAR(512)= NULL, @XMLCompareData XML
	IF NOT EXISTS(SELECT id FROM dbo.Mandant WHERE id = @mandantId)
		BEGIN
			RETURN
		END
		IF (@version IS NULL)
			SET @version = (SELECT MAX(version) FROM CSAPP_version_URL)
		IF (@version IS NULL OR @APP_TYPE NOT IN ('C-CHEQ','C-SHARE') )
			RETURN
        IF (@environment <> '') -- Reinfolge APP ACC dann LIVE wird eingestellt  
			BEGIN        
			--SELECT * FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = 447
				SELECT TOP 1 @XMLCompareData = DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @environment
				IF (@XMLCompareData IS NOT NULL)
					BEGIN  
						SELECT  @HOST=HOST,@INSTANCE=INSTANCE,@DB=DB,@DB_USER=DB_USER,--@DB_USER_PW=DB_USER_PW,
						@PORT=PORT FROM dbo.GET_XML_DATACOMPARE_CREDENTIALS(@MandantId,@environment)					  
						/*DECLARE @InstanceIndexLimitator INT = dbo.LastIndexOf(@HOST,'\')
						DECLARE @InstanceIndexLimitatorPort INT = dbo.LastIndexOf(@HOST,',')
						DECLARE @HOSTlenght INT =  LEN(@host)
						--192.168.253.209,1433\CRENT
						SET @HOST = ISNULL(@XMLCompareData.value('(/Project/DataSource2/ServerName/text())[1]', 'NVARCHAR(128)'),'')
						SET @DB = @XMLCompareData.value('(/Project/DataSource2/DatabaseName/text())[1]', 'NVARCHAR(128)')
						SET @DB_USER = @XMLCompareData.value('(/Project/DataSource2/Username/text())[1]', 'NVARCHAR(128)')
						--SET @DB_USER_PW = @XMLCompareData.value('(/Project/DataSource2/Password/text())[1]', 'NVARCHAR(128)')

 
						IF (@InstanceIndexLimitator = @HOSTlenght AND @InstanceIndexLimitatorPort <> @HOSTlenght)
							BEGIN						
								SELECT @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitatorPort+2,LEN(@HOST))
								, @HOST = SUBSTRING(@HOST,1,@InstanceIndexLimitatorPort)--hier für den Port doof
							END	
						IF (@InstanceIndexLimitator <> @HOSTlenght AND @InstanceIndexLimitatorPort = @HOSTlenght)
							BEGIN						
								SELECT @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitator+2,LEN(@HOST))
								, @HOST = SUBSTRING(@HOST,1,@InstanceIndexLimitator)--hier für den Port doof
							END	
						IF (@InstanceIndexLimitator <> @HOSTlenght AND @InstanceIndexLimitatorPort <> @HOSTlenght)
							BEGIN						
								SELECT  @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitator+2,LEN(@HOST))
								, @HOST =  SUBSTRING(@HOST,1,@InstanceIndexLimitatorPort)--hier für den Port doof
								, @PORT = SUBSTRING(@HOST,@InstanceIndexLimitatorPort+2,CHARINDEX('\',@HOST)- (@InstanceIndexLimitatorPort+2) ) 
							END	  */
									
					END  				
			END      
        IF (@environment = 'ACC' AND @APP_TYPE = 'C-CHEQ')
			BEGIN
				IF (@URL IS NULL)
					SET @URL = 'https://ccheq-acc.cx9.de/index.php/'	
				IF (@PRINT_PATH IS NULL)
					BEGIN
						SET @PRINT_PATH = '/var/www/'+ISNULL((SELECT documentRoot FROM dbo.Mandant WHERE id=@MandantId),'NONEXISTENCE_CRENTWEB_PATH_INSTALLATION')+'/crentweb_test/print'
					END 																			
			END
        IF (@environment = 'ACC' AND @APP_TYPE = 'C-SHARE')
			BEGIN
				IF (@URL IS NULL)
					SET @URL = 'https://cshare-acc.cx9.de/index.php/'	
				IF (@PRINT_PATH IS NULL)
					BEGIN
						SET @PRINT_PATH = '/var/www/'+ISNULL((SELECT documentRoot FROM dbo.Mandant WHERE id=@MandantId),'NONEXISTENCE_CRENTWEB_PATH_INSTALLATION')+'/crentweb_test/print'
					END 																			
			END	
        IF (@environment = 'LIVE' AND @APP_TYPE = 'C-CHEQ')
			BEGIN
				IF (@URL IS NULL)
					SET @URL = 'https://ccheq.cx9.de/index.php/'		
				IF (@PRINT_PATH IS NULL)
					BEGIN
						SET @PRINT_PATH = '/var/www/'+ISNULL((SELECT documentRoot FROM dbo.Mandant WHERE id=@MandantId),'NONEXISTENCE_CRENTWEB_PATH_INSTALLATION')+'/crentweb/print'
					END  																		
			END
        IF (@environment = 'LIVE' AND @APP_TYPE = 'C-SHARE')
			BEGIN
				IF (@URL IS NULL)
					SET @URL = 'https://cshare.cx9.de/index.php/'		
				IF (@PRINT_PATH IS NULL)
					BEGIN
						SET @PRINT_PATH = '/var/www/'+ISNULL((SELECT documentRoot FROM dbo.Mandant WHERE id=@MandantId),'NONEXISTENCE_CRENTWEB_PATH_INSTALLATION')+'/crentweb/print'
					END 																							
			END						          
		IF (@URL IS NULL) RETURN
		IF (@DB IS NULL) SET @DB = '' 
--SELECT @PRINT_PATH,* FROM dbo.CSAPP_version_URL WHERE mandant = @mandantId AND version = @version AND APP_TYPE = @APP_TYPE
	IF NOT EXISTS(SELECT PK FROM dbo.CSAPP_version_URL WHERE mandant = @mandantId AND version = @version AND APP_TYPE = @APP_TYPE AND URL = @URL)
		BEGIN
			INSERT INTO dbo.CSAPP_version_URL (mandant, version, URL, APP_TYPE, DB, HOST, INSTANCE, DB_USER, PORT, CSAPP_URL, PRINT_PATH)
			SELECT @mandantId, @version, @URL, @APP_TYPE, @DB, @HOST, @INSTANCE, @DB_USER, @PORT, @CSAPP_URL, @PRINT_PATH
		END 
	ELSE IF EXISTS(SELECT PK FROM dbo.CSAPP_version_URL WHERE mandant = @mandantId AND version = @version AND APP_TYPE = @APP_TYPE AND URL = @URL)
	   BEGIN
			UPDATE dbo.CSAPP_version_URL SET URL = @URL,
			DB=@DB, HOST=@HOST, INSTANCE=@INSTANCE, DB_USER=@DB_USER, PORT=@PORT, 
			CSAPP_URL=@CSAPP_URL, PRINT_PATH=@PRINT_PATH
			WHERE mandant = @mandantId AND version = @version AND APP_TYPE = @APP_TYPE AND URL = @URL
		END 
	--Nach Anweisungen von Florian
	IF (@DB <> '' AND @HOST <> '' AND @DB_USER <> '')
	UPDATE dbo.Mandant SET databaseName = @DB, databaseIp = @HOST, databaseInstance = @INSTANCE, databaseUser = @DB_USER, databasePort=@PORT WHERE id = @mandantId
GO
/****** Object:  StoredProcedure [dbo].[AUTOMATISCHE_PFLEGE_MANDANT_DB_ENVIRONMENT_UPDATE_DOKU]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[AUTOMATISCHE_PFLEGE_MANDANT_DB_ENVIRONMENT_UPDATE_DOKU](
@MANDANT_ID INT = NULL,  
@MANDANT_ENVIRONMENT VARCHAR(128) = NULL,
@MRJASPERNUMMER VARCHAR(32) = NULL,
@MRCRWNUMMER1 VARCHAR(32) = NULL,
@MRCRWNUMMER2 VARCHAR(32) = NULL
)
AS 	SET NOCOUNT ON
BEGIN
	DECLARE @deployPath VARCHAR(2048) = dbo.UPDATES_TMP_DEPLOY_FOLDER() 
	DECLARE @deployFile VARCHAR(2048) = ''
	IF ((ISNUMERIC(@MRJASPERNUMMER) = 0) OR (ISNUMERIC(@MRCRWNUMMER1) = 0) OR (ISNUMERIC(@MRCRWNUMMER2) = 0))
		BEGIN
			PRINT 'Falsche Einträge'
			RETURN	
		END
		
	DECLARE @MANDANT_ENVIRONMENT_AUX VARCHAR(128) = (CASE WHEN @MANDANT_ENVIRONMENT='LIVE' THEN 'DEFAULT' ELSE @MANDANT_ENVIRONMENT END)

	IF ( NOT EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@MANDANT_ID AND type=@MANDANT_ENVIRONMENT_AUX AND version = '6.0'))
		BEGIN
			SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@MANDANT_ID
			PRINT 'Environtment ist nicht auf 6.0 oder er existiert nicht'
			RETURN 
		END
	DECLARE @updateSuccess BIT = CASE WHEN dbo.GET_ENVIRONMENT_LOG_ERRORS(@MANDANT_ID, @MANDANT_ENVIRONMENT) = '' THEN 1 ELSE 0 END
	IF (@updateSuccess <> 1)
		BEGIN
			SELECT 
			 dbo.GET_ENVIRONMENT_LOG_ERRORS(@MANDANT_ID,@MANDANT_ENVIRONMENT)[GET_ENVIRONMENT_LOG_ERRORS],
			 dbo.GET_ENVIRONMENT_COMPARE_RESULT_LOG_ERRORS(@MANDANT_ID,@MANDANT_ENVIRONMENT,'SCHEMA')[GET_ENVIRONMENT_LOG_ERRORS],
			  * FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID =  @MANDANT_ID
			PRINT 'Environtment LOGs 6.0 nicht erfolgreich'		
			RETURN	
		END
	IF (@updateSuccess = 1)
		BEGIN
			DECLARE @MRLinkBeschreibung NVARCHAR(2048) = ''   
			DECLARE @ENVIRONMENT_ID INT
			SELECT TOP 1 @ENVIRONMENT_ID = PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id=@MANDANT_ID AND type=@MANDANT_ENVIRONMENT_AUX AND version = '6.0'
			PRINT @ENVIRONMENT_ID
			IF (ISNUMERIC(@ENVIRONMENT_ID)=1)
				BEGIN
					IF NOT EXISTS (SELECT * FROM dbo.Updates WHERE ENVIRONMENT_ID = @ENVIRONMENT_ID AND ISDATE(DATE_UPDATE)=0 )
						INSERT INTO dbo.Updates( ENVIRONMENT_ID  )
							SELECT @ENVIRONMENT_ID

					SELECT * FROM dbo.Updates WHERE ENVIRONMENT_ID = @ENVIRONMENT_ID
				END 
			EXEC dbo.TRIGGER_WEB_UPDATE @mandant_id = @MANDANT_ID, @mandant_environment_name = @MANDANT_ENVIRONMENT  
			EXEC dbo.PFLEGE_XML_LOG_MANDANT_WEB_PRODUKTE_UPDATE @mandantId = @MANDANT_ID, -- int
				@environment = @MANDANT_ENVIRONMENT, -- nvarchar(32)
				@logType = N'createReservierungFolder', -- nvarchar(128)
				@dataType = N'userInput', -- nvarchar(128)
				@message = N'Manuell'
 
			EXEC dbo.PFLEGE_XML_LOG_MANDANT_WEB_PRODUKTE_UPDATE @mandantId = @MANDANT_ID, -- int
				@environment = @MANDANT_ENVIRONMENT, -- nvarchar(32)
				@logType = N'createCRentWebFolder', -- nvarchar(128)
				@dataType = N'userInput', -- nvarchar(128)
				@message = N'Pipeline '
 
			EXEC dbo.PFLEGE_XML_LOG_MANDANT_WEB_PRODUKTE_UPDATE @mandantId = @MANDANT_ID, -- int
				@environment = @MANDANT_ENVIRONMENT, -- nvarchar(32)
				@logType = N'JasperMR', -- nvarchar(128)
				@dataType = N'userInput', -- nvarchar(128)
				@message = N'Manuell'
 
			EXEC dbo.PFLEGE_XML_LOG_MANDANT_WEB_PRODUKTE_UPDATE @mandantId = @MANDANT_ID, -- int
				@environment = @MANDANT_ENVIRONMENT, -- nvarchar(32)
				@logType = N'CRentWebMR', -- nvarchar(128)
				@dataType = N'userInput', -- nvarchar(128)
				@message = N'Manuell'
			SET @MRLinkBeschreibung = 'MR unter http://gitlab.cx9.info:8000/web/CRENTWEB_DEV/-/merge_requests/'+@MRCRWNUMMER1+' wurde gemerged' 
			EXEC dbo.PFLEGE_XML_LOG_MANDANT_WEB_PRODUKTE_UPDATE @mandantId = @MANDANT_ID, -- int
				@environment = @MANDANT_ENVIRONMENT, -- nvarchar(32)
				@logType = N'CX9GitLabCRentWebApprovedMR', -- nvarchar(128)
				@dataType = N'userInput', -- nvarchar(128)
				@message = @MRLinkBeschreibung -- nvarchar(max)
			SET @MRLinkBeschreibung = 'MR unter http://gitlab.cx9.info:8000/web/CRENTWEB_DEV/-/merge_requests/'+@MRCRWNUMMER2+' wurde gemerged' 
 
			EXEC dbo.PFLEGE_XML_LOG_MANDANT_WEB_PRODUKTE_UPDATE @mandantId = @MANDANT_ID, -- int
				@environment = @MANDANT_ENVIRONMENT, -- nvarchar(32)
				@logType = N'CX9GitLabCRentWebApprovedMR', -- nvarchar(128)
				@dataType = N'userInput', -- nvarchar(128)
				@message = @MRLinkBeschreibung
 			SET @MRLinkBeschreibung = 'MR unter http://gitlab.cx9.info:8000/cx9/jasper/-/merge_requests/'+@MRJASPERNUMMER+' wurde gemerged' 

			EXEC dbo.PFLEGE_XML_LOG_MANDANT_WEB_PRODUKTE_UPDATE @mandantId = @MANDANT_ID, -- int
				@environment = @MANDANT_ENVIRONMENT, -- nvarchar(32)
				@logType = N'CX9GitLabJasperApprovedMR', -- nvarchar(128)
				@dataType = N'userInput', -- nvarchar(128)
				@message = @MRLinkBeschreibung

			DECLARE @updateTriggerContents VARCHAR(MAX) = ''
			SET @updateTriggerContents =  dbo.getCRent60UpdateSHReservation(@MANDANT_ID, @MANDANT_ENVIRONMENT)  
			SET @updateTriggerContents = CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), @updateTriggerContents), 1)		 
			SET @updateTriggerContents = SUBSTRING(@updateTriggerContents,3,LEN(@updateTriggerContents))	
			SET @deployFile = @deployPath+'\deployment6\script.sh' 
			EXEC dbo.WriteFile @fileName = @deployFile, @fileContents = @updateTriggerContents

		END
END 
GO
/****** Object:  StoredProcedure [dbo].[AUTOMATISCHE_PFLEGE_MANDANT_WEB_ENVIRONMENTS]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
