GO
CREATE PROCEDURE [dbo].[AUTOMATISCHE_PFLEGE_MANDANT_WEB_ENVIRONMENTS](
@MandantId INT = NULL, 
@AbasId INT = NULL, 
@Environment VARCHAR(128) = 'ACC',
@EnvironmentUpdateDate DATETIME,
@version VARCHAR(30) = '6.0', 
@DB VARCHAR(255) = '',
@HOST VARCHAR(255) = '',
@INSTANCE VARCHAR(255) = '',
@DB_USER VARCHAR(255) = '',
@DB_USER_PW VARCHAR(255) = '',
@PORT INT = NULL,
@JasperBranch VARCHAR(255) = 'master',
@MainCRWBranch VARCHAR(255) = 'master',
@KUNDEN02_ORDNER_PREFIX VARCHAR(255) = '',
@searchDataIndex VARCHAR(128) ='',
@ABAS_TASK_NO VARCHAR(128) ='',
@WEBSERVERIP VARCHAR(128) = '',
@WEBSERVERSSHUSER VARCHAR(128) = '',
@WEBSERVERSSHUSERPW VARCHAR(128) = '',
@forceUpdate BIT = 0,
@batExec BIT = 1,
@doubleMandEnviroments BIT = 0
)
AS 
	SET NOCOUNT ON
    IF (@Environment = 'ACC')
		SET @KUNDEN02_ORDNER_PREFIX = '_test'
	DECLARE @AbasIdAux INT, @ip VARCHAR(255), @dbname VARCHAR(255), @dbuser VARCHAR(512)= NULL,
	@dbpassword VARCHAR(512)= NULL, @XMLCompareData XML,
	@batchEndTriggerCommand VARCHAR(2048) = 'DIR',
	@EnvironmentAux VARCHAR(128) = (CASE WHEN @Environment='LIVE' THEN 'DEFAULT' ELSE @Environment END)
	IF NOT EXISTS(SELECT id FROM dbo.Mandant WHERE id = @mandantId)
		BEGIN
			RETURN
		END 
    SET @AbasIdAux = ISNULL((SELECT abasId FROM dbo.Mandant WHERE id = @mandantId),0)
	IF (@AbasIdAux = 0 AND ISNULL(@AbasId,0) > 0)
		BEGIN
			PRINT 'AbasId des Kunden ist nicht gepflegt. Der Eintrag wird aktualisert.'
			UPDATE dbo.Mandant SET abasId = @AbasId WHERE id = @mandantId			
		END
        IF (@forceUpdate = 0 AND @environment <> 'LIVE' AND EXISTS(SELECT TOP 1 DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @environment AND MANDANT_ID=@MandantId))    
			BEGIN        
				SELECT TOP 1 @XMLCompareData = DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @environment  AND MANDANT_ID=@MandantId
				IF (@XMLCompareData IS NOT NULL)
					BEGIN  
						SELECT  @HOST=HOST,@INSTANCE=INSTANCE,@DB=DB,@DB_USER=DB_USER,@DB_USER_PW=DB_USER_PW,
						@PORT=PORT FROM dbo.GET_XML_DATACOMPARE_CREDENTIALS(@MandantId,@environment)  
						/*DECLARE @InstanceIndexLimitator INT = dbo.LastIndexOf(@HOST,'\')
						DECLARE @InstanceIndexLimitatorPort INT = dbo.LastIndexOf(@HOST,',')
						DECLARE @HOSTlenght INT =  LEN(@host)
						--192.168.253.209,1433\CRENT
						SET @HOST = ISNULL(@XMLCompareData.value('(/Project/DataSource2/ServerName/text())[1]', 'NVARCHAR(128)'),'')
						SET @DB = @XMLCompareData.value('(/Project/DataSource2/DatabaseName/text())[1]', 'NVARCHAR(128)')
						SET @DB_USER = @XMLCompareData.value('(/Project/DataSource2/Username/text())[1]', 'NVARCHAR(128)')
						SET @DB_USER_PW = @XMLCompareData.value('(/Project/DataSource2/Password/text())[1]', 'NVARCHAR(128)')
 
 
						IF (@InstanceIndexLimitator = @HOSTlenght AND @InstanceIndexLimitatorPort <> @HOSTlenght)
							BEGIN						
								SELECT @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitatorPort+2,LEN(@HOST))
								, @HOST = SUBSTRING(@HOST,1,@InstanceIndexLimitatorPort)--hier für den Port doof
							END	
						IF (@InstanceIndexLimitator <> @HOSTlenght AND @InstanceIndexLimitatorPort = @HOSTlenght)
							BEGIN						
								SELECT @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitator+2,LEN(@HOST))
								, @HOST = SUBSTRING(@HOST,1,@InstanceIndexLimitator)--hier für den Port doof
							END	
						IF (@InstanceIndexLimitator <> @HOSTlenght AND @InstanceIndexLimitatorPort <> @HOSTlenght)
							BEGIN						
								SELECT  @INSTANCE = SUBSTRING(@HOST,@InstanceIndexLimitator+2,LEN(@HOST))
								, @HOST =  SUBSTRING(@HOST,1,@InstanceIndexLimitatorPort)--hier für den Port doof
								, @PORT = SUBSTRING(@HOST,@InstanceIndexLimitatorPort+2,CHARINDEX('\',@HOST)- (@InstanceIndexLimitatorPort+2) ) 
							END	  */		
					END 
 				
			END  
	IF NOT EXISTS(SELECT PK FROM dbo.MANDANT_WEB_PRODUKTE WHERE mandantId = @mandantId AND version = @version AND Environment = @Environment)
		BEGIN 
			INSERT INTO dbo.MANDANT_WEB_PRODUKTE 
				 (mandantId, version, Environment, DB, HOST, INSTANCE, DB_USER, DB_USER_PW, PORT, JasperBranch, MainCRWBranch, KUNDEN02_ORDNER_PREFIX, searchDataIndex, ABAS_TASK_NO, TIMEOFUPDATE)
			SELECT @mandantId, @version, @Environment, @DB, @HOST, @INSTANCE, @DB_USER, @DB_USER_PW, @PORT, @JasperBranch, @MainCRWBranch, @KUNDEN02_ORDNER_PREFIX, @searchDataIndex, @ABAS_TASK_NO, @EnvironmentUpdateDate
			IF (ISNULL(@WEBSERVERIP,'')<>'' AND ISNULL(@WEBSERVERSSHUSER,'')<>'' AND ISNULL(@WEBSERVERSSHUSERPW,'')<>'')
				UPDATE dbo.MANDANT_WEB_PRODUKTE SET WEBSERVERIP=@WEBSERVERIP, WEBSERVERSSHUSER=@WEBSERVERSSHUSER, WEBSERVERSSHUSERPW=@WEBSERVERSSHUSERPW WHERE mandantId = @mandantId AND version = @version AND Environment = @Environment
		END 
	ELSE IF EXISTS(SELECT PK FROM dbo.MANDANT_WEB_PRODUKTE WHERE mandantId = @mandantId AND version = @version AND Environment = @Environment)
	   BEGIN
			UPDATE dbo.MANDANT_WEB_PRODUKTE SET Environment = @Environment,
			DB=@DB, HOST=@HOST, INSTANCE=@INSTANCE, DB_USER=@DB_USER, DB_USER_PW=@DB_USER_PW, PORT=@PORT, 
			JasperBranch=@JasperBranch, MainCRWBranch=@MainCRWBranch, KUNDEN02_ORDNER_PREFIX=@KUNDEN02_ORDNER_PREFIX, searchDataIndex=@searchDataIndex, ABAS_TASK_NO=@ABAS_TASK_NO, TIMEOFUPDATE=@EnvironmentUpdateDate
			WHERE mandantId = @mandantId AND version = @version AND Environment = @Environment
			IF (ISNULL(@WEBSERVERIP,'')<>'' AND ISNULL(@WEBSERVERSSHUSER,'')<>'' AND ISNULL(@WEBSERVERSSHUSERPW,'')<>'')
				UPDATE dbo.MANDANT_WEB_PRODUKTE SET WEBSERVERIP=@WEBSERVERIP, WEBSERVERSSHUSER=@WEBSERVERSSHUSER, WEBSERVERSSHUSERPW=@WEBSERVERSSHUSERPW WHERE mandantId = @mandantId AND version = @version AND Environment = @Environment
		END
    IF (@doubleMandEnviroments = 1)
		BEGIN
			INSERT INTO dbo.MANDANT_DB_ENVIRONMENT(mandant_id, type, version, databaseIp, databaseInstance, databaseName, databaseUser, tsCreateDate, databasePort)
				SELECT  @mandantId,'DEFAULT',
					'6.0',@HOST,@INSTANCE,@DB,@DB_USER, CURRENT_TIMESTAMP, @PORT			
		END 
	ELSE 
		BEGIN
			IF NOT EXISTS(SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @mandantId AND version = @version AND type = @EnvironmentAux)
				BEGIN 
					INSERT INTO dbo.MANDANT_DB_ENVIRONMENT(mandant_id, type, version, databaseIp, databaseInstance, databaseName, databaseUser, tsCreateDate, databasePort)
					  SELECT  MandantId,@EnvironmentAux,
							ISNULL(version,'') ,ISNULL(HOST,''),ISNULL(INSTANCE,''),ISNULL(DB,''),ISNULL(DB_USER,''), CURRENT_TIMESTAMP, PORT
					FROM dbo.MANDANT_WEB_PRODUKTE mwp WHERE mwp.MandantId=@mandantId AND mwp.Environment = @Environment

					UPDATE 
						 t1
					SET 
						 t1.C_RENT_ENVIRONMENT_PK = t2.PK 
					FROM 
						 MANDANT_WEB_PRODUKTE t1,
						 MANDANT_DB_ENVIRONMENT t2
					WHERE 
						 t1.DB = t2.databaseName 
						 AND t1.HOST = t2.databaseIp
						 AND t1.DB_USER = t2.databaseUser
						 AND t1.INSTANCE = t2.databaseInstance
						 AND t1.MandantId=@mandantId 

				END 
			ELSE IF EXISTS(SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @mandantId AND version = @version AND type = @EnvironmentAux)
			   BEGIN
					UPDATE dbo.MANDANT_DB_ENVIRONMENT SET  databaseIp=@HOST, databaseInstance = @INSTANCE, databaseName=@DB,
					databaseUser=@DB_USER, databasePort=@PORT WHERE mandant_id = @mandantId AND version = @version AND type = @EnvironmentAux			 
				END			
		END     

	SET @batchEndTriggerCommand = 'cd C:\SQLJobs'+CHAR(13)
	SET @batchEndTriggerCommand = 'makeGlobalJob.bat av_'+CAST(@mandantId AS VARCHAR(32))+' '+CAST(@mandantId AS VARCHAR(32))+' '+CAST(@AbasIdAux AS VARCHAR(32))+' '+@Environment+' '+@ABAS_TASK_NO
	PRINT 'In ca. 10 Sekunden wird der folgende commando auf dem 192.168.254.210 ausgeführt, wenn @batExec auf 1 dieser Prozedur gestellt ist'
	PRINT @batchEndTriggerCommand
	IF (@batExec = 1)
		PRINT dbo.WRITE_STRING_TO_FILE_LINE_BY_LINE (@batchEndTriggerCommand, 'C:\updates6\commandUpdate60.txt') -- varchar(max)

	EXEC dbo.GET_SQL_COMPARE_XML @MandantId = @mandantId, @Environment = @Environment, @compareType='DATA'
	EXEC dbo.GET_SQL_COMPARE_XML @MandantId = @mandantId, @Environment = @Environment, @compareType='SCHEMA'
	SELECT * FROM MANDANT_WEB_PRODUKTE WHERE MandantId = @mandantId
	SELECT * FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId
GO
/****** Object:  StoredProcedure [dbo].[AUTOMATISCHE_PFLEGE_MANDANT_WEB_ENVIRONMENTS_BY_MANDANT_ENVIRONMENT_PK]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[AUTOMATISCHE_PFLEGE_MANDANT_WEB_ENVIRONMENTS_BY_MANDANT_ENVIRONMENT_PK](
@AbasId INT = NULL, 
@MANDANT_ENVIRONMENT_PK INT = NULL,  
@EnvironmentUpdateDate DATETIME,
@versionToBeUpdated NVARCHAR(30) = '6.0',
@JasperBranch VARCHAR(255) = '',
@MainCRWBranch VARCHAR(255) = 'master',
@kundenBetreuerMails VARCHAR(2048) = 'a.bernhard@cx9.de',
@KUNDEN02_ORDNER_PREFIX VARCHAR(255) = '',
@searchDataIndex VARCHAR(128) ='',
@ABAS_TASK_NO VARCHAR(128) ='',
@WEBSERVERIP VARCHAR(128) = '',
@WEBSERVERSSHUSER VARCHAR(128) = '',
@WEBSERVERSSHUSERPW VARCHAR(128) = '', 
@CLIENT_INTERN_HOST VARCHAR(128) = '' 
)
AS 
			--EXEC dbo.SEND_MAIL_BEFORE_UPDATE @mandID = 245, @env = 'ACC', @reportJustDeveloper = 1  
	SET NOCOUNT ON
	DECLARE @WHERE_CONDITION NVARCHAR(128) =  N' PK = '+CAST(@MANDANT_ENVIRONMENT_PK AS VARCHAR(16))     
	
	IF NOT EXISTS (SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @MANDANT_ENVIRONMENT_PK AND type IN ('ACC', 'DEFAULT'))  
		BEGIN
			EXEC dbo.getHelpDefinitionVariablesFromTableProc @TABLE_NAME   = 'MANDANT_DB_ENVIRONMENT', @WHERE_CONDITION = @WHERE_CONDITION
			RETURN 'Umgebung kann nicht üpgedatet werden: '
		END
		
	DECLARE @mandant_id INT = NULL 	DECLARE @PK INT = NULL 	DECLARE @type NVARCHAR(30) = NULL 	DECLARE @path NVARCHAR(255) = NULL 	DECLARE @version NVARCHAR(30) = NULL 	DECLARE @fromversion NVARCHAR(30) = NULL 	DECLARE @databaseIp NVARCHAR(255) = NULL 	DECLARE @databaseInstance NVARCHAR(255) = NULL 	DECLARE @databaseName NVARCHAR(255) = NULL 	DECLARE @databaseUser NVARCHAR(255) = NULL 	DECLARE @tsCreateDate DATETIME2 = NULL 	DECLARE @installBase INT = NULL 	DECLARE @databasePort INT = NULL	DECLARE @mailAnBetreuer BIT = NULL 
	DECLARE @mailAnKunden BIT = NULL     	DECLARE @databaseUser_PW NVARCHAR(255) = ''
	DECLARE @updateSuccess BIT = 0
	DECLARE @deployPath VARCHAR(2048) = dbo.UPDATES_TMP_DEPLOY_FOLDER() 
	DECLARE @deployFile VARCHAR(2048) = ''
	SELECT TOP 1  @mandant_id=ISNULL(mandant_id,@mandant_id), @PK=ISNULL(PK,@PK), @type=ISNULL(type,@type), @path=ISNULL(path,@path), @version=ISNULL(version,@version), @databaseIp=ISNULL(databaseIp,@databaseIp), @databaseInstance=ISNULL(databaseInstance,@databaseInstance), @databaseName=ISNULL(databaseName,@databaseName), @databaseUser=ISNULL(databaseUser,@databaseUser), @tsCreateDate=ISNULL(tsCreateDate,@tsCreateDate), @installBase=ISNULL(installBase,@installBase), @databasePort=ISNULL(databasePort,@databasePort) FROM MANDANT_DB_ENVIRONMENT WHERE  PK = @MANDANT_ENVIRONMENT_PK
	--SELECT  @mandant_id[mandant_id], @PK[PK], @type[type], @path[path], @version[version], @databaseIp[databaseIp], @databaseInstance[databaseInstance], @databaseName[databaseName], @databaseUser[databaseUser], @tsCreateDate[tsCreateDate], @installBase[installBase], @databasePort[databasePort]
	SET @fromversion = @version
	SET @databaseUser_PW = dbo.SEC_GetPWCOde(@databaseUser)
	IF (@type = @versionToBeUpdated)
		BEGIN
			SET @WHERE_CONDITION =  N' PK = '+CAST(@MANDANT_ENVIRONMENT_PK AS VARCHAR(16))     
			RETURN 'Umgebung kann nicht üpgedatet werden: Es handelt sich um die selber DB-version'
			EXEC dbo.getHelpDefinitionVariablesFromTableProc @TABLE_NAME   = 'MANDANT_DB_ENVIRONMENT', @WHERE_CONDITION = @WHERE_CONDITION			
		END
    IF (ISNULL(@JasperBranch,'')='')
		SET @JasperBranch = dbo.GET_MANDANT_JASPER_DEPLOYMENT_NAME(@mandant_id)
    IF (ISNULL(@kundenBetreuerMails,'')='')
		SET @kundenBetreuerMails = 'a.bernhard@cx9.de'
    IF (ISNULL(@searchDataIndex,'')='')
		SET @searchDataIndex = dbo.GET_MANDANT_JASPER_DEPLOYMENT_NAME(@mandant_id)
			--SELECT @searchDataIndex,@kundenBetreuerMails,@JasperBranch
-- RETURN    
    IF (@type = 'ACC')
		SET @KUNDEN02_ORDNER_PREFIX = '_test'
	DECLARE @OrigAbasId INT, @XMLCompareData XML,
	@batchEndTriggerCommand VARCHAR(2048) = 'DIR',
	@environment NVARCHAR(128) = (CASE WHEN @type='DEFAULT' THEN 'LIVE' ELSE @type END)
	IF NOT EXISTS(SELECT id FROM dbo.Mandant WHERE id = @mandant_id)
		BEGIN
			SET @WHERE_CONDITION =  N' ID = '+CAST(@mandant_id AS VARCHAR(16)) 
			RETURN 'Mandand ID existiert nicht'    			      
			EXEC dbo.getHelpDefinitionVariablesFromTableProc @TABLE_NAME   = 'MANDANT', @WHERE_CONDITION = @WHERE_CONDITION						
		END 
    SET @OrigAbasId = ISNULL((SELECT abasId FROM dbo.Mandant WHERE id = @mandant_id),0)
	IF (@OrigAbasId = 0 AND ISNULL(@AbasId,0) > 0)
		BEGIN
			PRINT 'AbasId des Kunden ist nicht gepflegt. Der Eintrag wird aktualisert.'
			UPDATE dbo.Mandant SET abasId = @AbasId WHERE id = @mandant_id			
		END
    SET @OrigAbasId = ISNULL((SELECT abasId FROM dbo.Mandant WHERE id = @mandant_id),0)      
    --restart crent db updates 
	--DELETE  FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @mandant_id
	SET @updateSuccess = CASE WHEN dbo.GET_ENVIRONMENT_LOG_ERRORS(@mandant_id, @environment) = '' THEN 1 ELSE 0 END
 
	IF (@updateSuccess = 0)
		DELETE FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandant_id AND ENVIRONMENT = @environment
	/*EXEC dbo.C_RENT_PRODUKTE_UPDATE6_RESTART @MandantId = @mandant_id, -- int
	    @environment = @environment, -- nvarchar(32)
	    @forceUpdate = 1 -- bit*/
		--RETURN
	       
    IF (EXISTS(SELECT TOP 1 DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @environment AND MANDANT_ID=@mandant_id))    
		BEGIN        
			SELECT TOP 1 @XMLCompareData = DATA FROM [dbo].[DB_SCHEMA_DATA_COMPARE_UPDATE] WHERE ENVIRONMENT = @environment  AND MANDANT_ID=@mandant_id
			IF (@XMLCompareData IS NOT NULL)
				BEGIN  
					SELECT  @databaseIp=HOST,@databaseInstance=INSTANCE,@databaseName=DB,@databaseUser=DB_USER,@databaseUser_PW=DB_USER_PW,
					@databasePort=PORT FROM dbo.GET_XML_DATACOMPARE_CREDENTIALS(@mandant_id,@environment) 		
				END 
 				
		END 
	IF EXISTS (SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE  mandantId = @mandant_id AND version < @versionToBeUpdated AND Environment = @environment)
		DELETE FROM MANDANT_WEB_PRODUKTE WHERE mandantId = @mandant_id AND version < @versionToBeUpdated  AND Environment = @environment 
	IF NOT EXISTS(SELECT PK FROM dbo.MANDANT_WEB_PRODUKTE WHERE mandantId = @mandant_id AND version = @versionToBeUpdated AND Environment = @environment)
		BEGIN 
			INSERT INTO dbo.MANDANT_WEB_PRODUKTE 
				 (mandantId, version, Environment, DB, HOST, INSTANCE, DB_USER, DB_USER_PW, PORT, JasperBranch, MainCRWBranch, KUNDEN02_ORDNER_PREFIX, searchDataIndex, ABAS_TASK_NO, TIMEOFUPDATE, betreuer, C_RENT_ENVIRONMENT_PK, CLIENT_INTERN_HOST)
			SELECT @mandant_id, @versionToBeUpdated, @environment, @databaseName, @databaseIp, @databaseInstance, @databaseUser, @databaseUser_PW, @databasePort, @JasperBranch, @MainCRWBranch, @KUNDEN02_ORDNER_PREFIX, @searchDataIndex, @ABAS_TASK_NO, @EnvironmentUpdateDate,@kundenBetreuerMails, @MANDANT_ENVIRONMENT_PK, @CLIENT_INTERN_HOST
			IF (ISNULL(@WEBSERVERIP,'')<>'' AND ISNULL(@WEBSERVERSSHUSER,'')<>'' AND ISNULL(@WEBSERVERSSHUSERPW,'')<>'')
				UPDATE dbo.MANDANT_WEB_PRODUKTE SET WEBSERVERIP=@WEBSERVERIP, WEBSERVERSSHUSER=@WEBSERVERSSHUSER, WEBSERVERSSHUSERPW=@WEBSERVERSSHUSERPW WHERE mandantId = @mandant_id AND version = @versionToBeUpdated AND Environment = @environment
			IF (EXISTS (SELECT PK FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID AND Environment = @environment ))
				UPDATE MANDANT_WEB_PRODUKTE SET fromversion = @fromversion WHERE MandantId = @MANDANT_ID AND Environment = @environment
		END 
	ELSE IF EXISTS(SELECT PK FROM dbo.MANDANT_WEB_PRODUKTE WHERE mandantId = @mandant_id AND version = @versionToBeUpdated AND Environment = @environment)
	   BEGIN
			UPDATE dbo.MANDANT_WEB_PRODUKTE SET Environment = @environment,
			DB=@databaseName, HOST=@databaseIp, INSTANCE=@databaseInstance, DB_USER=@databaseUser, DB_USER_PW=@databaseUser_PW, PORT=@databasePort, 
			JasperBranch=@JasperBranch, MainCRWBranch=@MainCRWBranch, KUNDEN02_ORDNER_PREFIX=@KUNDEN02_ORDNER_PREFIX, searchDataIndex=@searchDataIndex, ABAS_TASK_NO=@ABAS_TASK_NO, TIMEOFUPDATE=@EnvironmentUpdateDate, betreuer =@kundenBetreuerMails, C_RENT_ENVIRONMENT_PK = @MANDANT_ENVIRONMENT_PK, CLIENT_INTERN_HOST = @CLIENT_INTERN_HOST
			WHERE mandantId = @mandant_id AND version = @versionToBeUpdated AND Environment = @environment
			IF (ISNULL(@WEBSERVERIP,'')<>'' AND ISNULL(@WEBSERVERSSHUSER,'')<>'' AND ISNULL(@WEBSERVERSSHUSERPW,'')<>'')
				UPDATE dbo.MANDANT_WEB_PRODUKTE SET WEBSERVERIP=@WEBSERVERIP, WEBSERVERSSHUSER=@WEBSERVERSSHUSER, WEBSERVERSSHUSERPW=@WEBSERVERSSHUSERPW WHERE mandantId = @mandant_id AND version = @versionToBeUpdated AND Environment = @environment
		END
	IF (@version <> @versionToBeUpdated)
		UPDATE dbo.MANDANT_DB_ENVIRONMENT SET version = @versionToBeUpdated WHERE PK = @MANDANT_ENVIRONMENT_PK      
	   
    UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET C_RENT_ENVIRONMENT_PK=@MANDANT_ENVIRONMENT_PK WHERE MANDANT_ID = @mandant_id AND ENVIRONMENT = @environment
		      
	SET @batchEndTriggerCommand = 'C:\SQLJobs\makeGlobalJob.bat av_'+CAST(@mandant_id AS VARCHAR(32))+' '+CAST(@mandant_id AS VARCHAR(32))+' '+CAST(@OrigAbasId AS VARCHAR(32))+' '+@environment+' '+@ABAS_TASK_NO
	--PRINT 'In ca. 10 Sekunden wird der folgende commando auf dem 192.168.254.210 ausgeführt, wenn @batExec auf 1 dieser Prozedur gestellt ist'
    DECLARE @subject NVARCHAR(MAX) = 'Anfrage Nr. '+@ABAS_TASK_NO+' '+@environment+' Update 6.0 Kommando auf 192.168.254.210 wird ausgeführt'
    DECLARE @EmailContents NVARCHAR(MAX) = 'Hallo guter Mann, <br><br><br><b>folgenden Kommando auf dem 192.168.254.210 wird ausgeführt unter window+run / batch:</b> <br><br> '+@batchEndTriggerCommand+' <br><br> Es ist wichtig die individuellen Programmierungen ins CX9 Gitlab zu sichern und dem Kunden Umgebung ausliefern. <br><br>Viel Spaß damit!<br><br>'  
	IF(@updateSuccess = 1)
		SET @EmailContents = 'Hallo guter Mann, <br><br><br><b>der Kommando auf dem 192.168.254.210 unter window+run:</b> <br><br> <p style="font-weight: bold; font-size: 25px; color: #4CAF50;">'+@batchEndTriggerCommand+' wurde bereits ausgeführt.</p><br><br>'  
	ELSE 
		BEGIN  
			--EXEC dbo.DEPLOY_DB_ENVIRONMENTS @mandID = @mandant_id, @userEnv = @environment
			EXEC dbo.DEPLOY_DB_ENVIRONMENT_MULTITASK @MANDANT_ID = @mandant_id, @ENVIRONMENT_NAME = @environment 
			DECLARE @subFolder VARCHAR(1024) = 'single\'+CAST(@mandant_id AS NVARCHAR(32))
			DECLARE @deploymentName VARCHAR(1024) =   dbo.getLocalNameDeploymentFileByName(@mandant_id,@type,'SCHEMA',@subFolder)
			PRINT @deploymentName
			DECLARE @deploymentKunden NVARCHAR(2048) = ''  
			SELECT TOP 1 @deploymentKunden = MANDANT_NAME FROM dbo.GET_CRW6DEPLOYMENT_MANDANT_DB_ENVIRONMENT(@mandant_id)  WHERE MANDANT_ID=@mandant_id
			DECLARE @path VARCHAR(1024) = @deploymentName
			DECLARE @preUpdateSkripte VARCHAR(1024) = ''

			
			DECLARE @batchGetDBChangesRemoteDB VARCHAR(1024) =   ''
			DECLARE @lastIndex INT = CHARINDEX('Schema Compare',@path)
			IF (@lastIndex > 0)
				BEGIN 
					SET @preUpdateSkripte = SUBSTRING(@path,1,@lastIndex-1)+'advance_trans_deployment\deploy.bat' 
					SET @path = SUBSTRING(@path,1,@lastIndex-1)	+'tableReports\tableDiffs.bat' 
					SET @batchGetDBChangesRemoteDB= ''+@path 
					SET @preUpdateSkripte= ''+@preUpdateSkripte 
				END 
			SET @deployFile = @deployPath + '\updates\crent_schema'
			EXEC dbo.CLEAN_SERVER_LOCAL_FOLDER @SHARED_PATH_OR_FILE = @deployFile ---clean my folder
			SET @deployFile = @deployPath + '\deployment6\merge_continue.txt'
			DECLARE @waitingFile NVARCHAR(1536)=@deployFile
		    EXEC dbo.CLEAN_SERVER_LOCAL_FOLDER @SHARED_PATH_OR_FILE = @waitingFile,  @isFile = 1
			SET @deployFile = @deployPath + '\deployment6\copy_to_path.txt'
