sh ~/updates/CX9MR.sh "crent_schema" "master" "cx9" "jose" "'+@ABAS_TASK_NO+'" "Anpassungen IND Schema vom Kunden '+@deploymentKunden+'" "crent_schema_mr_sync"
'+CHAR(10)
