	EXEC dbo.CRENT_UPDATES_SEND_EMAIL @MANDANT_ID = @mandant_id, @subject = @subject, @recipients = 'j.munoz@cx9.de', @contents = @EmailContents,@resultMessage = NULL, @reportJustDeveloper = 0, @printStatusTimestamp = 0 
	EXEC dbo.GET_SQL_COMPARE_XML @mandantId = @mandant_id, @Environment = @environment, @compareType='DATA', @KUNDEDATAINDSEARCH = @searchDataIndex
	EXEC dbo.GET_SQL_COMPARE_XML @mandantId = @mandant_id, @Environment = @environment, @compareType='SCHEMA', @KUNDEDATAINDSEARCH = @searchDataIndex

	SELECT TOP 1  @mailAnBetreuer=ISNULL(mailAnBetreuer,@mailAnBetreuer), @mailAnKunden=ISNULL(mailAnKunden,@mailAnKunden) FROM MANDANT_WEB_PRODUKTE WHERE  C_RENT_ENVIRONMENT_PK = @MANDANT_ENVIRONMENT_PK
	--SELECT TOP 1  mailAnBetreuer, mailAnKunden FROM MANDANT_WEB_PRODUKTE WHERE  MandantID = 245
	--EXEC dbo.SEND_MAIL_BEFORE_UPDATE @mandID = 245, @env = 'ACC', @reportJustDeveloper = 1 
	--SELECT  @PK[PK], @mailAnBetreuer[mailAnBetreuer], @mailAnKunden[mailAnKunden],@environment
	IF (ISNULL(@mailAnBetreuer,0) <> 1 AND @environment = 'ACC')
