CREATE PROCEDURE [dbo].[BACKUP_DB] (@mandant_environment_pk INT = NULL, @justCheck BIT = 1, @result_as_string BIT = 0, @output NVARCHAR(MAX) = '' OUT, @mailAnEntwickler BIT = 0 , @reportHardware BIT = 0, @reportAnMails VARCHAR(2048) = '' )
AS
BEGIN  -- Authors Jose / Nicolas
	SET NOCOUNT ON
	IF (NOT EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandant_environment_pk))
		BEGIN
			SELECT 0[result], 'MANDANT_ENVIRONMENT existiert nicht'[msg]
			RETURN
		END    
	CREATE TABLE #sourceInfo(Umsatz NVARCHAR(MAX) NULL, lastBackupInfo NVARCHAR(MAX) NULL, deploymentDate DATETIME NULL, vorgaenge INT NULL, creationDate DATETIME NULL, version NVARCHAR(1024) NULL, typ NVARCHAR(1024) NULL, fileNames NVARCHAR(1024) NULL, size FLOAT NULL)

	DECLARE @LINKED_SERVER_NAMEConfig XML = dbo.getAdminLinkedServerNameByPK(@mandant_environment_pk)
	DECLARE @DatabaseName VARCHAR(1024) = (SELECT DatabaseName FROM dbo.getLinkedServerNameByPK(@mandant_environment_pk))
 
	DECLARE @LINKED_SERVER_NAME VARCHAR(1024) = (SELECT linkedServerName FROM dbo.getLinkedServerNameByPK(@mandant_environment_pk))
/*select ISNULL((SELECT TOP 1 '"DB letzte Sicherung":"'+dbo.getFormatDateTimeFromString((bs.backup_finish_date),'dd.mm.Y H:i:s')+'", "Sicherungsgroße":"' + CAST(CAST(backup_size / 1048576 AS DECIMAL(10, 2) ) AS varchar(16))+' MB / '+ CAST(CAST(backup_size / 1048576 AS DECIMAL(10, 2) )/1024 AS varchar(16))+' GB"' FROM msdb.dbo.backupset bs where database_name = 'BETHUNDER_JL' ORDER BY backup_finish_date DESC),'')
GO*/ ----	DECLARE @executingTSQL XML = '<TSQL>SELECT ISNULL((STUFF((SELECT ( SELECT ''; ''+ CAST(DATEPART(year, rr.rechnungsdatum ) AS VARCHAR(32))+'' = ''+CAST(ROUND(SUM(rp.GesamtPreis),2) AS VARCHAR(32))+'' €'' AS ''*'' FOR XML PATH(''''), TYPE) FROM ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+'].dbo.RECH_POS rp, ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+'].dbo.RECH_RECHNUNG rr WHERE rp.Rate = ''ES.'' AND rp.PKRECHNUNG = rr.pk GROUP BY DATEPART(year, rr.rechnungsdatum) ORDER BY DATEPART(year, rr.rechnungsdatum) FOR XML PATH('''')),1,1,'''')), '''')[Umsatz], ISNULL((SELECT TOP 1 ''"DBLetzteSicherung":"''+dbo.getFormatDateTimeFromString((bs.backup_finish_date),''dd.mm.Y H:i:s'')+''", "Sicherungsgrosse":"''+ CAST(CAST(ROUND((backup_size / 1048576)/1024,2) AS DECIMAL(10, 2) ) AS varchar(16))+'' GB"'' FROM ['+@LINKED_SERVER_NAME+'].msdb.dbo.backupset bs where database_name = '''+@DatabaseName+''' ORDER BY backup_finish_date DESC),'''')[dbSicherungsinfo] ,ISNULL((SELECT TOP 1 modify_date FROM ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+'].sys.objects ORDER BY modify_date DESC),CURRENT_TIMESTAMP) [deploymentDate],(ISNULL((SELECT COUNT(VERTRAGSNUMMER) FROM ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+'].dbo.MIETVERTRAEGE),0))[vorgaenge], (SELECT TOP 1 create_date FROM ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+'].sys.databases where name = '''+@DatabaseName+''')[creationDate], (SELECT version FROM ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+'].dbo.version)[version], type_desc, name, ((size * 8) / 1024) FROM ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+'].sys.database_files WHERE file_id IN (1,2)</TSQL>' 	DECLARE @mandant_id INT = (SELECT mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandant_environment_pk)   	DECLARE @TSQSuccess BIT 	EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @LINKED_SERVER_NAMEConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TMP_TABLE_NAME = '#sourceInfo', @TSQSuccess = @TSQSuccess OUTPUT
	--SELECT * FROM #sourceInfo
	DECLARE @Umsatz NVARCHAR(MAX) = CAST(ISNULL((SELECT TOP 1 ISNULL(Umsatz,'') FROM #sourceInfo ),'') AS VARCHAR(MAX))	
	DECLARE @lastBackupInfo NVARCHAR(MAX) = CAST(ISNULL((SELECT TOP 1 ISNULL(lastBackupInfo,'') FROM #sourceInfo ),'') AS VARCHAR(MAX))
	DECLARE @vorgaenge VARCHAR(32) = CAST(ISNULL((SELECT TOP 1 ISNULL(vorgaenge,0) FROM #sourceInfo ),0) AS VARCHAR(32))
	DECLARE @deploymentDate DATETIME = ISNULL((SELECT TOP 1 ISNULL(deploymentDate,CURRENT_TIMESTAMP) FROM #sourceInfo ),NULL)
	DECLARE @creationDate DATETIME = ISNULL((SELECT TOP 1 ISNULL(creationDate,'') FROM #sourceInfo ),NULL)
	DECLARE @version VARCHAR(128) = ISNULL((SELECT TOP 1 ISNULL(version,'') FROM #sourceInfo ),'')
	DECLARE @sourceDBRowname VARCHAR(128) = ISNULL((SELECT TOP 1 ISNULL(fileNames,'') FROM #sourceInfo WHERE typ = 'ROWS'),'')
	DECLARE @sourceDBLogname VARCHAR(128) = ISNULL((SELECT TOP 1 ISNULL(fileNames,'') FROM #sourceInfo WHERE typ = 'LOG'),'')
	DECLARE @sizeInMB FLOAT = ISNULL((SELECT SUM(size) FROM #sourceInfo),'')
	--SELECT * FROM #sourceInfo
	IF (@justCheck = 1 AND @result_as_string = 1)
		BEGIN
			IF (@TSQSuccess <> 1)
				BEGIN
					SET @output='{"Info":"Info der DB'+@DatabaseName+' wurde nicht gefunden. Error:'+ERROR_MESSAGE()+'"}'
				END
			ELSE IF (@TSQSuccess = 1)
				BEGIN
 -- PRINT @lastBackupInfo              
					SET @output=
'{
	"DBLogicalName":"'+@sourceDBRowname+'", 
	"DatabaseName":"'+@DatabaseName+'", 
	"DBErstellungsdatum":"'+dbo.getFormatDateTimeFromString(@creationDate,'dd.mm.Y H:i:s')+'", 
    "DBLetztesSCHEMADeployment":"'+dbo.getFormatDateTimeFromString(@deploymentDate,'dd.mm.Y H:i:s')+'", 
	"VorgängeAnzahl":"'+@vorgaenge+'", 
	'+CASE WHEN @lastBackupInfo<>'' then @lastBackupInfo+',' ELSE '' END+'
	"AktuelleGrosse":"'+CAST(ROUND(@sizeInMB/1024,2) AS NVARCHAR(64))+' GB",
	"_Umsatz":"'+@Umsatz+'"
}'		 
				END   			
			RETURN
		END

	IF (@justCheck = 1 AND @result_as_string = 0)
		BEGIN
			IF (@TSQSuccess <> 1)
				BEGIN
					SELECT ''[dbLogicName],@DatabaseName[DBName],@TSQSuccess[result],0[size],'LogDBInfoSQLProblem'[msg]
					RETURN
				END
			ELSE IF (@TSQSuccess = 1)
				BEGIN
					SELECT @sourceDBRowname[dbLogicName],@DatabaseName[DBName],@TSQSuccess[result],@sizeInMB[size],'success'[msg]
					RETURN
				END   		
		END

	--SELECT * FROM #sourceInfo
	DROP TABLE #sourceInfo  
	IF (@justCheck = 0)
		BEGIN 
			DECLARE @mandantIDPKACC INT =(SELECT TOP 1 PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE databaseName LIKE 'ACC_%')
			DECLARE @targetLinkedServerNameConfig XML = dbo.getAdminLinkedServerNameByPK(@mandantIDPKACC) --take ein acc von 209 =pk= 97
			DECLARE @backupDBTSQL VARCHAR(MAX) = '<TSQL>'+REPLACE(dbo.getTSQLRestoreDBFROMTO(@DatabaseName, DEFAULT),@DatabaseName+'.bak','transfer_'+@DatabaseName+'_'+@version+'.bak')+'</TSQL>'
			PRINT @backupDBTSQL
			--RETURN 
			IF (@targetLinkedServerNameConfig IS NULL)
				SET  @targetLinkedServerNameConfig = 
				'<server>
					<LINKED_SERVER name="KUNDEN253_209_ACC">
					<ServerName>192.168.253.209</ServerName>
					<DatabaseName></DatabaseName>
					<Username>sa</Username>
					<Password>chevy#2020</Password>
					</LINKED_SERVER>
				</server>'	
			DECLARE @cmds VARCHAR(1024)=''
			DECLARE @dbDatabaseBackupfile VARCHAR(1024)='\\ku-fs01.kunden.local\dbtransfer\transfer_'+@DatabaseName+'_'+@version+'.bak'
			DECLARE @tab TABLE(cmdRes VARCHAR(MAX) NULL)

			IF (@mailAnEntwickler = 1 OR @reportHardware = 1)
				BEGIN    
					DECLARE @mailRecipients NVARCHAR(1024) = 'j.munoz@cx9.de'  
					IF (ISNULL(@reportAnMails,'')<>'')
						SET @mailRecipients +=';'+@reportAnMails 
					--, @reportAnMails VARCHAR(2048) = ''
					IF (@reportHardware = 1)
						SET @mailRecipients +=';hardware@cx9.de'
					DECLARE @dbInfo NVARCHAR(1024) = '<br>{<br>"DB Logical Name":"<b>'+@sourceDBRowname+'</b>"<br>"Database Name":"<b>'+@DatabaseName+'</b>",<br>"Database version":"<b>'+@version+'</b>",<br>"Size ":"<b>'+CAST(@sizeInMB AS NVARCHAR(64))+' MB / '+CAST(@sizeInMB/1024 AS NVARCHAR(64))+' GB</b>",<br>"LINKED SERVER":"<b>OK</b>"<br>}<br><br>'	              
					DECLARE @mailContents NVARCHAR(MAX)= 'folgende Datei wird erstellt: <br><br>'+@dbDatabaseBackupfile+'<br><br>Bitte auf dem Platz achten!<br>Daten zum Backup:<br>'+@dbInfo+dbo.GET_MANDANT_DATA_MAIL_FORMATED(@mandant_id)             
					EXEC  dbo.SendContentEMail @recipients=@mailRecipients, @info = @mailContents, @subject = N'Ein Datenbank Backup wird erstellt', @MANDANT_ID = @mandant_id -- int		
 							
				END
			 
			SET @cmds = 'DEL /S /Q "'+@dbDatabaseBackupfile+'"'
			INSERT INTO @tab
			EXECUTE Master.dbo.xp_CmdShell @cmds   
		  
			EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @LINKED_SERVER_NAMEConfig, @SQL_INSTRUCTIONS=@backupDBTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TSQL_PARSE=1, @TSQSuccess = @TSQSuccess OUT			
			IF (@result_as_string = 1)
				BEGIN
					IF (@TSQSuccess <> 1)
						BEGIN
							SET @output='{"Info":"Info der DB'+@DatabaseName+' wurde nicht gefunden. Error:'+ERROR_MESSAGE()+'"}'
						END
					ELSE IF (@TSQSuccess = 1)
						BEGIN
							SET @output='{"DB Logical Name":"'+@sourceDBRowname+'", "Database Name":"'+@DatabaseName+'", "Database Backup File":"'+REPLACE(@dbDatabaseBackupfile,'\','/' )+'", "Size ":"'+CAST(@sizeInMB AS NVARCHAR(64))+' MB / '+CAST(@sizeInMB/1024 AS NVARCHAR(64))+' GB", "LINKED SERVER":"OK"}'		 
						END   			
					RETURN
				END			
			IF (@TSQSuccess <> 1)
				BEGIN
					SELECT @sourceDBRowname[dbLogicName],@DatabaseName[DBName],@TSQSuccess[Result],@sizeInMB[size],'Couldnot backup'[msg]
					RETURN
				END 
			ELSE
				BEGIN
					SELECT @sourceDBRowname[dbLogicName],@DatabaseName[DBName],@TSQSuccess[Result],@sizeInMB[size],'success'[Mmsg]
					RETURN
				END 				  						
		END
END
GO
/****** Object:  StoredProcedure [dbo].[C_RENT_PRODUKTE_UPDATE6_RESTART]    Script Date: 25.01.2022 03:14:47 ******/
