CREATE PROCEDURE [dbo].[C_RENT_PRODUKTE_UPDATE6_RESTART](@MandantId INT, @environment NVARCHAR(32) = '', @forceUpdate BIT = 0)
AS
BEGIN
	SET NOCOUNT ON
	IF EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @MandantId AND ENVIRONMENT = @environment) 
		BEGIN  
			--uploadLogMessage
			IF (@forceUpdate = 1) -- von GET_SQL_COMPARE_XML wird xml datacompare und schema compare neu gestartet
				UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET EXECUTED = 0, IMPORT_EXPORT_TRANSLATIONS_JOB_LOG = NULL, TRANSLATIONS_JOB_LOG = NULL, 
				CREATE_COMPARE_JOB_LOG = NULL, UPLOAD_JOB_LOG = NULL, COMPARE_RESULT_LOGS=NULL WHERE MANDANT_ID = @MandantId AND ENVIRONMENT = @environment 
			ELSE IF (@forceUpdate = 0)	-- für Kunden, die mit speziellen konfiguration compared wurden
				IF EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @MandantId AND ENVIRONMENT = @environment AND EXECUTED = 1)
					BEGIN
						UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET IMPORT_EXPORT_TRANSLATIONS_JOB_LOG = NULL, TRANSLATIONS_JOB_LOG = NULL, 
						CREATE_COMPARE_JOB_LOG = NULL, UPLOAD_JOB_LOG = NULL, COMPARE_RESULT_LOGS=NULL WHERE MANDANT_ID = @MandantId AND ENVIRONMENT = @environment 						
					END
			--EXEC dbo.C_RENTWEB_PRODUKTE_UPDATE6_RESTART @MandantId = @MandantId, @environment = @environment
		END 
	SELECT  * FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @MandantId AND ENVIRONMENT = @environment
  
END
GO
