/****** Object:  StoredProcedure [dbo].[CALC_CAR_AMOUNTS]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CALC_CAR_AMOUNTS] (@month INT, @year INT)
as
-- Start
DECLARE @von DATETIME, @bis DATETIME
DECLARE @mvatab TABLE (mvanummer VARCHAR(10),von DATETIME, bis DATETIME, Tagenutzung int, anzahlkfz FLOAT, Mieten INT, Faktor FLOAT, Abzurechnen float)
DECLARE @AQUERY VARCHAR(8000)
CREATE TABLE #ACTIVE_VEHICLES  (dbname varchar(255), mvanummer varchar(10),von datetime, bis datetime, Tagenutzung int, anzahlkfz FLOAT, MAND_NAME VARCHAR(255))
CREATE TABLE #autosvorhanden (status BIT)

SET @von='01.'+CONVERT(varchar,@month)+'.'+CONVERT(VARCHAR,@year)
SET @bis=DATEADD(mm,1,@von)

DECLARE @db_name VARCHAR(255)
DECLARE @mand_id BIGINT
DECLARE #MANDANT_CURSOR CURSOR FOR SELECT name FROM master.dbo.sysdatabases  WHERE dbid>=5 AND status<>66056 AND NOT name LIKE '%kopie%'
OPEN #MANDANT_CURSOR
FETCH NEXT FROM #MANDANT_CURSOR INTO @db_name

WHILE (@@FETCH_STATUS=0)
  BEGIN    
    DELETE FROM #autosvorhanden
    SET @AQUERY='if (exists(Select name from '+@db_name+'.dbo.sysobjects where name=''AUTOS''))'
	SET @AQuery=@AQUERY+'  INSERT into #autosvorhanden values(1)'
	EXEC (@AQUERY)
	IF (EXISTS(SELECT status FROM #autosvorhanden WHERE status=1))
	  begin
		SET @AQUERY='INSERT INTO #ACTIVE_VEHICLES (dbname,mvanummer,von) SELECT '''+@db_name+''',mvanummer,zuldat FROM '+@db_name+'.dbo.autos WHERE OWNER=(SELECT ownercode FROM '+@db_name+'.dbo.MAND_GLOBAL WHERE pk=1)'
		EXEC (@AQUERY)
		SET @AQUERY='UPDATE #active_VEHICLES SET bis=(SELECT rueckgabehaendler FROM '+@db_name+'.dbo.autoszusdaten az WHERE az.mvanummer=#active_VEHICLES.mvanummer)'+
					'WHERE dbname='''+@db_name+''''
		EXEC (@AQUERY)	
		SET @AQUERY='UPDATE #active_VEHICLES SET MAND_NAME=(Select MandantName from '+@db_name+'.dbo.MAND_GLOBAL WHERE PK=1)'+
					'WHERE dbname='''+@db_name+''''
		EXEC (@AQUERY)	
		
		UPDATE #active_VEHICLES SET bis=@bis WHERE (bis IS NULL OR bis>@bis)
		 AND dbname=@db_name 
		UPDATE #active_VEHICLES SET von=@von WHERE von<@von
		 AND dbname=@db_name 
		DELETE FROM #active_VEHICLES WHERE bis<=von 
		  AND dbname=@db_name 
		UPDATE #active_VEHICLES SET Tagenutzung=datediff(dd,von,bis)
			WHERE dbname=@db_name 
		UPDATE #active_VEHICLES SET anzahlkfz=ROUND(CONVERT(FLOAT,Tagenutzung) / CONVERT(FLOAT,DATEDIFF(dd, @von,@bis)),1)
			WHERE dbname=@db_name 
	  end
	FETCH NEXT FROM #MANDANT_CURSOR INTO @db_name
END
DEALLOCATE #MANDANT_CURSOR

--SELECT * FROM #ACTIVE_VEHICLES ORDER BY dbname,mvanummer
SELECT avm.dbname,avm.MAND_NAME,ROUND(SUM(avm.anzahlkfz),0) AS Fahrzeuge FROM #ACTIVE_VEHICLES avm
  GROUP BY avm.dbname,avm.MAND_NAME ORDER BY dbname 


GO
/****** Object:  StoredProcedure [dbo].[CHECK_DB_CONNECTION_BY_PK]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CHECK_DB_CONNECTION_BY_PK] (@mandant_environment_pk INT = NULL)
AS
BEGIN  -- Authors Jose
	SET NOCOUNT ON
	IF (NOT EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandant_environment_pk))
		BEGIN
		/*dbLogicName	DBName	result	size	msg
ACC_mietcamper	ACC_mietcamper	1	28853	success*/
			SELECT ''[dbLogicName],''[DBName],'0'[result], 0[size], 'MANDANT_ENVIRONMENT existiert nicht'[msg]
			RETURN
		END    
	CREATE TABLE #dbInfoConnection(typ NVARCHAR(1024) NULL, fileNames NVARCHAR(1024) NULL, size FLOAT NULL, dbversion NVARCHAR(1024) NULL)

	DECLARE @originLinkedServerNameConfig XML = dbo.getAdminLinkedServerNameByPK(@mandant_environment_pk)
	DECLARE @sourceDBName VARCHAR(1024) = (SELECT DatabaseName FROM dbo.getLinkedServerNameByPK(@mandant_environment_pk))
 
	DECLARE @originLinkedServerName VARCHAR(1024) = (SELECT linkedServerName FROM dbo.getLinkedServerNameByPK(@mandant_environment_pk))
 	DECLARE @executingTSQL XML = '<TSQL>SELECT type_desc, name, ((size * 8) / 1024), (ISNULL((SELECT TOP 1 version FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.version),''''))[version] FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].sys.database_files WHERE file_id IN (1,2)</TSQL>' 	DECLARE @TSQSuccess BIT 	EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TMP_TABLE_NAME = '#dbInfoConnection', @TSQSuccess = @TSQSuccess OUTPUT

	DECLARE @sourceDBRowname VARCHAR(128) = ISNULL((SELECT TOP 1 ISNULL(fileNames,'') FROM #dbInfoConnection WHERE typ = 'ROWS'),'')
	DECLARE @sourceDBLogname VARCHAR(128) = ISNULL((SELECT TOP 1 ISNULL(fileNames,'') FROM #dbInfoConnection WHERE typ = 'LOG'),'')
	DECLARE @sourceDBversion VARCHAR(128) = ISNULL((SELECT TOP 1 ISNULL(dbversion,'') FROM #dbInfoConnection WHERE typ = 'ROWS'),'')
	DECLARE @sizeInMB FLOAT = ISNULL((SELECT SUM(size) FROM #dbInfoConnection),'')
	IF (@TSQSuccess <> 1)
		BEGIN
			SELECT ''[dbLogicName],@sourceDBName[DBName],@TSQSuccess[result],0[size],'LogDBInfoSQLProblem'[msg],''[DBversion]
			RETURN
		END
	ELSE IF (@TSQSuccess = 1)
		BEGIN
			SELECT @sourceDBRowname[dbLogicName],@sourceDBName[DBName],@TSQSuccess[result],@sizeInMB[size],'success'[msg],@sourceDBversion[DBversion]
			RETURN
		END   
	DROP TABLE #dbInfoConnection   
END
GO
/****** Object:  StoredProcedure [dbo].[CHECK_TSQL_SYNTAX]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CHECK_TSQL_SYNTAX] (@TSQL VARCHAR(MAX) = '', @result BIT = 0 OUTPUT) 
AS BEGIN 
	DECLARE @validSyntaxTSQL VARCHAR(MAX) = 'SET PARSEONLY ON'+	
	CHAR(13)+@TSQL
	--SET @TSQL = STUFF(@TSQL, CHARINDEX('FROM', @TSQL), LEN('FROM'), 'INTO #testingTableResults FROM') --first occurrence
	SET @TSQL =  STUFF(@TSQL, dbo.LastIndexOf(@TSQL,'FROM')+2, LEN('FROM'), 'INTO #testingTableResults FROM') --last occurence
    BEGIN TRY		
	--PRINT @TSQL  
	--RETURN 
        EXEC(@validSyntaxTSQL) -- first check valid syntax 
		BEGIN TRY		    
			EXEC(@TSQL)  -- check valid results
			SET @result = 1 
		END TRY
		BEGIN CATCH
			SET @result = 0
			PRINT @TSQL
			PRINT ERROR_MESSAGE()
		END CATCH  
    END TRY
    BEGIN CATCH
        SET @result = 0
		PRINT @TSQL
		PRINT ERROR_MESSAGE()
    END CATCH  
END 
GO
/****** Object:  StoredProcedure [dbo].[CLEAN_SERVER_LOCAL_FOLDER]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CLEAN_SERVER_LOCAL_FOLDER]( 
@SHARED_PATH_OR_FILE VARCHAR(1536) = '\\ku-fs01.kunden.local\deployment\single\updates\crent_schema\', @isFile BIT = 0 
)
AS SET NOCOUNT ON
	BEGIN
	DECLARE @cmds VARCHAR(2048)=''  
	DECLARE @tab TABLE(cmdRes VARCHAR(MAX) NULL)    
	  IF (@isFile = 0)
		BEGIN
			IF (SUBSTRING(@SHARED_PATH_OR_FILE,LEN(@SHARED_PATH_OR_FILE),1)<>'\')
				SET @SHARED_PATH_OR_FILE +='\' 
	
			PRINT 'Removing folders and files from: '+@SHARED_PATH_OR_FILE
			SET @cmds = 'RD /S /Q "'+@SHARED_PATH_OR_FILE+'"'
			INSERT INTO @tab
			EXECUTE Master.dbo.xp_CmdShell @cmds 

			SET @cmds = 'FOR /D %i IN ("'+@SHARED_PATH_OR_FILE+'"*) DO RD /S /Q "%i"'
			INSERT INTO @tab
			EXECUTE Master.dbo.xp_CmdShell @cmds 

			SET @cmds = 'DEL /S /Q "'+@SHARED_PATH_OR_FILE+'*.*"'
			INSERT INTO @tab
			EXECUTE Master.dbo.xp_CmdShell @cmds 

		END
		
	  IF (@isFile = 1)
		BEGIN
			PRINT 'Removing file: '+@SHARED_PATH_OR_FILE
			SET @cmds = 'DEL /S /Q "'+@SHARED_PATH_OR_FILE+'"'
			INSERT INTO @tab
			EXECUTE Master.dbo.xp_CmdShell @cmds 
		END		  

	END 
GO
/****** Object:  StoredProcedure [dbo].[CONFIGURE_DB_AS_ACC]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CONFIGURE_DB_AS_ACC] (@targetLinkedServerNameConfig xml,@db_name varchar(8000))
as
-- Maildomains
DECLARE @linkedserver VARCHAR(8000)
SELECT @linkedserver=ISNULL(@targetLinkedServerNameConfig.value('(/server/LINKED_SERVER/@name)[1]','NVARCHAR(512)'),'') 
DECLARE @executingTSQL XML = '<TSQL>Select wert from '+@linkedserver+'.'+@db_name+'.dbo.params where param=''SACC_CUSTOMER_DOMAINS''</TSQL>'				--(SELECT DatabaseName FROM dbo.getLinkedServerNameByPK(50))		--(SELECT linkedServerName FROM dbo.getLinkedServerNameByPK(50))DECLARE @TSQSuccess BIT CREATE TABLE #tmp (aname VARCHAR(255))EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, 
  @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TMP_TABLE_NAME = '#tmp', @TSQSuccess = @TSQSuccess OUT
DECLARE @domains VARCHAR(8000)
SELECT TOP 1 @domains=aname FROM #tmp


DECLARE @atab TABLE (maildomain VARCHAR(255))
INSERT INTO @atab SELECT * FROM dbo.GET_TABLE_FROM_LIST_DELIM(@domains,',')
DROP TABLE #tmp
--SELECT * FROM @atab
DECLARE #amailadrcur CURSOR FOR SELECT maildomain FROM @atab
OPEN #amailadrcur
DECLARE @maildomain VARCHAR(8000)
FETCH NEXT FROM #amailadrcur INTO @maildomain
DECLARE @query VARCHAR(8000)=''
DECLARE @whereclause VARCHAR(8000)=''
IF (@@FETCH_STATUS=0)
  begin
    WHILE (@@FETCH_STATUS=0)
      BEGIN
	    IF (@whereclause='')
		  SET @whereclause=@whereclause+'not(EMAIL LIKE ''%'+@maildomain+''')'
		ELSE
          SET @whereclause=@whereclause+' AND not(EMAIL LIKE ''%'+@maildomain+''')'
        FETCH NEXT FROM #amailadrcur INTO @maildomain
      END
	SET @query='UPDATE kd SET EMAIL=null from '+@db_name+'.dbo.KUNDEN kd where '+@whereclause
	SET @query=@query+' DELETE FROM '+@db_name+'.dbo.WEBSERVICE_LOGIN where '+@whereclause	
  END
ELSE
  begin
    SET @query='UPDATE '+@db_name+'.dbo.kunden set email=null'
	SET @query=@query+' delete from '+@db_name+'.dbo.WEBSERVICE_LOGIN'
  END
DEALLOCATE #amailadrcur
SET @query='<TSQL>'+@query+'</TSQL>'
EXEC EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, 
					@SQL_INSTRUCTIONS=@query, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TSQL_PARSE=1, @TSQSuccess = @TSQSuccess OUT


-- sonstige Params
SET @query  = '<TSQL>update '+@db_name+'.dbo.params set wert=(Select wert from '+@db_name+'.dbo.params where param=''SACC_APP_AUTHCODE'') where param=''SAPP_AUTHCODE''</TSQL>'
EXEC EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, 
					@SQL_INSTRUCTIONS=@query, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TSQL_PARSE=1, @TSQSuccess = @TSQSuccess OUT
SET @query  = '<TSQL>update '+@db_name+'.dbo.params set wert=(Select wert from '+@db_name+'.dbo.params where param=''SACC_APP_INVOICE_META_DATA_RECEIVER'') where param=''SAPP_INVOICE_META_DATA_RECEIVER''</TSQL>'
EXEC EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, 
					@SQL_INSTRUCTIONS=@query, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TSQL_PARSE=1, @TSQSuccess = @TSQSuccess OUT
SET @query  = '<TSQL>update '+@db_name+'.dbo.params set wert=(Select wert from '+@db_name+'.dbo.params where param=''SACC_CSAPP_HOMEPAGE'') where param=''CSAPP_HOMEPAGE''</TSQL>'
EXEC EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, 
					@SQL_INSTRUCTIONS=@query, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TSQL_PARSE=1, @TSQSuccess = @TSQSuccess OUT

GO
