/****** Object:  StoredProcedure [dbo].[CREATE_ACC_WITH_MAINTENANCE]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CREATE_ACC_WITH_MAINTENANCE](@MANDANT_ENVIRONMENT_PK_LIST VARCHAR(MAX)= '', @reportJustDeveloper BIT = 0, @reportHardware BIT = 0, @reportAnMails VARCHAR(2048) = '', @optimize_db BIT = 1)
AS
BEGIN  -- Author José
	SET NOCOUNT ON
	DECLARE @mandantEnvironmentPK INT 
	DECLARE @mandantEnvironmentDBName NVARCHAR(128) 
	DECLARE @mandantACCEnvironmentPK INT 	
	DECLARE cursor_restore_with_mantainance CURSOR FAST_FORWARD READ_ONLY FOR SELECT PK FROM [BETHUNDER_JL].dbo.MANDANT_DB_ENVIRONMENT WHERE databaseName NOT LIKE 'ACC_%' AND type='DEFAULT' AND PK IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@MANDANT_ENVIRONMENT_PK_LIST,';'))
	OPEN cursor_restore_with_mantainance

	FETCH NEXT FROM cursor_restore_with_mantainance INTO @mandantEnvironmentPK

	WHILE @@FETCH_STATUS = 0
	BEGIN
		PRINT @mandantEnvironmentPK 
		EXEC dbo.BACKUP_DB @mandant_environment_pk = @mandantEnvironmentPK, @justCheck = 0, @mailAnEntwickler = @reportJustDeveloper, @reportHardware = @reportHardware, @reportAnMails = @reportAnMails 
		EXEC dbo.RESTORE_DB_AS_ACC @mandant_environment_pk = @mandantEnvironmentPK, @reportJustDeveloper = @reportJustDeveloper, @reportHardware = @reportHardware, @reportAnMails = @reportAnMails, @optimize_db = @optimize_db 
		SET @mandantEnvironmentDBName = ((SELECT TOP 1 databaseName FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandantEnvironmentPK))
		SET @mandantACCEnvironmentPK = (SELECT TOP 1 PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE databaseName LIKE 'ACC_'+@mandantEnvironmentDBName)
		IF (ISNUMERIC(@mandantACCEnvironmentPK) = 1 AND @optimize_db = 1)
			EXEC dbo.FREESPACE_ON_DB_ACC @mandantID_PK = @mandantACCEnvironmentPK, @reportJustDeveloper = @reportJustDeveloper, @reportHardware = @reportHardware, @reportAnMails = @reportAnMails  
		--SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @mandantEnvironmentPK
		--EXEC [BETHUNDER_JL].dbo.FREESPACE_ON_DB_ACC @mandantID_PK = @mandantEnvironmentPK 
		FETCH NEXT FROM cursor_restore_with_mantainance INTO @mandantEnvironmentPK
	END

	CLOSE cursor_restore_with_mantainance
	DEALLOCATE cursor_restore_with_mantainance 
END
GO
/****** Object:  StoredProcedure [dbo].[create_archive_db]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
