GO
CREATE PROCEDURE [dbo].[create_archive_db](@mandant_id INT = 0, @type VARCHAR(255) = '', @DBname VARCHAR(255) = '', @dbo VARCHAR(255) = '')
AS
BEGIN
	DECLARE @sql VARCHAR(MAX)
	IF (@DBname = '' AND @dbo = '')
		SELECT TOP 1 @DBname = databaseName, @dbo = databaseUser FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE [mandant_id] = @mandant_id AND type = @type

	-- Datenbank erstellen
	SET @sql = 'IF NOT EXISTS(SELECT [name] FROM sys.databases WHERE [name] = ''archiv_'+@DBname+''')'
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + 'CREATE DATABASE archiv_'+@DBname
	SET @sql = @sql + ' ON (NAME = ''archiv_'+@DBname+''', FILENAME = ''F:\Archivdb\archiv_'+@DBname+'.mdf'')'
	SET @sql = @sql + ' LOG ON (NAME = ''archiv_'+@DBname+'_log'', FILENAME = ''F:\Archivdb\archiv_'+@DBname+'_log.ldf'');'
	SET @sql = @sql + 'IF EXISTS(SELECT [name] FROM sys.databases WHERE [name] = ''archiv_'+@DBname+''')'
	SET @sql = @sql + 'ALTER DATABASE [archiv_'+@DBname+'] SET RECOVERY SIMPLE;'
	SET @sql = @sql + 'print ''Archiv Datenbank angelegt.''; END ELSE BEGIN print ''Archiv Datenbank existiert schon.'' END;'
	EXEC (@sql)

	-- dbo Benutzer für die archiv Datenbank anlegen
	SET @sql = 'use archiv_'+@DBname+';'
	SET @sql = @sql + 'IF NOT EXISTS (SELECT [name] FROM sys.database_principals WHERE [name] = '''+@dbo+''')'
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + 'CREATE USER "'+@dbo+'" FOR LOGIN  "'+@dbo+'";'
	SET @sql = @sql + 'EXEC sp_addrolemember N''db_owner'', N'''+@dbo+''';'
	SET @sql = @sql + 'print ''Benutzer wurde angelegt.''; END ELSE BEGIN print''Benutzer existiert schon.''; END;'
	EXEC (@sql)

	-- Leere Tabellen erstellen
	SET @sql = 'use archiv_'+@DBname+';'
	SET @sql = @sql + 'declare @sql2 varchar(max);'
	SET @sql = @sql + 'IF (NOT EXISTS(SELECT [TABLE_NAME] FROM INFORMATION_SCHEMA.TABLES WHERE [TABLE_NAME] = ''docs''))'
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + 'SELECT @sql2='+@DBname+'.[dbo].[create_table_script](''dbo.docs'');'
	SET @sql = @sql + 'exec (@sql2);'
	SET @sql = @sql + 'print ''docs Tabelle wurde erstellt.''; END ELSE BEGIN print ''docs Tabelle existiert schon.''; END;'
	SET @sql = @sql + 'IF (NOT EXISTS(SELECT [TABLE_NAME] FROM INFORMATION_SCHEMA.TABLES WHERE [TABLE_NAME] = ''bilder'')) '
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + 'SELECT @sql2='+@DBname+'.[dbo].[create_table_script](''dbo.bilder'');'
	SET @sql = @sql + 'exec (@sql2);'
	SET @sql = @sql + 'print ''bilder Tabelle wurde erstellt.''; END ELSE BEGIN print ''bilder Tabelle existiert schon.''; END;'
	SET @sql = @sql + 'IF (NOT EXISTS(SELECT [TABLE_NAME] FROM INFORMATION_SCHEMA.TABLES WHERE [TABLE_NAME] = ''docs_docs'')) '
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + 'SELECT @sql2='+@DBname+'.[dbo].[create_table_script](''dbo.docs_docs'');'
	SET @sql = @sql + 'exec (@sql2);'
	SET @sql = @sql + 'print ''docs_docs Tabelle wurde erstellt.''; END ELSE BEGIN print ''docs_docs Tabelle existiert schon.''; END;'
	EXEC (@sql)

	-- Tabellen befüllen
	SET @sql = 'use '+@DBname+';'
	SET @sql = @sql + 'print ''docs_docs wird befüllt.'';'
	SET @sql = @sql + 'WHILE ((SELECT COUNT(*) FROM DOCS_DOCS WHERE NOT PK IN (SELECT PK FROM archiv_'+@DBname+'.dbo.DOCS_DOCS))>0)'
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + 'INSERT INTO archiv_'+@DBname+'.dbo.DOCS_DOCS SELECT TOP 100 * FROM DOCS_DOCS WHERE NOT PK IN (SELECT PK FROM archiv_'+@DBname+'.dbo.DOCS_DOCS);'
	SET @sql = @sql + 'WAITFOR DELAY ''00:00:01'';'
	SET @sql = @sql + 'END;'
	SET @sql = @sql + 'print ''docs wird befüllt.'';'
	SET @sql = @sql + 'WHILE ((SELECT COUNT(*) FROM DOCS WHERE NOT PK IN (SELECT PK FROM archiv_'+@DBname+'.dbo.DOCS))>0)'
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + 'INSERT INTO archiv_'+@DBname+'.dbo.DOCS SELECT TOP 100 * FROM DOCS WHERE NOT PK IN (SELECT PK FROM archiv_'+@DBname+'.dbo.DOCS);'
	SET @sql = @sql + 'WAITFOR DELAY ''00:00:01'';'
	SET @sql = @sql + 'END;'
	SET @sql = @sql + 'print ''bilder wird befüllt.'';'
	SET @sql = @sql + 'WHILE ((SELECT COUNT(*) FROM bilder WHERE NOT PK IN (SELECT PK FROM archiv_'+@DBname+'.dbo.bilder))>0)'
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + 'INSERT INTO archiv_'+@DBname+'.dbo.bilder SELECT TOP 100 * FROM bilder WHERE NOT PK IN (SELECT PK FROM archiv_'+@DBname+'.dbo.bilder);'
	SET @sql = @sql + 'WAITFOR DELAY ''00:00:01'';'
	SET @sql = @sql + 'END;'
	SET @sql = @sql + 'print ''befüllen abgeschlossen.'';'
	EXEC (@sql)

	-- tabellen durch synonyme ersetzen
	SET @sql = 'use '+@DBname+';'
	SET @sql = @sql + 'if ((select count(*) from dbo.docs) = (select count(*) from archiv_'+@DBname+'.dbo.docs)) '
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + '	IF (not EXISTS (SELECT * FROM [sys].[synonyms] WHERE [name]=N''docs'')) begin;'
	SET @sql = @sql + '		EXEC [sys].[sp_rename] @objname = N''docs'',@newname = ''sicherung_docs'',@objtype = ''object'';'
	SET @sql = @sql + '		CREATE SYNONYM docs FOR archiv_'+@DBname+'.dbo.docs;'
	SET @sql = @sql + '	END;'
	SET @sql = @sql + '	IF (EXISTS (SELECT * FROM [sys].[synonyms] WHERE [name]=N''docs'') and EXISTS(SELECT [TABLE_NAME] FROM INFORMATION_SCHEMA.TABLES WHERE [TABLE_NAME] = ''sicherung_docs''))'
	SET @sql = @sql + '	BEGIN;'
	SET @sql = @sql + '		print ''docs Tabelle wurde in sicherung_docs umbenannt.'';'
	SET @sql = @sql + '		print ''docs Synonym wurde erstellt.'';'
	SET @sql = @sql + '		DROP TABLE sicherung_docs;'
	SET @sql = @sql + '		print ''docs Tabelle wurde gelöscht.'';'
	SET @sql = @sql + '	END else begin;'
	SET @sql = @sql + '		print ''docs Synonym konnte nicht erstellt werden.'';'
	SET @sql = @sql + '		if (EXISTS(SELECT [TABLE_NAME] FROM INFORMATION_SCHEMA.TABLES WHERE [TABLE_NAME] = ''sicherung_docs''))'
	SET @sql = @sql + '			EXEC [sys].[sp_rename] @objname = N''sicherung_docs'',@newname = ''docs'',@objtype = ''object'';'
	SET @sql = @sql + '	END;'
	SET @sql = @sql + 'END;'

	SET @sql = @sql + 'if ((select count(*) from dbo.bilder) = (select count(*) from archiv_'+@DBname+'.dbo.bilder)) '
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + '	IF (not EXISTS (SELECT * FROM [sys].[synonyms] WHERE [name]=N''bilder'')) begin;'
	SET @sql = @sql + '		EXEC [sys].[sp_rename] @objname = N''bilder'',@newname = ''sicherung_bilder'',@objtype = ''object'';'
	SET @sql = @sql + '		CREATE SYNONYM bilder FOR archiv_'+@DBname+'.dbo.bilder;'
	SET @sql = @sql + '	END;'
	SET @sql = @sql + '	IF (EXISTS (SELECT * FROM [sys].[synonyms] WHERE [name]=N''bilder'') and EXISTS(SELECT [TABLE_NAME] FROM INFORMATION_SCHEMA.TABLES WHERE [TABLE_NAME] = ''sicherung_bilder''))'
	SET @sql = @sql + '	BEGIN;'
	SET @sql = @sql + '		print ''bilder Tabelle wurde in sicherung_bilder umbenannt.'';'
	SET @sql = @sql + '		print ''bilder Synonym wurde erstellt.'';'
	SET @sql = @sql + '		DROP TABLE sicherung_bilder;'
	SET @sql = @sql + '		print ''bilder Tabelle wurde gelöscht.'';'
	SET @sql = @sql + '	END else begin;'
	SET @sql = @sql + '		print ''bilder Synonym konnte nicht erstellt werden.'';'
	SET @sql = @sql + '		if (EXISTS(SELECT [TABLE_NAME] FROM INFORMATION_SCHEMA.TABLES WHERE [TABLE_NAME] = ''sicherung_bilder''))'
	SET @sql = @sql + '			EXEC [sys].[sp_rename] @objname = N''sicherung_bilder'',@newname = ''bilder'',@objtype = ''object'';'
	SET @sql = @sql + '	END;'
	SET @sql = @sql + 'END;'

	SET @sql = @sql + 'if ((select count(*) from dbo.docs_docs) = (select count(*) from archiv_'+@DBname+'.dbo.docs_docs)) '
	SET @sql = @sql + 'BEGIN;'
	SET @sql = @sql + '	IF (not EXISTS (SELECT * FROM [sys].[synonyms] WHERE [name]=N''docs_docs'')) begin;'
	SET @sql = @sql + '		EXEC [sys].[sp_rename] @objname = N''docs_docs'',@newname = ''sicherung_docs_docs'',@objtype = ''object'';'
	SET @sql = @sql + '		CREATE SYNONYM docs_docs FOR archiv_'+@DBname+'.dbo.docs_docs;'
	SET @sql = @sql + '	END;'
	SET @sql = @sql + '	IF (EXISTS (SELECT * FROM [sys].[synonyms] WHERE [name]=N''docs_docs'') and EXISTS(SELECT [TABLE_NAME] FROM INFORMATION_SCHEMA.TABLES WHERE [TABLE_NAME] = ''sicherung_docs_docs''))'
	SET @sql = @sql + '	BEGIN;'
	SET @sql = @sql + '		print ''docs_docs Tabelle wurde in sicherung_docs_docs umbenannt.'';'
	SET @sql = @sql + '		print ''docs_docs Synonym wurde erstellt.'';'
	SET @sql = @sql + '		DROP TABLE sicherung_docs_docs;'
	SET @sql = @sql + '		print ''docs_docs Tabelle wurde gelöscht.'';'
	SET @sql = @sql + '	END else begin;'
	SET @sql = @sql + '		print ''docs_docs Synonym konnte nicht erstellt werden.'';'
	SET @sql = @sql + '		if (EXISTS(SELECT [TABLE_NAME] FROM INFORMATION_SCHEMA.TABLES WHERE [TABLE_NAME] = ''sicherung_docs_docs''))'
	SET @sql = @sql + '			EXEC [sys].[sp_rename] @objname = N''sicherung_docs_docs'',@newname = ''docs_docs'',@objtype = ''object'';'
	SET @sql = @sql + '	END;'
	SET @sql = @sql + 'END;'
	EXEC (@sql)
END
GO
/****** Object:  StoredProcedure [dbo].[CREATE_TSUSER_FOR_MANDANT]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- 441 für crentdemo, 451 für km (hat keine User als Beispielfall)
--DECLARE @MandantID AS int = 442
--DECLARE @NumberOfUsers int = 2
--GO
CREATE PROCEDURE [dbo].[CREATE_TSUSER_FOR_MANDANT](@MandantID int,@NumberOfUsers int)
--alter function dbo.GET_TEST_NICOLAS(@MandantID int,@NumberOfUsers int)
--returns VARCHAR(16) 
-- vielleicht eine Funktion oder so die man aufruft mit der Mandant ID und der Menge der Users? 
AS 

--declare @result varchar(16)
-- Keine Änderungen nach hier, MandantID + Menge der User muss reichen, rest muss sich "selbst befüllen"
DECLARE @MandantGlobName AS VARCHAR(17)
DECLARE @tsUsersName AS VARCHAR(20)
DECLARE @tsUsersNextName AS VARCHAR(20)
DECLARE @NameSpacer AS VARCHAR(2) = '_0'
DECLARE @tsUsersNextNumber AS int
DECLARE @tsUserPass VARCHAR(10)

-- SELECT * FROM [dbo].[Mandant] WHERE [Mandant].id = @MandantID

SELECT TOP 1 @MandantGlobName=globalName FROM [dbo].[Mandant] WHERE [Mandant].id = @MandantID

-- SELECT * FROM [dbo].[TSUsers] WHERE [dbo].[TSUsers].[customer_id] = @MandantID AND [dbo].[TSUsers].[NAME] LIKE @MandantGlobName+'%' order by NAME desc

IF EXISTS (SELECT * from [dbo].[TSUsers] WHERE [dbo].[TSUsers].[customer_id] = @MandantID AND [dbo].[TSUsers].[NAME] LIKE @MandantGlobName+'%')
	BEGIN
		SELECT TOP 1 @tsUsersName=[NAME]  from [dbo].[TSUsers] WHERE [dbo].[TSUsers].[customer_id] = @MandantID AND [dbo].[TSUsers].[NAME] LIKE @MandantGlobName+'%' order by [NAME] desc
		-- SELECT CAST(RIGHT(@tsUsersName,2) as int )
		SET @tsUsersNextNumber = CAST(RIGHT(@tsUsersName,2) as int )+1
	END
ELSE
	BEGIN 
		SET @tsUsersNextNumber = 1 
	END 

DECLARE @i INT = 0

DECLARE @sqlInsertValues VARCHAR(255) 

WHILE (@i < @NumberOfUsers)
	BEGIN 
		IF (@tsUsersNextNumber > 9) SET @NameSpacer = '_' 
		SET @tsUsersNextName = @MandantGlobName+@NameSpacer+CAST(@tsUsersNextNumber as varchar)
		SELECT @tsUserPass = dbo.GenPass(1)
		SET @sqlInsertValues = 'Neuer User: '+@tsUsersNextName+' mit Passwort: '+@tsUserPass
		INSERT INTO [dbo].[TSUsers] ([customer_id],[NAME],[InitialPass],[aktiv],[UserCreateDate]) VALUES (@MandantID,@tsUsersNextName,@tsUserPass,NULL,GetDate())
		--PRINT  @MandantID 
		--PRINT  @tsUsersNextName
		--PRINT  @tsUserPass
		--PRINT @sqlInsertValues
		SET @tsUsersNextNumber = @tsUsersNextNumber + 1 
		SET @i = @i + 1 
	END
--return @tsUsersNextName
