/****** Object:  StoredProcedure [dbo].[CRENT_UPDATE_REPORTS]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CRENT_UPDATE_REPORTS] (@recipients NVARCHAR(MAX)= 'j.munoz@cx9.de;t.seitz@cx9.de;n.lermann@cx9.de;m.schwarzkopf@cx9.de;n.schwarzkopf@cx9.de')
AS
DECLARE @sep varchar(255)
SET @sep = '[sep=,' + CHAR(13) + CHAR(10) + 'Kunde]'
 DECLARE @TSQLCSV NVARCHAR(MAX)='SELECT companyname as '+@sep+',
CASE WHEN EXISTS(SELECT MandantId FROM MANDANT_WEB_PRODUKTE WHERE MandantId=id AND Environment=''ACC'')
	THEN (SELECT TOP 1 ISNULL(dbo.getFormatDateTimeFromString(ISNULL(TIMEOFUPDATE,(SELECT TOP 1 LAST_EXECUTION_TIME FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID=id AND ENVIRONMENT = ''ACC'')) ,''dd.mm.Y''),''vor 01.12.2020'') FROM MANDANT_WEB_PRODUKTE WHERE MandantId=id AND Environment=''ACC'' AND dbo.GET_ENVIRONMENT_LOG_ERRORS(MandantId, ''ACC'') = '''')
	WHEN EXISTS(SELECT mandant_id FROM MANDANT_DB_ENVIRONMENT WHERE mandant_id=id AND type=''DEFAULT'' AND version=''6.0'')
	 THEN '''' 
	ELSE ''''
	
	 END [ACC Update-Datum],
CASE WHEN EXISTS(SELECT MandantId FROM MANDANT_WEB_PRODUKTE WHERE MandantId=id AND Environment=''LIVE'')
	THEN (SELECT TOP 1 ISNULL(dbo.getFormatDateTimeFromString(ISNULL(TIMEOFUPDATE,(SELECT TOP 1 LAST_EXECUTION_TIME FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID=id AND ENVIRONMENT = ''LIVE'')),''dd.mm.Y''),''vor 01.12.2020'') FROM MANDANT_WEB_PRODUKTE WHERE MandantId=id AND Environment=''LIVE'' AND dbo.GET_ENVIRONMENT_LOG_ERRORS(MandantId, ''LIVE'') = '''')
	ELSE '''' END [LIVE Update-Datum], --,ISNULL(version_CHECK,'''')[version_CHECK] 
CASE WHEN EXISTS(SELECT mandant_id FROM MANDANT_DB_ENVIRONMENT WHERE mandant_id=id AND type=''DEFAULT'' AND version=''6.0'')
 THEN ''6.0'' ELSE '''' END [Liveversion],
 CASE WHEN dbo.isClientExtern(id)=1 THEN ''JA'' ELSE ''NEIN'' END[Extern],
(SELECT number FROM CRENT_UPDATES6_BETWEENDATES(DEFAULT))[UpdatesderWoche],
(SELECT numberLive FROM CRENT_UPDATES6_BETWEENDATES(DEFAULT))[LiveUpdatesderWoche],
(SELECT numberACC FROM CRENT_UPDATES6_BETWEENDATES(DEFAULT))[ACCUpdatesderWoche] 
 FROM dbo.Mandant WHERE ISNULL(companyname,'''')<>'''' ' 
 --SELECT dbo.isClientExtern(98)
 --SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT
 -- AND id NOT IN (SELECT mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE type=''DEFAULT'' AND version = ''6.0'')' 
 DECLARE @datum NVARCHAR(128) = dbo.getFormatDateTimeFromString(dbo.CRW_ISO_DATE(CURRENT_TIMESTAMP,'0000'),'dd.mm.Y')
 DECLARE @csvFilename NVARCHAR(128) = 'C-Rent60Bericht_'+@datum+'.csv' 
 DECLARE @subject NVARCHAR(MAX) = 'C-Rent Updates 6.0 Bericht bis zum '+@datum+' :'
 DECLARE @EmailContents NVARCHAR(MAX) = 'Guten Tag, <br><br><br><b>
										anbei eine CSV Datei mit den C-Rent 5.x auf C-Rent 6.0! <br><br>  
										Die Daten wurden aus der Tabelle Mandant zusammengefasst.<br><br>  
										Fehlende Informationen können vorhanden sein.<br><br>  
										</b>'+
										'[P.S.: Bitte Anhang mit Excel aufmachen]:<br><br>' 
										 
 --IF (@user)
 EXEC dbo.CRENT_UPDATES_SEND_EMAIL @MANDANT_ID = 415, @subject = @subject, @recipients = @recipients, @contents = @EmailContents,@resultMessage = NULL, @reportJustDeveloper = 0, @printStatusTimestamp = 0,
 @TSQLCSV = @TSQLCSV, @csvFilename  = @csvFilename
GO
/****** Object:  StoredProcedure [dbo].[CRENT_UPDATE6_ACC_LIVE_ESTIMATION_COSTS]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CRENT_UPDATE6_ACC_LIVE_ESTIMATION_COSTS](@mandantId INT = NULL, @recipients VARCHAR(1024) = '', @ABAS_TASK_NO VARCHAR(32) = '')
AS --Author José 
BEGIN 

	DECLARE @concept VARCHAR(max),@typ VARCHAR(128),@id INT,@costs FLOAT
	DECLARE @foreignkey VARCHAR(128) 
	DECLARE @E_MailContents NVARCHAR(MAX) = ''
 
	DECLARE crentupdate6_estimation_text_costs_cursor CURSOR  
	   FOR SELECT concept,typ,cost_in_minutes,foreignkey FROM dbo.CRENT_UPDATE6_ESTIMATION_COSTS(@mandantId)
	OPEN crentupdate6_estimation_text_costs_cursor  
	FETCH NEXT FROM crentupdate6_estimation_text_costs_cursor INTO @concept,@typ,@costs,@foreignkey
	WHILE @@FETCH_STATUS = 0  
	BEGIN  
		IF (@typ = 'subtopic')
			BEGIN
				IF (@foreignkey IN ('QS'))  
					BEGIN
						PRINT CHAR(9)+@concept
						SET @E_MailContents+=CHAR(9)+CHAR(9)+@concept+CHAR(13)
					END    
				ELSE 
					BEGIN
						PRINT CHAR(9)+@concept+  ' => '+CAST(ROUND(@costs/60,3)  AS VARCHAR(16))+' Std ('+CAST(@costs AS VARCHAR(16))+' Min)'
						SET @E_MailContents+=CHAR(9)+CHAR(9)+@concept+  ' => '+CAST(ROUND(@costs/60,3)  AS VARCHAR(16))+' Std ('+CAST(@costs AS VARCHAR(16))+' Min)'+CHAR(13)
					END 
					
			END
		ELSE IF(@typ = 'main' AND @foreignkey IN ('GESAMTAUFWAND','QS'))  
			BEGIN
				PRINT CHAR(13)+@concept+CHAR(13)+CHAR(9)+' => '+CAST(ROUND(@costs/60,3) AS VARCHAR(16))+' Std ('+CAST(@costs AS VARCHAR(16))+' Min)'  
				SET @E_MailContents+=CHAR(13)+@concept+CHAR(13)+CHAR(9)+' => '+CAST(ROUND(@costs/60,3) AS VARCHAR(16))+' Std ('+CAST(@costs AS VARCHAR(16))+' Min)'+CHAR(13)  
			END 		 
			
		ELSE IF(@typ = 'main' AND @foreignkey <> 'GESAMTAUFWAND') 
			BEGIN
				PRINT CHAR(13)+@concept+' ['+CAST(ROUND(@costs/60,3) AS VARCHAR(16))+' Std ('+CAST(@costs AS VARCHAR(16))+' Min)]'   
				SET @E_MailContents+=CHAR(13)+@concept+' ['+CAST(ROUND(@costs/60,3) AS VARCHAR(16))+' Std ('+CAST(@costs AS VARCHAR(16))+' Min)]'+CHAR(13)   
			END 		  
			
		FETCH NEXT FROM crentupdate6_estimation_text_costs_cursor INTO @concept,@typ,@costs,@foreignkey
	END   
	CLOSE crentupdate6_estimation_text_costs_cursor  
	DEALLOCATE crentupdate6_estimation_text_costs_cursor 

	PRINT @E_MailContents
	IF (ISNULL(@E_MailContents,'') <> '')
		BEGIN
			SET @E_MailContents = REPLACE(@E_MailContents,CHAR(13),'<br>')      
			SET @E_MailContents = REPLACE(@E_MailContents,CHAR(9),'&emsp;')      
			IF (ISNULL(@recipients,'')='')
				SET @recipients='j.munoz@cx9.de'
			ELSE IF (ISNULL(@recipients,'')<>'')
				SET @recipients+=';j.munoz@cx9.de'
			DECLARE @EmailContents NVARCHAR(MAX) = 'Guten Tag, <br><br><b>
												 Anfrage wie gewünscht:</b><br> 
												'+@E_MailContents + ' <br><br> '
			SET @ABAS_TASK_NO = ISNULL(@ABAS_TASK_NO,'')
			DECLARE @SUBJECT NVARCHAR(128) = 'Anfrage No.: '+@ABAS_TASK_NO+' Aufwand des Updates 6.0'
			EXEC dbo.CRENT_UPDATES_SEND_EMAIL @MANDANT_ID = @mandantId, @subject = @SUBJECT, @recipients = @recipients, @contents = @EmailContents,@resultMessage = NULL, @reportJustDeveloper = 0, @printStatusTimestamp = 0

		END
END
GO
