CREATE PROCEDURE [dbo].[CRENTWEB_6_DEPLOYMENT_FILES](@branch VARCHAR(255) = '')
AS 
	SET NOCOUNT ON
	DECLARE @deployPath VARCHAR(2048) = dbo.UPDATES_TMP_DEPLOY_FOLDER() 
	DECLARE @deployFile VARCHAR(2048) = ''
	--SET @deployFile = @deployPath+'\deployment6\script.sh'    
	DECLARE @gitlab_ciPath VARCHAR(2048)=@deployPath+'\crentweb_deployment\'
	DECLARE @tab TABLE(cmdRes VARCHAR(MAX) NULL)
	DECLARE @cmds VARCHAR(2048)=''	
	SET @cmds = 'RD /S /Q "'+@gitlab_ciPath+'"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds
	DECLARE @gitlab_ciFilename VARCHAR(1024)=@gitlab_ciPath+'.gitlab-ci.yml'
	DECLARE @gitlab_ciContents VARCHAR(MAX) = dbo.GET_CRW6_DEPLOYMENT_GITLAB_CI(@branch)
	PRINT 'Processing ... '+@gitlab_ciFilename
	EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 

	IF (ISNULL(@branch,'') NOT IN ('master','develop')) --für single branches wie acl
		BEGIN
 	
			IF ((SELECT COUNT (MainCRWBranch) FROM dbo.MANDANT_WEB_PRODUKTE WHERE MainCRWBranch = @branch AND Environment='ACC')=1)	
				BEGIN
					SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT('ACC','6.0',@branch)
					SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\acceptance_600.yml' 
					PRINT 'Processing ... '+@gitlab_ciFilename
					EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 					
				END 
			IF ((SELECT COUNT (MainCRWBranch) FROM dbo.MANDANT_WEB_PRODUKTE WHERE MainCRWBranch = @branch AND Environment='LIVE')=1)	
				BEGIN
					SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT('LIVE','6.0',@branch)
					SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\productive_600.yml' 
					PRINT 'Processing ... '+@gitlab_ciFilename
					EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 					
				END
		END
	ELSE
		BEGIN      

			SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT('LIVE','5.16',DEFAULT)
			SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\productive_516.yml' 
			PRINT 'Processing ... '+@gitlab_ciFilename
			EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 


			SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT('ACC','5.16',DEFAULT)
			SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\acceptance_516.yml' 
			PRINT 'Processing ... '+@gitlab_ciFilename
			EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 

			/*SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT('LIVE','6.0',DEFAULT)
			SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\productive_600.yml' 
			PRINT 'Processing ... '+@gitlab_ciFilename
			EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents
			*/ 
			SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT_LIMIT('LIVE','6.0',1,100)
			SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\productive_600_1_100.yml' 
			PRINT 'Processing ... '+@gitlab_ciFilename
			EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 

			SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT_LIMIT('LIVE','6.0',101,200)
			SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\productive_600_101_200.yml' 
			PRINT 'Processing ... '+@gitlab_ciFilename
			EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 


			SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT_LIMIT('ACC','6.0',1,100)
			SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\acceptance_600_1_100.yml' 
			PRINT 'Processing ... '+@gitlab_ciFilename
			EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 

			SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_GROUP_ENVIRONMENT_LIMIT('ACC','6.0',101,200)
			SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\acceptance_600_101_200.yml' 
			PRINT 'Processing ... '+@gitlab_ciFilename
			EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 
	
		END
GO
/****** Object:  StoredProcedure [dbo].[CRENTWEB_6_DEPLOYMENT_FILES_old]    Script Date: 25.01.2022 03:14:47 ******/
