CREATE PROCEDURE [dbo].[CRENTWEB_6_DEPLOYMENT_FILES_old]
AS 
	SET NOCOUNT ON
	DECLARE @gitlab_ciPath VARCHAR(1024)= dbo.UPDATES_TMP_DEPLOY_FOLDER()+'\crentweb_deployment\'
	DECLARE @tab TABLE(cmdRes VARCHAR(MAX) NULL)
	DECLARE @cmds VARCHAR(2048)=''	
	SET @cmds = 'RD /S /Q "'+@gitlab_ciPath+'"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds 
	DECLARE @gitlab_ciFilename VARCHAR(1024)=@gitlab_ciPath+'.gitlab-ci.yml'
	DECLARE @gitlab_ciContents NVARCHAR(MAX) = dbo.GET_CRW6_DEPLOYMENT_GITLAB_CI('master')
	PRINT 'Processing ... '+@gitlab_ciFilename
	EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents
	DECLARE @MANDANT_ID INT = NULL
	DECLARE @MANDANT_DEPLOYMENTNAME VARCHAR(1024)  = ''
	DECLARE crw_environment CURSOR  
	   FOR SELECT MANDANT_ID, CRW_DEPLOYMENT_NAME FROM dbo.GET_CRW6DEPLOYMENT_MANDANT_DB_ENVIRONMENT(DEFAULT)

	OPEN crw_environment  
	FETCH NEXT FROM crw_environment INTO @MANDANT_ID, @MANDANT_DEPLOYMENTNAME
  
	WHILE @@FETCH_STATUS = 0  
	BEGIN  
 
		SET @gitlab_ciFilename = @gitlab_ciPath+'.deployment\'+@MANDANT_DEPLOYMENTNAME+'.yml'
		SET @gitlab_ciContents = dbo.GET_CRW6_DEPLOYMENT_ENVIRONMENTS (@MANDANT_ID)
		PRINT 'Processing ... '+@gitlab_ciFilename
		EXEC dbo.WriteFile @fileName = @gitlab_ciFilename, @fileContents = @gitlab_ciContents 
	
		FETCH NEXT FROM crw_environment	INTO @MANDANT_ID, @MANDANT_DEPLOYMENTNAME
	END   
	CLOSE crw_environment  
	DEALLOCATE crw_environment 
GO
