CREATE PROCEDURE [dbo].[CRW_INSTALL_DB_CREATE] @databasename NVARCHAR(17)
as

-- Umgebugsvariablen festlegen
DECLARE @sql NVARCHAR(MAX)
SET @sql=''

DECLARE @bckpFile NVARCHAR(MAX)
SET @bckpFile = N'B:\temp\tmp_VorlageCRW.bak'

DECLARE @masterProcedure NVARCHAR(MAX)
SET @masterProcedure = N'master.dbo.sp_executesql'

DECLARE @log_mdf NVARCHAR(max)
SET @log_mdf = N'E:\Standard\dbs\' + @databasename + '.mdf'

DECLARE @log_ldf NVARCHAR(max)
SET @log_ldf = N'E:\Standard\dbs\' + @databasename + '.LDF'



SELECT @sql=@sql + 'kill ' + CONVERT(VARCHAR,spid) +';'
FROM master..sysprocesses
WHERE dbid=DB_ID(@databasename) AND spid<>@@SPID AND cmd<>'CHECKPOINT'
EXEC(@sql)


IF ( NOT EXISTS(SELECT name FROM master.dbo.sysdatabases WHERE name = @databasename))
BEGIN
	-- Datenbank backup
	BACKUP DATABASE VorlageCRW TO DISK = @bckpFile with INIT

	-- Datenbank wiederherstellen
	/*
	RESTORE DATABASE @databasename FROM DISK = N'B:\dbs-sicherung\STD_VorlageCRW.bak' WITH FILE=1,
		MOVE N'VorlageCRW' TO @log_mdf,
		MOVE N'VorlageCRW_log' TO @log_ldf, NOUNLOAD, STATS = 10
	*/
	SET @sql = N'RESTORE DATABASE ' + @databasename + N' FROM DISK = N''' + @bckpFile + ''' WITH FILE=1,
			   MOVE N''VorlageCRW'' TO N''' + @log_mdf + N''',
			   MOVE N''VorlageCRW_log'' TO N''' + @log_ldf + N''', NOUNLOAD, STATS = 10'
	--EXECUTE master.dbo.sp_executesql @sql
	--MASTER.dbo.sp_executesql @sql
	EXECUTE @masterProcedure @sql
END

GO
