CREATE PROCEDURE [dbo].[CRW_INSTALL_USER_CREATE] @dbuser sysname, @dbname sysname
   
as

DECLARE @sql NVARCHAR(MAX)
DECLARE @dbpass sysname


SELECT @dbpass = dbo.SEC_GetPWCOde(@dbuser)

		EXECUTE master.dbo.sp_addlogin
			@loginame = @dbuser,
			@passwd = @dbpass,
			@defdb = @dbname,
			@deflanguage = [Deutsch],
			@sid = null,
			@encryptopt= NULL
        
		EXECUTE master.sys.sp_addsrvrolemember @loginame = @dbuser, @rolename = N'bulkadmin'

SET @sql = 'USE [' + @dbname + ']'
EXECUTE master.dbo.sp_executesql @sql

SET @sql = 'USE [' + @dbname + ']; CREATE USER ' + @dbuser +' FOR LOGIN ' + @dbuser + ';'
EXECUTE master.dbo.sp_executesql @sql

SET @sql = 'USE [' + @dbname + ']; EXEC sp_addrolemember N''db_owner'', ' + @dbuser +';'
EXECUTE master.dbo.sp_executesql @sql
GO
/****** Object:  StoredProcedure [dbo].[CX9_CALC_VEHICLE_AMOUNT]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[CX9_CALC_VEHICLE_AMOUNT] (@von DATETIME,@bis DATETIME,@monthdays INT) 
AS  
IF (exists (SELECT name FROM sysobjects WHERE name='CX9_VEHICLE_AMOUNT'))    
DROP TABLE CX9_VEHICLE_AMOUNT  
CREATE TABLE CX9_VEHICLE_AMOUNT (mvanummer VARCHAR (30),von datetime, bis DATETIME, tagenutzung FLOAT, anzahlkfz FLOAT, mieten INT, miettage FLOAT, langzeit BIT, faktor FLOAT, abzurechnen float)  
INSERT INTO CX9_VEHICLE_AMOUNT (mvanummer,von) 
SELECT mvanummer,zuldat FROM autos WHERE OWNER=(SELECT ownercode FROM MAND_GLOBAL WHERE pk=1)  
UPDATE a SET bis=(SELECT rueckgabehaendler FROM autoszusdaten az WHERE az.mvanummer=a.mvanummer)  
FROM CX9_VEHICLE_AMOUNT a  
UPDATE CX9_VEHICLE_AMOUNT set bis=@bis WHERE (bis IS NULL OR bis>@bis)  
UPDATE CX9_VEHICLE_AMOUNT SET von=@von WHERE von<@von
DELETE FROM CX9_VEHICLE_AMOUNT WHERE bis<=von  
UPDATE CX9_VEHICLE_AMOUNT SET Tagenutzung=datediff(dd,von,bis)  
UPDATE CX9_VEHICLE_AMOUNT SET anzahlkfz=ROUND(CONVERT(FLOAT,Tagenutzung) / CONVERT(FLOAT,DATEDIFF(dd, @von,@bis)),1)  
UPDATE a SET Mieten = (SELECT COUNT(*) FROM MIETVERTRAEGE m WHERE ISNULL(VTC, '')<>'V' AND ISNULL(Reservierung,'')<>'j'  
  AND m.mvanummer=a.mvanummer AND NOT (dbo.VTR_CALC_GetGroupStartDat(m.VERTRAGSNUMMER)>@bis) AND NOT (dbo.VTR_CALC_GetGroupEndDat(m.VERTRAGSNUMMER)<@von))  
  FROM CX9_VEHICLE_AMOUNT a  
UPDATE a SET Miettage = (SELECT ceiling(sum(dbo.REL_GETRELTAGE_OPEN_ALSO(vertragsnummer,@von,@bis))) 
 FROM MIETVERTRAEGE m   WHERE ISNULL(VTC, '')<>'V' AND ISNULL(Reservierung,'')<>'J' AND m.mvanummer=a.mvanummer AND NOT   
 (dbo.VTR_CALC_GetGroupStartDat(VERTRAGSNUMMER)>@bis) AND NOT (dbo.VTR_CALC_GetGroupEndDat(VERTRAGSNUMMER)<@von))  from CX9_VEHICLE_AMOUNT a  
UPDATE a SET Langzeit = CASE WHEN Miettage>=@monthdays and mieten=1 then 1 else 0 END  FROM CX9_VEHICLE_AMOUNT a  
UPDATE CX9_VEHICLE_AMOUNT SET faktor=CASE WHEN langzeit=1 THEN 0.25 ELSE 1 END  
UPDATE CX9_VEHICLE_AMOUNT SET Abzurechnen=anzahlkfz * Faktor
GO
