CREATE PROCEDURE [dbo].[CX9_CRENT_SEND_EMAIL](@MANDANT_ID INT = NULL,@subject NVARCHAR(255)='', @recipients VARCHAR(1024)='', @contents NVARCHAR(MAX)='', @resultMessage NVARCHAR(2048) OUTPUT,  @reportJustDeveloper BIT = 1,   @TSQLCSV NVARCHAR(MAX)='', @csvFilename VARCHAR(255) = '_report.csv', @checkTSQLCSV BIT = 0 ,@debug bit = 0) 
 AS SET NOCOUNT ON
	SET @resultMessage = ''
 
	IF (ISNULL(@recipients,'')='')
		SET @resultMessage = 'Geben Sie gültige E-Mail Adressen ein!'
	IF (ISNULL(@subject,'')='')
		SET @resultMessage = 'Geben Sie ein gültiges Subject ein!'
	IF (@resultMessage <> '')
		RETURN @resultMessage
	DECLARE  @csv_result BIT = NULL 
	IF ( @checkTSQLCSV = 0 AND ISNULL(@TSQLCSV,'')<>'')
		SET @csv_result = 1	  
	IF (ISNULL(@TSQLCSV,'')<>'' AND @checkTSQLCSV = 1)
		BEGIN 
			EXEC dbo.CHECK_TSQL_SYNTAX @TSQL = @TSQLCSV,  @result = @csv_result OUTPUT
		END 
	DECLARE @props VARCHAR(255)
	SET @props = '
	SET NOCOUNT ON
	SET ANSI_WARNINGS ON 
	SET ANSI_NULLS ON
	'
	IF(ISNULL(@TSQLCSV,'')<>'')
		SET @TSQLCSV = @props+ @TSQLCSV
 
	DECLARE @absendermail VARCHAR(255) = 'mailer@cx9.de'
	DECLARE @mailserver VARCHAR(255) = '192.168.254.213'
	DECLARE @mailport int ='587'
	DECLARE @mand_name_email_profil NVARCHAR(255) = ''
	DECLARE @SMAIL_SMTP_USER VARCHAR(255) = 'mailer@cx9.de'
	DECLARE @SMAIL_SMTP_PW VARCHAR(255) = 'gR0un#07'
