	DECLARE @mandantNameAbasID VARCHAR(255) = ISNULL((SELECT TOP 1 abasId FROM dbo.Mandant WHERE id = @MANDANT_ID),'1')
	IF (@reportJustDeveloper = 1) SET @recipients = 'j.munoz@cx9.de'  
  
	IF (@reportJustDeveloper = 1) SET @recipients = 'j.munoz@cx9.de'  
	DECLARE @myid uniqueidentifier = NEWID()   
 
	SET @mand_name_email_profil = ISNULL((SELECT TOP 1 companyname FROM dbo.Mandant WHERE id = @MANDANT_ID),'')
	set @mand_name_email_profil = UPPER(@mand_name_email_profil) + ''+CONVERT(NVARCHAR(255), @myid)

	 IF (@debug = 1)
		BEGIN
			SELECT @mailserver[@mailserver], @mailport[@mailport], @SMAIL_SMTP_USER[@SMAIL_SMTP_USER], @SMAIL_SMTP_PW[@SMAIL_SMTP_PW], @mandantName[@mandantName],@mand_name_email_profil[@mand_name_email_profil]
			PRINT @TSQLCSV   
		END
  
 /*SELECT * FROM  msdb.dbo.sysmail_profile             
  SELECT * FROM  msdb.dbo.sysmail_account */      

	delete FROM msdb.dbo.sysmail_profile WHERE name = @mand_name_email_profil
	delete FROM msdb.dbo.sysmail_account WHERE name = @mand_name_email_profil
	--delete FROM msdb.dbo.sysmail_profile WHERE profile_id >=7789
	--SELECT * FROM msdb.dbo.sysmail_profile
	-- Create a Database Mail profile 
	EXECUTE msdb.dbo.sysmail_add_profile_sp @profile_name = @mand_name_email_profil, @description = @mand_name_email_profil; 

	-- Create a Database Mail account 
	EXECUTE msdb.dbo.sysmail_add_account_sp  @account_name = @mand_name_email_profil,  @description = @mand_name_email_profil,
			@email_address = @absendermail,@port = @mailport,
				@enable_ssl = 0,  @mailserver_name = @mailserver, @mailserver_type  = N'SMTP', @username  = @SMAIL_SMTP_USER, @password  = @SMAIL_SMTP_PW;		 

	-- Add the account to the profile 
	EXECUTE msdb.dbo.sysmail_add_profileaccount_sp  @profile_name = @mand_name_email_profil, @account_name = @mand_name_email_profil,  @sequence_number =1 ; 

	-- Grant access to the profile to the DBMailUsers role 
	EXECUTE msdb.dbo.sysmail_add_principalprofile_sp  @profile_name = @mand_name_email_profil,  @principal_id = 0, @is_default = 1 ; 
 
	DECLARE @empfaengermail VARCHAR(MAX) = ''
	DECLARE @station VARCHAR(30) 

	DECLARE @databasename VARCHAR(128) = DB_NAME()
	DECLARE @email NVARCHAR(MAX) = @contents
	DECLARE @emailSignature NVARCHAR(MAX)=''
	DECLARE @emailSubject VARCHAR(MAX)= @subject+' ['+@mandantName+']'
	DECLARE @error VARCHAR(MAX)
	 
	--DECLARE @CURRENT_TIMESTAMP VARCHAR(32) = dbo.GET_ISO_DATETIME(CURRENT_TIMESTAMP,DEFAULT)-- CONVERT(VARCHAR(32),CURRENT_TIMESTAMP,104)+' '+CONVERT(VARCHAR(32),CURRENT_TIMESTAMP,114) 
	DECLARE @CURRENT_TIMESTAMP VARCHAR(32) =  CONVERT(VARCHAR(32),CURRENT_TIMESTAMP,104)+' '+CONVERT(VARCHAR(8),CURRENT_TIMESTAMP,114) 
	DECLARE @mail_recipients_string VARCHAR(1024) = @recipients 
 
	DECLARE @connectionString VARCHAR(2048) = CHAR(13)+CHAR(10)+
											 '</br>Servername: ' +CAST(ISNULL(@@SERVERNAME,'SERVERNAME') AS VARCHAR(32))+','+CHAR(13)+CHAR(10)+
											 '</br>Net_transport: ' +CAST(ISNULL(CONNECTIONPROPERTY('net_transport'),'') AS VARCHAR(32))+','+CHAR(13)+CHAR(10)+
											 '</br>Protocol_type: '+CAST(ISNULL(CONNECTIONPROPERTY('protocol_type'),'') AS VARCHAR(32))+','+CHAR(13)+CHAR(10)+
											 '</br>Auth_scheme: ' +CAST(ISNULL(CONNECTIONPROPERTY('auth_scheme'),'') AS VARCHAR(32))+','+CHAR(13)+CHAR(10)+
											 '</br>Local_net_address: '+CAST(ISNULL(CONNECTIONPROPERTY('local_net_address'),'') AS VARCHAR(32))+','+CHAR(13)+CHAR(10)+
											 '</br>Local_tcp_port: ' +CAST(ISNULL(CONNECTIONPROPERTY('local_tcp_port'),'') AS VARCHAR(32))+','+CHAR(13)+CHAR(10)+
											 '</br>Client_net_address: '+CAST(ISNULL(CONNECTIONPROPERTY('client_net_address'),'') AS VARCHAR(32))+CHAR(13)+CHAR(10)										 
 
 
 
	BEGIN TRY
		BEGIN
				--SET @email = 'test 1'
			IF (ISNULL(@csv_result,0) = 0)
				BEGIN
					PRINT 'sending normal mail'	
					EXEC msdb.dbo.sp_send_dbmail @profile_name = @mand_name_email_profil,
					@recipients=@mail_recipients_string,
					@subject=@emailSubject,
					@body=@email,
					@query = '',
					@execute_query_database = @databasename,
					@attach_query_result_as_file=0,
					@query_attachment_filename = '',
					@query_result_separator = ';',
					@query_result_width = 550,
					@query_result_no_padding =1,
					@body_format = 'HTML'				    
				END

			ELSE IF (@csv_result = 1)
				BEGIN
					PRINT 'sending csv'
					EXEC msdb.dbo.sp_send_dbmail @profile_name =  @mand_name_email_profil,
					 @recipients=@mail_recipients_string,
					 @subject=@emailSubject,
					 @body=@email,
					 @execute_query_database = @databasename,
					 @query_attachment_filename = @csvFilename,
					 --@query_result_header = 0,
					 @body_format = 'html',
					 @query = @TSQLCSV,
					 @attach_query_result_as_file=1,
					 @query_result_separator = ',',
					 @query_result_header = 1,
					 @query_no_truncate = 0,
					 @query_result_width = 32767,
					 @query_result_no_padding =1 				    
				END
 
		END
	END TRY
	BEGIN CATCH 
		SET @resultMessage = ERROR_MESSAGE()
	END CATCH
    WAITFOR DELAY '00:00:09'  
  
	delete FROM msdb.dbo.sysmail_profile WHERE name = @mand_name_email_profil
	delete FROM msdb.dbo.sysmail_account WHERE name = @mand_name_email_profil    
	--SELECT * FROM msdb.dbo.sysmail_account WHERE name = 'CX9 SYSTEMS GMBH526C01F0-3786-4879-9E79-AD2AB29765F8'    
