	/*DELETE FROM  msdb.dbo.sysmail_profile WHERE profile_id IN ( SELECT account_id FROM  msdb.dbo.sysmail_account WHERE email_address='j.munoz@cx9.de' )
	 DELETE FROM  msdb.dbo.sysmail_account WHERE email_address='j.munoz@cx9.de'
	 */
	RETURN @resultMessage    
	 
