CREATE PROCEDURE [dbo].[DEPLOY_DB_ENVIRONMENT_MULTITASK](
@MANDANT_ID INT = NULL, @ENVIRONMENT_NAME NVARCHAR(128)= NULL, @ENVIRONMENT_version VARCHAR(16)= '6.0', @prodBigTransBatch BIT = 0, @tagversion VARCHAR(128) = '', @type VARCHAR(32) = 'single' ,@miltiNumber INT = 5 )
AS SET NOCOUNT ON
	BEGIN
	    DECLARE @environments TABLE (MANDANT_ENV_PK INT NULL, MANDANT_ID INT NOT NULL, ENVIRONMENT VARCHAR(128) NOT NULL)
		
		IF (@type NOT IN ('single','all','update','multi'))
			SET @type = 'single'
		if (@MANDANT_ID IS NOT NULL)
			SET @type = @type+'\'+CAST(@MANDANT_ID AS NVARCHAR(32))
		DECLARE @deploymentBasePath NVARCHAR(2048) = '\\ku-fs01.kunden.local\deployment\'+@type+'\'
		DECLARE @deploymentBasePathFilename NVARCHAR(4000) = ''
		DECLARE @deploymentBasePathFileContents NVARCHAR(MAX) = ''

		IF (@tagversion <> '')
		INSERT INTO dbo.DEPLOYMENT_versionS
		        SELECT REPLACE(REPLACE(@tagversion,'version_',''),'_','.'), GETDATE(), NULL

		INSERT INTO @environments
			SELECT PK, mandant_id, CASE WHEN type ='DEFAULT' THEN 'LIVE'
				WHEN databaseName LIKE 'ACC_%' THEN 'ACC'
				WHEN databaseName LIKE 'KOPIE_%' THEN 'ACC' ELSE type END[env]
			FROM MANDANT_DB_ENVIRONMENT ME WHERE me.version = @ENVIRONMENT_version AND ME.mandant_id IN (SELECT id FROM dbo.Mandant)
		IF (@MANDANT_ID IS NOT NULL AND @ENVIRONMENT_NAME IS NULL)
			DELETE FROM @environments WHERE MANDANT_ID NOT IN (@MANDANT_ID) 
		ELSE IF (@MANDANT_ID IS NULL AND @ENVIRONMENT_NAME IS NOT NULL)
			BEGIN 
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@ENVIRONMENT_NAME)
			END 
		ELSE IF (@MANDANT_ID IS NOT NULL AND @ENVIRONMENT_NAME IS NOT NULL)
			BEGIN
				DELETE FROM @environments WHERE MANDANT_ID NOT IN (@MANDANT_ID)  
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@ENVIRONMENT_NAME)
			END 
	--Blacklist entfernen		
--	DELETE FROM @environments WHERE MANDANT_ENV_PK IN (SELECT MANDANT_ENVIRONMENT_PK FROM [dbo].[BLACKLIST_MANDANT_DB_ENVIRONMENT])
	
	/* declare variables */
	DECLARE @cursor_mandant_id INT
	DECLARE @mandant_env VARCHAR(128)
	DECLARE @mandant_env_pk INT
	DECLARE @param_deploy_procs_directly VARCHAR(2048)=''
	DECLARE @cmds VARCHAR(1024)=''
	DECLARE @COMPARE_DATEN_STATIC_DATA_USER_EXCLUDED_FILENAME VARCHAR(1024)=''+@deploymentBasePath+'Schema Compare\user_excluded.scpf'  
	DECLARE @tab TABLE(cmdRes VARCHAR(MAX) NULL)
	SET @cmds = 'RD /S /Q "'+@deploymentBasePath+'Schema Compare\"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds 
	SET @cmds = 'RD /S /Q "'+@deploymentBasePath+'Data Compare\"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds 

	SET @cmds = 'RD /S /Q "'+@deploymentBasePath+'advance_trans_deployment\"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds 

	SET @cmds = 'DEL /S /Q "'+@deploymentBasePath+'*.*"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds 

	DECLARE @batchfileForTransContents VARCHAR(MAX)= ''
	DECLARE @batchfileNameForTransContents VARCHAR(MAX)= ''
	DECLARE @serverConnections XML = NULL
	DECLARE @tsql NVARCHAR(MAX) = ''
	DECLARE @taskLabel VARCHAR(128) = 'Anfrage Nr. '

	--deploy tsql advance translations
	DECLARE @batchFileTranslations NVARCHAR(MAX) = dbo.GET_ADVANCE_DEPLOY_TRANS_BATCH_FOLDER(@type)
	SET @deploymentBasePathFilename = ''+@deploymentBasePath+'advance_trans_deployment\deploy.bat'
	EXEC dbo.WriteFile @fileName = @deploymentBasePathFilename, @fileContents = @batchFileTranslations -- nvarchar(max)
	
	DECLARE cursor_environments CURSOR FOR SELECT MANDANT_ENV_PK, MANDANT_ID , ENVIRONMENT FROM @environments

	OPEN cursor_environments
	FETCH NEXT FROM cursor_environments INTO @mandant_env_pk, @cursor_mandant_id, @mandant_env
	WHILE @@FETCH_STATUS = 0
	BEGIN
		--PRINT @@cursor_mandant_id
		--PRINT @mandant_env
		 --TSE 20.12.21 ist doch besser aus der entsprechenden Tabelle?!?!
			--IF((SELECT COUNT(*) FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @cursor_mandant_id AND version = @ENVIRONMENT_version)>=2 AND @mandant_id NOT IN (410,409,635,446,562) OR ( @mandant_id IN (98,441) AND @ENVIRONMENT_version = '6.0' )) 
			IF((SELECT COUNT(*) FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @cursor_mandant_id AND version = @ENVIRONMENT_version)>=2 AND 
			    @mandant_id NOT IN (SELECT DISTINCT mandantid FROM MANDANT_WEB_PRODUKTE WHERE ISNULL(ARCHIV_DB,'')<>'') OR ( @mandant_id IN (98,441) AND @ENVIRONMENT_version = '6.0' )) 
				BEGIN --PRINT @mandant_env_pk
					EXEC dbo.GET_SQL_COMPARE_XML_BY_MAND_ENV_PK @MAND_ENV_PK = @mandant_env_pk, @deploymentSubfolder = @type, @execUpdate6 = 1
				END     
			--ELSE IF((SELECT COUNT(*) FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @cursor_mandant_id AND version = @ENVIRONMENT_version AND type='DEFAULT')=1 AND @mandant_id NOT IN (410,409,635,446,562) OR ( @mandant_id IN (98,441) AND @ENVIRONMENT_version = '6.0' )) 
			ELSE IF((SELECT COUNT(*) FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @cursor_mandant_id AND version = @ENVIRONMENT_version AND type='DEFAULT')=1 
			    AND @mandant_id NOT IN (SELECT DISTINCT mandantid FROM MANDANT_WEB_PRODUKTE WHERE ISNULL(ARCHIV_DB,'')<> '') OR ( @mandant_id IN (98,441) AND @ENVIRONMENT_version = '6.0' )) 
				BEGIN --PRINT @mandant_env_pk
					EXEC dbo.GET_SQL_COMPARE_XML_BY_MAND_ENV_PK @MAND_ENV_PK = @mandant_env_pk, @deploymentSubfolder = @type, @execUpdate6 = 1
				END     
			ELSE  
				BEGIN --  PRINT @mandant_env_pk
					EXEC dbo.GET_SQL_COMPARE_XML @MandantId = @cursor_mandant_id, @Environment = @mandant_env,  @compareType = 'SCHEMA', @writeFile = 1, @updateScript = 0, @writeOnSubfolder = @type, @execUpdate6 = 1
					EXEC dbo.GET_SQL_COMPARE_XML @MandantId = @cursor_mandant_id, @Environment = @mandant_env,  @compareType = 'DATA', @writeFile = 1, @updateScript = 0, @writeOnSubfolder = @type, @execUpdate6 = 0		
				END
			IF (@prodBigTransBatch = 1)
				BEGIN
					SET @batchfileForTransContents = dbo.DEPLOY_TRANSLATIONS_BY_PK(@mandant_env_pk,'STATIC_DATA_TO_CLIENT')
					SET @batchfileNameForTransContents = ''+@deploymentBasePath+'post_trans6\trans_'+CAST(@mandant_env_pk AS VARCHAR(32))+'_'+CAST(@cursor_mandant_id AS VARCHAR(32))+'_'+@mandant_env+'.bat'
					--EXEC dbo.longPrintingString @printigString = @t -- nvarchar(max)
					--PRINT LEN(@batchfileForTransContents)
					IF(@batchfileForTransContents <> '' AND LEN(@batchfileForTransContents) > 1)
						EXEC dbo.WriteFile @fileName = @batchfileNameForTransContents, @fileContents = @batchfileForTransContents                 
					SET @batchfileForTransContents = ''/**/					
				END   
		-- postscripst für translations
		
		 IF(dbo.GET_DEPLOYMENT_LINKED_SERVER_CONNECTION_BY_PK(@mandant_env_pk,@ENVIRONMENT_version)<>'')
			BEGIN
					          
				 SET @serverConnections = dbo.GET_DEPLOYMENT_LINKED_SERVER_CONNECTION_BY_PK(@mandant_env_pk,@ENVIRONMENT_version)
				 SET @tsql  = 'DECLARE @connections XML = '''+ dbo.RenderXMLToString(@serverConnections)
												+''''+CHAR(13)+
							  'DECLARE @patchesTSQL XML = ''<TSQL>'+ CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), dbo.GET_PRE_CRENT_UPDATE6_SQLSCRIPTS(@cursor_mandant_id)), 1) +'</TSQL>'
												+''''+CHAR(13)+--
												+'/*EXEC dbo.DEPLOY_TRANSLATIONS_ON_REMOTE_LINKED_SERVER'+CHAR(13)
												+'@LINKED_SERVERS_DATA_CONNECTION = @connections'+CHAR(13)
												+'*/ '+CHAR(13)
												+'EXEC dbo.DEPLOY_SQL_ON_REMOTE_LINKED_SERVER'+CHAR(13)
												+'@LINKED_SERVERS_DATA_CONNECTION = @connections, '+CHAR(13)
												+'@SQL_INSTRUCTIONS=@patchesTSQL,@TSQL_PARSE=1/**/'
				 SET @batchfileNameForTransContents = ''+@deploymentBasePath+'advance_trans_deployment\tsql_'+CAST(@mandant_env_pk AS VARCHAR(32))+'_'+CAST(@cursor_mandant_id AS VARCHAR(32))+'_'+@mandant_env+'.sql'
				 EXEC dbo.WriteFile @fileName = @batchfileNameForTransContents, @fileContents = @tsql	
				 
				 
/*
DECLARE @LINKED_SERVERS_DATA_CONNECTION XML = 
   '<server>
      <LINKED_SERVER name="HEZEL_ACC">
		  <ServerName>10.0.69.9\CRENT,1433</ServerName>
		  <DatabaseName>ACC_crent</DatabaseName>
		  <Username>ACC_HZ</Username> 
		  <Password>%BGL%o#)a)%~</Password>
	  </LINKED_SERVER>
	 </server>'
--INSERT INTO @fields
EXEC dbo.SQL2012DEV_EXEC_TSQLQUERY_ON_REMOTE_LINKED_SERVER 
@LINKED_SERVERS_DATA_CONNECTION = @LINKED_SERVERS_DATA_CONNECTION, @type ='diffTables', @mandantName='Hezel'

*/				 SET @param_deploy_procs_directly='' 
				 IF(dbo.isClientExtern(@cursor_mandant_id) = 1)
					SET @param_deploy_procs_directly = '@deployProcsDirectlyNamesLike = ''TRESOR_%'','
				 SET @taskLabel += ISNULL((SELECT TOP 1 ABAS_TASK_NO FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @cursor_mandant_id AND ISNULL(ABAS_TASK_NO,'')<>''),'KEINE_ABAS_NO :')
				 SET @tsql  = 'DECLARE @connections XML = '''+ dbo.RenderXMLToString(@serverConnections)
												+''''+CHAR(13)+												
												+'EXEC dbo.SQL2012DEV_EXEC_TSQLQUERY_ON_REMOTE_LINKED_SERVER'+CHAR(13)
												+'@LINKED_SERVERS_DATA_CONNECTION = @connections,'+CHAR(13)
												+'@type =''diffTables'', '+CHAR(13)
												+@param_deploy_procs_directly+CHAR(13)
												+'@mandantName ='''+@taskLabel+': ('+(SELECT TOP 1 MANDANT_NAME FROM  dbo.GET_CRWJASPERDEPLOYMENT_MANDANT_DB_ENVIRONMENT(@cursor_mandant_id))+')'+''' '
				 SET @batchfileNameForTransContents = ''+@deploymentBasePath+'tableReports\tsql_'+CAST(@mandant_env_pk AS VARCHAR(32))+'_'+CAST(@cursor_mandant_id AS VARCHAR(32))+'_'+@mandant_env+'.sql'
				 EXEC dbo.WriteFile @fileName = @batchfileNameForTransContents, @fileContents = @tsql					 			           
			END
		FETCH NEXT FROM cursor_environments INTO @mandant_env_pk, @cursor_mandant_id, @mandant_env
	END
	
	DECLARE @tableDiffsBatch NVARCHAR(MAX) = dbo.GET_ADVANCE_DEPLOY_TRANS_BATCH_TABLE_REPORTS_FOLDER(@type)
	DECLARE @tableDiffsBatchName NVARCHAR(MAX) =  @deploymentBasePath+'tableReports\tableDiffs.bat'
	EXEC dbo.WriteFile @fileName = @tableDiffsBatchName, @fileContents = @tableDiffsBatch	
	CLOSE cursor_environments
	DEALLOCATE cursor_environments

	DECLARE @typeOfDeploy VARCHAR(32) = 'all'
	IF ( (SELECT COUNT(*) FROM @environments) = 1 )
		SET @typeOfDeploy = ISNULL((SELECT TOP 1 CAST(MANDANT_ID AS VARCHAR(32)) +'_'+ ENVIRONMENT FROM @environments),@typeOfDeploy)
	  --write default deploy environments
	EXEC dbo.setCRENTDEVDEPLOYMENTDEFAULTS @type = @typeOfDeploy, @subfolder = @type, @update_crent_schema_deployment = 0
	--EXEC dbo.setCRENTDEVDEPLOYMENTDEFAULTSUpdate @type = @typeOfDeploy, @subfolder = @type, @update_crent_schema_deployment = 0
     --Make Postscripts for 6.0
    EXEC dbo.DEPLOY_PRE_POST_SQL_SCRIPTS_BY_MANDENV_PK @mandID = @MANDANT_ID, @userEnv = @ENVIRONMENT_NAME, @patchesversion = @ENVIRONMENT_version, @subfolder = @type

	IF (@prodBigTransBatch = 1)
		BEGIN
			SET @deploymentBasePathFilename = ''+@deploymentBasePath+'deploy_big_trans.bat'
			SET @deploymentBasePathFileContents =
			'echo Big Translations files are going to be deployed
			echo ==============================================================================
			echo %TIME%

			for %%f in ("'+@deploymentBasePath+'post_trans6\*.bat") do (
				echo "%%f"
	
				echo %TIME%
				call "%%f"
				echo %TIME%
			)
			'
			EXEC dbo.WriteFile @fileName = @deploymentBasePathFilename, @fileContents = @deploymentBasePathFileContents			
		END 
END 
GO
/****** Object:  StoredProcedure [dbo].[DEPLOY_DB_ENVIRONMENTS]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
