CREATE PROCEDURE [dbo].[DEPLOY_DB_ENVIRONMENTS]( @environment VARCHAR(128) = 'ALL', @Deploy_Branch VARCHAR(128) = NULL,
@mandID INT = NULL, @userEnv NVARCHAR(128)= NULL, @envversion VARCHAR(16)= '6.0', @prodBigTransBatch BIT = 0, @tagversion VARCHAR(128) = '' )
AS SET NOCOUNT ON
	BEGIN
	--PRINT @environment  
	    DECLARE @environments TABLE (MANDANT_ENV_PK INT NULL, MANDANT_ID INT NOT NULL, ENVIRONMENT VARCHAR(128) NOT NULL)		
		--SELECT * FROM dbo.DEPLOYMENT_versionS
		IF (ISNULL(@tagversion,'') <> '' OR ISNULL(@Deploy_Branch,'') <> '') --Aufruf von Gitlab
		begin
		
		IF (ISNULL(@Deploy_Branch,'') ='') --TSE 20.04.21 Deploy_branch aus Tagversion erstellen
		  BEGIN
			SET @Deploy_Branch = @tagversion
			SELECT @Deploy_Branch =  REPLACE(REPLACE(ISNULL(@Deploy_Branch,''),'version_','release-'),'_','.')
			SELECT @Deploy_Branch = LEFT(@Deploy_Branch,dbo.LastIndexOf(@Deploy_Branch,'.'))			
		  END
		
		INSERT INTO dbo.DEPLOYMENT_versionS
		        SELECT REPLACE(REPLACE(ISNULL(@tagversion,''),'version_',''),'_','.'), GETDATE(), ISNULL(@Deploy_Branch,'')

		end
		INSERT INTO @environments
			SELECT PK, mandant_id, CASE WHEN type ='DEFAULT' THEN 'LIVE'
				WHEN databaseName LIKE 'ACC_%' THEN 'ACC'
				WHEN databaseName LIKE 'KOPIE_%' THEN 'ACC' ELSE type END[env]
			FROM MANDANT_DB_ENVIRONMENT ME WHERE me.version = @envversion AND ME.mandant_id IN (SELECT id FROM dbo.Mandant)
		IF (@mandID IS NOT NULL AND @userEnv IS NULL)
			DELETE FROM @environments WHERE MANDANT_ID NOT IN (@mandID) 
		ELSE IF (@mandID IS NULL AND @userEnv IS NOT NULL)
			BEGIN 
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@userEnv)
			END 
		ELSE IF (@mandID IS NOT NULL AND @userEnv IS NOT NULL)
			BEGIN
				DELETE FROM @environments WHERE MANDANT_ID NOT IN (@mandID)  
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@userEnv)
			END 
			--SELECT * FROM @environments
			--SELECT * FROM  [dbo].[BLACKLIST_MANDANT_DB_ENVIRONMENT]
	--Blacklist entfernen		
	DELETE FROM @environments WHERE MANDANT_ENV_PK IN (SELECT MANDANT_ENVIRONMENT_PK FROM [dbo].[BLACKLIST_MANDANT_DB_ENVIRONMENT])
	
	/* declare variables */
	DECLARE @mandant_id INT
	DECLARE @mandant_env VARCHAR(128)
	DECLARE @mandant_env_pk INT
	DECLARE @cmds VARCHAR(1024)=''
	DECLARE @COMPARE_DATEN_STATIC_DATA_USER_EXCLUDED_FILENAME VARCHAR(1024)='\\ku-fs01.kunden.local\deployment\Schema Compare\user_excluded.scpf'  
	DECLARE @tab TABLE(cmdRes VARCHAR(MAX) NULL)
	SET @cmds = 'RD /S /Q "\\ku-fs01.kunden.local\deployment\Schema Compare\"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds 
	SET @cmds = 'RD /S /Q "\\ku-fs01.kunden.local\deployment\Data Compare\"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds 

	SET @cmds = 'RD /S /Q "\\ku-fs01.kunden.local\deployment\advance_trans_deployment\"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds 

	SET @cmds = 'DEL /S /Q "\\ku-fs01.kunden.local\deployment\*.bat"'
	INSERT INTO @tab
	EXECUTE Master.dbo.xp_CmdShell @cmds 

	DECLARE @batchfileForTransContents VARCHAR(MAX)= ''
	DECLARE @batchfileNameForTransContents VARCHAR(MAX)= ''
	DECLARE @serverConnections XML = NULL
	DECLARE @tsql NVARCHAR(MAX) = ''

	--deploy tsql advance translations
	DECLARE @batchFileTranslations NVARCHAR(MAX) = dbo.GET_ADVANCE_DEPLOY_TRANS_BATCH()
	EXEC dbo.WriteFile @fileName = '\\ku-fs01.kunden.local\deployment\advance_trans_deployment\deploy.bat', @fileContents = @batchFileTranslations -- nvarchar(max)
	
	DECLARE cursor_environments CURSOR FOR SELECT MANDANT_ENV_PK, MANDANT_ID , ENVIRONMENT FROM @environments

	OPEN cursor_environments
	FETCH NEXT FROM cursor_environments INTO @mandant_env_pk, @mandant_id, @mandant_env
	WHILE @@FETCH_STATUS = 0
	BEGIN
		--PRINT @mandant_id
		--PRINT @mandant_env
		 
			IF((SELECT COUNT(*) FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @mandant_id AND version = @envversion)>=2 OR ( @mandant_id IN (98,441) AND @envversion in ('6.0') ) 
			   OR ((SELECT  COUNT(*) FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @mandant_id AND version in ('6.0','MASTER') 
			   AND type IN ('ACC','DEFAULT'))=1) ) --oder der Kunde hat mit 6.0 angefangen zu arbeiten und mandant darf keine Archiv DB haben
				BEGIN 
					--PRINT @mandant_id
					--PRINT @mandant_env_pk
					--IF (@mandant_id IN (410,409,635,446,562))
					IF (@mandant_id IN (SELECT DISTINCT mandantid FROM MANDANT_WEB_PRODUKTE WHERE ISNULL(ARCHIV_DB,'')<> ''))
					BEGIN  
						--PRINT @mandant_env_pk
						--PRINT @mandant_env
						--IF (@mandant_env = 'LIVE')
						--	SET @mandant_env = 'DEFAULT'
						EXEC dbo.GET_SQL_COMPARE_XML @MandantId = @mandant_id, @Environment = @mandant_env,  @compareType = 'SCHEMA', @writeFile = 1, @updateScript = 0 -- bit
						EXEC dbo.GET_SQL_COMPARE_XML @MandantId = @mandant_id, @Environment = @mandant_env,  @compareType = 'DATA', @writeFile = 1, @updateScript = 0 -- bit				
					END
					ELSE 
						EXEC dbo.GET_SQL_COMPARE_XML_BY_MAND_ENV_PK @MAND_ENV_PK = @mandant_env_pk
				END     
			ELSE
				BEGIN 
					EXEC dbo.GET_SQL_COMPARE_XML @MandantId = @mandant_id, @Environment = @mandant_env,  @compareType = 'SCHEMA', @writeFile = 1, @updateScript = 0 -- bit
					EXEC dbo.GET_SQL_COMPARE_XML @MandantId = @mandant_id, @Environment = @mandant_env,  @compareType = 'DATA', @writeFile = 1, @updateScript = 0 -- bit				
				END
			IF (@prodBigTransBatch = 1)
				BEGIN
					SET @batchfileForTransContents = dbo.DEPLOY_TRANSLATIONS_BY_PK(@mandant_env_pk,'STATIC_DATA_TO_CLIENT')
					SET @batchfileNameForTransContents = '\\ku-fs01.kunden.local\deployment\post_trans6\trans_'+CAST(@mandant_env_pk AS VARCHAR(32))+'_'+CAST(@mandant_id AS VARCHAR(32))+'_'+@mandant_env+'.bat'
					--EXEC dbo.longPrintingString @printigString = @t -- nvarchar(max)
					--PRINT LEN(@batchfileForTransContents)
					IF(@batchfileForTransContents <> '' AND LEN(@batchfileForTransContents) > 1)
						EXEC dbo.WriteFile @fileName = @batchfileNameForTransContents, @fileContents = @batchfileForTransContents                 
					SET @batchfileForTransContents = ''/**/					
				END   
		-- postscripst für translations
		
		 IF(dbo.GET_DEPLOYMENT_LINKED_SERVER_CONNECTION_BY_PK(@mandant_env_pk,@envversion)<>'')
			BEGIN
				 SET @serverConnections = dbo.GET_DEPLOYMENT_LINKED_SERVER_CONNECTION_BY_PK(@mandant_env_pk,@envversion)
				 SET @tsql  = 'DECLARE @connections XML = '''+ dbo.RenderXMLToString(@serverConnections)
												+''''+CHAR(13)+
							  'DECLARE @patchesTSQL XML = ''<TSQL>'+ CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), dbo.GET_PRE_POST_CRENT_SQLSCRIPTS(@envversion)), 1) +'</TSQL>'
												+''''+CHAR(13)+--
												+'EXEC dbo.DEPLOY_TRANSLATIONS_ON_REMOTE_LINKED_SERVER'+CHAR(13)
												+'@LINKED_SERVERS_DATA_CONNECTION = @connections'+CHAR(13)
												+' /*'+CHAR(13)
												+'EXEC dbo.DEPLOY_SQL_ON_REMOTE_LINKED_SERVER'+CHAR(13)
												+'@LINKED_SERVERS_DATA_CONNECTION = @connections, '+CHAR(13)
												+'@SQL_INSTRUCTIONS=@patchesTSQL,@TSQL_PARSE=1*/'
				 SET @batchfileNameForTransContents = '\\ku-fs01.kunden.local\deployment\advance_trans_deployment\tsql_'+CAST(@mandant_env_pk AS VARCHAR(32))+'_'+CAST(@mandant_id AS VARCHAR(32))+'_'+@mandant_env+'.sql'
				 EXEC dbo.WriteFile @fileName = @batchfileNameForTransContents, @fileContents = @tsql				           
			END
		FETCH NEXT FROM cursor_environments INTO @mandant_env_pk, @mandant_id, @mandant_env
	END

	CLOSE cursor_environments
	DEALLOCATE cursor_environments

	DECLARE @typeOfDeploy VARCHAR(32) = 'all'
	IF ( (SELECT COUNT(*) FROM @environments) = 1 )
		SET @typeOfDeploy = ISNULL((SELECT TOP 1 CAST(MANDANT_ID AS VARCHAR(32)) +'_'+ ENVIRONMENT FROM @environments),@typeOfDeploy)
	  --write default deploy environments
	 
	  EXEC dbo.setCRENTDEVDEPLOYMENTDEFAULTS @type = @typeOfDeploy, @envversion = @envversion
     --Make Postscripts for 6.0
     EXEC dbo.DEPLOY_PRE_POST_SQL_SCRIPTS_BY_MANDENV_PK @mandID = @mandID, @userEnv = @userEnv, @patchesversion = @envversion

	 IF (@prodBigTransBatch = 1)
		BEGIN
			EXEC dbo.WriteFile @fileName = '\\ku-fs01.kunden.local\deployment\deploy_big_trans.bat', @fileContents = 
			'echo Big Translations files are going to be deployed
			echo ==============================================================================
			echo %TIME%

			for %%f in ("\\ku-fs01.kunden.local\deployment\post_trans6\*.bat") do (
				echo "%%f"
	
				echo %TIME%
				call "%%f"
				echo %TIME%
			)
			'
							
		END 
END 
GO
/****** Object:  StoredProcedure [dbo].[DEPLOY_PRE_POST_SQL_SCRIPTS]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE	[dbo].[DEPLOY_PRE_POST_SQL_SCRIPTS](@mandID INT = NULL, @userEnv NVARCHAR(128)= NULL, @patchesversion VARCHAR(16)= '6.0' )
AS
	BEGIN
		IF (@userEnv = 'DEFAULT') SET @userEnv='LIVE'
	    DECLARE @environments TABLE (MANDANT_ID INT NOT NULL, ENVIRONMENT VARCHAR(128) NOT NULL)
		IF (@mandID IS NULL AND @userEnv IS NULL) 
			INSERT INTO @environments
				SELECT mandant_id, CASE WHEN type ='DEFAULT' THEN 'LIVE'
					WHEN databaseName LIKE 'ACC_%' THEN 'ACC'
					WHEN databaseName LIKE 'KOPIE_%' THEN 'ACC' ELSE type END[env]
				FROM MANDANT_DB_ENVIRONMENT ME WHERE me.version = @patchesversion AND ME.mandant_id IN (SELECT id FROM dbo.Mandant)
		ELSE IF (@mandID IS NOT NULL AND @userEnv IS NULL) 
			INSERT INTO @environments
				SELECT @mandID, 'ACC'
					UNION ALL
				SELECT @mandID, 'LIVE'
		ELSE IF (@mandID IS NOT NULL AND @userEnv IS NOT NULL) 
			INSERT INTO @environments
				SELECT @mandID, @userEnv
		ELSE IF (@mandID IS NOT NULL AND @userEnv IS NOT NULL)
			BEGIN
				DELETE FROM @environments WHERE MANDANT_ID NOT IN (@mandID)  
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@userEnv)
			END 
	    ELSE RETURN
 
 SELECT * FROM @environments

		DECLARE @mandant_id INT
		DECLARE @env VARCHAR(128)
		DECLARE @RAWDATA VARCHAR(1024) = ''
		DECLARE @HOST VARCHAR(255) = ''
		DECLARE @INSTANCE VARCHAR(255) = ''		
		DECLARE @DB VARCHAR(255) = ''
		DECLARE @DB_USER VARCHAR(128) = ''
		DECLARE @DB_USER_PW NVARCHAR(128) = ''
		DECLARE @PORT VARCHAR(15) = NULL 
		DECLARE cursor_name CURSOR FAST_FORWARD READ_ONLY FOR SELECT MANDANT_ID, ENVIRONMENT FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE TYPE = 'SCHEMA' AND CAST(MANDANT_ID AS VARCHAR(32))+ENVIRONMENT IN (SELECT CAST(MANDANT_ID AS VARCHAR(32))+ENVIRONMENT FROM @environments)
		DECLARE @TODBBATINSTRUCTIONS NVARCHAR(MAX) = '
			@Echo Off

			echo Patches fuer Kunden
			echo ==============================================================================
			echo %TIME%
		
		'
		DECLARE @FileInputPatchesPath NVARCHAR(MAX) = '\\ku-fs01.kunden.local\deployment\patches'+REPLACE(@patchesversion,'.','_')+'\'
		--DECLARE @cmd AS VARCHAR(MAX) = 'DEL "'+@FileInputPatchesPath+'"'
		DECLARE @cmd VARCHAR(255)
		DECLARE @tab TABLE(cmdRes VARCHAR(MAX) NULL)
		SET @cmd = 'RD /S /Q "'+@FileInputPatchesPath+'"'
		INSERT INTO @tab
			EXECUTE Master.dbo.xp_CmdShell @cmd 
		DECLARE @FileInputPatches NVARCHAR(MAX) = @FileInputPatchesPath+'patches.sql'
		DECLARE @FileInputPatchesResult NVARCHAR(MAX) = @FileInputPatchesPath+'resultLog'
		DECLARE @FileInputPatchesBatch NVARCHAR(MAX) = @FileInputPatchesPath+'exec_patches.bat'
		DECLARE @SQLPATCHES NVARCHAR(MAX) = dbo.GET_PRE_POST_CRENT_SQLSCRIPTS(@patchesversion)
		EXEC dbo.WriteFile @fileName = @FileInputPatches, @fileContents = @SQLPATCHES
		--EXEC dbo.WriteFile @fileName = @FileInputPatchesResult, @fileContents = N''

		OPEN cursor_name

		FETCH NEXT FROM cursor_name INTO @mandant_id,@env

		WHILE @@FETCH_STATUS = 0
		BEGIN
    
			SELECT @RAWDATA=RAWDATA,@HOST=HOST,@INSTANCE=INSTANCE,@DB=DB,@DB_USER=DB_USER,@DB_USER_PW=DB_USER_PW,
				   @PORT=PORT FROM dbo.GET_XML_DATACOMPARE_CREDENTIALS(@mandant_id,@env)

			SET @TODBBATINSTRUCTIONS += '
						SET TOServer='+@RAWDATA+'
						SET TOServerUser='+dbo.GET_BATCH_ESCAPED_PWD(@DB_USER)+' 
						SET TOServerPW='+dbo.GET_BATCH_ESCAPED_PWD(@DB_USER_PW)+'
						SET TODB='+@DB+'
						SET FileInputPatches="'+@FileInputPatches+'"
						SET FileInputPatchesResultSpecificClient='+REPLACE(REPLACE(@RAWDATA,'\','_'),',','_')+'.'+@DB+'
						SET FileInputPatchesResult="'+@FileInputPatchesResult+'.log'+'"
 			
						SET GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %FileInputPatches% >> %FileInputPatchesResult%"
						echo %GLOBALLOGMESSAGE% 
						ECHO LOGS RESULTED FROM %FileInputPatchesResultSpecificClient% >> %FileInputPatchesResult%
						sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %FileInputPatches% >> %FileInputPatchesResult%
						ECHO END OF LOGS RESULTED FROM: %FileInputPatchesResultSpecificClient% >> %FileInputPatchesResult%
				        ECHO ____________________________________________________________________ >> %FileInputPatchesResult%
				        ECHO. >> %FileInputPatchesResult%
				        ECHO. >> %FileInputPatchesResult%
		'

		/*
		PRINT '-----------------------: '
		PRINT @RAWDATA
		PRINT @HOST
		--PRINT @INSTANCE
		PRINT @DB
		PRINT @DB_USER
		PRINT @DB_USER_PW
		PRINT '@mandant_id: '+CAST(@mandant_id AS VARCHAR(32))
		PRINT '-----------------------: 

		'*/
			FETCH NEXT FROM cursor_name INTO @mandant_id,@env
		END

		CLOSE cursor_name
		DEALLOCATE cursor_name	 
		--PRINT @TODBBATINSTRUCTIONS
 		EXEC dbo.WriteFile @fileName = @FileInputPatchesBatch, @fileContents = @TODBBATINSTRUCTIONS
 
	END
GO
/****** Object:  StoredProcedure [dbo].[DEPLOY_PRE_POST_SQL_SCRIPTS_BY_MANDENV_PK]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[DEPLOY_PRE_POST_SQL_SCRIPTS_BY_MANDENV_PK](@mandID INT = NULL, @userEnv NVARCHAR(128)= NULL, @patchesversion VARCHAR(16)= '6.0', @subfolder NVARCHAR(255)='' )
AS
	BEGIN
		SET @subfolder = ISNULL(@subfolder,'')
		DECLARE @deploymentBasePath NVARCHAR(2048) = '\\ku-fs01.kunden.local\deployment\'+@subfolder+'\'
		IF (@subfolder = '')
			SET  @deploymentBasePath  = '\\ku-fs01.kunden.local\deployment\'
	    DECLARE @environments TABLE (MANDANT_ENV_PK INT NULL, MANDANT_ID INT NOT NULL, ENVIRONMENT VARCHAR(128) NOT NULL)
		
		INSERT INTO @environments
			SELECT PK, mandant_id, CASE WHEN type ='DEFAULT' THEN 'LIVE'
				WHEN databaseName LIKE 'ACC_%' THEN 'ACC'
				WHEN databaseName LIKE 'KOPIE_%' THEN 'ACC' ELSE type END[env]
			FROM MANDANT_DB_ENVIRONMENT ME WHERE me.version = @patchesversion AND ME.mandant_id IN (SELECT id FROM dbo.Mandant)
		IF (@mandID IS NOT NULL AND @userEnv IS NULL)
			DELETE FROM @environments WHERE MANDANT_ID NOT IN (@mandID) 
		ELSE IF (@mandID IS NULL AND @userEnv IS NOT NULL)
			BEGIN 
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@userEnv)
			END 
		ELSE IF (@mandID IS NOT NULL AND @userEnv IS NOT NULL)
			BEGIN
				DELETE FROM @environments WHERE MANDANT_ID NOT IN (@mandID)  
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@userEnv)
			END 
	--Blacklist entfernen		
	DELETE FROM @environments WHERE MANDANT_ENV_PK IN (SELECT MANDANT_ENVIRONMENT_PK FROM [dbo].[BLACKLIST_MANDANT_DB_ENVIRONMENT])
	
  
		DECLARE @mandant_id INT
		DECLARE @mandant_id_pk INT
		DECLARE @env VARCHAR(128)
		DECLARE @RAWDATA VARCHAR(1024) = ''
		DECLARE @HOST VARCHAR(255) = ''
		DECLARE @INSTANCE VARCHAR(255) = ''		
		DECLARE @DB VARCHAR(255) = ''
		DECLARE @DB_USER VARCHAR(128) = ''
		DECLARE @DB_USER_PW NVARCHAR(128) = ''
		DECLARE @PORT VARCHAR(15) = NULL 
		DECLARE cursor_name CURSOR FAST_FORWARD READ_ONLY FOR 
			SELECT pk, mandant_id, type  --
			FROM dbo.MANDANT_DB_ENVIRONMENT WHERE  PK IN (SELECT MANDANT_ENV_PK FROM @environments) AND  version = @patchesversion AND ISNULL(databaseIp,'') <> '' AND 
								ISNULL(databaseName,'') <> '' AND ISNULL(databaseUser,'')<>''
							 
		DECLARE @TODBBATINSTRUCTIONS NVARCHAR(MAX) = '
			@Echo Off

			echo Patches fuer Kunden
			echo ==============================================================================
			echo %TIME%
		
		'
		DECLARE @FileInputPatchesPath NVARCHAR(MAX) = @deploymentBasePath+'patches'+REPLACE(@patchesversion,'.','_')+'\'
		--DECLARE @cmd AS VARCHAR(MAX) = 'DEL "'+@FileInputPatchesPath+'"'
		DECLARE @cmd VARCHAR(255)
		DECLARE @tab TABLE(cmdRes VARCHAR(MAX) NULL)
		SET @cmd = 'RD /S /Q "'+@FileInputPatchesPath+'"'
		INSERT INTO @tab
			EXECUTE Master.dbo.xp_CmdShell @cmd 
		DECLARE @FileInputPatches NVARCHAR(MAX) = @FileInputPatchesPath+'patches.sql'
		DECLARE @FileInputPatchesResult NVARCHAR(MAX) = @FileInputPatchesPath+'resultLog'
		DECLARE @FileInputPatchesBatch NVARCHAR(MAX) = @FileInputPatchesPath+'exec_patches.bat'
		DECLARE @SQLPATCHES NVARCHAR(MAX) = dbo.GET_PRE_POST_CRENT_SQLSCRIPTS(@patchesversion)
		EXEC dbo.WriteFile @fileName = @FileInputPatches, @fileContents = @SQLPATCHES
		--EXEC dbo.WriteFile @fileName = @FileInputPatchesResult, @fileContents = N''

		OPEN cursor_name

		FETCH NEXT FROM cursor_name INTO @mandant_id_pk,@mandant_id,@env

		WHILE @@FETCH_STATUS = 0
		BEGIN
			IF EXISTS(SELECT * FROM dbo.GET_XML_DATACOMPARE_CREDENTIALS(@mandant_id,@env))
				SELECT @RAWDATA=RAWDATA,@HOST=HOST,@INSTANCE=INSTANCE,@DB=DB,@DB_USER=DB_USER,@DB_USER_PW=DB_USER_PW,
				   @PORT=PORT FROM dbo.GET_XML_DATACOMPARE_CREDENTIALS(@mandant_id,@env)
			ELSE 
	IF (EXISTS (SELECT * FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE PK = @mandant_id_pk and version = @patchesversion AND ISNULL(databaseIp,'') <> '' AND ISNULL(databaseName,'')<>'' AND ISNULL(databaseUser,'')<>''))
		BEGIN 
			SELECT TOP 1 @DB=ISNULL(databaseName,''), @DB_USER=ISNULL(databaseUser,''), @DB_USER_PW=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
			@RAWDATA=ISNULL(databaseIp,'')+
			   CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END + 
				CASE WHEN dbo.isClientExtern(mandant_id)=1 AND ISNUMERIC(databasePort)=1 /*intern extern unterschied*/  THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
				 
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE PK = @mandant_id_pk and version = @patchesversion 
		END 

			SET @TODBBATINSTRUCTIONS += '
						SET TOServer='+@RAWDATA+'
						SET TOServerUser='+dbo.GET_BATCH_ESCAPED_PWD(@DB_USER)+'
						SET TOServerPW='+dbo.GET_BATCH_ESCAPED_PWD(@DB_USER_PW)+'
						SET TODB='+@DB+'
						SET FileInputPatches="'+@FileInputPatches+'"
						SET FileInputPatchesResult="'+@FileInputPatchesResult+'.log'+'"
 						SET FileInputPatchesResultSpecificClient="'+@FileInputPatchesResult+''+REPLACE(REPLACE(@RAWDATA,'\','_'),',','_')+'.'+@DB+'.log'+'"

						SET GLOBALLOGMESSAGE=Calling SQLCMD: "sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %FileInputPatches% >> %FileInputPatchesResult%"
						echo %GLOBALLOGMESSAGE% 
						ECHO LOGS RESULTED FROM %FileInputPatchesResultSpecificClient% >> %FileInputPatchesResult%
						sqlcmd -S %TOServer% -U %TOServerUser% -P %TOServerPW% -d %TODB% -i %FileInputPatches% -o %FileInputPatchesResultSpecificClient%
						type %FileInputPatchesResultSpecificClient% >> %FileInputPatchesResult%
						ECHO END OF LOGS RESULTED FROM: %FileInputPatchesResultSpecificClient% >> %FileInputPatchesResult%
				        ECHO ____________________________________________________________________ >> %FileInputPatchesResult%
				        ECHO. >> %FileInputPatchesResult%
				        ECHO. >> %FileInputPatchesResult%
		'

		/*
		PRINT '-----------------------: '
		PRINT @RAWDATA
		PRINT @HOST
		--PRINT @INSTANCE
		PRINT @DB
		PRINT @DB_USER
		PRINT @DB_USER_PW
		PRINT '@mandant_id: '+CAST(@mandant_id AS VARCHAR(32))
		PRINT '-----------------------: 

		'*/
			FETCH NEXT FROM cursor_name INTO @mandant_id_pk,@mandant_id,@env
		END

		CLOSE cursor_name
		DEALLOCATE cursor_name	 
		--PRINT @TODBBATINSTRUCTIONS
 		EXEC dbo.WriteFile @fileName = @FileInputPatchesBatch, @fileContents = @TODBBATINSTRUCTIONS
 
	END
GO
/****** Object:  StoredProcedure [dbo].[EXEC_SQL_ON_REMOTE_LINKED_SERVER]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
 
CREATE PROCEDURE [dbo].[EXEC_SQL_ON_REMOTE_LINKED_SERVER](@LINKED_SERVERS_DATA_CONNECTION XML = NULL, @SQL_INSTRUCTIONS XML = NULL, @SQL_INSTRUCTIONS_ENCRIPTED BIT = 1, @TSQL_PARSE BIT = NULL, @JUST_ON_MAIN_SERVER BIT = 1, @TMP_TABLE_NAME VARCHAR(512) = '', @tableReplacement BIT = 0, @TSQSuccess BIT = NULL OUTPUT) 
AS SET NOCOUNT ON	--Author José
	 DECLARE @TSQL NVARCHAR(MAX) = ''
	 DECLARE @TSQL_TOBE_EXECUTED NVARCHAR(MAX) = ''
	 DECLARE @INDIVIDUAL_TSQL_TOBE_EXECUTED NVARCHAR(MAX) = ''
	 DECLARE @LINKED_SERVER_NAME NVARCHAR(512) = ''
	 DECLARE @ServerName NVARCHAR(1024) = ''
	 DECLARE @DatabaseName NVARCHAR(128) = ''
	 DECLARE @DatabaseNameOrig NVARCHAR(128) = ''
	 DECLARE @Username NVARCHAR(128) = ''
	 DECLARE @Password NVARCHAR(512) = ''
	 DECLARE @linkedServerCanBeUsed BIT
	 /*Usage 
			DECLARE @connections XML = '<server>
			  <LINKED_SERVER name="althoff_ACC">
				<ServerName>192.168.253.209</ServerName>
				<DatabaseName>ACC_althoff</DatabaseName>
				<Username>althacc</Username>
				<Password>%B#P#)]#)X%Zgt</Password>
				<TSQL>73656c656374202a2066726f6d2076657273696f6e</TSQL>
			  </LINKED_SERVER>
			</server>'
			DECLARE @executingTSQL XML = '<TSQL></TSQL>'
 
			EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER
			@LINKED_SERVERS_DATA_CONNECTION = @connections, 
			@SQL_INSTRUCTIONS=@executingTSQL

	 */ 

    IF (@LINKED_SERVERS_DATA_CONNECTION IS NULL OR (@LINKED_SERVERS_DATA_CONNECTION.exist('(/server/LINKED_SERVER[@name != "*"])[1]')) = 0) 
		RETURN 'XML LINKED_SERVERS_DATA_CONNECTIONS False format'

    IF (@SQL_INSTRUCTIONS IS NULL OR (@SQL_INSTRUCTIONS.exist('(TSQL/text())[1]')) = 0) 
		RETURN 'NO SQL were given'
    SET @TSQL_TOBE_EXECUTED = ISNULL(@SQL_INSTRUCTIONS.value('(TSQL/text())[1]','NVARCHAR(MAX)'),'') --must be binary 0x14655587 or 0984895479
	
	IF(@SQL_INSTRUCTIONS_ENCRIPTED = 1)
		BEGIN
			IF (SUBSTRING(@TSQL_TOBE_EXECUTED,1,1)='0' AND SUBSTRING(@TSQL_TOBE_EXECUTED,2,1)='x')
				SET @TSQL_TOBE_EXECUTED = SUBSTRING(@TSQL_TOBE_EXECUTED,3,LEN(@TSQL_TOBE_EXECUTED))
			SET @TSQL_TOBE_EXECUTED =  REPLACE(CONVERT(NVARCHAR(MAX), CONVERT(VARBINARY(MAX), @TSQL_TOBE_EXECUTED, 2)),'<?xml version="1.0" encoding="UTF-8"?>','') 				
			--PRINT @TSQL_TOBE_EXECUTED
		END
--PRINT @TSQL_TOBE_EXECUTED
	--RETURN
	IF (@TSQL_TOBE_EXECUTED <> '')
		BEGIN
			WHILE (@LINKED_SERVERS_DATA_CONNECTION.exist('(/server/LINKED_SERVER[@name != "*"])[1]')) = 1
				BEGIN 
					SET @linkedServerCanBeUsed = NULL
					SET @LINKED_SERVER_NAME = ISNULL(@LINKED_SERVERS_DATA_CONNECTION.value('(/server/LINKED_SERVER/@name)[1]','NVARCHAR(512)'),'') 
					SET @ServerName = ISNULL(@LINKED_SERVERS_DATA_CONNECTION.value('(/server/LINKED_SERVER/ServerName/text())[1]','NVARCHAR(1024)'),'') 
					SET @DatabaseName = ISNULL(@LINKED_SERVERS_DATA_CONNECTION.value('(/server/LINKED_SERVER/DatabaseName/text())[1]','NVARCHAR(128)'),'NO_DATABASE_SELECTED') 
					SET @DatabaseNameOrig = ISNULL(@DatabaseName,'NO_DATABASE_SELECTED') 
					IF (@JUST_ON_MAIN_SERVER = 1)
						SET @DatabaseName = NULL
					SET @Username = ISNULL(@LINKED_SERVERS_DATA_CONNECTION.value('(/server/LINKED_SERVER/Username/text())[1]','NVARCHAR(512)'),'') 
					SET @Password = ISNULL(@LINKED_SERVERS_DATA_CONNECTION.value('(/server/LINKED_SERVER/Password/text())[1]','NVARCHAR(512)'),'') 
					SET @INDIVIDUAL_TSQL_TOBE_EXECUTED = ISNULL(@LINKED_SERVERS_DATA_CONNECTION.value('(/server/LINKED_SERVER/TSQL/text())[1]','NVARCHAR(MAX)'),'') 
					IF (SUBSTRING(@INDIVIDUAL_TSQL_TOBE_EXECUTED,1,1)='0' AND SUBSTRING(@INDIVIDUAL_TSQL_TOBE_EXECUTED,2,1)='x')
						SET @INDIVIDUAL_TSQL_TOBE_EXECUTED = SUBSTRING(@INDIVIDUAL_TSQL_TOBE_EXECUTED,3,LEN(@INDIVIDUAL_TSQL_TOBE_EXECUTED))
					SET @INDIVIDUAL_TSQL_TOBE_EXECUTED =  REPLACE(CONVERT(NVARCHAR(MAX), CONVERT(VARBINARY(MAX), @INDIVIDUAL_TSQL_TOBE_EXECUTED, 2)),'<?xml version="1.0" encoding="UTF-8"?>','') 
					--PRINT @INDIVIDUAL_TSQL_TOBE_EXECUTED
					EXEC dbo.MANAGE_LINKED_SERVER @VIRTUAL_UNIQUE_SERVER_NAME = @LINKED_SERVER_NAME,                -- nvarchar(512)
						@SERVER_STRING = @ServerName,                             -- nvarchar(512)
						@SERVER_CATALOG = @DatabaseName,                            -- nvarchar(512)
						@SERVER_USER = @Username,                               -- nvarchar(128)
						@SERVER_USER_PW = @Password,                            -- nvarchar(128)
						@returnValidLoggedIn = @linkedServerCanBeUsed OUTPUT-- bit
					SET @TSQSuccess = 0 
					IF (@linkedServerCanBeUsed = 1) --if linked server OK (with all exists and credentials are valid) then deploy translations
						BEGIN 
							SET @DatabaseName = @DatabaseNameOrig
							IF (@INDIVIDUAL_TSQL_TOBE_EXECUTED<>'')
								BEGIN
									PRINT '-- Starting SQL QUERY at ['+dbo.GET_ISO_DATETIME(DEFAULT,'')+']' 
									IF (@TSQL_PARSE=1)
										SET @INDIVIDUAL_TSQL_TOBE_EXECUTED = REPLACE(@INDIVIDUAL_TSQL_TOBE_EXECUTED,'''','''''')
									SET @TSQL =  'EXECUTE ('''+@INDIVIDUAL_TSQL_TOBE_EXECUTED+''') AT ['+@LINKED_SERVER_NAME+']'
									BEGIN TRY		
										IF (@TMP_TABLE_NAME <> '' AND @tableReplacement = 0)
											BEGIN
												SET @TSQL = 'INSERT INTO '+@TMP_TABLE_NAME+' '+@TSQL_TOBE_EXECUTED						
													EXEC (@TSQL)										
											END															
										ELSE IF (@tableReplacement = 1) --end user defines where table to be put
											BEGIN
												SET @TSQL = @TSQL_TOBE_EXECUTED						
													EXEC (@TSQL)										
											END															
										ELSE 
											EXEC (@TSQL)
											PRINT '-- SQL QUERY success on  ['+@LINKED_SERVER_NAME+']'
										SET @TSQSuccess = 1
									END TRY
									BEGIN CATCH
										EXEC dbo.longPrintingString  @printigString = @TSQL-- nvarchar(max)	
										PRINT '-- SQL QUERY failed on  ['+@LINKED_SERVER_NAME+']'+CHAR(13)+ERROR_MESSAGE()					
									END CATCH
									PRINT '-- Ending SQL QUERY at ['+dbo.GET_ISO_DATETIME(DEFAULT,'')+'] on ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+']' 									    
								END								
							IF (@TSQL_PARSE=1)
								SET @TSQL_TOBE_EXECUTED = REPLACE(@TSQL_TOBE_EXECUTED,'''','''''')
							SET @TSQL =  'EXECUTE ('''+@TSQL_TOBE_EXECUTED+''') AT ['+@LINKED_SERVER_NAME+']'
							PRINT '-- Starting SQL QUERY at ['+dbo.GET_ISO_DATETIME(DEFAULT,'')+'] on ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+']'  
							BEGIN TRY
								IF (@TMP_TABLE_NAME <> '' AND  @tableReplacement = 0)
									BEGIN
										SET @TSQL = 'INSERT INTO '+@TMP_TABLE_NAME+' '+@TSQL_TOBE_EXECUTED						
											EXEC (@TSQL)										
									END
								ELSE IF (@tableReplacement = 1)
									BEGIN
										SET @TSQL = @TSQL_TOBE_EXECUTED						
											EXEC (@TSQL)										
									END     
								ELSE 
									EXEC (@TSQL)
								SET @TSQSuccess = 1
								PRINT '-- success QUERY on ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+']'  
							END TRY
							BEGIN CATCH
								EXEC dbo.longPrintingString  @printigString = @TSQL-- nvarchar(max)	
								PRINT '-- failed QUERY on ['+@LINKED_SERVER_NAME+'].['+@DatabaseName+']'+CHAR(13)+ERROR_MESSAGE()					
							END CATCH		
							PRINT '-- Ending SQL QUERY at ['+dbo.GET_ISO_DATETIME(DEFAULT,'')+']' 		    
						END

			
					SET @LINKED_SERVERS_DATA_CONNECTION.modify('delete (/server/LINKED_SERVER)[1]')  
				END 		    
		END
GO
/****** Object:  StoredProcedure [dbo].[EXTRACT_DB_USERS]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[EXTRACT_DB_USERS] (@PK INT = NULL )
AS
BEGIN  -- Authors Jose / Nicolas
	SET NOCOUNT ON
	IF (NOT EXISTS(SELECT * FROM dbo.nlCustomerDatabases WHERE PK = @PK))
		BEGIN
			SELECT 0[result], 'nlCustomerDatabases existiert nicht'[msg]
			RETURN
		END    
	CREATE TABLE #sourceInfo(USERS XML NULL)
	CREATE TABLE #validUser(usr VARCHAR(MAX) NULL)

	DECLARE @originLinkedServerNameConfig XML = dbo.getAdminLinkedServerNameBynlCustomerDatabasePK(@PK)
	DECLARE @sourceDBName VARCHAR(1024) = (SELECT DBNAME FROM dbo.nlCustomerDatabases WHERE PK = @PK)
 
	DECLARE @originLinkedServerName VARCHAR(1024) = (SELECT DBSVRINST FROM dbo.nlCustomerDatabases WHERE PK = @PK)
 
	DECLARE @executingTSQL XML = '' 
	DECLARE @executingTSQLVARCHAR NVARCHAR(MAX) = '
SELECT ISNULL((STUFF((SELECT( 	 
SELECT NAME AS ''*'' FOR XML PATH(''''), TYPE)
FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].sys.database_principals
WHERE TYPE NOT IN (''A'', ''G'', ''R'', ''X'') AND SID IS NOT NULL AND NAME NOT IN (''guest'',''sa'',''c*]'',''dbo'')
	  AND TYPE_DESC = ''SQL_USER'' FOR XML PATH(''username''),ROOT(''users'')),1,0,'''')),''<users/>'')' 
SET @executingTSQL = '<TSQL>'+ CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), @executingTSQLVARCHAR), 1) +'</TSQL>'
	--SELECT @executingTSQL
	DECLARE @TSQSuccess BIT 
	EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 1, @TMP_TABLE_NAME = '#sourceInfo', @TSQSuccess = @TSQSuccess OUTPUT

	DECLARE @users XML = ISNULL((SELECT (USERS) FROM #sourceInfo),NULL)
	DECLARE @user NVARCHAR(128)
	DECLARE @pw NVARCHAR(128)
	UPDATE dbo.nlCustomerDatabases SET DBUSERS=@users WHERE pk=@PK 

	--check valid users

	SET @executingTSQLVARCHAR = ' SELECT TOP 1 version FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.version' 
	DECLARE @originLinkedServerNameTesting NVARCHAR(512) = @originLinkedServerName+'_TESTING_CONNECTION'
	SET @executingTSQL = '<TSQL>'+ CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), @executingTSQLVARCHAR), 1) +'</TSQL>'
	UPDATE dbo.nlCustomerDatabases SET DB_LOGIN_CX9_LOGIC_SUCCESSFUL='' WHERE pk=@PK 
	SET @originLinkedServerNameConfig.modify('replace value of (/server/LINKED_SERVER/@name)[1] with sql:variable("@originLinkedServerNameTesting")')

	WHILE (@users.exist('(/users/username)[1]')=1)
		BEGIN
			 --#validUser
			SET @TSQSuccess = NULL
			SET @user = @users.value('(/users/username)[1]','NVARCHAR(128)')
			SET @pw = dbo.SEC_GetPWCOde(@user)
			SET @originLinkedServerNameConfig.modify('replace value of (/server/LINKED_SERVER/Username/text())[1] with sql:variable("@user")')
			SET @originLinkedServerNameConfig.modify('replace value of (/server/LINKED_SERVER/Password/text())[1] with sql:variable("@pw")')
			--SELECT @originLinkedServerNameConfig
 			EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 1, @TMP_TABLE_NAME = '#validUser', @TSQSuccess = @TSQSuccess OUTPUT
			IF (EXISTS (SELECT * FROM #validUser))
				UPDATE dbo.nlCustomerDatabases SET DB_LOGIN_CX9_LOGIC_SUCCESSFUL=ISNULL(DB_LOGIN_CX9_LOGIC_SUCCESSFUL,'')+@user+',' WHERE pk=@PK 
			SET @users.modify('delete (/users/username)[1]')
			DELETE FROM #validUser 
			BEGIN TRY
			EXEC master.dbo.sp_dropserver @server=@originLinkedServerNameTesting, @droplogins='droplogins' 
			END TRY
			BEGIN CATCH
				PRINT @originLinkedServerNameTesting +' wurde nicht erstellt'
			END CATCH           
		END

	--SELECT * FROM #sourceInfo
	--SELECT * FROM #validUser
	UPDATE dbo.nlCustomerDatabases SET DB_LOGIN_CX9_LOGIC_SUCCESSFUL=SUBSTRING(ISNULL(DB_LOGIN_CX9_LOGIC_SUCCESSFUL,''),1,dbo.LastIndexOf(ISNULL(DB_LOGIN_CX9_LOGIC_SUCCESSFUL,''),',')) WHERE pk=@PK 
	DROP TABLE #sourceInfo  
  
END
GO
/****** Object:  StoredProcedure [dbo].[EXTRACT_INFO_FROM_CLIENT]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
