CREATE PROCEDURE [dbo].[EXTRACT_INFO_FROM_CLIENT] (@MANDANT_ENV_PK INT = NULL, @MANDANT_ID INT = NULL, @ENVIRONMENT_NAME NVARCHAR(128)= NULL, @infoType NVARCHAR(64)='module' )
AS BEGIN --Author José 
   SET NOCOUNT ON
		DECLARE @jsonLinkedResponse NVARCHAR(MAX) = '' 
	    DECLARE @AUX_MANDANT_ENV_PK INT = NULL, @AUX_MANDANT_ID INT = NULL, @AUX_ENVIRONMENT VARCHAR(128)= NULL
	    DECLARE @environments TABLE (MANDANT_ENV_PK INT NULL, MANDANT_ID INT NULL, ENVIRONMENT VARCHAR(128) NULL)
		DECLARE @MENVPK INT 
		DECLARE @mand_module_table TABLE(MANDANT_ID INT NULL, MENVPK INT NULL, Modul VARCHAR(100) NULL, enabled VARCHAR(1) NULL)
		INSERT INTO @environments
			SELECT PK, mandant_id, CASE WHEN type ='DEFAULT' THEN 'LIVE'
				WHEN databaseName LIKE 'ACC_%' THEN 'ACC'
				WHEN databaseName LIKE 'KOPIE_%' THEN 'ACC' ELSE type END[env]
			FROM MANDANT_DB_ENVIRONMENT ME WHERE ME.mandant_id IN (SELECT id FROM dbo.Mandant WHERE dbo.isClientExtern(id)=0)
		IF (@MANDANT_ID IS NOT NULL AND @ENVIRONMENT_NAME IS NULL)
			DELETE FROM @environments WHERE MANDANT_ID NOT IN (@MANDANT_ID) 
		ELSE IF (@MANDANT_ID IS NULL AND @ENVIRONMENT_NAME IS NOT NULL)
			BEGIN 
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@ENVIRONMENT_NAME)
			END 
		ELSE IF (@MANDANT_ID IS NOT NULL AND @ENVIRONMENT_NAME IS NOT NULL)
			BEGIN
				DELETE FROM @environments WHERE MANDANT_ID NOT IN (@MANDANT_ID)  
				DELETE FROM @environments WHERE ENVIRONMENT NOT IN (@ENVIRONMENT_NAME)
			END 
		IF (EXISTS (SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE PK = @MANDANT_ENV_PK))
				DELETE FROM @environments WHERE MANDANT_ENV_PK <> @MANDANT_ENV_PK
		IF (EXISTS (SELECT * FROM @environments))
			BEGIN
				DECLARE cursor_info_extract_environments CURSOR  
				   FOR SELECT MANDANT_ENV_PK, MANDANT_ID, ENVIRONMENT FROM @environments 
				OPEN cursor_info_extract_environments  
				FETCH NEXT FROM cursor_info_extract_environments INTO @AUX_MANDANT_ENV_PK, @AUX_MANDANT_ID, @AUX_ENVIRONMENT
  
				WHILE @@FETCH_STATUS = 0  
				BEGIN  
					SET  @jsonLinkedResponse = '' --always restart it
					IF (@infoType = 'module')
						BEGIN
							/*PRINT @AUX_MANDANT_ENV_PK
							PRINT @AUX_MANDANT_ID
							PRINT @AUX_ENVIRONMENT      
							 */
							DELETE FROM @mand_module_table                      
							EXEC dbo.GET_DB_INFO_TSQL_FROM_REMOTE @MANDANT_ENVIRONMENT_PK = @AUX_MANDANT_ENV_PK, @TABLE='module', @FIELDS  = ' * ', @output = @jsonLinkedResponse OUT 
							--	PRINT @jsonLinkedResponse
							INSERT INTO @mand_module_table (MANDANT_ID, MENVPK, Modul, enabled) 
								SELECT  @AUX_MANDANT_ID, @AUX_MANDANT_ENV_PK,
										MAX(CASE WHEN name='Modul' THEN ISNULL(StringValue,'') ELSE '' END)[Modul],
										MAX(CASE WHEN name='enabled' THEN ISNULL(StringValue,'') ELSE '' END)[enabled]  
								FROM dbo.parseJSON(@jsonLinkedResponse) WHERE ValueType = 'string' GROUP BY parent_ID	/**/
							IF (EXISTS (SELECT * FROM @mand_module_table))
								BEGIN
									DELETE FROM [dbo].[MANDANT_MODULE_ALTE_STRUKTUR] WHERE [MANDANT_ID]= @AUX_MANDANT_ID AND MENVPK = @AUX_MANDANT_ENV_PK
										INSERT INTO [dbo].[MANDANT_MODULE_ALTE_STRUKTUR] (MANDANT_ID, MENVPK, Modul, enabled) 
											SELECT MANDANT_ID, MENVPK, Modul, enabled FROM @mand_module_table 
								END							
						END

					FETCH NEXT FROM cursor_info_extract_environments INTO @AUX_MANDANT_ENV_PK, @AUX_MANDANT_ID, @AUX_ENVIRONMENT
				END   
				CLOSE cursor_info_extract_environments
				DEALLOCATE cursor_info_extract_environments				
			END
END 
GO
/****** Object:  StoredProcedure [dbo].[FREESPACE_ON_ALL_ACCs]    Script Date: 25.01.2022 03:14:47 ******/
