CREATE PROCEDURE [dbo].[FREESPACE_ON_ALL_ACCs] 
AS
BEGIN  -- Authors José
	SET NOCOUNT ON
	DECLARE @mandantEnvironmentID INT
	DECLARE cursor_name CURSOR FAST_FORWARD READ_ONLY FOR SELECT PK FROM [BETHUNDER_JL].dbo.MANDANT_DB_ENVIRONMENT WHERE databaseName LIKE 'ACC_%' AND databaseIp = '192.168.253.209'
	OPEN cursor_name

	FETCH NEXT FROM cursor_name INTO @mandantEnvironmentID

	WHILE @@FETCH_STATUS = 0
	BEGIN
    
		EXEC [BETHUNDER_JL].dbo.FREESPACE_ON_DB_ACC @mandantID_PK = @mandantEnvironmentID 
		FETCH NEXT FROM cursor_name INTO @mandantEnvironmentID
	END

	CLOSE cursor_name
	DEALLOCATE cursor_name 
END
GO
/****** Object:  StoredProcedure [dbo].[FREESPACE_ON_DB_ACC]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[FREESPACE_ON_DB_ACC] (@mandantID_PK INT = NULL, @reportJustDeveloper BIT = 0, @reportHardware BIT = 0 , @reportAnMails VARCHAR(2048) = '')
AS
BEGIN  -- Author José
	SET NOCOUNT ON
	IF (NOT EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandantID_PK AND databaseName LIKE 'ACC_%' AND databaseIp='192.168.253.209'))
		BEGIN
			SELECT 0[result], 'MANDANT_ENVIRONMENT existiert nicht / nicht kalculierbar'[msg]
			RETURN
		END    
	--CREATE TABLE #sourceInfo(vor NVARCHAR(1024) NULL, nach NVARCHAR(1024) NULL, dbname NVARCHAR(128) NULL, dbname1 NVARCHAR(128) NULL, dbname2 NVARCHAR(128) NULL)
	CREATE TABLE #sourceInfo(id INT IDENTITY(1,1) not NULL, size INT NULL)
	DECLARE @MANDANT_ID INT = (SELECT mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandantID_PK)
	DECLARE @dbname VARCHAR(128) = (SELECT databaseName FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandantID_PK)
	DECLARE  @targetLinkedServerNameConfig XML = 
	'<server>
		<LINKED_SERVER name="KUNDEN253_209_ACC">
		<ServerName>192.168.253.209</ServerName>
		<DatabaseName></DatabaseName>
		<Username>sa</Username>
		<Password>chevy#2020</Password>
		</LINKED_SERVER>
	</server>'	 
	DECLARE @executingTSQL XML = '<TSQL>'+dbo.getTSQLCleanACCDB(@dbname)+'</TSQL>' 
	DECLARE @executingTSQLDBSize XML = '<TSQL> SELECT SUM((size * 8) / 1024)  FROM [KUNDEN253_209_ACC].['+@dbname+'].sys.database_files WHERE file_id IN (1,2)</TSQL>' 
	
	DECLARE @TSQSuccess BIT 
	EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQLDBSize, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TMP_TABLE_NAME = '#sourceInfo', @TSQSuccess = @TSQSuccess OUT
		IF (@TSQSuccess <> 1)
			BEGIN
				SELECT @TSQSuccess[result], 'Couldnot get db first size.'[msg]
				RETURN
			END
	EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, @TSQL_PARSE=1, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, /*@TMP_TABLE_NAME = '#sourceInfo',*/ @TSQSuccess = @TSQSuccess OUTPUT
    IF (@TSQSuccess <> 1)
		BEGIN
			SELECT @TSQSuccess[result], 'Couldnot execute db freespace process.'[msg]
			RETURN
		END  

	EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQLDBSize, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TMP_TABLE_NAME = '#sourceInfo', @TSQSuccess = @TSQSuccess OUT
		IF (@TSQSuccess <> 1)
			BEGIN
				SELECT @TSQSuccess[result], 'Couldnot get db second size.'[msg]
				RETURN
			END 
		ELSE IF (@TSQSuccess = 1)
			BEGIN
				DECLARE @dbSize1 FLOAT = NULL
				DECLARE @dbSize2 FLOAT = NULL
				DECLARE @dbSizeVorOptimierung VARCHAR(128) = NULL
				DECLARE @dbSizeNachOptimierung VARCHAR(128) = NULL
				SELECT @dbSize1 =  (SELECT size FROM #sourceInfo WHERE id = 1)
				SELECT @dbSize2 =  (SELECT size FROM #sourceInfo WHERE id = 2)
				SELECT @dbSizeVorOptimierung = CAST( (@dbSize1/1024.0) AS VARCHAR(128))+' (GB).'
				SELECT @dbSizeNachOptimierung = CAST( (@dbSize2/1024.0) AS VARCHAR(128))+' (GB).'
				SELECT @dbSizeVorOptimierung[vorher],@dbSizeNachOptimierung[nachher],@dbname[dbname]
				DECLARE  @mailContents NVARCHAR(MAX)= 'Guten Tag!, <br><br><b>Optimierung der Datenbank mit den Environmentdaten: </b><br><br>'+ REPLACE(dbo.GET_MANDANT_DB_ENVIRONMENT_DATA(@mandantID_PK),'"'+CHAR(13),'"<br>')+'<br><br>'+
				' vorher: <h3>'+@dbSizeVorOptimierung+'</h3>'+
				' naher: <h3>'+@dbSizeNachOptimierung+'</h3><br><br>'
				PRINT '' -- C-Rent Driver Ausgabe, damit er nicht anmeckert and send email 
				DECLARE @mailRecipients NVARCHAR(1024) = 'j.munoz@cx9.de' 
				IF (ISNULL(@reportAnMails,'')<>'')
					SET @mailRecipients +=';'+@reportAnMails 
				--, @reportAnMails VARCHAR(2048) = ''
				IF (@reportHardware = 1)
					BEGIN     
						SET @mailRecipients +=';hardware@cx9.de'
					END		
				EXEC dbo.CRENT_UPDATES_SEND_EMAIL @MANDANT_ID = @MANDANT_ID, -- int
				@subject = 'ACC_ DB-Optimierungsinfo', -- nvarchar(255)
				@recipients = @mailRecipients, -- varchar(1024)
				@contents = @mailContents, -- nvarchar(max)
				@resultMessage = NULL, @reportJustDeveloper = 0,@printStatusTimestamp = 0 -- nvarchar(2048) 
			END
	--SELECT * FROM #sourceInfo
	DROP TABLE #sourceInfo
END
GO
