					RETURN
				END
    
			SET @executingTSQL = '<TSQL>USE '+@sourceDBName+';'++dbo.GET_CODE_RESTORE_SYNONYME_AS_TABLES(@MANDANT_ID,2)+'</TSQL>'			INSERT INTO #ARCHIV_DB_TABLE_DEF ( TDEFINITONS ) 			  			EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TMP_TABLE_NAME = '', @TSQL_PARSE=1, @JUST_ON_MAIN_SERVER = 1, @TSQSuccess = @TSQLSuccess OUT
 
			IF (@TSQLSuccess <> 1)
				BEGIN
					SELECT 0,'Failed EXECUTION on ARCHIV_DB Linked Server executing function create_table_script'[msg]
					RETURN
				END	             
			SET @executingTSQL = '<TSQL>USE '+@sourceDBName+';'++dbo.GET_CODE_RESTORE_SYNONYME_AS_TABLES(@MANDANT_ID,0)+'</TSQL>'  			
			EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TMP_TABLE_NAME = '', @TSQL_PARSE=1, @JUST_ON_MAIN_SERVER = 1, @TSQSuccess = @TSQLSuccess OUT
 
			IF (@TSQLSuccess <> 1)
				BEGIN
					SELECT 0,'Failed EXECUTION on ARCHIV_DB Linked Server deleting function create_table_script'[msg]
					RETURN
				END
 
			SET @TSQLOUTPUT = ISNULL((SELECT TOP 1 TDEFINITONS FROM #ARCHIV_DB_TABLE_DEF),'')


			DROP TABLE #ARCHIV_DB_TABLE_DEF			
		END
END
