/****** Object:  StoredProcedure [dbo].[GET_DB_INFO_TSQL_FROM_REMOTE]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[GET_DB_INFO_TSQL_FROM_REMOTE] (@MANDANT_ENVIRONMENT_PK INT = 381, @TABLE NVARCHAR(255) = '', @FIELDS NVARCHAR(1024) = '*', @WHERECONDITION NVARCHAR(1024) = '', @output NVARCHAR(MAX) = '' OUT )
AS
BEGIN  -- Authors José
	 SET NOCOUNT ON
     SET CONCAT_NULL_YIELDS_NULL ON  
     SET NOCOUNT ON  
     SET ANSI_WARNINGS ON
     SET ANSI_PADDING ON
	 SET CONCAT_NULL_YIELDS_NULL ON    
	IF (NOT EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @MANDANT_ENVIRONMENT_PK) OR ISNULL(@TABLE,'')='' OR ISNULL(@FIELDS,'')='')
		BEGIN
			SET @output = '{"info":"Missing TSQL parameters"}' 
			RETURN
		END    
	CREATE TABLE #wishedRemoteInformation(data NVARCHAR(MAX) NULL) 
	DECLARE @originLinkedServerNameConfig XML = dbo.getAdminLinkedServerNameByPK(@MANDANT_ENVIRONMENT_PK)
	DECLARE @sourceDBName VARCHAR(1024) = (SELECT DatabaseName FROM dbo.getLinkedServerNameByPK(@MANDANT_ENVIRONMENT_PK))
 
	DECLARE @originLinkedServerName VARCHAR(1024) = (SELECT linkedServerName FROM dbo.getLinkedServerNameByPK(@MANDANT_ENVIRONMENT_PK))
DECLARE @executingTSQL XML = '<TSQL>'+ CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), CAST('
SET CONCAT_NULL_YIELDS_NULL ON  
SET NOCOUNT ON  
SET ANSI_WARNINGS ON
SET ANSI_PADDING ON
SET CONCAT_NULL_YIELDS_NULL ONBEGIN TRY	IF NOT EXISTS(SELECT TOP 1 COLUMN_NAME FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].INFORMATION_SCHEMA.columns WHERE TABLE_NAME = '''+@TABLE+''')		BEGIN			INSERT INTO #wishedRemoteInformation
			SELECT ''[]''			RETURN		END	DECLARE @wellFormedJSON NVARCHAR(MAX)=''''
	DECLARE @tsqlTableResultAsXML XML = NULL
	DECLARE @index INT = 1, @count INT
	DECLARE @TSQL NVARCHAR(512) = ''SELECT CAST ((SELECT '+@FIELDS+' FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.'+@TABLE+' '+@WHERECONDITION+' FOR XML AUTO) AS XML)''
	DECLARE @TABLE TABLE (RESULT XML NULL)
	INSERT INTO @TABLE 
		EXEC(@TSQL)
	IF EXISTS (SELECT * FROM @TABLE)
		BEGIN
			SELECT TOP 1 @tsqlTableResultAsXML = RESULT FROM @TABLE
		END
		
	--SELECT @tsqlTableResultAsXML = CAST ((SELECT '+@FIELDS+' FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.'+@TABLE+' '+@WHERECONDITION+' FOR XML AUTO) AS XML)
	WHILE (@tsqlTableResultAsXML.exist(''(/'+@originLinkedServerName+'.'+@sourceDBName+'.dbo.'+@TABLE+'[1])[1]'')) = 1
		BEGIN
			SET @count = @tsqlTableResultAsXML.query(''count(/'+@originLinkedServerName+'.'+@sourceDBName+'.dbo.'+@TABLE+'[1]/@*)'').value(''.'',''int'')
			SET @index =1
			SET @wellFormedJSON+=''{''
			WHILE @index <= @count 
				BEGIN
					SET @wellFormedJSON+=''"''+ISNULL(@tsqlTableResultAsXML.value(''local-name((/'+@originLinkedServerName+'.'+@sourceDBName+'.dbo.'+@TABLE+'[1]/@*[sql:variable("@index")])[1])'', ''varchar(max)''),''noattr''+@index)+''":"''+ ISNULL(@tsqlTableResultAsXML.value(''(/'+@originLinkedServerName+'.'+@sourceDBName+'.dbo.'+@TABLE+'[1]/@*[sql:variable("@index")])[1]'', ''varchar(max)''),''noval''+@index) +''",''
					SET @index = @index + 1
				END
			SET @wellFormedJSON+=''},''      
			SET @tsqlTableResultAsXML.modify(''delete (/'+@originLinkedServerName+'.'+@sourceDBName+'.dbo.'+@TABLE+'[1])[1]'')
		END
	  IF (LEN(@wellFormedJSON) > 2)
		BEGIN
			SET @wellFormedJSON = REPLACE(@wellFormedJSON,'',}'',''}'')
			SET @wellFormedJSON = ''[''+SUBSTRING(@wellFormedJSON,1,LEN(@wellFormedJSON)-1)+'']''		
		END  
	INSERT INTO #wishedRemoteInformation
	SELECT @wellFormedJSONEND TRYBEGIN CATCH	INSERT INTO #wishedRemoteInformation
	SELECT ''[]''END CATCH ' AS NVARCHAR(MAX)) ), 1) +'</TSQL>'  	DECLARE @mandant_id INT = (SELECT mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @MANDANT_ENVIRONMENT_PK)   	DECLARE @TSQSuccess BIT 	EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 1, @TMP_TABLE_NAME = '#wishedRemoteInformation', @TSQL_PARSE = 0, @tableReplacement = 1, @TSQSuccess = @TSQSuccess OUTPUT
 
 
	 IF EXISTS (SELECT * FROM #wishedRemoteInformation)
		SET @output = ISNULL((SELECT TOP 1 data FROM #wishedRemoteInformation),'[]')
	DROP TABLE #wishedRemoteInformation  
 END 
GO
/****** Object:  StoredProcedure [dbo].[GET_DB_INFO_TSQL_FROM_REMOTE_OLD]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
