CREATE PROCEDURE [dbo].[GET_DB_INFO_TSQL_FROM_REMOTE_OLD] (@MANDANT_ENVIRONMENT_PK INT = 381, @TABLE NVARCHAR(255) = '', @FIELDS NVARCHAR(1024) = '*', @WHERECONDITION NVARCHAR(1024) = '', @output NVARCHAR(MAX) = '' OUT )
AS
BEGIN  -- Authors José
	SET NOCOUNT ON
	IF (NOT EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @MANDANT_ENVIRONMENT_PK) OR ISNULL(@TABLE,'')='' OR ISNULL(@FIELDS,'')='')
		BEGIN
			SET @output = '{"info":"Missing TSQL parameters"}' 
			RETURN
		END    
	CREATE TABLE #wishedRemoteInformation(data NVARCHAR(MAX) NULL) 
	DECLARE @originLinkedServerNameConfig XML = dbo.getAdminLinkedServerNameByPK(@MANDANT_ENVIRONMENT_PK)
	DECLARE @sourceDBName VARCHAR(1024) = (SELECT DatabaseName FROM dbo.getLinkedServerNameByPK(@MANDANT_ENVIRONMENT_PK))
 
	DECLARE @originLinkedServerName VARCHAR(1024) = (SELECT linkedServerName FROM dbo.getLinkedServerNameByPK(@MANDANT_ENVIRONMENT_PK))
DECLARE @executingTSQL XML = '<TSQL>'+ CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), CAST('
DECLARE @fieldCounter INT = 1
DECLARE @DB_SPECIFIC_INFORMATION NVARCHAR(MAX)
SET @DB_SPECIFIC_INFORMATION = ISNULL(CAST ((SELECT '+@FIELDS+' FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.'+@TABLE+' '+@WHERECONDITION+' FOR XML AUTO  ) AS NVARCHAR(MAX)),'''') 
SET @DB_SPECIFIC_INFORMATION = REPLACE(@DB_SPECIFIC_INFORMATION,''<'',''{'')
SET @DB_SPECIFIC_INFORMATION = REPLACE(@DB_SPECIFIC_INFORMATION,''/>'',''},'')
SET @DB_SPECIFIC_INFORMATION = REPLACE(@DB_SPECIFIC_INFORMATION,'''+@originLinkedServerName+'.'+@sourceDBName+'.dbo.'+@TABLE+' '','''')
 
SELECT @DB_SPECIFIC_INFORMATION = REPLACE (@DB_SPECIFIC_INFORMATION, COLUMN_NAME,'',"''+COLUMN_NAME+''"'') FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].INFORMATION_SCHEMA.columns WHERE TABLE_NAME = '''+@TABLE+'''

SET @DB_SPECIFIC_INFORMATION = REPLACE(@DB_SPECIFIC_INFORMATION,''"="'',''":"'')
SET @DB_SPECIFIC_INFORMATION = SUBSTRING(@DB_SPECIFIC_INFORMATION,1,LEN(@DB_SPECIFIC_INFORMATION)-1) 
SET @DB_SPECIFIC_INFORMATION = ''[''+@DB_SPECIFIC_INFORMATION+'']''
SET @DB_SPECIFIC_INFORMATION = REPLACE(@DB_SPECIFIC_INFORMATION,''{,'',''{'')
INSERT INTO #wishedRemoteInformation
SELECT @DB_SPECIFIC_INFORMATION' AS NVARCHAR(MAX)) ), 1) +'</TSQL>'  	DECLARE @mandant_id INT = (SELECT mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @MANDANT_ENVIRONMENT_PK)   	DECLARE @TSQSuccess BIT 	EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 1, @TMP_TABLE_NAME = '#wishedRemoteInformation', @TSQL_PARSE = 0, @tableReplacement = 1, @TSQSuccess = @TSQSuccess OUTPUT
 
 
	 IF EXISTS (SELECT * FROM #wishedRemoteInformation)
		SET @output = ISNULL((SELECT TOP 1 data FROM #wishedRemoteInformation),'[]')
	DROP TABLE #wishedRemoteInformation  
 
END
GO
/****** Object:  StoredProcedure [dbo].[GET_SQL_COMPARE_XML]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[GET_SQL_COMPARE_XML]
	@MandantId INT, @AbasId INT = NULL,
	@ip VARCHAR(255) = '', @dbname VARCHAR(255) = '', @dbuser VARCHAR(512)='', @dbpassword NVARCHAR(512)='',
	@Environment VARCHAR(128)='LIVE', @compareType VARCHAR(128)='SCHEMA', @KUNDEDATAINDSEARCH VARCHAR(255)='',
	@ignoreExecutedXML BIT = 0, @writeFile BIT = 0, @updateScript BIT = 0, @writeOnSubfolder NVARCHAR(255)='', @execUpdate6 BIT = 0
AS
BEGIN
	SET NOCOUNT ON
    DECLARE @SCHEMA_COMPARE XML, @DATA_COMPARE XML, @RAW_DATA XML,  @ARCHIV_SCHEMA_COMPARE XML
	DECLARE @environmentXML NVARCHAR(MAX) = ''
	DECLARE @abfragenComplementLike VARCHAR(512) = ''
	DECLARE @AUSW_Abfragen_ParameterComplementLike VARCHAR(512) = ''
	DECLARE @AUSW_Abfragen_SummenComplementLike VARCHAR(512) = ''
	DECLARE @RIGHTS_LISTComplementLike VARCHAR(512) = ''
	DECLARE @ARCHIV_outputfileName VARCHAR(1024)

	IF (ISNULL(@KUNDEDATAINDSEARCH,'') <> '')
		BEGIN
			SET @abfragenComplementLike = 'OR Beschreibung LIKE ''%Individuell%'+@KUNDEDATAINDSEARCH+'%'''
			SET @AUSW_Abfragen_ParameterComplementLike = @abfragenComplementLike
			SET @AUSW_Abfragen_SummenComplementLike = @abfragenComplementLike
			SET @RIGHTS_LISTComplementLike = 'OR ISNULL(Kunde,'''') LIKE ''%'+@KUNDEDATAINDSEARCH+'%'''			
		END


	 
	-- TODO @Environment berücksichtigen
	IF(@Environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS))
	BEGIN
		RAISERROR (N'Environment ''%s'' does not exist or is empty.', 10, 1, @Environment)
		RETURN
	END
	IF(@compareType NOT IN ('DATA','SCHEMA'))
	BEGIN
		RAISERROR (N'Compare type ''%s'' does not exist or is empty.', 10, 1, @compareType)
		RETURN
	END    
	/*IF(@Environment NOT IN ('LIVE_SCHEMA_COMPARE','ACC_SCHEMA_COMPARE', 'ACC_DATA_COMPARE', 'LIVE_DATA_COMPARE'))
	BEGIN
		RAISERROR (N'Environment ''%s'' does not exist or is empty.', 10, 1, @Environment)
		RETURN
	END    */
	DECLARE @env NVARCHAR(128) = @Environment
	DECLARE @env_auxiliary NVARCHAR(128) = CASE WHEN @env = 'LIVE' THEN 'DEFAULT' ELSE @env END
	DECLARE @type NVARCHAR(128) = @compareType
      
	IF (@env <> 'LIVE' AND @env <> 'DEFAULT' AND EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@env))
		BEGIN
			SELECT TOP 1 @dbname=DB, @dbuser=DB_USER, @dbpassword=DB_USER_PW, 
			@ip=ISNULL(HOST,'')+				
				CASE WHEN ISNULL(INSTANCE,'')<>'' THEN '\'+INSTANCE ELSE '' END+
				CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(PORT)=1 /*intern extern unterschied*/  THEN ','+CAST(PORT AS VARCHAR(32)) ELSE '' END   --tsql port sintax				 
			FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@env ORDER BY version DESC	 
		END  				 
		--SELECT databasePort FROM dbo.Mandant
	-- TODO @Environment berücksichtigen
	IF( NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN
		RAISERROR (N'Mandant with id ''%d'' does not exist.', 10, 1, @MandantId)
		RETURN
	END
   
    DECLARE @outputfileName VARCHAR(1024) = dbo.getLocalNameDeploymentFileByName(@mandantId, @env_auxiliary,@type,@writeOnSubfolder)    
	IF (@ignoreExecutedXML = 0) AND EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @env AND TYPE = @type AND EXECUTED=1)
		BEGIN --PRINT 'sssssss'
			SELECT TOP 1 @RAW_DATA = DATA FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @env AND TYPE = @type AND EXECUTED=1
			IF (@TYPE = 'DATA' AND @updateScript = 1)
				BEGIN
					--PRINT CAST(@RAW_DATA AS NVARCHAR(MAX))
					SET @RAW_DATA.modify('delete /Project[1]/TableActions/value[position()=(last())]')
				END
				--SELECT @RAW_DATA
			SET @environmentXML = dbo.RenderXMLToString(@RAW_DATA)
			--IF (@execUpdate6 = 1 AND @type = 'SCHEMA')
			--	SET @environmentXML = REPLACE(@environmentXML,'crent_schema_deployment','crent_schema_update')
			IF (@type = 'SCHEMA')
				BEGIN
					SELECT TOP 1 @ARCHIV_SCHEMA_COMPARE= ARCHIV_SCHEMA_COMPARE FROM dbo.GET_ARCHIV_SQL_XMLSCHEMACOMPARE(@RAW_DATA,@mandantId,@env)					
					--SELECT * FROM dbo.GET_ARCHIV_SQL_XMLSCHEMACOMPARE(@RAW_DATA,@mandantId,@env)					
				END

			IF (@writeFile = 1)
				BEGIN 
					IF (@environmentXML <> '')
						EXEC dbo.WriteFile @fileName = @outputfileName, @fileContents = @environmentXML 
					IF (@ARCHIV_SCHEMA_COMPARE IS NOT NULL)
					 BEGIN
						IF (ISNULL(@dbname,'')='' AND @env = 'LIVE' AND EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@env))
							BEGIN
								SELECT TOP 1 @dbname=DB, @dbuser=DB_USER, @dbpassword=DB_USER_PW, 
								@ip=ISNULL(HOST,'')+				
									CASE WHEN ISNULL(INSTANCE,'')<>'' THEN '\'+INSTANCE ELSE '' END+
									CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(PORT)=1 /*intern extern unterschied*/  THEN ','+CAST(PORT AS VARCHAR(32)) ELSE '' END   --tsql port sintax				 
								FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@env ORDER BY version DESC	 
							END                     
						SET @ARCHIV_outputfileName = replace(@outputfileName,@dbname,'ARCHIVDB_'+@dbname)
						SET @environmentXML = dbo.RenderXMLToString(@ARCHIV_SCHEMA_COMPARE)
						--PRINT @dbname
						--PRINT @outputfileName
						--PRINT @ARCHIV_outputfileName
						EXEC dbo.WriteFile @fileName = @ARCHIV_outputfileName, @fileContents = @environmentXML			
					 END
					RETURN
				END
			IF (@environmentXML <> '')
				BEGIN
					EXEC dbo.longPrint @environmentXML
					RETURN
				END				
		END     
    SET @SCHEMA_COMPARE = dbo.GET_SQL_XMLCOMPARE('SCHEMA',DEFAULT,DEFAULT,DEFAULT,DEFAULT, @MandantId)
    SET @DATA_COMPARE = dbo.GET_SQL_XMLCOMPARE('DATA',@abfragenComplementLike, @AUSW_Abfragen_ParameterComplementLike, @RIGHTS_LISTComplementLike, @AUSW_Abfragen_SummenComplementLike,@MandantId)
 
	IF (@Environment IN ('LIVE', 'DEFAULT'))
	IF (EXISTS (SELECT * FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@env_auxiliary and version in ('6.0','MASTER')))
		BEGIN 
			SELECT TOP 1 @dbname=ISNULL(databaseName,''), @dbuser=ISNULL(databaseUser,''), @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
			@ip=ISNULL(databaseIp,'')+
			   CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END + 
				CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(databasePort)=1 /*intern extern unterschied*/  THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@env_auxiliary and version in ('6.0','MASTER')	 
		END 
		
	IF( @ip = '' )
	BEGIN
		RAISERROR (N'IP (and/or instance) for database of mandant with id ''%d'' is empty.', 10, 1, @MandantId)
		RETURN
	END
	IF( @dbname = '' )
	BEGIN
		RAISERROR (N'Name for database of mandant with id ''%d'' is empty.', 10, 1, @MandantId)
		RETURN
	END
	IF( @dbuser = '' )
	BEGIN
		RAISERROR (N'User for database of mandant with id ''%d'' is empty.', 10, 1, @MandantId)
		RETURN
	END
	IF (@Environment IN ('LIVE'))
		SET @dbpassword = dbo.SEC_GetPWCOde(@dbuser)

	-- Ersetzung von Platzhaltern
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/ServerName/text())[1] with sql:variable("@ip")')
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/DatabaseName/text())[1] with sql:variable("@dbname")')
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@dbuser")')
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@dbpassword")')

	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/ServerName/text())[1] with sql:variable("@ip")')
	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/DatabaseName/text())[1] with sql:variable("@dbname")')
	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@dbuser")')
	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@dbpassword")')
 

	IF (@type IN ('SCHEMA'))
		BEGIN
		/*[TYPE] -- SCHEMA | DATA [ENVIRONMENT]  -- ACC | LIVE*/
		SELECT TOP 1 @SCHEMA_COMPARE=SCHEMA_COMPARE, @ARCHIV_SCHEMA_COMPARE= ARCHIV_SCHEMA_COMPARE FROM dbo.GET_ARCHIV_SQL_XMLSCHEMACOMPARE(@RAW_DATA,@mandantId,@env)					
			SET @environmentXML = dbo.RenderXMLToString(@SCHEMA_COMPARE)
			EXEC dbo.PFLEGE_XML_MANDANT_ENVIRONMENT @mandantId = @mandantId, @AbasId = @AbasId, 
			@environment = @env, @type = @type, @data = @SCHEMA_COMPARE, @updateScript = @updateScript
		END
	IF (@type IN ('DATA'))
		BEGIN 
			IF (@updateScript = 1)
				SET @DATA_COMPARE.modify('delete /Project[1]/TableActions/value[position()=(last())]')
			--SELECT  @DATA_COMPARE         
			SET @environmentXML = dbo.RenderXMLToString(@DATA_COMPARE)
			EXEC dbo.PFLEGE_XML_MANDANT_ENVIRONMENT @mandantId = @mandantId, @AbasId = @AbasId, 
			@environment = @env, @type = @type, @data = @DATA_COMPARE, @updateScript = @updateScript
		END
	--IF (@execUpdate6 = 1 AND @type = 'SCHEMA')
	--	SET @environmentXML = REPLACE(@environmentXML,'crent_schema_deployment','crent_schema_update')		
    IF (@writeFile = 1)
		BEGIN 
			IF (@environmentXML <> '')EXEC dbo.WriteFile @fileName = @outputfileName, @fileContents = @environmentXML			
			IF (@ARCHIV_SCHEMA_COMPARE IS NOT NULL)
			 BEGIN
				SET @ARCHIV_outputfileName = replace(@outputfileName,@dbname,'ARCHIVDB_'+@dbname)
				SET @environmentXML = dbo.RenderXMLToString(@ARCHIV_SCHEMA_COMPARE)
				EXEC dbo.WriteFile @fileName = @ARCHIV_outputfileName, @fileContents = @environmentXML			
			 END
			RETURN
		END
	IF (@environmentXML <> '')EXEC dbo.longPrint @environmentXML
END
GO
/****** Object:  StoredProcedure [dbo].[GET_SQL_COMPARE_XML_BAK08012021]    Script Date: 25.01.2022 03:14:47 ******/
