CREATE PROCEDURE [dbo].[GET_SQL_COMPARE_XML_BAK08012021]
	@MandantId INT, @AbasId INT = NULL,
	@ip VARCHAR(255) = '', @dbname VARCHAR(255) = '', @dbuser VARCHAR(512)='', @dbpassword NVARCHAR(512)='',
	@Environment VARCHAR(128)='LIVE', @compareType VARCHAR(128)='SCHEMA', @KUNDEDATAINDSEARCH VARCHAR(255)='',
	@ignoreExecutedXML BIT = 0, @writeFile BIT = 0, @updateScript BIT = 0
AS
BEGIN
	SET NOCOUNT ON
    DECLARE @SCHEMA_COMPARE XML, @DATA_COMPARE XML, @RAW_DATA XML,  @ARCHIV_SCHEMA_COMPARE XML
	DECLARE @environmentXML NVARCHAR(MAX) = ''
	DECLARE @abfragenComplementLike VARCHAR(512) = ''
	DECLARE @AUSW_Abfragen_ParameterComplementLike VARCHAR(512) = ''
	DECLARE @AUSW_Abfragen_SummenComplementLike VARCHAR(512) = ''
	DECLARE @RIGHTS_LISTComplementLike VARCHAR(512) = ''
	DECLARE @ARCHIV_DB VARCHAR(255) = '' 
	DECLARE @ARCHIV_HOST VARCHAR(255) = '' 
	DECLARE @ARCHIV_INSTANCE VARCHAR(255) = '' 
	DECLARE @ARCHIV_DB_USER VARCHAR(255) = '' 
	DECLARE @ARCHIV_DB_USER_PW NVARCHAR(255) = '' 
	DECLARE @ARCHIV_PORT NVARCHAR(255) = '' 
	DECLARE @ARCHIV_IP NVARCHAR(1024) = '' 

	IF (ISNULL(@KUNDEDATAINDSEARCH,'') <> '')
		BEGIN
			SET @abfragenComplementLike = 'OR Beschreibung LIKE ''%Individuell%'+@KUNDEDATAINDSEARCH+'%'''
			SET @AUSW_Abfragen_ParameterComplementLike = @abfragenComplementLike
			SET @AUSW_Abfragen_SummenComplementLike = @abfragenComplementLike
			SET @RIGHTS_LISTComplementLike = 'OR ISNULL(Kunde,'''') LIKE ''%'+@KUNDEDATAINDSEARCH+'%'''			
		END


	 
	-- TODO @Environment berücksichtigen
	IF(@Environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS))
	BEGIN
		RAISERROR (N'Environment ''%s'' does not exist or is empty.', 10, 1, @Environment)
		RETURN
	END
	IF(@compareType NOT IN ('DATA','SCHEMA'))
	BEGIN
		RAISERROR (N'Compare type ''%s'' does not exist or is empty.', 10, 1, @compareType)
		RETURN
	END    
	/*IF(@Environment NOT IN ('LIVE_SCHEMA_COMPARE','ACC_SCHEMA_COMPARE', 'ACC_DATA_COMPARE', 'LIVE_DATA_COMPARE'))
	BEGIN
		RAISERROR (N'Environment ''%s'' does not exist or is empty.', 10, 1, @Environment)
		RETURN
	END    */
	DECLARE @env NVARCHAR(128) = @Environment
	DECLARE @env_auxiliary NVARCHAR(128) = CASE WHEN @env = 'LIVE' THEN 'DEFAULT' ELSE @env END
	DECLARE @type NVARCHAR(128) = @compareType
      
	IF (@env <> 'LIVE' AND @env <> 'DEFAULT' AND EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@env))
		BEGIN
			SELECT TOP 1 @dbname=DB, @dbuser=DB_USER, @dbpassword=DB_USER_PW, 
			@ip=ISNULL(HOST,'')+				
				CASE WHEN ISNULL(INSTANCE,'')<>'' THEN '\'+INSTANCE ELSE '' END+
				CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(PORT)=1 /*intern extern unterschied*/  THEN ','+CAST(PORT AS VARCHAR(32)) ELSE '' END   --tsql port sintax				 
			FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@env ORDER BY version DESC	 
		END  
		
	IF (EXISTS (SELECT PK FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@env))
		BEGIN
			SELECT TOP 1  @ARCHIV_DB = ISNULL(ARCHIV_DB, @ARCHIV_DB), 
			@ARCHIV_HOST = ISNULL(ARCHIV_HOST, @ARCHIV_HOST), 
			@ARCHIV_INSTANCE = ISNULL(ARCHIV_INSTANCE, @ARCHIV_INSTANCE), 
			@ARCHIV_DB_USER = ISNULL(ARCHIV_DB_USER, @ARCHIV_DB_USER), 
			@ARCHIV_DB_USER_PW = dbo.SEC_GetPWCOde(ARCHIV_DB_USER),
			@ARCHIV_PORT = ISNULL(ARCHIV_PORT, @ARCHIV_PORT),
			@ARCHIV_IP=ISNULL(ARCHIV_HOST,'')+				
				CASE WHEN ISNULL(ARCHIV_INSTANCE,'')<>'' THEN '\'+ARCHIV_INSTANCE ELSE '' END+
				CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(ARCHIV_PORT)=1    THEN ','+CAST(ARCHIV_PORT AS VARCHAR(32)) ELSE '' END   --tsql port sintax		
			FROM [dbo].[MANDANT_WEB_PRODUKTE] WHERE MandantId = @MandantId AND Environment=@env ORDER BY version DESC	 
		END  		 
		--SELECT databasePort FROM dbo.Mandant
	-- TODO @Environment berücksichtigen
	IF( NOT( EXISTS(SELECT * FROM dbo.Mandant WHERE id=@MandantId) ) )
	BEGIN
		RAISERROR (N'Mandant with id ''%d'' does not exist.', 10, 1, @MandantId)
		RETURN
	END
    DECLARE @outputfileName VARCHAR(1024) = dbo.getKU_FSUpdateCompareSchemaName(@mandantId, @env_auxiliary,@type)    
	IF (@ignoreExecutedXML = 0) AND EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @env AND TYPE = @type AND EXECUTED=1)
		BEGIN
			SELECT TOP 1 @RAW_DATA = DATA FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @env AND TYPE = @type AND EXECUTED=1
			IF (@TYPE = 'DATA' AND @updateScript = 1)
				SET @RAW_DATA.modify('delete /Project[1]/TableActions/value[position()=(last())]')
			SET @environmentXML = dbo.RenderXMLToString(@RAW_DATA)
			IF (@writeFile = 1)
				BEGIN 
					IF (@environmentXML <> '')
						EXEC dbo.WriteFile @fileName = @outputfileName, @fileContents = @environmentXML 
					RETURN
				END
			IF (@environmentXML <> '')
				BEGIN
					EXEC dbo.longPrint @environmentXML
					RETURN
				END				
		END    

	--, @ip VARCHAR(255), @dbname VARCHAR(255), @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)=''				
	-- Standard XML-Schema für Schema Compare-Job. Enthält Platzhalter "###", die weiter unten ersetzt werden
    SET @SCHEMA_COMPARE = dbo.GET_SQL_XMLCOMPARE('SCHEMA',DEFAULT,DEFAULT,DEFAULT,DEFAULT)
    SET @DATA_COMPARE = dbo.GET_SQL_XMLCOMPARE('DATA',@abfragenComplementLike, @AUSW_Abfragen_ParameterComplementLike, @RIGHTS_LISTComplementLike, @AUSW_Abfragen_SummenComplementLike)


	-- TODO @Environment berücksichtigen
	
	/*IF (@Environment IN ('LIVE'))
		SELECT @ip=ISNULL(databaseIp,'')+
		    CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(databasePort)=1 THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END +  --tsql port sintax
			CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END, 
			   @dbname=ISNULL(databaseName,''),
			   @dbuser=ISNULL(databaseUser,'') FROM dbo.Mandant WHERE id=@MandantId*/ --nicht mehr von mandant wegen API Änderungen auf der Tabelle
	IF (@Environment IN ('LIVE', 'DEFAULT'))
	IF (EXISTS (SELECT * FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@env_auxiliary and version = '6.0'))
		BEGIN 
			SELECT TOP 1 @dbname=ISNULL(databaseName,''), @dbuser=ISNULL(databaseUser,''), @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
			@ip=ISNULL(databaseIp,'')+
			   CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END + 
				CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(databasePort)=1 /*intern extern unterschied*/  THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@env_auxiliary and version = '6.0'	 
		END 
		
	IF( @ip = '' )
	BEGIN
		RAISERROR (N'IP (and/or instance) for database of mandant with id ''%d'' is empty.', 10, 1, @MandantId)
		RETURN
	END
	IF( @dbname = '' )
	BEGIN
		RAISERROR (N'Name for database of mandant with id ''%d'' is empty.', 10, 1, @MandantId)
		RETURN
	END
	IF( @dbuser = '' )
	BEGIN
		RAISERROR (N'User for database of mandant with id ''%d'' is empty.', 10, 1, @MandantId)
		RETURN
	END
	IF (@Environment IN ('LIVE'))
		SET @dbpassword = dbo.SEC_GetPWCOde(@dbuser)

	-- Ersetzung von Platzhaltern
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/ServerName/text())[1] with sql:variable("@ip")')
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/DatabaseName/text())[1] with sql:variable("@dbname")')
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@dbuser")')
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@dbpassword")')

	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/ServerName/text())[1] with sql:variable("@ip")')
	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/DatabaseName/text())[1] with sql:variable("@dbname")')
	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@dbuser")')
	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@dbpassword")')

	IF (@ARCHIV_DB <> '')
		BEGIN
			DECLARE @SelectedSyncObjectsArchiv XML = 
'
  <SelectedSyncObjects version="1" type="SelectedSyncObjects">
    <Schemas type="ListString" version="2">
      <value type="string">ZABiAG8A</value>
      <value type="string">UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA</value>
    </Schemas>
    <ZABiAG8A>__</ZABiAG8A>
    <UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>ceEOw2bE7MRHO2asdFCfCwoAABJ9sr4Y5irklyH2c2tMcegKAABd+yoBYoVUbjPyopCJsn1QCgAAHxv9HLwiUEQE1p9mrkybAgoBAFntUP8LT+JbJ98WJXqrrOgKAQA_</UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>
    <Grouping type="ListByte" version="2">
      <value type="Byte">63</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
    </Grouping>
    <SelectAll>True</SelectAll>
  </SelectedSyncObjects>
'  
	DECLARE @SelectedSyncObjectsCHEMA XML =    
'  <SelectedSyncObjects version="1" type="SelectedSyncObjects">
    <Schemas type="ListString" version="2">
      <value type="string">ZABiAG8A</value>
      <value type="string">UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA</value>
    </Schemas>
    <ZABiAG8A>__</ZABiAG8A>
    <UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>mTXTBhq1DfjYp7bnvRvyngoBAHHhDsNmxOzERztmrHRQnwsKAAASfbK+GOYq5Jch9nNrTHHoCgAAXfsqAWKFVG4z8qKQibJ9UAoAADvJgfdd5juNpkabzWJb+K8KAQAPPX2osGw+Oq5YB9LTb6tmCgEA+bBynOTJcSzdxMIx6PLr1woBAFntUP8LT+JbJ98WJXqrrOgKAQDuhY6/yW3YAD8n0pcRxPIJCgEA</UgBlAGQARwBhAHQAZQBfAFMAUQBMAEMAbwBtAHAAYQByAGUAXwBEAGUAZgBhAHUAbAB0AF8AUwBjAGgAZQBtAGEA>
    <Grouping type="ListByte" version="2">
      <value type="Byte">63</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
      <value type="Byte">0</value>
    </Grouping>
    <SelectAll>True</SelectAll>
  </SelectedSyncObjects>'

  declare @ta xml = 
  '    <value version="1" type="SelectTableEvent">
      <action>DeselectItem</action>
      <val>[dbo].[DOCS_STANDARD_BELEGARTEN]:[dbo].[DOCS_STANDARD_BELEGARTEN]</val>
    </value>
	
	'
			SET @ARCHIV_SCHEMA_COMPARE = @SCHEMA_COMPARE
			SET @ARCHIV_SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/ServerName/text())[1] with sql:variable("@ARCHIV_IP")')
			SET @ARCHIV_SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/DatabaseName/text())[1] with sql:variable("@ARCHIV_DB")')
			SET @ARCHIV_SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@ARCHIV_DB_USER")')
			SET @ARCHIV_SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@ARCHIV_DB_USER_PW")')
			SET @ARCHIV_SCHEMA_COMPARE.modify('delete (/Project/SelectedSyncObjects)[1]')
			SET @ARCHIV_SCHEMA_COMPARE.modify('insert sql:variable("@SelectedSyncObjectsArchiv") after (/Project/UserNote)[1]')
			SET @SCHEMA_COMPARE.modify('delete (/Project/SelectedSyncObjects)[1]')
			SET @SCHEMA_COMPARE.modify('insert sql:variable("@SelectedSyncObjectsCHEMA") after (/Project/UserNote)[1]')
			--SET @SCHEMA_COMPARE.modify('insert sql:variable("@ta") into (/Project/TableActions)[1]')
		END
	-- TODO Where Clauses für Data Compare-Job [abfragen], [AUSW_Abfragen_Parameter], [AUSW_Abfragen_Summen] und [RIGHTS_LIST]
	/* In @DATA_COMPARE sind Standardwerte enthalten, bei manchen Kunden müssen diese individuell angepasst werden z.B.
    <value version="1" type="SelectTableEvent">
      <action>SetLeftWhereClause</action>
      <TableName>[dbo].[abfragen]:[dbo].[abfragen]</TableName>
      <IndexName>WHERE Beschreibung NOT LIKE '%Individuell%' OR Beschreibung LIKE '%Individuell%KM%'</IndexName>
    </value>
    <value version="1" type="SelectTableEvent">
      <action>SetLeftWhereClause</action>
      <TableName>[dbo].[AUSW_Abfragen_Parameter]:[dbo].[AUSW_Abfragen_Parameter]</TableName>
      <IndexName>WHERE FKabfragenr IN (SELECT nummer FROM dbo.Abfragen WHERE Beschreibung NOT LIKE '%Individuell%' OR Beschreibung LIKE '%Individuell%KM%')</IndexName>
    </value>
    <value version="1" type="SelectTableEvent">
      <action>SetLeftWhereClause</action>
      <TableName>[dbo].[AUSW_Abfragen_Summen]:[dbo].[AUSW_Abfragen_Summen]</TableName>
      <IndexName>WHERE FKabfragenr IN (SELECT nummer FROM dbo.Abfragen WHERE Beschreibung NOT LIKE '%Individuell%' OR Beschreibung LIKE '%Individuell%KM%')</IndexName>
    </value>
    <value version="1" type="SelectTableEvent">
      <action>SetLeftWhereClause</action>
      <TableName>[dbo].[RIGHTS_LIST]:[dbo].[RIGHTS_LIST]</TableName>
      <IndexName>WHERE ISNULL(Kunde,'')='' OR ISNULL(Kunde,'') LIKE '%KM%'</IndexName>
    </value>
	*/
	 

	IF (@type IN ('SCHEMA'))
		BEGIN
		/*[TYPE]    -- SCHEMA | DATA
[ENVIRONMENT]  -- ACC | LIVE*/
			SET @environmentXML = dbo.RenderXMLToString(@SCHEMA_COMPARE)
			EXEC dbo.PFLEGE_XML_MANDANT_ENVIRONMENT @mandantId = @mandantId, @AbasId = @AbasId, 
			@environment = @env, @type = @type, @data = @SCHEMA_COMPARE, @updateScript = @updateScript
		END
	IF (@type IN ('DATA'))
		BEGIN
			IF (@updateScript = 1)
				SET @DATA_COMPARE.modify('delete /Project[1]/TableActions/value[position()=(last())]')
			        
			SET @environmentXML = dbo.RenderXMLToString(@DATA_COMPARE)
			EXEC dbo.PFLEGE_XML_MANDANT_ENVIRONMENT @mandantId = @mandantId, @AbasId = @AbasId, 
			@environment = @env, @type = @type, @data = @DATA_COMPARE, @updateScript = @updateScript
		END
		
    IF (@writeFile = 1)
		BEGIN 
			IF (@environmentXML <> '')EXEC dbo.WriteFile @fileName = @outputfileName, @fileContents = @environmentXML			
			IF (@ARCHIV_SCHEMA_COMPARE IS NOT NULL and @ARCHIV_DB <> '')
			 BEGIN
				DECLARE @ARCHIV_outputfileName VARCHAR(1024) = replace(@outputfileName,@dbname,@ARCHIV_DB)
				SET @environmentXML = dbo.RenderXMLToString(@ARCHIV_SCHEMA_COMPARE)
				EXEC dbo.WriteFile @fileName = @ARCHIV_outputfileName, @fileContents = @environmentXML			
			 END
			RETURN
		END
	IF (@environmentXML <> '')EXEC dbo.longPrint @environmentXML
END
GO
/****** Object:  StoredProcedure [dbo].[GET_SQL_COMPARE_XML_BY_MAND_ENV_PK]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[GET_SQL_COMPARE_XML_BY_MAND_ENV_PK]
	@MAND_ENV_PK INT = NULL,
	@ip VARCHAR(255) = '', @dbname VARCHAR(255) = '', @dbuser VARCHAR(512)='', @dbpassword NVARCHAR(512)='',
	@KUNDEDATAINDSEARCH VARCHAR(255)='', @deploymentSubfolder NVARCHAR(255)='', @execUpdate6 BIT = 0
AS
BEGIN
	SET NOCOUNT ON
    DECLARE @SCHEMA_COMPARE XML, @DATA_COMPARE XML, @RAW_DATA XML
	DECLARE @environmentXML NVARCHAR(MAX) = ''
	DECLARE @abfragenComplementLike VARCHAR(512) = ''
	DECLARE @MANDANT_ID INT = NULL
	DECLARE @AUSW_Abfragen_ParameterComplementLike VARCHAR(512) = ''
	DECLARE @AUSW_Abfragen_SummenComplementLike VARCHAR(512) = ''
	DECLARE @RIGHTS_LISTComplementLike VARCHAR(512) = ''

	IF (ISNULL(@KUNDEDATAINDSEARCH,'') <> '')
		BEGIN
			SET @abfragenComplementLike = 'OR Beschreibung LIKE ''%Individuell%'+@KUNDEDATAINDSEARCH+'%'''
			SET @AUSW_Abfragen_ParameterComplementLike = @abfragenComplementLike
			SET @AUSW_Abfragen_SummenComplementLike = @abfragenComplementLike
			SET @RIGHTS_LISTComplementLike = 'OR ISNULL(Kunde,'''') LIKE ''%'+@KUNDEDATAINDSEARCH+'%'''			
		END
		 
		--SELECT databasePort FROM dbo.Mandant
	-- TODO @Environment berücksichtigen
	IF( NOT( EXISTS(SELECT * FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE PK = @MAND_ENV_PK and version in ('6.0','MASTER')) ) )
	BEGIN
		RAISERROR (N'Mandant with id ''%d'' does not exist.', 10, 1, @MAND_ENV_PK)
		RETURN
	END
 --PRINT @MAND_ENV_PK
	IF (EXISTS (SELECT * FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE PK = @MAND_ENV_PK and version in ('6.0','MASTER')))
		BEGIN 
			SELECT TOP 1 @MANDANT_ID = mandant_id, @dbname=ISNULL(databaseName,''), @dbuser=ISNULL(databaseUser,''), @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
			@ip=ISNULL(databaseIp,'')+
			   CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END + 
				CASE WHEN dbo.isClientExtern(mandant_id)=1 AND ISNUMERIC(databasePort)=1 /*intern extern unterschied*/  THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
			FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE PK = @MAND_ENV_PK and version in ('6.0','MASTER')	 
		END 
 

    DECLARE @outputfileSCHEMA_COMPAREName nVARCHAR(2048) = dbo.getLocalNameDeploymentFileByMandandtEnvironmentPK(@MAND_ENV_PK,'SCHEMA',@deploymentSubfolder)    
    DECLARE @outputfileDATA_COMPAREName nVARCHAR(2048) = dbo.getLocalNameDeploymentFileByMandandtEnvironmentPK(@MAND_ENV_PK,'DATA',@deploymentSubfolder)    
  
    SET @SCHEMA_COMPARE = dbo.GET_SQL_XMLCOMPARE('SCHEMA',DEFAULT,DEFAULT,DEFAULT,DEFAULT, @MANDANT_ID)
    SET @DATA_COMPARE = dbo.GET_SQL_XMLCOMPARE('DATA',@abfragenComplementLike, @AUSW_Abfragen_ParameterComplementLike, @RIGHTS_LISTComplementLike, @AUSW_Abfragen_SummenComplementLike, @MANDANT_ID)


 
	IF( @ip = '' )
	BEGIN
		RAISERROR (N'IP (and/or instance) for database of mandant with @MAND_ENV_PK ''%d'' is empty.', 10, 1, @MAND_ENV_PK)
		RETURN
	END
	IF( @dbname = '' )
	BEGIN
		RAISERROR (N'Name for database of mandant with @MAND_ENV_PK ''%d'' is empty.', 10, 1, @MAND_ENV_PK)
		RETURN
	END
	IF( @dbuser = '' )
	BEGIN
		RAISERROR (N'User for database of mandant with @MAND_ENV_PK ''%d'' is empty.', 10, 1, @MAND_ENV_PK)
		RETURN
	END
	SET @dbpassword = dbo.SEC_GetPWCOde(@dbuser)

	-- Ersetzung von Platzhaltern
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/ServerName/text())[1] with sql:variable("@ip")')
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/DatabaseName/text())[1] with sql:variable("@dbname")')
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@dbuser")')
	SET @SCHEMA_COMPARE.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@dbpassword")')

	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/ServerName/text())[1] with sql:variable("@ip")')
	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/DatabaseName/text())[1] with sql:variable("@dbname")')
	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@dbuser")')
	SET @DATA_COMPARE.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@dbpassword")')
	SET @environmentXML = dbo.RenderXMLToString(@SCHEMA_COMPARE)
	--IF (@execUpdate6 = 1)
		--SET @environmentXML = REPLACE(@environmentXML,'crent_schema_deployment','crent_schema_update')
	EXEC dbo.WriteFile @fileName = @outputfileSCHEMA_COMPAREName, @fileContents = @environmentXML			
	SET @environmentXML = dbo.RenderXMLToString(@DATA_COMPARE)
	EXEC dbo.WriteFile @fileName = @outputfileDATA_COMPAREName, @fileContents = @environmentXML			
 
 
END
GO
/****** Object:  StoredProcedure [dbo].[getHelpDefinitionVariablesFromTableProc]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[getHelpDefinitionVariablesFromTableProc] (@TABLE_NAME NVARCHAR(2048) = NULL, @WHERE_CONDITION NVARCHAR(MAX)=NULL, @FORM_SELECT_ASSIGNATION BIT = 0, @JUST_DEFAULT_DEFINITION BIT = 0, @justFields NVARCHAR(MAX)='', @justFieldsSep NVARCHAR(1)=';')
AS 
SET NOCOUNT ON
BEGIN
	DECLARE @result NVARCHAR(MAX) = ''
	DECLARE @tsql NVARCHAR(MAX) = ''
	DECLARE @counterStringSeparator INT = 0
	DECLARE @counterStringEnter INT = 1
	DECLARE @counterStringConstant INT = 3950
	--DECLARE @counterStringEnter INT = 0
	DECLARE @tsqlSelectFromWhere NVARCHAR(MAX) = ''
	DECLARE @stringCounterSeparator VARCHAR(1) = ','
	DECLARE @tsqlSelect0 NVARCHAR(MAX) = 'SELECT TOP 1 '
	DECLARE @tsqlSelect NVARCHAR(MAX) = 'SELECT TOP 1 '
	DECLARE @tsqlSelectHelp1 NVARCHAR(MAX) = '--SELECT TOP 1 '
	DECLARE @tsqlSelectHelpTable NVARCHAR(MAX) = 'DECLARE @'+@TABLE_NAME+' TABLE('
	DECLARE @tsqlSelectHelpTableInsertInto NVARCHAR(MAX) = 'INSERT INTO @'+@TABLE_NAME+' ('
	DECLARE @tsqlSelectHelp2 NVARCHAR(MAX) = 'SELECT '
	DECLARE @tsqlSelectHelp3 NVARCHAR(MAX) = '--/*not execute*/ UPDATE '+ISNULL(@TABLE_NAME,'')+' SET'
	DECLARE @tsqlCursorHelpName1 NVARCHAR(512) = UPPER(ISNULL(@TABLE_NAME,''))+'_CURSOR'
	DECLARE @tsqlCursorHelp1 NVARCHAR(MAX) = ''
	DECLARE @tsqlCursorHelp1Vars NVARCHAR(MAX) = ''
	DECLARE @tsqlCursorHelp2Vars NVARCHAR(MAX) = ''
	--DECLARE @tsqlCursorHelp1 NVARCHAR(MAX) = 'DECLARE ' +@tsqlCursorHelpName1+CHAR(13)
	
	CREATE TABLE #tmptable_value (VALUE VARCHAR(MAX) NULL)
	DECLARE @VALUE NVARCHAR(MAX) = ''
	DECLARE @table TABLE(COLUMN_NAME NVARCHAR(128) NULL, IS_NULLABLE NVARCHAR(128) NULL, DATA_TYPE NVARCHAR(128) NULL, CHARACTER_MAXIMUM_LENGTH NVARCHAR(128) NULL, COLUMN_DEFAULT NVARCHAR(2048) NULL)
	DECLARE @COLUMN_NAME NVARCHAR(128) = NULL, @IS_NULLABLE NVARCHAR(128) = NULL, @DATA_TYPE NVARCHAR(128) = NULL, @CHARACTER_MAXIMUM_LENGTH NVARCHAR(128) = NULL, @COLUMN_DEFAULT NVARCHAR(2048) = NULL 
	DECLARE @TSQLFIELD_DEFINITION NVARCHAR(MAX) = ''
	IF EXISTS (SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TABLE_NAME)
		BEGIN
			INSERT INTO @table
			SELECT COLUMN_NAME, IS_NULLABLE, DATA_TYPE, CHARACTER_MAXIMUM_LENGTH,COLUMN_DEFAULT
			FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TABLE_NAME
												DECLARE help_table_field_definition CURSOR  
			   FOR  SELECT COLUMN_NAME, IS_NULLABLE, UPPER(DATA_TYPE), CHARACTER_MAXIMUM_LENGTH,ISNULL(COLUMN_DEFAULT,'NULL') FROM @table
			OPEN help_table_field_definition  
			FETCH NEXT FROM help_table_field_definition INTO @COLUMN_NAME, @IS_NULLABLE, @DATA_TYPE, @CHARACTER_MAXIMUM_LENGTH, @COLUMN_DEFAULT
			SET @tsqlSelectFromWhere =' FROM '+ISNULL(@TABLE_NAME,'_TABLE_')+' WHERE '+ISNULL(@WHERE_CONDITION,'_CONDITION_') 
			--SELECT * FROM @table
			IF (ISNULL(@justFields,'')<>'')
				DELETE FROM @table WHERE COLUMN_NAME NOT IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@justFields,@justFieldsSep))
			WHILE @@FETCH_STATUS = 0  
			BEGIN  
				--evaluate column default 
				IF (ISNULL(@WHERE_CONDITION,'')<>'')	
					BEGIN
						SET @tsql = 'SELECT TOP 1 CAST(ISNULL('+@COLUMN_NAME+',NULL) AS VARCHAR(MAX))'+@tsqlSelectFromWhere
						IF (@DATA_TYPE IN ('DATETIME','DATETIME2') AND (@VALUE <> 'NULL' OR @VALUE IS NOT NULL) )
							SET @tsql = 'SELECT TOP 1 dbo.CRW_ISO_DATE('+@COLUMN_NAME+',DEFAULT)'+@tsqlSelectFromWhere
							
						--PRINT @tsql
						BEGIN TRY
							INSERT INTO #tmptable_value
							EXEC (@tsql)
							IF EXISTS (SELECT * FROM #tmptable_value)
								BEGIN 
									SET @VALUE = ISNULL((SELECT TOP 1 VALUE FROM #tmptable_value),@COLUMN_DEFAULT)
									--PRINT @VALUE
									IF @DATA_TYPE IN ('VARCHAR','NVARCHAR','TEXT','NTEXT') AND @VALUE <> 'NULL'
										SET @COLUMN_DEFAULT = N''''+@VALUE+''''
									ELSE IF @DATA_TYPE IN ('DATETIME','DATETIME2') AND @VALUE <> 'NULL'
										BEGIN
											IF (CHARINDEX('.',@VALUE)> 0)
												SET @VALUE = SUBSTRING(@VALUE,1,CHARINDEX('.',@VALUE)-1)
											SET @COLUMN_DEFAULT = N''''+dbo.CRW_ISO_DATE(@VALUE,DEFAULT) +''''
										END										
									--ELSE IF @DATA_TYPE IN ('DATETIME','DATETIME2') AND @VALUE = 'NULL'
										--SET @COLUMN_DEFAULT = N'''NULL'''
									ELSE SET @COLUMN_DEFAULT = @VALUE								
									SET @IS_NULLABLE = 'NO'
									DELETE FROM #tmptable_value
									--PRINT @COLUMN_DEFAULT
								END 
						END TRY
						BEGIN CATCH
							--SET @VALUE = ISNULL((SELECT TOP 1 VALUE FROM #tmptable_value),@COLUMN_DEFAULT)
							PRINT '--'+@VALUE                        
							PRINT 'SQL has failed: '+ERROR_MESSAGE()+CHAR(13)+@tsql
							--CONTINUE
						END CATCH					
					END
					--@COLUMN_NAME NVARCHAR(128) = NULL 
					--SET @TSQLFIELD_DEFINITION = ''
					IF (@CHARACTER_MAXIMUM_LENGTH <=0)SET @CHARACTER_MAXIMUM_LENGTH=255 
					SET @TSQLFIELD_DEFINITION += N'DECLARE @'+@COLUMN_NAME+' '+CASE 
																					WHEN @DATA_TYPE IN ('VARCHAR','NVARCHAR') AND ISNUMERIC(@CHARACTER_MAXIMUM_LENGTH)=1 AND @IS_NULLABLE='YES' THEN @DATA_TYPE+'('+@CHARACTER_MAXIMUM_LENGTH+') = NULL '+CHAR(13)
																					WHEN @DATA_TYPE IN ('VARCHAR','NVARCHAR') AND ISNUMERIC(@CHARACTER_MAXIMUM_LENGTH)=1 AND @IS_NULLABLE='NO' THEN @DATA_TYPE+'('+@CHARACTER_MAXIMUM_LENGTH+') = '+REPLACE(REPLACE(@COLUMN_DEFAULT,'(',''),')','')+' '+CHAR(13)
																					WHEN @DATA_TYPE IN ('TEXT','NTEXT')  THEN 'NVARCHAR(MAX) = '+REPLACE(REPLACE(@COLUMN_DEFAULT,'(',''),')','')+' '+CHAR(13)
																					WHEN @DATA_TYPE IN ('BIGINT','INT','BIT', 'DECIMAL', 'MONEY', 'FLOAT', 'DECIMAL') AND ISNUMERIC(@COLUMN_DEFAULT) = 1 THEN @DATA_TYPE+' = '+REPLACE(REPLACE(@COLUMN_DEFAULT,'(',''),')','')+' '+CHAR(13)
																					--WHEN @DATA_TYPE IN ('BIGINT','INT','BIT', 'DECIMAL', 'MONEY', 'FLOAT', 'DECIMAL') AND ISNUMERIC(@CHARACTER_MAXIMUM_LENGTH)=1 AND @IS_NULLABLE='NO' THEN @DATA_TYPE+'('+@CHARACTER_MAXIMUM_LENGTH+') = '''' '+CHAR(13)
																					ELSE @DATA_TYPE+' = '+REPLACE(REPLACE(@COLUMN_DEFAULT,'(',''),')','')+' '+CHAR(13)
																			   END 
					--PRINT @TSQLFIELD_DEFINITION
					IF(@FORM_SELECT_ASSIGNATION = 1)
						BEGIN
							SET @tsqlSelect0 += ' @'+@COLUMN_NAME+' = '+@COLUMN_NAME+',' 	
							SET @tsqlSelectHelpTableInsertInto += @COLUMN_NAME+', '																				
							SET @tsqlSelect += ' @'+@COLUMN_NAME+' = ISNULL('+@COLUMN_NAME+', @'+@COLUMN_NAME+'),' 																						
							SET @tsqlSelectHelp1 += ' '+@COLUMN_NAME+',' 
							SET @tsqlSelectHelp2 += ' @'+@COLUMN_NAME+'['+@COLUMN_NAME+'],'
							SET @tsqlSelectHelp3 += ' '+@COLUMN_NAME+'= @'+@COLUMN_NAME+','
							
							SET @tsqlCursorHelp1Vars +=  ' @'+@COLUMN_NAME+','
							SET @tsqlCursorHelp2Vars += -- ' '+@COLUMN_NAME+','
							   CASE 
																					WHEN @DATA_TYPE IN ('VARCHAR','NVARCHAR','TEXT','NTEXT') THEN ' ISNULL('+@COLUMN_NAME+',''''),'																					
																					WHEN @DATA_TYPE IN ('BIGINT','INT','BIT', 'DECIMAL', 'MONEY', 'FLOAT', 'DECIMAL') THEN ' ISNULL('+@COLUMN_NAME+',0),'																					
																					ELSE ' '+@COLUMN_NAME+','
																			   END 

							  
							SET @counterStringSeparator = (LEN(@tsqlSelect)) -  CHARINDEX(@stringCounterSeparator, REVERSE(@tsqlSelect)) 
							--SET @counterStringEnter = (LEN(@tsqlSelect)) -  CHARINDEX(CHAR(13), REVERSE(@tsqlSelect)) 
							--PRINT @counterStringSeparator%(@counterStringConstant*@counterStringEnter)							
							IF (@counterStringSeparator>@counterStringConstant AND (@counterStringSeparator%(@counterStringConstant*@counterStringEnter))<@counterStringConstant)
								BEGIN
									SET @tsqlSelect+=CHAR(10)
									SET @tsqlSelectHelp1+=CHAR(10)
									SET @tsqlSelectHelp2+=CHAR(10)
									SET @tsqlSelectHelp3+=CHAR(10)
									SET @tsqlCursorHelp1Vars+=CHAR(10)
									SET @tsqlCursorHelp2Vars+=CHAR(10)
									SET @counterStringEnter+=1
								END 
						END
						--PRINT @tsqlSelect
					FETCH NEXT FROM help_table_field_definition	INTO @COLUMN_NAME, @IS_NULLABLE, @DATA_TYPE, @CHARACTER_MAXIMUM_LENGTH, @COLUMN_DEFAULT
	
			END   
			CLOSE help_table_field_definition
			DEALLOCATE help_table_field_definition 	
			IF (@TSQLFIELD_DEFINITION <> '')
				SET @result = @TSQLFIELD_DEFINITION	
		END
  DROP TABLE #tmptable_value

  IF (@JUST_DEFAULT_DEFINITION = 1)
	BEGIN
		SET @result = dbo.getHelpDefinitionVariablesFromTable(@TABLE_NAME, @justFields, @justFieldsSep)
	END
  SET @tsqlSelectHelpTable += REPLACE(dbo.getHelpDefinitionVariablesFromTable(@TABLE_NAME, DEFAULT, DEFAULT),'DECLARE @', '')
  SET @tsqlSelectHelpTable = REPLACE(@tsqlSelectHelpTable, CHAR(10), ', ')
  SET @tsqlSelectHelpTable = REPLACE(@tsqlSelectHelpTable, CHAR(13), ', ')
  SET @tsqlSelectHelpTable = REPLACE(@tsqlSelectHelpTable, ' , ',', ')
  SET @tsqlSelectHelpTable = REPLACE(@tsqlSelectHelpTable, '=', '')
  SET @tsqlSelectHelpTable = REPLACE(@tsqlSelectHelpTable, '  ', ' ')
   
  IF(@FORM_SELECT_ASSIGNATION = 1)	
	BEGIN 
		SET @tsqlSelect=SUBSTRING(@tsqlSelect,1,LEN(@tsqlSelect)-1)+@tsqlSelectFromWhere
		SET @tsqlSelect0=SUBSTRING(@tsqlSelect0,1,LEN(@tsqlSelect0)-1)+@tsqlSelectFromWhere
		SET @tsqlSelectHelp1=SUBSTRING(@tsqlSelectHelp1,1,LEN(@tsqlSelectHelp1)-1)+@tsqlSelectFromWhere
		SET @tsqlSelectHelp2=SUBSTRING(@tsqlSelectHelp2,1,LEN(@tsqlSelectHelp2)-1)
		SET @tsqlCursorHelp1Vars=SUBSTRING(@tsqlCursorHelp1Vars,1,LEN(@tsqlCursorHelp1Vars)-1)
		SET @tsqlCursorHelp2Vars=SUBSTRING(@tsqlCursorHelp2Vars,1,LEN(@tsqlCursorHelp2Vars)-1)
		SET @tsqlSelectHelp3=SUBSTRING(@tsqlSelectHelp3,1,LEN(@tsqlSelectHelp3)-1)+' WHERE '+@WHERE_CONDITION
		SET @tsqlCursorHelp1+='DECLARE '+@tsqlCursorHelpName1+' CURSOR'+CHAR(13)+
							  '	FOR SELECT '+@tsqlCursorHelp2Vars +@tsqlSelectFromWhere+CHAR(13)+
							  'OPEN '+@tsqlCursorHelpName1 +CHAR(13)+
							  'FETCH NEXT FROM '+@tsqlCursorHelpName1+' INTO '+@tsqlCursorHelp1Vars+CHAR(13)+
							  'WHILE @@FETCH_STATUS = 0'+CHAR(13)+
							  'BEGIN'+CHAR(13)+
							  '	--do your stuff'+CHAR(13)+
							  '	--'+@tsqlSelectHelp2+CHAR(13)+
							  '	FETCH NEXT FROM '+@tsqlCursorHelpName1+' INTO '+@tsqlCursorHelp1Vars+CHAR(13)+
							  'END'+CHAR(13)+
							  'CLOSE '+@tsqlCursorHelpName1+CHAR(13)+
							  'DEALLOCATE '+@tsqlCursorHelpName1 
		--PRINT ' '+@tsqlSelect
		SET @tsqlSelectHelpTable=SUBSTRING(@tsqlSelectHelpTable,1,LEN(@tsqlSelectHelpTable)-1)+')'
		SET @tsqlSelectHelpTableInsertInto=SUBSTRING(@tsqlSelectHelpTableInsertInto,1,LEN(@tsqlSelectHelpTableInsertInto)-1)+')'+CHAR(13)+
							  '		SELECT '+@tsqlCursorHelp2Vars +@tsqlSelectFromWhere
		SET @result+=CHAR(13)+@tsqlSelect0+CHAR(13)+@tsqlSelect+CHAR(13)+@tsqlSelectHelp1+CHAR(13)+@tsqlSelectHelp2+CHAR(13)+@tsqlSelectHelp3+CHAR(13)+@tsqlCursorHelp1+CHAR(13)+@tsqlSelectHelpTable+CHAR(13)+@tsqlSelectHelpTableInsertInto
		EXEC dbo.longPrintingString @printigString = @result -- nvarchar(max)
		RETURN
		
	END
  EXEC dbo.longPrint @printigString = @result
END
GO
/****** Object:  StoredProcedure [dbo].[grep]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[grep](@s1 VARCHAR(255), @s2 VARCHAR(255) = '', @s3 VARCHAR(255) = '', @s4 VARCHAR(255) = '')
AS
begin

SELECT name, type_desc,definition FROM sys.objects, sys.sql_modules WHERE sys.objects.object_id = sys.sql_modules.object_id
AND  sys.sql_modules.definition LIKE '%' + @s1 + '%'
	AND   ((@s2 = '') OR (sys.sql_modules.definition LIKE '%' + @s2 + '%')) 
	AND   ((@s3 = '') OR (sys.sql_modules.definition LIKE '%' + @s3 + '%')) 
	AND   ((@s4 = '') OR (sys.sql_modules.definition LIKE '%' + @s4 + '%')) 


end
GO
