				</server>'
				--(SELECT TOP 3 dbo.CRW_GET_MV_STATUS(VERTRAGSNUMMER), CAST (VERTRAGSNUMMER AS VARCHAR(32)) FROM dbo.MIETVERTRAEGE WHERE VERTRAGSNUMMER>1000 AND dbo.CRW_GET_MV_STATUS(VERTRAGSNUMMER) = 'reservation'  )
