UNION
SELECT TOP 3 ''ACC'', ''MIETVERTRAG_CI'', CAST (VERTRAGSNUMMER AS VARCHAR(32)) FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.MIETVERTRAEGE WHERE VERTRAGSNUMMER>1000 AND (OFFENODERCHECKIN = ''I'' AND (vtc<>''V'' OR vtc IS NULL))
UNION 
SELECT TOP 3 ''ACC'', ''RECHNUNG'', PK FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.RECH_RECHNUNG WHERE PK LIKE ''RE%'' AND verbucht = 1
UNION   
SELECT DISTINCT TOP 3 ''ACC'', ''PROTOCOL'', CAST (PROTOCOL_PK AS VARCHAR(32)) FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.CSAPP_PROTOCOL 
WHERE PROTOCOL_PK IN ((SELECT MAX(PROTOCOL_PK) FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.CSAPP_PROTOCOL),(SELECT MAX(PROTOCOL_PK)-1 FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.CSAPP_PROTOCOL),(SELECT MAX(PROTOCOL_PK)-2 FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.CSAPP_PROTOCOL))
' 
			DECLARE @changeBasicDBConfigTSQLString VARCHAR(MAX) = CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), @executingTSQLVARCHAR), 1)		 
			SET @changeBasicDBConfigTSQLString = SUBSTRING(@changeBasicDBConfigTSQLString,3,LEN(@changeBasicDBConfigTSQLString))
			SET  @executingTSQL = '<TSQL>'+@changeBasicDBConfigTSQLString+'</TSQL>'
			EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 1, @TMP_TABLE_NAME = '#sourceInfo', @TSQSuccess = @TSQSuccess OUT
 
		END  
	IF (EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandant_environment_default_pk))
		BEGIN
			SET @targetLinkedServerNameConfig = dbo.getAdminLinkedServerNameByPK(@mandant_environment_default_pk)
			IF (@targetLinkedServerNameConfig IS NOT NULL)
				BEGIN
					SELECT @sourceDBName = DatabaseName, @originLinkedServerName = linkedServerName  FROM dbo.getLinkedServerNameByPK(@mandant_environment_default_pk)
					SET @originLinkedServerNameConfig = dbo.getAdminLinkedServerNameByPK(@mandant_environment_default_pk)
					SET @executingTSQLVARCHAR = 
'SELECT TOP 3 ''LIVE'', ''RESERVIERUNG'', CAST (VERTRAGSNUMMER AS VARCHAR(32)) FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.MIETVERTRAEGE WHERE VERTRAGSNUMMER>1000 AND (OFFENODERCHECKIN = ''O'' AND Reservierung = ''J'' AND (vtc<>''V'' OR vtc IS NULL))
UNION
SELECT TOP 3 ''LIVE'', ''LAUFENDER_MIETVERTRAG'', CAST (VERTRAGSNUMMER AS VARCHAR(32)) FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.MIETVERTRAEGE WHERE VERTRAGSNUMMER>1000 AND (OFFENODERCHECKIN = ''O'' AND Reservierung = ''N'' AND (vtc<>''V'' OR vtc IS NULL))
UNION
SELECT TOP 3 ''LIVE'', ''MIETVERTRAG_CI'', CAST (VERTRAGSNUMMER AS VARCHAR(32)) FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.MIETVERTRAEGE WHERE VERTRAGSNUMMER>1000 AND (OFFENODERCHECKIN = ''I'' AND (vtc<>''V'' OR vtc IS NULL))
UNION 
SELECT TOP 3 ''LIVE'', ''RECHNUNG'', PK FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.RECH_RECHNUNG WHERE PK LIKE ''RE%'' AND verbucht = 1
UNION   
SELECT DISTINCT TOP 3 ''LIVE'', ''PROTOCOL'', CAST (PROTOCOL_PK AS VARCHAR(32)) FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.CSAPP_PROTOCOL 
WHERE PROTOCOL_PK IN ((SELECT MAX(PROTOCOL_PK) FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.CSAPP_PROTOCOL),(SELECT MAX(PROTOCOL_PK)-1 FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.CSAPP_PROTOCOL),(SELECT MAX(PROTOCOL_PK)-2 FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.CSAPP_PROTOCOL))
' 
					DECLARE @changeBasicDBConfigTSQLStringLIVE VARCHAR(MAX) = CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), @executingTSQLVARCHAR), 1)		 
					SET @changeBasicDBConfigTSQLStringLIVE = SUBSTRING(@changeBasicDBConfigTSQLStringLIVE,3,LEN(@changeBasicDBConfigTSQLStringLIVE))
					SET  @executingTSQL = '<TSQL>'+@changeBasicDBConfigTSQLStringLIVE+'</TSQL>'
					EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 1, @TMP_TABLE_NAME = '#sourceInfo', @TSQSuccess = @TSQSuccess OUT
 				    
				END

		END  		 
	
	--SELECT * FROM #sourceInfo

	DECLARE @typ NVARCHAR(1024) = NULL 
	DECLARE @keyname NVARCHAR(1024) = NULL 
	DECLARE @keynamevalue NVARCHAR(128) = NULL 
	DECLARE @comodoroChar NVARCHAR(128) = 'ein' 
  
	DECLARE SOURCEINFO_CURSOR CURSOR
		FOR SELECT  ISNULL(typ,''), ISNULL(keyname,''), ISNULL(keynamevalue,'') FROM #sourceInfo  
	OPEN SOURCEINFO_CURSOR
	FETCH NEXT FROM SOURCEINFO_CURSOR INTO  @typ, @keyname, @keynamevalue
	WHILE @@FETCH_STATUS = 0
	BEGIN
		--do your stuff
		SET @comodoroChar = 'ein'
		IF (@keyname IN ('RECHNUNG','RESERVIERUNG'))
			SET @comodoroChar = 'eine'
		PRINT 'Beispiel: von der '+@typ+' Umgebung '+@comodoroChar+' '+@keyname+' mit dem Wert: "'+@keynamevalue+'"'
		--SELECT  @typ[typ], @keyname[keyname], @keynamevalue[keynamevalue]
		FETCH NEXT FROM SOURCEINFO_CURSOR INTO  @typ, @keyname, @keynamevalue
	END
	CLOSE SOURCEINFO_CURSOR
	DEALLOCATE SOURCEINFO_CURSOR
	DROP TABLE #sourceInfo
 
END
GO
/****** Object:  StoredProcedure [dbo].[LongPrint]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
