CREATE PROCEDURE [dbo].[LongPrint](@printigString NVARCHAR(MAX) = '')
AS --Author José Problem gelost von PRINT @text VARCHAR(500000)
BEGIN 
DECLARE @offset TINYINT, @size BIGINT = 4000 --first size 
SET @printigString = REPLACE(@printigString, CHAR(13)+CHAR(10), CHAR(10))--Line feed and carriage return reblaced by Line feed
SET @printigString = REPLACE(@printigString, CHAR(13), CHAR(10)) --return by line feed replaced
	WHILE LEN(@printigString) > 1
	BEGIN
		SELECT @offset = 1
		IF CHARINDEX(CHAR(10), @printigString) BETWEEN 1 AND 4000
			SELECT @size = CHARINDEX(CHAR(10), @printigString) -1, @offset = 2
		PRINT SUBSTRING(@printigString, 1, @size) 
		SET @printigString = SUBSTRING(@printigString, @size+@offset, LEN(@printigString))   
	END 
END
GO
/****** Object:  StoredProcedure [dbo].[longPrintingString]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[longPrintingString](@printigString NVARCHAR(MAX) = '')
AS --Author José Problem gelöst von PRINT @text VARCHAR(500000)
BEGIN 
DECLARE @text_offset INT = 1
DECLARE @text_length INT
DECLARE @print_length INT = 3584
DECLARE @print_length_aux INT = 0
DECLARE @text_counter INT = 1
DECLARE @result NVARCHAR(MAX)
SET @printigString = REPLACE(@printigString, CHAR(13)+CHAR(10), CHAR(10))--Line feed and carriage return reblaced by Line feed
SET @printigString = REPLACE(@printigString, CHAR(13), CHAR(10)) --return by line feed replaced
			SET @text_length=LEN(@printigString)
			WHILE(@text_counter <= @text_length)
			BEGIN    
				SET @text_offset = 1    
				SET @print_length = 4000   
				SET @result= SUBSTRING(@printigString,@text_counter,@print_length)
				SET @print_length_aux = dbo.LastIndexOf(@result,CHAR(10))
				IF(@print_length_aux > 1) 
				    BEGIN
						SET @print_length=@print_length_aux+1
						SET @result= SUBSTRING(@printigString,@text_counter,@print_length)
					END
				PRINT @result
				SET @text_counter+=@print_length
			END     
END
GO
