CREATE PROCEDURE [dbo].[MANAGE_LINKED_SERVER](@VIRTUAL_UNIQUE_SERVER_NAME NVARCHAR(512) = NULL, @SERVER_STRING NVARCHAR(512) = NULL, @SERVER_CATALOG NVARCHAR(512) = NULL, @SERVER_USER NVARCHAR(128) = NULL, @SERVER_USER_PW NVARCHAR(128) = NULL, @returnValidLoggedIn BIT = 1 OUTPUT ) 
	AS SET NOCOUNT ON -- Author Jose
	DECLARE @PROVIDERSTR NVARCHAR(1024) = N'PROVIDER=SQLOLEDB;SERVER='+ISNULL(@SERVER_STRING,'')--  ---N'PROVIDER=SQLOLEDB;SERVER=10.0.69.9\CRENT,1433'
	DECLARE @retval INT
	IF EXISTS(SELECT server_id FROM sys.servers WHERE name = @VIRTUAL_UNIQUE_SERVER_NAME)
		BEGIN
		    PRINT '--'+@VIRTUAL_UNIQUE_SERVER_NAME+' Server name already in use'
			SET @returnValidLoggedIn = 1
			RETURN
		END

	/****** Object:  LinkedServer [@VIRTUAL_UNIQUE_SERVER_NAME]  ******/
	EXEC master.dbo.sp_addlinkedserver @server = @VIRTUAL_UNIQUE_SERVER_NAME, @srvproduct=N'MSSQL', @provider=N'SQLNCLI', @provstr=@PROVIDERSTR,@catalog=@SERVER_CATALOG
	 /* For security reasons the linked server remote logins password is changed with ######## */
	EXEC master.dbo.sp_addlinkedsrvlogin @rmtsrvname=@VIRTUAL_UNIQUE_SERVER_NAME,@useself=N'False',@locallogin = NULL,@rmtuser=@SERVER_USER,@rmtpassword=@SERVER_USER_PW
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'collation compatible', @optvalue=N'false'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'data access', @optvalue=N'true'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'dist', @optvalue=N'false'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'pub', @optvalue=N'false'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'rpc', @optvalue=N'true'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'rpc out', @optvalue=N'true'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'sub', @optvalue=N'false'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'connect timeout', @optvalue=N'0'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'collation name', @optvalue = NULL
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'lazy schema validation', @optvalue=N'false'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'query timeout', @optvalue=N'0'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'use remote collation', @optvalue=N'true'
	EXEC master.dbo.sp_serveroption @server=@VIRTUAL_UNIQUE_SERVER_NAME, @optname=N'remote proc transaction promotion', @optvalue=N'true'
	--check remote connection to linked server
	BEGIN TRY
		EXEC @retval = sys.sp_testlinkedserver @VIRTUAL_UNIQUE_SERVER_NAME
	END TRY
	BEGIN CATCH
		SET @retval = sign(@@error);
		--delete server 
		EXEC master.dbo.sp_dropserver @server=@VIRTUAL_UNIQUE_SERVER_NAME, @droplogins='droplogins' 
	END CATCH
	IF (@retval <> 0)
		BEGIN
		    PRINT '--'+@VIRTUAL_UNIQUE_SERVER_NAME+' SQL LINKED SERVER enthält keine valide Anmeldung'
			SET @returnValidLoggedIn = 0
			RETURN 
		END
	 SET @returnValidLoggedIn = 1
	RETURN
GO
/****** Object:  StoredProcedure [dbo].[monthly_Invoice]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
