CREATE PROCEDURE [dbo].[monthly_Invoice] (@month INT, @year INT)
as
-- Start
DECLARE @PROC VARCHAR(MAX)

DECLARE @von DATETIME, @bis DATETIME
DECLARE @mvatab TABLE (mvanummer VARCHAR(10),von DATETIME, bis DATETIME, Tagenutzung int, anzahlkfz FLOAT, Mieten INT, Faktor FLOAT, Abzurechnen FLOAT)
DECLARE @AQUERY VARCHAR(8000)
DECLARE @monthdays INT

SET @von='01.'+CONVERT(varchar,@month)+'.'+CONVERT(VARCHAR,@year)
SET @bis=DATEADD(mm,1,@von)
SET @monthdays=DATEDIFF(dd,@von,@bis)

DECLARE @db_name VARCHAR(255)
DECLARE @mand_id BIGINT
DECLARE @environment_id BIGINT
DECLARE @errortab TABLE (DB varchar(255),id bigint)
DECLARE #MANDANT_CURSOR CURSOR FOR SELECT m.id,
  CASE WHEN me.databaseIp='192.168.253.109' THEN me.databaseName ELSE '['+me.databaseIp+'].'+me.databaseName END,
  me.PK
  FROM mandant_invoice_by_car_amount mc, dbo.Mandant m,dbo.MANDANT_DB_ENVIRONMENT me WHERE m.id=mc.mandant_id AND m.id=me.mandant_id
  AND me.type='DEFAULT'    
OPEN #MANDANT_CURSOR
DELETE FROM ACTIVE_VEHICLES_MONTHLY WHERE [MONTH]=@month and [year]=@year
FETCH NEXT FROM #MANDANT_CURSOR INTO @mand_id,@db_name,@environment_id
WHILE (@@FETCH_STATUS=0)
  BEGIN    
    BEGIN TRY	    
		SET @AQuery='EXEC '+@db_name+'.dbo.CX9_CALC_VEHICLE_AMOUNT '''+CONVERT(VARCHAR,@von)+''','''+CONVERT(VARCHAR,@bis)+''','+CONVERT(VARCHAR,@monthdays)	
		EXEC (@AQUERY)			
		SET @AQUERY='insert into ACTIVE_VEHICLES_MONTHLY (MandantID,MONTH,YEAR,EnvironmentID,mvanummer,von,bis,Tagenutzung,anzahlkfz,mieten,Faktor,Abzurechnen,Langzeit,miettage)'+
					' SELECT '+CONVERT(VARCHAR,@mand_id)+','+CONVERT(VARCHAR,@month)+','+CONVERT(VARCHAR,@year)+','+CONVERT(VARCHAR,@environment_id)+',mvanummer,von,bis,tagenutzung,anzahlkfz,mieten,faktor,abzurechnen,langzeit,miettage'+' FROM '+@db_name+'.dbo.CX9_VEHICLE_AMOUNT'
		EXEC (@AQUERY)	
	END TRY
	BEGIN CATCH
	  INSERT INTO @errortab VALUES (@db_name,@mand_id)
	END CATCH    
/*
    PRINT @db_name
	SET @AQUERY='INSERT INTO ACTIVE_VEHICLES_MONTHLY (MandantID,MONTH,YEAR, mvanummer,von,EnvironmentID) SELECT '+CONVERT(varchar,@mand_id)+','+CONVERT(VARCHAR,@month)+','+CONVERT(varchar,@year)+',mvanummer,zuldat,'+CONVERT(VARCHAR,@environment_id)+' FROM '+@db_name+'.dbo.autos WHERE OWNER=(SELECT ownercode FROM '+@db_name+'.dbo.MAND_GLOBAL WHERE pk=1)'
	EXEC (@AQUERY)
	SET @AQUERY='UPDATE ACTIVE_VEHICLES_MONTHLY SET bis=(SELECT rueckgabehaendler FROM '+@db_name+'.dbo.autoszusdaten az WHERE az.mvanummer=ACTIVE_VEHICLES_MONTHLY.mvanummer)'+
	            'WHERE MandantID='+CONVERT(varchar,@mand_id)+' AND [MONTH]='+CONVERT(VARCHAR,@month)+' and [year]='+CONVERT(VARCHAR,@year)+' and EnvironmentID='+CONVERT(VARCHAR(255),@environment_id)
	EXEC (@AQUERY)	
	UPDATE ACTIVE_VEHICLES_MONTHLY SET bis=@bis WHERE (bis IS NULL OR bis>@bis)
	 AND MandantID=@mand_id AND [MONTH]=@month and [year]=@year AND EnvironmentID=@environment_id
	UPDATE ACTIVE_VEHICLES_MONTHLY SET von=@von WHERE von<@von
	 AND MandantID=@mand_id AND [MONTH]=@month and [year]=@year AND EnvironmentID=@environment_id
	DELETE FROM ACTIVE_VEHICLES_MONTHLY WHERE bis<=von 
	  AND MandantID=@mand_id AND [MONTH]=@month and [year]=@year AND EnvironmentID=@environment_id
	UPDATE ACTIVE_VEHICLES_MONTHLY SET Tagenutzung=datediff(dd,von,bis)
		WHERE MandantID=@mand_id AND [MONTH]=@month and [year]=@year AND EnvironmentID=@environment_id
	UPDATE ACTIVE_VEHICLES_MONTHLY SET anzahlkfz=ROUND(CONVERT(FLOAT,Tagenutzung) / CONVERT(FLOAT,DATEDIFF(dd, @von,@bis)),1)
	    WHERE MandantID=@mand_id AND [MONTH]=@month and [year]=@year AND EnvironmentID=@environment_id
	
	SET @AQUERY='UPDATE ACTIVE_VEHICLES_MONTHLY SET Mieten = (SELECT COUNT(*) FROM '+@db_name+'.dbo.MIETVERTRAEGE m WHERE ISNULL(VTC, '''')<>''v'' AND ISNULL(Reservierung,'''')<>''j'' AND m.mvanummer=[ACTIVE_VEHICLES_MONTHLY].mvanummer AND NOT (VorlageCRW.dbo.VTR_GetGroupStartDat(m.VERTRAGSNUMMER)>'''+CONVERT (VARCHAR,@bis)+''') AND NOT (VorlageCRW.dbo.VTR_GetGroupEndDat(m.VERTRAGSNUMMER)<'''+CONVERT(VARCHAR,@von)+'''))'
	    +'WHERE MandantID='+CONVERT(varchar,@mand_id)+' AND [MONTH]='+CONVERT(VARCHAR,@month)+' and [year]='+CONVERT(VARCHAR,@year)  +' and EnvironmentID='+CONVERT(VARCHAR(255),@environment_id)

    --EXEC (@AQUERY)
	SET @AQUERY='UPDATE ACTIVE_VEHICLES_MONTHLY SET Miettage = (SELECT ceiling(sum(VorlageCRW.dbo.REL_GETRELTAGE_OPEN_ALSO(vertragsnummer,'''+CONVERT(VARCHAR,@von)+''','''+CONVERT(VARCHAR,@bis)+'''))) FROM '+@db_name+'.dbo.MIETVERTRAEGE m WHERE ISNULL(VTC, '''')<>''v'' AND ISNULL(Reservierung,'''')<>''j'' AND m.mvanummer=[ACTIVE_VEHICLES_MONTHLY].mvanummer AND NOT (VorlageCRW.dbo.VTR_GetGroupStartDat(VERTRAGSNUMMER)>'''+CONVERT (VARCHAR,@bis)+''') AND NOT (VorlageCRW.dbo.VTR_GetGroupEndDat(VERTRAGSNUMMER)<'''+CONVERT(VARCHAR,@von)+'''))'
	    +'WHERE MandantID='+CONVERT(varchar,@mand_id)+' AND [MONTH]='+CONVERT(VARCHAR,@month)+' and [year]='+CONVERT(VARCHAR,@year)+' and EnvironmentID='+CONVERT(VARCHAR(255),@environment_id)
    EXEC (@AQUERY)
	
	SET @AQUERY='UPDATE ACTIVE_VEHICLES_MONTHLY SET Langzeit = CASE WHEN Miettage>='+CONVERT(VARCHAR,@monthdays)+' and mieten=1 then 1 else 0 END '
	    +'WHERE MandantID='+CONVERT(varchar,@mand_id)+' AND [MONTH]='+CONVERT(VARCHAR,@month)+' and [year]='+CONVERT(VARCHAR,@year)+' and EnvironmentID='+CONVERT(VARCHAR(255),@environment_id)
    EXEC (@AQUERY)

	UPDATE ACTIVE_VEHICLES_MONTHLY SET faktor=CASE WHEN langzeit=1 THEN 0.25 ELSE 1 END
	    WHERE MandantID=@mand_id AND [MONTH]=@month and [year]=@year AND EnvironmentID=@environment_id
	UPDATE ACTIVE_VEHICLES_MONTHLY SET Abzurechnen=anzahlkfz * Faktor
	    WHERE MandantID=@mand_id AND [MONTH]=@month and [year]=@year AND EnvironmentID=@environment_id
		*/
	FETCH NEXT FROM #MANDANT_CURSOR INTO @mand_id,@db_name,@environment_id
--SELECT a.MVANUMMER,a.KENNZEICHEN,a.FAHRZEUG,Von,Bis,Abzurechnen AS Menge FROM @mvatab m, autos a WHERE m.mvanummer=a.MVANUMMER
--SELECT SUM(abzurechnen) FROM @mvatab
END

DEALLOCATE #MANDANT_CURSOR
SELECT * FROM @errortab


SELECT m.abasId AS Kundennummer,m.companyname AS Firma, avm.mvanummer AS Fahrzeugnummer, avm.von AS Von, avm.bis AS Bis, avm.Mieten AS 'Anzahl Mieten', avm.anzahlkfz as 'Berechnung',avm.miettage AS 'Miettage',
  avm.Langzeit AS 'Langzeit', faktor AS 'Faktor',
  me.databaseName, avm.Tagenutzung,CONVERT(FLOAT,Tagenutzung) / CONVERT(FLOAT,DATEDIFF(dd, @von,@bis))
  FROM ACTIVE_VEHICLES_MONTHLY avm, dbo.Mandant m, dbo.MANDANT_DB_ENVIRONMENT me WHERE avm.MandantID=m.id AND avm.EnvironmentID=me.PK AND avm.MONTH=@month AND avm.YEAR=@year
  ORDER BY m.companyname
SELECT MAX(m.abasId) AS Kundennummer,MAX(me.databaseName), MAX(m.companyname) as Firma,ROUND(SUM(avm.anzahlkfz),0) AS Fahrzeuge, Langzeit 
  FROM ACTIVE_VEHICLES_MONTHLY avm, dbo.Mandant m, dbo.MANDANT_DB_ENVIRONMENT me  WHERE avm.MandantID=m.id AND  avm.EnvironmentID=me.PK AND avm.MONTH=@month AND avm.YEAR=@year 
  GROUP BY avm.MandantID,me.pk,Langzeit ORDER BY MAX(m.abasid)


GO
/****** Object:  StoredProcedure [dbo].[PFLEGE_XML_LOG_MANDANT_ENVIRONMENT]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
