CREATE PROCEDURE [dbo].[PFLEGE_XML_LOG_MANDANT_ENVIRONMENT](
@mandantId INT = NULL,  
@environment NVARCHAR(32) = '', 
@type NVARCHAR(32) = '',
@logType NVARCHAR(128) = '',
@dataType NVARCHAR(128) = 'output',
@message NVARCHAR(MAX) = ''
)
AS SET NOCOUNT ON
	DECLARE @AbasIdAux INT, @ip VARCHAR(255), @dbname VARCHAR(255), @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)='',
	@data XML = NULL, @logEntry NVARCHAR(MAX)='', @now VARCHAR(32)='', @xmlMainLogTag VARCHAR(128)=@logType+'Log', @mandName VARCHAR(255)=ISNULL((SELECT TOP 1 companyname FROM dbo.Mandant WHERE id = @mandantId),'NO_COMPANY_NAME')
	IF (@environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS))
		BEGIN
			PRINT 'Environment ist nicht erkannt!'
			RETURN
		END
	IF (@type NOT IN ('SCHEMA','DATA'))
		BEGIN
			PRINT 'Type ist nicht erkannt!'
			RETURN
		END    
	IF (@logType NOT IN ('create','upload','translation','impExpTrans','compare'))
		BEGIN
			PRINT @logType+' ist nicht erkannt!'
			RETURN
		END    		    
      
	IF NOT EXISTS(SELECT id FROM dbo.Mandant WHERE id = @mandantId)
		BEGIN
			PRINT 'Live Daten des Kunden sind nicht gepflegt!. Bitte pflegen Sie die Daten in der Tabelle Mandant.'
			RETURN
		END
 
	SET @now = dbo.GET_ISO_DATETIME(DEFAULT, DEFAULT)--'create','upload','translation','importExportTranslation'
    SET @logEntry = '<log time="'+@now+'">'+@message+'</log>' 
	
	IF EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type) AND (@message IS NOT NULL AND @message <> '')
	   BEGIN
			SELECT @data = (SELECT TOP 1 
								CASE 
									WHEN @logType = 'create' THEN CREATE_COMPARE_JOB_LOG
									WHEN @logType = 'upload' THEN UPLOAD_JOB_LOG
									WHEN @logType = 'translation' THEN TRANSLATIONS_JOB_LOG
									WHEN @logType = 'impExpTrans' THEN IMPORT_EXPORT_TRANSLATIONS_JOB_LOG
									WHEN @logType = 'compare' THEN COMPARE_RESULT_LOGS
								END
							 FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
							)
			--SET @message = dbo.GET_XML_ESCAPED(@message)
			IF (@data IS NULL) 
				SET @data = 
				'<'+@xmlMainLogTag+' mandant="'+dbo.GET_XML_ESCAPED(@mandName)+'" time="'+@now+'" environment="'+@environment+'" type="'+@type+'">
					<logs></logs>
				</'+@xmlMainLogTag+'>'
			IF (@logType = 'create')
				BEGIN 
					BEGIN	---PRINT 'sfad'						
						--SET @data.modify('insert sql:variable("@logEntry") into (/createLog)[1]') 
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/createLog/logs)[1]') 
						UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET CREATE_COMPARE_JOB_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
					END 
				END 
			IF (@logType = 'upload')
				BEGIN 
					BEGIN
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/uploadLog/logs)[1]') 							
						UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET UPLOAD_JOB_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
					END 
				END 
			IF (@logType = 'translation')
				BEGIN 
					BEGIN		
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/translationLog/logs)[1]') 											
						UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET TRANSLATIONS_JOB_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
					END 
				END 
			IF (@logType = 'impExpTrans')
				BEGIN 
					BEGIN				
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/impExpTransLog/logs)[1]') 																			
						UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET IMPORT_EXPORT_TRANSLATIONS_JOB_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
					END 
				END
			IF (@logType = 'compare')
				BEGIN 
					BEGIN				
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/compareLog/logs)[1]') 																			
						UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET COMPARE_RESULT_LOGS = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
					END 
				END                
		END 
 
GO
