CREATE PROCEDURE [dbo].[PFLEGE_XML_LOG_MANDANT_WEB_PRODUKTE_UPDATE](
@mandantId INT = NULL,  
@environment NVARCHAR(32) = '',
@logType NVARCHAR(128) = '',
@dataType NVARCHAR(128) = 'output',
@message NVARCHAR(MAX) = ''
)
AS SET NOCOUNT ON
	DECLARE @AbasIdAux INT, @ip VARCHAR(255), @dbname VARCHAR(255), @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)='',
	@data XML = NULL, @logEntry NVARCHAR(MAX)='', @now VARCHAR(32)='', @xmlMainLogTag VARCHAR(128)=@logType+'Log', @mandName VARCHAR(255)=ISNULL((SELECT TOP 1 companyname FROM dbo.Mandant WHERE id = @mandantId),'NO_COMPANY_NAME')
	IF (@environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS))
		BEGIN
			PRINT 'Environment ist nicht erkannt!'
			RETURN
		END  
	IF (@logType NOT IN ('createCRentWebFolder','createReservierungFolder','JasperMR','CRentWebMR','CX9GitLabJasperApprovedMR','CX9GitLabCRentWebApprovedMR'))
		BEGIN
			PRINT @logType+' ist nicht erkannt!'
			RETURN
		END    		    
      
	IF NOT EXISTS(SELECT id FROM dbo.Mandant WHERE id = @mandantId)
		BEGIN
			PRINT 'Live Daten des Kunden sind nicht gepflegt!. Bitte pflegen Sie die Daten in der Tabelle Mandant.'
			RETURN
		END
 
	SET @now = dbo.GET_ISO_DATETIME(DEFAULT, DEFAULT)--'create','upload','translation','importExportTranslation'
    SET @logEntry = '<log time="'+@now+'">'+@message+'</log>' 

	IF EXISTS(SELECT PK FROM dbo.WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND @message IS NOT NULL AND @message <> '')
	   BEGIN   
			SELECT @data = (SELECT TOP 1 
								CASE 
									WHEN @logType = 'createCRentWebFolder' THEN CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG
									WHEN @logType = 'createReservierungFolder' THEN CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG
									WHEN @logType = 'JasperMR' THEN CREATE_GITLAB_JASPERMR_LOG
									WHEN @logType = 'CRentWebMR' THEN CREATE_GITLAB_CRENTWEBMR_LOG
									WHEN @logType = 'CX9GitLabJasperApprovedMR' THEN JASPER_MR_APPROVED_LOG
									WHEN @logType = 'CX9GitLabCRentWebApprovedMR' THEN CRWEB_MR_APPROVED_LOG
								END
							 FROM dbo.WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment
							) 
			IF (@data IS NULL) 
				SET @data = 
				'<'+@xmlMainLogTag+' mandant="'+dbo.GET_XML_ESCAPED(@mandName)+'" time="'+@now+'" environment="'+@environment+'">
					<logs></logs>
				</'+@xmlMainLogTag+'>'
			IF (@logType = 'createCRentWebFolder')
				BEGIN 
					BEGIN							
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/createCRentWebFolderLog/logs)[1]') 
						UPDATE dbo.WEB_PRODUKTE_LOG_UPDATE SET CREATE_WEBSERVER_CRENTWEB_FOLDER_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment
					END 
				END 
			IF (@logType = 'createReservierungFolder')
				BEGIN 
					BEGIN
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/createReservierungFolderLog/logs)[1]') 							
						UPDATE dbo.WEB_PRODUKTE_LOG_UPDATE SET CREATE_WEBSERVER_RESERVIERUNG_FOLDER_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment
					END 
				END 
			IF (@logType = 'JasperMR')
				BEGIN 
					BEGIN		
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/JasperMRLog/logs)[1]') 											
						UPDATE dbo.WEB_PRODUKTE_LOG_UPDATE SET CREATE_GITLAB_JASPERMR_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment
					END 
				END 
			IF (@logType = 'CRentWebMR')
				BEGIN 
					BEGIN				
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/CRentWebMRLog/logs)[1]') 																			
						UPDATE dbo.WEB_PRODUKTE_LOG_UPDATE SET CREATE_GITLAB_CRENTWEBMR_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment
					END 
				END
			IF (@logType = 'CX9GitLabJasperApprovedMR')
				BEGIN 
					BEGIN				
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/CX9GitLabJasperApprovedMRLog/logs)[1]') 																			
						UPDATE dbo.WEB_PRODUKTE_LOG_UPDATE SET JASPER_MR_APPROVED_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment
					END 
				END
			IF (@logType = 'CX9GitLabCRentWebApprovedMR')
				BEGIN 
					BEGIN				
						SET @data.modify('insert (<log time="{sql:variable("@now")}" type="{sql:variable("@dataType")}">{sql:variable("@message")}</log> ) into (/CX9GitLabCRentWebApprovedMRLog/logs)[1]') 																			
						UPDATE dbo.WEB_PRODUKTE_LOG_UPDATE SET CRWEB_MR_APPROVED_LOG = @data WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment
					END 
				END				                
		END 
 
GO
