CREATE PROCEDURE [dbo].[PFLEGE_XML_MANDANT_ENVIRONMENT](
@mandantId INT = NULL, 
@AbasId INT = NULL,
@environment NVARCHAR(30) = '',
@type NVARCHAR(30) = '',
@data XML = NULL,
@CREATE_COMPARE_JOB_LOG XML = NULL,
@UPLOAD_JOB_LOG XML = NULL,
@IMPORT_EXPORT_TRANSLATIONS_JOB_LOG XML = NULL,
@TRANSLATIONS_JOB_LOG XML = NULL,
@updateScript BIT = 1
)
AS SET NOCOUNT ON
	DECLARE @AbasIdAux INT, @ip VARCHAR(255), @dbname VARCHAR(255), @dbuser VARCHAR(512)='', @dbpassword VARCHAR(512)='' 
	IF (@environment NOT IN (SELECT ENVIRONMENT FROM dbo.MAND_DB_SCHEMA_DATA_ENVIRONMENTS))
		BEGIN
			PRINT 'Environment ist nicht erkannt!'
			RETURN
		END
	IF (@type NOT IN ('SCHEMA','DATA'))
		BEGIN
			PRINT 'Type ist nicht erkannt!'
			RETURN
		END        
	IF (@data IS NULL AND @CREATE_COMPARE_JOB_LOG IS NULL AND @UPLOAD_JOB_LOG IS NULL AND @TRANSLATIONS_JOB_LOG IS NULL AND @IMPORT_EXPORT_TRANSLATIONS_JOB_LOG IS NULL)
		BEGIN
			PRINT 'Update Daten [CREATE_COMPARE_JOB_LOG, etc] wurden nicht erkannt!'
			RETURN
		END        
	IF NOT EXISTS(SELECT id FROM dbo.Mandant WHERE id = @mandantId)
		BEGIN
			PRINT 'Live Daten des Kunden sind nicht gepflegt!. Bitte pflegen Sie die Daten in der Tabelle Mandant.'
			RETURN
		END
    SET @AbasIdAux = ISNULL((SELECT abasId FROM dbo.Mandant WHERE id = @mandantId),0)
	IF (@AbasIdAux = 0 AND ISNULL(@AbasId,0) > 0)
		BEGIN
			PRINT 'AbasId des Kunden ist nicht gepflegt. Der Eintrag wird aktualisert.'
			UPDATE dbo.Mandant SET abasId = @AbasId WHERE id = @mandantId			
		END
    IF (@Environment IN ('LIVE', 'DEFAULT'))
		BEGIN
			DECLARE @env_auxiliary NVARCHAR(128) = CASE WHEN @Environment = 'LIVE' THEN 'DEFAULT' ELSE @Environment END      
			--take the live daten      
			SELECT @ip=ISNULL(databaseIp,'')+CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '/'+databaseInstance ELSE '' END, 
					@dbname=ISNULL(databaseName,''),
					@dbuser=ISNULL(databaseUser,''), @abasId=ISNULL(abasId,0) FROM dbo.Mandant WHERE id=@MandantId	
	
			IF (EXISTS (SELECT * FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@env_auxiliary and version = '6.0'))
				BEGIN  
					SELECT TOP 1 @dbname=ISNULL(databaseName,''), @dbuser=ISNULL(databaseUser,''), @dbpassword=dbo.SEC_GetPWCOde(ISNULL(databaseUser,'')), 
					@ip=ISNULL(databaseIp,'')+
					   CASE WHEN ISNULL(databaseInstance,'')<>'' THEN '\'+databaseInstance ELSE '' END + 
						CASE WHEN dbo.isClientExtern(@MandantId)=1 AND ISNUMERIC(databasePort)=1 /*intern extern unterschied*/  THEN ','+CAST(databasePort AS VARCHAR(32)) ELSE '' END   --tsql port sintax				
					FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MandantId AND type=@env_auxiliary and version = '6.0'	 
				END 
			SET @dbpassword = dbo.SEC_GetPWCOde(@dbuser)
			SET @data.modify('replace value of (/Project/DataSource2/ServerName/text())[1] with sql:variable("@ip")')
			SET @data.modify('replace value of (/Project/DataSource2/DatabaseName/text())[1] with sql:variable("@dbname")')
			SET @data.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@dbuser")')
			SET @data.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@dbpassword")')								
			SET @data.modify('replace value of (/Project/DataSource2/Password/@encrypted)[1] with "0"')	
			UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET EXECUTED = 1, LAST_EXECUTION_TIME=CURRENT_TIMESTAMP WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = 'ACC' AND TYPE = @type							
		END
    IF (@updateScript = 1)
		BEGIN
			EXEC dbo.AUTOMATISCHE_PFLEGE_MANDANT_API_ENVIRONMENTS @mandantId = @mandantId, @environment = @environment, @APP_TYPE = 'C-CHEQ'  
			EXEC dbo.AUTOMATISCHE_PFLEGE_MANDANT_API_ENVIRONMENTS @mandantId = @mandantId, @environment = @environment, @APP_TYPE = 'C-SHARE'        			
		END      
	IF NOT EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type)
		BEGIN
			INSERT INTO dbo.DB_SCHEMA_DATA_COMPARE_UPDATE (MANDANT_ID, ENVIRONMENT, TYPE, DATA)
			SELECT @mandantId, @environment, @type, @data
		END 
	IF EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type) AND @data IS NOT NULL
	   BEGIN
			UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET DATA=@data  WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
		END 
	/*IF EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type) AND @CREATE_COMPARE_JOB_LOG IS NOT NULL
	   BEGIN
			UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET CREATE_COMPARE_JOB_LOG=@CREATE_COMPARE_JOB_LOG WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
		END
	IF EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type) AND @UPLOAD_JOB_LOG IS NOT NULL
	   BEGIN
			UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET UPLOAD_JOB_LOG=@UPLOAD_JOB_LOG WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
		END		 
	IF EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type) AND @TRANSLATIONS_JOB_LOG IS NOT NULL
	   BEGIN
			UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET TRANSLATIONS_JOB_LOG=@TRANSLATIONS_JOB_LOG WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
		END
	IF EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type) AND @IMPORT_EXPORT_TRANSLATIONS_JOB_LOG IS NOT NULL
	   BEGIN
			UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET IMPORT_EXPORT_TRANSLATIONS_JOB_LOG=@IMPORT_EXPORT_TRANSLATIONS_JOB_LOG WHERE MANDANT_ID = @mandantId AND ENVIRONMENT = @environment AND TYPE = @type
		END*/
GO
/****** Object:  StoredProcedure [dbo].[PFLEGE_XML_MANDANT_ENVIRONMENT_PARSER]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[PFLEGE_XML_MANDANT_ENVIRONMENT_PARSER](
@mandantId INT = NULL, 
@AbasId INT = NULL,
@environment NVARCHAR(30) = '',
@type NVARCHAR(30) = '',
@data NVARCHAR(MAX) = NULL,
@CREATE_COMPARE_JOB_LOG NVARCHAR(MAX) = NULL,
@UPLOAD_JOB_LOG NVARCHAR(MAX) = NULL,
@IMPORT_EXPORT_TRANSLATIONS_JOB_LOG NVARCHAR(MAX) = NULL,
@TRANSLATIONS_JOB_LOG NVARCHAR(MAX) = NULL
)
AS
BEGIN 
	DECLARE @xmlData1 XML = NULL
	DECLARE @xmlData2 XML = NULL
	DECLARE @xmlData3 XML = NULL
	DECLARE @xmlData4 XML = NULL
    
	IF (@data IS NOT NULL)SET @data = REPLACE(@data,'BATCHSPECIALCHARACTER','!')
	IF (@CREATE_COMPARE_JOB_LOG IS NOT NULL)
		SET @xmlData1 = CAST('<createCompareJobLogs time="'+dbo.GET_ISO_DATETIME(DEFAULT, DEFAULT)+'">'+(@CREATE_COMPARE_JOB_LOG)+'</createCompareJobLogs>' AS XML)
	IF (@UPLOAD_JOB_LOG IS NOT NULL)
		SET @xmlData2 = CAST('<uploadJobLogs time="'+dbo.GET_ISO_DATETIME(DEFAULT, DEFAULT)+'">'+(@UPLOAD_JOB_LOG)+'</uploadJobLogs>' AS XML)
	IF (@TRANSLATIONS_JOB_LOG IS NOT NULL)
		SET @xmlData3 = CAST('<translationJobLogs time="'+dbo.GET_ISO_DATETIME(DEFAULT, DEFAULT)+'">'+(@TRANSLATIONS_JOB_LOG)+'</translationJobLogs>' AS XML)
	IF (@IMPORT_EXPORT_TRANSLATIONS_JOB_LOG IS NOT NULL)
		SET @xmlData4 = CAST('<translationJobLogs time="'+dbo.GET_ISO_DATETIME(DEFAULT, DEFAULT)+'">'+(@IMPORT_EXPORT_TRANSLATIONS_JOB_LOG)+'</translationJobLogs>' AS XML)
	EXEC dbo.PFLEGE_XML_MANDANT_ENVIRONMENT @MandantId = @mandantId, @AbasId = @AbasId, @environment = @environment, 
	@type = @type, @data=@data, @CREATE_COMPARE_JOB_LOG=@xmlData1, @UPLOAD_JOB_LOG=@xmlData2, @TRANSLATIONS_JOB_LOG = @xmlData3, @IMPORT_EXPORT_TRANSLATIONS_JOB_LOG = @xmlData4
END
GO
/****** Object:  StoredProcedure [dbo].[PROD___dfd]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
