CREATE PROCEDURE [dbo].[PROD___dfd]  @tableName NVARCHAR(255)= 'MY_TEST_JOSE'
AS
BEGIN
	SET NOCOUNT ON 
	DECLARE @pas NVARCHAR(MAX)
	DECLARE @dfm NVARCHAR(MAX)

	DECLARE @path NVARCHAR(2048) = dbo.UPDATES_TMP_DEPLOY_FOLDER()+'\tests\'
	DECLARE @filename NVARCHAR(2048) = ''

	DECLARE @tableDefinition TABLE (PK INT NOT NULL IDENTITY(1,1), field NVARCHAR(255) NULL, fieldDefinition NVARCHAR(255), isIdentity VARCHAR(1) NULL, tsqlDataType VARCHAR(128) NULL)
 
	INSERT INTO @tableDefinition (field , fieldDefinition , isIdentity)
 		SELECT COLUMN_NAME, dbo.fn_GetTFieldDDL(@tableName,COLUMN_NAME,DEFAULT), ISNULL(COLUMNPROPERTY(object_id(TABLE_SCHEMA+'.'+TABLE_NAME), COLUMN_NAME, 'IsIdentity'),0)  FROM INFORMATION_SCHEMA.COLUMNS 
 		WHERE TABLE_NAME = @tableName -- ORDER BY col
 
SET @pas=
'unit '+@tableName+';

interface

uses
  Windows, Messages, SysUtils, Variants, Classes, Graphics, Controls, Forms,
  Dialogs, ActnList, DB, StdCtrls, Buttons, ExtCtrls, Grids,
  DBGrids, Globalvars, ADODB, cxGraphics, cxControls, cxLookAndFeels,
  cxLookAndFeelPainters, cxStyles, cxCustomData, cxFilter, cxData,
  cxDataStorage, cxEdit, cxDBData, cxGridCustomTableView, cxGridTableView,
  cxGridDBTableView, cxGridLevel, cxClasses, cxGridCustomView, cxGrid,
  UDispoPanel, ULANG, cxNavigator, dxDateRanges, dxScrollbarAnnotations, System.Actions;

type
  T'+@tableName+'_FORM = class(TForm)
    MainPanel_'+@tableName+': THeaderPanel;
    btnAAbbr: TBitBtn;
    btnANeu: TBitBtn;
    btnALoe: TBitBtn;
    cxgrd'+@tableName+': TcxGrid;
    CXGrid_'+@tableName+'_DBTableView1: TcxGridDBTableView;
    cxgrdlvl'+@tableName+'Level1: TcxGridLevel;
    ds'+@tableName+': TDataSource;
