CREATE PROCEDURE [dbo].[PY_PROCESS_MANDANT_ENVIRONMENT_REQUEST] (@INPUT_CLIENT_DATA XML = NULL, @unique_confirm_transaction BIT = 0)  
AS
BEGIN  -- Author José
	 SET CONCAT_NULL_YIELDS_NULL ON  
     SET NOCOUNT ON  
     SET ANSI_WARNINGS ON
     SET ANSI_PADDING ON
	 SET CONCAT_NULL_YIELDS_NULL ON
	DECLARE @JSON_RESPONSE NVARCHAR(MAX) = ''
	DECLARE @JASPER_TYP NVARCHAR(64) = ''
	DECLARE @URL_PARAMS NVARCHAR(255) = ''
	DECLARE @JASPER_PARAMS NVARCHAR(MAX) = ''
	DECLARE @SET_VARS NVARCHAR(MAX) = ''
	
	DECLARE @message NVARCHAR(MAX) = 'connection successfully'
	DECLARE @EMAILContents NVARCHAR(MAX) = ''
	DECLARE @EMAILRecipients VARCHAR(1024) = ''
	DECLARE @messageTitle NVARCHAR(128) = 'Information!'
	DECLARE @OBJECT_RESULT NVARCHAR(MAX) = '{}'
	DECLARE @action VARCHAR(64) = ''
	DECLARE @MandantId INT = 98
	DECLARE @Type VARCHAR(64) = ''
	DECLARE @WINDOW_WIDTH VARCHAR(64) = ''
	DECLARE @WINDOW_HEIGHT VARCHAR(64) = ''
	DECLARE @ABAS_TASK_NO VARCHAR(64) = ''
	DECLARE @AUFWAND_AN VARCHAR(2048) = ''
	DECLARE @INFO_AN_MAILS VARCHAR(2048) = ''
	DECLARE @ABAS_MAIL_INFO_AN VARCHAR(2048) = ''
	DECLARE @LIKE_PARAM_NAME VARCHAR(2048) = ''
		
	DECLARE @Kundenbetreuer VARCHAR(1024) = ''
	DECLARE @RDPS_AN VARCHAR(1024) = ''
	DECLARE @E_MAILSUBJECT NVARCHAR(1024) = ''
	DECLARE @GIT_PROJEKT NVARCHAR(1024) = ''
	DECLARE @BRANCH NVARCHAR(1024) = ''
	DECLARE @PRIVATE_BRANCH NVARCHAR(1024) = ''
	
	DECLARE @COMMIT_MSG NVARCHAR(2048) = ''
	DECLARE @TEAMVIEWER_PWD NVARCHAR(2048) = ''
	DECLARE @CX9_PWD_ALGO NVARCHAR(2048) = ''
	
	DECLARE @TEAMVIEWER_AN NVARCHAR(2048) = ''
	 		  --,"TEAMVIEWER_PWD","TEAMVIEWER_AN"
	DECLARE @deployPath VARCHAR(2048) = dbo.UPDATES_TMP_DEPLOY_FOLDER() 
	DECLARE @deployFile VARCHAR(2048) = ''
	DECLARE @DatabaseName VARCHAR(255) = ''
	
	--SET @deployFile = @deployPath+'\deployment6\script.sh'
 			
	DECLARE @manage_linked_server VARCHAR(1) = ''
	DECLARE @optimize_db VARCHAR(1) = ''
	DECLARE @INFO_AN_HARDWARE VARCHAR(1) = ''
	
	DECLARE @JMRMergeLIVE VARCHAR(1) = ''
	DECLARE @UpdateDate VARCHAR(32) = ''
	DECLARE @MRJASPERNUMMER VARCHAR(4) = ''
	DECLARE @MRCRWNUMMER1 VARCHAR(4) = ''
	DECLARE @MRCRWNUMMER2 VARCHAR(4) = ''
	DECLARE @messageType VARCHAR(64) = 'showinfo'
	DECLARE @mandant_environment_pk INT
    DECLARE @newTSQL NVARCHAR(MAX) = ''
    DECLARE @newTSQLExecuteOn NVARCHAR(32) = ''
	DECLARE @uuid INT
    DECLARE @sql_in_separated_process VARCHAR(1) = '0'  
    DECLARE @other_cmd VARCHAR(256) = 'echo clossing window in 60 seconds ; sleep 60 ; exit ' 
	DECLARE @job NVARCHAR(MAX) = ''
	DECLARE @confirm_output NVARCHAR(MAX) = ''
	DECLARE @separated_process VARCHAR(MAX) = ''
	DECLARE @separated_process_type VARCHAR(16) = 'DB'
	--, "separated_process_type":"'+@separated_process_type+'"	 
	--"other_cmd":"echo clossing window in 30 seconds && sleep 30 && exit"
	DECLARE @notupdatecapable TABLE(mandant_id INT NULL, environtment VARCHAR(32) NULL)
	DECLARE @updateTriggerContents VARCHAR(MAX) = ''
	DECLARE @jsonLinkedResponse NVARCHAR(MAX) = '{}'

 
	IF (@INPUT_CLIENT_DATA IS NULL)
		SET @message = 'Die erforderlichen Parameter wurden nicht übergeben'
	SET NOCOUNT ON
	BEGIN TRY
		IF (@INPUT_CLIENT_DATA IS NOT NULL) 
			BEGIN
				SET @mandant_environment_pk = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="PK"]/text())[1]','INT')),'')
				SET @MandantId = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="MandantId"]/text())[1]','INT')),'')
				SET @Type = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="Type"]/text())[1]','VARCHAR(8)')),'')
				SET @action = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/@action)','VARCHAR(64)')),'')  
				SET @AUFWAND_AN = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="AUFWAND_AN"]/text())[1]','VARCHAR(2048)')),'')
				SET @INFO_AN_MAILS = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="INFO_AN_MAILS"]/text())[1]','VARCHAR(2048)')),@INFO_AN_MAILS)
				SET @INFO_AN_MAILS = REPLACE(@INFO_AN_MAILS,'a.a_@cx9.de','')
				
				SET @JASPER_TYP = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="JASPER_TYP"]/text())[1]','VARCHAR(64)')),@JASPER_TYP)
				SET @URL_PARAMS = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="URL_PARAMS"]/text())[1]','VARCHAR(255)')),@URL_PARAMS)
				SET @JASPER_PARAMS = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="JASPER_PARAMS"]/text())[1]','VARCHAR(MAX)')),@JASPER_PARAMS)    
				--
				SET @ABAS_MAIL_INFO_AN = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="ABAS_MAIL_INFO_AN"]/text())[1]','VARCHAR(2048)')),'')
				SET @ABAS_MAIL_INFO_AN = REPLACE(@ABAS_MAIL_INFO_AN,'a.a_@cx9.de','')
				SET @ABAS_TASK_NO = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="ABAS_TASK_NO"]/text())[1]','VARCHAR(64)')),'')
				SET @Kundenbetreuer = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="Kundenbetreuer"]/text())[1]','VARCHAR(1024)')),'')
				SET @RDPS_AN = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="RDPS_AN"]/text())[1]','VARCHAR(1024)')),'')
				SET @manage_linked_server = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="manage_linked_server"]/text())[1]','VARCHAR(1)')),'')
				SET @optimize_db = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="optimize_db"]/text())[1]','VARCHAR(1)')),'')
				
				SET @INFO_AN_HARDWARE = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="INFO_AN_HARDWARE"]/text())[1]','VARCHAR(1)')),'')
				
				SET @JMRMergeLIVE = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="JMRMergeLIVE"]/text())[1]','VARCHAR(1)')),'0')
				SET @UpdateDate = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="UpdateDate"]/text())[1]','VARCHAR(32)')),'')
				SET @MRJASPERNUMMER = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="MRJASPERNUMMER"]/text())[1]','VARCHAR(4)')),'')
				SET @MRCRWNUMMER1 = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="MRCRWNUMMER1"]/text())[1]','VARCHAR(4)')),'')
				SET @MRCRWNUMMER2 = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="MRCRWNUMMER2"]/text())[1]','VARCHAR(4)')),'')
				SET @LIKE_PARAM_NAME = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="LIKE_PARAM_NAME"]/text())[1]','VARCHAR(2048)')),'')
				SET @WINDOW_WIDTH = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="WINDOW_WIDTH"]/text())[1]','VARCHAR(64)')),'')
				SET @WINDOW_HEIGHT = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="WINDOW_HEIGHT"]/text())[1]','VARCHAR(64)')),'')
				SET @GIT_PROJEKT = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="GIT_PROJEKT"]/text())[1]','NVARCHAR(1024)')),@GIT_PROJEKT)
				SET @PRIVATE_BRANCH = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="PRIVATE_BRANCH"]/text())[1]','NVARCHAR(1024)')),@PRIVATE_BRANCH)
				SET @BRANCH = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="BRANCH"]/text())[1]','NVARCHAR(1024)')),@BRANCH)
				SET @COMMIT_MSG = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="COMMIT_MSG"]/text())[1]','NVARCHAR(2048)')),@COMMIT_MSG)
				SET @TEAMVIEWER_AN = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="TEAMVIEWER_AN"]/text())[1]','NVARCHAR(2048)')),@TEAMVIEWER_AN)
				SET @TEAMVIEWER_PWD = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="TEAMVIEWER_PWD"]/text())[1]','NVARCHAR(2048)')),@TEAMVIEWER_PWD)
				SET @CX9_PWD_ALGO = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="CX9_PWD_ALGO"]/text())[1]','NVARCHAR(2048)')),@CX9_PWD_ALGO)
				SET @DatabaseName = ISNULL((@INPUT_CLIENT_DATA.value(N'(/input[1]/param[@id="DatabaseName"]/text())[1]','NVARCHAR(255)')),@DatabaseName)
			
				 --
				SET @message = 'Missing requirements in input parameters: '
				--
				IF (@action LIKE 'test_tmp_shared_folder' AND ISNUMERIC(@mandant_environment_pk) = 1)
					BEGIN 
						DECLARE @UPDATES_TMP_DEPLOY_FOLDER_FILE NVARCHAR(2048)= dbo.UPDATES_TMP_DEPLOY_FOLDER()+'\getTSQLSkriptCleanACCDB_'+dbo.GET_MANDANT_NAME_PARSED(@MandantId)+'_'+@DatabaseName+'.txt'
						DECLARE @UPDATES_TMP_FILE_CONTENTS NVARCHAR(MAX)= dbo.getTSQLCleanACCDB(@DatabaseName)
						EXEC dbo.WriteFile @fileName = @UPDATES_TMP_DEPLOY_FOLDER_FILE, @fileContents = @UPDATES_TMP_FILE_CONTENTS
						SET @message = 'Gute Nachrichten!'
						SET @UPDATES_TMP_DEPLOY_FOLDER_FILE = REPLACE(@UPDATES_TMP_DEPLOY_FOLDER_FILE,'\','\\')
						SET @confirm_output='{"INFO":"\nBitte folgende Datei checken", "Datei":"'+@UPDATES_TMP_DEPLOY_FOLDER_FILE+'"}'
						--SET @confirm_output='{"INFO":"Dieser Prozess ", "Grund 1":"Es kann lange dauern, bist du manuell alles geändert hast", "Grund 2":"Ich bin nicht verantwortlich für deine Fehler :-)", "Bitte ":"enjoy!!"}'		 
								 
						SET @OBJECT_RESULT = @confirm_output
					 	SET @messageTitle = 'Enjoy!!!'	
						SET @messageType = 'showinfo' 
					END	 
				IF (@action LIKE 'kunden_open_%' AND ISNUMERIC(@mandant_environment_pk) = 1)
					BEGIN
						DECLARE @OPEN_PK VARCHAR(255) = REPLACE(@action, 'kunden_open_','')
						SET @message = ''
						SET @confirm_output='{"INFO":"Dieser Prozess wurde bereits in der Konsole gestartet\nBitte sofort mit den Änderungen anfangen", "Grund 1":"Es kann lange dauern, bist du manuell alles geändert hast", "Grund 2":"Ich bin nicht verantwortlich für deine Fehler :-)", "Bitte ":"enjoy!!"}'		 
						SET @OBJECT_RESULT = @confirm_output
					 	SET @messageTitle = 'Enjoy!!!'	
						SET @messageType = 'showinfo'
						SET @sql_in_separated_process = '1'
						SET @separated_process_type = 'console' 
					    SET @separated_process = 'sh ~/bin/exec.sh [\\\"gnome-system-monitor\\\" \\\"teamviewer\\\" \\\"icedove\\\" \\\"nautilus ~/updates/\\\" \\\"nautilus ~/bin/\\\"] ''0''' 
					    IF (@OPEN_PK = 'GIT_OPEN_PROJECT')
							SET @separated_process = dbo.__fnGET_USABLE_LINK_STRING(@mandant_environment_pk,@OPEN_PK,@GIT_PROJEKT,@BRANCH,'')
						ELSE 
							SET @separated_process = dbo.__fnGET_USABLE_LINK_STRING(@mandant_environment_pk,@OPEN_PK,@JASPER_TYP,@URL_PARAMS,@JASPER_PARAMS)
						--sh ~/bin/exec.sh ["gnome-system-monitor" "teamviewer" "icedove" "nautilus ~/updates/" "nautilus ~/bin/"] '0'
						
					END    
