					END 					  				
 
			END 
		SET @JSON_RESPONSE = '{"title":"'+@messageTitle+'","message":"'+@message+'", "type":"'+@messageType+'", "result":['+@OBJECT_RESULT+'], "newTSQL":"'+@newTSQL+'", "newTSQLExecuteOn":"'+@newTSQLExecuteOn+'", "sql_in_separated_process":"'+@sql_in_separated_process+'","other_cmd":"'+@other_cmd+'", "separated_process_type":"'+@separated_process_type+'", "separated_process":"'+@separated_process+'", "set_vars":"'+@SET_VARS+'"}'
