/****** Object:  StoredProcedure [dbo].[RESET_ALL_COMPARE_CREDENTIALS]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[RESET_ALL_COMPARE_CREDENTIALS]  
AS
BEGIN  -- Author José
	SET NOCOUNT ON

		DECLARE @MANDANT_ID INT
		DECLARE @ENVIRONMENT NVARCHAR(32)
		DECLARE cursor_name CURSOR FAST_FORWARD READ_ONLY FOR SELECT mandant_id,type FROM [BETHUNDER_JL].dbo.MANDANT_DB_ENVIRONMENT WHERE type IN ('DEFAULT','LIVE','ACC')
		OPEN cursor_name

		FETCH NEXT FROM cursor_name INTO @MANDANT_ID, @ENVIRONMENT

		WHILE @@FETCH_STATUS = 0
		BEGIN
			EXEC dbo.RESET_COMPARE_CREDENTIALS @MANDANT_ID = @MANDANT_ID, @ENVIRONTMENT = @ENVIRONMENT
			FETCH NEXT FROM cursor_name INTO @MANDANT_ID, @ENVIRONMENT
		END

		CLOSE cursor_name
		DEALLOCATE cursor_name
 END
GO
/****** Object:  StoredProcedure [dbo].[RESET_COMPARE_CREDENTIALS]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[RESET_COMPARE_CREDENTIALS] (@MANDANT_ID INT = NULL, @ENVIRONTMENT VARCHAR(32) =''/*, @TYPE VARCHAR(32) =''*/ )
AS
BEGIN  -- Author José
	SET NOCOUNT ON

	DECLARE @data_schema_compare_file XML
 
	DECLARE @PK INT
	DECLARE @existNodeTableActionPrintDok NVARCHAR(MAX)
	DECLARE @env NVARCHAR(128) = @ENVIRONTMENT
	DECLARE @dbuser NVARCHAR(1024) = @ENVIRONTMENT
	DECLARE @dbpassword NVARCHAR(1024) = @ENVIRONTMENT
	DECLARE @env_auxiliary NVARCHAR(128) = CASE WHEN @env = 'LIVE' THEN 'DEFAULT' ELSE @env END 
      
 
	SELECT TOP 1  @dbuser=databaseUser, @dbpassword=  	dbo.SEC_GetPWCOde(databaseUser)		 
	FROM [dbo].[MANDANT_DB_ENVIRONMENT] WHERE mandant_id = @MANDANT_ID AND type=@env_auxiliary ORDER BY version DESC	 
		 

	DECLARE CURSOR_RESET_COMPARE_CREDENTIALS CURSOR  
	   FOR SELECT --TOP 1
				DATA, MANDANT_ID,PK  FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE   
				WHERE-- TYPE = @TYPE AND
				  (MANDANT_ID = @MANDANT_ID AND ENVIRONMENT = @ENVIRONTMENT)
			--AND pk <> 1689
	OPEN CURSOR_RESET_COMPARE_CREDENTIALS  
	FETCH NEXT FROM CURSOR_RESET_COMPARE_CREDENTIALS INTO @data_schema_compare_file,@MANDANT_ID, @PK
  
	WHILE @@FETCH_STATUS = 0  
	BEGIN  
     
		--SET @data_schema_compare_file.modify('delete //*/ColumnName[text()="Legende_CRW:Legende_CRW"]/parent::value')
		--SELECT @data_schema_compare_file 
		SET @data_schema_compare_file.modify('replace value of (/Project/DataSource2/Username/text())[1] with sql:variable("@dbuser")')
		SET @data_schema_compare_file.modify('replace value of (/Project/DataSource2/Password/text())[1] with sql:variable("@dbpassword")')
		--SELECT @data_schema_compare_file
		--print @pk
		UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET DATA = @data_schema_compare_file WHERE PK = @PK  

		FETCH NEXT FROM CURSOR_RESET_COMPARE_CREDENTIALS	INTO @data_schema_compare_file, @MANDANT_ID, @PK
	END   
	CLOSE CURSOR_RESET_COMPARE_CREDENTIALS;  
	DEALLOCATE CURSOR_RESET_COMPARE_CREDENTIALS;	 
  
END
GO
/****** Object:  StoredProcedure [dbo].[RESTORE_DB_AS_ACC]    Script Date: 25.01.2022 03:14:47 ******/
