CREATE PROCEDURE [dbo].[RESTORE_DB_AS_ACC_TEST] (@mandant_environment_pk INT = NULL)
AS
BEGIN  -- Authors Jose
	SET NOCOUNT ON
	IF (NOT EXISTS(SELECT * FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandant_environment_pk))
		BEGIN
			SELECT 0[result], 'MANDANT_ENVIRONMENT existiert nicht'[msg]
			RETURN
		END
    DECLARE @mandantID INT = (SELECT mandant_id FROM dbo.MANDANT_DB_ENVIRONMENT WHERE pk = @mandant_environment_pk)      
	CREATE TABLE #sourceInfo(typ NVARCHAR(1024) NULL, fileNames NVARCHAR(1024) NULL, DBversion NVARCHAR(128) NULL)

	DECLARE @originLinkedServerNameConfig XML = dbo.getAdminLinkedServerNameByPK(@mandant_environment_pk)
	DECLARE @sourceDBName VARCHAR(1024) = (SELECT DatabaseName FROM dbo.getLinkedServerNameByPK(@mandant_environment_pk))
	--DECLARE @targetDBName VARCHAR(1024) = (SELECT DatabaseName FROM dbo.getLinkedServerNameByPK(@mandant_environment_pk))
	
    DECLARE @mandantIDPKACC INT =(SELECT TOP 1 PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE databaseName LIKE 'ACC_%')
	DECLARE @targetLinkedServerNameConfig XML = dbo.getAdminLinkedServerNameByPK(@mandantIDPKACC) --take ein acc von 209 =pk= 97
	IF (@targetLinkedServerNameConfig IS NULL)
		SET  @targetLinkedServerNameConfig = 
		'<server>
			<LINKED_SERVER name="KUNDEN253_209_ACC">
			<ServerName>192.168.253.209</ServerName>
			<DatabaseName></DatabaseName>
			<Username>sa</Username>
			<Password>chevy#2020</Password>
			</LINKED_SERVER>
		</server>'	
	DECLARE @targetDBIPServer VARCHAR(1024) = (SELECT ServerName FROM dbo.getLinkedServerNameByPK(@mandantIDPKACC))
	DECLARE @originLinkedServerName VARCHAR(1024) = (SELECT linkedServerName FROM dbo.getLinkedServerNameByPK(@mandant_environment_pk))
		DECLARE @executingTSQL XML = '<TSQL>SELECT type_desc, name, (SELECT version FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].dbo.version)[version] FROM ['+@originLinkedServerName+'].['+@sourceDBName+'].sys.database_files WHERE file_id IN (1,2)</TSQL>' 	DECLARE @TSQSuccess BIT 	--EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @originLinkedServerNameConfig, @SQL_INSTRUCTIONS=@executingTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TMP_TABLE_NAME = '#sourceInfo', @TSQSuccess = @TSQSuccess OUT
	DECLARE @ipacc VARCHAR(255)='', @dbnameacc VARCHAR(255)='',@dbinstanceacc VARCHAR(255)='', @dbuseracc VARCHAR(512)='', @dbpasswordacc NVARCHAR(512)=''
	SELECT TOP 1 @ipacc=@targetDBIPServer, @dbnameacc='ACC_'+DatabaseName,@dbuseracc=SUBSTRING(DatabaseName,1,4)+'acc', @dbpasswordacc=dbo.SEC_GetPWCOde(SUBSTRING(DatabaseName,1,4)+'acc')  FROM dbo.getLinkedServerNameByPK(@mandant_environment_pk) 
	DECLARE @sourceDBRowname VARCHAR(128) = ISNULL((SELECT TOP 1 ISNULL(fileNames,'') FROM #sourceInfo WHERE typ = 'ROWS'),'')
	DECLARE @sourceDBLogname VARCHAR(128) = ISNULL((SELECT TOP 1 ISNULL(fileNames,'') FROM #sourceInfo WHERE typ = 'LOG'),'')
	DECLARE @version VARCHAR(128) = ISNULL((SELECT TOP 1 ISNULL(DBversion,'') FROM #sourceInfo WHERE typ = 'LOG'),'')
	--SELECT * FROM #sourceInfo
	DROP TABLE #sourceInfo
	 
	IF (@TSQSuccess <> 1)
		BEGIN
			SELECT @TSQSuccess[result], 'LogDBInfoSQLProblem'[msg]
			RETURN
		END
 
 
	DECLARE @backupDBTSQL VARCHAR(MAX) = '<TSQL>'+dbo.getTSQLRestoreDBFROMTO(@sourceDBName, DEFAULT)+'</TSQL>'
	DECLARE @restoreDBTSQL VARCHAR(MAX) = ''
	DECLARE @renameDBTSQL VARCHAR(MAX) = ''

	DECLARE @changeBasicDBConfigTSQLString VARCHAR(MAX) = CONVERT(VARCHAR(MAX), CONVERT(VARBINARY(MAX), dbo.GET_RESTORE_PATCHES(@mandantID,@dbnameacc)), 1)		 
	SET @changeBasicDBConfigTSQLString = SUBSTRING(@changeBasicDBConfigTSQLString,3,LEN(@changeBasicDBConfigTSQLString))
	DECLARE @changeBasicDBConfigTSQL XML = '<TSQL>'+@changeBasicDBConfigTSQLString+'</TSQL>'
	-- SELECT @changeBasicDBConfigTSQL
	-- RETURN
	DECLARE @restoreDBLoginTSQL VARCHAR(MAX) = ''
	--SELECT @sourceDBRowname , @sourceDBLogname
	SELECT @dbnameacc,@targetLinkedServerNameConfig
	IF (@sourceDBRowname <> '' AND @sourceDBLogname<>'')
		BEGIN		  
			SET @restoreDBTSQL = '<TSQL>'+ REPLACE(dbo.getTSQLCreateDBFROMTO(@sourceDBName, DEFAULT, DEFAULT,@sourceDBRowname,@sourceDBLogname,'restore'),@sourceDBName+'.bak','transfer_'+@sourceDBName+'.bak') +'</TSQL>'
			SET @restoreDBLoginTSQL = '<TSQL>'+dbo.getTSQLCreateDBFROMTO(@sourceDBName, DEFAULT, DEFAULT,@sourceDBRowname,@sourceDBLogname,'login') +'</TSQL>'        
			SET @renameDBTSQL = '<TSQL>'+dbo.getTSQLCreateDBFROMTO(@sourceDBName, DEFAULT, DEFAULT,@sourceDBRowname,@sourceDBLogname,'rename') +'</TSQL>'        
			--EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, @SQL_INSTRUCTIONS=@restoreDBTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TSQL_PARSE=1, @TSQSuccess = @TSQSuccess OUT
			IF (@TSQSuccess <> 1)
				BEGIN
					SELECT @TSQSuccess[result], 'Couldnot restore. Be sure there exist the \\ku-fs01.kunden.local\dbtransfer\transfer_'+@sourceDBName+'.bak file'[msg]
					RETURN
				END   /**/
			--EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, @SQL_INSTRUCTIONS=@restoreDBLoginTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TSQL_PARSE=1, @TSQSuccess = @TSQSuccess OUT
			IF (@TSQSuccess <> 1)
				BEGIN
					SELECT @TSQSuccess[result], 'Couldnot create user.'[msg]
					RETURN
				END 
			--EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, @SQL_INSTRUCTIONS=@renameDBTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 0, @TSQL_PARSE=1, @TSQSuccess = @TSQSuccess OUT
			IF (@TSQSuccess <> 1)
				BEGIN
					SELECT @TSQSuccess[result], 'Couldnot rename logical name.'[msg]
					RETURN
				END
			--EXEC dbo.EXEC_SQL_ON_REMOTE_LINKED_SERVER @LINKED_SERVERS_DATA_CONNECTION = @targetLinkedServerNameConfig, @SQL_INSTRUCTIONS=@changeBasicDBConfigTSQL, @SQL_INSTRUCTIONS_ENCRIPTED = 1, @TSQL_PARSE=1, @TSQSuccess = @TSQSuccess OUT
			IF (@TSQSuccess <> 1)
				BEGIN
					SELECT @TSQSuccess[result], 'Couldnot change DB default configs.'[msg]
					RETURN
				END 				  				  
			IF (@TSQSuccess = 1)
				BEGIN
				    
					--delete transfer_dbsource.bak
					DECLARE @cmds VARCHAR(1024)=''
					/*
					DECLARE @tab TABLE(cmdRes VARCHAR(MAX) NULL) 
					SET @cmds = 'DEL /S /Q "\\ku-fs01.kunden.local\dbtransfer\transfer_'+@sourceDBName+'.bak"'
					INSERT INTO @tab
					--EXECUTE Master.dbo.xp_CmdShell @cmds 					            
					
					 IF NOT EXISTS(SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @mandantID AND type = 'ACC')
						BEGIN 
							INSERT INTO dbo.MANDANT_DB_ENVIRONMENT(mandant_id, type, version, databaseIp, databaseInstance, 
																databaseName, databaseUser, tsCreateDate, databasePort)
								SELECT @mandantID,'ACC',@version,@ipacc, @dbinstanceacc, @dbnameacc, @dbuseracc, CURRENT_TIMESTAMP, NULL				 					      
						END 
					ELSE IF EXISTS(SELECT PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @mandantId AND type = 'ACC')
						BEGIN
							UPDATE dbo.MANDANT_DB_ENVIRONMENT SET version=@version, databaseIp=@ipacc, databaseInstance = @dbinstanceacc, databaseName=@dbnameacc,
							databaseUser=@dbuseracc, databasePort=NULL WHERE mandant_id = @mandantId AND type = 'ACC'			 
						END 	*/			
				END      
		END
END
