CREATE PROCEDURE [dbo].[SendContentEMail] (@recipients NVARCHAR(MAX)= 'j.munoz@cx9.de', @info NVARCHAR(MAX) = '', @subject NVARCHAR(MAX) = '',  @MANDANT_ID INT = 415 )
AS 
	DECLARE @replacingString NVARCHAR(max)=''
	DECLARE @startPos INT = CHARINDEX(' Main PID:',@info)
	DECLARE @endPos INT = CHARINDEX(' with given password:',@info)
 
	IF (@startPos>=1 AND @endPos >=1 AND @endPos > @startPos)
		BEGIN
			SET @replacingString = SUBSTRING(@info,@startPos,(@endPos-@startPos))  
			PRINT @replacingString
			SET @info = REPLACE(@info,@replacingString,'')
		END 
 
 IF (ISNULL(@subject,'') = '') SET @subject = 'INFO bekommen'
 DECLARE @EmailContents NVARCHAR(MAX) = 'Guten Tag, <br><br><br><b>
										 die folgende Info ist wichtig zu beachten:</b> <br><br> 
										'+@info + ' <br><br> '
 EXEC dbo.CRENT_UPDATES_SEND_EMAIL @MANDANT_ID = @MANDANT_ID, @subject = @subject, @recipients = @recipients, @contents = @EmailContents,@resultMessage = NULL, @reportJustDeveloper = 0, @printStatusTimestamp = 0

GO
