 --IF (@user)
 EXEC dbo.CRENT_UPDATES_SEND_EMAIL @MANDANT_ID = 415, @subject = @subject, @recipients = @recipients, @contents = @EmailContents,@resultMessage = NULL, @reportJustDeveloper = 0, @printStatusTimestamp = 0

