/****** Object:  StoredProcedure [dbo].[SET_ARCHIV_DB_SYNONYM_SCHEMA_DEPLOYMENT]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SET_ARCHIV_DB_SYNONYM_SCHEMA_DEPLOYMENT](@MANDANT_ID INT = 446, @ENVIRONMENT varchar(32) = 'ACC',@synonyms varchar(MAX) = 'bilder;docs;DOCS_DOCS')
AS SET NOCOUNT ON
BEGIN
    --Author Jose
	DECLARE @synonymName nvarchar(255) = ''
	--SET @synonyms = REPLACE(@synonyms,'_','[_]')
	DECLARE @synonymsExpression NVARCHAR(MAX) = '' 
	DECLARE synonyms_cursor CURSOR  
	FOR SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@synonyms,';')
			
	OPEN synonyms_cursor  
	FETCH NEXT FROM synonyms_cursor INTO @synonymName
  
	WHILE @@FETCH_STATUS = 0  
		BEGIN    
			SET @synonymsExpression+='(@NAME = '''+@synonymName+''') OR '
			FETCH NEXT FROM synonyms_cursor INTO @synonymName
		END 
	CLOSE synonyms_cursor;  
	DEALLOCATE synonyms_cursor;
	SET @synonymsExpression = SUBSTRING(@synonymsExpression,1,LEN(@synonymsExpression)-3) 
	--PRINT @synonymsExpression
	--PRINT @synonyms
	--RETURN
	DECLARE @data_schema_compare_file XML 
	DECLARE @PK INT
	DECLARE @synonymsExpression1 NVARCHAR(MAX) = '((@NAME = ''bilder'')) OR ((@NAME = ''docs'')) OR ((@NAME = ''DOCS[_]DOCS''))'
	DECLARE @excludingTableSynonyms XML =
'      <Table version="1">
        <Include>False</Include>
        <Expression>'+@synonymsExpression+'</Expression>
      </Table> '
	DECLARE @excludingSynonymNames XML =
'      <Synonym version="1">
        <Include>False</Include>
        <Expression>(@NAME = ''RIGHTS_LIST'') OR (@NAME = ''PARAMS'') OR (@NAME = ''FARBEN'') OR (@NAME = ''AUTOS_GRUPPEN_MERKMALE'') OR (@NAME = ''PRINT_MENU_DOKUMENTE'') OR (@NAME = ''PRINT_DOKUMENTE'') OR (@NAME = ''WAEHRUNGSFORMAT'') OR (@NAME = ''WAEHRUNGEN'') OR (@NAME = ''STARTUP_ANWENDUNG'') OR (@NAME = ''SPRACHEN'') OR (@NAME = ''SEPA_BLZ_BIC'') OR (@NAME = ''module'') OR (@NAME = ''LANG_TEXTE'') OR (@NAME = ''LANG_COMPONETS'') OR (@NAME = ''LAENDERKENNZEICHEN'') OR (@NAME = ''KUNDEN_MAIL_REL_STANDARDTYP'') OR (@NAME = ''fieldactions'') OR (@NAME = ''DOCS_STANDARD_BELEGARTEN'') OR (@NAME = ''DATE_FORMATS'') OR (@NAME = ''CSAPP_TEMPLATES'') OR (@NAME = ''CSAPP_TEMPLATE_VARIABLES'') OR (@NAME = ''CSAPP_TEMPLATE_REL_VARIABLES'') OR (@NAME = ''CSAPP_TEMPLATE_ASSETS'') OR (@NAME = ''COUNTRY_SIGN_RELATION_DATE_FORMAT'') OR (@NAME = ''COUNTRY_SIGN_RELATION_CURRENCY'') OR (@NAME = ''AUSW_Abfragen_Summen'') OR (@NAME = ''AUSW_Abfragen_Parameter'') OR (@NAME = ''alte_abfragen'') OR (@NAME = ''abfragen'') OR (@NAME = ''DSGVO_AUFBEWAHRUNGSFRISTEN'') OR (@NAME = ''CSAPP_PROTOCOL_GROUPS'') OR (@NAME = ''CSAPP_PROTOCOL_GROUPS_REL_TYPES'') OR (@NAME = ''CSAPP_PROTOCOL_TYPES'') OR '+@synonymsExpression+'</Expression>
      </Synonym>'
	SELECT TOP 1 
			@data_schema_compare_file = DATA, @PK = PK  FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE  TYPE = 'SCHEMA' AND EXECUTED = 1 --AND N'false' = CAST(DATA.query('/Project[1]/TableActions[1]/*/val/text()="[dbo].[CSAPP_PROTOCOL_GROUPS_REL_TYPES]:[dbo].[CSAPP_PROTOCOL_GROUPS_REL_TYPES]"') AS nvarchar(MAX))
		AND (MANDANT_ID = @MANDANT_ID AND ENVIRONMENT = @ENVIRONMENT) 
 
	IF (@data_schema_compare_file IS NOT NULL AND ISNULL(@synonymsExpression,'') <> '')
	BEGIN
	  --PRINT @pk
	  --SELECT * FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE pk = @pk
		SET @data_schema_compare_file.modify('delete (/Project/ProjectFilter/Filters/Table[1])[1]')
		SET @data_schema_compare_file.modify('insert sql:variable("@excludingTableSynonyms") after (/Project/ProjectFilter[1]/Filters[1]/Synonym[1])[1]')
		SET @data_schema_compare_file.modify('delete (/Project/ProjectFilter/Filters/Synonym[1])[1]')
		SET @data_schema_compare_file.modify('insert sql:variable("@excludingSynonymNames") before (/Project/ProjectFilter[1]/Filters[1]/Table[1])[1]')
		
		--SELECT @data_schema_compare_file.query('/Project/ProjectFilter/Filters/Table[1]/*/Include/text()="False"')
		--SELECT @data_schema_compare_file 
		--SELECT @data_schema_compare_file
		UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET DATA = @data_schema_compare_file WHERE PK = @PK 
		PRINT 'DONE on: '+CAST(@PK AS VARCHAR)		
	END
	ELSE 
		PRINT 'No changes were done, since environtment was not found'  
END 
