/****** Object:  StoredProcedure [dbo].[SET_CSAPP_version]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE  [dbo].[SET_CSAPP_version](@mandant_id INT = NULL, @app_release VARCHAR(32) = '6.21.1')
AS --Author José, nach Absprache mit Florian Wedemeier
BEGIN 
	DECLARE @version VARCHAR(128) = ''
	DECLARE @apptype VARCHAR(128) = ''

	DECLARE @companyAppCode VARCHAR(128) = ISNULL(CAST((SELECT TOP 1 companyAppcode FROM dbo.Mandant WHERE id = @mandant_id) AS VARCHAR(128)),'')
	DECLARE @companyAppCodeMSG VARCHAR(MAX) = ''
	DECLARE @versionenMSGs VARCHAR(MAX) = ''
	DECLARE @UpdateHelpCommand VARCHAR(MAX) = ''
	DECLARE @PK INT = NULL 
	-- PK= @PK, version= @version, URL= @URL, APP_TYPE= @APP_TYPE WHERE
	DECLARE @URL VARCHAR(255) = ''

	IF (@companyAppCode = '' OR (SELECT COUNT(id) FROM dbo.Mandant WHERE companyAppcode=@companyAppCode)>=2)
		BEGIN      
			SET @companyAppCode = SUBSTRING(dbo.getSHA1PWD(dbo.GET_MANDANT_DEPLOYMENT_NAME(@mandant_id),1,1,1),1,12) 
			IF (ISNULL(@companyAppCode,'') = '')
				SET @companyAppCode = SUBSTRING(dbo.getSHA1PWD(SUBSTRING(dbo.GET_MANDANT_DEPLOYMENT_NAME(@mandant_id),1,14),1,1,1),1,12)
				--PRINT @companyAppCode
			UPDATE dbo.Mandant SET companyAppcode = @companyAppCode WHERE id = @mandant_id
			SET @companyAppCodeMSG = 'Folgender Code: <b>'+@companyAppCode +'</b> wurde als companyAppCode für den o.g. Mandant festgelegt. <br> Viel Spaß damit!'
			--EXEC dbo.SendContentEMail @recipients = N'j.munoz@cx9.de',  @info = @companyAppCodeMSG,  @subject = N'companyAppCode wurde gepflegt',  @MANDANT_ID = @mandant_id
			EXEC dbo.SendContentEMail @recipients = N'j.munoz@cx9.de;F.Wedemeier@cx9.de',  @info = @companyAppCodeMSG,  @subject = N'companyAppCode wurde gepflegt',  @MANDANT_ID = @mandant_id
		END

	DECLARE #tmp_cursor_csapp CURSOR  
	   FOR SELECT DISTINCT TOP 20 version, APP_TYPE FROM dbo.CSAPP_version_URL ORDER BY version DESC
	OPEN #tmp_cursor_csapp  
	FETCH NEXT FROM #tmp_cursor_csapp INTO @version, @apptype
  
	WHILE @@FETCH_STATUS = 0  
	BEGIN  
		IF (EXISTS (SELECT * FROM dbo.Mandant WHERE id = @mandant_id))
			BEGIN
				IF NOT EXISTS (SELECT * FROM CSAPP_version_URL WHERE mandant = @mandant_id AND version = @version AND APP_TYPE = @apptype)  
					BEGIN
						SET @URL='https://apiapp.cx9.de/'+@app_release+'/index.php/'
						IF (@version = 'TESTversion')
							SET @URL='https://apiapp-acc.cx9.de/'+@app_release+'/index.php/'
						IF (@version = 'DEVELOPMENT')
							SET @URL='https://apiapp-acc.cx9.de/master/index.php/'
						IF ( @version like '21.1.%' )  
							SET @URL='https://apiapp.cx9.de/6.21.1/index.php/' 

						IF ( @version like '21.3.%' )  
							SET @URL='https://apiapp.cx9.de/6.21.3/index.php/' 

						IF ( @version like '21.4.%' )  
							SET @URL='https://apiapp.cx9.de/6.21.4/index.php/' 

						IF ( @version like '22.1.%' )  
							SET @URL='https://apiapp.cx9.de/6.22.1/index.php/' 
														          
						INSERT INTO dbo.CSAPP_version_URL ( mandant ,  version, URL , APP_TYPE )
							SELECT @mandant_id, @version, @URL, @apptype
						SET @PK = (SELECT TOP 1 PK FROM CSAPP_version_URL WHERE mandant = @mandant_id AND version = @version AND APP_TYPE = @apptype)
						SET @versionenMSGs += 'version: <b>'+@version+'</b> mit URL: <b>'+@URL+'</b> wurde in CSAPP_version_URL eingetragen. <br>'	
						SET @UpdateHelpCommand += 'UPDATE CSAPP_version_URL SET version = '''+@version+''', <br>'		
						SET @UpdateHelpCommand += 'URL = '''+@URL+''' <br>'		
						SET @UpdateHelpCommand += 'WHERE mandant = '+CAST(@mandant_id AS VARCHAR(32))+' AND PK = '+CAST(@PK AS VARCHAR(32))+' <br><br>'		
					END        
			
			END
  

		FETCH NEXT FROM #tmp_cursor_csapp	INTO @version, @apptype
	END   
	CLOSE #tmp_cursor_csapp;  
	DEALLOCATE #tmp_cursor_csapp; 

	UPDATE dbo.CSAPP_version_URL SET 
		db = (SELECT databaseName FROM dbo.MANDANT_DB_ENVIRONMENT WHERE type = 'ACC' AND mandant_id = mandant), 
		HOST = (SELECT databaseIp FROM dbo.MANDANT_DB_ENVIRONMENT WHERE type = 'ACC' AND mandant_id = mandant),
		INSTANCE = (SELECT databaseInstance FROM dbo.MANDANT_DB_ENVIRONMENT WHERE type = 'ACC' AND mandant_id = mandant),  
		DB_USER = (SELECT databaseUser FROM dbo.MANDANT_DB_ENVIRONMENT WHERE type = 'ACC' AND mandant_id = mandant),  
		PORT = (SELECT databasePort FROM dbo.MANDANT_DB_ENVIRONMENT WHERE type = 'ACC' AND mandant_id = mandant)
	WHERE version in ('TESTversion', 'DEVELOPMENT') AND mandant = @mandant_id

	IF (@versionenMSGs <> '') 
		BEGIN
			SET @UpdateHelpCommand+='<br>SELECT * FROM CSAPP_version_URL WHERE mandant = ' +CAST(@mandant_id AS VARCHAR(32))     
			SET @versionenMSGs = '<br>'+@versionenMSGs+'<br><br> Nach Bedarf nachpflegen!<br><br>Dein TSQL Help:<br><br>'+@UpdateHelpCommand       
			EXEC dbo.SendContentEMail @recipients = N'j.munoz@cx9.de;F.Wedemeier@cx9.de',  @info = @versionenMSGs,  @subject = N'CSAPP_version_URL Tabelle wurde gepflegt',  @MANDANT_ID = @mandant_id
			--EXEC dbo.SendContentEMail @recipients = N'j.munoz@cx9.de;',  @info = @versionenMSGs,  @subject = N'CSAPP_version_URL Tabelle wurde gepflegt',  @MANDANT_ID = @mandant_id
		END
			
END
GO
