CREATE PROCEDURE [dbo].[sp_ACIDTableLogicGenerator] (@tableName NVARCHAR(255) = '', @tableNameColumnIdentity VARCHAR(255) = 'id', @searchOnFields VARCHAR(MAX) = 'id;companyname;email;AbasId', @searchOnFieldSeparator VARCHAR(1) = ';', @maskeDetailsColumn INT = 4, @create BIT = 0) 
AS BEGIN --Author José
	DECLARE @TSQL VARCHAR(MAX) = ''
	DECLARE @TSQLExistencePart VARCHAR(MAX) = ''
	DECLARE @validColumnCounter INT = 2
	DECLARE @TSQLErrorMessages NVARCHAR(MAX) = ''
	DECLARE @tsqlDefinition TABLE  (tsqlFunctionName VARCHAR(MAX) NULL, tsqlDefinition VARCHAR(MAX) NULL) 
	SET @tableName = UPPER(@tableName) 	
	DECLARE @rootName NVARCHAR(255) = LOWER(@tableName)+'s'
	DECLARE @childName NVARCHAR(255) = LOWER(@tableName)
	DECLARE @ACIDProcedureNameOnTable NVARCHAR(MAX) = '' 
	DECLARE @searchTSQLFunctionNameOnTable NVARCHAR(MAX) = '' 
	DECLARE @searchFunctionNameOnTable NVARCHAR(MAX) = '' 
	DECLARE @viewerFunctionNameOnTable NVARCHAR(MAX) = '' 
	DECLARE @creatingDBO NVARCHAR(255) = '' 
    SET @tableNameColumnIdentity = ISNULL((SELECT TOP 1 UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS 		WHERE  COLUMNPROPERTY(object_id(TABLE_SCHEMA+'.'+TABLE_NAME), COLUMN_NAME, 'IsIdentity') = 1 AND TABLE_NAME = @tableName),@tableNameColumnIdentity)  
	SET @ACIDProcedureNameOnTable = '__procProcess_XML_ACID_'+@tableName+'_DATA_BY_'+@tableNameColumnIdentity+'' 
	SET @searchTSQLFunctionNameOnTable = '__fnSEARCH_ON_'+@tableName+'_BY_TERMS'
	SET @searchFunctionNameOnTable = '__fnSEARCH_XML_'+@tableName+'_BY_TERMS'
	SET @viewerFunctionNameOnTable = '__fnGET_XML_'+@tableName+'_BY_'+@tableNameColumnIdentity

	--
	IF (@create = 1)
		BEGIN 
			DECLARE @validFields TABLE (fieldName NVARCHAR(255) NULL)
				INSERT INTO @validFields  ( fieldName )
					SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @tableName AND COLUMN_NAME IN (SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@searchOnFields,@searchOnFieldSeparator)) 
			SET @validColumnCounter = ISNULL((SELECT COUNT(*) FROM @validFields),2)
			INSERT INTO @tsqlDefinition (tsqlFunctionName, tsqlDefinition)
				 SELECT procedureName, procedureDefinition FROM dbo.__generator_PROCEDURE_ACID_TABLE_DEFINITION(@tableName,@tableNameColumnIdentity) --PROC um client response zu bearbeiten
			INSERT INTO @tsqlDefinition (tsqlFunctionName, tsqlDefinition)
				SELECT functionName, functionDefinition FROM dbo.__generator_FUNCTION_SEARCH_ON_TABLE_BY_TERMS(@tableName,@tableNameColumnIdentity,@searchOnFields,@searchOnFieldSeparator)--funktion um production von search funktion
			INSERT INTO @tsqlDefinition (tsqlFunctionName, tsqlDefinition)
				SELECT functionName, functionDefinition FROM dbo.__generator_FUNCTION_SEARCH_ON_TABLE_DEFINITION(@tableName,@tableNameColumnIdentity,@searchOnFields,@searchOnFieldSeparator)--funktion um production von search funktion
 			INSERT INTO @tsqlDefinition (tsqlFunctionName, tsqlDefinition)
				SELECT functionName, functionDefinition FROM dbo.__generator_FUNCTION_TABLE_DEFINITION(@tableName,@tableNameColumnIdentity,@maskeDetailsColumn)--funktion um prodution von search funktion
 
			DECLARE tsqlCursorGenerator CURSOR  
			   FOR SELECT tsqlFunctionName, tsqlDefinition FROM @tsqlDefinition 
			OPEN tsqlCursorGenerator  
			FETCH NEXT FROM tsqlCursorGenerator INTO @creatingDBO, @TSQL 
			WHILE @@FETCH_STATUS = 0  
				BEGIN  

					SET @TSQLExistencePart = SUBSTRING(@TSQL,0,CHARINDEX('CREATE',@TSQL))  
					SET @TSQLExistencePart = REPLACE(@TSQLExistencePart,'--IF EXISTS','IF EXISTS')
					SET @TSQLExistencePart = REPLACE(@TSQLExistencePart,'--DROP','DROP')
					--PRINT @TSQLExistencePart                
					BEGIN TRY   	
							PRINT 'Doing: '+@creatingDBO 	    
							EXEC(@TSQLExistencePart)  -- check valid results  
							EXEC(@TSQL)  -- check valid results  
					END TRY
					BEGIN CATCH 
						PRINT 'Failed: '+@creatingDBO 
						PRINT (@TSQLExistencePart) 
						EXEC dbo.longPrintingString @printigString = @TSQL 

						SET @TSQLErrorMessages+= ERROR_MESSAGE()
					END CATCH   

					FETCH NEXT FROM tsqlCursorGenerator	INTO @creatingDBO, @TSQL 
				END   
			CLOSE tsqlCursorGenerator 
			DEALLOCATE tsqlCursorGenerator
		 

		END 
	SELECT @ACIDProcedureNameOnTable[acidProcedureName],
		   @searchTSQLFunctionNameOnTable[searchTSQLFunctionName],
		   @searchFunctionNameOnTable[searchFunctionName],
		   @viewerFunctionNameOnTable[editFunctionName],
		   @rootName[xmlRootName],
		   @childName[xmlChildName],
		   @TSQLErrorMessages[errorMessage]

END 
GO
/****** Object:  StoredProcedure [dbo].[TRIGGER_MAIL_REPORT_UPDATES]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[TRIGGER_MAIL_REPORT_UPDATES](@mandID INT = NULL, @env NVARCHAR(128)= NULL, @justDBReport BIT = NULL, @reportJustDeveloper BIT = 1)
AS SET NOCOUNT ON
BEGIN
	DECLARE @environments TABLE (MANDANT_ID INT NOT NULL, ENVIRONMENT VARCHAR(128) NOT NULL)
	DECLARE @MANDANT_ID INT, @ENVIRONMENT VARCHAR(128)
	DECLARE @res NVARCHAR(128)
	DECLARE @emailSubject NVARCHAR(1024) = ''
	DECLARE @mailRecipients VARCHAR(1024) = 'j.munoz@cx9.de'
	DECLARE @emailResult NVARCHAR(128) = '' 
	DECLARE @emailContents NVARCHAR(MAX)=''    
	DECLARE @emailContentsTable NVARCHAR(MAX)=''    
	DECLARE @EnvironmentToBeUpdated VARCHAR(128) = ''
	DECLARE @EnvironmentUpdateStatus VARCHAR(128) = ''
	DECLARE @kundenEMail VARCHAR(512)=''
	DECLARE @betreuerEMail VARCHAR(512)=''
	DECLARE @ABAS_TASK_NO VARCHAR(128)=''
	IF (@env = 'DEFAULT') SET @env='LIVE'
	
	DECLARE @contents NVARCHAR(MAX)=''
	
--	PRINT ''
--	RETURN
	IF EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID=@mandID AND ENVIRONMENT = @env)
		BEGIN
			INSERT INTO @environments
				SELECT @mandID, @env
			-- wenn ein Update frisch gemacht wurde
			SET @mailRecipients = 'j.munoz@cx9.de;t.seitz@cx9.de;n.lermann@cx9.de;m.schwarzkopf@cx9.de'
		END
	ELSE IF(NOT EXISTS(SELECT PK FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID=@mandID AND ENVIRONMENT = @env)
			AND @mandID IS NOT NULL OR @env IS NOT NULL)
		BEGIN
			RETURN
		END
	ELSE    
		INSERT INTO @environments
		SELECT  MANDANT_ID, ENVIRONMENT FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE 	WHERE 
		CREATE_COMPARE_JOB_LOG IS NOT NULL
		AND UPLOAD_JOB_LOG IS NOT NULL 
		AND TRANSLATIONS_JOB_LOG IS NOT NULL
		AND IMPORT_EXPORT_TRANSLATIONS_JOB_LOG IS NOT NULL
		AND (TYPE = 'DATA' OR TYPE = 'SCHEMA') GROUP BY MANDANT_ID, ENVIRONMENT HAVING COUNT(PK) = 2

	DECLARE cursor_mail_updates CURSOR  
	   FOR SELECT MANDANT_ID, ENVIRONMENT FROM @environments
	OPEN cursor_mail_updates  
	FETCH NEXT FROM cursor_mail_updates INTO @MANDANT_ID, @ENVIRONMENT 
	WHILE @@FETCH_STATUS = 0  
	BEGIN  
		SELECT 
			TOP 1 @ABAS_TASK_NO = ABAS_TASK_NO, 
			@kundenEMail = ISNULL((SELECT TOP 1 email FROM dbo.Mandant WHERE id= MandantId),''),  
			--(SELECT companyname FROM dbo.Mandant WHERE id = @MANDANT_ID)[kunden],
			@betreuerEMail = betreuer 
		FROM MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID AND Environment = @ENVIRONMENT
		IF (@kundenEMail = '') SET @kundenEMail = @betreuerEMail
		SET @emailContentsTable = '<b>E-Mail des Kunden: '+@kundenEMail+'</b><br>
<b>E-Mail des Kundenbetreuers: '+@betreuerEMail+'</b><br>
<b>CX9 '+@ENVIRONMENT+' Interner Ablauf:</b>
<table style="background:gray; border:1px solid; color:white; font-size:15px; width: auto !important;" class="table table-dark">
    <thead>
      <tr>
        <th scope="col">No.</th>
        <th scope="col">Beschreibung</th>
        <th scope="col">Meldung</th>
        <th scope="col">Status</th>
      </tr>
    </thead>
    <tbody>
'+dbo.GET_ENVIRONMENT_EMAIL_STATUS_LOGS(@MANDANT_ID,@ENVIRONMENT, @justDBReport)+'   
    </tbody>
  </table>'
		SET @contents = 
'<p>Lieber Kundenbetreuer, <br><br>wir haben folgende Info des Updates zusammengefasst: </p>
'+@emailContentsTable	
 
SET @emailSubject = 'Anfrage Nr. '+@ABAS_TASK_NO+ ' C-Rent 6.0 '+@ENVIRONMENT+' Update Status'
IF (@reportJustDeveloper = 1)
  SET @mailRecipients = 'j.munoz@cx9.de'
SET @mailRecipients = 'j.munoz@cx9.de'
  IF (dbo.GET_ENVIRONMENT_UPDATE_STATUS(@MANDANT_ID,@ENVIRONMENT) = '' AND @ENVIRONMENT <> 'ACC')
	UPDATE dbo.DB_SCHEMA_DATA_COMPARE_UPDATE SET EXECUTED = 1 WHERE MANDANT_ID = @MANDANT_ID AND ENVIRONMENT = @ENVIRONMENT
		EXEC dbo.CRENT_UPDATES_SEND_EMAIL @MANDANT_ID = @MANDANT_ID, -- int
			@subject = @emailSubject, -- nvarchar(255)
			@recipients = @mailRecipients, -- varchar(1024)
			@contents = @contents, -- nvarchar(max)
			@resultMessage = @res, @reportJustDeveloper = @reportJustDeveloper -- nvarchar(2048) 
			IF (EXISTS (SELECT EXECUTED FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @MANDANT_ID
						AND ENVIRONMENT = @ENVIRONMENT AND EXECUTED = 1)
						AND dbo.GET_ENVIRONMENT_LOG_ERRORS(@MANDANT_ID,@ENVIRONMENT)='')
				BEGIN
             
					SET @EnvironmentUpdateStatus = dbo.GET_ENVIRONMENT_UPDATE_STATUS(@MANDANT_ID,@ENVIRONMENT)
 					BEGIN TRANSACTION
						UPDATE dbo.WEB_PRODUKTE_LOG_UPDATE SET LAST_STATUS=@EnvironmentUpdateStatus WHERE 
						MANDANT_ID = @MANDANT_ID AND ENVIRONMENT = @ENVIRONMENT
					COMMIT TRANSACTION
					IF (@EnvironmentUpdateStatus = 'success' OR @EnvironmentUpdateStatus = '')
					BEGIN
						INSERT INTO dbo.Updates ( ENVIRONMENT_ID ,  DATE_INSERTED )   
							SELECT (SELECT TOP 1 PK FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MANDANT_ID AND type = CASE WHEN @ENVIRONMENT = 'LIVE' THEN 'DEFAULT' ELSE @ENVIRONMENT END ) , CURRENT_TIMESTAMP          
						-- wenn ein Live Update gemacht werden kann, dann alle informieren
						--SET @mailRecipients = 'j.munoz@cx9.de;t.seitz@cx9.de;n.lermann@cx9.de;m.schwarzkopf@cx9.de'                    
						SET @emailContents = dbo.getUpdateENVInfoLinks(@MANDANT_ID,@ENVIRONMENT)+@emailContentsTable
						SET @mailRecipients = 'j.munoz@cx9.de'+';'+@betreuerEMail
						IF (@environment = 'LIVE')
							SET @mailRecipients += ';'+@kundenEMail
						IF (@environment = 'ACC' AND @reportJustDeveloper <> 1)
							BEGIN
								SET @mailRecipients += ';support@cx9.de'
								/*IF NOT EXISTS (SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId=@MANDANT_ID AND
										 Environment = @environment AND mailAnBetreuer<>)*/
								UPDATE  dbo.MANDANT_WEB_PRODUKTE SET mailAnBetreuer = 1, mailAnBetreuerDatum = 
									CASE WHEN mailAnBetreuerDatum IS NULL THEN CURRENT_TIMESTAMP ELSE mailAnBetreuerDatum END 
									WHERE MandantId=@MANDANT_ID AND  Environment = @environment
							END
							
							
						--PRINT 'send email with environment ' + @EnvironmentToBeUpdated + ' data - todo'
						--SET @emailSubject = 'C-Rent 6.0 '+@ENVIRONMENT+' Update Status'
						EXEC dbo.CRENT_UPDATES_SEND_EMAIL @MANDANT_ID = @MANDANT_ID, @subject = @emailSubject,  
							@recipients = @mailRecipients, @contents = @emailContents, @resultMessage = @emailResult, @reportJustDeveloper = @reportJustDeveloper 				
					END

				END

		FETCH NEXT FROM cursor_mail_updates	INTO @MANDANT_ID, @ENVIRONMENT 
	END   
	CLOSE cursor_mail_updates 
	DEALLOCATE cursor_mail_updates
END
GO
/****** Object:  StoredProcedure [dbo].[TRIGGER_WEB_UPDATE]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[TRIGGER_WEB_UPDATE](@mandant_id INT = NULL, @mandant_environment_name VARCHAR(128)='')
AS SET NOCOUNT ON
BEGIN
	DECLARE @environmentPKTOBeUpdated INT = NULL
	DECLARE @MandantIDToBeUpdated INT = NULL
	DECLARE @emailResult NVARCHAR(128) = '' 
	DECLARE @emailContents NVARCHAR(MAX)=''    
	DECLARE @EnvironmentToBeUpdated VARCHAR(128) = ''
	DECLARE @EnvironmentUpdateStatus VARCHAR(128) = ''
	DECLARE @mailRecipients VARCHAR(1024) = 'j.munoz@cx9.de'

	DECLARE @nextExcutionTime VARCHAR(128) = CAST (FLOOR(RAND()*(500-400+1))+400 AS VARCHAR(8)) --betwen 30-50 seconds
	DECLARE @instructions NVARCHAR(MAX) =
'#!/bin/bash
# SH Updates
# Jose M.
export LANG=C.UTF-8
timeout () {
    tput sc
    time=$1; while [ $time -ge 0 ]; do
        tput rc; tput el
        printf "$2" $time
        ((time--))
        sleep 1
    done
    tput rc; tput ed;
}
WATING_TIME='+@nextExcutionTime+'
echo "======== N O T H I N G    T O   D E P L O Y ==========="
echo "=== WATING TIME IN SECONDS FOR NEXT DEPLOYMENT: '+@nextExcutionTime+'. ==="
timeout '+@nextExcutionTime+' "=== Remining time in seconds %s from '+@nextExcutionTime+' ==============="
echo "======================================================="
<<''COMMENTS''
'
	DECLARE @environments TABLE (MANDANT_ID INT NOT NULL, ENVIRONMENT VARCHAR(128) NOT NULL)
	DECLARE @leer TABLE (daten VARCHAR(2048) NOT NULL)
	INSERT INTO @environments
	SELECT  MANDANT_ID, ENVIRONMENT FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE 	WHERE 
    EXECUTED = 1 AND CREATE_COMPARE_JOB_LOG IS NOT NULL
	AND UPLOAD_JOB_LOG IS NOT NULL 
	AND TRANSLATIONS_JOB_LOG IS NOT NULL
	AND IMPORT_EXPORT_TRANSLATIONS_JOB_LOG IS NOT NULL
	AND COMPARE_RESULT_LOGS IS NOT NULL
	AND (TYPE = 'DATA' OR TYPE = 'SCHEMA') GROUP BY MANDANT_ID, ENVIRONMENT HAVING COUNT(PK) = 2	

	INSERT INTO dbo.WEB_PRODUKTE_LOG_UPDATE (MANDANT_ID,ENVIRONMENT)
		SELECT MANDANT_ID,ENVIRONMENT FROM @environments 
		 WHERE ENVIRONMENT <> 'DEFAULT' AND 
		 CAST(MANDANT_ID AS VARCHAR(32))+ENVIRONMENT NOT IN (SELECT CAST(MANDANT_ID AS VARCHAR(32))+ENVIRONMENT FROM dbo.WEB_PRODUKTE_LOG_UPDATE)
		 
    IF (EXISTS (SELECT * FROM WEB_PRODUKTE_LOG_UPDATE WHERE ISNULL(LAST_STATUS,'')<>'success'))
		BEGIN 
			SELECT TOP 1 @environmentPKTOBeUpdated=PK, @MandantIDToBeUpdated = MANDANT_ID,@EnvironmentToBeUpdated=ENVIRONMENT  
			FROM WEB_PRODUKTE_LOG_UPDATE WHERE ISNULL(LAST_STATUS,'')<>'success'
			IF EXISTS (SELECT * FROM WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID=@mandant_id AND ENVIRONMENT = @mandant_environment_name)			 
				SELECT @MandantIDToBeUpdated=@mandant_id, @EnvironmentToBeUpdated=@mandant_environment_name/**/
			IF (EXISTS (SELECT EXECUTED FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @MandantIDToBeUpdated
						AND ENVIRONMENT = @EnvironmentToBeUpdated AND EXECUTED = 1)
						AND dbo.GET_ENVIRONMENT_LOG_ERRORS(@MandantIDToBeUpdated,@EnvironmentToBeUpdated)='')
				BEGIN             
					BEGIN TRANSACTION
						UPDATE dbo.WEB_PRODUKTE_LOG_UPDATE SET LAST_STATUS='pending' WHERE PK = @environmentPKTOBeUpdated
					COMMIT TRANSACTION
					SET @instructions = dbo.getCRent60UpdateSHInstructions(@MandantIDToBeUpdated,@EnvironmentToBeUpdated)+CHAR(10)+
					'<<''COMMENTS'''
					--EXEC dbo.LongPrint @printigString = @instructions	
					--PRINT @instructions						
				END 
		END	
	EXEC dbo.LongPrint @printigString = @instructions
	--SELECT * FROM WEB_PRODUKTE_LOG_UPDATE WHERE ISNULL(LAST_STATUS,'')<>'success'
    IF (EXISTS (SELECT PK FROM WEB_PRODUKTE_LOG_UPDATE WHERE ISNULL(LAST_STATUS,'')<>'success'))
		BEGIN
			SELECT TOP 1 @environmentPKTOBeUpdated=PK, @MandantIDToBeUpdated = MANDANT_ID,@EnvironmentToBeUpdated=ENVIRONMENT
			FROM WEB_PRODUKTE_LOG_UPDATE WHERE ISNULL(LAST_STATUS,'')<>'success' ORDER BY pk DESC
			IF EXISTS (SELECT * FROM WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID=@mandant_id AND ENVIRONMENT = @mandant_environment_name)			 
				SELECT @MandantIDToBeUpdated=@mandant_id, @EnvironmentToBeUpdated=@mandant_environment_name/**/            
				-- SELECT @MandantIDToBeUpdated=505, @EnvironmentToBeUpdated='LIVE'
			 
			SELECT @environmentPKTOBeUpdated, @MandantIDToBeUpdated, @EnvironmentToBeUpdated
			IF (EXISTS (SELECT EXECUTED FROM dbo.DB_SCHEMA_DATA_COMPARE_UPDATE WHERE MANDANT_ID = @MandantIDToBeUpdated
						AND ENVIRONMENT = @EnvironmentToBeUpdated AND EXECUTED = 1)
						AND dbo.GET_ENVIRONMENT_LOG_ERRORS(@MandantIDToBeUpdated,@EnvironmentToBeUpdated)='')
				BEGIN
					SET @EnvironmentUpdateStatus = dbo.GET_ENVIRONMENT_UPDATE_STATUS(@MandantIDToBeUpdated,@EnvironmentToBeUpdated)           
					--PRINT @EnvironmentUpdateStatus
					BEGIN TRANSACTION
						UPDATE dbo.WEB_PRODUKTE_LOG_UPDATE SET LAST_STATUS=@EnvironmentUpdateStatus WHERE PK = @environmentPKTOBeUpdated
					COMMIT TRANSACTION
					IF (@EnvironmentUpdateStatus = 'success')
					BEGIN
						-- wenn ein Live Update gemacht werden kann, dann alle informieren
						SET @mailRecipients = 'j.munoz@cx9.de;t.seitz@cx9.de;n.lermann@cx9.de;m.schwarzkopf@cx9.de'                    
						SET @emailContents = '
						 <h5>Guten Tag,<br>Ein Live Update für den o.g. Kunden ist jetzt möglich</h5>
						'+dbo.getUpdateENVInfoLinks(@MandantIDToBeUpdated,@EnvironmentToBeUpdated)
						--PRINT 'send email with environment ' + @EnvironmentToBeUpdated + ' data - todo'
 
						EXEC dbo.CRENT_UPDATES_SEND_EMAIL @MANDANT_ID = @MandantIDToBeUpdated, @subject = N'C-Rent 6.0 Live Update',  
							@recipients = @mailRecipients, @contents = @emailContents, @resultMessage = @emailResult 				
					END
						
					--send email 
					EXEC TRIGGER_MAIL_REPORT_UPDATES @mandID=@MandantIDToBeUpdated, @env=@EnvironmentToBeUpdated					
				END 
		END				
		
END
GO
/****** Object:  StoredProcedure [dbo].[UPDATE_C_RENT_6_PRODUKTE_FINAL]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[UPDATE_C_RENT_6_PRODUKTE_FINAL] (@MANDANT_ID INT = NULL, @MANDANT_ENVIRONMENT_NAME NVARCHAR(30) = 'ACC',  @EnvironmentUpdateDate DATETIME = NULL, @ABAS_TASK_NO VARCHAR(128) = '',
@MRJASPERNUMMER VARCHAR(32) = NULL, @MRCRWNUMMER1 VARCHAR(32) = '372',@MRCRWNUMMER2 VARCHAR(32) = '373', @kundenBetreuerMails VARCHAR(2048) = 'a.bernhard@cx9.de',  @reportJustDeveloper BIT = 1, @manage_linked_server BIT = 1, @optimize_db BIT = 1) 
AS SET NOCOUNT ON -- Autor José
BEGIN 
	DECLARE @AbasIdAUX INT = NULL
	DECLARE @lastACCDayCounter INT = NULL
	DECLARE @lastACCUpdate DATETIME = NULL
    DECLARE @mandantDetectedErrors VARCHAR(MAX) = ''  
	IF (ISDATE(@EnvironmentUpdateDate) = 0)
		BEGIN
			SET @EnvironmentUpdateDate = CURRENT_TIMESTAMP
		    --get last update date if we are updating a ACC System
			SET @lastACCUpdate = ISNULL((SELECT MAX(TIMEOFUPDATE) FROM dbo.MANDANT_WEB_PRODUKTE),@EnvironmentUpdateDate)
			--how many updates there was?
			SET @lastACCDayCounter = ISNULL( (SELECT COUNT(*) FROM dbo.MANDANT_WEB_PRODUKTE WHERE TIMEOFUPDATE IS NOT NULL AND Environment=@MANDANT_ENVIRONMENT_NAME AND dbo.Dattodt(TIMEOFUPDATE,'0000') = dbo.Dattodt(@lastACCUpdate,'0000') ),0 )
			IF (@lastACCDayCounter < 6 AND dbo.GET_WEEKDAY(@lastACCUpdate) NOT IN ('Sa','So','Mo','Di')) -- updates pro tag so mit Marc besprochen
				BEGIN 
				    SET @EnvironmentUpdateDate = DATEADD(HOUR,2,@lastACCUpdate)
					--PRINT @EnvironmentUpdateDate
				END
			IF (@lastACCDayCounter IN (0,5) AND dbo.GET_WEEKDAY(@lastACCUpdate) IN ('Sa','So','Mo','Di')) -- updates pro tag so mit Marc besprochen
				BEGIN
					WHILE  (dbo.GET_WEEKDAY(@lastACCUpdate) IN ('Sa','So','Mo','Di'))
						BEGIN
							SET @lastACCUpdate = DATEADD(DAY,1,dbo.Dattodt(@lastACCUpdate,'0900'))
						   -- PRINT @lastACCUpdate
						END
						SET @EnvironmentUpdateDate = @lastACCUpdate
				END

		END
		
	DECLARE @MANDANT_ENVIRONMENT_NAME_AUX NVARCHAR(30) = (CASE WHEN @MANDANT_ENVIRONMENT_NAME = 'LIVE' THEN 'DEFAULT' ELSE @MANDANT_ENVIRONMENT_NAME END)
	DECLARE @MANDANT_ENVIRONMENT_PK INT = (SELECT TOP 1 PK  FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MANDANT_ID AND type = @MANDANT_ENVIRONMENT_NAME_AUX )
	DECLARE @MANDANT_ENVIRONMENT_LIVE_PK INT = (SELECT TOP 1 PK  FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MANDANT_ID AND type='DEFAULT' AND version <> '6.0' )
	DECLARE @STEP INT = 1
	
	IF NOT EXISTS (SELECT TOP 1 PK  FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MANDANT_ID AND type = @MANDANT_ENVIRONMENT_NAME_AUX )
		BEGIN
		    PRINT 'FALSCHE INFO MANDANT_DB_ENVIRONMENT: DB existiert nicht.'
			SET @mandantDetectedErrors+='FALSCHE INFO MANDANT_DB_ENVIRONMENT: DB existiert nicht.<br>'
			IF (ISNUMERIC(@MANDANT_ENVIRONMENT_LIVE_PK)=1 AND @MANDANT_ENVIRONMENT_NAME = 'ACC' AND dbo.isClientExtern(@MANDANT_ID)=0)
				BEGIN
				    --make an ACC from live db
					PRINT 'Making DB Backup from LIVE DB '
					EXEC dbo.BACKUP_DB @mandant_environment_pk = @MANDANT_ENVIRONMENT_LIVE_PK, @justCheck = 0
					EXEC dbo.RESTORE_DB_AS_ACC @mandant_environment_pk = @MANDANT_ENVIRONMENT_LIVE_PK --LIV DB backup wird hier auch gelsöcht
					IF (@MANDANT_ID NOT IN (410))--dbs mit Archiv DB, wegen Synonyme nicht schrinken
						BEGIN
							SET @MANDANT_ENVIRONMENT_PK = (SELECT TOP 1 PK  FROM dbo.MANDANT_DB_ENVIRONMENT WHERE mandant_id = @MANDANT_ID AND type = @MANDANT_ENVIRONMENT_NAME_AUX )
						    EXEC dbo.FREESPACE_ON_DB_ACC @mandantID_PK = @MANDANT_ENVIRONMENT_PK -- int
						END
				END
			RETURN
		END
		IF (ISNUMERIC(@MANDANT_ENVIRONMENT_LIVE_PK)=1 AND @MANDANT_ENVIRONMENT_NAME = 'LIVE' AND dbo.isClientExtern(@MANDANT_ID)=0)-- wenn es um ein Live Update geht
			BEGIN
				--make an LIVE DB Backup
				PRINT 'Making DB Backup from LIVE DB muss manuell gemacht werden, wenn es nicht gemacht worden ist.'
				SET @mandantDetectedErrors+='Making DB Backup from LIVE DB muss manuell gemacht werden, wenn es nicht gemacht worden ist.<br>'
				--EXEC dbo.BACKUP_DB @mandant_environment_pk = @MANDANT_ENVIRONMENT_LIVE_PK, @justCheck = 0 
			END
	SET @AbasIdAUX = (SELECT TOP 1 abasId FROM dbo.Mandant WHERE id = @MANDANT_ID)
	DECLARE @id INT = NULL 
	DECLARE @companyname NVARCHAR(255) = '' 
	DECLARE @companynameHelpABAS NVARCHAR(MAX) = '' 
	DECLARE @email NVARCHAR(255) = '' 
	DECLARE @documentRoot NVARCHAR(255) = '' 
	DECLARE @ormUrl NVARCHAR(255) = '' 
	DECLARE @crwUrl NVARCHAR(255) = '' 
	DECLARE @abasId INT = NULL  
	DECLARE @validMandantData BIT = 0  
	DECLARE @printEstimationCosts BIT = 1
	DECLARE @dbConnection BIT = 0  
	DECLARE @dbversion NVARCHAR(MAX) 
	DECLARE @mandantTSQL VARCHAR(MAX)
	
	DECLARE @JASPER_MR_LINK VARCHAR(1024) = ''
	DECLARE @dbConnetionInfo TABLE(dbLogicName VARCHAR(255), DBName VARCHAR(128) , result BIT, size INT , msg NVARCHAR(max), dbversion NVARCHAR(1024) NULL)
	DECLARE @dbMandantEnvironmentInfo NVARCHAR(MAX) = --dbo.GET_MANDANT_DB_ENVIRONMENT_DATA(@MANDANT_ENVIRONMENT_PK)
	REPLACE(dbo.GET_MANDANT_DB_ENVIRONMENT_DATA(@MANDANT_ENVIRONMENT_PK),'"'+CHAR(13),'"<br>')+'<br><br>'
	DECLARE @validBetreuerMails BIT = CASE WHEN EXISTS(
			SELECT Aval FROM dbo.GET_TABLE_FROM_LIST_DELIM(@kundenBetreuerMails,';') WHERE dbo.VALIDATE_EMAIL_ADDRESS(Aval)=0)
			 THEN 0 ELSE 1 END
		--	 SELECT * FROM VALIDATE_MANDANT_UPDATE(506)
	SELECT TOP 1 @validMandantData=valid, @mandantTSQL= TSQL_UPDATE FROM dbo.VALIDATE_MANDANT_UPDATE(@MANDANT_ID)
	EXEC dbo.SET_CSAPP_version @mandant_id = @MANDANT_ID --set APP Configs
	IF (@validMandantData = 0)
		BEGIN
			SET @mandantTSQL = REPLACE(@mandantTSQL, CHAR(13),'<br>')
			SET @mandantTSQL = REPLACE(@mandantTSQL, CHAR(10),'<br>')
			SET @mandantTSQL = 'Mandant Missing Data TSQL to be fixed <br>' + @mandantTSQL
		    EXEC dbo.SendContentEMail @recipients = N'j.munoz@cx9.de',  @info = @mandantTSQL,  @subject = N'Problem gefunden. Bitte dokumentieren',  @MANDANT_ID = @MANDANT_ID
			SET @STEP = 0
		END
	IF (@validMandantData = 1 AND @STEP = 1)
		BEGIN 
			--SET NOCOUNT OFF            
			--check b connention to updating db 5.x
			IF (@manage_linked_server = 1)
				BEGIN
					INSERT INTO @dbConnetionInfo
					EXEC dbo.CHECK_DB_CONNECTION_BY_PK  @mandant_environment_pk = @MANDANT_ENVIRONMENT_PK
					SELECT TOP 1 @dbConnection = result, @dbversion=dbversion  FROM @dbConnetionInfo
					IF (EXISTS (SELECT PK FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId = @MANDANT_ID) AND ISNULL(@dbversion,'') <> '6.0')
						UPDATE MANDANT_WEB_PRODUKTE SET fromversion = @dbversion WHERE MandantId = @MANDANT_ID 
					--SET NOCOUNT ON
					IF (@dbConnection = 0)
						BEGIN
							SET @dbMandantEnvironmentInfo = 'Verbindung zur DB ist fehlgeschlagen. Bitte DB Anmeldung prüfen. <br>DB aktuelle version: '+@dbversion+' <br><br>'+@dbMandantEnvironmentInfo+' <br><br>'+dbo.GET_MANDANT_DATA(@MANDANT_ID)

							EXEC dbo.SendContentEMail @recipients = N'j.munoz@cx9.de',  @info = @dbMandantEnvironmentInfo,  @subject = N'Problem gefunden. Bitte dokumentieren',  @MANDANT_ID = @MANDANT_ID
							SET @STEP = 0
							SET @mandantDetectedErrors+=@dbMandantEnvironmentInfo
						END
					/*IF (@dbversion = '6.0')
						SET @STEP = 3
					ELSE */					
				END 
		END
	IF @validBetreuerMails = 0
	BEGIN
		PRINT 'Kundenbetreuermails pflegen'
		SET @mandantDetectedErrors+='Kundenbetreuermails pflegen.<br>'
		SELECT Aval[falscheMail] FROM dbo.GET_TABLE_FROM_LIST_DELIM(@kundenBetreuerMails,';') WHERE dbo.VALIDATE_EMAIL_ADDRESS(Aval)=0
		SET @STEP = 0 
	END		
	IF (ISNULL(@ABAS_TASK_NO,'') ='')
	BEGIN
		PRINT 'ABAS Aufgabenummer fehlt'
		SET @mandantDetectedErrors+='ABAS Aufgabenummer fehlt.<br>'

		SET @STEP = 0
	END  
	SET @JASPER_MR_LINK = 'http://gitlab.cx9.info:8000/cx9/jasper/-/merge_requests/'+ISNULL(@MRJASPERNUMMER,'')
	IF (@STEP = 1 AND (dbo.GET_ENVIRONMENT_LOG_ERRORS(@MANDANT_ID, @MANDANT_ENVIRONMENT_NAME) <> '' OR (@dbversion <> '6.0')))
		BEGIN
			IF EXISTS (SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId=@MANDANT_ID AND ISNULL((@ABAS_TASK_NO),'') ='')
			BEGIN
				PRINT 'ABAS Aufgabenummer fehlt'
				SET @mandantDetectedErrors+='ABAS Aufgabenummer fehlt.<br>'

				SET @STEP = 0
			END  
			IF EXISTS (SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId<>@MANDANT_ID AND ABAS_TASK_NO = CAST(@ABAS_TASK_NO AS NVARCHAR(128)))
			BEGIN
				PRINT 'ABAS Aufgabenummer doppel im System'
				SET @mandantDetectedErrors+='ABAS Aufgabenummer doppel im System<br>'
				SET @STEP = 0
			END  			  
		END
	IF (@STEP = 1 AND dbo.GET_ENVIRONMENT_LOG_ERRORS(@MANDANT_ID, @MANDANT_ENVIRONMENT_NAME) = '' AND (@dbversion = '6.0'))
		BEGIN
			IF EXISTS (SELECT * FROM dbo.MANDANT_WEB_PRODUKTE WHERE MandantId<>@MANDANT_ID AND  ABAS_TASK_NO = CAST(@ABAS_TASK_NO AS NVARCHAR(128)) OR ISNULL((@ABAS_TASK_NO),'') ='')
			BEGIN
				PRINT 'ABAS Aufgabenummer doppel im System oder oder keine Aufgabe nicht erlaubt '
				SET @mandantDetectedErrors+='ABAS Aufgabenummer doppel im System oder oder keine Aufgabe nicht erlaubt <br>'
				SET @STEP = 0
				SET @printEstimationCosts= 0
			END  
			ELSE IF ((ISNUMERIC(@MRJASPERNUMMER) = 0) OR (ISNUMERIC(@MRCRWNUMMER1) = 0) OR (ISNUMERIC(@MRCRWNUMMER2) = 0))
				BEGIN
					PRINT 'Falsche Einträge check wie folgt:'
					PRINT '@MRJASPERNUMMER: http://gitlab.cx9.info:8000/cx9/jasper/-/merge_requests/'+@MRJASPERNUMMER 
					PRINT '@MRCRWNUMMER1: http://gitlab.cx9.info:8000/web/CRENTWEB_DEV/-/merge_requests/'+@MRCRWNUMMER1 
					PRINT '@MRCRWNUMMER2: http://gitlab.cx9.info:8000/web/CRENTWEB_DEV/-/merge_requests/'+@MRCRWNUMMER2 
					SET @STEP = 0
					SET @printEstimationCosts = 0
				    SET @mandantDetectedErrors+='Falsche Einträge check wie folgt: @MRJASPERNUMMER:,@MRCRWNUMMER1:, @MRCRWNUMMER2, <br>'

				END	
			ELSE IF (EXISTS ( SELECT JASPER_MR_APPROVED_LOG FROM dbo.WEB_PRODUKTE_LOG_UPDATE WHERE MANDANT_ID <> @MANDANT_ID AND dbo.GET_UPDATE_LOG_ERRORS(ISNULL(JASPER_MR_APPROVED_LOG,''), @JASPER_MR_LINK, DEFAULT) <> '') )
				BEGIN
					PRINT 'Jasper Merge Request must be unique:'
					PRINT '@MRJASPERNUMMER: '+@JASPER_MR_LINK
				    SET @mandantDetectedErrors+='Jasper Merge Request must be unique:,@MRJASPERNUMMER: '+@JASPER_MR_LINK+' <br>'

					SET @STEP = 0
					SET @printEstimationCosts = 0
				END	/**/
			 ELSE SET @STEP = 2	    
		END		 
	IF (@mandantDetectedErrors <> '')
		BEGIN
			SET @mandantDetectedErrors = 'Doing Step: '+CAST(@STEP AS VARCHAR(16))+': LOGS:<br>'+@mandantDetectedErrors
			EXEC dbo.SendContentEMail @recipients = N'j.munoz@cx9.de',  @info = @mandantDetectedErrors,  @subject = N'Update 6.0 Logs. Bitte dokumentieren/korrigieren',  @MANDANT_ID = @MANDANT_ID
		END
	IF (@STEP = 1 AND dbo.GET_ENVIRONMENT_UPDATE_STATUS(@MANDANT_ID, @MANDANT_ENVIRONMENT_NAME) = ''  )
		BEGIN 
			 SET @STEP = 2	    -- dokumentieren
	 
		END	
	IF (@STEP = 2 AND dbo.GET_ENVIRONMENT_UPDATE_STATUS(@MANDANT_ID, @MANDANT_ENVIRONMENT_NAME) <> 'success'  )
		BEGIN 
			 SET @STEP = 2	    -- dokumentieren
		END			
	IF (@STEP = 2 AND dbo.GET_ENVIRONMENT_UPDATE_STATUS(@MANDANT_ID, @MANDANT_ENVIRONMENT_NAME) = 'success'  )
		BEGIN 
			 SET @STEP = 3	    -- send tatus
		END
	PRINT 'Doing Step: '+ CAST(@STEP AS NVARCHAR(32))	+'    ["0.- Aufgabe anlegen+Daten pflegen", "1.- Start/restart DB update", "2.- Doku + ORM", "3.- Berichte per Mail" ]' 	
	print 'dbversion: '+CAST (@dbversion AS NVARCHAR(32))		
 
	IF (@STEP = 0) --Datenflege
		BEGIN 
			DECLARE @like NVARCHAR(16) = (SELECT SUBSTRING(companyname,1,6) FROM dbo.Mandant WHERE id = @MANDANT_ID)
			--PRINT dbo.GET_MANDANT_DATA(@MANDANT_ID)
			SET @companynameHelpABAS = ISNULL((SELECT companyname+' (AbasId: '+CAST(abasId AS NVARCHAR(32))+') 70174' FROM dbo.Mandant WHERE id = @MANDANT_ID 	),'')
			IF (@printEstimationCosts=1)
				BEGIN
				    PRINT CHAR(13)+CHAR(13)+CHAR(13)+ @companynameHelpABAS
					EXEC dbo.CRENT_UPDATE6_ACC_LIVE_ESTIMATION_COSTS @mandantId = @MANDANT_ID
				END
			SELECT * FROM dbo.nlCustomerImport2 WHERE CompanyName LIKE '%'+@like+'%' 
			SELECT abasId, email, companyname+ ' (AbasId: '+CAST(abasId AS NVARCHAR(32))+') 70174', documentRoot , * FROM dbo.Mandant WHERE id = @MANDANT_ID 			
			RETURN
		END
	IF (@STEP = 1) --start update oder restart
		BEGIN 
			EXEC dbo.AUTOMATISCHE_PFLEGE_MANDANT_WEB_ENVIRONMENTS_BY_MANDANT_ENVIRONMENT_PK @AbasId = @AbasIdAUX,  @MANDANT_ENVIRONMENT_PK = @MANDANT_ENVIRONMENT_PK, 
			@EnvironmentUpdateDate = @EnvironmentUpdateDate,  @ABAS_TASK_NO = @ABAS_TASK_NO, @kundenBetreuerMails = @kundenBetreuerMails
			RETURN
		END
	IF (@STEP = 2) -- doku machen
		BEGIN 
			EXEC dbo.AUTOMATISCHE_PFLEGE_MANDANT_DB_ENVIRONMENT_UPDATE_DOKU @MANDANT_ID = @MANDANT_ID,  @MANDANT_ENVIRONMENT = @MANDANT_ENVIRONMENT_NAME,  @MRJASPERNUMMER = @MRJASPERNUMMER,  @MRCRWNUMMER1 = @MRCRWNUMMER1, @MRCRWNUMMER2 = @MRCRWNUMMER2 -- varchar(32)
			SET @STEP = 3
		END
	IF (@STEP = 3)
		BEGIN 
		PRINT @MANDANT_ENVIRONMENT_NAME
			 EXEC TRIGGER_MAIL_REPORT_UPDATES @mandID=@MANDANT_ID, @env=@MANDANT_ENVIRONMENT_NAME,  @justDBReport = 0, @reportJustDeveloper = @reportJustDeveloper 
			RETURN
		END
END 
GO
/****** Object:  StoredProcedure [dbo].[WriteFile]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[WriteFile](@fileName VARCHAR(2048), @fileContents NVARCHAR(MAX)) AS
DECLARE @FS int, @OLEResult int, @FileID int
DECLARE @cmd AS VARCHAR(4000)  
SET @cmd = 'DEL "'+@fileName+'"'
--EXECUTE Master.dbo.xp_CmdShell @cmd 
 
DECLARE @RESULT TABLE(RES VARCHAR(1024) NULL)

SET @cmd = 'IF NOT EXIST "'+SUBSTRING(@fileName,1,dbo.LastIndexOf(@fileName,'\'))+'" (MD "'+SUBSTRING(@fileName,1,dbo.LastIndexOf(@fileName,'\'))+'" 2>NUL)'
--PRINT 'processing command: '+@cmd
INSERT INTO @RESULT
	EXECUTE Master.dbo.xp_CmdShell @cmd  

EXECUTE @OLEResult = sp_OACreate 'Scripting.FileSystemObject', @FS OUT
 
IF @OLEResult <> 0 PRINT 'Failed: Scripting.FileSystemObject'

--Open a file
EXECUTE @OLEResult = sp_OAMethod @FS, 'OpenTextFile', @FileID OUT, @fileName, 2, 1
IF @OLEResult <> 0 PRINT 'Failed: OpenTextFile '+@fileName
 
--Write Text1
EXECUTE @OLEResult = sp_OAMethod @FileID, 'WriteLine', Null, @fileContents
IF @OLEResult <> 0 PRINT 'Failed: WriteLine '+@fileName
 
EXECUTE @OLEResult = sp_OADestroy @FileID
EXECUTE @OLEResult = sp_OADestroy @FS
GO
/****** Object:  StoredProcedure [dbo].[zz_JOB_EXECUTOR]    Script Date: 25.01.2022 03:14:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[zz_JOB_EXECUTOR] (@uuid INT, @result BIT = 1 OUTPUT) 
AS BEGIN 
	DECLARE @TSQL VARCHAR(MAX) = ''	
	SET @TSQL = ISNULL((SELECT command FROM zzExecJobs WHERE PK = @uuid),'')
	IF (@TSQL = '')
		BEGIN 
			SELECT 'no query found'[error]
			RETURN
		END
    BEGIN TRY  
		BEGIN TRY		    
			EXEC(@TSQL)  -- check valid results
			UPDATE zzExecJobs SET executed=CURRENT_TIMESTAMP WHERE pk = @uuid
			SET @result = 1 
		END TRY
		BEGIN CATCH
			SET @result = 0
			PRINT @TSQL
			SELECT ERROR_MESSAGE()[error]
		END CATCH  
    END TRY
    BEGIN CATCH
        SET @result = 0
		PRINT @TSQL
		SELECT ERROR_MESSAGE()[error]
    END CATCH  
END 
GO
